// Main.java — Entry point demonstrating the parking lot system with test scenarios

import java.util.ArrayList;
import java.util.List;

public class Main {
    public static void main(String[] args) {
        System.out.println("=== Parking Lot System Test ===\n");

        // Reset singleton for clean test
        ParkingLot.resetInstance();
        Ticket.resetCounter();

        // Initialize parking lot
        ParkingLot lot = ParkingLot.getInstance();
        lot.addLevel(5, 10, 5); // Level 0
        lot.addLevel(5, 10, 5); // Level 1

        System.out.println("Parking Lot initialized with " + lot.getLevelCount() + " levels");
        System.out.println("Level 0: 5 SMALL, 10 MEDIUM, 5 LARGE spots");
        System.out.println("Level 1: 5 SMALL, 10 MEDIUM, 5 LARGE spots");

        // Add observer — DisplayBoard implements ParkingObserver
        lot.addObserver(new DisplayBoard("Main Entrance"));

        // --- Test: Park Vehicles ---
        System.out.println("\n--- Test: Park Vehicles ---");
        Vehicle car1 = new Car("ABC-123");
        Vehicle moto1 = new Motorcycle("MOTO-1");
        Vehicle truck1 = new Truck("TRUCK-1");

        Ticket t1 = lot.parkVehicle(car1);
        System.out.println("Car (ABC-123) parked. Ticket: " + t1.getTicketId());

        Ticket t2 = lot.parkVehicle(moto1);
        System.out.println("Motorcycle (MOTO-1) parked. Ticket: " + t2.getTicketId());

        Ticket t3 = lot.parkVehicle(truck1);
        System.out.println("Truck (TRUCK-1) parked. Ticket: " + t3.getTicketId());

        // --- Test: Check Availability ---
        System.out.println("\n--- Test: Check Availability ---");
        System.out.println(lot.getAvailabilitySummary());

        // --- Test: Unpark with Hourly Pricing ---
        System.out.println("\n--- Test: Unpark with Hourly Pricing ---");
        lot.setPricingStrategy(new HourlyPricing(2.0));
        // Simulate 2 hours later
        long twoHoursLater = System.currentTimeMillis() + (2 * 60 * 60 * 1000);
        double fee1 = lot.unparkVehicle(t1.getTicketId(), twoHoursLater);
        System.out.println("Car (ABC-123) unparked. Fee: $" + String.format("%.2f", fee1) + " (2 hours @ $2/hr)");

        // --- Test: Unpark with Flat Rate Pricing ---
        System.out.println("\n--- Test: Unpark with Flat Rate Pricing ---");
        lot.setPricingStrategy(new FlatRatePricing(15.0));
        long oneHourLater = System.currentTimeMillis() + (60 * 60 * 1000);
        double fee2 = lot.unparkVehicle(t3.getTicketId(), oneHourLater);
        System.out.println("Truck (TRUCK-1) unparked. Fee: $" + String.format("%.2f", fee2) + " (flat rate)");

        // --- Test: Vehicle Type Pricing ---
        System.out.println("\n--- Test: Vehicle Type Based Pricing ---");
        lot.setPricingStrategy(new VehicleTypePricing(1.0, 2.0, 4.0));
        long threeHoursLater = System.currentTimeMillis() + (3 * 60 * 60 * 1000);
        double fee3 = lot.unparkVehicle(t2.getTicketId(), threeHoursLater);
        System.out.println("Motorcycle (MOTO-1) unparked. Fee: $" + String.format("%.2f", fee3) + " (3 hours @ $1/hr for motorcycle)");

        // --- Test: Spot Full Scenario ---
        System.out.println("\n--- Test: Fill All LARGE Spots on Level 0 ---");
        lot.setPricingStrategy(new HourlyPricing(2.0));
        List<Ticket> truckTickets = new ArrayList<>();
        for (int i = 0; i < 5; i++) {
            Ticket tt = lot.parkVehicle(new Truck("TRUCK-L0-" + i));
            if (tt != null) {
                truckTickets.add(tt);
                System.out.println("  Truck TRUCK-L0-" + i + " parked at " + tt.getSpot().getSpotId());
            }
        }
        // Next truck should go to Level 1
        Ticket overflowTicket = lot.parkVehicle(new Truck("TRUCK-OVERFLOW"));
        if (overflowTicket != null) {
            System.out.println("  Overflow Truck parked at " + overflowTicket.getSpot().getSpotId() + " (Level " + overflowTicket.getSpot().getLevel() + ")");
        }

        // --- Test: No Spot Available ---
        System.out.println("\n--- Test: No Spot Available ---");
        // Fill all large spots on level 1 (4 remaining + overflow = 5 total used, so 4 left)
        for (int i = 0; i < 4; i++) {
            lot.parkVehicle(new Truck("TRUCK-L1-" + i));
        }
        // Now try to park another truck - should fail
        Ticket failTicket = lot.parkVehicle(new Truck("TRUCK-FAIL"));
        if (failTicket == null) {
            System.out.println("  No spot available for TRUCK-FAIL - Parking lot full for LARGE vehicles!");
        }

        // --- Test: Payment Receipt ---
        System.out.println("\n--- Test: Payment Receipt ---");
        Vehicle car2 = new Car("XYZ-789");
        Ticket t4 = lot.parkVehicle(car2);
        t4.markExit(t4.getEntryTime() + (3 * 60 * 60 * 1000)); // 3 hours
        String receipt = lot.getPaymentProcessor().generateReceipt(t4);
        System.out.println(receipt);

        System.out.println("\n--- Final Availability ---");
        System.out.println(lot.getAvailabilitySummary());

        System.out.println("\n=== All Tests Passed ===");
    }
}

// model/ParkingSpot.java — Represents a single parking spot with size and availability

enum SpotSize {                       // enum = fixed set of constants; only these sizes exist
    SMALL, MEDIUM, LARGE
}

class ParkingSpot {
    private String spotId;            // private = only ParkingSpot can read/write this
    private SpotSize size;            // private = encapsulated; external code uses getSize()
    private int level;                // private = hidden detail; accessed via getLevel()
    private Vehicle parkedVehicle;    // private = only park()/unpark() can modify this
    private boolean available;        // private = controlled by park()/unpark() logic

    public ParkingSpot(String spotId, SpotSize size, int level) {
        this.spotId = spotId;
        this.size = size;
        this.level = level;
        this.available = true;
        this.parkedVehicle = null;
    }

    public synchronized boolean park(Vehicle vehicle) { // synchronized = only one thread can enter at a time
        if (!available) return false;
        if (vehicle.getRequiredSpotSize() != size) return false;
        this.parkedVehicle = vehicle;
        this.available = false;
        return true;
    }

    public synchronized Vehicle unpark() { // synchronized = prevents concurrent park+unpark conflicts
        Vehicle vehicle = this.parkedVehicle;
        this.parkedVehicle = null;
        this.available = true;
        return vehicle;
    }

    public boolean isAvailable() { return available; }
    public SpotSize getSize() { return size; }
    public String getSpotId() { return spotId; }
    public int getLevel() { return level; }
    public Vehicle getParkedVehicle() { return parkedVehicle; }

    @Override
    public String toString() {
        return spotId + " (" + size + ", Level " + level + ")";
    }
}

// model/Ticket.java — Represents a parking session with entry/exit timestamps for billing

class Ticket {
    private static int counter = 0;   // static = shared across ALL Ticket instances; tracks next ID
    private String ticketId;          // private = only this class manages the ID
    private Vehicle vehicle;          // private = encapsulated; read via getVehicle()
    private ParkingSpot spot;         // private = encapsulated; read via getSpot()
    private long entryTime;           // private = set at creation; read via getter
    private long exitTime;            // private = set only by markExit(); read via getter

    public Ticket(Vehicle vehicle, ParkingSpot spot) {
        this.ticketId = "T-" + (++counter);
        this.vehicle = vehicle;
        this.spot = spot;
        this.entryTime = System.currentTimeMillis();
        this.exitTime = 0;
    }

    // Constructor for testing with custom entry time
    public Ticket(Vehicle vehicle, ParkingSpot spot, long entryTime) {
        this.ticketId = "T-" + (++counter);
        this.vehicle = vehicle;
        this.spot = spot;
        this.entryTime = entryTime;
        this.exitTime = 0;
    }

    public void markExit() {
        this.exitTime = System.currentTimeMillis();
    }

    public void markExit(long exitTime) {
        this.exitTime = exitTime;
    }

    public long getDurationInHours() {
        long duration = exitTime - entryTime;
        long hours = duration / (1000 * 60 * 60);
        if (duration % (1000 * 60 * 60) > 0) hours++; // Round up
        return Math.max(1, hours);
    }

    public String getTicketId() { return ticketId; }
    public Vehicle getVehicle() { return vehicle; }
    public ParkingSpot getSpot() { return spot; }
    public long getEntryTime() { return entryTime; }
    public long getExitTime() { return exitTime; }

    @Override
    public String toString() {
        return ticketId;
    }

    public static void resetCounter() { counter = 0; }
}

// model/Vehicle.java — Domain entities for vehicles in the parking system

enum VehicleType {                    // enum = fixed set of constants; safer than raw strings
    MOTORCYCLE, CAR, TRUCK
}

abstract class Vehicle {              // abstract = can't create Vehicle directly; must be Car/Truck/Motorcycle
    private String licensePlate;      // private = only this class can access; encapsulates data
    private VehicleType type;         // private = hidden from outside; must use getter to read

    public Vehicle(String licensePlate, VehicleType type) {
        this.licensePlate = licensePlate;
        this.type = type;
    }

    public String getLicensePlate() { return licensePlate; }
    public VehicleType getType() { return type; }

    public abstract SpotSize getRequiredSpotSize(); // abstract = each subclass MUST implement this differently

    @Override                           // tells compiler: I'm intentionally replacing parent's method
    public String toString() {
        return type + " (" + licensePlate + ")";
    }
}

class Motorcycle extends Vehicle {    // extends = Motorcycle IS-A Vehicle; inherits its fields/methods
    public Motorcycle(String licensePlate) {
        super(licensePlate, VehicleType.MOTORCYCLE);
    }

    @Override                           // tells compiler: I'm intentionally replacing parent's method
    public SpotSize getRequiredSpotSize() {
        return SpotSize.SMALL;
    }
}

class Car extends Vehicle {           // extends = Car IS-A Vehicle; inherits its fields/methods
    public Car(String licensePlate) {
        super(licensePlate, VehicleType.CAR);
    }

    @Override
    public SpotSize getRequiredSpotSize() {
        return SpotSize.MEDIUM;
    }
}

class Truck extends Vehicle {          // extends = Truck IS-A Vehicle; inherits its fields/methods
    public Truck(String licensePlate) {
        super(licensePlate, VehicleType.TRUCK);
    }

    @Override
    public SpotSize getRequiredSpotSize() {
        return SpotSize.LARGE;
    }
}

// service/DisplayBoard.java — Concrete observer that prints spot status changes

class DisplayBoard implements ParkingObserver { // implements = this class fulfills the ParkingObserver contract
    private String boardName;                   // private = only this class manages its own name

    public DisplayBoard(String boardName) {
        this.boardName = boardName;
    }

    @Override                                   // @Override = implementing the interface method
    public void onSpotAvailabilityChanged(ParkingSpot spot, boolean available) {
        String status = available ? "AVAILABLE" : "OCCUPIED";
        System.out.println("  [" + boardName + "] Spot " + spot.getSpotId() + " on Level " + spot.getLevel() + " is now " + status);
    }
}

// service/ParkingLevel.java — Represents one floor of the parking structure with spot-finding logic

import java.util.ArrayList;
import java.util.List;

class ParkingLevel {
    private int levelNumber;          // private = only this class uses the level number directly
    private List<ParkingSpot> spots;  // private = external code can't tamper with the list
    private int smallCount;           // private = internal bookkeeping
    private int mediumCount;          // private = internal bookkeeping
    private int largeCount;           // private = internal bookkeeping

    public ParkingLevel(int levelNumber, int smallSpots, int mediumSpots, int largeSpots) {
        this(levelNumber, smallSpots, mediumSpots, largeSpots, new DefaultParkingSpotFactory());
    }

    /** Inject a custom factory for testing or alternative spot-construction schemes. */
    public ParkingLevel(int levelNumber, int smallSpots, int mediumSpots, int largeSpots, ParkingSpotFactory factory) {
        this.levelNumber = levelNumber;
        this.smallCount = smallSpots;
        this.mediumCount = mediumSpots;
        this.largeCount = largeSpots;
        // Factory pattern: delegate spot construction so this class doesn't know spotId conventions.
        this.spots = new ArrayList<>(factory.createSpotsForLevel(levelNumber, smallSpots, mediumSpots, largeSpots));
    }

    public synchronized ParkingSpot findAvailableSpot(SpotSize size) { // synchronized = thread-safe search
        for (ParkingSpot spot : spots) {
            if (spot.getSize() == size && spot.isAvailable()) {
                return spot;
            }
        }
        return null;
    }

    public int getAvailableCount(SpotSize size) {
        int count = 0;
        for (ParkingSpot spot : spots) {
            if (spot.getSize() == size && spot.isAvailable()) {
                count++;
            }
        }
        return count;
    }

    public int getLevelNumber() { return levelNumber; }
    public int getTotalSpots() { return spots.size(); }

    public String getAvailabilitySummary() {
        return "Level " + levelNumber + ": SMALL=" + getAvailableCount(SpotSize.SMALL) +
               ", MEDIUM=" + getAvailableCount(SpotSize.MEDIUM) +
               ", LARGE=" + getAvailableCount(SpotSize.LARGE);
    }
}

// service/ParkingLot.java — Singleton facade that orchestrates parking operations and notifies observers
// DESIGN PATTERN: Singleton | Facade
//
// FACADE: Main.java talks only to this class.
// Delegates observer notification to ParkingObserver (defined in ParkingObserver.java).

import java.util.ArrayList;
import java.util.HashMap;
import java.util.List;
import java.util.Map;

class ParkingLot {
    private static ParkingLot instance; // static = belongs to class, not any instance; shared across all code
    private List<ParkingLevel> levels;  // private = internal state hidden from callers
    private Map<String, Ticket> activeTickets; // private = only ParkingLot manages tickets
    private List<ParkingObserver> observers;   // private = observer list managed internally
    private PaymentProcessor paymentProcessor; // private = billing logic encapsulated

    private ParkingLot() {            // private constructor = only getInstance() can create this
        levels = new ArrayList<>();
        activeTickets = new HashMap<>();
        observers = new ArrayList<>();
        paymentProcessor = new PaymentProcessor(new HourlyPricing(2.0));
    }

    public static synchronized ParkingLot getInstance() { // static+synchronized = thread-safe singleton access
        if (instance == null) {
            instance = new ParkingLot();
        }
        return instance;
    }

    public static void resetInstance() {
        instance = null;
    }

    public void addLevel(int smallSpots, int mediumSpots, int largeSpots) {
        levels.add(new ParkingLevel(levels.size(), smallSpots, mediumSpots, largeSpots));
    }

    public void addObserver(ParkingObserver observer) {
        observers.add(observer);
    }

    public void removeObserver(ParkingObserver observer) {
        observers.remove(observer);
    }

    private void notifyObservers(ParkingSpot spot, boolean available) {
        for (ParkingObserver observer : observers) {
            observer.onSpotAvailabilityChanged(spot, available);
        }
    }

    public Ticket parkVehicle(Vehicle vehicle) {
        SpotSize requiredSize = vehicle.getRequiredSpotSize();
        for (ParkingLevel level : levels) {
            ParkingSpot spot = level.findAvailableSpot(requiredSize);
            if (spot != null) {
                spot.park(vehicle);
                Ticket ticket = new Ticket(vehicle, spot);
                activeTickets.put(ticket.getTicketId(), ticket);
                notifyObservers(spot, false);
                return ticket;
            }
        }
        return null; // No spot available
    }

    public double unparkVehicle(String ticketId) {
        return unparkVehicle(ticketId, System.currentTimeMillis());
    }

    public double unparkVehicle(String ticketId, long exitTime) {
        Ticket ticket = activeTickets.get(ticketId);
        if (ticket == null) {
            System.out.println("Invalid ticket: " + ticketId);
            return -1;
        }
        ticket.markExit(exitTime);
        double fee = paymentProcessor.processPayment(ticket);
        ParkingSpot spot = ticket.getSpot();
        spot.unpark();
        activeTickets.remove(ticketId);
        notifyObservers(spot, true);
        return fee;
    }

    public void setPricingStrategy(PricingStrategy strategy) {
        paymentProcessor.setStrategy(strategy);
    }

    public PaymentProcessor getPaymentProcessor() {
        return paymentProcessor;
    }

    public int getLevelCount() { return levels.size(); }

    public ParkingLevel getLevel(int index) { return levels.get(index); }

    public String getAvailabilitySummary() {
        StringBuilder sb = new StringBuilder();
        for (ParkingLevel level : levels) {
            sb.append(level.getAvailabilitySummary()).append("\n");
        }
        return sb.toString().trim();
    }
}

// service/ParkingObserver.java — Observer pattern interface for parking events
// DESIGN PATTERN: Observer
//
// WHO IMPLEMENTS THIS? → DisplayBoard (in DisplayBoard.java)
// WHO CALLS IT? → ParkingLot calls notifyObservers() on park/unpark
// WHY? → Decouples "spot changed" from "show something on screen/update dashboard".
//         New listeners (e.g., SMS alerts) can be added without changing ParkingLot code.

interface ParkingObserver {            // interface = contract; any class implementing this MUST define these methods
    void onSpotAvailabilityChanged(ParkingSpot spot, boolean available);
}

// service/ParkingSpotFactory.java — Factory pattern: encapsulates ParkingSpot creation rules

import java.util.ArrayList;
import java.util.List;

/**
 * Factory pattern: centralizes the construction of ParkingSpot objects.
 * Callers do not call `new ParkingSpot(...)` directly — they request a configured
 * batch of spots for a level. This keeps the spotId scheme (e.g. "L2-S0", "L2-M0",
 * "L2-LG0") in one place, and lets us swap the implementation (e.g. read from a
 * config file, randomize, or pre-warm a pool) without changing callers.
 */
interface ParkingSpotFactory {
    /** Create all spots for a single level given the desired counts per size. */
    List<ParkingSpot> createSpotsForLevel(int level, int smallCount, int mediumCount, int largeCount);
}

/** Default factory: produces spots with a deterministic naming scheme. */
class DefaultParkingSpotFactory implements ParkingSpotFactory {
    @Override
    public List<ParkingSpot> createSpotsForLevel(int level, int smallCount, int mediumCount, int largeCount) {
        List<ParkingSpot> spots = new ArrayList<>(smallCount + mediumCount + largeCount);
        for (int i = 0; i < smallCount; i++) {
            spots.add(createSpot(level, SpotSize.SMALL, "S", i));
        }
        for (int i = 0; i < mediumCount; i++) {
            spots.add(createSpot(level, SpotSize.MEDIUM, "M", i));
        }
        for (int i = 0; i < largeCount; i++) {
            spots.add(createSpot(level, SpotSize.LARGE, "LG", i));
        }
        return spots;
    }

    private ParkingSpot createSpot(int level, SpotSize size, String prefix, int index) {
        String spotId = "L" + level + "-" + prefix + index;
        return new ParkingSpot(spotId, size, level);
    }
}

// service/PaymentProcessor.java — Processes payments by delegating fee calculation to the pricing strategy

class PaymentProcessor {
