// service/ParkingLevel.java — O(1) spot lookup using pre-bucketed queues and atomic counters

import java.util.*;
import java.util.concurrent.ConcurrentLinkedQueue;
import java.util.concurrent.atomic.AtomicInteger;

class ParkingLevel {
    private final int levelNumber;    // final = set once; level identity never changes
    // O(1) spot retrieval — pre-bucketed by size
    private final Map<SpotSize, Queue<ParkingSpot>> availableSpots; // ConcurrentLinkedQueue = O(1) poll vs O(n) linear scan
    private final Map<SpotSize, AtomicInteger> availableCounts;     // AtomicInteger = O(1) count vs recounting every time

    public ParkingLevel(int levelNumber, int smallSpots, int mediumSpots, int largeSpots) {
        this(levelNumber, smallSpots, mediumSpots, largeSpots, new DefaultParkingSpotFactory());
    }

    /** Inject a custom factory for testing or alternative spot-construction schemes. */
    public ParkingLevel(int levelNumber, int smallSpots, int mediumSpots, int largeSpots, ParkingSpotFactory factory) {
        this.levelNumber = levelNumber;
        this.availableSpots = new EnumMap<>(SpotSize.class);
        this.availableCounts = new EnumMap<>(SpotSize.class);

        for (SpotSize size : SpotSize.values()) {
            availableSpots.put(size, new ConcurrentLinkedQueue<>());
            availableCounts.put(size, new AtomicInteger(0));
        }

        // Factory pattern: delegate spot construction; bucket the spots into the per-size queues.
        for (ParkingSpot spot : factory.createSpotsForLevel(levelNumber, smallSpots, mediumSpots, largeSpots)) {
            availableSpots.get(spot.getSize()).offer(spot);
            availableCounts.get(spot.getSize()).incrementAndGet();
        }
    }

    // O(1) — just poll from the queue!
    public ParkingSpot findAvailableSpot(SpotSize size) {
        ParkingSpot spot = availableSpots.get(size).poll();
        if (spot != null) {
            availableCounts.get(size).decrementAndGet();
        }
        return spot;
    }

    // Return a spot to the available pool after unpark
    public void returnSpot(ParkingSpot spot) {
        availableSpots.get(spot.getSize()).offer(spot);
        availableCounts.get(spot.getSize()).incrementAndGet();
    }

    // O(1) — just read the counter
    public int getAvailableCount(SpotSize size) {
        return availableCounts.get(size).get();
    }

    public int getLevelNumber() { return levelNumber; }

    public int getTotalSpots() {
        int total = 0;
        for (AtomicInteger count : availableCounts.values()) {
            total += count.get();
        }
        return total;
    }

    public String getAvailabilitySummary() {
        return "Level " + levelNumber + ": SMALL=" + getAvailableCount(SpotSize.SMALL) +
               ", MEDIUM=" + getAvailableCount(SpotSize.MEDIUM) +
               ", LARGE=" + getAvailableCount(SpotSize.LARGE);
    }
}

// service/ParkingLot.java — Injectable (no singleton), uses ConcurrentHashMap for thread-safe ticket storage
// DESIGN PATTERN: Facade
//
// FACADE: Main.java talks only to this class.
// Delegates observer notification to ParkingObserver (defined in ParkingObserver.java).

import java.util.ArrayList;
import java.util.List;
import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.CopyOnWriteArrayList;

class ParkingLot {
    private final List<ParkingLevel> levels;       // final = reference won't change after construction
    private final ConcurrentHashMap<String, Ticket> activeTickets; // ConcurrentHashMap = thread-safe O(1) put/get/remove
    private final CopyOnWriteArrayList<ParkingObserver> observers; // CopyOnWriteArrayList = safe iteration without locking
    private volatile PaymentProcessor paymentProcessor; // volatile = strategy swap visible to all threads immediately

    // No singleton — just construct it. Makes testing trivial.
    public ParkingLot() {
        this.levels = new ArrayList<>();
        this.activeTickets = new ConcurrentHashMap<>();
        this.observers = new CopyOnWriteArrayList<>();
        this.paymentProcessor = new PaymentProcessor(new HourlyPricing(2.0));
    }

    public ParkingLot(PricingStrategy strategy) {
        this.levels = new ArrayList<>();
        this.activeTickets = new ConcurrentHashMap<>();
        this.observers = new CopyOnWriteArrayList<>();
        this.paymentProcessor = new PaymentProcessor(strategy);
    }

    public void addLevel(int smallSpots, int mediumSpots, int largeSpots) {
        if (smallSpots < 0 || mediumSpots < 0 || largeSpots < 0) {
            throw new IllegalArgumentException("Spot counts cannot be negative");
        }
        levels.add(new ParkingLevel(levels.size(), smallSpots, mediumSpots, largeSpots));
    }

    public void addObserver(ParkingObserver observer) {
        if (observer == null) throw new IllegalArgumentException("Observer cannot be null");
        observers.add(observer);
    }

    public void removeObserver(ParkingObserver observer) {
        observers.remove(observer);
    }

    private void notifyObservers(ParkingSpot spot, boolean available) {
        for (ParkingObserver observer : observers) {
            observer.onSpotAvailabilityChanged(spot, available);
        }
    }

    public Ticket parkVehicle(Vehicle vehicle) {
        if (vehicle == null) {
            throw new IllegalArgumentException("Vehicle cannot be null");
        }
        SpotSize requiredSize = vehicle.getRequiredSpotSize();
        for (ParkingLevel level : levels) {
            ParkingSpot spot = level.findAvailableSpot(requiredSize);
            if (spot != null) {
                spot.park(vehicle);
                Ticket ticket = new Ticket(vehicle, spot);
                activeTickets.put(ticket.getTicketId(), ticket);
                notifyObservers(spot, false);
                return ticket;
            }
        }
        return null; // No spot available
    }

    public double unparkVehicle(String ticketId) {
        return unparkVehicle(ticketId, System.currentTimeMillis());
    }

    public double unparkVehicle(String ticketId, long exitTime) {
        if (ticketId == null || ticketId.isBlank()) {
            throw new IllegalArgumentException("Ticket ID cannot be null or empty");
        }
        Ticket ticket = activeTickets.get(ticketId);
        if (ticket == null) {
            System.out.println("Invalid ticket: " + ticketId);
            return -1;
        }
        ticket.markExit(exitTime);
        double fee = paymentProcessor.processPayment(ticket);
        ParkingSpot spot = ticket.getSpot();
        spot.unpark();
        activeTickets.remove(ticketId);

        // Return the spot to its level's available pool
        for (ParkingLevel level : levels) {
            if (level.getLevelNumber() == spot.getLevel()) {
                level.returnSpot(spot);
                break;
            }
        }

        notifyObservers(spot, true);
        return fee;
    }

    public void setPricingStrategy(PricingStrategy strategy) {
        if (strategy == null) throw new IllegalArgumentException("Strategy cannot be null");
        paymentProcessor.setStrategy(strategy);
    }

    public PaymentProcessor getPaymentProcessor() {
        return paymentProcessor;
    }

    public int getLevelCount() { return levels.size(); }

    public ParkingLevel getLevel(int index) {
        if (index < 0 || index >= levels.size()) {
            throw new IndexOutOfBoundsException("Level " + index + " does not exist");
        }
        return levels.get(index);
    }

    public String getAvailabilitySummary() {
        StringBuilder sb = new StringBuilder();
        for (ParkingLevel level : levels) {
            sb.append(level.getAvailabilitySummary()).append("\n");
        }
        return sb.toString().trim();
    }
}

// service/ParkingObserver.java — Observer pattern interface for parking events
// DESIGN PATTERN: Observer
//
// WHO IMPLEMENTS THIS? → DisplayBoard (in DisplayBoard.java)
// WHO CALLS IT? → ParkingLot calls notifyObservers() on park/unpark
// WHY? → Decouples "spot changed" from "show something on screen/update dashboard".
//         New listeners (e.g., SMS alerts) can be added without changing ParkingLot code.

interface ParkingObserver {            // interface = contract; observers MUST define this method
    void onSpotAvailabilityChanged(ParkingSpot spot, boolean available);
}

// service/ParkingSpotFactory.java — Factory pattern: encapsulates ParkingSpot creation rules

import java.util.ArrayList;
import java.util.List;

/**
 * Factory pattern: centralizes the construction of ParkingSpot objects.
 * Callers do not call `new ParkingSpot(...)` directly — they request a configured
 * batch of spots for a level. This keeps the spotId scheme (e.g. "L2-S0", "L2-M0",
 * "L2-LG0") in one place, and lets us swap the implementation (e.g. read from a
 * config file, randomize, or pre-warm a pool) without changing callers.
 */
interface ParkingSpotFactory {
    /** Create all spots for a single level given the desired counts per size. */
    List<ParkingSpot> createSpotsForLevel(int level, int smallCount, int mediumCount, int largeCount);
}

/** Default factory: produces spots with a deterministic naming scheme. */
class DefaultParkingSpotFactory implements ParkingSpotFactory {
    @Override
    public List<ParkingSpot> createSpotsForLevel(int level, int smallCount, int mediumCount, int largeCount) {
        List<ParkingSpot> spots = new ArrayList<>(smallCount + mediumCount + largeCount);
        for (int i = 0; i < smallCount; i++) {
            spots.add(createSpot(level, SpotSize.SMALL, "S", i));
        }
        for (int i = 0; i < mediumCount; i++) {
            spots.add(createSpot(level, SpotSize.MEDIUM, "M", i));
        }
        for (int i = 0; i < largeCount; i++) {
            spots.add(createSpot(level, SpotSize.LARGE, "LG", i));
        }
        return spots;
    }

    private ParkingSpot createSpot(int level, SpotSize size, String prefix, int index) {
        String spotId = "L" + level + "-" + prefix + index;
        return new ParkingSpot(spotId, size, level);
    }
}

// service/PaymentProcessor.java — Processes payments by delegating fee calculation to the pricing strategy

class PaymentProcessor {
    private volatile PricingStrategy strategy; // volatile = strategy can be swapped; readers see latest

    public PaymentProcessor(PricingStrategy strategy) {
        if (strategy == null) throw new IllegalArgumentException("Strategy cannot be null");
        this.strategy = strategy;
    }

    public void setStrategy(PricingStrategy strategy) {
        if (strategy == null) throw new IllegalArgumentException("Strategy cannot be null");
        this.strategy = strategy;
    }

    public PricingStrategy getStrategy() {
        return strategy;
    }

    public double processPayment(Ticket ticket) {
        if (ticket == null) throw new IllegalArgumentException("Ticket cannot be null");
        return strategy.calculateFee(ticket);
    }

    public String generateReceipt(Ticket ticket) {
        if (ticket == null) throw new IllegalArgumentException("Ticket cannot be null");
        double fee = strategy.calculateFee(ticket);
        StringBuilder sb = new StringBuilder();
        sb.append("=== Payment Receipt ===\n");
        sb.append("Ticket: ").append(ticket.getTicketId()).append("\n");
        sb.append("Vehicle: ").append(ticket.getVehicle()).append("\n");
        sb.append("Spot: ").append(ticket.getSpot()).append("\n");
        sb.append("Duration: ").append(ticket.getDurationInHours()).append(" hour(s)\n");
        sb.append("Pricing: ").append(strategy.getName()).append("\n");
        sb.append("Amount: $").append(String.format("%.2f", fee)).append("\n");
        sb.append("========================");
        return sb.toString();
    }
}

// strategy/PricingStrategy.java — Interchangeable pricing algorithms (same as naive, strategy pattern is already clean)
// DESIGN PATTERN: Strategy

interface PricingStrategy {            // interface = contract; any pricing class MUST define these
    double calculateFee(Ticket ticket);
    String getName();
}

class HourlyPricing implements PricingStrategy { // implements = fulfills PricingStrategy contract
    private final double ratePerHour; // final = rate set once at construction, never changes

    public HourlyPricing(double ratePerHour) {
        if (ratePerHour < 0) throw new IllegalArgumentException("Rate cannot be negative");
        this.ratePerHour = ratePerHour;
    }

    @Override
    public double calculateFee(Ticket ticket) {
        return ticket.getDurationInHours() * ratePerHour;
    }

    @Override
    public String getName() {
        return "Hourly ($" + String.format("%.2f", ratePerHour) + "/hr)";
    }
}

class FlatRatePricing implements PricingStrategy { // implements = fulfills PricingStrategy contract
    private final double flatRate;    // final = immutable after construction

    public FlatRatePricing(double flatRate) {
        if (flatRate < 0) throw new IllegalArgumentException("Rate cannot be negative");
        this.flatRate = flatRate;
    }

    @Override
    public double calculateFee(Ticket ticket) {
        return flatRate;
    }

    @Override
    public String getName() {
        return "Flat Rate ($" + String.format("%.2f", flatRate) + ")";
    }
}

class VehicleTypePricing implements PricingStrategy { // implements = fulfills PricingStrategy contract
    private final double motorcycleRate; // final = rates are immutable after construction
    private final double carRate;        // final = immutable
    private final double truckRate;      // final = immutable

    public VehicleTypePricing(double motorcycleRate, double carRate, double truckRate) {
        if (motorcycleRate < 0 || carRate < 0 || truckRate < 0) {
            throw new IllegalArgumentException("Rates cannot be negative");
        }
        this.motorcycleRate = motorcycleRate;
        this.carRate = carRate;
        this.truckRate = truckRate;
    }

    @Override
    public double calculateFee(Ticket ticket) {
        long hours = ticket.getDurationInHours();
        switch (ticket.getVehicle().getType()) {
            case MOTORCYCLE: return hours * motorcycleRate;
            case CAR: return hours * carRate;
            case TRUCK: return hours * truckRate;
            default: return hours * carRate;
        }
    }

    @Override
    public String getName() {
        return "Vehicle-Type Based";
    }
}

// concurrent/Main.java — Spawns 20 threads all trying to park simultaneously

import java.util.ArrayList;
import java.util.Collections;
import java.util.List;
import java.util.concurrent.CountDownLatch;
import java.util.concurrent.atomic.AtomicInteger;

public class Main {
    public static void main(String[] args) throws InterruptedException {
        System.out.println("=== Concurrent Parking Lot Demo ===\n");

        // Create a parking lot with limited spots: 3 small, 5 medium, 2 large = 10 total
        ParkingLot lot = new ParkingLot();
        lot.addLevel(3, 5, 2);

        // 20 threads try to park cars simultaneously, but only 5 MEDIUM spots exist
        int threadCount = 20;
        CountDownLatch startLatch = new CountDownLatch(1);  // All threads start at once
        CountDownLatch doneLatch = new CountDownLatch(threadCount);

        List<String> results = Collections.synchronizedList(new ArrayList<>());
        AtomicInteger successCount = new AtomicInteger(0);
        AtomicInteger failCount = new AtomicInteger(0);

        System.out.println("Scenario: 20 cars trying to park, but only 5 MEDIUM spots available.");
        System.out.println("Expected: Exactly 5 succeed, 15 are rejected.\n");

        for (int i = 0; i < threadCount; i++) {
            final int id = i;
            new Thread(() -> {
                try {
                    startLatch.await(); // Wait for signal — all threads start simultaneously
                    Vehicle car = new Car("CAR-" + id);
                    Ticket ticket = lot.parkVehicle(car);
                    if (ticket != null) {
                        successCount.incrementAndGet();
                        results.add("  [PARKED] " + car + " -> " + ticket.getSpot().getSpotId());
                    } else {
                        failCount.incrementAndGet();
                        results.add("  [REJECTED] " + car + " — no spots available");
                    }
                } catch (InterruptedException e) {
                    Thread.currentThread().interrupt();
                } finally {
                    doneLatch.countDown();
                }
            }, "Parker-" + i).start();
        }

        // Fire! All threads start at once
        startLatch.countDown();
        doneLatch.await();

        // Print results
        results.sort(String::compareTo);
        for (String r : results) {
            System.out.println(r);
        }

        System.out.println("\n--- Summary ---");
        System.out.println("Threads attempted: " + threadCount);
        System.out.println("Successfully parked: " + successCount.get());
        System.out.println("Correctly rejected: " + failCount.get());
        System.out.println("Active tickets: " + lot.getActiveTicketCount());

        // Verify correctness
        boolean correct = successCount.get() == 5 && failCount.get() == 15;
        System.out.println("\nCorrectness check: " + (correct ? "PASSED" : "FAILED"));
        if (!correct) {
            System.out.println("  ERROR: Expected 5 parked + 15 rejected, but got " +
                    successCount.get() + " parked + " + failCount.get() + " rejected");
        }

        System.out.println("\n--- Availability After Parking ---");
        System.out.println(lot.getAvailabilitySummary());
    }
}

// concurrent/RaceConditionDemo.java — Demonstrates the race condition bug and the fix

import java.util.concurrent.CountDownLatch;
import java.util.concurrent.atomic.AtomicInteger;
import java.util.concurrent.atomic.AtomicReference;

/**
 * RACE CONDITION: Two vehicles trying to park in the last available spot simultaneously.
 *
 * BUG: Using check-then-act without atomicity:
 *   if (spot.isAvailable()) {   // Thread A checks — true
 *                                // Thread B checks — also true!
 *       spot.setVehicle(v);     // Thread A parks
 *                                // Thread B parks — OVERWRITES Thread A!
 *   }
 *
 * FIX: Use AtomicReference.compareAndSet() — atomically checks AND sets in one operation.
 */
public class RaceConditionDemo {

    // ===== BUGGY VERSION: Not thread-safe =====
    static class BuggyParkingSpot {
        private Vehicle parkedVehicle = null;

        // BUG: check-then-act is NOT atomic!
        // Between checking isAvailable and setting the vehicle, another thread can intervene.
        public boolean park(Vehicle vehicle) {
            if (parkedVehicle == null) {  // CHECK
                // Simulate tiny delay that makes race condition more likely
                Thread.yield();
                parkedVehicle = vehicle;  // ACT — another thread may have already set this!
                return true;
            }
            return false;
        }

        public Vehicle getParkedVehicle() { return parkedVehicle; }
        public boolean isAvailable() { return parkedVehicle == null; }
    }

    // ===== FIXED VERSION: Thread-safe with CAS =====
    static class FixedParkingSpot {
        private final AtomicReference<Vehicle> parkedVehicle = new AtomicReference<>(null);

        // FIX: compareAndSet is atomic — only ONE thread can succeed
        public boolean park(Vehicle vehicle) {
            return parkedVehicle.compareAndSet(null, vehicle);
        }

        public Vehicle getParkedVehicle() { return parkedVehicle.get(); }
        public boolean isAvailable() { return parkedVehicle.get() == null; }
    }

    public static void main(String[] args) throws InterruptedException {
        System.out.println("=== Race Condition Demo: Parking Lot ===\n");

        demonstrateBug();
        System.out.println();
        demonstrateFix();
    }

    static void demonstrateBug() throws InterruptedException {
        System.out.println("--- BUGGY VERSION (check-then-act without atomicity) ---");
        System.out.println("Two threads try to park in the SAME spot simultaneously.\n");

        int races = 0;
        int trials = 1000;

        for (int t = 0; t < trials; t++) {
            BuggyParkingSpot spot = new BuggyParkingSpot();
            CountDownLatch start = new CountDownLatch(1);
            AtomicInteger successCount = new AtomicInteger(0);

            Thread t1 = new Thread(() -> {
                try { start.await(); } catch (InterruptedException e) { return; }
                if (spot.park(new Car("CAR-A"))) successCount.incrementAndGet();
            });
            Thread t2 = new Thread(() -> {
                try { start.await(); } catch (InterruptedException e) { return; }
                if (spot.park(new Car("CAR-B"))) successCount.incrementAndGet();
            });

            t1.start();
            t2.start();
            start.countDown(); // Both threads race
            t1.join();
            t2.join();

            if (successCount.get() > 1) {
                races++;
            }
        }

        System.out.println("Results over " + trials + " trials:");
        System.out.println("  Race conditions detected: " + races + " times");
        System.out.println("  (Both threads thought they parked successfully!)");
        if (races > 0) {
            System.out.println("  BUG CONFIRMED: Multiple vehicles assigned to same spot.");
        } else {
            System.out.println("  (Race didn't manifest this run — but the bug exists. Run again or increase trials.)");
        }
    }

    static void demonstrateFix() throws InterruptedException {
        System.out.println("--- FIXED VERSION (AtomicReference.compareAndSet) ---");
        System.out.println("Two threads try to park in the SAME spot simultaneously.\n");

        int races = 0;
        int trials = 1000;

        for (int t = 0; t < trials; t++) {
            FixedParkingSpot spot = new FixedParkingSpot();
            CountDownLatch start = new CountDownLatch(1);
            AtomicInteger successCount = new AtomicInteger(0);

            Thread t1 = new Thread(() -> {
                try { start.await(); } catch (InterruptedException e) { return; }
                if (spot.park(new Car("CAR-A"))) successCount.incrementAndGet();
            });
            Thread t2 = new Thread(() -> {
                try { start.await(); } catch (InterruptedException e) { return; }
                if (spot.park(new Car("CAR-B"))) successCount.incrementAndGet();
            });

            t1.start();
            t2.start();
            start.countDown();
            t1.join();
            t2.join();

            if (successCount.get() > 1) {
                races++;
            }
        }

        System.out.println("Results over " + trials + " trials:");
        System.out.println("  Race conditions detected: " + races + " times");
        System.out.println("  Exactly one thread succeeds EVERY time.");
        System.out.println("  FIX VERIFIED: CAS guarantees mutual exclusion without locks.");
    }
}

// concurrent/model/ParkingSpot.java — Thread-safe parking spot using AtomicReference for CAS parking

import java.util.concurrent.atomic.AtomicReference;

enum SpotSize {
    SMALL, MEDIUM, LARGE
}

class ParkingSpot {
    private final String spotId;                                                       // immutable identity — safe publication to all threads
    private final SpotSize size;                                                        // never changes after construction — no sync needed
    private final int level;                                                            // set once in ctor — final guarantees visibility
    private final AtomicReference<Vehicle> parkedVehicle = new AtomicReference<>(null); // multiple writers → need CAS for lock-free park/unpark

    public ParkingSpot(String spotId, SpotSize size, int level) {
        this.spotId = spotId;
        this.size = size;
        this.level = level;
    }

    /**
     * CAS-based park — lock-free, thread-safe.
     * Only one thread can successfully park in this spot even if multiple
     * threads attempt simultaneously. compareAndSet atomically checks that
     * the spot is null (empty) and sets the vehicle in one operation.
     */
    public boolean park(Vehicle vehicle) {
        if (vehicle.getRequiredSpotSize() != size) return false;
        return parkedVehicle.compareAndSet(null, vehicle);
    }

    /**
     * Atomic unpark — returns the vehicle that was parked (or null if already empty).
     */
    public Vehicle unpark() {
        return parkedVehicle.getAndSet(null);
    }

    public boolean isAvailable() {
        return parkedVehicle.get() == null;
    }

    public SpotSize getSize() { return size; }
    public String getSpotId() { return spotId; }
    public int getLevel() { return level; }
    public Vehicle getParkedVehicle() { return parkedVehicle.get(); }

    @Override
    public String toString() {
        return spotId + " (" + size + ", Level " + level + ")";
    }
}

// concurrent/model/Ticket.java — Parking session with thread-safe ID generation

import java.util.concurrent.atomic.AtomicInteger;

class Ticket {
    private static final AtomicInteger counter = new AtomicInteger(0); // shared ID generator across all instances — static + atomic for uniqueness
    private final String ticketId;                                     // immutable after ctor — safe to read from any thread without sync
    private final Vehicle vehicle;                                     // set once — final ensures happens-before to all readers
    private final ParkingSpot spot;                                    // set once — final ensures happens-before to all readers
    private final long entryTime;                                      // captured at creation — never changes
    private volatile long exitTime;                                    // written by exit-gate thread, read by billing — volatile sufficient

    public Ticket(Vehicle vehicle, ParkingSpot spot) {
        this.ticketId = "T-" + counter.incrementAndGet();
        this.vehicle = vehicle;
        this.spot = spot;
        this.entryTime = System.currentTimeMillis();
        this.exitTime = 0;
    }

    public void markExit() {
        this.exitTime = System.currentTimeMillis();
    }

    public long getDurationInHours() {
        long duration = exitTime - entryTime;
        long hours = duration / (1000 * 60 * 60);
        if (duration % (1000 * 60 * 60) > 0) hours++;
        return Math.max(1, hours);
    }

    public String getTicketId() { return ticketId; }
    public Vehicle getVehicle() { return vehicle; }
    public ParkingSpot getSpot() { return spot; }
    public long getEntryTime() { return entryTime; }
    public long getExitTime() { return exitTime; }

    @Override
    public String toString() {
        return ticketId;
    }

    public static void resetCounter() { counter.set(0); }
}

// concurrent/model/Vehicle.java — Domain entities for vehicles (same as optimized)

enum VehicleType {                    // enum = fixed set of constants; type-safe vehicle categories
    MOTORCYCLE, CAR, TRUCK
