// concurrent/service/ParkingLevel.java — ConcurrentLinkedQueue + AtomicInteger for thread-safe level management

import java.util.*;
import java.util.concurrent.ConcurrentLinkedQueue;
import java.util.concurrent.atomic.AtomicInteger;

class ParkingLevel {
    private final int levelNumber;    // final = immutable identity; safe publication to all threads
    private final Map<SpotSize, ConcurrentLinkedQueue<ParkingSpot>> availableSpots; // ConcurrentLinkedQueue = lock-free poll gives each thread a unique spot
    private final Map<SpotSize, AtomicInteger> availableCounts; // AtomicInteger = lock-free counter; no lost updates

    public ParkingLevel(int levelNumber, int smallSpots, int mediumSpots, int largeSpots) {
        this.levelNumber = levelNumber;
        this.availableSpots = new EnumMap<>(SpotSize.class);
        this.availableCounts = new EnumMap<>(SpotSize.class);

        for (SpotSize size : SpotSize.values()) {
            availableSpots.put(size, new ConcurrentLinkedQueue<>());
            availableCounts.put(size, new AtomicInteger(0));
        }

        initSpots(SpotSize.SMALL, smallSpots, "S");
        initSpots(SpotSize.MEDIUM, mediumSpots, "M");
        initSpots(SpotSize.LARGE, largeSpots, "LG");
    }

    private void initSpots(SpotSize size, int count, String prefix) {
        for (int i = 0; i < count; i++) {
            ParkingSpot spot = new ParkingSpot("L" + levelNumber + "-" + prefix + i, size, levelNumber);
            availableSpots.get(size).offer(spot);
            availableCounts.get(size).incrementAndGet();
        }
    }

    /**
     * Thread-safe spot retrieval using ConcurrentLinkedQueue.poll().
     * Multiple threads can safely call this simultaneously — each gets a unique spot or null.
     */
    public ParkingSpot findAvailableSpot(SpotSize size) {
        ParkingSpot spot = availableSpots.get(size).poll();
        if (spot != null) {
            availableCounts.get(size).decrementAndGet();
        }
        return spot;
    }

    /**
     * Return a spot to the available pool after unpark.
     */
    public void returnSpot(ParkingSpot spot) {
        availableSpots.get(spot.getSize()).offer(spot);
        availableCounts.get(spot.getSize()).incrementAndGet();
    }

    public int getAvailableCount(SpotSize size) {
        return availableCounts.get(size).get();
    }

    public int getLevelNumber() { return levelNumber; }

    public int getTotalAvailable() {
        int total = 0;
        for (AtomicInteger count : availableCounts.values()) {
            total += count.get();
        }
        return total;
    }

    public String getAvailabilitySummary() {
        return "Level " + levelNumber + ": SMALL=" + getAvailableCount(SpotSize.SMALL) +
               ", MEDIUM=" + getAvailableCount(SpotSize.MEDIUM) +
               ", LARGE=" + getAvailableCount(SpotSize.LARGE);
    }
}

// concurrent/service/ParkingLot.java — Thread-safe parking with CAS-based spot assignment
// DESIGN PATTERN: Facade
//
// FACADE: Main.java talks only to this class.
// Delegates observer notification to ParkingObserver (defined in ParkingObserver.java).

import java.util.ArrayList;
import java.util.List;
import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.CopyOnWriteArrayList;
import java.util.concurrent.atomic.AtomicInteger;

class ParkingLot {
    private final List<ParkingLevel> levels;                            // populated at startup only — final ref, no structural mutation after init
    private final ConcurrentHashMap<String, Ticket> activeTickets;      // concurrent put/remove from many threads — CHM gives segment-level locking
    private final CopyOnWriteArrayList<ParkingObserver> observers;      // rarely written, frequently iterated — COW avoids iterator locking
    private final AtomicInteger totalParked = new AtomicInteger(0);    // multiple park threads increment — atomic avoids lost updates
    private final AtomicInteger totalRejected = new AtomicInteger(0);  // same as above — lock-free counter for stats

    public ParkingLot() {
        this.levels = new ArrayList<>();
        this.activeTickets = new ConcurrentHashMap<>();
        this.observers = new CopyOnWriteArrayList<>();
    }

    public void addLevel(int smallSpots, int mediumSpots, int largeSpots) {
        levels.add(new ParkingLevel(levels.size(), smallSpots, mediumSpots, largeSpots));
    }

    public void addObserver(ParkingObserver observer) {
        observers.add(observer);
    }

    private void notifyObservers(ParkingSpot spot, boolean available) {
        for (ParkingObserver observer : observers) {
            observer.onSpotAvailabilityChanged(spot, available);
        }
    }

    /**
     * Thread-safe parking operation.
     * ConcurrentLinkedQueue.poll() ensures each spot is handed out to exactly one thread.
     * CAS on ParkingSpot.park() provides a second safety layer.
     * ConcurrentHashMap ensures ticket storage is thread-safe.
     */
    public Ticket parkVehicle(Vehicle vehicle) {
        if (vehicle == null) {
            throw new IllegalArgumentException("Vehicle cannot be null");
        }
        SpotSize requiredSize = vehicle.getRequiredSpotSize();
        for (ParkingLevel level : levels) {
            ParkingSpot spot = level.findAvailableSpot(requiredSize);
            if (spot != null) {
                if (spot.park(vehicle)) {
                    Ticket ticket = new Ticket(vehicle, spot);
                    activeTickets.put(ticket.getTicketId(), ticket);
                    totalParked.incrementAndGet();
                    notifyObservers(spot, false);
                    return ticket;
                }
                // If CAS failed (another thread parked here), spot was already taken from queue
                // This shouldn't happen with our queue-based design, but is safe regardless
            }
        }
        totalRejected.incrementAndGet();
        return null; // No spot available
    }

    public double unparkVehicle(String ticketId) {
        if (ticketId == null || ticketId.isBlank()) {
            throw new IllegalArgumentException("Ticket ID cannot be null or empty");
        }
        Ticket ticket = activeTickets.remove(ticketId);
        if (ticket == null) {
            return -1;
        }
        ticket.markExit();
        ParkingSpot spot = ticket.getSpot();
        spot.unpark();

        for (ParkingLevel level : levels) {
            if (level.getLevelNumber() == spot.getLevel()) {
                level.returnSpot(spot);
                break;
            }
        }

        notifyObservers(spot, true);
        return ticket.getDurationInHours() * 2.0; // Simple $2/hour
    }

    public int getTotalParked() { return totalParked.get(); }
    public int getTotalRejected() { return totalRejected.get(); }
    public int getActiveTicketCount() { return activeTickets.size(); }

    public String getAvailabilitySummary() {
        StringBuilder sb = new StringBuilder();
        for (ParkingLevel level : levels) {
            sb.append(level.getAvailabilitySummary()).append("\n");
        }
        return sb.toString().trim();
    }
}

// service/ParkingObserver.java — Observer pattern interface for parking events
// DESIGN PATTERN: Observer
//
// WHO IMPLEMENTS THIS? → DisplayBoard (in DisplayBoard.java)
// WHO CALLS IT? → ParkingLot calls notifyObservers() on park/unpark
// WHY? → Decouples "spot changed" from "show something on screen/update dashboard".
//         New listeners (e.g., SMS alerts) can be added without changing ParkingLot code.

interface ParkingObserver {            // interface = contract; observers MUST define this method
    void onSpotAvailabilityChanged(ParkingSpot spot, boolean available);
}

