// model/Display.java — Concrete observer that prints elevator events to the console
//
// This class IMPLEMENTS ElevatorObserver (defined in ElevatorObserver.java).
// It gets called automatically whenever an elevator arrives at a floor, changes state, or opens doors.

class Display implements ElevatorObserver { // implements = Display fulfills the observer contract
    private String displayName;       // private = only Display manages its own name
    private boolean verbose;          // private = controls whether to print (can mute output)

    public Display(String displayName, boolean verbose) {
        this.displayName = displayName;
        this.verbose = verbose;
    }

    public Display(String displayName) {
        this(displayName, true);
    }

    @Override                          // @Override = implementing ElevatorObserver.onFloorArrival
    public void onFloorArrival(int elevatorId, int floor, ElevatorState state) {
        if (verbose) {
            System.out.println("  [" + displayName + "] Elevator " + elevatorId + " at Floor " + floor + " (" + state + ")");
        }
    }

    @Override                          // @Override = implementing ElevatorObserver.onStateChange
    public void onStateChange(int elevatorId, ElevatorState oldState, ElevatorState newState) {
        if (verbose) {
            System.out.println("  [" + displayName + "] Elevator " + elevatorId + ": " + oldState + " -> " + newState);
        }
    }

    @Override                          // @Override = implementing ElevatorObserver.onDoorOpen
    public void onDoorOpen(int elevatorId, int floor) {
        if (verbose) {
            System.out.println("  [" + displayName + "] Elevator " + elevatorId + " doors open at Floor " + floor);
        }
    }
}

// model/Elevator.java — Single elevator car managing stops, movement, direction, and observers
//
// KEY ALGORITHM: SCAN (elevator algorithm)
// - Collects all requested floors and serves them in sorted order
// - upStops: floors to visit while going UP (sorted ascending via TreeSet)
// - downStops: floors to visit while going DOWN (sorted descending via TreeSet)
// - When all up stops are served, switches to down direction (and vice versa)
// - Like a disk arm sweep — serves requests in one pass without zigzagging

import java.util.ArrayList;
import java.util.List;
import java.util.TreeSet;

class Elevator {
    private int id;                   // private = identity; only readable via getId()
    private int currentFloor;         // private = only step() changes this; tracks physical position
    private ElevatorState state;      // private = IDLE/MOVING_UP/MOVING_DOWN/MAINTENANCE; drives all decisions
    private TreeSet<Integer> upStops; // TreeSet = sorted set; iterate low→high for upward sweep
    private TreeSet<Integer> downStops; // TreeSet = sorted set; iterate high→low for downward sweep
    private int minFloor;             // private = lowest possible floor (bounds check)
    private int maxFloor;             // private = highest possible floor (bounds check)
    private List<ElevatorObserver> observers; // private = observer list; notified on floor arrival/state change

    public Elevator(int id, int minFloor, int maxFloor) {
        this.id = id;
        this.currentFloor = minFloor;
        this.state = ElevatorState.IDLE;
        this.upStops = new TreeSet<>();
        this.downStops = new TreeSet<>();
        this.minFloor = minFloor;
        this.maxFloor = maxFloor;
        this.observers = new ArrayList<>();
    }

    public void addObserver(ElevatorObserver observer) {
        observers.add(observer);
    }

    private void notifyFloorArrival() {
        for (ElevatorObserver o : observers) {
            o.onFloorArrival(id, currentFloor, state);
        }
    }

    private void notifyStateChange(ElevatorState oldState, ElevatorState newState) {
        for (ElevatorObserver o : observers) {
            o.onStateChange(id, oldState, newState);
        }
    }

    private void notifyDoorOpen() {
        for (ElevatorObserver o : observers) {
            o.onDoorOpen(id, currentFloor);
        }
    }

    /**
     * Adds a floor to the appropriate stop list based on SCAN algorithm.
     *
     * Decision logic:
     * - floor ABOVE current → must go UP to reach it → add to upStops
     * - floor BELOW current → must go DOWN to reach it → add to downStops
     * - floor == current → we're already here! → just open doors immediately
     */
    public void addStop(int floor) {
        if (state == ElevatorState.MAINTENANCE) return; // can't accept stops during maintenance

        if (floor > currentFloor) {
            // Floor is above us → add to upward sweep list
            upStops.add(floor);
        } else if (floor < currentFloor) {
            // Floor is below us → add to downward sweep list
            downStops.add(floor);
        } else {
            // floor == currentFloor → already here, just open doors
            notifyDoorOpen();
        }
    }

    /**
     * Convenience: adds both the pickup floor and destination floor as stops.
     */
    public void addRequest(Request request) {
        addStop(request.getSourceFloor());
        addStop(request.getDestinationFloor());
    }

    /**
     * step() = ONE tick of time. Called repeatedly by the system to simulate movement.
     *
     * Each call does ONE of:
     * - If IDLE: pick a direction (up if there are upStops, else down) and start moving
     * - If MOVING_UP: move one floor up, check if anyone wants to get off, switch if done
     * - If MOVING_DOWN: move one floor down, check if anyone wants to get off, switch if done
     *
     * Think of it like a game loop — each tick, the elevator moves one floor.
     */
    public void step() {
        if (state == ElevatorState.MAINTENANCE) return; // out of service

        // --- IDLE: decide which direction to start moving ---
        if (state == ElevatorState.IDLE) {
            if (!upStops.isEmpty()) {
                setState(ElevatorState.MOVING_UP);   // people waiting above → go up
            } else if (!downStops.isEmpty()) {
                setState(ElevatorState.MOVING_DOWN); // people waiting below → go down
            }
            // else: no stops anywhere → stay idle
            return;
        }

        // --- MOVING UP: advance one floor, check for stops ---
        if (state == ElevatorState.MOVING_UP) {
            currentFloor++;                          // physically move up one floor
            notifyFloorArrival();                    // tell observers we arrived at a new floor

            if (upStops.contains(currentFloor)) {   // someone pressed this floor
                upStops.remove(currentFloor);        // served! remove from queue
                notifyDoorOpen();                    // open doors for passengers
            }

            if (upStops.isEmpty()) {                 // no more floors to visit going up
                if (!downStops.isEmpty()) {
                    setState(ElevatorState.MOVING_DOWN); // switch to downward sweep
                } else {
                    setState(ElevatorState.IDLE);    // nothing left → rest
                }
            }
        }
        // --- MOVING DOWN: advance one floor down, check for stops ---
        else if (state == ElevatorState.MOVING_DOWN) {
            currentFloor--;                          // physically move down one floor
            notifyFloorArrival();

            if (downStops.contains(currentFloor)) {  // someone pressed this floor
                downStops.remove(currentFloor);      // served!
                notifyDoorOpen();
            }

            if (downStops.isEmpty()) {               // no more floors to visit going down
                if (!upStops.isEmpty()) {
                    setState(ElevatorState.MOVING_UP); // switch to upward sweep
                } else {
                    setState(ElevatorState.IDLE);
                }
            }
        }
    }

    private void setState(ElevatorState newState) {
        ElevatorState oldState = this.state;
        this.state = newState;
        notifyStateChange(oldState, newState);       // tell observers about direction change
    }

    public void setMaintenance(boolean maintenance) {
        if (maintenance) {
            setState(ElevatorState.MAINTENANCE);
            upStops.clear();                         // cancel all pending stops
            downStops.clear();
        } else {
            setState(ElevatorState.IDLE);            // return to service
        }
    }

    public int distanceTo(int floor) {
        return Math.abs(currentFloor - floor);
    }

    public boolean hasStops() {
        return !upStops.isEmpty() || !downStops.isEmpty();
    }

    public int getId() { return id; }
    public int getCurrentFloor() { return currentFloor; }
    public ElevatorState getState() { return state; }
    public int getPendingStops() { return upStops.size() + downStops.size(); }

    public String getStatus() {
        return "Elevator " + id + ": Floor " + currentFloor + " | " + state +
               " | Pending: " + getPendingStops();
    }
}

// model/ElevatorObserver.java — Observer pattern interface for elevator events
// DESIGN PATTERN: Observer
//
// WHO IMPLEMENTS THIS? → Display (in Display.java)
// WHO CALLS IT? → Elevator calls notifyFloorArrival/notifyStateChange/notifyDoorOpen
//                  which loops through all registered observers and calls these methods.
// WHY? → Decouples "elevator moved" from "show something on screen".
//         Tomorrow you could add SMSNotifier, LoggingObserver, etc. without touching Elevator.

interface ElevatorObserver {           // interface = contract; any observer MUST define these 3 methods
    void onFloorArrival(int elevatorId, int floor, ElevatorState state);
    void onStateChange(int elevatorId, ElevatorState oldState, ElevatorState newState);
    void onDoorOpen(int elevatorId, int floor);
}

// model/ElevatorState.java — Enum defining possible elevator states with availability checks

enum ElevatorState {                  // enum = fixed set of states; elevator can only be in one of these
    IDLE,
    MOVING_UP,
    MOVING_DOWN,
    MAINTENANCE;

    public boolean isAvailable() {
        return this != MAINTENANCE;
    }
}

// model/Request.java — Elevator request with source floor, destination, and direction

enum Direction {                      // enum = fixed set of directions; type-safe alternatives
    UP, DOWN, NONE
}

class Request {
    private int sourceFloor;          // private = only this class manages floor data
    private int destinationFloor;     // private = hidden from outside; accessed via getter
    private Direction direction;      // private = computed internally from floors

    public Request(int sourceFloor, int destinationFloor) {
        this.sourceFloor = sourceFloor;
        this.destinationFloor = destinationFloor;
        this.direction = destinationFloor > sourceFloor ? Direction.UP : Direction.DOWN;
    }

    public int getSourceFloor() { return sourceFloor; }
    public int getDestinationFloor() { return destinationFloor; }
    public Direction getDirection() { return direction; }

    @Override
    public String toString() {
        return "Request(Floor " + sourceFloor + " -> Floor " + destinationFloor + " " + direction + ")";
    }
}

// service/ElevatorSystem.java — Orchestrates multiple elevators, dispatches requests via strategy
// DESIGN PATTERN: Facade
//
// This is the FACADE: Main.java talks to ElevatorSystem, not individual elevators.
// ElevatorSystem decides WHICH elevator handles a request (via SchedulingStrategy)
// and advances time (via step()).

import java.util.ArrayList;
import java.util.List;

class ElevatorSystem {
    private List<Elevator> elevators; // private = the pool of elevator cars
    private SchedulingStrategy strategy; // private = swappable algorithm (Strategy pattern)
    private int totalFloors;          // private = building config

    public ElevatorSystem(int numElevators, int totalFloors) {
        this.totalFloors = totalFloors;
        this.elevators = new ArrayList<>();
        this.strategy = new SCANStrategy(); // default scheduling algorithm
        for (int i = 1; i <= numElevators; i++) {
            elevators.add(new Elevator(i, 0, totalFloors));
        }
    }

    public void setStrategy(SchedulingStrategy strategy) {
        this.strategy = strategy;    // swap scheduling algorithm at runtime
    }

    public void addObserverToAll(ElevatorObserver observer) {
        for (Elevator elevator : elevators) {
            elevator.addObserver(observer); // every elevator notifies this observer
        }
    }

    /**
     * Dispatches a request to the best elevator (chosen by the scheduling strategy).
     * The strategy scores all elevators and picks the one with the lowest cost.
     */
    public Elevator handleRequest(Request request) {
        Elevator selected = strategy.selectElevator(elevators, request);
        if (selected != null) {
            selected.addRequest(request); // adds source + destination floors to its stop list
        }
        return selected;
    }

    /**
     * step() = advance time by ONE tick. ALL elevators move one floor simultaneously.
     *
     * This is the simulation clock. In a real system this would be event-driven,
     * but for LLD interviews we use discrete ticks to make behavior deterministic and testable.
     *
     * Usage in Main.java:
     *   system.handleRequest(request);  // assign request to an elevator
     *   system.stepN(10);               // simulate 10 ticks of time passing
     *   // Now elevators have moved, picked up passengers, delivered them
     */
    public void step() {
        for (Elevator elevator : elevators) {
            elevator.step(); // each elevator moves one floor (see Elevator.step() for details)
        }
    }

    /** Convenience: run N ticks of simulation */
    public void stepN(int n) {
        for (int i = 0; i < n; i++) {
            step();
        }
    }

    public Elevator getElevator(int index) {
        return elevators.get(index);
    }

    public void setMaintenance(int elevatorIndex, boolean maintenance) {
        elevators.get(elevatorIndex).setMaintenance(maintenance);
    }

    public String getStatus() {
        StringBuilder sb = new StringBuilder();
        sb.append("Strategy: ").append(strategy.getName()).append("\n");
        for (Elevator elevator : elevators) {
            sb.append("  ").append(elevator.getStatus()).append("\n");
        }
        return sb.toString().trim();
    }

    public boolean allIdle() {
        for (Elevator e : elevators) {
            if (e.hasStops()) return false;
        }
        return true;
    }
}

// strategy/SchedulingStrategy.java — Strategy pattern interface for elevator dispatch algorithms
// DESIGN PATTERN: Strategy
//
// WHO IMPLEMENTS THIS? → SCANStrategy, LOOKStrategy (below in this file)
// WHO CALLS IT? → ElevatorSystem.handleRequest() calls strategy.selectElevator()
// WHY? → Different algorithms for "which elevator should serve this request?"
//         Swap strategies at runtime without changing ElevatorSystem code.

import java.util.List;

interface SchedulingStrategy {        // interface = contract; any scheduling algorithm MUST define these
    Elevator selectElevator(List<Elevator> elevators, Request request);
    String getName();
}

/**
 * SCAN Strategy: picks the elevator with the lowest "cost" to reach the request.
 *
 * Scoring:
 * - IDLE elevator → cost = pure distance to source floor
 * - Moving TOWARD the request (same direction, hasn't passed) → cost = distance
 * - Moving AWAY or opposite direction → cost = distance + 10 (penalty)
 *
 * Picks elevator with the lowest score.
 */
class SCANStrategy implements SchedulingStrategy { // implements = fulfills the strategy contract
    @Override
    public Elevator selectElevator(List<Elevator> elevators, Request request) {
        Elevator best = null;
        int bestScore = Integer.MAX_VALUE;

        for (Elevator elevator : elevators) {
            if (elevator.getState() == ElevatorState.MAINTENANCE) continue; // skip broken elevators

            int distance = elevator.distanceTo(request.getSourceFloor());
            int score = distance;

            // IDLE: just go there → pure distance
            if (elevator.getState() == ElevatorState.IDLE) {
                score = distance;
            }
            // Going UP, request is UP, and we haven't passed it yet → on the way!
            else if (elevator.getState() == ElevatorState.MOVING_UP && request.getDirection() == Direction.UP
                    && elevator.getCurrentFloor() <= request.getSourceFloor()) {
                score = distance;
            }
            // Going DOWN, request is DOWN, and we haven't passed it yet → on the way!
            else if (elevator.getState() == ElevatorState.MOVING_DOWN && request.getDirection() == Direction.DOWN
                    && elevator.getCurrentFloor() >= request.getSourceFloor()) {
                score = distance;
            }
            // Otherwise: must reverse or detour → penalty
            else {
                score = distance + 10;
            }

            if (score < bestScore) {
                bestScore = score;
                best = elevator;
            }
        }
        return best;
    }

    @Override
    public String getName() { return "SCAN"; }
}

/**
 * LOOK Strategy: Like SCAN but also factors in elevator LOAD (pending stops).
 * A busy elevator gets a higher penalty, spreading requests more evenly.
 *
 * Scoring:
 * - IDLE → pure distance
 * - Same direction and on the way → distance + pendingStops (load factor)
 * - Otherwise → distance + 20 + pendingStops (heavy penalty)
 */
class LOOKStrategy implements SchedulingStrategy { // implements = fulfills the strategy contract
    @Override
    public Elevator selectElevator(List<Elevator> elevators, Request request) {
        Elevator best = null;
        int bestScore = Integer.MAX_VALUE;

        for (Elevator elevator : elevators) {
            if (elevator.getState() == ElevatorState.MAINTENANCE) continue;

            int distance = elevator.distanceTo(request.getSourceFloor());
            int score;

            if (elevator.getState() == ElevatorState.IDLE) {
                score = distance;
            } else if ((elevator.getState() == ElevatorState.MOVING_UP && request.getDirection() == Direction.UP
                    && elevator.getCurrentFloor() <= request.getSourceFloor()) ||
                    (elevator.getState() == ElevatorState.MOVING_DOWN && request.getDirection() == Direction.DOWN
                    && elevator.getCurrentFloor() >= request.getSourceFloor())) {
                score = distance + elevator.getPendingStops(); // on the way but account for load
            } else {
                score = distance + 20 + elevator.getPendingStops(); // heavy penalty
            }

            if (score < bestScore) {
                bestScore = score;
                best = elevator;
            }
        }
        return best;
    }

    @Override
    public String getName() { return "LOOK"; }
}

