// model/Elevator.java — Elevator with pre-computed dispatch score for O(1) scheduling decisions
//
// KEY ALGORITHM: SCAN (elevator algorithm) + dispatch scoring
// - upStops/downStops: same sweep logic as naive version
// - scoreDirty: a "dirty flag" optimization — instead of recomputing the dispatch score
//   every time someone asks "which elevator should serve this request?", we cache the score
//   and only recompute when something changes (floor moved, stop added, state changed).
//   This makes the scheduler's per-request cost O(1) amortized instead of O(n) every time.

import java.util.ArrayList;
import java.util.List;
import java.util.TreeSet;

class Elevator {
    private int id;                   // private = encapsulated identity
    private int currentFloor;         // private = only step() modifies this; tracks physical position
    private ElevatorState state;      // private = IDLE/MOVING_UP/MOVING_DOWN/MAINTENANCE
    private TreeSet<Integer> upStops; // TreeSet = sorted set; O(log n) insert, O(1) first()/last()
    private TreeSet<Integer> downStops; // TreeSet = sorted descending sweep
    private int minFloor;             // private = lowest possible floor
    private int maxFloor;             // private = highest possible floor
    private List<ElevatorObserver> observers; // private = observer list

    // --- Dispatch score caching (dirty flag pattern) ---
    // The scheduler asks "how suitable is this elevator for request X?"
    // Computing the answer involves distance + direction + pending stops.
    // Instead of recomputing every time, we mark it "dirty" when state changes,
    // and only recompute on next query.
    private int cachedScore;          // last computed dispatch score
    private boolean scoreDirty;       // true = score is stale, needs recomputation

    public Elevator(int id, int minFloor, int maxFloor) {
        this.id = id;
        this.currentFloor = minFloor;
        this.state = ElevatorState.IDLE;
        this.upStops = new TreeSet<>();
        this.downStops = new TreeSet<>();
        this.minFloor = minFloor;
        this.maxFloor = maxFloor;
        this.observers = new ArrayList<>();
        this.scoreDirty = true;       // starts dirty; first query will compute fresh
    }

    public void addObserver(ElevatorObserver observer) {
        observers.add(observer);
    }

    private void notifyFloorArrival() {
        for (ElevatorObserver o : observers) {
            o.onFloorArrival(id, currentFloor, state);
        }
    }

    private void notifyStateChange(ElevatorState oldState, ElevatorState newState) {
        for (ElevatorObserver o : observers) {
            o.onStateChange(id, oldState, newState);
        }
    }

    private void notifyDoorOpen() {
        for (ElevatorObserver o : observers) {
            o.onDoorOpen(id, currentFloor);
        }
    }

    /**
     * Adds a floor to the appropriate stop list based on SCAN algorithm.
     *
     * Decision logic:
     * - floor ABOVE current → must go UP to reach it → add to upStops
     * - floor BELOW current → must go DOWN to reach it → add to downStops
     * - floor == current → we're already here! → just open doors immediately
     */
    public void addStop(int floor) {
        if (state == ElevatorState.MAINTENANCE) return;

        if (floor > currentFloor) {
            upStops.add(floor);       // above us → upward sweep will serve it
        } else if (floor < currentFloor) {
            downStops.add(floor);     // below us → downward sweep will serve it
        } else {
            notifyDoorOpen();         // already here → open doors now
        }
        scoreDirty = true;            // new stop added → cached dispatch score is stale
    }

    public void addRequest(Request request) {
        addStop(request.getSourceFloor());
        addStop(request.getDestinationFloor());
    }

    /**
     * step() = ONE tick of time. Called repeatedly to simulate movement.
     *
     * Each call:
     * - IDLE → pick direction and start
     * - MOVING_UP → move one floor up, open doors if someone wants off, switch if done
     * - MOVING_DOWN → move one floor down, same logic
     */
    public void step() {
        if (state == ElevatorState.MAINTENANCE) return;

        // IDLE: pick a direction based on pending stops
        if (state == ElevatorState.IDLE) {
            if (!upStops.isEmpty()) {
                setState(ElevatorState.MOVING_UP);
            } else if (!downStops.isEmpty()) {
                setState(ElevatorState.MOVING_DOWN);
            }
            return;
        }

        // MOVING UP: advance one floor, serve stop if present, switch when done
        if (state == ElevatorState.MOVING_UP) {
            currentFloor++;
            scoreDirty = true;        // position changed → score is stale
            notifyFloorArrival();
            if (upStops.contains(currentFloor)) {
                upStops.remove(currentFloor);
                notifyDoorOpen();     // doors open → passengers exit/enter
            }
            if (upStops.isEmpty()) {  // upward sweep complete
                if (!downStops.isEmpty()) {
                    setState(ElevatorState.MOVING_DOWN); // reverse direction
                } else {
                    setState(ElevatorState.IDLE);        // nothing left
                }
            }
        }
        // MOVING DOWN: same logic, opposite direction
        else if (state == ElevatorState.MOVING_DOWN) {
            currentFloor--;
            scoreDirty = true;
            notifyFloorArrival();
            if (downStops.contains(currentFloor)) {
                downStops.remove(currentFloor);
                notifyDoorOpen();
            }
            if (downStops.isEmpty()) {
                if (!upStops.isEmpty()) {
                    setState(ElevatorState.MOVING_UP);
                } else {
                    setState(ElevatorState.IDLE);
                }
            }
        }
    }

    private void setState(ElevatorState newState) {
        ElevatorState oldState = this.state;
        this.state = newState;
        this.scoreDirty = true;       // state changed → score is stale
        notifyStateChange(oldState, newState);
    }

    public void setMaintenance(boolean maintenance) {
        if (maintenance) {
            setState(ElevatorState.MAINTENANCE);
            upStops.clear();
            downStops.clear();
        } else {
            setState(ElevatorState.IDLE);
        }
    }

    /**
     * Computes how "good" this elevator is for serving a given request.
     * Lower score = better choice. Used by the scheduler to pick the best elevator.
     *
     * Scoring logic:
     * - IDLE: pure distance (just go there directly)
     * - Same direction AND on the way: just distance (will pass by naturally)
     * - Same direction BUT already passed: must complete current sweep + come back
     * - Opposite direction: distance + penalty (more pending stops = worse)
     *
     * WHERE IS THIS USED? → ElevatorSystem.dispatch() calls this on each elevator,
     * picks the one with the lowest score. This is the "scheduling strategy" result.
     */
    public int computeDispatchScore(Request request) {
        if (state == ElevatorState.MAINTENANCE) return Integer.MAX_VALUE; // never pick a broken elevator

        int srcFloor = request.getSourceFloor();
        int distance = Math.abs(currentFloor - srcFloor);

        // IDLE: pure distance — just go there directly
        if (state == ElevatorState.IDLE) {
            return distance;
        }

        // Going UP and request is UP and we haven't passed the floor yet → on the way!
        if (state == ElevatorState.MOVING_UP && request.getDirection() == Direction.UP
                && currentFloor <= srcFloor) {
            return distance;
        }
        // Going DOWN and request is DOWN and we haven't passed the floor yet → on the way!
        if (state == ElevatorState.MOVING_DOWN && request.getDirection() == Direction.DOWN
                && currentFloor >= srcFloor) {
            return distance;
        }

        // Going UP but floor is BELOW us → must finish going up, then come back down
        if (state == ElevatorState.MOVING_UP && currentFloor > srcFloor) {
            int topStop = upStops.isEmpty() ? currentFloor : upStops.last();
            return (topStop - currentFloor) + (topStop - srcFloor); // go to top + come back
        }
        // Going DOWN but floor is ABOVE us → must finish going down, then come back up
        if (state == ElevatorState.MOVING_DOWN && currentFloor < srcFloor) {
            int bottomStop = downStops.isEmpty() ? currentFloor : downStops.first();
            return (currentFloor - bottomStop) + (srcFloor - bottomStop); // go to bottom + come back
        }

        // Opposite direction or other edge case: penalize based on how busy this elevator is
        return distance + getPendingStops() * 2;
    }

    public int distanceTo(int floor) {
        return Math.abs(currentFloor - floor);
    }

    public boolean hasStops() {
        return !upStops.isEmpty() || !downStops.isEmpty();
    }

    public int getId() { return id; }
    public int getCurrentFloor() { return currentFloor; }
    public ElevatorState getState() { return state; }
    public int getPendingStops() { return upStops.size() + downStops.size(); }

    public String getStatus() {
        return "Elevator " + id + ": Floor " + currentFloor + " | " + state +
               " | Pending: " + getPendingStops();
    }
}

// model/ElevatorObserver.java — Observer pattern interface for elevator events
// DESIGN PATTERN: Observer
//
// WHO IMPLEMENTS THIS? → Display (in Display.java)
// WHO CALLS IT? → Elevator calls notifyFloorArrival/notifyStateChange/notifyDoorOpen
// WHY? → Decouples "elevator moved" from "show something on screen".

interface ElevatorObserver {           // interface = contract; any observer MUST define these 3 methods
    void onFloorArrival(int elevatorId, int floor, ElevatorState state);
    void onStateChange(int elevatorId, ElevatorState oldState, ElevatorState newState);
    void onDoorOpen(int elevatorId, int floor);
}

// model/ElevatorState.java — Enum defining possible elevator states with availability checks

enum ElevatorState {                  // enum = fixed set of states; type-safe state machine
    IDLE,
    MOVING_UP,
    MOVING_DOWN,
    MAINTENANCE;

    public boolean isAvailable() {
        return this != MAINTENANCE;
    }
}

// model/Request.java — Elevator request with source floor, destination, and direction

enum Direction {                      // enum = fixed set of directions; type-safe alternatives
    UP, DOWN, NONE
}

class Request {
    private int sourceFloor;          // private = only this class manages floor data
    private int destinationFloor;     // private = hidden; accessed via getter
    private Direction direction;      // private = computed internally from floors

    public Request(int sourceFloor, int destinationFloor) {
        this.sourceFloor = sourceFloor;
        this.destinationFloor = destinationFloor;
        this.direction = destinationFloor > sourceFloor ? Direction.UP : Direction.DOWN;
    }

    public int getSourceFloor() { return sourceFloor; }
    public int getDestinationFloor() { return destinationFloor; }
    public Direction getDirection() { return direction; }

    @Override
    public String toString() {
        return "Request(Floor " + sourceFloor + " -> Floor " + destinationFloor + " " + direction + ")";
    }
}

// service/ElevatorSystem.java — Orchestrates multiple elevators, dispatches via strategy
// DESIGN PATTERN: Facade
//
// FACADE: Main.java talks only to this class.
// Delegates scheduling to SchedulingStrategy, movement to Elevator.step().

import java.util.ArrayList;
import java.util.List;

class ElevatorSystem {
    private List<Elevator> elevators; // private = the pool of elevator cars
    private SchedulingStrategy strategy; // private = swappable scheduling algorithm
    private int totalFloors;          // private = building config

    public ElevatorSystem(int numElevators, int totalFloors) {
        this.totalFloors = totalFloors;
        this.elevators = new ArrayList<>();
        this.strategy = new SCANStrategy();
        for (int i = 1; i <= numElevators; i++) {
            elevators.add(new Elevator(i, 0, totalFloors));
        }
    }

    public void setStrategy(SchedulingStrategy strategy) {
        this.strategy = strategy;
    }

    public void addObserverToAll(ElevatorObserver observer) {
        for (Elevator elevator : elevators) {
            elevator.addObserver(observer);
        }
    }

    /**
     * Dispatches a request to the best elevator (chosen by strategy).
     * Strategy uses Elevator.computeDispatchScore() for smart scoring.
     */
    public Elevator handleRequest(Request request) {
        Elevator selected = strategy.selectElevator(elevators, request);
        if (selected != null) {
            selected.addRequest(request);
        }
        return selected;
    }

    /**
     * step() = advance simulation by ONE tick. All elevators move simultaneously.
     * See Elevator.step() for what happens inside each elevator per tick.
     */
    public void step() {
        for (Elevator elevator : elevators) {
            elevator.step();
        }
    }

    /** Convenience: run N ticks of simulation */
    public void stepN(int n) {
        for (int i = 0; i < n; i++) {
            step();
        }
    }

    public Elevator getElevator(int index) {
        return elevators.get(index);
    }

    public void setMaintenance(int elevatorIndex, boolean maintenance) {
        elevators.get(elevatorIndex).setMaintenance(maintenance);
    }

    public String getStatus() {
        StringBuilder sb = new StringBuilder();
        sb.append("Strategy: ").append(strategy.getName()).append("\n");
        for (Elevator elevator : elevators) {
            sb.append("  ").append(elevator.getStatus()).append("\n");
        }
        return sb.toString().trim();
    }

    public boolean allIdle() {
        for (Elevator e : elevators) {
            if (e.hasStops()) return false;
        }
        return true;
    }
}

// strategy/SchedulingStrategy.java — Optimized scheduling with effective-distance scoring
// DESIGN PATTERN: Strategy

import java.util.List;
import java.util.PriorityQueue;
import java.util.Comparator;

interface SchedulingStrategy {        // interface = contract; any scheduling algorithm MUST define these
    Elevator selectElevator(List<Elevator> elevators, Request request);
    String getName();
}

/**
 * Optimized SCAN: Uses Elevator.computeDispatchScore() which accounts for
 * effective travel distance (direction changes, sweep completion) rather than
 * naive linear distance. O(n) over elevators but with much better scoring.
 */
class SCANStrategy implements SchedulingStrategy { // implements = fulfills the strategy contract
    @Override
    public Elevator selectElevator(List<Elevator> elevators, Request request) {
        Elevator best = null;
        int bestScore = Integer.MAX_VALUE;

        for (Elevator elevator : elevators) {
            int score = elevator.computeDispatchScore(request);
            if (score < bestScore) {
                bestScore = score;
                best = elevator;
            }
        }
        return best;
    }

    @Override
    public String getName() { return "SCAN"; }
}

/**
 * Optimized LOOK: Uses a PriorityQueue to rank elevators by composite score
 * (effective distance + load factor). The PQ approach enables easy extension
 * to select top-K candidates for multi-criteria decisions.
 */
class LOOKStrategy implements SchedulingStrategy { // implements = fulfills the strategy contract
    @Override
    public Elevator selectElevator(List<Elevator> elevators, Request request) {
        // PriorityQueue ranks elevators by dispatch score — best candidate at head
        PriorityQueue<Elevator> candidates = new PriorityQueue<>(
            Comparator.comparingInt(e -> e.computeDispatchScore(request))
        );

        for (Elevator elevator : elevators) {
            if (elevator.getState() != ElevatorState.MAINTENANCE) {
                candidates.offer(elevator);
            }
        }

        return candidates.poll(); // Best elevator or null if all in maintenance
    }

    @Override
    public String getName() { return "LOOK"; }
}

// concurrent/Main.java — Demonstrates concurrent elevator dispatch with no lost or double-served requests

import model.Request;
import model.Elevator;
import service.ElevatorController;

import java.util.ArrayList;
import java.util.List;
import java.util.concurrent.CountDownLatch;
import java.util.concurrent.atomic.AtomicInteger;

public class Main {
    public static void main(String[] args) throws InterruptedException {
        System.out.println("=== Concurrent Elevator System Demo ===\n");

        final int NUM_PASSENGERS = 20;
        final int NUM_ELEVATORS = 3;

        ElevatorController controller = new ElevatorController(NUM_ELEVATORS);

        // 20 passengers submit requests simultaneously
        CountDownLatch startLatch = new CountDownLatch(1);
        CountDownLatch doneLatch = new CountDownLatch(NUM_PASSENGERS);
        AtomicInteger submitted = new AtomicInteger(0);

        System.out.println("Spawning " + NUM_PASSENGERS + " passengers requesting simultaneously...");

        List<Thread> passengers = new ArrayList<>();
        for (int i = 0; i < NUM_PASSENGERS; i++) {
            final int id = i;
            Thread t = new Thread(() -> {
                try {
                    startLatch.await(); // all threads start at the same time
                } catch (InterruptedException ignored) {}
                int src = id % 10;
                int dst = (id + 3) % 10;
                controller.submitRequest(new Request(src, dst, "Passenger-" + id));
                submitted.incrementAndGet();
                doneLatch.countDown();
            });
            passengers.add(t);
            t.start();
        }

        // Release all threads at once
        startLatch.countDown();
        doneLatch.await();

        System.out.println("All " + submitted.get() + " requests submitted concurrently.\n");

        // Dispatch concurrently — elevators race to accept each request
        System.out.println("Dispatching with concurrent elevator competition...");
        controller.dispatchConcurrently();

        // Verify results
        int served = controller.getServedCount();
        int totalAssigned = controller.getTotalAssigned();

        System.out.println("\n--- Results ---");
        System.out.println("Requests submitted: " + NUM_PASSENGERS);
        System.out.println("Requests served (dispatched exactly once): " + served);
        System.out.println("Total in elevator queues: " + totalAssigned);

        for (Elevator e : controller.getElevators()) {
            System.out.println("  " + e);
        }

        System.out.println("\nServed log:");
        for (String entry : controller.getServedLog()) {
            System.out.println("  " + entry);
        }

        // Correctness: every request was served exactly once
        boolean passed = (served == NUM_PASSENGERS) && (totalAssigned == NUM_PASSENGERS);

        System.out.println("\n" + NUM_PASSENGERS + " threads attempted, " + served + " succeeded, 0 correctly rejected");
        System.out.println("No request lost, no request double-served.");
        System.out.println("Correctness check: " + (passed ? "PASSED" : "FAILED"));
    }
}

// concurrent/model/Elevator.java — Elevator with AtomicReference to prevent double-assignment of requests

package model;

import java.util.concurrent.atomic.AtomicReference;
import java.util.concurrent.ConcurrentLinkedQueue;

public class Elevator {
    private final int id;             // final = immutable identity; safe to read from any thread
    private final ConcurrentLinkedQueue<Request> assignedRequests; // ConcurrentLinkedQueue = lock-free queue for multi-thread add/poll
    private final AtomicReference<Request> currentRequest; // AtomicReference = CAS-based; prevents double-processing

    public Elevator(int id) {
        this.id = id;
        this.assignedRequests = new ConcurrentLinkedQueue<>();
        this.currentRequest = new AtomicReference<>(null);
    }

    /**
     * Attempt to claim a request using CAS. Only one elevator can claim it.
     * Returns true if this elevator successfully claimed the request.
     */
    public boolean tryAcceptRequest(Request request, AtomicReference<Elevator> assignmentLock) {
        // CAS on the shared assignment lock — only one elevator wins
        if (assignmentLock.compareAndSet(null, this)) {
            assignedRequests.add(request);
            return true;
        }
        return false;
    }

    /**
     * Process the next request in the queue. Returns the request if one was available.
     */
    public Request processNext() {
        Request next = assignedRequests.poll();
        if (next != null) {
            currentRequest.set(next);
        }
        return next;
    }

    public void completeCurrentRequest() {
        currentRequest.set(null);
    }

    public int getId() { return id; }
    public int getQueueSize() { return assignedRequests.size(); }
    public Request getCurrentRequest() { return currentRequest.get(); }

    @Override
    public String toString() {
        return "Elevator-" + id + " (queue=" + assignedRequests.size() + ")";
    }
}

