// strategy/SearchStrategy.java — O(1) HashMap-indexed search by title, author, ISBN
// DESIGN PATTERN: Strategy

import java.util.ArrayList;
import java.util.HashMap;
import java.util.List;
import java.util.Map;

interface SearchStrategy {            // interface = contract; any search algorithm MUST define these
    List<Book> search(List<Book> books, String query);
    String getName();
    // Optimized strategies can pre-build indexes
    default void buildIndex(List<Book> books) {} // default = optional method; implementors can override or skip
}

/**
 * Optimized: Maintains a HashMap<lowercaseWord, List<Book>> index.
 * Searching is O(1) lookup instead of O(n) scan.
 */
class TitleSearch implements SearchStrategy { // implements = fulfills SearchStrategy contract
    private Map<String, List<Book>> index = new HashMap<>(); // HashMap = O(1) word-to-books lookup
    private boolean indexed = false;  // flag to lazily build index on first search

    @Override
    public void buildIndex(List<Book> books) {
        index.clear();
        for (Book book : books) {
            String[] words = book.getTitle().toLowerCase().split("\\s+");
            for (String word : words) {
                index.computeIfAbsent(word, k -> new ArrayList<>()).add(book);
            }
            // Also index the full title
            index.computeIfAbsent(book.getTitle().toLowerCase(), k -> new ArrayList<>()).add(book);
        }
        indexed = true;
    }

    @Override
    public List<Book> search(List<Book> books, String query) {
        if (!indexed) buildIndex(books);
        String lowerQuery = query.toLowerCase();
        // Try exact word match first (O(1))
        List<Book> result = index.get(lowerQuery);
        if (result != null) return new ArrayList<>(result);
        // Fallback: check partial matches from index keys
        List<Book> partial = new ArrayList<>();
        for (Map.Entry<String, List<Book>> entry : index.entrySet()) {
            if (entry.getKey().contains(lowerQuery)) {
                for (Book b : entry.getValue()) {
                    if (!partial.contains(b)) partial.add(b);
                }
            }
        }
        return partial;
    }

    @Override
    public String getName() { return "Title Search (Indexed)"; }
}

/**
 * Optimized: HashMap<authorNameLower, List<Book>> for O(1) author lookup.
 */
class AuthorSearch implements SearchStrategy { // implements = fulfills SearchStrategy contract
    private Map<String, List<Book>> index = new HashMap<>(); // HashMap = O(1) author-to-books lookup
    private boolean indexed = false;  // flag to lazily build index on first search

    @Override
    public void buildIndex(List<Book> books) {
        index.clear();
        for (Book book : books) {
            String key = book.getAuthor().toLowerCase();
            index.computeIfAbsent(key, k -> new ArrayList<>()).add(book);
            // Also index individual name parts
            String[] parts = key.split("\\s+");
            for (String part : parts) {
                index.computeIfAbsent(part, k -> new ArrayList<>()).add(book);
            }
        }
        indexed = true;
    }

    @Override
    public List<Book> search(List<Book> books, String query) {
        if (!indexed) buildIndex(books);
        String lowerQuery = query.toLowerCase();
        List<Book> result = index.get(lowerQuery);
        if (result != null) return new ArrayList<>(result);
        // Partial match fallback
        List<Book> partial = new ArrayList<>();
        for (Map.Entry<String, List<Book>> entry : index.entrySet()) {
            if (entry.getKey().contains(lowerQuery)) {
                for (Book b : entry.getValue()) {
                    if (!partial.contains(b)) partial.add(b);
                }
            }
        }
        return partial;
    }

    @Override
    public String getName() { return "Author Search (Indexed)"; }
}

/**
 * Optimized: HashMap<ISBN, Book> for O(1) exact lookup.
 */
class ISBNSearch implements SearchStrategy { // implements = fulfills SearchStrategy contract
    private Map<String, Book> index = new HashMap<>(); // HashMap = O(1) ISBN-to-book lookup
    private boolean indexed = false;  // flag to lazily build index on first search

    @Override
    public void buildIndex(List<Book> books) {
        index.clear();
        for (Book book : books) {
            index.put(book.getIsbn(), book);
        }
        indexed = true;
    }

    @Override
    public List<Book> search(List<Book> books, String query) {
        if (!indexed) buildIndex(books);
        List<Book> results = new ArrayList<>();
        Book found = index.get(query);
        if (found != null) results.add(found);
        return results;
    }

    @Override
    public String getName() { return "ISBN Search (Indexed)"; }
}

// concurrent/Main.java — 10 members try to borrow 3 available copies simultaneously, exactly 3 succeed

import model.Book;
import model.Member;
import service.Library;

import java.util.ArrayList;
import java.util.List;
import java.util.concurrent.CountDownLatch;
import java.util.concurrent.atomic.AtomicInteger;

public class Main {
    public static void main(String[] args) throws InterruptedException {
        System.out.println("=== Concurrent Library Management Demo ===\n");

        final int NUM_MEMBERS = 10;
        final int AVAILABLE_COPIES = 3;

        Library library = new Library();
        Book book = new Book("978-0132350884", "Clean Code", "Robert C. Martin", AVAILABLE_COPIES);
        library.addBook(book);

        System.out.println("Book: " + book);
        System.out.println("Members attempting to borrow: " + NUM_MEMBERS);
        System.out.println("Available copies: " + AVAILABLE_COPIES + "\n");

        CountDownLatch startLatch = new CountDownLatch(1);
        CountDownLatch doneLatch = new CountDownLatch(NUM_MEMBERS);
        AtomicInteger successCount = new AtomicInteger(0);
        AtomicInteger failCount = new AtomicInteger(0);

        List<Thread> threads = new ArrayList<>();
        for (int i = 0; i < NUM_MEMBERS; i++) {
            Member member = new Member(i, "Member-" + i);
            Thread t = new Thread(() -> {
                try {
                    startLatch.await();
                } catch (InterruptedException ignored) {}

                boolean success = library.borrowBook(member, book);
                if (success) {
                    successCount.incrementAndGet();
                    System.out.println("  [SUCCESS] " + member.getName() + " borrowed the book");
                } else {
                    failCount.incrementAndGet();
                    System.out.println("  [REJECTED] " + member.getName() + " — no copies available");
                }
                doneLatch.countDown();
            });
            threads.add(t);
            t.start();
        }

        // Release all threads simultaneously
        startLatch.countDown();
        doneLatch.await();

        System.out.println("\n--- Results ---");
        System.out.println("Book after all attempts: " + book);
        System.out.println("Available copies remaining: " + book.getAvailableCopies());

        int succeeded = successCount.get();
        int rejected = failCount.get();

        System.out.println("\n" + NUM_MEMBERS + " threads attempted, " + succeeded + " succeeded, " + rejected + " correctly rejected");

        boolean passed = (succeeded == AVAILABLE_COPIES) && (rejected == NUM_MEMBERS - AVAILABLE_COPIES)
                && (book.getAvailableCopies() == 0);
        System.out.println("Correctness check: " + (passed ? "PASSED" : "FAILED"));
    }
}

// concurrent/model/Book.java — Book with AtomicInteger for thread-safe available copy tracking

package model;

import java.util.concurrent.atomic.AtomicInteger;

public class Book {
    private final String isbn;        // final = immutable identity; safe publication to all threads
    private final String title;       // final = set once; no synchronization needed
    private final String author;      // final = set once; no synchronization needed
    private final AtomicInteger availableCopies; // AtomicInteger = CAS-based decrement prevents over-borrowing
    private final int totalCopies;    // final = never changes; reference value for capacity

    public Book(String isbn, String title, String author, int totalCopies) {
        this.isbn = isbn;
        this.title = title;
        this.author = author;
        this.totalCopies = totalCopies;
        this.availableCopies = new AtomicInteger(totalCopies);
    }

    /**
     * CAS-based borrow: decrementAndGet, if result < 0, rollback.
     * Returns true if borrow succeeded.
     */
    public boolean tryBorrow() {
        int remaining = availableCopies.decrementAndGet();
        if (remaining < 0) {
            // Rollback — no copies were actually available
            availableCopies.incrementAndGet();
            return false;
        }
        return true;
    }

    public void returnCopy() {
        availableCopies.incrementAndGet();
    }

    public String getIsbn() { return isbn; }
    public String getTitle() { return title; }
    public String getAuthor() { return author; }
    public int getAvailableCopies() { return availableCopies.get(); }
    public int getTotalCopies() { return totalCopies; }

    @Override
    public String toString() {
        return "Book(\"" + title + "\" available=" + availableCopies.get() + "/" + totalCopies + ")";
    }
}

// concurrent/model/Member.java — Library member identified by name

package model;

public class Member {
    private final String name;        // final = immutable; safe to read from any thread
    private final int id;             // final = immutable identity; no sync needed

    public Member(int id, String name) {
        this.id = id;
        this.name = name;
    }

    public String getName() { return name; }
    public int getId() { return id; }

    @Override
    public String toString() {
        return "Member(" + id + ", " + name + ")";
    }
}

// concurrent/service/Library.java — Library service with CAS-based concurrent borrow logic

package service;

import model.Book;
import model.Member;

import java.util.Collections;
import java.util.ArrayList;
import java.util.List;

public class Library {
    private final List<Book> books;   // final = reference won't change; books added at setup
    private final List<String> borrowLog; // synchronizedList = safe for concurrent appends from many threads

    public Library() {
        this.books = new ArrayList<>();
        this.borrowLog = Collections.synchronizedList(new ArrayList<>());
    }

    public void addBook(Book book) {
        books.add(book);
    }

    /**
     * Attempt to borrow a book. Uses CAS (AtomicInteger.decrementAndGet with rollback).
     * Returns true if the member successfully borrowed the book.
     */
    public boolean borrowBook(Member member, Book book) {
        boolean success = book.tryBorrow();
        if (success) {
            borrowLog.add(member.getName() + " borrowed \"" + book.getTitle() + "\"");
        }
        return success;
    }

    public void returnBook(Member member, Book book) {
        book.returnCopy();
        borrowLog.add(member.getName() + " returned \"" + book.getTitle() + "\"");
    }

    public List<String> getBorrowLog() { return borrowLog; }
}

