// model/Coin.java — Enum defining coin denominations with cent values

enum Coin {                           // enum = fixed set of coin types with associated values
    PENNY(1),
    NICKEL(5),
    DIME(10),
    QUARTER(25);

    private int valueInCents;         // private = each enum constant stores its cent value

    Coin(int valueInCents) {
        this.valueInCents = valueInCents;
    }

    public int getValue() { return valueInCents; }

    public static String formatCents(int cents) {
        return "$" + String.format("%.2f", cents / 100.0);
    }
}

// model/Inventory.java — Product stock management with add/remove/check operations

import java.util.HashMap;
import java.util.Map;
import java.util.ArrayList;
import java.util.List;

class Inventory {
    private Map<String, Product> products;  // private = internal product catalog
    private Map<String, Integer> quantities; // private = stock levels managed internally

    public Inventory() {
        this.products = new HashMap<>();
        this.quantities = new HashMap<>();
    }

    public void addProduct(Product product, int quantity) {
        products.put(product.getCode(), product);
        quantities.put(product.getCode(), quantities.getOrDefault(product.getCode(), 0) + quantity);
    }

    public Product getProduct(String code) {
        return products.get(code);
    }

    public boolean isAvailable(String code) {
        return quantities.getOrDefault(code, 0) > 0;
    }

    public boolean dispense(String code) {
        if (!isAvailable(code)) return false;
        quantities.put(code, quantities.get(code) - 1);
        return true;
    }

    public int getQuantity(String code) {
        return quantities.getOrDefault(code, 0);
    }

    public List<Product> getAllProducts() {
        return new ArrayList<>(products.values());
    }

    public String getDisplayInfo() {
        StringBuilder sb = new StringBuilder();
        for (Map.Entry<String, Product> entry : products.entrySet()) {
            Product p = entry.getValue();
            int qty = quantities.get(entry.getKey());
            sb.append("  ").append(p).append(" - Stock: ").append(qty);
            if (qty == 0) sb.append(" [SOLD OUT]");
            sb.append("\n");
        }
        return sb.toString().trim();
    }
}

// model/Product.java — Vendable product with name, price, and selection code

class Product {
    private String code;              // private = only this class manages the code
    private String name;              // private = encapsulated; accessed via getter
    private int priceInCents;         // private = price hidden; read via getter

    public Product(String code, String name, int priceInCents) {
        this.code = code;
        this.name = name;
        this.priceInCents = priceInCents;
    }

    public String getCode() { return code; }
    public String getName() { return name; }
    public int getPriceInCents() { return priceInCents; }

    @Override
    public String toString() {
        return code + ": " + name + " (" + Coin.formatCents(priceInCents) + ")";
    }
}

// service/ChangeCalculator.java — Formatting helpers for a change Map.
// (Algorithm itself lives in ChangeStrategy implementations.)

import java.util.Map;

class ChangeCalculator {

    public static String formatChange(Map<Coin, Integer> change) {
        if (change.isEmpty()) return "none";
        StringBuilder sb = new StringBuilder();
        boolean first = true;
        for (Map.Entry<Coin, Integer> e : change.entrySet()) {
            if (!first) sb.append(", ");
            sb.append(e.getValue()).append("× ").append(e.getKey().name());
            first = false;
        }
        return sb.toString();
    }

    public static int totalValue(Map<Coin, Integer> change) {
        int total = 0;
        for (Map.Entry<Coin, Integer> e : change.entrySet()) {
            total += e.getKey().getValue() * e.getValue();
        }
        return total;
    }
}

// service/ChangeStrategy.java — Strategy contract for change-making algorithms

import java.util.Map;

interface ChangeStrategy {
    /** Compute coin counts that sum to the requested amount in cents. */
    Map<Coin, Integer> calculateChange(int amountInCents);
}

// service/GreedyChangeStrategy.java — Greedy change-making (works for canonical coin systems)
//
// For US coin denominations (1, 5, 10, 25 cents) the greedy algorithm always
// returns the minimum-coin solution. For non-canonical systems (e.g. 1, 3, 4)
// it can be suboptimal — see DP-based strategies for those cases.

import java.util.LinkedHashMap;
import java.util.Map;

class GreedyChangeStrategy implements ChangeStrategy {

    private static final Coin[] DENOMINATIONS_DESC =
            {Coin.QUARTER, Coin.DIME, Coin.NICKEL, Coin.PENNY};

    @Override
    public Map<Coin, Integer> calculateChange(int amountInCents) {
        // Naive variant: still greedy, but uses a simple per-coin subtractive
        // loop. This is intentionally NOT modulo-based; the optimized
        // variant uses integer division + modulo for O(1) per denomination.
        Map<Coin, Integer> change = new LinkedHashMap<>();
        int remaining = amountInCents;
        for (Coin coin : DENOMINATIONS_DESC) {
            int count = 0;
            while (remaining >= coin.getValue()) {
                remaining -= coin.getValue();
                count++;
            }
            if (count > 0) change.put(coin, count);
        }
        return change;
    }
}

// service/LoggingObserver.java — Console logger; demonstrates observing vending events

class LoggingObserver implements VendingMachineObserver {
    @Override
    public void onProductDispensed(Product product, int changeReturnedCents) {
        System.out.println("  [event] sold: " + product.getName()
                + " (change=" + Coin.formatCents(changeReturnedCents) + ")");
    }

    @Override
    public void onLowStock(Product product, int remainingQuantity) {
        System.out.println("  [event] LOW STOCK: " + product.getName()
                + " has " + remainingQuantity + " left — restock soon");
    }

    @Override
    public void onSoldOut(Product product) {
        System.out.println("  [event] SOLD OUT: " + product.getName());
    }
}

// service/VendingMachine.java — State context with pluggable change strategy and observer fan-out

import java.util.ArrayList;
import java.util.List;

class VendingMachine {
    private State state;                    // current FSM state; changed via setState()
    private Inventory inventory;            // product stock managed internally
    private int insertedAmountInCents;      // total cents the user has inserted but not yet spent
    private Product selectedProduct;        // what the user chose; set during selection

    // Strategy: pluggable change-making algorithm.
    private ChangeStrategy changeStrategy;

    // Observer: fan-out for vending events (sales, low stock, sold out).
    private final List<VendingMachineObserver> observers = new ArrayList<>();

    /** Default ctor uses the greedy change strategy. */
    public VendingMachine() {
        this(new GreedyChangeStrategy());
    }

    /** Inject a different change strategy (e.g. for testing or alternative coin systems). */
    public VendingMachine(ChangeStrategy changeStrategy) {
        this.state = new IdleState();
        this.inventory = new Inventory();
        this.insertedAmountInCents = 0;
        this.selectedProduct = null;
        this.changeStrategy = changeStrategy;
    }

    public void insertCoin(Coin coin) {
        state.insertCoin(this, coin);
    }

    public void selectProduct(String productCode) {
        state.selectProduct(this, productCode);
    }

    public void cancel() {
        state.cancel(this);
    }

    void setState(State state) { this.state = state; }
    State getState() { return state; }

    void addInsertedAmount(int cents) { this.insertedAmountInCents += cents; }
    void deductInsertedAmount(int cents) { this.insertedAmountInCents -= cents; }
    void resetInsertedAmount() { this.insertedAmountInCents = 0; }
    int getInsertedAmount() { return insertedAmountInCents; }

    void setSelectedProduct(Product product) { this.selectedProduct = product; }
    Product getSelectedProduct() { return selectedProduct; }
    Inventory getInventory() { return inventory; }

    ChangeStrategy getChangeStrategy() { return changeStrategy; }
    public void setChangeStrategy(ChangeStrategy strategy) { this.changeStrategy = strategy; }

    // === Observer plumbing ===

    public void addObserver(VendingMachineObserver observer) { observers.add(observer); }
    public void removeObserver(VendingMachineObserver observer) { observers.remove(observer); }

    /** Threshold under which onLowStock fires after a successful dispense. */
    private static final int LOW_STOCK_THRESHOLD = 2;

    /** Called by DispensingState after a successful dispense. */
    void fireDispensed(Product product, int changeReturnedCents) {
        for (VendingMachineObserver o : observers) {
            o.onProductDispensed(product, changeReturnedCents);
        }
        int remaining = inventory.getQuantity(product.getCode());
        if (remaining == 0) {
            for (VendingMachineObserver o : observers) o.onSoldOut(product);
        } else if (remaining <= LOW_STOCK_THRESHOLD) {
            for (VendingMachineObserver o : observers) o.onLowStock(product, remaining);
        }
    }

    public String getStatus() {
        return "State: " + state.getName() + " | Inserted: " + Coin.formatCents(insertedAmountInCents);
    }
}

// service/VendingMachineObserver.java — Observer contract for vending events
//
// Subscribers receive notifications when business events happen inside the
// machine. Examples: a console logger, an analytics sink, a restock alert
// service. The machine fires events; observers decide what to do with them.

interface VendingMachineObserver {
    /** A product was successfully dispensed. */
    void onProductDispensed(Product product, int changeReturnedCents);

    /** A product's stock has fallen at or below the configured low-stock threshold. */
    void onLowStock(Product product, int remainingQuantity);

    /** A product just hit zero stock. */
    void onSoldOut(Product product);
}

// state/DispensingState.java — Dispensing product and returning change

import java.util.Map;

class DispensingState implements State {
    @Override
    public void insertCoin(VendingMachine machine, Coin coin) {
        System.out.println("  Please wait, dispensing in progress.");
    }

    @Override
    public void selectProduct(VendingMachine machine, String productCode) {
        System.out.println("  Please wait, dispensing in progress.");
    }

    @Override
    public void dispense(VendingMachine machine) {
        Product product = machine.getSelectedProduct();
        machine.getInventory().dispense(product.getCode());
        machine.deductInsertedAmount(product.getPriceInCents());

        System.out.println("  Dispensing " + product.getName() + "...");

        int changeAmount = machine.getInsertedAmount();
        if (changeAmount > 0) {
            Map<Coin, Integer> change = machine.getChangeStrategy().calculateChange(changeAmount);
            System.out.println("  Change returned: " + ChangeCalculator.formatChange(change) +
                    " (" + Coin.formatCents(changeAmount) + ")");
        } else {
            System.out.println("  Change: none (exact amount)");
        }

        machine.resetInsertedAmount();
        machine.setSelectedProduct(null);
        machine.setState(new IdleState());

        // Fire observer events AFTER state has settled, so listeners see consistent post-sale state.
        machine.fireDispensed(product, changeAmount);
    }

    @Override
    public void cancel(VendingMachine machine) {
        System.out.println("  Cannot cancel during dispensing.");
    }

    @Override
    public String getName() { return "DISPENSING"; }
}

