// concurrent/Main.java — 10 threads buying product with stock=3, exactly 3 succeed

import model.Product;
import service.VendingMachine;

import java.util.ArrayList;
import java.util.List;
import java.util.concurrent.CountDownLatch;
import java.util.concurrent.atomic.AtomicInteger;

public class Main {
    public static void main(String[] args) throws InterruptedException {
        System.out.println("=== Concurrent Vending Machine Demo ===\n");

        final int NUM_BUYERS = 10;
        final int STOCK = 3;

        VendingMachine machine = new VendingMachine();
        Product cola = new Product("Cola", 1.50, STOCK);
        machine.addProduct(cola);

        System.out.println("Product: " + cola);
        System.out.println("Buyers attempting simultaneously: " + NUM_BUYERS + "\n");

        CountDownLatch startLatch = new CountDownLatch(1);
        CountDownLatch doneLatch = new CountDownLatch(NUM_BUYERS);
        AtomicInteger successCount = new AtomicInteger(0);
        AtomicInteger failCount = new AtomicInteger(0);

        List<Thread> threads = new ArrayList<>();
        for (int i = 0; i < NUM_BUYERS; i++) {
            final String userId = "User-" + i;
            Thread t = new Thread(() -> {
                try {
                    startLatch.await();
                } catch (InterruptedException ignored) {}

                boolean success = machine.purchase(userId, "Cola");
                if (success) {
                    successCount.incrementAndGet();
                    System.out.println("  [SUCCESS] " + userId + " got a Cola");
                } else {
                    failCount.incrementAndGet();
                    System.out.println("  [REJECTED] " + userId + " — out of stock");
                }
                doneLatch.countDown();
            });
            threads.add(t);
            t.start();
        }

        // Release all threads simultaneously
        startLatch.countDown();
        doneLatch.await();

        System.out.println("\n--- Results ---");
        System.out.println("Product after attempts: " + cola);
        System.out.println("Remaining stock: " + cola.getQuantity());

        int succeeded = successCount.get();
        int rejected = failCount.get();

        System.out.println("\n" + NUM_BUYERS + " threads attempted, " + succeeded + " succeeded, " + rejected + " correctly rejected");

        boolean passed = (succeeded == STOCK) && (rejected == NUM_BUYERS - STOCK) && (cola.getQuantity() == 0);
        System.out.println("Correctness check: " + (passed ? "PASSED" : "FAILED"));
    }
}

// concurrent/model/Product.java — Product with AtomicInteger stock for thread-safe vending

package model;

import java.util.concurrent.atomic.AtomicInteger;

public class Product {
    private final String name;              // immutable product identity — no sync needed
    private final double price;             // never changes after init — final ensures visibility
    private final AtomicInteger quantity;   // many buyers decrement concurrently — CAS loop prevents overselling

    public Product(String name, double price, int quantity) {
        this.name = name;
        this.price = price;
        this.quantity = new AtomicInteger(quantity);
    }

    /**
     * CAS-based purchase: try to decrement quantity.
     * Only succeeds if current quantity > 0.
     */
    public boolean tryPurchase() {
        while (true) {
            int current = quantity.get();
            if (current <= 0) {
                return false;
            }
            if (quantity.compareAndSet(current, current - 1)) {
                return true;
            }
            // CAS failed — another thread changed it, retry
        }
    }

    public String getName() { return name; }
    public double getPrice() { return price; }
    public int getQuantity() { return quantity.get(); }

    @Override
    public String toString() {
        return "Product(\"" + name + "\" price=$" + String.format("%.2f", price) + " stock=" + quantity.get() + ")";
    }
}

// concurrent/service/VendingMachine.java — Thread-safe vending with CAS on product quantity

package service;

import model.Product;

import java.util.Collections;
import java.util.ArrayList;
import java.util.List;
import java.util.concurrent.ConcurrentHashMap;

public class VendingMachine {
    private final ConcurrentHashMap<String, Product> products; // ConcurrentHashMap = thread-safe product lookup from many buyers
    private final List<String> transactionLog; // synchronizedList = safe for concurrent log appends

    public VendingMachine() {
        this.products = new ConcurrentHashMap<>();
        this.transactionLog = Collections.synchronizedList(new ArrayList<>());
    }

    public void addProduct(Product product) {
        products.put(product.getName(), product);
    }

    /**
     * Attempt to purchase a product. Uses CAS (AtomicInteger.compareAndSet loop).
     * Returns true if purchase succeeded (stock was available).
     */
    public boolean purchase(String userId, String productName) {
        Product product = products.get(productName);
        if (product == null) {
            transactionLog.add(userId + " FAILED — product not found: " + productName);
            return false;
        }

        boolean success = product.tryPurchase();
        if (success) {
            transactionLog.add(userId + " purchased \"" + productName + "\"");
        } else {
            transactionLog.add(userId + " REJECTED — out of stock: " + productName);
        }
        return success;
    }

    public Product getProduct(String name) { return products.get(name); }
    public List<String> getTransactionLog() { return transactionLog; }
}

