        System.out.println("After 2 ticks: " + intersection2.getStatus());

        System.out.println("EMERGENCY: Vehicle approaching from EW direction!");
        intersection2.emergencyOverride("EW");
        System.out.println("After override: " + intersection2.getStatus());

        intersection2.tick();
        intersection2.tick();
        System.out.println("During emergency (2 ticks): " + intersection2.getStatus());

        System.out.println("Emergency cleared.");
        intersection2.clearEmergency();
        System.out.println("After clear: " + intersection2.getStatus());

        for (int i = 0; i < 5; i++) {
            intersection2.tick();
        }
        System.out.println("After 5 more ticks: " + intersection2.getStatus());

        System.out.println("\n--- Test: Signal State Logic ---");
        System.out.println("GREEN.next() = " + SignalState.GREEN.next());
        System.out.println("YELLOW.next() = " + SignalState.YELLOW.next());
        System.out.println("RED.next() = " + SignalState.RED.next());

        System.out.println("\n=== All Tests Passed ===");
    }
}

// model/PedestrianSignal.java — Pedestrian crossing signal coordinated with traffic

enum PedestrianState {                // enum = fixed set of pedestrian signal states
    WALK, DONT_WALK, FLASHING
}

class PedestrianSignal implements SignalObserver { // implements = reacts to traffic signal changes
    private String id;                // private = signal identity
    private String crossingDirection; // private = which crossing this controls
    private PedestrianState state;    // private = updated via onSignalChange callback
    private String associatedSignalId; // private = links to the traffic signal it follows

    public PedestrianSignal(String id, String crossingDirection, String associatedSignalId) {
        this.id = id;
        this.crossingDirection = crossingDirection;
        this.state = PedestrianState.DONT_WALK;
        this.associatedSignalId = associatedSignalId;
    }

    @Override
    public void onSignalChange(String signalId, SignalState oldState, SignalState newState) {
        if (!signalId.equals(associatedSignalId)) return;
        switch (newState) {
            case GREEN:
                setState(PedestrianState.WALK);
                break;
            case YELLOW:
                setState(PedestrianState.FLASHING);
                break;
            case RED:
                setState(PedestrianState.DONT_WALK);
                break;
        }
    }

    private void setState(PedestrianState newState) {
        this.state = newState;
    }

    public PedestrianState getState() { return state; }
    public String getId() { return id; }

    @Override
    public String toString() {
        return id + " (" + crossingDirection + "): " + state;
    }
}

// model/SignalDisplay.java — Concrete observer that prints signal state changes

class SignalDisplay implements SignalObserver { // implements = fulfills the SignalObserver contract
    private String displayName;                // private = only this class manages its name

    public SignalDisplay(String displayName) {
        this.displayName = displayName;
    }

    @Override                                  // @Override = implementing the interface method
    public void onSignalChange(String signalId, SignalState oldState, SignalState newState) {
        System.out.println("  [" + displayName + "] " + signalId + ": " + oldState + " -> " + newState);
    }
}

// model/SignalObserver.java — Observer pattern interface for signal state changes
// DESIGN PATTERN: Observer
//
// WHO IMPLEMENTS THIS? → SignalDisplay (in SignalDisplay.java)
// WHO CALLS IT? → TrafficSignal calls notifyObservers() on state change
// WHY? → Decouples "signal changed" from "update display/log event".
//         New observers (e.g., analytics, pedestrian crossing) can be added without touching TrafficSignal.

interface SignalObserver {             // interface = contract; any observer MUST handle signal changes
    void onSignalChange(String signalId, SignalState oldState, SignalState newState);
}

// model/SignalState.java — Traffic signal states with transition logic

enum SignalState {                    // enum = fixed set of signal states; type-safe transitions
    RED("STOP"),
    YELLOW("CAUTION"),
    GREEN("GO");

    private String instruction;       // private = each enum constant has its own instruction text

    SignalState(String instruction) {
        this.instruction = instruction;
    }

    public String getInstruction() { return instruction; }

    public SignalState next() {
        switch (this) {
            case GREEN: return YELLOW;
            case YELLOW: return RED;
            case RED: return GREEN;
            default: return RED;
        }
    }
}

// model/SignalStateBehavior.java — State pattern: each signal phase is its own class
// with its own tick() transition logic and instruction text.
//
// Why this is the State pattern (and not just an enum-as-state):
//   - Each state is a separate class (RedState, YellowState, GreenState).
//   - Transitions are encoded inside the state's tick() method, not in a switch.
//   - The TrafficSignal context holds a reference to a SignalStateBehavior and
//     replaces it when the state advances — classic GoF State.

interface SignalStateBehavior {
    /** Advance one tick; return the next state (may be `this` if not yet transitioning). */
    SignalStateBehavior tick();

    /** Human-readable state name, e.g. "RED" / "YELLOW" / "GREEN". */
    String name();

    /** Driver-facing instruction for this phase. */
    String instruction();

    /** The matching SignalState enum value — used by observers and pedestrian signals. */
    SignalState asEnum();
}

/** Vehicles must stop. Transitions to GREEN on tick. */
class RedState implements SignalStateBehavior {
    @Override public SignalStateBehavior tick() { return new GreenState(); }
    @Override public String name() { return "RED"; }
    @Override public String instruction() { return "STOP"; }
    @Override public SignalState asEnum() { return SignalState.RED; }
}

/** Caution; transition imminent. Transitions to RED on tick. */
class YellowState implements SignalStateBehavior {
    @Override public SignalStateBehavior tick() { return new RedState(); }
    @Override public String name() { return "YELLOW"; }
    @Override public String instruction() { return "CAUTION"; }
    @Override public SignalState asEnum() { return SignalState.YELLOW; }
}

/** Vehicles may proceed. Transitions to YELLOW on tick. */
class GreenState implements SignalStateBehavior {
    @Override public SignalStateBehavior tick() { return new YellowState(); }
    @Override public String name() { return "GREEN"; }
    @Override public String instruction() { return "GO"; }
    @Override public SignalState asEnum() { return SignalState.GREEN; }
}

// model/Timer.java — Countdown timing for signal phases

class Timer {
    private int greenDuration;        // private = timing config hidden from outside
    private int yellowDuration;       // private = timing config hidden from outside
    private int currentTick;          // private = internal counter; managed via tick()/reset()

    public Timer(int greenDuration, int yellowDuration) {
        this.greenDuration = greenDuration;
        this.yellowDuration = yellowDuration;
        this.currentTick = 0;
    }

    public void tick() { currentTick++; }
    public void reset() { currentTick = 0; }

    public int getCycleDuration() { return greenDuration + yellowDuration; }
    public boolean isGreenExpired() { return currentTick >= greenDuration; }
    public boolean isYellowExpired() { return currentTick >= greenDuration + yellowDuration; }

    public int getCurrentTick() { return currentTick; }
    public int getGreenDuration() { return greenDuration; }
    public int getYellowDuration() { return yellowDuration; }
}

// model/TrafficSignal.java — Single traffic signal with observer notification
//
// Acts as the *Context* in the State pattern: holds a `SignalStateBehavior` and
// replaces it on every transition. The enum `SignalState` is kept as a lightweight
// value for observers (so they keep receiving an enum and don't need to depend on
// the state classes), and the matching enum is derived via behavior.asEnum().

import java.util.ArrayList;
import java.util.List;

class TrafficSignal {
    private String id;                // private = signal identity
    private String direction;         // private = which road direction this signal controls
    private SignalStateBehavior stateBehavior; // State pattern context: current state object
    private List<SignalObserver> observers;    // private = observer list managed internally

    public TrafficSignal(String id, String direction) {
        this.id = id;
        this.direction = direction;
        this.stateBehavior = new RedState();   // signals start RED for safety
        this.observers = new ArrayList<>();
    }

    public void addObserver(SignalObserver observer) {
        observers.add(observer);
    }

    /** Set state by enum — kept for backward compatibility with the Intersection mediator. */
    public void setState(SignalState newState) {
        SignalStateBehavior next;
        switch (newState) {
            case RED:    next = new RedState(); break;
            case YELLOW: next = new YellowState(); break;
            case GREEN:  next = new GreenState(); break;
            default:     throw new IllegalStateException("Unknown state: " + newState);
        }
        applyTransition(next);
    }

    /** Set state directly via the State pattern object. */
    public void setStateBehavior(SignalStateBehavior next) {
        applyTransition(next);
    }

    /** Advance using the State pattern: ask the current state for the next one. */
    public void advance() {
        applyTransition(stateBehavior.tick());
    }

    private void applyTransition(SignalStateBehavior next) {
        SignalState oldState = stateBehavior.asEnum();
        this.stateBehavior = next;
        SignalState newState = stateBehavior.asEnum();
        if (oldState != newState) {
            notifyObservers(oldState, newState);
        }
    }

    private void notifyObservers(SignalState oldState, SignalState newState) {
        for (SignalObserver observer : observers) {
            observer.onSignalChange(id, oldState, newState);
        }
    }

    /** Compatibility accessor: returns the enum value matching the current state object. */
    public SignalState getState() { return stateBehavior.asEnum(); }
    public SignalStateBehavior getStateBehavior() { return stateBehavior; }
    public String getId() { return id; }
    public String getDirection() { return direction; }

    @Override
    public String toString() {
        return direction + "=" + stateBehavior.name();
    }
}

// service/EmergencyOverride.java — Emergency vehicle preemption control

class EmergencyOverride {
    private boolean active;           // private = only activate()/deactivate() modify this
    private String priorityDirection; // private = which direction gets green during emergency

    public EmergencyOverride() {
        this.active = false;
        this.priorityDirection = null;
    }

    public void activate(String direction) {
        this.active = true;
        this.priorityDirection = direction;
    }

    public void deactivate() {
        this.active = false;
        this.priorityDirection = null;
    }

    public boolean isActive() { return active; }
    public String getPriorityDirection() { return priorityDirection; }
}

// service/Intersection.java — Configurable timing with per-direction durations and dynamic adjustment

import java.util.ArrayList;
import java.util.HashMap;
import java.util.List;
import java.util.Map;
import java.util.concurrent.Executors;
import java.util.concurrent.ScheduledExecutorService;
import java.util.concurrent.TimeUnit;

/**
 * Optimized: Each direction has configurable green/yellow duration.
 * Supports dynamic timing adjustment (e.g., longer green for busier roads).
 * Uses ScheduledExecutorService for real-time mode (disabled in test/tick mode).
 */
class Intersection {
    private String name;              // private = intersection identity
    private Map<String, TrafficSignal> signals; // HashMap = O(1) direction-to-signal lookup
    private List<PedestrianSignal> pedestrianSignals; // private = coordinated ped signals
    private Timer timer;              // private = phase timing logic
    private String currentGreenDirection; // private = which direction currently has green
    private String[] directionOrder;  // private = round-robin direction sequence
    private int currentDirectionIndex; // private = position in the direction cycle
    private EmergencyOverride emergencyOverride; // private = emergency preemption state
    // Per-direction configurable durations
    private Map<String, Integer> greenDurations; // HashMap = O(1) lookup of per-direction green time
    private Map<String, Integer> yellowDurations; // HashMap = O(1) lookup of per-direction yellow time
    private int defaultGreenDuration; // private = fallback when no per-direction config
    private int defaultYellowDuration; // private = fallback when no per-direction config
    private int tickCount;            // private = ticks elapsed in current phase
    private SignalState currentPhase; // private = GREEN or YELLOW within active direction
    // Optional real-time scheduler
    private ScheduledExecutorService scheduler; // ScheduledExecutorService = auto-ticks at fixed interval

    public Intersection(String name, int greenDuration, int yellowDuration) {
        this.name = name;
        this.signals = new HashMap<>();
        this.pedestrianSignals = new ArrayList<>();
        this.timer = new Timer(greenDuration, yellowDuration);
        this.emergencyOverride = new EmergencyOverride();
        this.defaultGreenDuration = greenDuration;
        this.defaultYellowDuration = yellowDuration;
        this.greenDurations = new HashMap<>();
        this.yellowDurations = new HashMap<>();
        this.tickCount = 0;
        this.currentDirectionIndex = 0;
    }

    public void addSignal(String direction) {
        TrafficSignal signal = new TrafficSignal(direction, direction);
        signals.put(direction, signal);
        greenDurations.put(direction, defaultGreenDuration);
        yellowDurations.put(direction, defaultYellowDuration);
    }

    /**
     * Dynamically adjust timing for a direction (e.g., based on traffic sensors).
     */
    public void setDirectionTiming(String direction, int green, int yellow) {
        greenDurations.put(direction, green);
        yellowDurations.put(direction, yellow);
    }

    public void addPedestrianSignal(PedestrianSignal pedSignal, String trafficDirection) {
        pedestrianSignals.add(pedSignal);
        TrafficSignal associated = signals.get(trafficDirection);
        if (associated != null) {
            associated.addObserver(pedSignal);
        }
    }

    public void initialize(String[] directionOrder) {
        this.directionOrder = directionOrder;
        this.currentDirectionIndex = 0;
        this.currentGreenDirection = directionOrder[0];
        this.currentPhase = SignalState.GREEN;
        this.tickCount = 0;

        for (Map.Entry<String, TrafficSignal> entry : signals.entrySet()) {
            if (entry.getKey().equals(currentGreenDirection)) {
                entry.getValue().setState(SignalState.GREEN);
            } else {
                entry.getValue().setState(SignalState.RED);
            }
        }
    }

    /**
     * Start real-time mode: signals change automatically based on timing.
     * For production use; tests use manual tick() calls.
     */
    public void startRealTime(long tickIntervalMs) {
        scheduler = Executors.newSingleThreadScheduledExecutor();
        scheduler.scheduleAtFixedRate(this::tick, tickIntervalMs, tickIntervalMs, TimeUnit.MILLISECONDS);
    }

    public void stopRealTime() {
        if (scheduler != null) {
            scheduler.shutdown();
            scheduler = null;
        }
    }

    public void tick() {
        if (emergencyOverride.isActive()) return;

        int currentGreen = greenDurations.getOrDefault(currentGreenDirection, defaultGreenDuration);
        int currentYellow = yellowDurations.getOrDefault(currentGreenDirection, defaultYellowDuration);

        tickCount++;
        if (currentPhase == SignalState.GREEN && tickCount >= currentGreen) {
            currentPhase = SignalState.YELLOW;
            signals.get(currentGreenDirection).setState(SignalState.YELLOW);
            tickCount = 0;
        } else if (currentPhase == SignalState.YELLOW && tickCount >= currentYellow) {
            signals.get(currentGreenDirection).setState(SignalState.RED);
            currentDirectionIndex = (currentDirectionIndex + 1) % directionOrder.length;
            currentGreenDirection = directionOrder[currentDirectionIndex];
            signals.get(currentGreenDirection).setState(SignalState.GREEN);
            currentPhase = SignalState.GREEN;
            tickCount = 0;
        }
    }

    public void emergencyOverride(String direction) {
        emergencyOverride.activate(direction);
        for (TrafficSignal signal : signals.values()) {
            signal.setState(SignalState.RED);
        }
        signals.get(direction).setState(SignalState.GREEN);
        currentGreenDirection = direction;
        currentPhase = SignalState.GREEN;
        tickCount = 0;
    }

    public void clearEmergency() {
        emergencyOverride.deactivate();
        for (int i = 0; i < directionOrder.length; i++) {
            if (directionOrder[i].equals(currentGreenDirection)) {
                currentDirectionIndex = i;
                break;
            }
        }
        tickCount = 0;
    }

    public TrafficSignal getSignal(String direction) { return signals.get(direction); }
    public List<PedestrianSignal> getPedestrianSignals() { return pedestrianSignals; }

    public String getStatus() {
        StringBuilder sb = new StringBuilder();
        for (String dir : directionOrder) {
            if (sb.length() > 0) sb.append(", ");
            sb.append(signals.get(dir));
        }
        return sb.toString();
    }
}

// concurrent/Main.java — Timer and emergency threads competing, verify no invalid state

import model.Signal;
import service.TrafficController;

import java.util.ArrayList;
import java.util.List;
import java.util.concurrent.CountDownLatch;

public class Main {
    public static void main(String[] args) throws InterruptedException {
        System.out.println("=== Concurrent Traffic Signal Demo ===\n");

        final int TIMER_CYCLES = 50;
        final int EMERGENCY_OVERRIDES = 30;

        TrafficController controller = new TrafficController();

        System.out.println("Initial state: " + controller.getNorthSouth() + ", " + controller.getEastWest());
        System.out.println("Timer cycles to run: " + TIMER_CYCLES);
        System.out.println("Emergency overrides to run: " + EMERGENCY_OVERRIDES + "\n");

        CountDownLatch startLatch = new CountDownLatch(1);
        CountDownLatch doneLatch = new CountDownLatch(2);

        // Timer thread — cycles the signals regularly
        Thread timerThread = new Thread(() -> {
            try {
                startLatch.await();
            } catch (InterruptedException ignored) {}
            for (int i = 0; i < TIMER_CYCLES; i++) {
                controller.timerCycle();
                try { Thread.sleep(1); } catch (InterruptedException ignored) {}
            }
            doneLatch.countDown();
        });

        // Emergency thread — randomly forces signals
        Thread emergencyThread = new Thread(() -> {
            try {
                startLatch.await();
            } catch (InterruptedException ignored) {}
            for (int i = 0; i < EMERGENCY_OVERRIDES; i++) {
                String direction = (i % 2 == 0) ? "NS" : "EW";
                controller.emergencyOverride(direction);
                try { Thread.sleep(1); } catch (InterruptedException ignored) {}
            }
            doneLatch.countDown();
        });

        timerThread.start();
        emergencyThread.start();

        // Release both threads simultaneously
        startLatch.countDown();
        doneLatch.await();

        // Print results
        System.out.println("--- Results ---");
        System.out.println("Timer transitions completed: " + controller.getTimerTransitions());
        System.out.println("Emergency overrides completed: " + controller.getEmergencyOverrides());
        System.out.println("Final state: " + controller.getNorthSouth() + ", " + controller.getEastWest());

        System.out.println("\nState log (last 10 entries):");
        List<String> log = controller.getStateLog();
        int start = Math.max(0, log.size() - 10);
        for (int i = start; i < log.size(); i++) {
            System.out.println("  " + log.get(i));
        }

        int totalAttempts = TIMER_CYCLES + EMERGENCY_OVERRIDES;
        int totalCompleted = controller.getTimerTransitions() + controller.getEmergencyOverrides();
        boolean passed = !controller.isInvalidStateDetected();

        System.out.println("\n" + totalAttempts + " threads attempted, " + totalCompleted + " succeeded, 0 correctly rejected");
        System.out.println("No two-green invalid state detected: " + passed);
        System.out.println("Correctness check: " + (passed ? "PASSED" : "FAILED"));
    }
}

// concurrent/model/Signal.java — Traffic signal with AtomicReference for thread-safe state transitions

package model;

import java.util.concurrent.atomic.AtomicReference;

public class Signal {
    public enum SignalState {         // enum = fixed states; only valid transitions allowed
        RED, YELLOW, GREEN
    }

    private final String name;        // final = immutable identity; safe to read from any thread
    private final AtomicReference<SignalState> state; // AtomicReference = CAS-based transitions prevent corrupt state

    public Signal(String name, SignalState initialState) {
        this.name = name;
        this.state = new AtomicReference<>(initialState);
    }

    /**
     * CAS-based state transition. Only succeeds if current state matches expected.
     * Prevents corruption when timer and emergency override race.
     */
    public boolean tryTransition(SignalState expected, SignalState newState) {
        return state.compareAndSet(expected, newState);
    }

    public void forceState(SignalState newState) {
        state.set(newState);
    }

    public SignalState getState() { return state.get(); }
    public String getName() { return name; }

    @Override
    public String toString() {
        return name + "=" + state.get();
    }
}

// concurrent/service/TrafficController.java — Intersection controller with ReentrantLock for multi-signal coordination

package service;

import model.Signal;
import model.Signal.SignalState;

import java.util.ArrayList;
import java.util.Collections;
import java.util.List;
import java.util.concurrent.locks.ReentrantLock;
import java.util.concurrent.atomic.AtomicInteger;

public class TrafficController {
    private final Signal northSouth;  // final = reference never changes; safe publication
    private final Signal eastWest;    // final = reference never changes; safe publication
    private final ReentrantLock intersectionLock; // ReentrantLock = ensures only one thread mutates both signals at once
    private final List<String> stateLog; // synchronizedList = thread-safe append from timer+emergency threads
    private final AtomicInteger timerTransitions; // AtomicInteger = lock-free counter for stats
    private final AtomicInteger emergencyOverrides; // AtomicInteger = lock-free counter for stats
    private volatile boolean invalidStateDetected; // volatile = written by one thread, readable by all immediately

    public TrafficController() {
        this.northSouth = new Signal("NorthSouth", SignalState.GREEN);
        this.eastWest = new Signal("EastWest", SignalState.RED);
        this.intersectionLock = new ReentrantLock();
        this.stateLog = Collections.synchronizedList(new ArrayList<>());
        this.timerTransitions = new AtomicInteger(0);
        this.emergencyOverrides = new AtomicInteger(0);
        this.invalidStateDetected = false;
    }

    /**
     * Timer-based signal cycle. Acquires intersection lock to ensure
     * no two greens exist simultaneously.
     */
    public void timerCycle() {
        intersectionLock.lock();
        try {
            // Current: NS=GREEN, EW=RED -> transition to NS=RED, EW=GREEN
            SignalState nsState = northSouth.getState();
            SignalState ewState = eastWest.getState();

            if (nsState == SignalState.GREEN && ewState == SignalState.RED) {
                northSouth.tryTransition(SignalState.GREEN, SignalState.YELLOW);
                northSouth.tryTransition(SignalState.YELLOW, SignalState.RED);
                eastWest.tryTransition(SignalState.RED, SignalState.GREEN);
            } else if (nsState == SignalState.RED && ewState == SignalState.GREEN) {
                eastWest.tryTransition(SignalState.GREEN, SignalState.YELLOW);
                eastWest.tryTransition(SignalState.YELLOW, SignalState.RED);
                northSouth.tryTransition(SignalState.RED, SignalState.GREEN);
            }
            timerTransitions.incrementAndGet();
            logState("TIMER");
            validateState();
        } finally {
            intersectionLock.unlock();
        }
    }

    /**
     * Emergency override — forces a specific signal to GREEN.
     * Must acquire the intersection lock to avoid two greens.
     */
    public void emergencyOverride(String direction) {
        intersectionLock.lock();
        try {
            if ("NS".equals(direction)) {
                eastWest.forceState(SignalState.RED);
                northSouth.forceState(SignalState.GREEN);
            } else {
                northSouth.forceState(SignalState.RED);
                eastWest.forceState(SignalState.GREEN);
            }
            emergencyOverrides.incrementAndGet();
            logState("EMERGENCY(" + direction + ")");
            validateState();
        } finally {
            intersectionLock.unlock();
        }
    }

    private void validateState() {
        SignalState ns = northSouth.getState();
        SignalState ew = eastWest.getState();
        if (ns == SignalState.GREEN && ew == SignalState.GREEN) {
            invalidStateDetected = true;
            stateLog.add("!!! INVALID: Both signals GREEN !!!");
        }
    }

    private void logState(String trigger) {
        stateLog.add(trigger + " -> [" + northSouth + ", " + eastWest + "]");
    }

    public Signal getNorthSouth() { return northSouth; }
    public Signal getEastWest() { return eastWest; }
    public List<String> getStateLog() { return stateLog; }
    public int getTimerTransitions() { return timerTransitions.get(); }
    public int getEmergencyOverrides() { return emergencyOverrides.get(); }
    public boolean isInvalidStateDetected() { return invalidStateDetected; }
}

