// model/Board.java — NxN game grid managing cell state

class Board {
    private Symbol[][] grid;            // private = grid hidden; access only via placeSymbol/getSymbolAt
    private int size;                   // private = board dimension fixed at construction
    private int filledCount;            // private = internal counter to detect draw quickly

    public Board(int size) {
        this.size = size;
        this.grid = new Symbol[size][size];
        this.filledCount = 0;
    }

    public boolean placeSymbol(int row, int col, Symbol symbol) {
        if (!isValidPosition(row, col)) return false;
        if (grid[row][col] != null) return false;
        grid[row][col] = symbol;
        filledCount++;
        return true;
    }

    public boolean removeSymbol(int row, int col) {
        if (!isValidPosition(row, col)) return false;
        if (grid[row][col] == null) return false;
        grid[row][col] = null;
        filledCount--;
        return true;
    }

    public Symbol getSymbolAt(int row, int col) {
        if (!isValidPosition(row, col)) return null;
        return grid[row][col];
    }

    public boolean isValidPosition(int row, int col) {
        return row >= 0 && row < size && col >= 0 && col < size;
    }

    public boolean isEmpty(int row, int col) {
        return isValidPosition(row, col) && grid[row][col] == null;
    }

    public boolean isFull() { return filledCount == size * size; }
    public int getSize() { return size; }

    public String display() {
        StringBuilder sb = new StringBuilder();
        for (int r = 0; r < size; r++) {
            for (int c = 0; c < size; c++) {
                if (c > 0) sb.append("|");
                sb.append(grid[r][c] == null ? " " : grid[r][c]);
            }
            sb.append("\n");
            if (r < size - 1) {
                for (int c = 0; c < size * 2 - 1; c++) sb.append("-");
                sb.append("\n");
            }
        }
        return sb.toString();
    }
}

// model/Move.java — Command pattern: execute/undo a move on the board

class Move {
    private int row;                    // private = move coordinates encapsulated
    private int col;                    // private = access via getCol()
    private Symbol symbol;              // private = which player's mark (X or O)
    private Board board;                // private = reference to board for execute/undo

    public Move(Board board, int row, int col, Symbol symbol) {
        this.board = board;
        this.row = row;
        this.col = col;
        this.symbol = symbol;
    }

    public boolean execute() { return board.placeSymbol(row, col, symbol); }
    public boolean undo() { return board.removeSymbol(row, col); }

    public int getRow() { return row; }
    public int getCol() { return col; }
    public Symbol getSymbol() { return symbol; }

    @Override                            // tells compiler: I'm replacing Object's toString
    public String toString() { return symbol + " at (" + row + "," + col + ")"; }
}

// model/Player.java — Abstract player with Human and AI implementations

import java.util.Random;

abstract class Player {                 // abstract = can't create Player directly; must be Human or AI
    protected String name;              // protected = subclasses (HumanPlayer, AIPlayer) can access
    protected Symbol symbol;            // protected = subclasses can read symbol directly

    public Player(String name, Symbol symbol) {
        this.name = name;
        this.symbol = symbol;
    }

    public abstract int[] getMove(Board board); // abstract = each subclass decides how to pick moves
    public String getName() { return name; }
    public Symbol getSymbol() { return symbol; }

    @Override                            // tells compiler: I'm replacing Object's toString
    public String toString() { return name + " (" + symbol + ")"; }
}

class HumanPlayer extends Player {      // extends = inherits from Player; provides human move logic
    private int[][] moves;              // private = predetermined move sequence hidden
    private int moveIndex;              // private = internal index into move sequence

    public HumanPlayer(String name, Symbol symbol, int[][] moves) {
        super(name, symbol);            // super = call parent Player's constructor
        this.moves = moves;
        this.moveIndex = 0;
    }

    @Override                            // tells compiler: I'm providing Player's abstract getMove
    public int[] getMove(Board board) {
        if (moveIndex < moves.length) return moves[moveIndex++];
        return null;
    }
}

class AIPlayer extends Player {          // extends = inherits from Player; provides random move logic
    private Random random;              // private = RNG encapsulated; only getMove uses it

    public AIPlayer(String name, Symbol symbol) {
        super(name, symbol);
        this.random = new Random();
    }

    public AIPlayer(String name, Symbol symbol, long seed) {
        super(name, symbol);
        this.random = new Random(seed);
    }

    @Override                            // tells compiler: I'm providing Player's abstract getMove
    public int[] getMove(Board board) {
        int size = board.getSize();
        int emptyCount = 0;
        for (int r = 0; r < size; r++)
            for (int c = 0; c < size; c++)
                if (board.isEmpty(r, c)) emptyCount++;
        if (emptyCount == 0) return null;

        int target = random.nextInt(emptyCount);
        int count = 0;
        for (int r = 0; r < size; r++)
            for (int c = 0; c < size; c++)
                if (board.isEmpty(r, c)) {
                    if (count == target) return new int[]{r, c};
                    count++;
                }
        return null;
    }
}

