// service/Game.java — Game controller with turn management, undo, win detection, observer fan-out

import java.util.ArrayList;
import java.util.List;
import java.util.Stack;

enum GameStatus {                       // enum = fixed set of game outcomes; safer than strings
    IN_PROGRESS, X_WINS, O_WINS, DRAW
}

class Game {
    private Board board;                // private = board managed internally by Game
    private Player player1;             // private = players set at construction
    private Player player2;             // private = players set at construction
    private Player currentPlayer;       // private = Game controls whose turn it is
    private Stack<Move> moveHistory;    // private = Stack for LIFO undo support
    private GameStatus status;          // private = only Game logic changes game state

    // Observer: fan-out for game events (move, win, draw).
    private final List<GameObserver> observers = new ArrayList<>();

    public Game(int boardSize, Player player1, Player player2) {
        this.board = new Board(boardSize);
        this.player1 = player1;
        this.player2 = player2;
        this.currentPlayer = player1;
        this.moveHistory = new Stack<>();
        this.status = GameStatus.IN_PROGRESS;
    }

    public boolean playTurn() {
        if (status != GameStatus.IN_PROGRESS) return false;
        int[] pos = currentPlayer.getMove(board);
        if (pos == null) return false;

        Move move = new Move(board, pos[0], pos[1], currentPlayer.getSymbol());
        if (!move.execute()) {
            System.out.println("  Invalid move: " + move);
            return false;
        }
        moveHistory.push(move);
        Player mover = currentPlayer;
        for (GameObserver o : observers) o.onMove(mover, pos[0], pos[1], mover.getSymbol());

        Symbol winner = WinChecker.checkWinner(board);
        if (winner != null) {
            status = (winner == Symbol.X) ? GameStatus.X_WINS : GameStatus.O_WINS;
            for (GameObserver o : observers) o.onWin(mover, winner);
            return true;
        }
        if (board.isFull()) {
            status = GameStatus.DRAW;
            for (GameObserver o : observers) o.onDraw();
            return true;
        }
        currentPlayer = (currentPlayer == player1) ? player2 : player1;
        return true;
    }

    public boolean undoLastMove() {
        if (moveHistory.isEmpty()) return false;
        Move lastMove = moveHistory.pop();
        lastMove.undo();
        status = GameStatus.IN_PROGRESS;
        currentPlayer = (currentPlayer == player1) ? player2 : player1;
        return true;
    }

    public void playFullGame(boolean verbose) {
        while (status == GameStatus.IN_PROGRESS) {
            boolean moved = playTurn();
            if (!moved) break;
            if (verbose && !moveHistory.isEmpty()) {
                Move last = moveHistory.peek();
                Player who = (currentPlayer == player1) ? player2 : player1;
                if (status != GameStatus.IN_PROGRESS) who = (currentPlayer == player1) ? player2 : player1;
                System.out.println("  " + who.getName() + " plays " + last);
            }
        }
    }

    public Board getBoard() { return board; }
    public GameStatus getStatus() { return status; }
    public Player getCurrentPlayer() { return currentPlayer; }
    public Stack<Move> getMoveHistory() { return moveHistory; }

    public String getStatusMessage() {
        switch (status) {
            case X_WINS: return "X wins!";
            case O_WINS: return "O wins!";
            case DRAW: return "Draw!";
            default: return "Game in progress";
        }
    }

    // === Observer plumbing ===
    public void addObserver(GameObserver observer) { observers.add(observer); }
    public void removeObserver(GameObserver observer) { observers.remove(observer); }
}

// service/GameObserver.java — Observer contract for tic-tac-toe game events
//
// Subscribers receive notifications when moves are made and when the game
// reaches a terminal state (win/draw). Examples: a console logger, a UI
// renderer, an analytics sink.

interface GameObserver {
    /** A player just made a valid move at (row, col) using their symbol. */
    void onMove(Player player, int row, int col, Symbol symbol);

    /** A player has won the game. */
    void onWin(Player winner, Symbol symbol);

    /** The game ended in a draw (board full, no winner). */
    void onDraw();
}

// service/WinChecker.java — Full board scan to check winner (O(N) per check)

class WinChecker {

    public static Symbol checkWinner(Board board) { // static = utility; no instance state needed
        int size = board.getSize();

        // Check rows
        for (int r = 0; r < size; r++) {
            Symbol first = board.getSymbolAt(r, 0);
            if (first != null) {
                boolean win = true;
                for (int c = 1; c < size; c++) {
                    if (board.getSymbolAt(r, c) != first) { win = false; break; }
                }
                if (win) return first;
            }
        }

        // Check columns
        for (int c = 0; c < size; c++) {
            Symbol first = board.getSymbolAt(0, c);
            if (first != null) {
                boolean win = true;
                for (int r = 1; r < size; r++) {
                    if (board.getSymbolAt(r, c) != first) { win = false; break; }
                }
                if (win) return first;
            }
        }

        // Check main diagonal
        Symbol first = board.getSymbolAt(0, 0);
        if (first != null) {
            boolean win = true;
            for (int i = 1; i < size; i++) {
                if (board.getSymbolAt(i, i) != first) { win = false; break; }
            }
            if (win) return first;
        }

        // Check anti-diagonal
        first = board.getSymbolAt(0, size - 1);
        if (first != null) {
            boolean win = true;
            for (int i = 1; i < size; i++) {
                if (board.getSymbolAt(i, size - 1 - i) != first) { win = false; break; }
            }
            if (win) return first;
        }

        return null;
    }

    public static String getWinDescription(Board board) {
        int size = board.getSize();
        for (int r = 0; r < size; r++) {
            Symbol first = board.getSymbolAt(r, 0);
            if (first != null) {
                boolean win = true;
                for (int c = 1; c < size; c++) { if (board.getSymbolAt(r, c) != first) { win = false; break; } }
                if (win) return first + " wins (row " + r + ")";
            }
        }
        for (int c = 0; c < size; c++) {
            Symbol first = board.getSymbolAt(0, c);
            if (first != null) {
                boolean win = true;
                for (int r = 1; r < size; r++) { if (board.getSymbolAt(r, c) != first) { win = false; break; } }
                if (win) return first + " wins (column " + c + ")";
            }
        }
        Symbol d = board.getSymbolAt(0, 0);
        if (d != null) { boolean w = true; for (int i = 1; i < size; i++) { if (board.getSymbolAt(i, i) != d) { w = false; break; } } if (w) return d + " wins (main diagonal)"; }
        d = board.getSymbolAt(0, size - 1);
        if (d != null) { boolean w = true; for (int i = 1; i < size; i++) { if (board.getSymbolAt(i, size - 1 - i) != d) { w = false; break; } } if (w) return d + " wins (anti-diagonal)"; }
        return null;
    }
}

