// service/Game.java — Game controller using O(1) win check via board counters; observer fan-out

import java.util.ArrayList;
import java.util.List;
import java.util.Stack;

enum GameStatus {
    IN_PROGRESS, X_WINS, O_WINS, DRAW
}

/**
 * Optimized: After each move, uses Board.checkWinAt(row, col) for O(1) win check
 * instead of scanning the entire board.
 */
class Game {
    private Board board;
    private Player player1;
    private Player player2;
    private Player currentPlayer;
    private Stack<Move> moveHistory;    // Stack = LIFO; O(1) push/pop for undo support
    private GameStatus status;

    // Observer: fan-out for game events (move, win, draw).
    private final List<GameObserver> observers = new ArrayList<>();

    public Game(int boardSize, Player player1, Player player2) {
        this.board = new Board(boardSize);
        this.player1 = player1;
        this.player2 = player2;
        this.currentPlayer = player1;
        this.moveHistory = new Stack<>();
        this.status = GameStatus.IN_PROGRESS;
    }

    public boolean playTurn() {
        if (status != GameStatus.IN_PROGRESS) return false;
        int[] pos = currentPlayer.getMove(board);
        if (pos == null) return false;

        Move move = new Move(board, pos[0], pos[1], currentPlayer.getSymbol());
        if (!move.execute()) {
            System.out.println("  Invalid move: " + move);
            return false;
        }
        moveHistory.push(move);
        Player mover = currentPlayer;
        for (GameObserver o : observers) o.onMove(mover, pos[0], pos[1], mover.getSymbol());

        // O(1) win check using counters instead of full board scan
        Symbol winner = board.checkWinAt(pos[0], pos[1]);
        if (winner != null) {
            status = (winner == Symbol.X) ? GameStatus.X_WINS : GameStatus.O_WINS;
            for (GameObserver o : observers) o.onWin(mover, winner);
            return true;
        }
        if (board.isFull()) {
            status = GameStatus.DRAW;
            for (GameObserver o : observers) o.onDraw();
            return true;
        }
        currentPlayer = (currentPlayer == player1) ? player2 : player1;
        return true;
    }

    public boolean undoLastMove() {
        if (moveHistory.isEmpty()) return false;
        Move lastMove = moveHistory.pop();
        lastMove.undo();
        status = GameStatus.IN_PROGRESS;
        currentPlayer = (currentPlayer == player1) ? player2 : player1;
        return true;
    }

    public void playFullGame(boolean verbose) {
        while (status == GameStatus.IN_PROGRESS) {
            boolean moved = playTurn();
            if (!moved) break;
            if (verbose && !moveHistory.isEmpty()) {
                Move last = moveHistory.peek();
                Player who = (currentPlayer == player1) ? player2 : player1;
                if (status != GameStatus.IN_PROGRESS) who = (currentPlayer == player1) ? player2 : player1;
                System.out.println("  " + who.getName() + " plays " + last);
            }
        }
    }

    public Board getBoard() { return board; }
    public GameStatus getStatus() { return status; }
    public Player getCurrentPlayer() { return currentPlayer; }
    public Stack<Move> getMoveHistory() { return moveHistory; }

    public String getStatusMessage() {
        switch (status) {
            case X_WINS: return "X wins!";
            case O_WINS: return "O wins!";
            case DRAW: return "Draw!";
            default: return "Game in progress";
        }
    }

    // === Observer plumbing ===
    public void addObserver(GameObserver observer) { observers.add(observer); }
    public void removeObserver(GameObserver observer) { observers.remove(observer); }
}

// service/GameObserver.java — Observer contract for tic-tac-toe game events
//
// Subscribers receive notifications when moves are made and when the game
// reaches a terminal state (win/draw). Examples: a console logger, a UI
// renderer, an analytics sink.

interface GameObserver {
    /** A player just made a valid move at (row, col) using their symbol. */
    void onMove(Player player, int row, int col, Symbol symbol);

    /** A player has won the game. */
    void onWin(Player winner, Symbol symbol);

    /** The game ended in a draw (board full, no winner). */
    void onDraw();
}

// service/WinChecker.java — O(1) win detection using board counters

/**
 * Optimized: Uses Board's internal counters for O(1) win check.
 * The static checkWinner method still provides backward compatibility
 * by scanning, but Game uses checkWinAt() for O(1) after each move.
 */
class WinChecker {

    /**
     * Legacy full-scan method for compatibility with tests that call it directly.
     * In practice, Game uses Board.checkWinAt() for O(1).
     */
    public static Symbol checkWinner(Board board) {
        int size = board.getSize();
        // Use counter-based check for each possible line
        for (int r = 0; r < size; r++) {
            Symbol first = board.getSymbolAt(r, 0);
            if (first != null) {
                boolean win = true;
                for (int c = 1; c < size; c++) { if (board.getSymbolAt(r, c) != first) { win = false; break; } }
                if (win) return first;
            }
        }
        for (int c = 0; c < size; c++) {
            Symbol first = board.getSymbolAt(0, c);
            if (first != null) {
                boolean win = true;
                for (int r = 1; r < size; r++) { if (board.getSymbolAt(r, c) != first) { win = false; break; } }
                if (win) return first;
            }
        }
        Symbol d = board.getSymbolAt(0, 0);
        if (d != null) { boolean w = true; for (int i = 1; i < size; i++) { if (board.getSymbolAt(i, i) != d) { w = false; break; } } if (w) return d; }
        d = board.getSymbolAt(0, size - 1);
        if (d != null) { boolean w = true; for (int i = 1; i < size; i++) { if (board.getSymbolAt(i, size - 1 - i) != d) { w = false; break; } } if (w) return d; }
        return null;
    }

    public static String getWinDescription(Board board) {
        int size = board.getSize();
        for (int r = 0; r < size; r++) {
            Symbol first = board.getSymbolAt(r, 0);
            if (first != null) { boolean w = true; for (int c = 1; c < size; c++) { if (board.getSymbolAt(r, c) != first) { w = false; break; } } if (w) return first + " wins (row " + r + ")"; }
        }
        for (int c = 0; c < size; c++) {
            Symbol first = board.getSymbolAt(0, c);
            if (first != null) { boolean w = true; for (int r = 1; r < size; r++) { if (board.getSymbolAt(r, c) != first) { w = false; break; } } if (w) return first + " wins (column " + c + ")"; }
        }
        Symbol d = board.getSymbolAt(0, 0);
        if (d != null) { boolean w = true; for (int i = 1; i < size; i++) { if (board.getSymbolAt(i, i) != d) { w = false; break; } } if (w) return d + " wins (main diagonal)"; }
        d = board.getSymbolAt(0, size - 1);
        if (d != null) { boolean w = true; for (int i = 1; i < size; i++) { if (board.getSymbolAt(i, size - 1 - i) != d) { w = false; break; } } if (w) return d + " wins (anti-diagonal)"; }
        return null;
    }
}

// concurrent/Main.java — Rapid-fire moves from 2 threads, verify no cell overwritten

import model.Board;
import model.Board.Symbol;
import model.Player;
import service.Game;

import java.util.concurrent.CountDownLatch;
import java.util.concurrent.ThreadLocalRandom;

public class Main {
    public static void main(String[] args) throws InterruptedException {
        System.out.println("=== Concurrent Tic-Tac-Toe Demo ===\n");

        Board board = new Board(3);
        Player playerX = new Player("Alice", Symbol.X);
        Player playerO = new Player("Bob", Symbol.O);
        Game game = new Game(board, playerX, playerO);

        System.out.println("Players: " + playerX + " vs " + playerO);
        System.out.println("Both threads fire moves rapidly at all cells.\n");

        CountDownLatch startLatch = new CountDownLatch(1);
        CountDownLatch doneLatch = new CountDownLatch(2);

        // Player X thread — tries all cells rapidly
        Thread threadX = new Thread(() -> {
            try { startLatch.await(); } catch (InterruptedException ignored) {}
            for (int attempt = 0; attempt < 100 && !game.isGameOver(); attempt++) {
                int row = ThreadLocalRandom.current().nextInt(3);
                int col = ThreadLocalRandom.current().nextInt(3);
                game.attemptMove(playerX, row, col);
                Thread.yield();
            }
            doneLatch.countDown();
        });

        // Player O thread — tries all cells rapidly
        Thread threadO = new Thread(() -> {
            try { startLatch.await(); } catch (InterruptedException ignored) {}
            for (int attempt = 0; attempt < 100 && !game.isGameOver(); attempt++) {
                int row = ThreadLocalRandom.current().nextInt(3);
                int col = ThreadLocalRandom.current().nextInt(3);
                game.attemptMove(playerO, row, col);
                Thread.yield();
            }
            doneLatch.countDown();
        });

        threadX.start();
        threadO.start();
        startLatch.countDown();
        doneLatch.await();

        // Print results
        System.out.println("--- Results ---");
        System.out.println("Final board:");
        System.out.println(board);
        System.out.println("Game result: " + game.getResult());

        System.out.println("Move log:");
        for (String entry : game.getMoveLog()) {
            System.out.println("  " + entry);
        }

        // Verify no cell was overwritten
        boolean noOverwrite = verifyNoOverwrite(game);
        int totalAttempts = game.getSuccessfulMoves() + game.getRejectedMoves();

        System.out.println("\n" + totalAttempts + " threads attempted, " + game.getSuccessfulMoves()
                + " succeeded, " + game.getRejectedMoves() + " correctly rejected");
        System.out.println("No cell overwritten: " + noOverwrite);
        System.out.println("Correctness check: " + (noOverwrite ? "PASSED" : "FAILED"));
    }

    private static boolean verifyNoOverwrite(Game game) {
        // Each cell should have been placed at most once in the move log
        boolean[][] placed = new boolean[3][3];
        for (String entry : game.getMoveLog()) {
            // Parse "(row,col)" from log
            int openParen = entry.lastIndexOf('(');
            int comma = entry.indexOf(',', openParen);
            int closeParen = entry.indexOf(')', comma);
            int row = Integer.parseInt(entry.substring(openParen + 1, comma));
            int col = Integer.parseInt(entry.substring(comma + 1, closeParen));
            if (placed[row][col]) {
                return false; // overwritten!
            }
            placed[row][col] = true;
        }
        return true;
    }
}

// concurrent/model/Board.java — 3x3 board using AtomicReference[][] for CAS-based cell placement

package model;

import java.util.concurrent.atomic.AtomicReference;

public class Board {
    public enum Symbol { EMPTY, X, O }   // enum inside class = tightly coupled to Board usage

    private final AtomicReference<Symbol>[][] cells; // AtomicReference = CAS-based cell; prevents race on placement
    private final int size;              // final = immutable after construction; safe publication

    @SuppressWarnings("unchecked")
    public Board(int size) {
        this.size = size;
        this.cells = new AtomicReference[size][size];
        for (int r = 0; r < size; r++) {
            for (int c = 0; c < size; c++) {
                cells[r][c] = new AtomicReference<>(Symbol.EMPTY);
            }
        }
    }

    /**
     * CAS-based cell placement. Only succeeds if cell is EMPTY.
     * Prevents two players from placing on the same cell.
     */
    public boolean tryPlace(int row, int col, Symbol symbol) {
        if (row < 0 || row >= size || col < 0 || col >= size) return false;
        return cells[row][col].compareAndSet(Symbol.EMPTY, symbol); // CAS = atomic swap only if still EMPTY
    }

    public Symbol getCell(int row, int col) {
        return cells[row][col].get();
    }

    public int getSize() { return size; }

    public boolean isFull() {
        for (int r = 0; r < size; r++) {
            for (int c = 0; c < size; c++) {
                if (cells[r][c].get() == Symbol.EMPTY) return false;
            }
        }
        return true;
    }

    public Symbol checkWinner() {
        // Check rows
        for (int r = 0; r < size; r++) {
            Symbol first = cells[r][0].get();
            if (first != Symbol.EMPTY && first == cells[r][1].get() && first == cells[r][2].get()) {
                return first;
            }
        }
        // Check columns
        for (int c = 0; c < size; c++) {
            Symbol first = cells[0][c].get();
            if (first != Symbol.EMPTY && first == cells[1][c].get() && first == cells[2][c].get()) {
                return first;
            }
        }
        // Check diagonals
        Symbol center = cells[1][1].get();
        if (center != Symbol.EMPTY) {
            if (center == cells[0][0].get() && center == cells[2][2].get()) return center;
            if (center == cells[0][2].get() && center == cells[2][0].get()) return center;
        }
        return Symbol.EMPTY;
    }

    @Override
    public String toString() {
        StringBuilder sb = new StringBuilder();
        for (int r = 0; r < size; r++) {
            for (int c = 0; c < size; c++) {
                Symbol s = cells[r][c].get();
                sb.append(s == Symbol.EMPTY ? "." : s.name());
                if (c < size - 1) sb.append("|");
            }
            sb.append("\n");
        }
        return sb.toString();
    }
}

