// model/Pawn.java — Pawn: forward advance, diagonal capture, double first move

class Pawn extends Piece {              // extends = inherits from Piece; adds pawn-specific rules
    private boolean hasMoved;           // private = tracks whether double-move is still allowed

    public Pawn(Color color, Position position) { super(color, position); this.hasMoved = false; }

    @Override                            // tells compiler: I'm providing Piece's abstract method
    public boolean isValidMove(Position to, Board board) {
        int direction = (color == Color.WHITE) ? -1 : 1;
        int rowDiff = to.getRow() - position.getRow();
        int colDiff = Math.abs(to.getCol() - position.getCol());

        if (colDiff == 0) {
            if (rowDiff == direction) return board.getPieceAt(to) == null;
            if (!hasMoved && rowDiff == 2 * direction) {
                Position intermediate = new Position(position.getRow() + direction, position.getCol());
                return board.getPieceAt(intermediate) == null && board.getPieceAt(to) == null;
            }
        }
        if (colDiff == 1 && rowDiff == direction) {
            Piece target = board.getPieceAt(to);
            return target != null && target.getColor() != this.color;
        }
        return false;
    }

    public void markMoved() { this.hasMoved = true; }
    public boolean hasMoved() { return hasMoved; }

    @Override
    public char getSymbol() { return color == Color.WHITE ? 'P' : 'p'; }
    @Override
    public String getName() { return "Pawn"; }
}

// model/Piece.java — Abstract base for all chess pieces with movement validation

abstract class Piece {                  // abstract = can't create Piece directly; must be King, Queen, etc.
    protected Color color;              // protected = subclasses (Pawn, Rook...) can access directly
    protected Position position;        // protected = subclasses need position for move validation

    public Piece(Color color, Position position) { this.color = color; this.position = position; }

    public abstract boolean isValidMove(Position to, Board board); // abstract = each piece defines its own rules
    public abstract char getSymbol();   // abstract = each piece provides its own display char
    public abstract String getName();   // abstract = each piece provides its own name

    public Color getColor() { return color; }
    public Position getPosition() { return position; }
    public void setPosition(Position position) { this.position = position; }

    protected boolean isDiagonalMove(Position from, Position to) {
        return Math.abs(from.getRow() - to.getRow()) == Math.abs(from.getCol() - to.getCol());
    }

    protected boolean isStraightMove(Position from, Position to) {
        return from.getRow() == to.getRow() || from.getCol() == to.getCol();
    }

    protected boolean isPathClear(Position from, Position to, Board board) {
        int rowDir = Integer.signum(to.getRow() - from.getRow());
        int colDir = Integer.signum(to.getCol() - from.getCol());
        int r = from.getRow() + rowDir;
        int c = from.getCol() + colDir;
        while (r != to.getRow() || c != to.getCol()) {
            if (board.getPieceAt(new Position(r, c)) != null) return false;
            r += rowDir;
            c += colDir;
        }
        return true;
    }

    @Override                            // tells compiler: I'm replacing Object's toString
    public String toString() { return color + " " + getName() + " at " + position; }
}

