// service/Game.java — Chess game controller with turn management and check detection

import java.util.Stack;

class Game {
    private Board board;                // private = board managed internally
    private Player whitePlayer;         // private = player identity encapsulated
    private Player blackPlayer;         // private = player identity encapsulated
    private Color currentTurn;          // private = Game controls whose turn it is
    private Stack<Move> moveHistory;    // private = Stack for LIFO undo support
    private boolean gameOver;           // private = only Game sets game-over state
    private String result;              // private = result message set by Game logic

    public Game(Player white, Player black) {
        this.board = new Board();
        this.board.setupStandard();
        this.whitePlayer = white;
        this.blackPlayer = black;
        this.currentTurn = Color.WHITE;
        this.moveHistory = new Stack<>();
        this.gameOver = false;
    }

    public Game(Board board, Player white, Player black) {
        this.board = board;
        this.whitePlayer = white;
        this.blackPlayer = black;
        this.currentTurn = Color.WHITE;
        this.moveHistory = new Stack<>();
        this.gameOver = false;
    }

    public boolean makeMove(Position from, Position to) {
        if (gameOver) return false;
        if (!MoveValidator.isValidMove(board, from, to, currentTurn)) return false;

        Piece piece = board.getPieceAt(from);
        Piece captured = board.getPieceAt(to);
        Move move = new Move(from, to, piece, captured);
        moveHistory.push(move);

        board.setPieceAt(to, piece);
        board.removePiece(from);
        piece.setPosition(to);
        if (piece instanceof Pawn) ((Pawn) piece).markMoved();

        Color opponent = currentTurn.opposite();
        if (MoveValidator.isCheckmate(board, opponent)) {
            gameOver = true;
            result = currentTurn + " wins by checkmate!";
        }
        currentTurn = opponent;
        return true;
    }

    public boolean undoLastMove() {
        if (moveHistory.isEmpty()) return false;
        Move move = moveHistory.pop();
        Piece piece = move.getMovedPiece();
        board.setPieceAt(move.getFrom(), piece);
        piece.setPosition(move.getFrom());
        if (move.getCapturedPiece() != null) board.setPieceAt(move.getTo(), move.getCapturedPiece());
        else board.removePiece(move.getTo());
        currentTurn = currentTurn.opposite();
        gameOver = false;
        result = null;
        return true;
    }

    public Board getBoard() { return board; }
    public Color getCurrentTurn() { return currentTurn; }
    public boolean isGameOver() { return gameOver; }
    public String getResult() { return result; }
    public Stack<Move> getMoveHistory() { return moveHistory; }
    public boolean isInCheck() { return MoveValidator.isInCheck(board, currentTurn); }

    public String getCurrentStatus() {
        if (gameOver) return result;
        String status = currentTurn + "'s turn";
        if (isInCheck()) status += " (IN CHECK)";
        return status;
    }
}

// service/MoveValidator.java — Validates moves by iterating all pieces (naive linear scan)

import java.util.List;

class MoveValidator {

    public static boolean isValidMove(Board board, Position from, Position to, Color currentPlayer) { // static = stateless utility; no instance needed
        Piece piece = board.getPieceAt(from);
        if (piece == null) return false;
        if (piece.getColor() != currentPlayer) return false;
        Piece target = board.getPieceAt(to);
        if (target != null && target.getColor() == currentPlayer) return false;
        if (!piece.isValidMove(to, board)) return false;
        if (wouldBeInCheck(board, from, to, currentPlayer)) return false;
        return true;
    }

    public static boolean isInCheck(Board board, Color color) {
        Position kingPos = board.findKing(color);
        if (kingPos == null) return false;
        return isSquareAttacked(board, kingPos, color.opposite());
    }

    public static boolean isSquareAttacked(Board board, Position pos, Color attackingColor) {
        // Naive: iterate ALL pieces of attacking color
        List<Piece> attackers = board.getPieces(attackingColor);
        for (Piece attacker : attackers) {
            if (attacker.isValidMove(pos, board)) return true;
        }
        return false;
    }

    private static boolean wouldBeInCheck(Board board, Position from, Position to, Color color) {
        Piece moving = board.getPieceAt(from);
        Piece captured = board.getPieceAt(to);
        board.setPieceAt(to, moving);
        board.removePiece(from);
        Position originalPos = moving.getPosition();
        moving.setPosition(to);

        boolean inCheck = isInCheck(board, color);

        moving.setPosition(originalPos);
        board.setPieceAt(from, moving);
        board.setPieceAt(to, captured);
        return inCheck;
    }

    public static boolean isCheckmate(Board board, Color color) {
        if (!isInCheck(board, color)) return false;
        List<Piece> pieces = board.getPieces(color);
        for (Piece piece : pieces) {
            Position from = piece.getPosition();
            for (int r = 0; r < 8; r++) {
                for (int c = 0; c < 8; c++) {
                    Position to = new Position(r, c);
                    if (from.equals(to)) continue;
                    Piece target = board.getPieceAt(to);
                    if (target != null && target.getColor() == color) continue;
                    if (piece.isValidMove(to, board)) {
                        if (!wouldBeInCheck(board, from, to, color)) return false;
                    }
                }
            }
        }
        return true;
    }
}

