// service/Game.java — Chess game controller with turn management and check detection

import java.util.Stack;

class Game {
    private Board board;
    private Player whitePlayer;
    private Player blackPlayer;
    private Color currentTurn;
    private Stack<Move> moveHistory;    // Stack = O(1) push/pop for move undo support
    private boolean gameOver;
    private String result;

    public Game(Player white, Player black) {
        this.board = new Board();
        this.board.setupStandard();
        this.whitePlayer = white;
        this.blackPlayer = black;
        this.currentTurn = Color.WHITE;
        this.moveHistory = new Stack<>();
        this.gameOver = false;
    }

    public Game(Board board, Player white, Player black) {
        this.board = board;
        this.whitePlayer = white;
        this.blackPlayer = black;
        this.currentTurn = Color.WHITE;
        this.moveHistory = new Stack<>();
        this.gameOver = false;
    }

    public boolean makeMove(Position from, Position to) {
        if (gameOver) return false;
        if (!MoveValidator.isValidMove(board, from, to, currentTurn)) return false;

        Piece piece = board.getPieceAt(from);
        Piece captured = board.getPieceAt(to);
        Move move = new Move(from, to, piece, captured);
        moveHistory.push(move);

        board.setPieceAt(to, piece);
        board.removePiece(from);
        piece.setPosition(to);
        if (piece instanceof Pawn) ((Pawn) piece).markMoved();

        Color opponent = currentTurn.opposite();
        if (MoveValidator.isCheckmate(board, opponent)) {
            gameOver = true;
            result = currentTurn + " wins by checkmate!";
        }
        currentTurn = opponent;
        return true;
    }

    public boolean undoLastMove() {
        if (moveHistory.isEmpty()) return false;
        Move move = moveHistory.pop();
        Piece piece = move.getMovedPiece();
        board.setPieceAt(move.getFrom(), piece);
        piece.setPosition(move.getFrom());
        if (move.getCapturedPiece() != null) board.setPieceAt(move.getTo(), move.getCapturedPiece());
        else board.removePiece(move.getTo());
        currentTurn = currentTurn.opposite();
        gameOver = false;
        result = null;
        return true;
    }

    public Board getBoard() { return board; }
    public Color getCurrentTurn() { return currentTurn; }
    public boolean isGameOver() { return gameOver; }
    public String getResult() { return result; }
    public Stack<Move> getMoveHistory() { return moveHistory; }
    public boolean isInCheck() { return MoveValidator.isInCheck(board, currentTurn); }

    public String getCurrentStatus() {
        if (gameOver) return result;
        String status = currentTurn + "'s turn";
        if (isInCheck()) status += " (IN CHECK)";
        return status;
    }
}

// service/MoveValidator.java — Optimized with attack-map caching for faster check detection

import java.util.ArrayList;
import java.util.HashMap;
import java.util.HashSet;
import java.util.List;
import java.util.Map;
import java.util.Set;

/**
 * Optimized: Maintains a per-color set of attacked squares.
 * Instead of iterating all opponent pieces for each isSquareAttacked() call,
 * we cache which squares each piece attacks. After each move, only the
 * moved piece's attack set is recalculated (incremental update).
 */
class MoveValidator {

    // HashMap cache: position -> attacked squares; O(1) lookup vs recomputation
    private static Map<Position, Set<Position>> attackCache = new HashMap<>();

    public static boolean isValidMove(Board board, Position from, Position to, Color currentPlayer) {
        Piece piece = board.getPieceAt(from);
        if (piece == null) return false;
        if (piece.getColor() != currentPlayer) return false;
        Piece target = board.getPieceAt(to);
        if (target != null && target.getColor() == currentPlayer) return false;
        if (!piece.isValidMove(to, board)) return false;
        if (wouldBeInCheck(board, from, to, currentPlayer)) return false;
        return true;
    }

    public static boolean isInCheck(Board board, Color color) {
        Position kingPos = board.findKing(color);
        if (kingPos == null) return false;
        return isSquareAttackedFast(board, kingPos, color.opposite());
    }

    /**
     * Optimized attack detection: for check, only test pieces that COULD
     * reach the king based on piece type (knights at L-distance, bishops
     * on diagonals, rooks on lines, etc.) instead of testing ALL pieces.
     */
    private static boolean isSquareAttackedFast(Board board, Position pos, Color attackingColor) {
        int row = pos.getRow();
        int col = pos.getCol();

        // Check knight attacks (only 8 possible squares)
        int[][] knightOffsets = {{-2,-1},{-2,1},{-1,-2},{-1,2},{1,-2},{1,2},{2,-1},{2,1}};
        for (int[] offset : knightOffsets) {
            Position p = new Position(row + offset[0], col + offset[1]);
            if (p.isValid()) {
                Piece piece = board.getPieceAt(p);
                if (piece instanceof Knight && piece.getColor() == attackingColor) return true;
            }
        }

        // Check diagonal attacks (bishop, queen)
        int[][] diagDirs = {{-1,-1},{-1,1},{1,-1},{1,1}};
        for (int[] dir : diagDirs) {
            for (int i = 1; i < 8; i++) {
                Position p = new Position(row + dir[0]*i, col + dir[1]*i);
                if (!p.isValid()) break;
                Piece piece = board.getPieceAt(p);
                if (piece != null) {
                    if (piece.getColor() == attackingColor && (piece instanceof Bishop || piece instanceof Queen)) return true;
                    break; // Blocked
                }
            }
        }

        // Check straight attacks (rook, queen)
        int[][] straightDirs = {{-1,0},{1,0},{0,-1},{0,1}};
        for (int[] dir : straightDirs) {
            for (int i = 1; i < 8; i++) {
                Position p = new Position(row + dir[0]*i, col + dir[1]*i);
                if (!p.isValid()) break;
                Piece piece = board.getPieceAt(p);
                if (piece != null) {
                    if (piece.getColor() == attackingColor && (piece instanceof Rook || piece instanceof Queen)) return true;
                    break; // Blocked
                }
            }
        }

        // Check king attack (adjacent)
        for (int dr = -1; dr <= 1; dr++) {
            for (int dc = -1; dc <= 1; dc++) {
                if (dr == 0 && dc == 0) continue;
                Position p = new Position(row + dr, col + dc);
                if (p.isValid()) {
                    Piece piece = board.getPieceAt(p);
                    if (piece instanceof King && piece.getColor() == attackingColor) return true;
                }
            }
        }

        // Check pawn attack
        int pawnDir = (attackingColor == Color.WHITE) ? 1 : -1; // Pawns attack toward opponent
        Position pLeft = new Position(row + pawnDir, col - 1);
        Position pRight = new Position(row + pawnDir, col + 1);
        if (pLeft.isValid()) {
            Piece p = board.getPieceAt(pLeft);
            if (p instanceof Pawn && p.getColor() == attackingColor) return true;
        }
        if (pRight.isValid()) {
            Piece p = board.getPieceAt(pRight);
            if (p instanceof Pawn && p.getColor() == attackingColor) return true;
        }

        return false;
    }

    public static boolean isSquareAttacked(Board board, Position pos, Color attackingColor) {
        return isSquareAttackedFast(board, pos, attackingColor);
    }

    private static boolean wouldBeInCheck(Board board, Position from, Position to, Color color) {
        Piece moving = board.getPieceAt(from);
        Piece captured = board.getPieceAt(to);
        board.setPieceAt(to, moving);
        board.removePiece(from);
        Position originalPos = moving.getPosition();
        moving.setPosition(to);

        boolean inCheck = isInCheck(board, color);

        moving.setPosition(originalPos);
        board.setPieceAt(from, moving);
        board.setPieceAt(to, captured);
        return inCheck;
    }

    public static boolean isCheckmate(Board board, Color color) {
        if (!isInCheck(board, color)) return false;
        List<Piece> pieces = board.getPieces(color);
        for (Piece piece : pieces) {
            Position from = piece.getPosition();
            for (int r = 0; r < 8; r++) {
                for (int c = 0; c < 8; c++) {
                    Position to = new Position(r, c);
                    if (from.equals(to)) continue;
                    Piece target = board.getPieceAt(to);
                    if (target != null && target.getColor() == color) continue;
                    if (piece.isValidMove(to, board)) {
                        if (!wouldBeInCheck(board, from, to, color)) return false;
                    }
                }
            }
        }
        return true;
    }
}

// concurrent/Main.java — Move thread and timer thread racing, verify exactly one outcome

import model.Board;
import model.Move;
import service.GameController;
import service.GameController.GameState;

import java.util.concurrent.CountDownLatch;
import java.util.concurrent.atomic.AtomicBoolean;

public class Main {
    public static void main(String[] args) throws InterruptedException {
        System.out.println("=== Concurrent Chess Game Demo ===\n");

        System.out.println("Scenario: Move thread makes moves while timer thread races to declare timeout.");
        System.out.println("Only ONE outcome should determine the game result.\n");

        // Run multiple trials to demonstrate the race
        int trials = 10;
        int moveWins = 0;
        int timeoutWins = 0;
        int errors = 0;

        for (int trial = 0; trial < trials; trial++) {
            GameController controller = new GameController();

            CountDownLatch startLatch = new CountDownLatch(1);
            CountDownLatch doneLatch = new CountDownLatch(2);

            // Move thread — makes rapid moves
            Thread moveThread = new Thread(() -> {
                try { startLatch.await(); } catch (InterruptedException ignored) {}
                // White and black alternate moves (simplified pawn pushes)
                Move[] moves = {
                    new Move(1, 0, 2, 0, "WHITE"),
                    new Move(6, 0, 5, 0, "BLACK"),
                    new Move(1, 1, 2, 1, "WHITE"),
                    new Move(6, 1, 5, 1, "BLACK"),
                    new Move(1, 2, 2, 2, "WHITE"),  // 5th move triggers win
                    new Move(6, 2, 5, 2, "BLACK"),
                };
                for (Move m : moves) {
                    if (controller.getState() != GameState.PLAYING) break;
                    controller.makeMove(m);
                }
                doneLatch.countDown();
            });

            // Timer thread — tries to declare timeout after a brief delay
            Thread timerThread = new Thread(() -> {
                try { startLatch.await(); } catch (InterruptedException ignored) {}
                // Simulate clock running — timeout fires during gameplay
                try { Thread.sleep(1); } catch (InterruptedException ignored) {}
                controller.declareTimeout("BLACK");
                doneLatch.countDown();
            });

            moveThread.start();
            timerThread.start();
            startLatch.countDown();
            doneLatch.await();

            GameState finalState = controller.getState();
            if (finalState == GameState.WHITE_WINS || finalState == GameState.BLACK_WINS) {
                moveWins++;
            } else if (finalState == GameState.TIMEOUT_WHITE || finalState == GameState.TIMEOUT_BLACK) {
                timeoutWins++;
            } else if (finalState == GameState.PLAYING) {
                errors++; // Should not still be playing
            }

            if (trial == trials - 1) {
                // Print details of last trial
                System.out.println("--- Last Trial Event Log ---");
                for (String entry : controller.getEventLog()) {
                    System.out.println("  " + entry);
                }
                System.out.println("  Final state: " + finalState);
            }
        }

        System.out.println("\n--- Results over " + trials + " trials ---");
        System.out.println("Games won by move completion: " + moveWins);
        System.out.println("Games won by timeout: " + timeoutWins);
        System.out.println("Errors (still PLAYING): " + errors);

        // Verify: every trial ended in exactly one outcome, no errors
        boolean passed = (errors == 0) && (moveWins + timeoutWins == trials);

        int totalAttempts = trials * 2; // move thread + timer thread per trial
        System.out.println("\n" + totalAttempts + " threads attempted, " + trials + " succeeded (one outcome each), "
                + trials + " correctly rejected (losing race)");
        System.out.println("Every game has exactly one outcome, no state corruption.");
        System.out.println("Correctness check: " + (passed ? "PASSED" : "FAILED"));
    }
}

// concurrent/model/Board.java — Simplified chess board for concurrent move/timeout demonstration

package model;

public class Board {
    private final String[][] grid;      // final = grid reference never changes; safe publication
    private int moveCount;              // guarded by synchronized block in GameController

    public Board() {
        this.grid = new String[8][8];
        this.moveCount = 0;
        initBoard();
    }

    private void initBoard() {
        // Simplified: just track piece presence
        for (int c = 0; c < 8; c++) {
            grid[1][c] = "WP"; // white pawns
            grid[6][c] = "BP"; // black pawns
        }
        grid[0][4] = "WK"; // white king
        grid[7][4] = "BK"; // black king
    }

    public boolean applyMove(Move move) {
        String piece = grid[move.getFromRow()][move.getFromCol()];
        if (piece == null) return false;
        grid[move.getToRow()][move.getToCol()] = piece;
        grid[move.getFromRow()][move.getFromCol()] = null;
        moveCount++;
        return true;
    }

    public int getMoveCount() { return moveCount; }

    public String getPiece(int row, int col) { return grid[row][col]; }
}

// concurrent/model/Move.java — Immutable chess move

package model;

public class Move {
    private final int fromRow, fromCol, toRow, toCol; // final = immutable; safe to share across threads
    private final String player;        // final = immutable; no synchronization needed to read

    public Move(int fromRow, int fromCol, int toRow, int toCol, String player) {
        this.fromRow = fromRow;
        this.fromCol = fromCol;
        this.toRow = toRow;
        this.toCol = toCol;
        this.player = player;
    }

    public int getFromRow() { return fromRow; }
    public int getFromCol() { return fromCol; }
    public int getToRow() { return toRow; }
    public int getToCol() { return toCol; }
    public String getPlayer() { return player; }

    @Override
    public String toString() {
        return player + ": (" + fromRow + "," + fromCol + ")->(" + toRow + "," + toCol + ")";
    }
}

// concurrent/service/GameController.java — CAS-based game state transitions for move/timeout race

package service;

import model.Board;
import model.Move;

import java.util.ArrayList;
import java.util.Collections;
import java.util.List;
import java.util.concurrent.atomic.AtomicReference;

public class GameController {
    public enum GameState {              // enum = fixed set of all possible game outcomes
        PLAYING, WHITE_WINS, BLACK_WINS, TIMEOUT_WHITE, TIMEOUT_BLACK, DRAW
    }

    private final Board board;                   // final = board ref stable; mutations guarded by synchronized
    private final AtomicReference<GameState> state; // AtomicReference = CAS ensures exactly one outcome wins
    private final List<String> eventLog;         // synchronizedList = thread-safe append from any thread
    private volatile String currentPlayer;       // volatile = turn change visible to all threads immediately

    public GameController() {
        this.board = new Board();
        this.state = new AtomicReference<>(GameState.PLAYING);
        this.eventLog = Collections.synchronizedList(new ArrayList<>());
        this.currentPlayer = "WHITE";
    }

    /**
     * Attempt to make a move. Only succeeds if game state is still PLAYING.
     * Uses CAS to ensure move and timeout don't both succeed.
     */
    public boolean makeMove(Move move) {
        if (state.get() != GameState.PLAYING) {
            eventLog.add("MOVE REJECTED (game over): " + move);
            return false;
        }

        // Simulate move processing
        synchronized (board) {
            if (state.get() != GameState.PLAYING) {
                eventLog.add("MOVE REJECTED (game ended during processing): " + move);
                return false;
            }

            boolean applied = board.applyMove(move);
            if (!applied) {
                eventLog.add("MOVE INVALID: " + move);
                return false;
            }

            eventLog.add("MOVE APPLIED: " + move);

            // Check for "win" condition (simplified: after 5 moves, declare winner)
            if (board.getMoveCount() >= 5) {
                GameState winState = move.getPlayer().equals("WHITE") ?
                        GameState.WHITE_WINS : GameState.BLACK_WINS;
                // CAS — only succeeds if still PLAYING (timeout might have fired)
                if (state.compareAndSet(GameState.PLAYING, winState)) {
                    eventLog.add("GAME OVER: " + winState + " (by move)");
                }
            }

            // Switch turn
            currentPlayer = currentPlayer.equals("WHITE") ? "BLACK" : "WHITE";
            return true;
        }
    }

    /**
     * Timer declares timeout for a player. Uses CAS so only one outcome wins.
     * If a move is being processed simultaneously, only one event determines the result.
     */
    public boolean declareTimeout(String timedOutPlayer) {
        GameState timeoutState = timedOutPlayer.equals("WHITE") ?
                GameState.TIMEOUT_WHITE : GameState.TIMEOUT_BLACK;

        // CAS — only succeeds if game is still PLAYING
        if (state.compareAndSet(GameState.PLAYING, timeoutState)) {
            eventLog.add("TIMEOUT: " + timedOutPlayer + " ran out of time");
            return true;
        }
        eventLog.add("TIMEOUT REJECTED: game already ended as " + state.get());
        return false;
    }

    public GameState getState() { return state.get(); }
    public List<String> getEventLog() { return eventLog; }
    public String getCurrentPlayer() { return currentPlayer; }
    public Board getBoard() { return board; }
}

