// model/Bill.java — Aggregates room and service charges into a final invoice

import java.time.LocalDate;

class Bill {
    private Booking booking;            // private = booking reference encapsulated
    private double roomCharges;         // private = computed once in constructor
    private double serviceCharges;      // private = computed once in constructor
    private PricingStrategy pricingStrategy; // private = strategy used for price calculation

    public Bill(Booking booking, RoomService roomService, PricingStrategy pricingStrategy) {
        this.booking = booking;
        this.pricingStrategy = pricingStrategy;
        this.roomCharges = pricingStrategy.calculatePrice(booking.getRoom(), booking.getCheckInDate(), booking.getNights());
        this.serviceCharges = (roomService != null) ? roomService.getTotal() : 0;
    }

    public double getTotal() { return roomCharges + serviceCharges; }

    public String generateInvoice() {
        StringBuilder sb = new StringBuilder();
        sb.append("  Guest: ").append(booking.getGuest().getName()).append("\n");
        sb.append("  Room: ").append(booking.getRoom().getRoomNumber()).append(" (").append(booking.getRoom().getRoomType()).append(")\n");
        sb.append("  Period: ").append(booking.getCheckInDate()).append(" to ").append(booking.getCheckOutDate()).append("\n");
        sb.append("  Room Charges:    $").append(String.format("%.2f", roomCharges)).append("\n");
        sb.append("  Service Charges: $").append(String.format("%.2f", serviceCharges)).append("\n");
        sb.append("  TOTAL:           $").append(String.format("%.2f", getTotal()));
        return sb.toString();
    }
}

// model/Booking.java — Room reservation with guest, dates, and status

import java.time.LocalDate;

class Booking {
    private static int counter = 0;     // static = shared across all Bookings; generates unique IDs
    private String bookingId;           // private = ID hidden; access via getter
    private Guest guest;                // private = guest reference encapsulated
    private Room room;                  // private = room reference encapsulated
    private LocalDate checkInDate;      // private = date set at construction
    private LocalDate checkOutDate;     // private = computed from checkIn + nights
    private int nights;                 // private = duration set at construction
    private boolean checkedIn;          // private = only checkIn() can flip this
    private boolean checkedOut;         // private = only checkOut() can flip this

    public Booking(Guest guest, Room room, LocalDate checkInDate, int nights) {
        this.bookingId = "B-" + (++counter);
        this.guest = guest;
        this.room = room;
        this.checkInDate = checkInDate;
        this.checkOutDate = checkInDate.plusDays(nights);
        this.nights = nights;
        this.checkedIn = false;
        this.checkedOut = false;
    }

    public boolean checkIn() {
        if (checkedIn) return false;
        if (!room.setState(RoomState.OCCUPIED)) return false;
        checkedIn = true;
        return true;
    }

    public boolean checkOut() {
        if (!checkedIn || checkedOut) return false;
        if (!room.setState(RoomState.AVAILABLE)) return false;
        checkedOut = true;
        return true;
    }

    public String getBookingId() { return bookingId; }
    public Guest getGuest() { return guest; }
    public Room getRoom() { return room; }
    public LocalDate getCheckInDate() { return checkInDate; }
    public LocalDate getCheckOutDate() { return checkOutDate; }
    public int getNights() { return nights; }
    public boolean isCheckedIn() { return checkedIn; }
    public boolean isCheckedOut() { return checkedOut; }

    @Override
    public String toString() {
        return bookingId + ": " + guest.getName() + " -> Room " + room.getRoomNumber() +
               " (" + checkInDate + " to " + checkOutDate + ", " + nights + " nights)";
    }
    public static void resetCounter() { counter = 0; }
}

// model/Guest.java — Hotel guest with personal details

class Guest {
    private static int counter = 0;     // static = shared counter for unique guest IDs
    private String guestId;             // private = ID auto-generated; hidden from outside
    private String name;                // private = personal data encapsulated
    private String email;               // private = personal data encapsulated
    private String phone;               // private = personal data encapsulated

    public Guest(String name, String email, String phone) {
        this.guestId = "G-" + (++counter);
        this.name = name;
        this.email = email;
        this.phone = phone;
    }

    public String getGuestId() { return guestId; }
    public String getName() { return name; }
    public String getEmail() { return email; }

    @Override
    public String toString() { return name + " (" + guestId + ")"; }
    public static void resetCounter() { counter = 0; }
}

// model/Room.java — Hotel room with type, state, and pricing

abstract class Room {                   // abstract = can't create Room directly; must be Single/Double/Suite
    protected String roomNumber;        // protected = subclasses can access room number
    protected RoomState state;          // protected = subclasses can read state directly
    protected double basePrice;         // protected = subclasses set their own base price

    public Room(String roomNumber, double basePrice) {
        this.roomNumber = roomNumber;
        this.basePrice = basePrice;
        this.state = RoomState.AVAILABLE;
    }

    public boolean setState(RoomState newState) {
        if (state.canTransitionTo(newState)) { state = newState; return true; }
        return false;
    }

    public abstract String getRoomType(); // abstract = each subclass provides its own room type name
    public String getRoomNumber() { return roomNumber; }
    public RoomState getState() { return state; }
    public double getBasePrice() { return basePrice; }

    @Override
    public String toString() {
        return "Room " + roomNumber + " (" + getRoomType() + "): " + state + " - $" + String.format("%.0f", basePrice) + "/night";
    }
}

class SingleRoom extends Room {         // extends = inherits from Room; sets single-room price
    public SingleRoom(String roomNumber) { super(roomNumber, 100.0); }
    @Override public String getRoomType() { return "Single"; }
}

class DoubleRoom extends Room {         // extends = inherits from Room; sets double-room price
    public DoubleRoom(String roomNumber) { super(roomNumber, 150.0); }
    @Override public String getRoomType() { return "Double"; }
}

class Suite extends Room {              // extends = inherits from Room; sets suite price
    public Suite(String roomNumber) { super(roomNumber, 300.0); }
    @Override public String getRoomType() { return "Suite"; }
}

class RoomFactory {
    public static Room createRoom(String type, String roomNumber) { // static = factory; no instance needed
        switch (type.toUpperCase()) {
            case "SINGLE": return new SingleRoom(roomNumber);
            case "DOUBLE": return new DoubleRoom(roomNumber);
            case "SUITE": return new Suite(roomNumber);
            default: throw new IllegalArgumentException("Unknown room type: " + type);
        }
    }
}

// model/RoomState.java — Room lifecycle states with valid transitions

enum RoomState {                        // enum = fixed lifecycle states; prevents invalid string values
    AVAILABLE, BOOKED, OCCUPIED, MAINTENANCE;

    public boolean canTransitionTo(RoomState target) {
        switch (this) {
            case AVAILABLE: return target == BOOKED || target == MAINTENANCE;
            case BOOKED: return target == OCCUPIED || target == AVAILABLE;
            case OCCUPIED: return target == AVAILABLE;
            case MAINTENANCE: return target == AVAILABLE;
            default: return false;
        }
    }
}

// service/BookingObserver.java — Observer pattern interface for booking lifecycle events
// DESIGN PATTERN: Observer
//
// WHO IMPLEMENTS THIS? → NotificationService (in NotificationService.java)
// WHO CALLS IT? → Hotel calls observers on bookRoom(), checkIn(), checkOut()
// WHY? → Decouples "booking happened" from "notify guest/send email".
//         New listeners (e.g., analytics, loyalty points) can be added without changing Hotel code.

interface BookingObserver {            // interface = contract for event listeners (Observer pattern)
    void onBookingConfirmed(Booking booking);
    void onCheckIn(Booking booking);
    void onCheckOut(Booking booking);
}

// service/Hotel.java — Facade managing rooms, bookings, and check-in/out (linear room search)
// DESIGN PATTERN: Facade
//
// FACADE: Main.java talks only to this class.
// Uses BookingObserver (defined in BookingObserver.java) to notify on booking events.

import java.time.LocalDate;
import java.util.ArrayList;
import java.util.HashMap;
import java.util.List;
import java.util.Map;

class Hotel {
    private String name;                // private = hotel name encapsulated
    private List<Room> rooms;           // private = room list managed internally
    private List<Booking> bookings;     // private = booking history encapsulated
    private Map<String, RoomService> activeServices; // private = maps room# to active services
    private PricingStrategy pricingStrategy; // private = strategy swappable at runtime
    private List<BookingObserver> observers; // private = observer list for event notifications

    public Hotel(String name) {
        this.name = name;
        this.rooms = new ArrayList<>();
        this.bookings = new ArrayList<>();
        this.activeServices = new HashMap<>();
        this.pricingStrategy = new StandardPricing();
        this.observers = new ArrayList<>();
    }

    public void addObserver(BookingObserver observer) { observers.add(observer); }
    public void addRoom(Room room) { rooms.add(room); }
    public void addRoom(String type, String roomNumber) { rooms.add(RoomFactory.createRoom(type, roomNumber)); }
    public void setPricingStrategy(PricingStrategy strategy) { this.pricingStrategy = strategy; }

    // Linear scan to find available room
    public Room findAvailableRoom(String type) {
        for (Room room : rooms) {
            if (room.getRoomType().equalsIgnoreCase(type) && room.getState() == RoomState.AVAILABLE) return room;
        }
        return null;
    }

    public Booking bookRoom(Guest guest, String roomType, LocalDate checkIn, int nights) {
        Room room = findAvailableRoom(roomType);
        if (room == null) { System.out.println("  No " + roomType + " room available."); return null; }
        room.setState(RoomState.BOOKED);
        Booking booking = new Booking(guest, room, checkIn, nights);
        bookings.add(booking);
        for (BookingObserver obs : observers) obs.onBookingConfirmed(booking);
        return booking;
    }

    public boolean checkIn(Booking booking) {
        if (booking.checkIn()) {
            activeServices.put(booking.getRoom().getRoomNumber(), new RoomService(booking.getRoom().getRoomNumber()));
            for (BookingObserver obs : observers) obs.onCheckIn(booking);
            return true;
        }
        return false;
    }

    public Bill checkOut(Booking booking) {
        RoomService service = activeServices.get(booking.getRoom().getRoomNumber());
        if (booking.checkOut()) {
            activeServices.remove(booking.getRoom().getRoomNumber());
            for (BookingObserver obs : observers) obs.onCheckOut(booking);
            return new Bill(booking, service, pricingStrategy);
        }
        return null;
    }

    public void orderRoomService(String roomNumber, String item, double price) {
        RoomService service = activeServices.get(roomNumber);
        if (service != null) service.addOrder(item, price);
    }

    public void setRoomMaintenance(String roomNumber, boolean maintenance) {
        for (Room room : rooms) {
            if (room.getRoomNumber().equals(roomNumber)) {
                room.setState(maintenance ? RoomState.MAINTENANCE : RoomState.AVAILABLE);
                break;
            }
        }
    }

    public String getName() { return name; }
    public PricingStrategy getPricingStrategy() { return pricingStrategy; }

    public String getRoomStatus() {
        StringBuilder sb = new StringBuilder();
        for (Room room : rooms) sb.append("  ").append(room).append("\n");
        return sb.toString().trim();
    }
}

