        HotelService hotel = new HotelService();
        for (int i = 1; i <= NUM_ROOMS; i++) {
            hotel.addRoom(new Room(i, "DOUBLE", 150.0));
        }

        System.out.println("Hotel: " + NUM_ROOMS + " rooms available");
        System.out.println("Guests attempting to book simultaneously: " + NUM_GUESTS + "\n");

        CountDownLatch startLatch = new CountDownLatch(1);
        CountDownLatch doneLatch = new CountDownLatch(NUM_GUESTS);
        AtomicInteger successCount = new AtomicInteger(0);
        AtomicInteger failCount = new AtomicInteger(0);

        List<Thread> threads = new ArrayList<>();
        for (int i = 0; i < NUM_GUESTS; i++) {
            final String guestName = "Guest-" + i;
            Thread t = new Thread(() -> {
                try {
                    startLatch.await();
                } catch (InterruptedException ignored) {}

                Booking booking = hotel.bookRoom(guestName, "2026-05-13");
                if (booking != null) {
                    successCount.incrementAndGet();
                    System.out.println("  [SUCCESS] " + booking);
                } else {
                    failCount.incrementAndGet();
                    System.out.println("  [REJECTED] " + guestName + " — no rooms available");
                }
                doneLatch.countDown();
            });
            threads.add(t);
            t.start();
        }

        // Release all threads simultaneously
        startLatch.countDown();
        doneLatch.await();

        System.out.println("\n--- Results ---");
        System.out.println("Rooms booked: " + hotel.getBookedCount() + "/" + NUM_ROOMS);
        System.out.println("Rooms available: " + hotel.getAvailableCount());

        System.out.println("\nRoom status:");
        for (Room r : hotel.getRooms()) {
            System.out.println("  " + r);
        }

        int succeeded = successCount.get();
        int rejected = failCount.get();

        System.out.println("\n" + NUM_GUESTS + " threads attempted, " + succeeded + " succeeded, " + rejected + " correctly rejected");

        boolean passed = (succeeded == NUM_ROOMS) && (rejected == NUM_GUESTS - NUM_ROOMS)
                && (hotel.getBookedCount() == NUM_ROOMS);
        System.out.println("Correctness check: " + (passed ? "PASSED" : "FAILED"));
    }
}

// concurrent/model/Booking.java — Immutable booking record

package model;

public class Booking {
    private final String guestName;     // final = immutable; safe to share across threads without sync
    private final Room room;            // final = room ref never changes; safe publication
    private final String date;          // final = immutable; visible to all threads after construction

    public Booking(String guestName, Room room, String date) {
        this.guestName = guestName;
        this.room = room;
        this.date = date;
    }

    public String getGuestName() { return guestName; }
    public Room getRoom() { return room; }
    public String getDate() { return date; }

    @Override
    public String toString() {
        return "Booking(" + guestName + " -> Room-" + room.getNumber() + " on " + date + ")";
    }
}

// concurrent/model/Room.java — Hotel room with ReentrantLock for booking atomicity

package model;

import java.util.concurrent.locks.ReentrantLock;

public class Room {
    private final int number;           // final = room number never changes; safe publication
    private final String type;          // final = type immutable; safe to read from any thread
    private final double pricePerNight; // final = price set once; no sync needed to read
    private final ReentrantLock bookingLock; // ReentrantLock = ensures only one thread books at a time
    private volatile boolean booked;    // volatile = booking status visible to all threads immediately
    private volatile String bookedBy;   // volatile = guest name visible to all threads when set

    public Room(int number, String type, double pricePerNight) {
        this.number = number;
        this.type = type;
        this.pricePerNight = pricePerNight;
        this.bookingLock = new ReentrantLock();
        this.booked = false;
        this.bookedBy = null;
    }

    /**
     * Attempt to book this room. Uses ReentrantLock to ensure only one guest books it.
     * Returns true if booking succeeded.
     */
    public boolean tryBook(String guestName) {
        bookingLock.lock();
        try {
            if (booked) {
                return false;
            }
            booked = true;
            bookedBy = guestName;
            return true;
        } finally {
            bookingLock.unlock();
        }
    }

    public void release() {
        bookingLock.lock();
        try {
            booked = false;
            bookedBy = null;
        } finally {
            bookingLock.unlock();
        }
    }

    public int getNumber() { return number; }
    public String getType() { return type; }
    public double getPricePerNight() { return pricePerNight; }
    public boolean isBooked() { return booked; }
    public String getBookedBy() { return bookedBy; }
    public ReentrantLock getBookingLock() { return bookingLock; }

    @Override
    public String toString() {
        return "Room-" + number + "(" + type + ", " + (booked ? "booked by " + bookedBy : "available") + ")";
    }
}

// concurrent/service/HotelService.java — Hotel with ConcurrentHashMap for availability and per-room locking

package service;

import model.Booking;
import model.Room;

import java.util.ArrayList;
import java.util.Collections;
import java.util.List;
import java.util.concurrent.ConcurrentHashMap;

public class HotelService {
    private final List<Room> rooms;                  // final = room list ref stable; rooms added at setup
    private final ConcurrentHashMap<String, List<Booking>> bookingsByDate; // ConcurrentHashMap = thread-safe O(1) lookup by date
    private final List<String> bookingLog;           // synchronizedList = thread-safe append from any thread

    public HotelService() {
        this.rooms = new ArrayList<>();
        this.bookingsByDate = new ConcurrentHashMap<>();
        this.bookingLog = Collections.synchronizedList(new ArrayList<>());
    }

    public void addRoom(Room room) {
        rooms.add(room);
    }

    /**
     * Attempt to book any available room for a guest on a given date.
     * Uses per-room ReentrantLock to prevent two guests booking the last room.
     * Returns the Booking if successful, null otherwise.
     */
    public Booking bookRoom(String guestName, String date) {
        for (Room room : rooms) {
            if (room.tryBook(guestName)) {
                Booking booking = new Booking(guestName, room, date);
                bookingsByDate.computeIfAbsent(date, k ->
                    Collections.synchronizedList(new ArrayList<>())).add(booking);
                bookingLog.add(guestName + " booked Room-" + room.getNumber());
                return booking;
            }
        }
        bookingLog.add(guestName + " REJECTED — no rooms available");
        return null;
    }

    /**
     * Try to book a specific room.
     */
    public Booking bookSpecificRoom(String guestName, Room room, String date) {
        if (room.tryBook(guestName)) {
            Booking booking = new Booking(guestName, room, date);
            bookingsByDate.computeIfAbsent(date, k ->
                Collections.synchronizedList(new ArrayList<>())).add(booking);
            bookingLog.add(guestName + " booked Room-" + room.getNumber());
            return booking;
        }
        bookingLog.add(guestName + " REJECTED for Room-" + room.getNumber() + " — already booked");
        return null;
    }

    public List<Room> getRooms() { return rooms; }
    public List<String> getBookingLog() { return bookingLog; }

    public int getBookedCount() {
        int count = 0;
        for (Room r : rooms) {
            if (r.isBooked()) count++;
        }
        return count;
    }

    public int getAvailableCount() {
        return rooms.size() - getBookedCount();
    }
}

