// model/Booking.java — Confirmed ticket booking with cancellation support

import java.util.List;

enum BookingStatus { CONFIRMED, CANCELLED } // enum = fixed set of booking states; safer than strings

class Booking {
    private static int counter = 0;     // static = shared across all Bookings; auto-generates unique IDs
    private String bookingId;           // private = ID hidden; access via getter
    private String userId;              // private = user identity encapsulated
    private Show show;                  // private = show reference encapsulated
    private List<Seat> seats;           // private = booked seats list encapsulated
    private Payment payment;            // private = payment details encapsulated
    private BookingStatus status;       // private = only cancel() can change status

    public Booking(String userId, Show show, List<Seat> seats, Payment payment) {
        this.bookingId = "BK-" + (++counter); this.userId = userId; this.show = show; this.seats = seats; this.payment = payment; this.status = BookingStatus.CONFIRMED;
    }

    public boolean cancel() {
        if (status == BookingStatus.CANCELLED) return false;
        status = BookingStatus.CANCELLED;
        payment.refund();
        for (Seat seat : seats) show.setSeatStatus(seat.getSeatId(), SeatStatus.AVAILABLE);
        return true;
    }

    public double getTotalAmount() { double t = 0; for (Seat s : seats) t += s.getPrice(); return t; }
    public String getBookingId() { return bookingId; }
    public String getUserId() { return userId; }
    public Show getShow() { return show; }
    public List<Seat> getSeats() { return seats; }
    public Payment getPayment() { return payment; }
    public BookingStatus getStatus() { return status; }

    @Override
    public String toString() {
        StringBuilder sb = new StringBuilder();
        sb.append(bookingId).append(": ").append(userId).append(" | ").append(show.getMovie().getTitle()).append(" | Seats: [");
        for (int i = 0; i < seats.size(); i++) { if (i > 0) sb.append(", "); sb.append(seats.get(i).getSeatId()); }
        sb.append("] | $").append(String.format("%.2f", getTotalAmount())).append(" | ").append(status);
        return sb.toString();
    }
    public static void resetCounter() { counter = 0; }
}

// model/Movie.java — Movie with title, genre, and duration

class Movie {
    private String movieId;             // private = ID encapsulated; access via getter
    private String title;               // private = movie data hidden from outside
    private String genre;               // private = movie data hidden from outside
    private int durationMinutes;        // private = duration encapsulated

    public Movie(String movieId, String title, String genre, int durationMinutes) {
        this.movieId = movieId; this.title = title; this.genre = genre; this.durationMinutes = durationMinutes;
    }

    public String getMovieId() { return movieId; }
    public String getTitle() { return title; }
    public String getGenre() { return genre; }
    public int getDurationMinutes() { return durationMinutes; }

    @Override
    public String toString() { return title + " (" + genre + ", " + durationMinutes + " min)"; }
}

// model/Payment.java — Payment transaction with status tracking

enum PaymentStatus { PENDING, SUCCESS, FAILED, REFUNDED } // enum = fixed payment lifecycle states

class Payment {
    private static int counter = 0;     // static = shared counter for unique payment IDs
    private String paymentId;           // private = auto-generated ID encapsulated
    private double amount;              // private = amount set at construction
    private PaymentStatus status;       // private = state machine controlled by process/refund
    private String userId;              // private = payer identity encapsulated

    public Payment(double amount, String userId) {
        this.paymentId = "PAY-" + (++counter); this.amount = amount; this.userId = userId; this.status = PaymentStatus.PENDING;
    }

    public boolean process() { this.status = PaymentStatus.SUCCESS; return true; }
    public boolean refund() { if (status == PaymentStatus.SUCCESS) { this.status = PaymentStatus.REFUNDED; return true; } return false; }

    public String getPaymentId() { return paymentId; }
    public double getAmount() { return amount; }
    public PaymentStatus getStatus() { return status; }

    @Override
    public String toString() { return paymentId + ": $" + String.format("%.2f", amount) + " (" + status + ")"; }
    public static void resetCounter() { counter = 0; }
}

// model/Screen.java — Cinema screen with seat layout configuration

import java.util.ArrayList;
import java.util.List;

class Screen {
    private String screenId;            // private = screen ID encapsulated
    private String name;                // private = screen name encapsulated
    private List<Seat> seats;           // private = seat layout managed internally

    public Screen(String screenId, String name) {
        this.screenId = screenId; this.name = name; this.seats = new ArrayList<>();
    }

    public void setupSeats(int regularRows, int premiumRows, int vipRows, int seatsPerRow) {
        int rowNum = 0;
        for (int r = 0; r < vipRows; r++) { char rc = (char)('A' + rowNum); for (int c = 1; c <= seatsPerRow; c++) seats.add(SeatFactory.createSeat(SeatType.VIP, rc + "" + c, rowNum, c)); rowNum++; }
        for (int r = 0; r < premiumRows; r++) { char rc = (char)('A' + rowNum); for (int c = 1; c <= seatsPerRow; c++) seats.add(SeatFactory.createSeat(SeatType.PREMIUM, rc + "" + c, rowNum, c)); rowNum++; }
        for (int r = 0; r < regularRows; r++) { char rc = (char)('A' + rowNum); for (int c = 1; c <= seatsPerRow; c++) seats.add(SeatFactory.createSeat(SeatType.REGULAR, rc + "" + c, rowNum, c)); rowNum++; }
    }

    public Seat getSeat(String seatId) {
        for (Seat seat : seats) if (seat.getSeatId().equals(seatId)) return seat;
        return null;
    }

    public List<Seat> getSeats() { return seats; }
    public String getScreenId() { return screenId; }
