// service/BookingObserver.java — Observer pattern interface for booking events
// DESIGN PATTERN: Observer
//
// WHO IMPLEMENTS THIS? → BookingNotifier (in BookingNotifier.java)
// WHO CALLS IT? → BookingSystem calls observers on confirmBooking(), cancelBooking()
// WHY? → Decouples "booking confirmed/cancelled" from "notify user/send email".
//         New listeners (e.g., analytics, refund service) can be added without changing BookingSystem.

interface BookingObserver {            // interface = Observer pattern; notifies on booking events
    void onBookingConfirmed(Booking booking);
    void onBookingCancelled(Booking booking);
}

// service/BookingSystem.java — Lock-free seat reads, per-show locking for booking
// DESIGN PATTERN: Facade
//
// FACADE: Main.java talks only to this class.
// Uses BookingObserver (defined in BookingObserver.java) to notify on booking events.

import java.util.ArrayList;
import java.util.List;
import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.CopyOnWriteArrayList;

class BookingSystem {
    private List<Movie> movies;
    private List<Screen> screens;
    private ConcurrentHashMap<String, Show> showIndex; // ConcurrentHashMap = O(1) thread-safe show lookup by ID
    private List<Show> shows;
    private CopyOnWriteArrayList<Booking> bookings; // CopyOnWriteArrayList = safe iteration while adding bookings
    private SeatLockManager lockManager;
    private List<BookingObserver> observers; // CopyOnWriteArrayList = safe observer notification

    public BookingSystem() {
        this.movies = new ArrayList<>(); this.screens = new ArrayList<>();
        this.showIndex = new ConcurrentHashMap<>(); this.shows = new ArrayList<>();
        this.bookings = new CopyOnWriteArrayList<>(); this.lockManager = new SeatLockManager(5 * 60 * 1000);
        this.observers = new CopyOnWriteArrayList<>();
    }

    public void addObserver(BookingObserver observer) { observers.add(observer); }
    public void addMovie(Movie movie) { movies.add(movie); }
    public void addScreen(Screen screen) { screens.add(screen); }

    public Show addShow(Movie movie, Screen screen, String timing) {
        Show show = new Show("S" + (shows.size() + 1), movie, screen, timing);
        shows.add(show);
        showIndex.put(show.getShowId(), show);
        return show;
    }

    public List<Show> getShowsForMovie(String movieId) {
        List<Show> result = new ArrayList<>();
        for (Show show : shows) if (show.getMovie().getMovieId().equals(movieId)) result.add(show);
        return result;
    }

    public boolean lockSeats(String showId, List<String> seatIds, String userId) {
        Show show = showIndex.get(showId);
        if (show == null) return false;
        for (String seatId : seatIds) if (show.getSeatStatus(seatId) == SeatStatus.BOOKED) return false;
        return lockManager.lockSeats(showId, seatIds, userId);
    }

    public Booking confirmBooking(String showId, List<String> seatIds, String userId) {
        Show show = showIndex.get(showId);
        if (show == null) return null;
        for (String seatId : seatIds) if (!userId.equals(lockManager.getLockedBy(showId, seatId))) return null;

        List<Seat> seats = new ArrayList<>();
        double total = 0;
        for (String seatId : seatIds) { Seat seat = show.getScreen().getSeat(seatId); if (seat == null) return null; seats.add(seat); total += seat.getPrice(); }

        Payment payment = new Payment(total, userId);
        if (!payment.process()) { lockManager.unlockSeats(showId, seatIds); return null; }

        if (!show.tryBookSeats(seatIds)) { payment.refund(); lockManager.unlockSeats(showId, seatIds); return null; }
        lockManager.unlockSeats(showId, seatIds);

        Booking booking = new Booking(userId, show, seats, payment);
        bookings.add(booking);
        for (BookingObserver obs : observers) obs.onBookingConfirmed(booking);
        return booking;
    }

    public boolean cancelBooking(String bookingId) {
        for (Booking b : bookings) {
            if (b.getBookingId().equals(bookingId)) {
                boolean c = b.cancel();
                if (c) for (BookingObserver obs : observers) obs.onBookingCancelled(b);
                return c;
            }
        }
        return false;
    }

    public List<Movie> getMovies() { return movies; }
    public List<Screen> getScreens() { return screens; }
    public List<Show> getShows() { return shows; }
    public SeatLockManager getLockManager() { return lockManager; }
}

// service/SeatLock.java — ConcurrentHashMap seat locking with per-show ReentrantLock

import java.util.List;
import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.locks.ReentrantLock;

class SeatLock {
    private String seatId;
    private String showId;
    private String userId;
    private long expiryTime;

    public SeatLock(String seatId, String showId, String userId, long lockDurationMs) {
        this.seatId = seatId; this.showId = showId; this.userId = userId;
        this.expiryTime = System.currentTimeMillis() + lockDurationMs;
    }

    public boolean isExpired() { return System.currentTimeMillis() > expiryTime; }
    public String getSeatId() { return seatId; }
    public String getShowId() { return showId; }
    public String getUserId() { return userId; }
}

class SeatLockManager {
    private ConcurrentHashMap<String, SeatLock> locks; // ConcurrentHashMap = thread-safe lock registry; O(1) lookup
    private ConcurrentHashMap<String, ReentrantLock> showLocks; // per-show lock = finer granularity than global lock
    private long defaultLockDurationMs;

    public SeatLockManager(long defaultLockDurationMs) {
        this.locks = new ConcurrentHashMap<>();
        this.showLocks = new ConcurrentHashMap<>();
        this.defaultLockDurationMs = defaultLockDurationMs;
    }

    private String getKey(String showId, String seatId) { return showId + "_" + seatId; }

    private ReentrantLock getShowLock(String showId) {
        return showLocks.computeIfAbsent(showId, k -> new ReentrantLock());
    }

    public boolean lockSeat(String showId, String seatId, String userId) {
        String key = getKey(showId, seatId);
        SeatLock existing = locks.get(key);
        if (existing != null) {
            if (existing.isExpired()) locks.remove(key, existing);
            else if (!existing.getUserId().equals(userId)) return false;
            else return true;
        }
        SeatLock newLock = new SeatLock(seatId, showId, userId, defaultLockDurationMs);
        SeatLock prev = locks.putIfAbsent(key, newLock);
        if (prev == null) return true;
        if (prev.isExpired()) { locks.replace(key, prev, newLock); return true; }
        return prev.getUserId().equals(userId);
    }

    public boolean lockSeats(String showId, List<String> seatIds, String userId) {
        ReentrantLock showLock = getShowLock(showId);
        showLock.lock();
        try {
            for (String seatId : seatIds) {
                String key = getKey(showId, seatId);
                SeatLock existing = locks.get(key);
                if (existing != null && !existing.isExpired() && !existing.getUserId().equals(userId)) return false;
            }
            for (String seatId : seatIds) {
                String key = getKey(showId, seatId);
                locks.put(key, new SeatLock(seatId, showId, userId, defaultLockDurationMs));
            }
            return true;
        } finally {
            showLock.unlock();
        }
    }

    public void unlockSeat(String showId, String seatId) { locks.remove(getKey(showId, seatId)); }
    public void unlockSeats(String showId, List<String> seatIds) { for (String s : seatIds) unlockSeat(showId, s); }

    public String getLockedBy(String showId, String seatId) {
        SeatLock lock = locks.get(getKey(showId, seatId));
        return (lock != null && !lock.isExpired()) ? lock.getUserId() : null;
    }
}

// concurrent/Main.java — 50 threads trying to book same seats, only correct number succeeds

import java.util.*;
import java.util.concurrent.CountDownLatch;
import java.util.concurrent.atomic.AtomicInteger;

public class Main {
    public static void main(String[] args) throws InterruptedException {
        System.out.println("=== Concurrent Movie Ticket Booking Demo ===\n");

        BookingService service = new BookingService();

        // Create a show with 5 rows x 5 columns = 25 seats
        Show show = new Show("SHOW-1", "Inception", "7:00 PM", 5, 5);
        service.addShow(show);

        // 50 users all trying to book seat A1 and A2 (same 2 seats)
        int threadCount = 50;
        List<String> targetSeats = List.of("A1", "A2");
        CountDownLatch startLatch = new CountDownLatch(1);
        CountDownLatch doneLatch = new CountDownLatch(threadCount);
        AtomicInteger successCount = new AtomicInteger(0);
        AtomicInteger failCount = new AtomicInteger(0);
        List<String> results = Collections.synchronizedList(new ArrayList<>());

        System.out.println("Scenario: 50 users all trying to book seats A1+A2 for the same show.");
        System.out.println("Expected: Exactly 1 succeeds, 49 are rejected (no double-booking).\n");

        for (int i = 0; i < threadCount; i++) {
            final String userId = "USER-" + i;
            new Thread(() -> {
                try {
                    startLatch.await();
                    Booking booking = service.bookSeats(userId, "SHOW-1", targetSeats);
                    if (booking != null) {
                        successCount.incrementAndGet();
                        results.add("  [BOOKED] " + userId + " -> " + booking.getBookingId());
                    } else {
                        failCount.incrementAndGet();
                    }
                } catch (InterruptedException e) {
                    Thread.currentThread().interrupt();
                } finally {
                    doneLatch.countDown();
                }
            }, "Booker-" + i).start();
        }

        startLatch.countDown();
        doneLatch.await();

        // Print results
        for (String r : results) {
            System.out.println(r);
        }
        System.out.println("  [REJECTED] " + failCount.get() + " users could not book (seats taken)");

        System.out.println("\n--- Summary ---");
        System.out.println("Threads attempted: " + threadCount);
        System.out.println("Successfully booked: " + successCount.get());
        System.out.println("Correctly rejected: " + failCount.get());
        System.out.println("Seat A1 status: " + show.getSeat("A1").getStatus());
        System.out.println("Seat A2 status: " + show.getSeat("A2").getStatus());

        boolean correct = successCount.get() == 1 && failCount.get() == 49;
        System.out.println("\nCorrectness check: " + (correct ? "PASSED" : "FAILED"));
        System.out.println("Total booked seats in show: " + show.getBookedCount() + "/25");
    }
}

// concurrent/RaceConditionDemo.java — Shows double-booking bug then fix with proper locking

import java.util.concurrent.CountDownLatch;
import java.util.concurrent.atomic.AtomicInteger;
import java.util.concurrent.atomic.AtomicReference;

/**
 * RACE CONDITION: Two users booking the same seat at the same time.
 *
 * BUG: Check seat availability and mark as booked is NOT atomic:
 *   if (seat.status == AVAILABLE) {   // User A checks — available!
 *                                      // User B checks — also available!
 *       seat.status = BOOKED;          // User A books
 *                                      // User B books — DOUBLE BOOKING!
 *   }
 *
 * FIX: AtomicReference with CAS ensures only one thread transitions AVAILABLE -> BOOKED.
 */
public class RaceConditionDemo {

    // ===== BUGGY VERSION =====
    static class BuggySeat {
        private String status = "AVAILABLE";
        private String bookedBy = null;

        // BUG: Non-atomic check-then-act
        public boolean book(String userId) {
            if ("AVAILABLE".equals(status)) {
                Thread.yield(); // Simulate context switch
                status = "BOOKED";
                bookedBy = userId;
                return true;
            }
            return false;
        }

        public String getBookedBy() { return bookedBy; }
    }

    // ===== FIXED VERSION =====
    static class FixedSeat {
        private final AtomicReference<String> status = new AtomicReference<>("AVAILABLE"); // AtomicReference = CAS ensures only one thread transitions state
        private volatile String bookedBy = null; // volatile = bookedBy visible to all threads when set

        // FIX: CAS ensures only one thread transitions AVAILABLE -> BOOKED
        public boolean book(String userId) {
            if (status.compareAndSet("AVAILABLE", "BOOKED")) {
                bookedBy = userId;
                return true;
            }
            return false;
        }

        public String getBookedBy() { return bookedBy; }
    }

    public static void main(String[] args) throws InterruptedException {
        System.out.println("=== Race Condition Demo: Movie Ticket Booking ===\n");
        demonstrateBug();
        System.out.println();
        demonstrateFix();
    }

    static void demonstrateBug() throws InterruptedException {
        System.out.println("--- BUGGY VERSION (non-atomic check-then-act) ---");
        System.out.println("Two users try to book the SAME seat simultaneously.\n");

        int doubleBookings = 0;
        int trials = 1000;

        for (int t = 0; t < trials; t++) {
            BuggySeat seat = new BuggySeat();
            CountDownLatch start = new CountDownLatch(1);
            AtomicInteger successes = new AtomicInteger(0);

            Thread user1 = new Thread(() -> {
                try { start.await(); } catch (InterruptedException e) { return; }
                if (seat.book("Alice")) successes.incrementAndGet();
            });
            Thread user2 = new Thread(() -> {
                try { start.await(); } catch (InterruptedException e) { return; }
                if (seat.book("Bob")) successes.incrementAndGet();
            });

            user1.start();
            user2.start();
            start.countDown();
            user1.join();
            user2.join();

            if (successes.get() > 1) {
                doubleBookings++;
            }
        }

        System.out.println("Results over " + trials + " trials:");
        System.out.println("  Double bookings detected: " + doubleBookings + " times");
        if (doubleBookings > 0) {
            System.out.println("  BUG CONFIRMED: Same seat sold to two users!");
            System.out.println("  This means revenue loss + angry customers at the theater.");
        } else {
            System.out.println("  (Race didn't manifest — but the bug exists. Try increasing trials.)");
        }
    }

    static void demonstrateFix() throws InterruptedException {
        System.out.println("--- FIXED VERSION (AtomicReference CAS) ---");
        System.out.println("Two users try to book the SAME seat simultaneously.\n");

        int doubleBookings = 0;
        int trials = 1000;

        for (int t = 0; t < trials; t++) {
            FixedSeat seat = new FixedSeat();
            CountDownLatch start = new CountDownLatch(1);
            AtomicInteger successes = new AtomicInteger(0);

            Thread user1 = new Thread(() -> {
                try { start.await(); } catch (InterruptedException e) { return; }
                if (seat.book("Alice")) successes.incrementAndGet();
            });
            Thread user2 = new Thread(() -> {
                try { start.await(); } catch (InterruptedException e) { return; }
                if (seat.book("Bob")) successes.incrementAndGet();
            });

            user1.start();
            user2.start();
            start.countDown();
            user1.join();
            user2.join();

            if (successes.get() > 1) {
                doubleBookings++;
            }
        }

        System.out.println("Results over " + trials + " trials:");
        System.out.println("  Double bookings detected: " + doubleBookings + " times");
        System.out.println("  Exactly one user books the seat EVERY time.");
        System.out.println("  FIX VERIFIED: CAS prevents double-booking without heavyweight locks.");
    }
}

