// concurrent/model/Seat.java — Seat with atomic status for thread-safe booking

import java.util.concurrent.atomic.AtomicReference;

enum SeatStatus {
    AVAILABLE, LOCKED, BOOKED
}

class Seat {
    private final String seatId;        // final = immutable; safe to read from any thread
    private final int row;              // final = immutable; no sync needed
    private final int column;           // final = immutable; no sync needed
    private final AtomicReference<SeatStatus> status = new AtomicReference<>(SeatStatus.AVAILABLE); // AtomicReference = CAS-based state transition; prevents double-booking

    public Seat(String seatId, int row, int column) {
        this.seatId = seatId;
        this.row = row;
        this.column = column;
    }

    public String getSeatId() { return seatId; }
    public int getRow() { return row; }
    public int getColumn() { return column; }
    public SeatStatus getStatus() { return status.get(); }

    /**
     * CAS-based lock attempt — only one thread can lock a seat.
     */
    public boolean tryLock() {
        return status.compareAndSet(SeatStatus.AVAILABLE, SeatStatus.LOCKED); // CAS = atomic AVAILABLE->LOCKED
    }

    public boolean confirmBooking() {
        return status.compareAndSet(SeatStatus.LOCKED, SeatStatus.BOOKED); // CAS = atomic LOCKED->BOOKED
    }

    public boolean release() {
        return status.compareAndSet(SeatStatus.LOCKED, SeatStatus.AVAILABLE); // CAS = atomic rollback
    }

    @Override
    public String toString() {
        return seatId + " [" + status.get() + "]";
    }
}

// concurrent/model/Show.java — A movie show with seats

import java.util.*;
import java.util.concurrent.ConcurrentHashMap;

class Show {
    private final String showId;        // final = immutable; safe publication
    private final String movieName;     // final = immutable; safe to read from any thread
    private final String time;          // final = immutable; safe publication
    private final ConcurrentHashMap<String, Seat> seats; // ConcurrentHashMap = thread-safe O(1) seat lookup by ID

    public Show(String showId, String movieName, String time, int rows, int cols) {
        this.showId = showId;
        this.movieName = movieName;
        this.time = time;
        this.seats = new ConcurrentHashMap<>();

        for (int r = 1; r <= rows; r++) {
            for (int c = 1; c <= cols; c++) {
                String seatId = (char) ('A' + r - 1) + String.valueOf(c);
                seats.put(seatId, new Seat(seatId, r, c));
            }
        }
    }

    public String getShowId() { return showId; }
    public String getMovieName() { return movieName; }
    public String getTime() { return time; }

    public Seat getSeat(String seatId) {
        return seats.get(seatId);
    }

    public List<Seat> getAvailableSeats() {
        List<Seat> available = new ArrayList<>();
        for (Seat seat : seats.values()) {
            if (seat.getStatus() == SeatStatus.AVAILABLE) {
                available.add(seat);
            }
        }
        return available;
    }

    public int getTotalSeats() { return seats.size(); }

    public long getBookedCount() {
        return seats.values().stream()
                .filter(s -> s.getStatus() == SeatStatus.BOOKED)
                .count();
    }
}

// concurrent/service/BookingService.java — Thread-safe booking with ReentrantLock per show

import java.util.*;
import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.locks.ReentrantLock;
import java.util.concurrent.atomic.AtomicInteger;

class BookingService {
    private final ConcurrentHashMap<String, Show> shows = new ConcurrentHashMap<>(); // ConcurrentHashMap = thread-safe show registry
    private final ConcurrentHashMap<String, ReentrantLock> showLocks = new ConcurrentHashMap<>(); // per-show lock = parallel bookings across different shows
    private final ConcurrentHashMap<String, Booking> bookings = new ConcurrentHashMap<>(); // ConcurrentHashMap = thread-safe booking storage
    private final AtomicInteger successCount = new AtomicInteger(0); // AtomicInteger = lock-free counter
    private final AtomicInteger failCount = new AtomicInteger(0); // AtomicInteger = lock-free counter

    public void addShow(Show show) {
        shows.put(show.getShowId(), show);
        showLocks.put(show.getShowId(), new ReentrantLock());
    }

    /**
     * Book seats for a user. Uses per-show locking to allow parallel bookings
     * across different shows while serializing within the same show.
     *
     * Flow:
     * 1. Acquire show lock
     * 2. Try to lock all requested seats (CAS: AVAILABLE -> LOCKED)
     * 3. If all succeed, confirm booking (LOCKED -> BOOKED)
     * 4. If any fail, release already-locked seats (LOCKED -> AVAILABLE)
     */
    public Booking bookSeats(String userId, String showId, List<String> seatIds) {
        Show show = shows.get(showId);
        if (show == null) return null;

        ReentrantLock lock = showLocks.get(showId);
        lock.lock();
        try {
            List<Seat> lockedSeats = new ArrayList<>();

            // Try to lock all seats
            for (String seatId : seatIds) {
                Seat seat = show.getSeat(seatId);
                if (seat == null || !seat.tryLock()) {
                    // Rollback: release any seats we already locked
                    for (Seat locked : lockedSeats) {
                        locked.release();
                    }
                    failCount.incrementAndGet();
                    return null;
                }
                lockedSeats.add(seat);
            }

            // All seats locked — confirm booking
            for (Seat seat : lockedSeats) {
                seat.confirmBooking();
            }

            Booking booking = new Booking(userId, show, lockedSeats);
            bookings.put(booking.getBookingId(), booking);
            successCount.incrementAndGet();
            return booking;
        } finally {
            lock.unlock();
        }
    }

    public int getSuccessCount() { return successCount.get(); }
    public int getFailCount() { return failCount.get(); }
    public Show getShow(String showId) { return shows.get(showId); }
}

