}

// model/Receipt.java — Transaction receipt with account info, amounts, and timestamps

import java.time.LocalDateTime;
import java.time.format.DateTimeFormatter;

public class Receipt {
    private static int counter = 0;   // shared ID generator across all receipts
    private String receiptId;         // unique receipt identifier
    private String transactionType;   // WITHDRAWAL, DEPOSIT, TRANSFER
    private double amount;            // transaction amount
    private double balanceAfter;      // resulting account balance
    private String accountId;         // which account was used
    private LocalDateTime timestamp;  // when receipt was created
    private String details;           // extra info (dispensed notes, target account)

    public Receipt(String transactionType, double amount, double balanceAfter, String accountId, String details) {
        this.receiptId = "RCP-" + (++counter);
        this.transactionType = transactionType;
        this.amount = amount;
        this.balanceAfter = balanceAfter;
        this.accountId = accountId;
        this.timestamp = LocalDateTime.now();
        this.details = details;
    }

    public String getReceiptId() { return receiptId; }

    @Override
    public String toString() {
        DateTimeFormatter fmt = DateTimeFormatter.ofPattern("yyyy-MM-dd HH:mm:ss");
        StringBuilder sb = new StringBuilder();
        sb.append("========== RECEIPT ==========\n");
        sb.append("Receipt #: ").append(receiptId).append("\n");
        sb.append("Date: ").append(timestamp.format(fmt)).append("\n");
        sb.append("Account: ").append(accountId).append("\n");
        sb.append("Type: ").append(transactionType).append("\n");
        sb.append(String.format("Amount: $%.2f\n", amount));
        sb.append(String.format("Balance: $%.2f\n", balanceAfter));
        if (details != null && !details.isEmpty()) {
            sb.append("Details: ").append(details).append("\n");
        }
        sb.append("=============================");
        return sb.toString();
    }
}

// model/Transaction.java — ATM transactions (withdrawal, deposit, transfer) with execution logic

import java.util.Map;

public abstract class Transaction { // abstract = can't instantiate directly; must subclass
    protected double amount;         // protected = subclasses access for execution
    protected Account sourceAccount; // protected = subclasses need for balance ops
    protected boolean successful;    // protected = subclasses set after execution
    protected String failureReason;  // protected = subclasses set on failure

    public Transaction(Account sourceAccount, double amount) {
        this.sourceAccount = sourceAccount;
        this.amount = amount;
        this.successful = false;
    }

    public abstract Receipt execute(ATM atm);

    public boolean isSuccessful() { return successful; }
    public String getFailureReason() { return failureReason; }
    public double getAmount() { return amount; }
}

class Withdrawal extends Transaction {
    public Withdrawal(Account account, double amount) {
        super(account, amount);
    }

    @Override
    public Receipt execute(ATM atm) {
        if (amount > sourceAccount.getBalance()) {
            failureReason = "Insufficient balance";
            return null;
        }

        Map<Integer, Integer> dispensed = atm.getCashDispenser().dispense((int) amount);
        if (dispensed == null) {
            failureReason = "Cannot dispense exact amount with available denominations";
            return null;
        }

        sourceAccount.withdraw(amount);
        successful = true;

        StringBuilder details = new StringBuilder("Dispensed: ");
        for (Map.Entry<Integer, Integer> entry : dispensed.entrySet()) {
            details.append(entry.getValue()).append(" x $").append(entry.getKey()).append(", ");
        }

        return new Receipt("WITHDRAWAL", amount, sourceAccount.getBalance(),
                sourceAccount.getAccountId(), details.toString().replaceAll(", $", ""));
    }
}

class Deposit extends Transaction {
    public Deposit(Account account, double amount) {
        super(account, amount);
    }

    @Override
    public Receipt execute(ATM atm) {
        if (amount <= 0) {
            failureReason = "Invalid deposit amount";
            return null;
        }
        sourceAccount.deposit(amount);
        successful = true;
        return new Receipt("DEPOSIT", amount, sourceAccount.getBalance(),
                sourceAccount.getAccountId(), "Cash deposit");
    }
}

class Transfer extends Transaction {
    private Account targetAccount;

    public Transfer(Account sourceAccount, Account targetAccount, double amount) {
        super(sourceAccount, amount);
        this.targetAccount = targetAccount;
    }

    @Override
    public Receipt execute(ATM atm) {
        if (amount > sourceAccount.getBalance()) {
            failureReason = "Insufficient balance";
            return null;
        }
        if (targetAccount == null) {
            failureReason = "Target account not found";
            return null;
        }

        boolean success = sourceAccount.transfer(targetAccount, amount);
        if (!success) {
            failureReason = "Transfer failed";
            return null;
        }

        successful = true;
        String details = String.format("Transfer to %s", targetAccount.getAccountId());
        return new Receipt("TRANSFER", amount, sourceAccount.getBalance(),
                sourceAccount.getAccountId(), details);
    }
}

// service/ATM.java — ATM context class managing hardware, current card, and delegating to states

import java.util.*;

public class ATM {
    private ATMState currentState;              // State pattern; delegates behavior to state object
    private Card currentCard;                   // Currently inserted card reference
    private CashDispenser cashDispenser;        // TreeMap-based dispenser for O(log n) greedy
    private int pinAttempts;                    // Tracks failed PIN entries per session
    private List<Transaction> transactionHistory; // ArrayList = O(1) append for audit log
    private Map<String, Account> accounts;      // HashMap = O(1) account lookup by ID

    public ATM() {
        this.currentState = new NoCardState();
        this.cashDispenser = new CashDispenser();
        this.pinAttempts = 0;
        this.transactionHistory = new ArrayList<>();
        this.accounts = new HashMap<>();
    }

    public void registerAccount(Account account) {
        accounts.put(account.getAccountId(), account);
    }

    public Account findAccount(String accountId) {
        return accounts.get(accountId);
    }

    public void insertCard(Card card) { currentState.insertCard(this, card); }
    public void ejectCard() { currentState.ejectCard(this); }
    public boolean authenticate(String pin) { return currentState.authenticate(this, pin); }
    public double checkBalance() { return currentState.checkBalance(this); }

    public Receipt withdraw(double amount) {
        Withdrawal withdrawal = new Withdrawal(currentCard.getAccount(), amount);
        return currentState.performTransaction(this, withdrawal);
    }

    public Receipt deposit(double amount) {
        Deposit dep = new Deposit(currentCard.getAccount(), amount);
        return currentState.performTransaction(this, dep);
    }

    public Receipt transfer(String targetAccountId, double amount) {
        Account target = accounts.get(targetAccountId);
        Transfer txn = new Transfer(currentCard.getAccount(), target, amount);
        return currentState.performTransaction(this, txn);
    }

    public void setState(ATMState state) { this.currentState = state; }
    public ATMState getState() { return currentState; }
    public Card getCurrentCard() { return currentCard; }
    public void setCurrentCard(Card card) { this.currentCard = card; }
    public CashDispenser getCashDispenser() { return cashDispenser; }
    public int getPinAttempts() { return pinAttempts; }
    public void setPinAttempts(int attempts) { this.pinAttempts = attempts; }
    public void addTransaction(Transaction txn) { transactionHistory.add(txn); }
    public List<Transaction> getTransactionHistory() { return Collections.unmodifiableList(transactionHistory); }
}

// service/CashDispenser.java — TreeMap-backed inventory; dispense delegates to a Chain of Responsibility

import java.util.*;

public class CashDispenser {
    private TreeMap<Integer, Integer> denominations; // TreeMap = auto-sorted keys; O(log n) access
    private DenominationHandler chainHead;           // private = head of CoR chain (largest denom first)

    public CashDispenser() {
        // TreeMap keeps denominations sorted; we use descendingMap() for largest-first
        denominations = new TreeMap<>(Collections.reverseOrder()); // reverseOrder = largest denom first
        denominations.put(2000, 50);
        denominations.put(500, 100);
        denominations.put(200, 100);
        denominations.put(100, 200);
        denominations.put(50, 200);
        denominations.put(20, 300);

        // Build the CoR chain: largest denom first, each forwards remainder to the next.
        // 2000 -> 500 -> 200 -> 100 -> 50 -> 20
        chainHead = new TwoThousandHandler();
        chainHead.setNext(new FiveHundredHandler())
                 .setNext(new TwoHundredHandler())
                 .setNext(new HundredHandler())
                 .setNext(new FiftyHandler())
                 .setNext(new TwentyHandler());
    }

    public void loadDenomination(int denomination, int count) {
        denominations.merge(denomination, count, Integer::sum);
    }

    /**
     * Greedy dispensing through a Chain of Responsibility. Each handler tries its
     * own denomination first and forwards the remainder to the next. The TreeMap
     * is still used so handlers see notes in O(log n) and so removals stay sorted.
     */
    public Map<Integer, Integer> dispense(int amount) {
        if (amount <= 0) return null;

        // Snapshot inventory so we can roll back if the chain can't satisfy the amount.
        TreeMap<Integer, Integer> snapshot = new TreeMap<>(denominations);
        Map<Integer, Integer> output = new LinkedHashMap<>(); // LinkedHashMap = preserves insertion order

        int unsatisfied = chainHead.handle(amount, denominations, output);

        if (unsatisfied != 0) {
            denominations.clear();
            denominations.putAll(snapshot);
            return null;
        }

        // Cleanup: drop denominations whose count fell to zero so iteration stays compact.
        denominations.values().removeIf(count -> count == 0);
        return output;
    }

    /**
     * O(1) check if a denomination exists, O(log d) retrieval from TreeMap.
     */
    public boolean hasDenomination(int denomination) {
        Integer count = denominations.get(denomination);
        return count != null && count > 0;
    }

    public int getTotalCash() {
        int total = 0;
        for (Map.Entry<Integer, Integer> entry : denominations.entrySet()) {
            total += entry.getKey() * entry.getValue();
        }
        return total;
    }

    public String getStatus() {
        StringBuilder sb = new StringBuilder("Cash Dispenser Status:\n");
        for (Map.Entry<Integer, Integer> entry : denominations.entrySet()) {
            sb.append(String.format("  $%d: %d notes\n", entry.getKey(), entry.getValue()));
        }
        sb.append(String.format("  Total: $%d", getTotalCash()));
        return sb.toString();
    }
}

// service/DenominationHandler.java — Chain of Responsibility base for cash denomination dispensing

import java.util.Map;

public abstract class DenominationHandler {
    protected DenominationHandler next;            // protected = next link in chain; subclasses traverse it

    /** Wire the next handler. Returns the argument so chains read left-to-right when fluent. */
    public DenominationHandler setNext(DenominationHandler next) {
        this.next = next;
        return next;
    }

    /** Denomination this handler is responsible for (e.g. 2000, 500, 200, ...). */
    public abstract int denomination();

    /**
     * Try to dispense as many notes of this denomination as possible, then forward
     * the remainder down the chain. Returns the amount that could not be served.
     *
     * @param remaining cents/dollars still owed
     * @param inventory live note counts (updated in place on dispense)
     * @param output    map of denomination -> notes dispensed (updated in place)
     */
    public int handle(int remaining, Map<Integer, Integer> inventory, Map<Integer, Integer> output) {
        if (remaining <= 0) return 0;
        int denom = denomination();
        int available = inventory.getOrDefault(denom, 0);
        int needed = remaining / denom;
        int toDispense = Math.min(needed, available);

        if (toDispense > 0) {
            output.put(denom, toDispense);
            remaining -= toDispense * denom;
            inventory.put(denom, available - toDispense);
        }

        if (remaining == 0) return 0;
        if (next != null) return next.handle(remaining, inventory, output);
        return remaining; // unsatisfied — caller must roll back
    }
}

