        }
        return receipt;
    }
}

// concurrent/Main.java — 10 threads withdrawing $100 from $500 account, exactly 5 succeed

import java.util.*;
import java.util.concurrent.CountDownLatch;
import java.util.concurrent.atomic.AtomicInteger;

public class Main {
    public static void main(String[] args) throws InterruptedException {
        System.out.println("=== Concurrent ATM Machine Demo ===\n");

        Account account = new Account("ACC-001", "Alice", 500);
        Card card = new Card("4111111111114321", "1234", account);
        ATM atm = new ATM("ATM-01");

        int threadCount = 10;
        long withdrawalAmount = 100;

        System.out.println("Scenario: 10 threads each withdrawing $" + withdrawalAmount +
                " from account with $" + account.getBalanceDollars() + " balance.");
        System.out.println("Expected: Exactly 5 succeed (5 x $100 = $500), 5 fail (insufficient funds).\n");

        CountDownLatch startLatch = new CountDownLatch(1);
        CountDownLatch doneLatch = new CountDownLatch(threadCount);
        AtomicInteger successCount = new AtomicInteger(0);
        AtomicInteger failCount = new AtomicInteger(0);
        List<String> results = Collections.synchronizedList(new ArrayList<>());

        for (int i = 0; i < threadCount; i++) {
            final int id = i;
            new Thread(() -> {
                try {
                    startLatch.await();
                    boolean success = atm.withdraw(account, withdrawalAmount);
                    if (success) {
                        successCount.incrementAndGet();
                        results.add("  [SUCCESS] Thread-" + id + " withdrew $" + withdrawalAmount +
                                " | Balance after: $" + account.getBalanceDollars());
                    } else {
                        failCount.incrementAndGet();
                        results.add("  [FAILED]  Thread-" + id + " insufficient funds" +
                                " | Balance: $" + account.getBalanceDollars());
                    }
                } catch (InterruptedException e) {
                    Thread.currentThread().interrupt();
                } finally {
                    doneLatch.countDown();
                }
            }, "ATM-Thread-" + id).start();
        }

        // Release all threads simultaneously
        startLatch.countDown();
        doneLatch.await();

        // Print results
        results.sort(String::compareTo);
        for (String r : results) {
            System.out.println(r);
        }

        // Verification
        System.out.println("\n--- Summary ---");
        System.out.println("Initial balance: $500");
        System.out.println("Withdrawal amount: $" + withdrawalAmount + " x " + threadCount + " threads");
        System.out.println("Successful withdrawals: " + successCount.get());
        System.out.println("Failed withdrawals: " + failCount.get());
        System.out.println("Final balance: $" + account.getBalanceDollars());

        boolean correctCount = successCount.get() == 5 && failCount.get() == 5;
        boolean correctBalance = account.getBalanceDollars() == 0;
        boolean noOverdraft = account.getBalanceCents() >= 0;

        System.out.println("\nExactly 5 succeeded: " + (correctCount ? "PASSED" : "FAILED"));
        System.out.println("Final balance is $0: " + (correctBalance ? "PASSED" : "FAILED"));
        System.out.println("No overdraft (balance >= 0): " + (noOverdraft ? "PASSED" : "FAILED"));

        boolean allPassed = correctCount && correctBalance && noOverdraft;
        System.out.println("\nOverall: " + (allPassed ? "ALL TESTS PASSED" : "SOME TESTS FAILED"));
    }
}

// concurrent/model/Account.java — Account with AtomicLong balance for CAS-based withdrawal

import java.util.concurrent.atomic.AtomicLong;

class Account {
    private final String accountId;        // immutable identity — safe to read from any thread without sync
    private final String holderName;       // set once at creation — final guarantees visibility
    private final AtomicLong balanceCents; // multiple ATM threads withdraw/deposit — CAS loop prevents lost updates

    public Account(String accountId, String holderName, long balanceDollars) {
        this.accountId = accountId;
        this.holderName = holderName;
        this.balanceCents = new AtomicLong(balanceDollars * 100);
    }

    /**
     * CAS-based withdrawal — atomically checks and deducts balance.
     * Uses a compareAndSet loop: read balance, check sufficient, CAS to new balance.
     * Returns true if withdrawal succeeded, false if insufficient funds.
     */
    public boolean withdraw(long amountDollars) {
        long amountCents = amountDollars * 100;
        while (true) {
            long current = balanceCents.get();
            if (current < amountCents) {
                return false; // insufficient funds
            }
            long newBalance = current - amountCents;
            if (balanceCents.compareAndSet(current, newBalance)) {
                return true; // CAS succeeded
            }
            // CAS failed — another thread modified balance, retry
        }
    }

    /**
     * CAS-based deposit — atomically adds to balance.
     */
    public void deposit(long amountDollars) {
        balanceCents.addAndGet(amountDollars * 100);
    }

    public long getBalanceDollars() {
        return balanceCents.get() / 100;
    }

    public long getBalanceCents() {
        return balanceCents.get();
    }

    public String getAccountId() { return accountId; }
    public String getHolderName() { return holderName; }

    @Override
    public String toString() {
        return accountId + " (" + holderName + ") Balance: $" + getBalanceDollars();
    }
}

// concurrent/model/Card.java — Card linked to an Account

class Card {
    private final String cardNumber; // final = set once in constructor; safe publication to threads
    private final String pin;        // final = immutable after construction; thread-safe to read
    private final Account account;   // final = reference never changes; account itself is thread-safe

    public Card(String cardNumber, String pin, Account account) {
        this.cardNumber = cardNumber;
        this.pin = pin;
        this.account = account;
    }

    public boolean validatePin(String inputPin) {
        return pin.equals(inputPin);
    }

    public String getCardNumber() { return cardNumber; }
    public Account getAccount() { return account; }

    @Override
    public String toString() {
        return "Card ending " + cardNumber.substring(cardNumber.length() - 4);
    }
}

// concurrent/service/ATM.java — ATM service using CAS-based Account for thread-safe withdrawals

import java.util.concurrent.atomic.AtomicInteger;

class ATM {
    private final String atmId;      // final = immutable identity; safe to read from any thread
    private final AtomicInteger successfulTransactions = new AtomicInteger(0); // AtomicInteger = lock-free thread-safe counter
    private final AtomicInteger failedTransactions = new AtomicInteger(0);     // AtomicInteger = CAS-based increment, no locks

    public ATM(String atmId) {
        this.atmId = atmId;
    }

    /**
     * Attempt withdrawal from account. Thread-safe via Account's CAS-based withdraw.
     * Multiple concurrent calls will not allow overdraft.
     */
    public boolean withdraw(Account account, long amount) {
        boolean success = account.withdraw(amount);
        if (success) {
            successfulTransactions.incrementAndGet();
        } else {
            failedTransactions.incrementAndGet();
        }
        return success;
    }

    public boolean deposit(Account account, long amount) {
        account.deposit(amount);
        successfulTransactions.incrementAndGet();
        return true;
    }

    public long checkBalance(Account account) {
        return account.getBalanceDollars();
    }

    public int getSuccessfulTransactions() { return successfulTransactions.get(); }
    public int getFailedTransactions() { return failedTransactions.get(); }
    public String getAtmId() { return atmId; }
}

