    public Van(String id, String make, String model, int year, String plate, double rate, Location loc) {
        super(id, make, model, year, plate, rate, loc);
    }
    @Override public String getType() { return "Van"; }
}

class Truck extends Vehicle {
    public Truck(String id, String make, String model, int year, String plate, double rate, Location loc) {
        super(id, make, model, year, plate, rate, loc);
    }
    @Override public String getType() { return "Truck"; }
}

// service/RentalSystem.java — Optimized rental system with HashMap<VehicleType, PriorityQueue> for fast lookup

import java.util.*;

public class RentalSystem {
    private List<Vehicle> vehicles;          // ArrayList = O(1) append for full fleet registry
    private List<Reservation> reservations;  // ArrayList = O(1) append for reservation history
    private Map<String, List<Customer>> waitlist; // HashMap = O(1) lookup of waitlist by type

    // PriorityQueue = min-heap; cheapest vehicle at top for O(1) peek, O(log n) insert/remove
    private Map<String, PriorityQueue<Vehicle>> availableByType; // HashMap+PQ = O(1) type + O(1) cheapest
    private Map<String, Map<String, PriorityQueue<Vehicle>>> availableByTypeAndLocation; // nested index

    public RentalSystem() {
        this.vehicles = new ArrayList<>();
        this.reservations = new ArrayList<>();
        this.waitlist = new HashMap<>();
        this.availableByType = new HashMap<>();
        this.availableByTypeAndLocation = new HashMap<>();
    }

    public void addVehicle(Vehicle vehicle) {
        vehicles.add(vehicle);
        if (vehicle.isAvailable()) {
            indexVehicle(vehicle);
        }
    }

    private void indexVehicle(Vehicle vehicle) {
        String type = vehicle.getType().toUpperCase();
        // Index by type (PriorityQueue sorted by daily rate - cheapest first)
        availableByType
            .computeIfAbsent(type, k -> new PriorityQueue<>(
                Comparator.comparingDouble(Vehicle::getBaseDailyRate)))
            .offer(vehicle);

        // Index by type + location
        String locId = vehicle.getCurrentLocation().getLocationId();
        availableByTypeAndLocation
            .computeIfAbsent(type, k -> new HashMap<>())
            .computeIfAbsent(locId, k -> new PriorityQueue<>(
                Comparator.comparingDouble(Vehicle::getBaseDailyRate)))
            .offer(vehicle);
    }

    private void deindexVehicle(Vehicle vehicle) {
        String type = vehicle.getType().toUpperCase();
        PriorityQueue<Vehicle> typeQueue = availableByType.get(type);
        if (typeQueue != null) typeQueue.remove(vehicle);

        String locId = vehicle.getCurrentLocation().getLocationId();
        Map<String, PriorityQueue<Vehicle>> locMap = availableByTypeAndLocation.get(type);
        if (locMap != null) {
            PriorityQueue<Vehicle> locQueue = locMap.get(locId);
            if (locQueue != null) locQueue.remove(vehicle);
        }
    }

    public Vehicle createVehicle(String type, String id, String make, String model,
                                  int year, String plate, double rate, Location loc) {
        switch (type.toUpperCase()) {
            case "CAR": return new Car(id, make, model, year, plate, rate, loc);
            case "SUV": return new SUV(id, make, model, year, plate, rate, loc);
            case "VAN": return new Van(id, make, model, year, plate, rate, loc);
            case "TRUCK": return new Truck(id, make, model, year, plate, rate, loc);
            default: throw new IllegalArgumentException("Unknown vehicle type: " + type);
        }
    }

    /**
     * O(1) type lookup + O(k) to collect results from PriorityQueue (already sorted by price).
     * Naive version does O(n) linear scan through all vehicles.
     */
    public List<Vehicle> searchAvailable(String type, Location location) {
        List<Vehicle> results = new ArrayList<>();
        String typeKey = type != null ? type.toUpperCase() : null;

        if (typeKey != null && location != null) {
            Map<String, PriorityQueue<Vehicle>> locMap = availableByTypeAndLocation.get(typeKey);
            if (locMap != null) {
                PriorityQueue<Vehicle> queue = locMap.get(location.getLocationId());
                if (queue != null) results.addAll(queue);
            }
        } else if (typeKey != null) {
            PriorityQueue<Vehicle> queue = availableByType.get(typeKey);
            if (queue != null) results.addAll(queue);
        } else {
            for (Vehicle v : vehicles) {
                if (v.isAvailable()) results.add(v);
            }
        }
        return results;
    }

    public List<Vehicle> searchAvailable(String type) {
        return searchAvailable(type, null);
    }

    /**
     * Returns the cheapest available vehicle of a given type in O(log n).
     */
    public Vehicle getCheapestAvailable(String type) {
        PriorityQueue<Vehicle> queue = availableByType.get(type.toUpperCase());
        return queue != null ? queue.peek() : null;
    }

    public Reservation makeReservation(Reservation reservation) {
        Vehicle vehicle = reservation.getVehicle();
        if (!vehicle.isAvailable()) {
            System.out.println("Vehicle is not available: " + vehicle);
            return null;
        }
        vehicle.setAvailable(false);
        deindexVehicle(vehicle);
        reservations.add(reservation);
        return reservation;
    }

    public Bill completeReservation(Reservation reservation) {
        reservation.setStatus(Reservation.Status.COMPLETED);
        Vehicle vehicle = reservation.getVehicle();
        vehicle.setAvailable(true);
        vehicle.setCurrentLocation(reservation.getDropoffLocation());
        indexVehicle(vehicle);
        notifyWaitlist(vehicle.getType(), vehicle);
        return new Bill(reservation);
    }

    public void cancelReservation(Reservation reservation) {
        reservation.setStatus(Reservation.Status.CANCELLED);
        Vehicle vehicle = reservation.getVehicle();
        vehicle.setAvailable(true);
        indexVehicle(vehicle);
        notifyWaitlist(vehicle.getType(), vehicle);
    }

    public void addToWaitlist(String vehicleType, Customer customer) {
        waitlist.computeIfAbsent(vehicleType.toUpperCase(), k -> new ArrayList<>()).add(customer);
        System.out.println(customer.getName() + " added to waitlist for " + vehicleType);
    }

    private void notifyWaitlist(String vehicleType, Vehicle vehicle) {
        List<Customer> waiting = waitlist.get(vehicleType.toUpperCase());
        if (waiting != null && !waiting.isEmpty()) {
            for (Customer c : waiting) {
                c.notify(vehicle.getMake() + " " + vehicle.getModel() + " (" + vehicleType + ") is now available!");
            }
            waiting.clear();
        }
    }

    public List<Reservation> getReservations() { return Collections.unmodifiableList(reservations); }
    public List<Vehicle> getVehicles() { return Collections.unmodifiableList(vehicles); }
}

// strategy/PricingStrategy.java — Interchangeable rental pricing algorithms (daily, weekly, weekend)
// DESIGN PATTERN: Strategy

public interface PricingStrategy { // interface = swappable pricing; strategy pattern
    double calculatePrice(Vehicle vehicle, int days);
    String getName();
}

class DailyPricing implements PricingStrategy {
    @Override
    public double calculatePrice(Vehicle vehicle, int days) {
        return vehicle.getBaseDailyRate() * days;
    }

    @Override
    public String getName() { return "Daily"; }
}

class WeeklyPricing implements PricingStrategy {
    private static final double WEEKLY_DISCOUNT = 0.85; // 15% discount

    @Override
    public double calculatePrice(Vehicle vehicle, int days) {
        int weeks = days / 7;
        int remainingDays = days % 7;
        double weeklyRate = vehicle.getBaseDailyRate() * 7 * WEEKLY_DISCOUNT;
        return (weeks * weeklyRate) + (remainingDays * vehicle.getBaseDailyRate());
    }

    @Override
    public String getName() { return "Weekly"; }
}

class WeekendPricing implements PricingStrategy {
    private static final double WEEKEND_SURCHARGE = 1.20; // 20% surcharge

    @Override
    public double calculatePrice(Vehicle vehicle, int days) {
        return vehicle.getBaseDailyRate() * days * WEEKEND_SURCHARGE;
    }

    @Override
    public String getName() { return "Weekend"; }
}

// concurrent/Main.java — 15 customers competing for 5 SUVs, exactly 5 get reservations

import java.util.*;
import java.util.concurrent.CountDownLatch;
import java.util.concurrent.atomic.AtomicInteger;

public class Main {
    public static void main(String[] args) throws InterruptedException {
        System.out.println("=== Concurrent Car Rental System Demo ===\n");

        RentalService service = new RentalService();

        // Add 5 SUVs to the fleet
        for (int i = 0; i < 5; i++) {
            service.addVehicle(new Vehicle("SUV-" + i, "SUV Model-" + i, VehicleType.SUV, 75.0));
        }

        int customerCount = 15;
        System.out.println("Scenario: " + customerCount + " customers simultaneously trying to reserve SUVs.");
        System.out.println("Available SUVs: 5");
        System.out.println("Expected: Exactly 5 get reservations, 10 are denied.\n");

        CountDownLatch startLatch = new CountDownLatch(1);
        CountDownLatch doneLatch = new CountDownLatch(customerCount);
        AtomicInteger reserved = new AtomicInteger(0);
        AtomicInteger denied = new AtomicInteger(0);
        List<String> results = Collections.synchronizedList(new ArrayList<>());

        for (int i = 0; i < customerCount; i++) {
            final int id = i;
            new Thread(() -> {
                try {
                    startLatch.await();
                    String customerName = "Customer-" + id;
                    Reservation res = service.reserve(customerName, VehicleType.SUV);
                    if (res != null) {
                        reserved.incrementAndGet();
                        results.add("  [RESERVED] " + customerName + " got " + res.getVehicle().getName());
                    } else {
                        denied.incrementAndGet();
                        results.add("  [DENIED]   " + customerName + " — no SUVs available");
                    }
                } catch (InterruptedException e) {
                    Thread.currentThread().interrupt();
                } finally {
                    doneLatch.countDown();
                }
            }, "Customer-" + id).start();
        }

        startLatch.countDown();
        doneLatch.await();

        // Print results
        results.sort(String::compareTo);
        for (String r : results) {
            System.out.println(r);
        }

        // Verification
        System.out.println("\n--- Summary ---");
        System.out.println("Customers: " + customerCount);
        System.out.println("SUVs available: 5");
        System.out.println("Reservations made: " + reserved.get());
        System.out.println("Reservations denied: " + denied.get());
        System.out.println("Remaining SUVs: " + service.getAvailableCount(VehicleType.SUV));

        boolean correctReserved = reserved.get() == 5;
        boolean correctDenied = denied.get() == 10;
        boolean noRemainingCars = service.getAvailableCount(VehicleType.SUV) == 0;

        System.out.println("\nExactly 5 reservations: " + (correctReserved ? "PASSED" : "FAILED"));
        System.out.println("Exactly 10 denied: " + (correctDenied ? "PASSED" : "FAILED"));
        System.out.println("No SUVs remaining: " + (noRemainingCars ? "PASSED" : "FAILED"));

        boolean allPassed = correctReserved && correctDenied && noRemainingCars;
        System.out.println("\nOverall: " + (allPassed ? "ALL TESTS PASSED" : "SOME TESTS FAILED"));
    }
}

// concurrent/model/Reservation.java — Reservation linking a customer to a vehicle

import java.util.concurrent.atomic.AtomicLong;

class Reservation {
    private static final AtomicLong ID_GEN = new AtomicLong(1); // AtomicLong = thread-safe ID generator; no duplicates

    private final long reservationId;    // final = set once; safe publication across threads
    private final String customerName;   // final = immutable after construction; thread-safe read
    private final Vehicle vehicle;       // final = reference fixed; safe to share between threads
    private final long timestamp;        // final = creation time frozen; never changes

    public Reservation(String customerName, Vehicle vehicle) {
        this.reservationId = ID_GEN.getAndIncrement();
        this.customerName = customerName;
        this.vehicle = vehicle;
        this.timestamp = System.nanoTime();
    }

    public long getReservationId() { return reservationId; }
    public String getCustomerName() { return customerName; }
    public Vehicle getVehicle() { return vehicle; }
    public long getTimestamp() { return timestamp; }

    @Override
    public String toString() {
        return "Reservation#" + reservationId + " [" + customerName + " -> " + vehicle.getName() + "]";
    }
}

// concurrent/model/Vehicle.java — Vehicle with type classification for fleet management

enum VehicleType { SEDAN, SUV, TRUCK, VAN, COMPACT } // enum = fixed set; used as ConcurrentHashMap key

class Vehicle {
    private final String vehicleId;  // final = immutable identity; safe to read from any thread
    private final String name;       // final = never changes after construction
    private final VehicleType type;  // final = used as map key for fleet lookup
    private final double dailyRate;  // final = price fixed at creation; thread-safe

    public Vehicle(String vehicleId, String name, VehicleType type, double dailyRate) {
        this.vehicleId = vehicleId;
        this.name = name;
        this.type = type;
        this.dailyRate = dailyRate;
    }

    public String getVehicleId() { return vehicleId; }
    public String getName() { return name; }
