import java.util.*;
import java.time.LocalDateTime;

public class Order {
    private String orderId;              // unique order identifier
    private Customer customer;           // who placed the order
    private Restaurant restaurant;       // which restaurant prepares the food
    private Map<MenuItem, Integer> items; // LinkedHashMap = preserves insertion order of items
    private OrderState state;            // enum-based state machine for order lifecycle
    private DeliveryAgent agent;         // assigned delivery driver
    private LocalDateTime orderTime;     // timestamp when order was placed
    private LocalDateTime deliveryTime;  // timestamp when delivered

    private static int counter = 0;      // shared ID generator across all orders

    public Order(Customer customer, Restaurant restaurant) {
        this.orderId = "ORD-" + (++counter);
        this.customer = customer;
        this.restaurant = restaurant;
        this.items = new LinkedHashMap<>();
        this.state = OrderState.PLACED;
        this.orderTime = LocalDateTime.now();
    }

    public void addItem(MenuItem item, int quantity) {
        items.put(item, items.getOrDefault(item, 0) + quantity);
    }

    public boolean transition(OrderState newState) {
        if (state.canTransitionTo(newState)) {
            state = newState;
            if (newState == OrderState.DELIVERED) {
                deliveryTime = LocalDateTime.now();
            }
            customer.onOrderUpdate(this);
            return true;
        }
        System.out.println("Invalid transition: " + state + " -> " + newState);
        return false;
    }

    public double getTotalAmount() {
        double total = 0;
        for (Map.Entry<MenuItem, Integer> entry : items.entrySet()) {
            total += entry.getKey().getPrice() * entry.getValue();
        }
        return total;
    }

    public void assignAgent(DeliveryAgent agent) {
        this.agent = agent;
        agent.assignOrder();
    }

    public String getOrderId() { return orderId; }
    public Customer getCustomer() { return customer; }
    public Restaurant getRestaurant() { return restaurant; }
    public Map<MenuItem, Integer> getItems() { return Collections.unmodifiableMap(items); }
    public OrderState getState() { return state; }
    public DeliveryAgent getAgent() { return agent; }

    public String getItemsSummary() {
        StringBuilder sb = new StringBuilder();
        for (Map.Entry<MenuItem, Integer> entry : items.entrySet()) {
            if (sb.length() > 0) sb.append(", ");
            sb.append(entry.getValue()).append("x ").append(entry.getKey().getName());
        }
        return sb.toString();
    }

    @Override
    public String toString() {
        return String.format("Order[%s] from %s - %s - $%.2f [%s]",
                orderId, restaurant.getName(), getItemsSummary(), getTotalAmount(), state);
    }
}

// model/OrderState.java — Order lifecycle states with valid transition rules

public enum OrderState { // enum = fixed order lifecycle states; enforces valid transitions
    PLACED,
    CONFIRMED,
    PREPARING,
    OUT_FOR_DELIVERY,
    DELIVERED,
    CANCELLED;

    public boolean canTransitionTo(OrderState next) {
        switch (this) {
            case PLACED: return next == CONFIRMED || next == CANCELLED;
            case CONFIRMED: return next == PREPARING || next == CANCELLED;
            case PREPARING: return next == OUT_FOR_DELIVERY || next == CANCELLED;
            case OUT_FOR_DELIVERY: return next == DELIVERED;
            case DELIVERED: return false;
            case CANCELLED: return false;
            default: return false;
        }
    }
}

