// service/AssignDriverCommand.java — Command that picks an agent and dispatches the order

class AssignDriverCommand implements OrderCommand {
    private final FoodDeliverySystem system;
    private final Order order;
    private DeliveryAgent assigned;                 // captured for undo()

    public AssignDriverCommand(FoodDeliverySystem system, Order order) {
        this.system = system;
        this.order = order;
    }

    @Override
    public boolean execute() {
        boolean ok = system.assignAndDispatch(order);
        if (ok) assigned = order.getAgent();
        return ok;
    }

    @Override
    public boolean undo() {
        // Free up the agent by marking the order cancelled (compensating action).
        if (assigned == null) return false;
        return system.cancelOrder(order);
    }

    @Override
    public String name() { return "AssignDriver"; }
}

// service/CancelOrderCommand.java — Command that cancels a pre-existing order

class CancelOrderCommand implements OrderCommand {
    private final FoodDeliverySystem system;
    private final Order order;
    private OrderState previousState;               // snapshot for undo()

    public CancelOrderCommand(FoodDeliverySystem system, Order order) {
        this.system = system;
        this.order = order;
    }

    @Override
    public boolean execute() {
        previousState = order.getState();
        return system.cancelOrder(order);
    }

    @Override
    public boolean undo() {
        // Best-effort: restore prior state. Real systems would use compensating actions.
        if (previousState == null) return false;
        return order.transition(previousState);
    }

    @Override
    public String name() { return "CancelOrder"; }
}

// service/CommandInvoker.java — Runs OrderCommands and keeps a LIFO history for undo

import java.util.Stack;

class CommandInvoker {
    private final Stack<OrderCommand> history = new Stack<>();   // LIFO: latest command undone first

    /** Run a command and push it onto history if it succeeds. */
    public boolean run(OrderCommand command) {
        boolean ok = command.execute();
        System.out.println("  [cmd] " + command.name() + " -> " + (ok ? "OK" : "FAILED"));
        if (ok) history.push(command);
        return ok;
    }

    /** Undo the most recent successful command. */
    public boolean undoLast() {
        if (history.isEmpty()) return false;
        OrderCommand last = history.pop();
        boolean ok = last.undo();
        System.out.println("  [cmd] undo " + last.name() + " -> " + (ok ? "OK" : "FAILED"));
        return ok;
    }

    public int historySize() { return history.size(); }
}

// service/FoodDeliverySystem.java — Optimized orchestration with spatial indexing for agent dispatch

import java.util.*;

public class FoodDeliverySystem {
    private List<Restaurant> restaurants;       // ArrayList = O(1) append for registrations
    private List<DeliveryAgent> agents;         // ArrayList = O(1) append; passed to strategy
    private List<Order> orders;                 // ArrayList = O(1) append for order history
    private DeliveryStrategy deliveryStrategy;  // Strategy pattern; default uses spatial grid

    public FoodDeliverySystem() {
        this.restaurants = new ArrayList<>();
        this.agents = new ArrayList<>();
        this.orders = new ArrayList<>();
        this.deliveryStrategy = new SpatialGridStrategy(0.01); // ~1km grid cells
    }

    public void setDeliveryStrategy(DeliveryStrategy strategy) {
        this.deliveryStrategy = strategy;
    }

    public void registerRestaurant(Restaurant restaurant) { restaurants.add(restaurant); }
    public void registerAgent(DeliveryAgent agent) { agents.add(agent); }

    public List<Restaurant> getOpenRestaurants() {
        List<Restaurant> open = new ArrayList<>();
        for (Restaurant r : restaurants) {
            if (r.isOpen()) open.add(r);
        }
        return open;
    }

    public Order placeOrder(Customer customer, Restaurant restaurant, Map<MenuItem, Integer> items) {
        if (!restaurant.isOpen()) {
            System.out.println("Restaurant is closed.");
            return null;
        }
        Order order = new Order(customer, restaurant);
        for (Map.Entry<MenuItem, Integer> entry : items.entrySet()) {
            order.addItem(entry.getKey(), entry.getValue());
        }
        orders.add(order);
        System.out.println("Order placed: " + order);
        return order;
    }

    public boolean confirmOrder(Order order) { return order.transition(OrderState.CONFIRMED); }
    public boolean startPreparing(Order order) { return order.transition(OrderState.PREPARING); }

    public boolean assignAndDispatch(Order order) {
        DeliveryAgent agent = deliveryStrategy.selectAgent(agents, order.getRestaurant());
        if (agent == null) {
            System.out.println("No available delivery agents!");
            return false;
        }
        order.assignAgent(agent);
        System.out.println("Agent assigned: " + agent.getName() + " (strategy: " + deliveryStrategy.getName() + ")");
        return order.transition(OrderState.OUT_FOR_DELIVERY);
    }

    public boolean deliverOrder(Order order) {
        boolean result = order.transition(OrderState.DELIVERED);
        if (result && order.getAgent() != null) order.getAgent().completeOrder();
        return result;
    }

    public boolean cancelOrder(Order order) {
        boolean result = order.transition(OrderState.CANCELLED);
        if (result && order.getAgent() != null) order.getAgent().completeOrder();
        return result;
    }

    public Rating rateOrder(Order order, double restaurantRating, double agentRating, String comment) {
        Rating rating = new Rating(order.getOrderId(), restaurantRating, agentRating, comment);
        order.getRestaurant().addRating(restaurantRating);
        if (order.getAgent() != null) order.getAgent().addRating(agentRating);
        return rating;
    }

    public List<Order> getOrders() { return Collections.unmodifiableList(orders); }
}

// service/OrderCommand.java — Command contract for order operations with undo support
//
// Each concrete command captures all the state it needs in its constructor
// (system + target order/inputs) and operates on that state in execute().
// undo() reverses the effect when possible (e.g. restore prior order state).

interface OrderCommand {
    /** Run the command. Returns true on success. */
    boolean execute();

    /** Reverse the command's effect. Returns true on success. */
    boolean undo();

    /** Short label used by the invoker for logging. */
    String name();
}

