// strategy/DeliveryStrategy.java — Spatial grid-based agent lookup for O(1) nearest-agent retrieval
// DESIGN PATTERN: Strategy

import java.util.*;

public interface DeliveryStrategy { // interface = swappable agent selection algorithm
    DeliveryAgent selectAgent(List<DeliveryAgent> agents, Restaurant restaurant);
    String getName();
}

/**
 * Optimized: Grid-based spatial index for O(1) nearest agent lookup.
 * Divides the map into grid cells; agents register in cells by location.
 * Searching starts from the restaurant's cell and expands outward in rings.
 */
class SpatialGridStrategy implements DeliveryStrategy {
    private double cellSize;                        // grid cell dimension in degrees
    private Map<String, List<DeliveryAgent>> grid;  // HashMap = O(1) cell lookup by "x:y" key

    public SpatialGridStrategy(double cellSize) {
        this.cellSize = cellSize;
        this.grid = new HashMap<>();
    }

    private String cellKey(double lat, double lng) {
        int cellX = (int) Math.floor(lat / cellSize);
        int cellY = (int) Math.floor(lng / cellSize);
        return cellX + ":" + cellY;
    }

    public void indexAgents(List<DeliveryAgent> agents) {
        grid.clear();
        for (DeliveryAgent agent : agents) {
            if (!agent.isAvailable()) continue;
            String key = cellKey(agent.getLatitude(), agent.getLongitude());
            grid.computeIfAbsent(key, k -> new ArrayList<>()).add(agent);
        }
    }

    @Override
    public DeliveryAgent selectAgent(List<DeliveryAgent> agents, Restaurant restaurant) {
        indexAgents(agents);

        double lat = restaurant.getLatitude();
        double lng = restaurant.getLongitude();
        int centerX = (int) Math.floor(lat / cellSize);
        int centerY = (int) Math.floor(lng / cellSize);

        // Expand search in rings from center cell
        for (int ring = 0; ring <= 5; ring++) {
            DeliveryAgent best = null;
            double bestDist = Double.MAX_VALUE;

            for (int dx = -ring; dx <= ring; dx++) {
                for (int dy = -ring; dy <= ring; dy++) {
                    if (Math.abs(dx) != ring && Math.abs(dy) != ring) continue; // Only ring border
                    String key = (centerX + dx) + ":" + (centerY + dy);
                    List<DeliveryAgent> cellAgents = grid.get(key);
                    if (cellAgents == null) continue;

                    for (DeliveryAgent agent : cellAgents) {
                        if (!agent.isAvailable()) continue;
                        double dist = agent.distanceTo(lat, lng);
                        if (dist < bestDist) {
                            bestDist = dist;
                            best = agent;
                        }
                    }
                }
            }
            if (best != null) return best;
        }
        return null;
    }

    @Override
    public String getName() { return "Spatial Grid (O(1) cell lookup)"; }
}

/**
 * Priority queue based dispatch: agents sorted by composite score
 * (distance + load factor) for balanced assignment.
 */
class PriorityDispatchStrategy implements DeliveryStrategy { // PriorityQueue-based scoring
    @Override
    public DeliveryAgent selectAgent(List<DeliveryAgent> agents, Restaurant restaurant) {
        PriorityQueue<DeliveryAgent> pq = new PriorityQueue<>((a, b) -> {
            double scoreA = a.distanceTo(restaurant.getLatitude(), restaurant.getLongitude())
                           + a.getActiveOrders() * 2.0;
            double scoreB = b.distanceTo(restaurant.getLatitude(), restaurant.getLongitude())
                           + b.getActiveOrders() * 2.0;
            return Double.compare(scoreA, scoreB);
        });

        for (DeliveryAgent agent : agents) {
            if (agent.isAvailable()) pq.offer(agent);
        }
        return pq.poll();
    }

    @Override
    public String getName() { return "Priority Dispatch (distance + load)"; }
}

// concurrent/Main.java — 20 orders competing for 5 agents, exactly 5 assigned immediately

import java.util.*;
import java.util.concurrent.CountDownLatch;
import java.util.concurrent.atomic.AtomicInteger;

public class Main {
    public static void main(String[] args) throws InterruptedException {
        System.out.println("=== Concurrent Food Delivery Demo ===\n");

        DispatchService service = new DispatchService();

        // Register 5 delivery agents
        for (int i = 0; i < 5; i++) {
            service.registerAgent(new DeliveryAgent("AGENT-" + i, "Agent-" + i));
        }

        int orderCount = 20;
        System.out.println("Scenario: " + orderCount + " orders competing for 5 delivery agents simultaneously.");
        System.out.println("Expected: Exactly 5 assigned immediately, 15 queued.\n");

        CountDownLatch startLatch = new CountDownLatch(1);
        CountDownLatch doneLatch = new CountDownLatch(orderCount);
        AtomicInteger assigned = new AtomicInteger(0);
        AtomicInteger queued = new AtomicInteger(0);
        List<String> results = Collections.synchronizedList(new ArrayList<>());

        for (int i = 0; i < orderCount; i++) {
            final int id = i;
            new Thread(() -> {
                try {
                    startLatch.await();
                    Order order = new Order("Customer-" + id, "Restaurant-" + (id % 5));
                    boolean dispatched = service.dispatch(order);
                    if (dispatched) {
                        assigned.incrementAndGet();
                        results.add("  [ASSIGNED] " + order.getOrderId() + " -> " + order.getAssignedAgentId());
                    } else {
                        queued.incrementAndGet();
                        results.add("  [QUEUED]   " + order.getOrderId() + " — no agents available");
                    }
                } catch (InterruptedException e) {
                    Thread.currentThread().interrupt();
                } finally {
                    doneLatch.countDown();
                }
            }, "Order-" + id).start();
        }

        startLatch.countDown();
        doneLatch.await();

        // Print results
        results.sort(String::compareTo);
        for (String r : results) {
            System.out.println(r);
        }

        // Agent states
        System.out.println("\nAgent states:");
        for (DeliveryAgent agent : service.getAgents()) {
            System.out.println("  " + agent);
        }

        // Verification
        System.out.println("\n--- Summary ---");
        System.out.println("Orders: " + orderCount);
        System.out.println("Agents: 5");
        System.out.println("Assigned immediately: " + assigned.get());
        System.out.println("Queued: " + queued.get());
        System.out.println("Pending queue size: " + service.getPendingQueueSize());

        // Verify no agent has multiple orders
        Set<String> assignedAgents = new HashSet<>();
        boolean noDuplicateAssignment = true;
        for (DeliveryAgent agent : service.getAgents()) {
            if (agent.getCurrentOrder() != null) {
                if (!assignedAgents.add(agent.getAgentId())) {
                    noDuplicateAssignment = false;
                }
            }
        }

        boolean correctAssigned = assigned.get() == 5;
        boolean correctQueued = queued.get() == 15;

        System.out.println("\nExactly 5 assigned: " + (correctAssigned ? "PASSED" : "FAILED"));
        System.out.println("Exactly 15 queued: " + (correctQueued ? "PASSED" : "FAILED"));
        System.out.println("No duplicate agent assignment: " + (noDuplicateAssignment ? "PASSED" : "FAILED"));

        boolean allPassed = correctAssigned && correctQueued && noDuplicateAssignment;
        System.out.println("\nOverall: " + (allPassed ? "ALL TESTS PASSED" : "SOME TESTS FAILED"));
    }
}

// concurrent/model/DeliveryAgent.java — Agent with AtomicReference for CAS-based order assignment

import java.util.concurrent.atomic.AtomicReference;

class DeliveryAgent {
    private final String agentId;   // final = immutable identity; safe to read from any thread
    private final String name;      // final = never changes; safe publication guaranteed
    private final AtomicReference<Order> currentOrder = new AtomicReference<>(null); // AtomicReference = CAS-based assignment; prevents double-booking

    public DeliveryAgent(String agentId, String name) {
        this.agentId = agentId;
        this.name = name;
    }

    /**
     * CAS-based assignment: only ONE order can claim this agent.
     * Atomically transitions from null (free) to the given order (assigned).
     */
    public boolean tryAssign(Order order) {
        return currentOrder.compareAndSet(null, order);
    }

    /**
     * Release agent after delivery is complete.
     */
    public void release() {
        currentOrder.set(null);
    }

    public boolean isFree() {
        return currentOrder.get() == null;
    }

    public Order getCurrentOrder() { return currentOrder.get(); }
    public String getAgentId() { return agentId; }
    public String getName() { return name; }

    @Override
    public String toString() {
        Order o = currentOrder.get();
        return agentId + " (" + name + ") [" + (o == null ? "FREE" : "ASSIGNED: " + o.getOrderId()) + "]";
    }
}

// concurrent/model/Order.java — Order awaiting delivery agent assignment

import java.util.concurrent.atomic.AtomicLong;

class Order {
    private static final AtomicLong ID_GEN = new AtomicLong(1); // AtomicLong = thread-safe unique ID generator

    private final String orderId;        // final = set once; safe to read from any thread
    private final String customerName;   // final = immutable after construction
    private final String restaurant;     // final = immutable after construction
    private volatile String assignedAgentId; // volatile = visible to all threads when written

    public Order(String customerName, String restaurant) {
        this.orderId = "ORD-" + ID_GEN.getAndIncrement();
        this.customerName = customerName;
        this.restaurant = restaurant;
    }

    public String getOrderId() { return orderId; }
    public String getCustomerName() { return customerName; }
    public String getRestaurant() { return restaurant; }
    public String getAssignedAgentId() { return assignedAgentId; }
    public void setAssignedAgentId(String agentId) { this.assignedAgentId = agentId; }

    @Override
    public String toString() {
        return orderId + " [" + customerName + " from " + restaurant + "]";
    }
}

// concurrent/service/DispatchService.java — CAS-based agent assignment preventing double-booking

import java.util.concurrent.*;
import java.util.concurrent.atomic.AtomicInteger;

/**
 * Thread-safe dispatch service.
 *
 * Race condition solved: Multiple orders trying to claim the same delivery agent.
 * Each agent uses AtomicReference<Order> — CAS from null to order ensures
 * only one order can claim each agent.
 */
class DispatchService {
    private final CopyOnWriteArrayList<DeliveryAgent> agents = new CopyOnWriteArrayList<>(); // CopyOnWriteArrayList = safe iteration while adding agents
    private final ConcurrentLinkedQueue<Order> pendingOrders = new ConcurrentLinkedQueue<>(); // ConcurrentLinkedQueue = lock-free queue for pending orders
    private final AtomicInteger assignedCount = new AtomicInteger(0); // AtomicInteger = lock-free counter via CAS
    private final AtomicInteger queuedCount = new AtomicInteger(0);   // AtomicInteger = lock-free counter via CAS

    public void registerAgent(DeliveryAgent agent) {
        agents.add(agent);
    }

    /**
     * Dispatch an order to any available agent.
     * Iterates agents and attempts CAS assignment.
     * If no agent available, order goes to pending queue.
     */
    public boolean dispatch(Order order) {
        for (DeliveryAgent agent : agents) {
            if (agent.tryAssign(order)) {
                // CAS succeeded — this order got the agent
                order.setAssignedAgentId(agent.getAgentId());
                assignedCount.incrementAndGet();
                return true;
            }
            // CAS failed — agent already taken, try next
        }

        // No agent available — queue the order
        pendingOrders.offer(order);
        queuedCount.incrementAndGet();
        return false;
    }

    /**
     * Complete delivery and try to assign next pending order to freed agent.
     */
    public void completeDelivery(DeliveryAgent agent) {
        agent.release();

        // Try to assign a pending order
        Order pending = pendingOrders.poll();
        if (pending != null) {
            if (agent.tryAssign(pending)) {
                pending.setAssignedAgentId(agent.getAgentId());
                assignedCount.incrementAndGet();
                queuedCount.decrementAndGet();
            } else {
                pendingOrders.offer(pending); // re-queue if agent was taken
            }
        }
    }

    public int getAssignedCount() { return assignedCount.get(); }
    public int getQueuedCount() { return queuedCount.get(); }
    public int getPendingQueueSize() { return pendingOrders.size(); }
    public CopyOnWriteArrayList<DeliveryAgent> getAgents() { return agents; }
}

