import java.util.*;

public class RideService {
    private List<Driver> drivers;                  // private = registered driver pool
    private List<Trip> trips;                      // private = all trips in the system
    private MatchingStrategy matchingStrategy;     // private = strategy pattern for driver matching
    private PricingStrategy pricingStrategy;       // private = strategy pattern for fare calculation
    private PaymentProcessor paymentProcessor;     // private = proxy wrapping real payment gateway

    public RideService() {
        this.drivers = new ArrayList<>();
        this.trips = new ArrayList<>();
        this.matchingStrategy = new NearestDriverStrategy();
        this.pricingStrategy = new BasePricing();
        this.paymentProcessor = new PaymentProxy(new RealPaymentProcessor());
    }

    public void registerDriver(Driver driver) { drivers.add(driver); }

    public void setMatchingStrategy(MatchingStrategy strategy) { this.matchingStrategy = strategy; }
    public void setPricingStrategy(PricingStrategy strategy) { this.pricingStrategy = strategy; }

    public double estimateFare(Location pickup, Location dropoff, String vehicleType) {
        double distance = pickup.distanceTo(dropoff);
        return pricingStrategy.calculateFare(distance, vehicleType);
    }

    public Trip requestRide(Rider rider, Location pickup, Location dropoff) {
        Trip trip = new Trip(rider, pickup, dropoff);
        trips.add(trip);

        // Find a driver
        Driver driver = matchingStrategy.findDriver(drivers, pickup);
        if (driver == null) {
            System.out.println("No drivers available. Please try again.");
            trip.cancelTrip();
            return trip;
        }

        double distance = driver.distanceTo(pickup);
        System.out.printf("Driver matched: %s (%.1f stars, %.1f km away) [Strategy: %s]%n",
                driver.getName(), driver.getAverageRating(), distance, matchingStrategy.getName());
        trip.matchDriver(driver);
        return trip;
    }

    public void startTrip(Trip trip) {
        trip.startTrip();
    }

    public Payment completeTrip(Trip trip, Payment.Method paymentMethod) {
        double fare = pricingStrategy.calculateFare(trip.getDistance(), trip.getDriver().getVehicleType());
        trip.completeTrip(fare);

        Payment payment = new Payment(trip.getTripId(), fare, paymentMethod);
        boolean ok = paymentProcessor.process(fare, trip.getRider().getName());
        payment.markStatus(ok);
        return payment;
    }

    public void cancelTrip(Trip trip) {
        trip.cancelTrip();
    }

    public void rateDriver(Driver driver, double rating) {
        driver.addRating(rating);
    }

    public void rateRider(Rider rider, double rating) {
        rider.addRating(rating);
    }

    // Surge pricing control
    public void activateSurge(double multiplier) {
        this.pricingStrategy = new SurgePricing(new BasePricing(), multiplier);
        System.out.printf("Surge pricing activated: %.1fx%n", multiplier);
    }

    public void deactivateSurge() {
        this.pricingStrategy = new BasePricing();
        System.out.println("Surge pricing deactivated.");
    }

    public List<Driver> getAvailableDrivers() {
        List<Driver> available = new ArrayList<>();
        for (Driver d : drivers) {
            if (d.isAvailable()) available.add(d);
        }
        return available;
    }

    public List<Trip> getTrips() { return Collections.unmodifiableList(trips); }
}

// strategy/MatchingStrategy.java — Interchangeable driver matching algorithms (nearest, highest rated)
// DESIGN PATTERN: Strategy

import java.util.List;

public interface MatchingStrategy { // interface = contract for driver matching algorithms
    Driver findDriver(List<Driver> drivers, Location pickup);
    String getName();
}

class NearestDriverStrategy implements MatchingStrategy { // implements = fulfills the contract
    @Override
    public Driver findDriver(List<Driver> drivers, Location pickup) {
        Driver nearest = null;
        double minDist = Double.MAX_VALUE;

        for (Driver driver : drivers) {
            if (!driver.isAvailable()) continue;
            double dist = driver.distanceTo(pickup);
            if (dist < minDist) {
                minDist = dist;
                nearest = driver;
            }
        }
        return nearest;
    }

    @Override
    public String getName() { return "Nearest Driver"; }
}

class HighestRatedStrategy implements MatchingStrategy { // implements = fulfills the contract
    private double maxDistance;    // private = radius filter for candidate drivers

    public HighestRatedStrategy(double maxDistance) {
        this.maxDistance = maxDistance;
    }

    @Override
    public Driver findDriver(List<Driver> drivers, Location pickup) {
        Driver best = null;
        double bestRating = -1;

        for (Driver driver : drivers) {
            if (!driver.isAvailable()) continue;
            if (driver.distanceTo(pickup) > maxDistance) continue;
            if (driver.getAverageRating() > bestRating) {
                bestRating = driver.getAverageRating();
                best = driver;
            }
        }
        return best;
    }

    @Override
    public String getName() { return "Highest Rated (within " + maxDistance + " km)"; }
}

// strategy/PricingStrategy.java — Interchangeable fare calculation algorithms (base, surge)
// DESIGN PATTERN: Strategy

public interface PricingStrategy { // interface = contract for fare calculation algorithms
    double calculateFare(double distanceKm, String vehicleType);
    String getName();
}

class BasePricing implements PricingStrategy { // implements = fulfills the pricing contract
    private static final double BASE_FARE = 3.00;   // static final = compile-time constant
    private static final double PER_KM_RATE = 2.00; // static final = compile-time constant

    @Override
    public double calculateFare(double distanceKm, String vehicleType) {
        double multiplier = getVehicleMultiplier(vehicleType);
        return (BASE_FARE + distanceKm * PER_KM_RATE) * multiplier;
    }

    private double getVehicleMultiplier(String type) {
        switch (type.toLowerCase()) {
            case "economy": return 1.0;
            case "comfort": return 1.3;
            case "premium": return 1.8;
            case "xl": return 1.5;
            default: return 1.0;
        }
    }

    @Override
    public String getName() { return "Standard"; }
}

class SurgePricing implements PricingStrategy { // implements = decorator pattern over base pricing
    private PricingStrategy basePricing;    // private = wraps another pricing strategy (decorator)
    private double surgeMultiplier;         // private = multiplier applied to base fare

    public SurgePricing(PricingStrategy basePricing, double surgeMultiplier) {
        this.basePricing = basePricing;
        this.surgeMultiplier = surgeMultiplier;
    }

    @Override
    public double calculateFare(double distanceKm, String vehicleType) {
        return basePricing.calculateFare(distanceKm, vehicleType) * surgeMultiplier;
    }

    @Override
    public String getName() {
        return String.format("Surge (%.1fx)", surgeMultiplier);
    }

    public double getSurgeMultiplier() { return surgeMultiplier; }
}

