        if (state.canTransitionTo(newState)) {
            state = newState;
            rider.onTripUpdate(this);
            if (driver != null) driver.onTripUpdate(this);
            return true;
        }
        System.out.println("Invalid trip transition: " + state + " -> " + newState);
