    private MatchingStrategy matchingStrategy; // Default: GeospatialGridStrategy for O(1) cell lookup
    private PricingStrategy pricingStrategy;   // Swappable pricing; supports surge decorator
    private PaymentProcessor paymentProcessor; // Proxy wrapping real payment gateway

    public RideService() {
        this.drivers = new ArrayList<>();
        this.trips = new ArrayList<>();
        this.matchingStrategy = new GeospatialGridStrategy();
        this.pricingStrategy = new BasePricing();
        this.paymentProcessor = new PaymentProxy(new RealPaymentProcessor());
    }

    public void registerDriver(Driver driver) { drivers.add(driver); }
    public void setMatchingStrategy(MatchingStrategy strategy) { this.matchingStrategy = strategy; }
    public void setPricingStrategy(PricingStrategy strategy) { this.pricingStrategy = strategy; }

    public double estimateFare(Location pickup, Location dropoff, String vehicleType) {
        double distance = pickup.distanceTo(dropoff);
        return pricingStrategy.calculateFare(distance, vehicleType);
    }

    public Trip requestRide(Rider rider, Location pickup, Location dropoff) {
        Trip trip = new Trip(rider, pickup, dropoff);
        trips.add(trip);

        Driver driver = matchingStrategy.findDriver(drivers, pickup);
        if (driver == null) {
            System.out.println("No drivers available. Please try again.");
            trip.cancelTrip();
            return trip;
        }

        double distance = driver.distanceTo(pickup);
        System.out.printf("Driver matched: %s (%.1f stars, %.1f km away) [Strategy: %s]%n",
                driver.getName(), driver.getAverageRating(), distance, matchingStrategy.getName());
        trip.matchDriver(driver);
        return trip;
    }

    public void startTrip(Trip trip) { trip.startTrip(); }

    public Payment completeTrip(Trip trip, Payment.Method paymentMethod) {
        double fare = pricingStrategy.calculateFare(trip.getDistance(), trip.getDriver().getVehicleType());
        trip.completeTrip(fare);
        Payment payment = new Payment(trip.getTripId(), fare, paymentMethod);
        boolean ok = paymentProcessor.process(fare, trip.getRider().getName());
        payment.markStatus(ok);
        return payment;
    }

    public void cancelTrip(Trip trip) { trip.cancelTrip(); }
    public void rateDriver(Driver driver, double rating) { driver.addRating(rating); }
    public void rateRider(Rider rider, double rating) { rider.addRating(rating); }

    public void activateSurge(double multiplier) {
        this.pricingStrategy = new SurgePricing(new BasePricing(), multiplier);
        System.out.printf("Surge pricing activated: %.1fx%n", multiplier);
    }

    public void deactivateSurge() {
        this.pricingStrategy = new BasePricing();
        System.out.println("Surge pricing deactivated.");
    }

    public List<Trip> getTrips() { return Collections.unmodifiableList(trips); }
}

// strategy/MatchingStrategy.java — Geospatial grid + driver availability index with ConcurrentHashMap
// DESIGN PATTERN: Strategy

import java.util.*;
import java.util.concurrent.ConcurrentHashMap;

public interface MatchingStrategy { // interface = swappable driver matching algorithm
    Driver findDriver(List<Driver> drivers, Location pickup);
    String getName();
}

/**
 * Optimized: Geospatial grid with ConcurrentHashMap<GridCell, List<Driver>>
 * for O(1) cell lookup instead of O(n) scan through all drivers.
 */
class GeospatialGridStrategy implements MatchingStrategy {
    private static final double CELL_SIZE_KM = 2.0; // grid cell size in km
    private ConcurrentHashMap<String, List<Driver>> grid; // ConcurrentHashMap = O(1) cell lookup by key

    public GeospatialGridStrategy() {
        this.grid = new ConcurrentHashMap<>();
    }

    private String cellKey(Location loc) {
        int cellX = (int) Math.floor(loc.getLatitude() * 111 / CELL_SIZE_KM);
        int cellY = (int) Math.floor(loc.getLongitude() * 111 * Math.cos(Math.toRadians(loc.getLatitude())) / CELL_SIZE_KM);
        return cellX + "," + cellY;
    }

    private void rebuildIndex(List<Driver> drivers) {
        grid.clear();
        for (Driver driver : drivers) {
            if (!driver.isAvailable()) continue;
            String key = cellKey(driver.getCurrentLocation());
            grid.computeIfAbsent(key, k -> new ArrayList<>()).add(driver);
        }
    }

    @Override
    public Driver findDriver(List<Driver> drivers, Location pickup) {
        rebuildIndex(drivers);

        String centerKey = cellKey(pickup);
        int centerX = Integer.parseInt(centerKey.split(",")[0]);
        int centerY = Integer.parseInt(centerKey.split(",")[1]);

        // Expanding ring search from the pickup cell outward
        for (int ring = 0; ring <= 10; ring++) {
            Driver nearest = null;
            double minDist = Double.MAX_VALUE;

            for (int dx = -ring; dx <= ring; dx++) {
                for (int dy = -ring; dy <= ring; dy++) {
                    if (ring > 0 && Math.abs(dx) != ring && Math.abs(dy) != ring) continue;
                    String key = (centerX + dx) + "," + (centerY + dy);
                    List<Driver> cellDrivers = grid.get(key);
                    if (cellDrivers == null) continue;

                    for (Driver driver : cellDrivers) {
                        double dist = driver.distanceTo(pickup);
                        if (dist < minDist) {
                            minDist = dist;
                            nearest = driver;
                        }
                    }
                }
            }
            if (nearest != null) return nearest;
        }
        return null;
    }

    @Override
    public String getName() { return "Geospatial Grid (ConcurrentHashMap)"; }
}

class HighestRatedStrategy implements MatchingStrategy {
    private double maxDistance;

    public HighestRatedStrategy(double maxDistance) {
        this.maxDistance = maxDistance;
    }

    @Override
    public Driver findDriver(List<Driver> drivers, Location pickup) {
        Driver best = null;
        double bestRating = -1;
        for (Driver driver : drivers) {
            if (!driver.isAvailable()) continue;
            if (driver.distanceTo(pickup) > maxDistance) continue;
            if (driver.getAverageRating() > bestRating) {
                bestRating = driver.getAverageRating();
                best = driver;
            }
        }
        return best;
    }

    @Override
    public String getName() { return "Highest Rated (within " + maxDistance + " km)"; }
}

// strategy/PricingStrategy.java — Interchangeable fare calculation algorithms (base, surge)
// DESIGN PATTERN: Strategy

public interface PricingStrategy { // interface = swappable fare calculation strategy
    double calculateFare(double distanceKm, String vehicleType);
    String getName();
}

class BasePricing implements PricingStrategy {
    private static final double BASE_FARE = 3.00;
    private static final double PER_KM_RATE = 2.00;

    @Override
    public double calculateFare(double distanceKm, String vehicleType) {
        double multiplier = getVehicleMultiplier(vehicleType);
        return (BASE_FARE + distanceKm * PER_KM_RATE) * multiplier;
    }

    private double getVehicleMultiplier(String type) {
        switch (type.toLowerCase()) {
            case "economy": return 1.0;
            case "comfort": return 1.3;
            case "premium": return 1.8;
            case "xl": return 1.5;
            default: return 1.0;
        }
    }

    @Override
    public String getName() { return "Standard"; }
}

class SurgePricing implements PricingStrategy {
    private PricingStrategy basePricing;
    private double surgeMultiplier;

    public SurgePricing(PricingStrategy basePricing, double surgeMultiplier) {
        this.basePricing = basePricing;
        this.surgeMultiplier = surgeMultiplier;
    }

    @Override
    public double calculateFare(double distanceKm, String vehicleType) {
        return basePricing.calculateFare(distanceKm, vehicleType) * surgeMultiplier;
    }

    @Override
    public String getName() {
        return String.format("Surge (%.1fx)", surgeMultiplier);
    }

    public double getSurgeMultiplier() { return surgeMultiplier; }
}

// concurrent/Main.java — 20 riders competing for 5 drivers, only 5 succeed, others get re-queued

import java.util.*;
import java.util.concurrent.CountDownLatch;
import java.util.concurrent.atomic.AtomicInteger;

public class Main {
    public static void main(String[] args) throws InterruptedException {
        System.out.println("=== Concurrent Ride-Sharing Demo ===\n");

        ConcurrentMatchingService service = new ConcurrentMatchingService();

        // Register 5 drivers
        for (int i = 0; i < 5; i++) {
            service.registerDriver(new Driver("D-" + i, "Driver-" + i, 37.7 + i * 0.01, -122.4));
        }

        // 20 riders competing simultaneously
        int riderCount = 20;
        CountDownLatch startLatch = new CountDownLatch(1);
        CountDownLatch doneLatch = new CountDownLatch(riderCount);
        AtomicInteger matched = new AtomicInteger(0);
        AtomicInteger queued = new AtomicInteger(0);
        List<String> results = Collections.synchronizedList(new ArrayList<>());

        System.out.println("Scenario: 20 riders request rides simultaneously, but only 5 drivers available.");
        System.out.println("Expected: Exactly 5 get matched, 15 go to wait queue.\n");

        for (int i = 0; i < riderCount; i++) {
            final int id = i;
            new Thread(() -> {
                try {
                    startLatch.await();
                    Rider rider = new Rider("R-" + id, "Rider-" + id, 37.7, -122.4);
                    Trip trip = service.requestRide(rider);
                    if (trip != null) {
                        matched.incrementAndGet();
                        results.add("  [MATCHED] " + rider.getName() + " -> " + trip.getDriver().getName());
                    } else {
                        queued.incrementAndGet();
                    }
                } catch (InterruptedException e) {
                    Thread.currentThread().interrupt();
                } finally {
                    doneLatch.countDown();
                }
            }, "Rider-" + id).start();
        }

        startLatch.countDown();
        doneLatch.await();

        // Print matches
        results.sort(String::compareTo);
        for (String r : results) {
            System.out.println(r);
        }
        System.out.println("  [QUEUED] " + queued.get() + " riders waiting for a driver");

        // Verify driver states
        System.out.println("\nDriver states:");
        for (Driver d : service.getDrivers()) {
            System.out.println("  " + d);
        }

        // Verify: exactly 5 matched, 15 queued, no driver assigned to multiple riders
        Set<String> assignedDrivers = new HashSet<>();
        boolean noDuplicateAssignment = true;
        for (String r : results) {
            for (Driver d : service.getDrivers()) {
                if (r.contains(d.getName())) {
                    if (!assignedDrivers.add(d.getDriverId())) {
                        noDuplicateAssignment = false;
                    }
                }
            }
        }

        System.out.println("\n--- Summary ---");
        System.out.println("Riders: " + riderCount);
        System.out.println("Drivers: 5");
        System.out.println("Matched: " + matched.get());
        System.out.println("Queued: " + queued.get());
        System.out.println("Wait queue size: " + service.getWaitQueueSize());
        System.out.println("No duplicate driver assignment: " + (noDuplicateAssignment ? "PASSED" : "FAILED"));

        boolean correct = matched.get() == 5 && queued.get() == 15;
        System.out.println("\nCorrectness check: " + (correct ? "PASSED" : "FAILED"));
        if (!correct) {
            System.out.println("  Expected: 5 matched + 15 queued, got: " +
                    matched.get() + " matched + " + queued.get() + " queued");
        }
    }
}

// concurrent/model/Driver.java — Driver with atomic status for CAS-based assignment

import java.util.concurrent.atomic.AtomicReference;

enum DriverStatus { AVAILABLE, ASSIGNED, ON_TRIP, OFFLINE } // enum = fixed driver states for CAS transitions

class Driver {
    private final String driverId;   // final = immutable identity; safe to read from any thread
    private final String name;       // final = never changes; safe publication guaranteed
    private final AtomicReference<DriverStatus> status = new AtomicReference<>(DriverStatus.AVAILABLE); // AtomicReference = CAS-based state transitions; prevents double-assignment
    private volatile double latitude;  // volatile = location visible to all threads immediately
    private volatile double longitude; // volatile = location visible to all threads immediately

    public Driver(String driverId, String name, double latitude, double longitude) {
        this.driverId = driverId;
        this.name = name;
        this.latitude = latitude;
        this.longitude = longitude;
    }

    /**
     * CAS-based assignment — only ONE rider can claim this driver.
     * Atomically transitions from AVAILABLE to ASSIGNED.
     */
    public boolean tryAssign() {
        return status.compareAndSet(DriverStatus.AVAILABLE, DriverStatus.ASSIGNED);
    }

    public boolean startTrip() {
        return status.compareAndSet(DriverStatus.ASSIGNED, DriverStatus.ON_TRIP);
    }

    public boolean completeTrip() {
        return status.compareAndSet(DriverStatus.ON_TRIP, DriverStatus.AVAILABLE);
    }

    public void release() {
        status.set(DriverStatus.AVAILABLE);
    }

    public String getDriverId() { return driverId; }
    public String getName() { return name; }
    public DriverStatus getStatus() { return status.get(); }
    public double getLatitude() { return latitude; }
    public double getLongitude() { return longitude; }
    public void setLocation(double lat, double lng) { latitude = lat; longitude = lng; }

    public boolean isAvailable() { return status.get() == DriverStatus.AVAILABLE; }

    @Override
    public String toString() {
        return driverId + " (" + name + ") [" + status.get() + "]";
    }
}

// concurrent/model/Rider.java — A rider requesting a trip

class Rider {
    private final String riderId;    // final = immutable; safe to pass between threads
    private final String name;       // final = never changes after construction
    private final double latitude;   // final = pickup location fixed at creation
    private final double longitude;  // final = pickup location fixed at creation

    public Rider(String riderId, String name, double latitude, double longitude) {
        this.riderId = riderId;
        this.name = name;
        this.latitude = latitude;
        this.longitude = longitude;
    }

    public String getRiderId() { return riderId; }
    public String getName() { return name; }
    public double getLatitude() { return latitude; }
    public double getLongitude() { return longitude; }

    @Override
    public String toString() {
        return riderId + " (" + name + ")";
    }
}

// concurrent/model/Trip.java — A matched trip between rider and driver

import java.util.concurrent.atomic.AtomicInteger;

enum TripStatus { MATCHED, IN_PROGRESS, COMPLETED, CANCELLED } // enum = trip lifecycle states

class Trip {
    private static final AtomicInteger counter = new AtomicInteger(0); // AtomicInteger = thread-safe ID generator
    private final String tripId;     // final = set once; safe publication to other threads
    private final Rider rider;       // final = immutable reference; safe to read anywhere
    private final Driver driver;     // final = immutable reference; safe to read anywhere
    private volatile TripStatus status; // volatile = status changes visible to all threads immediately
    private final long matchedAt;    // final = timestamp frozen at creation

    public Trip(Rider rider, Driver driver) {
        this.tripId = "TRIP-" + counter.incrementAndGet();
        this.rider = rider;
        this.driver = driver;
        this.status = TripStatus.MATCHED;
        this.matchedAt = System.currentTimeMillis();
    }

    public String getTripId() { return tripId; }
    public Rider getRider() { return rider; }
    public Driver getDriver() { return driver; }
    public TripStatus getStatus() { return status; }
    public void setStatus(TripStatus status) { this.status = status; }

    @Override
    public String toString() {
        return tripId + " [" + rider.getName() + " -> " + driver.getName() + " | " + status + "]";
    }

    public static void resetCounter() { counter.set(0); }
}

// concurrent/service/ConcurrentMatchingService.java — AtomicReference per driver (CAS from AVAILABLE to ASSIGNED)

import java.util.*;
import java.util.concurrent.*;
import java.util.concurrent.atomic.AtomicInteger;

/**
 * Thread-safe ride matching service.
 *
 * Race condition solved: When 20 riders request rides and only 5 drivers
 * are available, each driver's AtomicReference status ensures only ONE
 * rider can claim each driver via CAS (compareAndSet).
 */
class ConcurrentMatchingService {
    private final CopyOnWriteArrayList<Driver> drivers = new CopyOnWriteArrayList<>(); // CopyOnWriteArrayList = safe iteration while adding drivers
    private final ConcurrentLinkedQueue<Rider> waitQueue = new ConcurrentLinkedQueue<>(); // ConcurrentLinkedQueue = lock-free FIFO for waiting riders
    private final ConcurrentHashMap<String, Trip> activeTrips = new ConcurrentHashMap<>(); // ConcurrentHashMap = thread-safe trip registry
    private final AtomicInteger matchedCount = new AtomicInteger(0);    // AtomicInteger = lock-free counter via CAS
    private final AtomicInteger requeuedCount = new AtomicInteger(0);   // AtomicInteger = lock-free counter via CAS
    private final AtomicInteger failedMatchCount = new AtomicInteger(0); // AtomicInteger = lock-free counter via CAS

    public void registerDriver(Driver driver) {
        drivers.add(driver);
    }

    /**
     * Request a ride for the given rider.
     * Scans available drivers and attempts CAS assignment.
     * If no driver available, rider goes to wait queue.
     */
    public Trip requestRide(Rider rider) {
        // Try to find and claim an available driver
        for (Driver driver : drivers) {
            if (driver.tryAssign()) {
                // CAS succeeded — this rider got the driver!
                Trip trip = new Trip(rider, driver);
                activeTrips.put(trip.getTripId(), trip);
                matchedCount.incrementAndGet();
                return trip;
            }
            // CAS failed — driver was taken by another rider, try next
        }

        // No driver available — add to wait queue
        waitQueue.offer(rider);
        requeuedCount.incrementAndGet();
        return null;
    }

    /**
     * Complete a trip and release the driver back to the pool.
     * Also attempts to match a waiting rider.
     */
    public void completeTrip(String tripId) {
        Trip trip = activeTrips.remove(tripId);
        if (trip == null) return;

        trip.setStatus(TripStatus.COMPLETED);
        Driver driver = trip.getDriver();
        driver.completeTrip();

        // Try to match a waiting rider
        Rider waitingRider = waitQueue.poll();
        if (waitingRider != null) {
            if (driver.tryAssign()) {
                Trip newTrip = new Trip(waitingRider, driver);
                activeTrips.put(newTrip.getTripId(), newTrip);
                matchedCount.incrementAndGet();
            } else {
                // Driver taken by another thread — re-queue rider
                waitQueue.offer(waitingRider);
            }
        }
    }

    public int getMatchedCount() { return matchedCount.get(); }
    public int getRequeuedCount() { return requeuedCount.get(); }
    public int getWaitQueueSize() { return waitQueue.size(); }
    public int getActiveTripsCount() { return activeTrips.size(); }
    public List<Driver> getDrivers() { return Collections.unmodifiableList(drivers); }
}

