// service/Feed.java — Feed generator collecting posts and applying ranking strategy

import java.util.*;

public class Feed {
    private User user;              // private = whose feed to generate
    private FeedStrategy strategy;  // private = strategy pattern for ranking posts

    public Feed(User user, FeedStrategy strategy) {
        this.user = user;
        this.strategy = strategy;
    }

    public void setStrategy(FeedStrategy strategy) {
        this.strategy = strategy;
    }

    public List<Post> generate(List<Post> allPosts, Set<String> following) {
        List<Post> relevantPosts = new ArrayList<>();
        for (Post post : allPosts) {
            if (following.contains(post.getAuthorId())) {
                relevantPosts.add(post);
            }
        }
        return strategy.rankPosts(relevantPosts);
    }

    public FeedIterator iterate(List<Post> posts, int pageSize) {
        return new FeedIterator(posts, pageSize);
    }

    public String getStrategyName() { return strategy.getName(); }
}

// service/FeedIterator.java — Paginated iteration over feed posts for infinite scroll

import java.util.*;

public class FeedIterator {
    private List<Post> posts;       // private = the ranked feed posts to paginate
    private int pageSize;           // private = how many posts per page
    private int currentIndex;       // private = tracks scroll position

    public FeedIterator(List<Post> posts, int pageSize) {
        this.posts = posts;
        this.pageSize = pageSize;
        this.currentIndex = 0;
    }

    public boolean hasNextPage() {
        return currentIndex < posts.size();
    }

    public List<Post> nextPage() {
        if (!hasNextPage()) return Collections.emptyList();

        int end = Math.min(currentIndex + pageSize, posts.size());
        List<Post> page = posts.subList(currentIndex, end);
        currentIndex = end;
        return page;
    }

    public int getCurrentPage() {
        return (currentIndex / pageSize);
    }

    public int getTotalPages() {
        return (int) Math.ceil((double) posts.size() / pageSize);
    }

    public void reset() {
        currentIndex = 0;
    }
}

// service/FollowManager.java — Follow/unfollow relationship management and social graph queries

import java.util.*;

public class FollowManager {
    private Map<String, Set<String>> following; // private = who each user follows (adjacency list)
    private Map<String, Set<String>> followers; // private = who follows each user (reverse index)

    public FollowManager() {
        this.following = new HashMap<>();
        this.followers = new HashMap<>();
    }

    public boolean follow(String followerId, String followeeId) {
        if (followerId.equals(followeeId)) return false;
        following.computeIfAbsent(followerId, k -> new HashSet<>());
        followers.computeIfAbsent(followeeId, k -> new HashSet<>());

        boolean added = following.get(followerId).add(followeeId);
        if (added) {
            followers.get(followeeId).add(followerId);
        }
        return added;
    }

    public boolean unfollow(String followerId, String followeeId) {
        Set<String> followingSet = following.get(followerId);
        if (followingSet == null) return false;

        boolean removed = followingSet.remove(followeeId);
        if (removed) {
            Set<String> followerSet = followers.get(followeeId);
            if (followerSet != null) followerSet.remove(followerId);
        }
        return removed;
    }

    public Set<String> getFollowing(String userId) {
        return following.getOrDefault(userId, Collections.emptySet());
    }

    public Set<String> getFollowers(String userId) {
        return followers.getOrDefault(userId, Collections.emptySet());
    }

    public int getFollowingCount(String userId) {
        return getFollowing(userId).size();
    }

    public int getFollowerCount(String userId) {
        return getFollowers(userId).size();
    }

    public boolean isFollowing(String followerId, String followeeId) {
        Set<String> set = following.get(followerId);
        return set != null && set.contains(followeeId);
    }
}

// service/SocialNetwork.java — Facade orchestrating posting, following, feeds, and notifications

import java.util.*;

public class SocialNetwork {
    private Map<String, User> users;                       // private = user registry by ID
    private FollowManager followManager;                   // private = manages follow relationships
    private List<Post> allPosts;                           // private = global post store
    private Map<String, List<Notification>> notifications; // private = per-user notification inbox

    public SocialNetwork() {
        this.users = new HashMap<>();
        this.followManager = new FollowManager();
        this.allPosts = new ArrayList<>();
        this.notifications = new HashMap<>();
    }

    public void registerUser(User user) {
        users.put(user.getUserId(), user);
        notifications.put(user.getUserId(), new ArrayList<>());
    }

    public Post createPost(User user, String content) {
        Post post = user.createPost(content);
        allPosts.add(post);

        // Notify followers
        Set<String> followers = followManager.getFollowers(user.getUserId());
        for (String followerId : followers) {
            Notification notif = new Notification(followerId, user.getUserId(), user.getName(),
                    Notification.Type.NEW_POST, user.getName() + " posted: \"" + content + "\"");
            notifications.get(followerId).add(notif);
        }
        return post;
    }

    public boolean follow(User follower, User followee) {
        boolean result = followManager.follow(follower.getUserId(), followee.getUserId());
        if (result) {
            Notification notif = new Notification(followee.getUserId(), follower.getUserId(),
                    follower.getName(), Notification.Type.FOLLOW,
                    follower.getName() + " started following you");
            notifications.get(followee.getUserId()).add(notif);
        }
        return result;
    }

    public boolean unfollow(User follower, User followee) {
        return followManager.unfollow(follower.getUserId(), followee.getUserId());
    }

    public boolean likePost(User user, Post post) {
        boolean liked = post.like(user.getUserId());
        if (liked && !user.getUserId().equals(post.getAuthorId())) {
            Notification notif = new Notification(post.getAuthorId(), user.getUserId(), user.getName(),
                    Notification.Type.LIKE, user.getName() + " liked your post");
            notifications.get(post.getAuthorId()).add(notif);
        }
        return liked;
    }

    public Comment commentOnPost(User user, Post post, String content) {
        Comment comment = new Comment(user.getUserId(), user.getName(), content);
        post.addComment(comment);
        if (!user.getUserId().equals(post.getAuthorId())) {
            Notification notif = new Notification(post.getAuthorId(), user.getUserId(), user.getName(),
                    Notification.Type.COMMENT, user.getName() + " commented on your post: \"" + content + "\"");
            notifications.get(post.getAuthorId()).add(notif);
        }
        return comment;
    }

    public List<Post> getFeed(User user, FeedStrategy strategy) {
        Feed feed = new Feed(user, strategy);
        Set<String> following = followManager.getFollowing(user.getUserId());
        return feed.generate(allPosts, following);
    }

    public FeedIterator getPaginatedFeed(User user, FeedStrategy strategy, int pageSize) {
        List<Post> feedPosts = getFeed(user, strategy);
        return new FeedIterator(feedPosts, pageSize);
    }

    public List<Notification> getNotifications(User user) {
        return notifications.getOrDefault(user.getUserId(), Collections.emptyList());
    }

    public List<Notification> getUnreadNotifications(User user) {
        List<Notification> unread = new ArrayList<>();
        for (Notification n : getNotifications(user)) {
            if (!n.isRead()) unread.add(n);
        }
        return unread;
    }

    public int getFollowerCount(User user) { return followManager.getFollowerCount(user.getUserId()); }
    public int getFollowingCount(User user) { return followManager.getFollowingCount(user.getUserId()); }
}

// strategy/FeedStrategy.java — Interchangeable feed ranking algorithms (chronological, engagement)
// DESIGN PATTERN: Strategy

import java.util.*;

public interface FeedStrategy { // interface = contract for feed ranking algorithms
    List<Post> rankPosts(List<Post> posts);
    String getName();
}

class ChronologicalFeed implements FeedStrategy { // implements = fulfills the interface contract
    @Override
    public List<Post> rankPosts(List<Post> posts) {
        List<Post> sorted = new ArrayList<>(posts);
        sorted.sort((a, b) -> b.getCreatedAt().compareTo(a.getCreatedAt()));
        return sorted;
    }

    @Override
    public String getName() { return "Chronological"; }
}

class RankedFeed implements FeedStrategy { // implements = fulfills the interface contract
    @Override
    public List<Post> rankPosts(List<Post> posts) {
        List<Post> sorted = new ArrayList<>(posts);
        // Rank by engagement (likes + 2*comments), break ties by recency
        sorted.sort((a, b) -> {
            int engDiff = b.getEngagement() - a.getEngagement();
            if (engDiff != 0) return engDiff;
            return b.getCreatedAt().compareTo(a.getCreatedAt());
        });
        return sorted;
    }

    @Override
    public String getName() { return "Engagement-Ranked"; }
}

