// service/FeedCache.java — Pre-computed feed with fan-out-on-write and pagination cursor

import java.util.*;

/**
 * Optimized feed: uses fan-out-on-write to pre-compute user feeds.
 * When a post is created, it's pushed to all followers' feed lists immediately.
 * Reading a feed is O(1) (just read from the pre-computed list).
 * Naive approach rebuilds the feed on every request by scanning all posts.
 */
public class FeedCache {
    private Map<String, LinkedList<Post>> userFeeds; // HashMap+LinkedList = O(1) lookup + O(1) addFirst/removeLast
    private int maxFeedSize;                         // caps memory usage; evicts oldest on overflow

    public FeedCache(int maxFeedSize) {
        this.userFeeds = new HashMap<>();
        this.maxFeedSize = maxFeedSize;
    }

    /**
     * Fan-out-on-write: push post to all followers' feeds.
     * O(f) where f = number of followers.
     */
    public void fanOutPost(Post post, Set<String> followers) {
        for (String followerId : followers) {
            LinkedList<Post> feed = userFeeds.computeIfAbsent(followerId, k -> new LinkedList<>());
            feed.addFirst(post); // newest first
            if (feed.size() > maxFeedSize) {
                feed.removeLast(); // evict oldest
            }
        }
    }

    /**
     * Get feed with cursor-based pagination.
     * Returns posts after the cursor position. O(pageSize).
     */
    public List<Post> getFeed(String userId, int cursor, int pageSize) {
        LinkedList<Post> feed = userFeeds.get(userId);
        if (feed == null || cursor >= feed.size()) return Collections.emptyList();

        int end = Math.min(cursor + pageSize, feed.size());
        return new ArrayList<>(feed.subList(cursor, end));
    }

    /**
     * Get full feed for ranking (used when strategy needs all posts).
     */
    public List<Post> getFullFeed(String userId) {
        LinkedList<Post> feed = userFeeds.get(userId);
        return feed != null ? new ArrayList<>(feed) : Collections.emptyList();
    }

    /**
     * Remove posts by a user from all feeds (on unfollow).
     */
    public void removeAuthorFromFeed(String feedOwnerId, String authorId) {
        LinkedList<Post> feed = userFeeds.get(feedOwnerId);
        if (feed != null) {
            feed.removeIf(p -> p.getAuthorId().equals(authorId));
        }
    }

    public int getFeedSize(String userId) {
        LinkedList<Post> feed = userFeeds.get(userId);
        return feed != null ? feed.size() : 0;
    }
}

// service/FollowManager.java — Follow/unfollow relationship management and social graph queries

import java.util.*;

public class FollowManager {
    private Map<String, Set<String>> following; // HashMap<userId, HashSet> = O(1) lookup + O(1) contains
    private Map<String, Set<String>> followers; // reverse index for fan-out-on-write

    public FollowManager() {
        this.following = new HashMap<>();
        this.followers = new HashMap<>();
    }

    public boolean follow(String followerId, String followeeId) {
        if (followerId.equals(followeeId)) return false;
        following.computeIfAbsent(followerId, k -> new HashSet<>());
        followers.computeIfAbsent(followeeId, k -> new HashSet<>());
        boolean added = following.get(followerId).add(followeeId);
        if (added) followers.get(followeeId).add(followerId);
        return added;
    }

    public boolean unfollow(String followerId, String followeeId) {
        Set<String> followingSet = following.get(followerId);
        if (followingSet == null) return false;
        boolean removed = followingSet.remove(followeeId);
        if (removed) {
            Set<String> followerSet = followers.get(followeeId);
            if (followerSet != null) followerSet.remove(followerId);
        }
        return removed;
    }

    public Set<String> getFollowing(String userId) {
        return following.getOrDefault(userId, Collections.emptySet());
    }

    public Set<String> getFollowers(String userId) {
        return followers.getOrDefault(userId, Collections.emptySet());
    }

    public int getFollowingCount(String userId) { return getFollowing(userId).size(); }
    public int getFollowerCount(String userId) { return getFollowers(userId).size(); }
}

// service/SocialNetwork.java — Optimized social network with fan-out-on-write feed pre-computation

import java.util.*;

public class SocialNetwork {
    private Map<String, User> users;                       // HashMap = O(1) user lookup by ID
    private FollowManager followManager;                   // manages bidirectional follow graph
    private List<Post> allPosts;                           // ArrayList = O(1) append; full post archive
    private Map<String, List<Notification>> notifications; // per-user notification inbox
    private FeedCache feedCache;                           // pre-computed feeds via fan-out-on-write

    public SocialNetwork() {
        this.users = new HashMap<>();
        this.followManager = new FollowManager();
        this.allPosts = new ArrayList<>();
        this.notifications = new HashMap<>();
        this.feedCache = new FeedCache(1000);
    }

    public void registerUser(User user) {
        users.put(user.getUserId(), user);
        notifications.put(user.getUserId(), new ArrayList<>());
    }

    /**
     * Fan-out-on-write: immediately pushes post to all followers' pre-computed feeds.
     */
    public Post createPost(User user, String content) {
        Post post = user.createPost(content);
        allPosts.add(post);

        Set<String> followers = followManager.getFollowers(user.getUserId());
        feedCache.fanOutPost(post, followers);

        for (String followerId : followers) {
            Notification notif = new Notification(followerId, user.getUserId(), user.getName(),
                    Notification.Type.NEW_POST, user.getName() + " posted: \"" + content + "\"");
            notifications.get(followerId).add(notif);
        }
        return post;
    }

    public boolean follow(User follower, User followee) {
        boolean result = followManager.follow(follower.getUserId(), followee.getUserId());
        if (result) {
            Notification notif = new Notification(followee.getUserId(), follower.getUserId(),
                    follower.getName(), Notification.Type.FOLLOW,
                    follower.getName() + " started following you");
            notifications.get(followee.getUserId()).add(notif);
        }
        return result;
    }

    public boolean unfollow(User follower, User followee) {
        boolean result = followManager.unfollow(follower.getUserId(), followee.getUserId());
        if (result) {
            feedCache.removeAuthorFromFeed(follower.getUserId(), followee.getUserId());
        }
        return result;
    }

    public boolean likePost(User user, Post post) {
        boolean liked = post.like(user.getUserId());
        if (liked && !user.getUserId().equals(post.getAuthorId())) {
            Notification notif = new Notification(post.getAuthorId(), user.getUserId(), user.getName(),
                    Notification.Type.LIKE, user.getName() + " liked your post");
            notifications.get(post.getAuthorId()).add(notif);
        }
        return liked;
    }

    public Comment commentOnPost(User user, Post post, String content) {
        Comment comment = new Comment(user.getUserId(), user.getName(), content);
        post.addComment(comment);
        if (!user.getUserId().equals(post.getAuthorId())) {
            Notification notif = new Notification(post.getAuthorId(), user.getUserId(), user.getName(),
                    Notification.Type.COMMENT, user.getName() + " commented on your post: \"" + content + "\"");
            notifications.get(post.getAuthorId()).add(notif);
        }
        return comment;
    }

    /**
     * O(1) feed retrieval from pre-computed cache + optional ranking.
     */
    public List<Post> getFeed(User user, FeedStrategy strategy) {
        List<Post> feedPosts = feedCache.getFullFeed(user.getUserId());
        return strategy.rankPosts(feedPosts);
    }

    /**
     * Cursor-based pagination: O(pageSize) retrieval.
     */
    public List<Post> getFeedPage(User user, int cursor, int pageSize) {
        return feedCache.getFeed(user.getUserId(), cursor, pageSize);
    }

    public List<Notification> getNotifications(User user) {
        return notifications.getOrDefault(user.getUserId(), Collections.emptyList());
    }

    public List<Notification> getUnreadNotifications(User user) {
        List<Notification> unread = new ArrayList<>();
        for (Notification n : getNotifications(user)) {
            if (!n.isRead()) unread.add(n);
        }
        return unread;
    }

    public int getFollowerCount(User user) { return followManager.getFollowerCount(user.getUserId()); }
    public int getFollowingCount(User user) { return followManager.getFollowingCount(user.getUserId()); }
}

// strategy/FeedStrategy.java — Interchangeable feed ranking algorithms (chronological, engagement)
// DESIGN PATTERN: Strategy

import java.util.*;

public interface FeedStrategy { // interface = swappable feed ranking algorithm
    List<Post> rankPosts(List<Post> posts);
    String getName();
}

class ChronologicalFeed implements FeedStrategy {
    @Override
    public List<Post> rankPosts(List<Post> posts) {
        List<Post> sorted = new ArrayList<>(posts);
        sorted.sort((a, b) -> b.getCreatedAt().compareTo(a.getCreatedAt()));
        return sorted;
    }

    @Override
    public String getName() { return "Chronological"; }
}

class RankedFeed implements FeedStrategy {
    @Override
    public List<Post> rankPosts(List<Post> posts) {
        List<Post> sorted = new ArrayList<>(posts);
        // Rank by engagement (likes + 2*comments), break ties by recency
        sorted.sort((a, b) -> {
            int engDiff = b.getEngagement() - a.getEngagement();
            if (engDiff != 0) return engDiff;
            return b.getCreatedAt().compareTo(a.getCreatedAt());
        });
        return sorted;
    }

    @Override
    public String getName() { return "Engagement-Ranked"; }
}

// concurrent/Main.java — 5 users posting while 10 readers generate feeds, no duplicates/missing

import java.util.*;
import java.util.concurrent.*;
import java.util.concurrent.atomic.AtomicInteger;

public class Main {
    public static void main(String[] args) throws InterruptedException {
        System.out.println("=== Concurrent Social Media Feed Demo ===\n");

        FeedService service = new FeedService();

        // Create 5 users, each follows all others
        int userCount = 5;
        for (int i = 0; i < userCount; i++) {
            service.registerUser(new User("U-" + i, "User-" + i));
        }
        for (int i = 0; i < userCount; i++) {
            for (int j = 0; j < userCount; j++) {
                if (i != j) {
                    service.follow("U-" + i, "U-" + j);
                }
            }
        }

        int postsPerUser = 20;
        int readerCount = 10;
        int totalExpectedPosts = userCount * postsPerUser;

        System.out.println("Scenario: " + userCount + " users each posting " + postsPerUser +
                " messages simultaneously,");
        System.out.println("          while " + readerCount + " readers generate feeds concurrently.");
        System.out.println("Expected: No duplicates, no ConcurrentModificationException,");
        System.out.println("          all " + totalExpectedPosts + " posts eventually visible.\n");

        CountDownLatch startLatch = new CountDownLatch(1);
        CountDownLatch writersDone = new CountDownLatch(userCount);
        CountDownLatch readersDone = new CountDownLatch(readerCount);
        AtomicInteger postsCreated = new AtomicInteger(0);
        AtomicInteger feedsGenerated = new AtomicInteger(0);
        AtomicInteger errors = new AtomicInteger(0);
        List<String> readerResults = Collections.synchronizedList(new ArrayList<>());

        // Writer threads — each user posts messages
        for (int i = 0; i < userCount; i++) {
            final int userId = i;
            new Thread(() -> {
                try {
                    startLatch.await();
                    for (int p = 0; p < postsPerUser; p++) {
                        Post post = service.createPost("U-" + userId,
                                "Post-" + p + " from User-" + userId);
                        if (post != null) {
                            postsCreated.incrementAndGet();
                        }
                    }
                } catch (InterruptedException e) {
                    Thread.currentThread().interrupt();
                } catch (Exception e) {
                    errors.incrementAndGet();
                } finally {
                    writersDone.countDown();
                }
            }, "Writer-" + i).start();
        }

        // Reader threads — generate feeds while posts are being created
        for (int i = 0; i < readerCount; i++) {
            final int readerId = i;
            new Thread(() -> {
                try {
                    startLatch.await();
                    String userId = "U-" + (readerId % userCount);

                    // Generate feed multiple times during writing
                    for (int r = 0; r < 5; r++) {
                        List<Post> feed = service.generateFeed(userId);
                        feedsGenerated.incrementAndGet();

                        // Check for duplicates in this feed
                        Set<Long> postIds = new HashSet<>();
                        for (Post post : feed) {
                            if (!postIds.add(post.getPostId())) {
                                errors.incrementAndGet();
                                readerResults.add("  [ERROR] Duplicate post in feed: " + post.getPostId());
                            }
                        }
                        Thread.sleep(1); // small delay to interleave with writers
                    }
                } catch (InterruptedException e) {
                    Thread.currentThread().interrupt();
                } catch (ConcurrentModificationException e) {
                    errors.incrementAndGet();
                    readerResults.add("  [ERROR] ConcurrentModificationException in reader-" + readerId);
                } catch (Exception e) {
                    errors.incrementAndGet();
                    readerResults.add("  [ERROR] " + e.getClass().getSimpleName() + " in reader-" + readerId);
                } finally {
                    readersDone.countDown();
                }
            }, "Reader-" + i).start();
        }

        startLatch.countDown();
        writersDone.await();
        readersDone.await();

        // Print any errors
        if (!readerResults.isEmpty()) {
            for (String r : readerResults) {
                System.out.println(r);
            }
        } else {
            System.out.println("  No errors detected during concurrent read/write operations.");
        }

        // Final verification — generate feed after all writes complete
        System.out.println("\nFinal feed verification (after all posts complete):");
        List<Post> finalFeed = service.generateFeed("U-0");
        // U-0 follows U-1..U-4, so should see (userCount-1) * postsPerUser posts
        int expectedInFeed = (userCount - 1) * postsPerUser;
        Set<Long> uniquePostIds = new HashSet<>();
        for (Post post : finalFeed) {
            uniquePostIds.add(post.getPostId());
        }
        boolean noDuplicates = uniquePostIds.size() == finalFeed.size();
        boolean allPostsVisible = finalFeed.size() == expectedInFeed;

        System.out.println("  Feed size for U-0: " + finalFeed.size() + " (expected " + expectedInFeed + ")");
        System.out.println("  Unique posts: " + uniquePostIds.size());

        // User post counts
        System.out.println("\nUser post counts:");
        for (int i = 0; i < userCount; i++) {
            User u = service.getUser("U-" + i);
            System.out.println("  " + u);
        }

        // Summary
        System.out.println("\n--- Summary ---");
        System.out.println("Total posts created: " + postsCreated.get() + " (expected " + totalExpectedPosts + ")");
        System.out.println("Feeds generated: " + feedsGenerated.get());
        System.out.println("Errors: " + errors.get());

        boolean correctPostCount = postsCreated.get() == totalExpectedPosts;

        System.out.println("\nAll posts created: " + (correctPostCount ? "PASSED" : "FAILED"));
        System.out.println("No duplicates in feed: " + (noDuplicates ? "PASSED" : "FAILED"));
        System.out.println("All posts visible in final feed: " + (allPostsVisible ? "PASSED" : "FAILED"));
        System.out.println("No concurrent errors: " + (errors.get() == 0 ? "PASSED" : "FAILED"));

        boolean allPassed = correctPostCount && noDuplicates && allPostsVisible && errors.get() == 0;
        System.out.println("\nOverall: " + (allPassed ? "ALL TESTS PASSED" : "SOME TESTS FAILED"));
    }
}

// concurrent/model/Post.java — Immutable post with unique ID

import java.util.concurrent.atomic.AtomicLong;

class Post {
    private static final AtomicLong ID_GEN = new AtomicLong(1); // AtomicLong = thread-safe unique ID generator

    private final long postId;       // final = immutable after construction; safe to share
    private final String authorId;   // final = never changes; safe to read from any thread
    private final String content;    // final = immutable; post content never changes
    private final long timestamp;    // final = creation time frozen; used for feed ordering

    public Post(String authorId, String content) {
        this.postId = ID_GEN.getAndIncrement();
        this.authorId = authorId;
        this.content = content;
        this.timestamp = System.nanoTime();
    }

    public long getPostId() { return postId; }
    public String getAuthorId() { return authorId; }
    public String getContent() { return content; }
    public long getTimestamp() { return timestamp; }

    @Override
    public boolean equals(Object o) {
        if (this == o) return true;
        if (!(o instanceof Post)) return false;
        return postId == ((Post) o).postId;
    }

    @Override
    public int hashCode() { return Long.hashCode(postId); }

    @Override
    public String toString() {
        return "Post#" + postId + " by " + authorId + ": " + content;
    }
}

// concurrent/model/User.java — User with thread-safe follower list and post feed

import java.util.List;
import java.util.concurrent.CopyOnWriteArrayList;
import java.util.concurrent.ConcurrentLinkedDeque;

class User {
    private final String userId;     // final = immutable identity; safe to read from any thread
    private final String name;       // final = never changes; safe publication guaranteed
    private final CopyOnWriteArrayList<String> followers = new CopyOnWriteArrayList<>(); // CopyOnWriteArrayList = snapshot iteration; safe during concurrent follow/unfollow
    private final CopyOnWriteArrayList<String> following = new CopyOnWriteArrayList<>(); // CopyOnWriteArrayList = addIfAbsent prevents duplicates atomically
    private final ConcurrentLinkedDeque<Post> posts = new ConcurrentLinkedDeque<>();     // ConcurrentLinkedDeque = lock-free; safe concurrent addFirst + iteration

    public User(String userId, String name) {
        this.userId = userId;
        this.name = name;
    }

    public void addFollower(String followerId) {
        followers.addIfAbsent(followerId);
    }

    public void addFollowing(String userId) {
        following.addIfAbsent(userId);
    }

    public void removeFollower(String followerId) {
        followers.remove(followerId);
    }

    public void removeFollowing(String userId) {
        following.remove(userId);
    }

    public void addPost(Post post) {
        posts.addFirst(post); // newest first
    }

    public String getUserId() { return userId; }
    public String getName() { return name; }
    public List<String> getFollowers() { return followers; }
    public List<String> getFollowing() { return following; }
    public ConcurrentLinkedDeque<Post> getPosts() { return posts; }
    public int getPostCount() { return posts.size(); }

    @Override
    public String toString() {
        return userId + " (" + name + ") [" + posts.size() + " posts, " + followers.size() + " followers]";
    }
}

// concurrent/service/FeedService.java — Thread-safe feed generation with CopyOnWriteArrayList + ConcurrentLinkedDeque

import java.util.*;
import java.util.concurrent.*;

/**
 * Thread-safe feed service.
 *
 * Race condition solved: User posts while another user's feed is being generated.
 * CopyOnWriteArrayList for followers ensures safe iteration during add/remove.
 * ConcurrentLinkedDeque for posts ensures safe concurrent append + read.
 * No duplicates or missing posts in generated feeds.
 */
class FeedService {
    private final ConcurrentHashMap<String, User> users = new ConcurrentHashMap<>(); // ConcurrentHashMap = thread-safe user registry; no global lock

    public void registerUser(User user) {
        users.put(user.getUserId(), user);
    }

    public void follow(String followerId, String targetId) {
        User follower = users.get(followerId);
        User target = users.get(targetId);
        if (follower != null && target != null) {
            target.addFollower(followerId);
            follower.addFollowing(targetId);
        }
    }

    public void unfollow(String followerId, String targetId) {
        User follower = users.get(followerId);
        User target = users.get(targetId);
        if (follower != null && target != null) {
            target.removeFollower(followerId);
            follower.removeFollowing(targetId);
        }
    }

    /**
     * Create a post for a user. Thread-safe via ConcurrentLinkedDeque.
     */
    public Post createPost(String userId, String content) {
        User user = users.get(userId);
        if (user == null) return null;
        Post post = new Post(userId, content);
        user.addPost(post);
        return post;
    }

    /**
     * Generate feed for a user — collects posts from all followed users.
     * Safe to call concurrently with createPost and follow/unfollow.
     * CopyOnWriteArrayList iteration is snapshot-based (no ConcurrentModificationException).
     * ConcurrentLinkedDeque iteration is weakly consistent (sees all completed posts).
     */
    public List<Post> generateFeed(String userId) {
        User user = users.get(userId);
        if (user == null) return Collections.emptyList();

        List<Post> feed = new ArrayList<>();

        // Safe iteration over following list (snapshot)
        for (String followedId : user.getFollowing()) {
            User followed = users.get(followedId);
            if (followed != null) {
                // Safe iteration over posts (weakly consistent)
                for (Post post : followed.getPosts()) {
                    feed.add(post);
                }
            }
        }

        // Sort by timestamp (newest first)
        feed.sort((a, b) -> Long.compare(b.getTimestamp(), a.getTimestamp()));
        return feed;
    }

    public User getUser(String userId) { return users.get(userId); }
    public int getUserCount() { return users.size(); }
}

