// service/NotificationService.java — Orchestrates delivery with priority handling and throttling

import java.util.*;

public class NotificationService {
    private Map<String, Channel> channels;       // private = internal state hidden from outside classes
    private Throttler throttler;                  // private = encapsulates rate-limiting logic
    private List<Notification> history;           // private = only this class manages history

    public NotificationService(int throttleLimit) {
        this.channels = new HashMap<>();
        this.throttler = new Throttler(throttleLimit);
        this.history = new ArrayList<>();
    }

    public void registerChannel(Channel channel) {
        channels.put(channel.getType(), channel);
    }

    public boolean send(Notification notification) {
        history.add(notification);

        // Check throttle
        if (!throttler.allowSend(notification.getUserId(), notification.getChannelType())) {
            notification.setStatus(Notification.Status.THROTTLED);
            System.out.printf("  [THROTTLED] %s rate limit exceeded for user %s on %s%n",
                    notification.getChannelType(), notification.getUserId(), notification.getChannelType());
            return false;
        }

        // Find channel
        Channel channel = channels.get(notification.getChannelType());
        if (channel == null) {
            notification.setStatus(Notification.Status.FAILED);
            System.out.println("  [ERROR] No channel registered for: " + notification.getChannelType());
            return false;
        }

        // Send
        boolean success = channel.send(notification);
        notification.setStatus(success ? Notification.Status.SENT : Notification.Status.FAILED);
        return success;
    }

    public void sendBatch(List<Notification> notifications) {
        // Sort by priority (critical first)
        notifications.sort((a, b) -> b.getPriority().getLevel() - a.getPriority().getLevel());
        for (Notification n : notifications) {
            send(n);
        }
    }

    public Throttler getThrottler() { return throttler; }

    public List<Notification> getHistory() { return Collections.unmodifiableList(history); }

    public List<Notification> getHistoryByStatus(Notification.Status status) {
        List<Notification> result = new ArrayList<>();
        for (Notification n : history) {
            if (n.getStatus() == status) result.add(n);
        }
        return result;
    }

    public long getSentCount() { return getHistoryByStatus(Notification.Status.SENT).size(); }
    public long getFailedCount() { return getHistoryByStatus(Notification.Status.FAILED).size(); }
    public long getThrottledCount() { return getHistoryByStatus(Notification.Status.THROTTLED).size(); }
}

// service/RetryDecorator.java — Decorator adding retry logic on delivery failure

public class RetryDecorator implements Channel { // implements = fulfills the Channel interface contract
    private Channel wrappedChannel;              // private = hides the decorated channel from outside
    private int maxRetries;
    private int failureCount; // for testing: simulates N failures before success

    public RetryDecorator(Channel channel, int maxRetries) {
        this.wrappedChannel = channel;
        this.maxRetries = maxRetries;
        this.failureCount = 0;
    }

    // For testing: simulate N failures before success
    public void setSimulatedFailures(int count) {
        this.failureCount = count;
    }

    @Override                                     // @Override = ensures this method matches Channel interface
    public boolean send(Notification notification) {
        int attempts = 0;
        while (attempts <= maxRetries) {
            notification.incrementAttempts();
            attempts++;

            boolean success;
            if (failureCount > 0) {
                failureCount--;
                success = false;
                System.out.printf("  [RETRY] Attempt %d/%d for %s failed. %s%n",
                        attempts, maxRetries + 1, notification.getNotificationId(),
                        attempts <= maxRetries ? "Retrying..." : "Giving up.");
            } else {
                success = wrappedChannel.send(notification);
            }

            if (success) {
                if (attempts > 1) {
                    System.out.printf("  [RETRY] Succeeded on attempt %d for %s%n",
                            attempts, notification.getNotificationId());
                }
                return true;
            }

            if (attempts <= maxRetries) {
                System.out.printf("  [RETRY] Attempt %d/%d failed for %s. Retrying...%n",
                        attempts, maxRetries + 1, notification.getNotificationId());
            }
        }
        return false;
    }

    @Override
    public String getType() { return wrappedChannel.getType(); }
}

// service/Throttler.java — Rate-limits notification delivery per user/channel

import java.util.*;
import java.time.LocalDateTime;

public class Throttler {
    private int maxPerMinute;                    // private = only this class controls the limit
    private Map<String, List<LocalDateTime>> sendTimes; // key: userId+channel

    public Throttler(int maxPerMinute) {
        this.maxPerMinute = maxPerMinute;
        this.sendTimes = new HashMap<>();
    }

    public boolean allowSend(String userId, String channelType) {
        String key = userId + ":" + channelType;
        LocalDateTime now = LocalDateTime.now();
        LocalDateTime windowStart = now.minusMinutes(1);

        List<LocalDateTime> times = sendTimes.computeIfAbsent(key, k -> new ArrayList<>());

        // Remove expired entries
        times.removeIf(t -> t.isBefore(windowStart));

        if (times.size() >= maxPerMinute) {
            return false;
        }

        times.add(now);
        return true;
    }

    public void reset(String userId, String channelType) {
        String key = userId + ":" + channelType;
        sendTimes.remove(key);
    }

    public void resetAll() {
        sendTimes.clear();
    }

    public int getMaxPerMinute() { return maxPerMinute; }
    public void setMaxPerMinute(int max) { this.maxPerMinute = max; }
}

