// concurrent/Main.java — 100 events for same user with limit=5/second, exactly 5 delivered

import java.util.*;
import java.util.concurrent.CountDownLatch;
import java.util.concurrent.atomic.AtomicInteger;

public class Main {
    public static void main(String[] args) throws InterruptedException {
        System.out.println("=== Concurrent Notification System Demo ===\n");

        int rateLimit = 5;
        Throttler throttler = new Throttler(rateLimit);
        NotificationService service = new NotificationService(throttler);

        int eventCount = 100;
        String targetUser = "user-alice";

        System.out.println("Scenario: " + eventCount + " events all targeting " + targetUser + " simultaneously.");
        System.out.println("Rate limit: " + rateLimit + " notifications per window.");
        System.out.println("Expected: Exactly " + rateLimit + " delivered, " +
                (eventCount - rateLimit) + " throttled.\n");

        CountDownLatch startLatch = new CountDownLatch(1);
        CountDownLatch doneLatch = new CountDownLatch(eventCount);
        AtomicInteger deliveredCount = new AtomicInteger(0);
        AtomicInteger throttledCount = new AtomicInteger(0);

        for (int i = 0; i < eventCount; i++) {
            final int id = i;
            new Thread(() -> {
                try {
                    startLatch.await();
                    Notification notif = new Notification(targetUser, "Event-" + id);
                    boolean sent = service.send(notif);
                    if (sent) {
                        deliveredCount.incrementAndGet();
                    } else {
                        throttledCount.incrementAndGet();
                    }
                } catch (InterruptedException e) {
                    Thread.currentThread().interrupt();
                } finally {
                    doneLatch.countDown();
                }
            }, "Event-" + id).start();
        }

        // Release all threads simultaneously
        startLatch.countDown();
        doneLatch.await();

        // Print delivered notifications
        System.out.println("Delivered notifications:");
        for (Notification n : service.getDelivered()) {
            System.out.println("  [DELIVERED] " + n.getMessage() + " -> " + n.getUserId());
        }

        System.out.println("\nThrottled: " + throttledCount.get() + " notifications suppressed.");

        // Verification
        System.out.println("\n--- Summary ---");
        System.out.println("Total events: " + eventCount);
        System.out.println("Rate limit: " + rateLimit + " per window");
        System.out.println("Delivered: " + deliveredCount.get());
        System.out.println("Throttled: " + throttledCount.get());
        System.out.println("Throttler counter: " + throttler.getCount(targetUser));

        boolean correctDelivered = deliveredCount.get() == rateLimit;
        boolean correctThrottled = throttledCount.get() == (eventCount - rateLimit);
        boolean noOverdelivery = deliveredCount.get() <= rateLimit;
        boolean totalCorrect = deliveredCount.get() + throttledCount.get() == eventCount;

        System.out.println("\nExactly " + rateLimit + " delivered: " + (correctDelivered ? "PASSED" : "FAILED"));
        System.out.println("Exactly " + (eventCount - rateLimit) + " throttled: " + (correctThrottled ? "PASSED" : "FAILED"));
        System.out.println("No over-delivery: " + (noOverdelivery ? "PASSED" : "FAILED"));
        System.out.println("Total accounted for: " + (totalCorrect ? "PASSED" : "FAILED"));

        boolean allPassed = correctDelivered && correctThrottled && noOverdelivery && totalCorrect;
        System.out.println("\nOverall: " + (allPassed ? "ALL TESTS PASSED" : "SOME TESTS FAILED"));
    }
}

// concurrent/model/Notification.java — Notification with delivery tracking

import java.util.concurrent.atomic.AtomicLong;

class Notification {
    private static final AtomicLong ID_GEN = new AtomicLong(1); // AtomicLong = thread-safe ID generator; no locks needed

    private final long notificationId;           // final = set once, never changes; safe for threads to read
    private final String userId;                 // final = immutable after construction; safe publication
    private final String message;                // final = guaranteed visible to all threads after constructor
    private final long timestamp;                // final = set once in constructor; thread-safe
    private volatile boolean delivered;          // volatile = writes visible to all threads immediately

    public Notification(String userId, String message) {
        this.notificationId = ID_GEN.getAndIncrement();
        this.userId = userId;
        this.message = message;
        this.timestamp = System.nanoTime();
        this.delivered = false;
    }

    public void markDelivered() { this.delivered = true; }

    public long getNotificationId() { return notificationId; }
    public String getUserId() { return userId; }
    public String getMessage() { return message; }
    public long getTimestamp() { return timestamp; }
    public boolean isDelivered() { return delivered; }

    @Override
    public String toString() {
        return "Notification#" + notificationId + " [" + userId + "] " + message +
                (delivered ? " (DELIVERED)" : " (THROTTLED)");
    }
}

// concurrent/service/NotificationService.java — Thread-safe notification delivery with throttling

import java.util.concurrent.*;
import java.util.concurrent.atomic.AtomicInteger;

/**
 * Thread-safe notification service with per-user rate limiting.
 *
 * Race condition solved: Multiple events triggering notifications to same user.
 * Without atomic throttle, all threads could read count < limit before any increments,
 * bypassing the rate limit. AtomicInteger with CAS ensures exact limit enforcement.
 */
class NotificationService {
    private final Throttler throttler;           // final = reference never changes; safe publication to threads
    private final ConcurrentLinkedQueue<Notification> delivered = new ConcurrentLinkedQueue<>(); // ConcurrentLinkedQueue = lock-free thread-safe queue
    private final ConcurrentLinkedQueue<Notification> throttled = new ConcurrentLinkedQueue<>(); // lock-free queue; multiple threads can offer simultaneously
    private final AtomicInteger deliveredCount = new AtomicInteger(0); // AtomicInteger = thread-safe counter without locks
    private final AtomicInteger throttledCount = new AtomicInteger(0); // AtomicInteger = uses CAS for atomic increment

    public NotificationService(Throttler throttler) {
        this.throttler = throttler;
    }

    /**
     * Send a notification. Respects per-user rate limit.
     * Thread-safe: throttler uses CAS to count permits.
     */
    public boolean send(Notification notification) {
        if (throttler.tryAcquire(notification.getUserId())) {
            notification.markDelivered();
            delivered.offer(notification);
            deliveredCount.incrementAndGet();
            return true;
        } else {
            throttled.offer(notification);
            throttledCount.incrementAndGet();
            return false;
        }
    }

    public int getDeliveredCount() { return deliveredCount.get(); }
    public int getThrottledCount() { return throttledCount.get(); }
    public ConcurrentLinkedQueue<Notification> getDelivered() { return delivered; }
    public ConcurrentLinkedQueue<Notification> getThrottled() { return throttled; }
}

// concurrent/service/Throttler.java — Semaphore-based per-user rate limiting

import java.util.concurrent.*;
import java.util.concurrent.atomic.AtomicInteger;

/**
 * Per-user throttle using AtomicInteger for rate counting within a window.
 * Ensures no more than maxPerWindow notifications are delivered per user per window.
 */
class Throttler {
    private final int maxPerWindow;              // final = immutable config; safe for all threads to read
    private final ConcurrentHashMap<String, AtomicInteger> userCounters = new ConcurrentHashMap<>(); // ConcurrentHashMap = thread-safe map; per-bucket locking

    public Throttler(int maxPerWindow) {
        this.maxPerWindow = maxPerWindow;
    }

    /**
     * Try to acquire a permit for the given user.
     * Uses AtomicInteger with CAS loop to ensure thread-safe counting.
     * Returns true if under limit, false if throttled.
     */
    public boolean tryAcquire(String userId) {
        AtomicInteger counter = userCounters.computeIfAbsent(userId, k -> new AtomicInteger(0));

        while (true) {
            int current = counter.get();
            if (current >= maxPerWindow) {
                return false; // throttled
            }
            if (counter.compareAndSet(current, current + 1)) { // CAS = atomic compare-and-swap; only succeeds if value unchanged
                return true; // acquired
            }
            // CAS failed — another thread incremented, retry loop
        }
    }

    /**
     * Reset counters (called at start of new window).
     */
    public void resetWindow() {
        userCounters.clear();
    }

    public int getCount(String userId) {
        AtomicInteger counter = userCounters.get(userId);
        return counter == null ? 0 : counter.get();
    }

    public int getMaxPerWindow() { return maxPerWindow; }
}

