// concurrent/Main.java — 20 threads logging 100 messages each, verify no interleaving, all 2000 present

import java.util.*;
import java.util.concurrent.CountDownLatch;
import java.util.concurrent.atomic.AtomicInteger;

public class Main {
    public static void main(String[] args) throws InterruptedException {
        System.out.println("=== Concurrent Logging Framework Demo ===\n");

        int threadCount = 20;
        int messagesPerThread = 100;
        int totalExpected = threadCount * messagesPerThread;

        AsyncAppender appender = new AsyncAppender(totalExpected + 100);
        appender.start();
        Logger logger = new Logger("AppLogger", appender, LogLevel.DEBUG);

        System.out.println("Scenario: " + threadCount + " threads logging " + messagesPerThread + " messages each.");
        System.out.println("Expected: All " + totalExpected + " messages written, no interleaving, no loss.\n");

        CountDownLatch startLatch = new CountDownLatch(1);
        CountDownLatch doneLatch = new CountDownLatch(threadCount);
        AtomicInteger submitted = new AtomicInteger(0);

        for (int i = 0; i < threadCount; i++) {
            final int threadId = i;
            new Thread(() -> {
                try {
                    startLatch.await();
                    for (int m = 0; m < messagesPerThread; m++) {
                        LogLevel level = LogLevel.values()[m % 4];
                        logger.log(level, "Thread-" + threadId + " message-" + m);
                        submitted.incrementAndGet();
                    }
                } catch (InterruptedException e) {
                    Thread.currentThread().interrupt();
                } finally {
                    doneLatch.countDown();
                }
            }, "Worker-" + threadId).start();
        }

        // Release all threads simultaneously
        startLatch.countDown();
        doneLatch.await();

        // Shutdown appender and wait for drain
        appender.shutdown();

        // Verify output
        List<String> outputLines = new ArrayList<>(appender.getOutput());
        int writtenCount = appender.getWrittenCount();

        // Show sample output (first 10 and last 5)
        System.out.println("Sample output (first 10 entries):");
        for (int i = 0; i < Math.min(10, outputLines.size()); i++) {
            System.out.println("  " + outputLines.get(i));
        }
        if (outputLines.size() > 10) {
            System.out.println("  ... (" + (outputLines.size() - 15) + " more entries) ...");
            for (int i = Math.max(10, outputLines.size() - 5); i < outputLines.size(); i++) {
                System.out.println("  " + outputLines.get(i));
            }
        }

        // Check for interleaving (each line should be a complete formatted entry)
        boolean noInterleaving = true;
        for (String line : outputLines) {
            // Each line should match format: [XXXXX] [LEVEL] [thread] message
            if (!line.matches("\\[\\d{5}\\] \\[\\w+\\s*\\] \\[.+\\] .+")) {
                noInterleaving = false;
                System.out.println("  [INTERLEAVED] " + line);
                break;
            }
        }

        // Check all messages are present (no loss)
        Set<String> expectedMessages = new HashSet<>();
        for (int t = 0; t < threadCount; t++) {
            for (int m = 0; m < messagesPerThread; m++) {
                expectedMessages.add("Thread-" + t + " message-" + m);
            }
        }

        Set<String> actualMessages = new HashSet<>();
        for (String line : outputLines) {
            // Extract message part after the last ']'
            int lastBracket = line.lastIndexOf(']');
            if (lastBracket >= 0 && lastBracket + 2 < line.length()) {
                actualMessages.add(line.substring(lastBracket + 2));
            }
        }

        int missingCount = 0;
        for (String expected : expectedMessages) {
            if (!actualMessages.contains(expected)) {
                missingCount++;
            }
        }

        // Summary
        System.out.println("\n--- Summary ---");
        System.out.println("Threads: " + threadCount);
        System.out.println("Messages per thread: " + messagesPerThread);
        System.out.println("Total submitted: " + submitted.get());
        System.out.println("Total written: " + writtenCount);
        System.out.println("Missing messages: " + missingCount);

        boolean allWritten = writtenCount == totalExpected;
        boolean noneMissing = missingCount == 0;

        System.out.println("\nAll " + totalExpected + " messages written: " + (allWritten ? "PASSED" : "FAILED"));
        System.out.println("No interleaving: " + (noInterleaving ? "PASSED" : "FAILED"));
        System.out.println("No missing messages: " + (noneMissing ? "PASSED" : "FAILED"));

        boolean allPassed = allWritten && noInterleaving && noneMissing;
        System.out.println("\nOverall: " + (allPassed ? "ALL TESTS PASSED" : "SOME TESTS FAILED"));
    }
}

// concurrent/model/LogEntry.java — Immutable log entry with sequence number

import java.util.concurrent.atomic.AtomicLong;

enum LogLevel { DEBUG, INFO, WARN, ERROR }

class LogEntry {
    private static final AtomicLong SEQ_GEN = new AtomicLong(1); // AtomicLong = thread-safe sequence generator; no duplicates

    private final long sequenceNumber;           // final = immutable after construction; safe for threads
    private final LogLevel level;                // final = set once; guaranteed visible to all threads
    private final String threadName;             // final = captures originating thread; immutable
    private final String message;                // final = safe publication; no synchronization needed
    private final long timestamp;                // final = set once in constructor

    public LogEntry(LogLevel level, String message) {
        this.sequenceNumber = SEQ_GEN.getAndIncrement();
        this.level = level;
        this.threadName = Thread.currentThread().getName();
        this.message = message;
        this.timestamp = System.nanoTime();
    }

    public long getSequenceNumber() { return sequenceNumber; }
    public LogLevel getLevel() { return level; }
    public String getThreadName() { return threadName; }
    public String getMessage() { return message; }
    public long getTimestamp() { return timestamp; }

    public String format() {
        return String.format("[%05d] [%-5s] [%-15s] %s",
                sequenceNumber, level, threadName, message);
    }

    @Override
    public String toString() { return format(); }
}

// concurrent/service/AsyncAppender.java — Single writer thread draining BlockingQueue to eliminate file contention

import java.util.concurrent.*;
import java.util.concurrent.atomic.AtomicBoolean;
import java.util.concurrent.atomic.AtomicInteger;

/**
 * Async log appender using BlockingQueue and single writer thread.
 *
 * Race condition solved: Multiple threads writing to same output — interleaved/corrupted entries.
 * Solution: All threads put entries into BlockingQueue (thread-safe), single writer thread
 * drains queue and writes sequentially (eliminates output contention).
 */
class AsyncAppender {
    private final BlockingQueue<LogEntry> queue;  // BlockingQueue = thread-safe; writer blocks when empty
    private final ConcurrentLinkedQueue<String> output; // ConcurrentLinkedQueue = lock-free output collection
    private final AtomicBoolean running = new AtomicBoolean(true); // AtomicBoolean = thread-safe shutdown flag
    private final AtomicInteger writtenCount = new AtomicInteger(0); // AtomicInteger = thread-safe counter
    private final Thread writerThread;           // final = single writer thread; eliminates interleaving

    public AsyncAppender(int queueCapacity) {
        this.queue = new LinkedBlockingQueue<>(queueCapacity); // LinkedBlockingQueue = bounded; backpressure if producers too fast
        this.output = new ConcurrentLinkedQueue<>();

        // Single writer thread — eliminates interleaving
        this.writerThread = new Thread(() -> {
            while (running.get() || !queue.isEmpty()) {
                try {
                    LogEntry entry = queue.poll(50, TimeUnit.MILLISECONDS);
                    if (entry != null) {
                        output.offer(entry.format());
                        writtenCount.incrementAndGet();
                    }
                } catch (InterruptedException e) {
                    Thread.currentThread().interrupt();
                    break;
                }
            }
            // Drain remaining entries
            LogEntry entry;
            while ((entry = queue.poll()) != null) {
                output.offer(entry.format());
                writtenCount.incrementAndGet();
            }
        }, "LogWriter");
        this.writerThread.setDaemon(true);
    }

    public void start() {
        writerThread.start();
    }

    /**
     * Submit a log entry to the async queue. Non-blocking for callers.
     */
    public boolean append(LogEntry entry) {
        try {
            return queue.offer(entry, 100, TimeUnit.MILLISECONDS);
        } catch (InterruptedException e) {
            Thread.currentThread().interrupt();
            return false;
        }
    }

    public void shutdown() throws InterruptedException {
        running.set(false);
        writerThread.join(5000);
    }

    public int getWrittenCount() { return writtenCount.get(); }
    public ConcurrentLinkedQueue<String> getOutput() { return output; }
    public int getQueueSize() { return queue.size(); }
}

// concurrent/service/Logger.java — Thread-safe logger delegating to AsyncAppender

import java.util.concurrent.atomic.AtomicInteger;

/**
 * Thread-safe Logger that accepts log calls from any thread
 * and delegates to AsyncAppender for serialized output.
 */
class Logger {
    private final String name;                   // final = immutable; safe for threads to read
    private final AsyncAppender appender;        // final = reference never changes; safe publication
    private final LogLevel minLevel;             // final = immutable config; no synchronization needed
    private final AtomicInteger totalLogged = new AtomicInteger(0); // AtomicInteger = thread-safe log counter

    public Logger(String name, AsyncAppender appender, LogLevel minLevel) {
        this.name = name;
        this.appender = appender;
        this.minLevel = minLevel;
    }

    public void log(LogLevel level, String message) {
        if (level.ordinal() >= minLevel.ordinal()) {
            LogEntry entry = new LogEntry(level, message);
            if (appender.append(entry)) {
                totalLogged.incrementAndGet();
            }
        }
    }

    public void debug(String message) { log(LogLevel.DEBUG, message); }
    public void info(String message) { log(LogLevel.INFO, message); }
    public void warn(String message) { log(LogLevel.WARN, message); }
    public void error(String message) { log(LogLevel.ERROR, message); }

    public int getTotalLogged() { return totalLogged.get(); }
    public String getName() { return name; }
}

