// service/FIFOCache.java — First-In-First-Out eviction using insertion order queue

import java.util.*;

public class FIFOCache<V> implements Cache<V> {  // implements = fulfills the Cache interface contract
    private int capacity;                        // private = internal limit hidden from callers
    private Map<String, CacheEntry<V>> cache;
    private Queue<String> insertionOrder;        // Queue tracks insertion order for FIFO eviction
    private CacheStats stats;

    public FIFOCache(int capacity) {
        this.capacity = capacity;
        this.cache = new HashMap<>();
        this.insertionOrder = new LinkedList<>();
        this.stats = new CacheStats();
    }

    @Override
    public void put(String key, V value) {
        stats.recordPut();

        if (cache.containsKey(key)) {
            cache.get(key).setValue(value);
            return;
        }

        if (cache.size() >= capacity) {
            evict();
        }

        CacheEntry<V> entry = new CacheEntry<>(key, value);
        cache.put(key, entry);
        insertionOrder.offer(key);
    }

    @Override
    public V get(String key) {
        CacheEntry<V> entry = cache.get(key);
        if (entry == null) {
            stats.recordMiss();
            return null;
        }
        stats.recordHit();
        entry.access();
        return entry.getValue();
    }

    private void evict() {
        String evictKey = insertionOrder.poll();
        if (evictKey != null) {
            cache.remove(evictKey);
            stats.recordEviction();
        }
    }

    @Override
    public boolean containsKey(String key) { return cache.containsKey(key); }

    @Override
    public void remove(String key) {
        cache.remove(key);
        insertionOrder.remove(key);
    }

    @Override
    public int size() { return cache.size(); }

    @Override
    public int capacity() { return capacity; }

    @Override
    public void clear() {
        cache.clear();
        insertionOrder.clear();
    }

    @Override
    public CacheStats getStats() { return stats; }

    @Override
    public String getPolicyName() { return "FIFO"; }
}

// service/LFUCache.java — Least Frequently Used eviction with frequency buckets

import java.util.*;

public class LFUCache<V> implements Cache<V> {   // implements = fulfills the Cache interface contract
    private int capacity;
    private Map<String, CacheEntry<V>> cache;
    private Map<String, Integer> frequencies;    // private = tracks how often each key is accessed
    private Map<Integer, LinkedHashSet<String>> frequencyBuckets; // groups keys by frequency for O(1) eviction
    private int minFrequency;                    // private = tracks lowest frequency for eviction target
    private CacheStats stats;

    public LFUCache(int capacity) {
        this.capacity = capacity;
        this.cache = new HashMap<>();
        this.frequencies = new HashMap<>();
        this.frequencyBuckets = new HashMap<>();
        this.minFrequency = 0;
        this.stats = new CacheStats();
    }

    @Override
    public void put(String key, V value) {
        if (capacity <= 0) return;
        stats.recordPut();

        if (cache.containsKey(key)) {
            cache.get(key).setValue(value);
            get(key); // update frequency
            return;
        }

        if (cache.size() >= capacity) {
            evict();
        }

        CacheEntry<V> entry = new CacheEntry<>(key, value);
        cache.put(key, entry);
        frequencies.put(key, 1);
        frequencyBuckets.computeIfAbsent(1, k -> new LinkedHashSet<>()).add(key);
        minFrequency = 1;
    }

    @Override
    public V get(String key) {
        if (!cache.containsKey(key)) {
            stats.recordMiss();
            return null;
        }
        stats.recordHit();

        int freq = frequencies.get(key);
        frequencies.put(key, freq + 1);
        frequencyBuckets.get(freq).remove(key);

        if (frequencyBuckets.get(freq).isEmpty()) {
            frequencyBuckets.remove(freq);
            if (minFrequency == freq) minFrequency++;
        }

        frequencyBuckets.computeIfAbsent(freq + 1, k -> new LinkedHashSet<>()).add(key);
        cache.get(key).access();
        return cache.get(key).getValue();
    }

    private void evict() {
        LinkedHashSet<String> bucket = frequencyBuckets.get(minFrequency);
        if (bucket == null || bucket.isEmpty()) return;

        String evictKey = bucket.iterator().next();
        bucket.remove(evictKey);
        if (bucket.isEmpty()) {
            frequencyBuckets.remove(minFrequency);
        }
        cache.remove(evictKey);
        frequencies.remove(evictKey);
        stats.recordEviction();
    }

    @Override
    public boolean containsKey(String key) { return cache.containsKey(key); }

    @Override
    public void remove(String key) {
        if (!cache.containsKey(key)) return;
        int freq = frequencies.get(key);
        frequencyBuckets.get(freq).remove(key);
        if (frequencyBuckets.get(freq).isEmpty()) frequencyBuckets.remove(freq);
        cache.remove(key);
        frequencies.remove(key);
    }

    @Override
    public int size() { return cache.size(); }

    @Override
    public int capacity() { return capacity; }

    @Override
    public void clear() {
        cache.clear();
        frequencies.clear();
        frequencyBuckets.clear();
        minFrequency = 0;
    }

    @Override
    public CacheStats getStats() { return stats; }

    @Override
    public String getPolicyName() { return "LFU"; }
}

// service/LRUCache.java — Least Recently Used eviction using LinkedHashMap

import java.util.*;

public class LRUCache<V> implements Cache<V> {   // implements = fulfills the Cache interface contract
    private int capacity;
    private LinkedHashMap<String, CacheEntry<V>> map; // LinkedHashMap with accessOrder=true gives LRU ordering
    private CacheStats stats;
    private List<EvictionListener<V>> listeners;  // private = observer list for eviction events

    public LRUCache(int capacity) {
        this.capacity = capacity;
        this.stats = new CacheStats();
        this.listeners = new ArrayList<>();
        this.map = new LinkedHashMap<String, CacheEntry<V>>(capacity, 0.75f, true) {
            @Override
            protected boolean removeEldestEntry(Map.Entry<String, CacheEntry<V>> eldest) {
                if (size() > LRUCache.this.capacity) {
                    stats.recordEviction();
                    notifyEviction(eldest.getValue());
                    return true;
                }
                return false;
            }
        };
    }

    public void addEvictionListener(EvictionListener<V> listener) {
        listeners.add(listener);
    }

    private void notifyEviction(CacheEntry<V> entry) {
        for (EvictionListener<V> l : listeners) {
            l.onEviction(entry.getKey(), entry.getValue());
        }
    }

    @Override
    public void put(String key, V value) {
        stats.recordPut();
        CacheEntry<V> entry = new CacheEntry<>(key, value);
        map.put(key, entry);
    }

    @Override
    public V get(String key) {
        CacheEntry<V> entry = map.get(key);
        if (entry == null) {
            stats.recordMiss();
            return null;
        }
        entry.access();
        stats.recordHit();
        return entry.getValue();
    }

    @Override
    public boolean containsKey(String key) { return map.containsKey(key); }

    @Override
    public void remove(String key) { map.remove(key); }

    @Override
    public int size() { return map.size(); }

    @Override
    public int capacity() { return capacity; }

    @Override
    public void clear() { map.clear(); }

    @Override
    public CacheStats getStats() { return stats; }

    @Override
    public String getPolicyName() { return "LRU"; }

    public interface EvictionListener<V> {        // interface = callback contract for eviction observers
        void onEviction(String key, V value);
    }
}

