// service/Cache.java — Generic Cache<K,V> with pluggable eviction strategy

import java.util.*;

/**
 * Optimized: Generic Cache<K,V> that accepts any eviction strategy.
 * Decouples cache storage from eviction policy via strategy pattern.
 */
public class Cache<K, V> {
    private int capacity;
    private Map<K, V> store;                     // HashMap = O(1) get/put; fast key-value storage
    private EvictionStrategy<K> evictionStrategy; // strategy pattern = pluggable eviction algorithm
    private CacheStats stats;

    public Cache(int capacity, EvictionStrategy<K> evictionStrategy) {
        this.capacity = capacity;
        this.store = new HashMap<>();
        this.evictionStrategy = evictionStrategy;
        this.stats = new CacheStats();
    }

    public void put(K key, V value) {
        stats.recordPut();
        if (store.containsKey(key)) {
            store.put(key, value);
            evictionStrategy.onAccess(key);
            return;
        }
        if (store.size() >= capacity) {
            K evictKey = evictionStrategy.evict();
            if (evictKey != null) {
                store.remove(evictKey);
                stats.recordEviction();
            }
        }
        store.put(key, value);
        evictionStrategy.onInsert(key);
    }

    public V get(K key) {
        if (!store.containsKey(key)) {
            stats.recordMiss();
            return null;
        }
        stats.recordHit();
        evictionStrategy.onAccess(key);
        return store.get(key);
    }

    public boolean containsKey(K key) { return store.containsKey(key); }

    public void remove(K key) {
        store.remove(key);
        evictionStrategy.onRemove(key);
    }

    public int size() { return store.size(); }
    public int capacity() { return capacity; }
    public void clear() { store.clear(); evictionStrategy.clear(); }
    public CacheStats getStats() { return stats; }
    public String getPolicyName() { return evictionStrategy.getName(); }
}

// service/CachingProxy.java — Proxy pattern: cache-aside layer in front of a real DataSource

public class CachingProxy<K, V> implements DataSource<K, V> {
    private final DataSource<K, V> inner;        // real backend; proxy delegates on miss
    private final Cache<K, V> cache;             // existing generic Cache<K,V> used as storage

    public CachingProxy(DataSource<K, V> inner, Cache<K, V> cache) {
        this.inner = inner;
        this.cache = cache;
    }

    @Override
    public V load(K key) {
        if (cache.containsKey(key)) {
            System.out.println("[proxy] HIT " + key);
            return cache.get(key);
        }
        System.out.println("[proxy] MISS " + key);
        V value = inner.load(key);               // delegate to real source on miss
        cache.put(key, value);                   // populate cache for future hits (cache-aside)
        return value;
    }
}

// service/DataSource.java — Source of truth that the cache fronts (Proxy target)

public interface DataSource<K, V> {              // generic so any backend (DB/HTTP/file) can be wrapped
    V load(K key);                               // load = fetch authoritative value for key
}

// service/LFUEviction.java — O(log n) LFU eviction using HashMap + TreeMap of frequencies

import java.util.*;

/**
 * O(log n) LFU eviction: HashMap for O(1) frequency lookup + TreeMap for O(log n) min-frequency access.
 * TreeMap<frequency, LinkedHashSet<key>> maintains insertion order within same frequency.
 */
public class LFUEviction<K> implements EvictionStrategy<K> { // implements = fulfills eviction strategy
    private Map<K, Integer> frequencies;         // HashMap = O(1) frequency lookup per key
    private TreeMap<Integer, LinkedHashSet<K>> frequencyBuckets; // TreeMap = O(log n) access to lowest frequency via firstEntry()

    public LFUEviction() {
        this.frequencies = new HashMap<>();
        this.frequencyBuckets = new TreeMap<>();
    }

    @Override
    public void onAccess(K key) {
        Integer freq = frequencies.get(key);
        if (freq == null) return;

        // Remove from current frequency bucket
        LinkedHashSet<K> bucket = frequencyBuckets.get(freq);
        if (bucket != null) {
            bucket.remove(key);
            if (bucket.isEmpty()) frequencyBuckets.remove(freq);
        }

        // Add to next frequency bucket
        int newFreq = freq + 1;
        frequencies.put(key, newFreq);
        frequencyBuckets.computeIfAbsent(newFreq, k -> new LinkedHashSet<>()).add(key);
    }

    @Override
    public void onInsert(K key) {
        frequencies.put(key, 1);
        frequencyBuckets.computeIfAbsent(1, k -> new LinkedHashSet<>()).add(key);
    }

    @Override
    public K evict() {
        if (frequencyBuckets.isEmpty()) return null;

        // TreeMap.firstEntry() gives the lowest frequency in O(log n)
        Map.Entry<Integer, LinkedHashSet<K>> lowest = frequencyBuckets.firstEntry();
        LinkedHashSet<K> bucket = lowest.getValue();
        K evictKey = bucket.iterator().next(); // FIFO within same frequency
        bucket.remove(evictKey);
        if (bucket.isEmpty()) frequencyBuckets.remove(lowest.getKey());
        frequencies.remove(evictKey);
        return evictKey;
    }

    @Override
    public void onRemove(K key) {
        Integer freq = frequencies.remove(key);
        if (freq != null) {
            LinkedHashSet<K> bucket = frequencyBuckets.get(freq);
            if (bucket != null) {
                bucket.remove(key);
                if (bucket.isEmpty()) frequencyBuckets.remove(freq);
            }
        }
    }

    @Override
    public void clear() {
        frequencies.clear();
        frequencyBuckets.clear();
    }

    @Override
    public String getName() { return "LFU (O(log n) TreeMap)"; }
}

// service/LRUEviction.java — O(1) LRU eviction using HashMap + DoublyLinkedList

import java.util.*;

/**
 * O(1) LRU eviction: HashMap for O(1) node lookup + DoublyLinkedList for O(1) move-to-head/remove-tail.
 * This is the classic LRU implementation used in production systems.
 */
public class LRUEviction<K> implements EvictionStrategy<K> { // implements = fulfills eviction strategy contract
    private Map<K, Node<K>> nodeMap;             // HashMap = O(1) node lookup by key
    private Node<K> head; // Most recently used — DoublyLinkedList gives O(1) move-to-head
    private Node<K> tail; // Least recently used — O(1) removal from tail

    public LRUEviction() {
        this.nodeMap = new HashMap<>();
        this.head = new Node<>(null);
        this.tail = new Node<>(null);
        head.next = tail;
        tail.prev = head;
    }

    @Override
    public void onAccess(K key) {
        Node<K> node = nodeMap.get(key);
        if (node != null) {
            removeNode(node);
            addToHead(node);
        }
    }

    @Override
    public void onInsert(K key) {
        Node<K> node = new Node<>(key);
        nodeMap.put(key, node);
        addToHead(node);
    }

    @Override
    public K evict() {
        if (tail.prev == head) return null; // Empty
        Node<K> lru = tail.prev;
        removeNode(lru);
        nodeMap.remove(lru.key);
        return lru.key;
    }

    @Override
    public void onRemove(K key) {
        Node<K> node = nodeMap.remove(key);
        if (node != null) removeNode(node);
    }

    @Override
    public void clear() {
        nodeMap.clear();
        head.next = tail;
        tail.prev = head;
    }

    @Override
    public String getName() { return "LRU (O(1) HashMap+DLL)"; }

    private void addToHead(Node<K> node) {
        node.next = head.next;
        node.prev = head;
        head.next.prev = node;
        head.next = node;
    }

    private void removeNode(Node<K> node) {
        node.prev.next = node.next;
        node.next.prev = node.prev;
    }

    private static class Node<K> {               // static inner class = DoublyLinkedList node; no outer ref needed
        K key;
        Node<K> prev, next;                      // prev/next = doubly linked for O(1) insert/remove
        Node(K key) { this.key = key; }
    }
}

