// concurrent/Main.java — 100 threads hitting expired key, shows only 1 actual computation happens

import java.util.concurrent.CountDownLatch;
import java.util.concurrent.atomic.AtomicInteger;

public class Main {
    public static void main(String[] args) throws InterruptedException {
        System.out.println("=== Concurrent Cache System Demo ===\n");

        demonstrateStampede();
        System.out.println();
        demonstrateStampedeProtection();
    }

    static void demonstrateStampede() throws InterruptedException {
        System.out.println("--- Without Stampede Protection ---");
        System.out.println("100 threads request the same expired key simultaneously.\n");

        // Cache with 100ms TTL
        ConcurrentLRUCache<String> cache = new ConcurrentLRUCache<>(100, 100);
        cache.put("popular-key", "initial-value");

        // Wait for entry to expire
        Thread.sleep(150);

        int threadCount = 100;
        CountDownLatch startLatch = new CountDownLatch(1);
        CountDownLatch doneLatch = new CountDownLatch(threadCount);
        AtomicInteger computeCount = new AtomicInteger(0);

        for (int i = 0; i < threadCount; i++) {
            new Thread(() -> {
                try {
                    startLatch.await();
                    String value = cache.get("popular-key");
                    if (value == null) {
                        // Simulate expensive backend call
                        computeCount.incrementAndGet();
                        cache.put("popular-key", "recomputed-value");
                    }
                } catch (InterruptedException e) {
                    Thread.currentThread().interrupt();
                } finally {
                    doneLatch.countDown();
                }
            }).start();
        }

        startLatch.countDown();
        doneLatch.await();

        System.out.println("Backend computations triggered: " + computeCount.get());
        System.out.println("PROBLEM: " + computeCount.get() + " redundant calls to backend!");
        System.out.println("(Should be 1, but without protection many threads hit the backend)");
    }

    static void demonstrateStampedeProtection() throws InterruptedException {
        System.out.println("--- With Stampede Protection (Singleflight Pattern) ---");
        System.out.println("100 threads request the same expired key simultaneously.\n");

        // Cache with 100ms TTL
        ConcurrentLRUCache<String> cache = new ConcurrentLRUCache<>(100, 100);
        StampedeProtection<String> protected_ = new StampedeProtection<>(cache);

        // Pre-populate and let it expire
        cache.put("popular-key", "initial-value");
        Thread.sleep(150);

        int threadCount = 100;
        CountDownLatch startLatch = new CountDownLatch(1);
        CountDownLatch doneLatch = new CountDownLatch(threadCount);
        AtomicInteger backendCalls = new AtomicInteger(0);

        for (int i = 0; i < threadCount; i++) {
            new Thread(() -> {
                try {
                    startLatch.await();
                    String value = protected_.getOrCompute("popular-key", key -> {
                        backendCalls.incrementAndGet();
                        // Simulate expensive computation
                        try { Thread.sleep(10); } catch (InterruptedException e) {}
                        return "recomputed-value-from-backend";
                    });
                } catch (InterruptedException e) {
                    Thread.currentThread().interrupt();
                } finally {
                    doneLatch.countDown();
                }
            }).start();
        }

        startLatch.countDown();
        doneLatch.await();

        System.out.println("Backend computations triggered: " + backendCalls.get());
        System.out.println("Threads that waited for result: " + protected_.getWaitCount());
        System.out.println("FIX: Only " + backendCalls.get() + " backend call(s) — others shared the result.");

        System.out.println("\n--- Summary ---");
        System.out.println("Total threads: " + threadCount);
        System.out.println("Actual computations: " + protected_.getComputeCount());
        System.out.println("Cache hits (after first compute): " + protected_.getWaitCount());
        System.out.println("Correctness: " + (backendCalls.get() <= 2 ? "PASSED" : "NEEDS REVIEW"));
        System.out.println("(Ideal is 1, acceptable is 1-2 due to lock granularity)");
    }
}

// concurrent/model/CacheEntry.java — Cache entry with expiration tracking

class CacheEntry<V> {
    private final String key;                    // final = set once, never changes; safe for threads to read
    private volatile V value;                    // volatile = value writes visible to all threads immediately
    private volatile long createdAt;             // volatile = timestamp visible across threads after update
    private volatile long lastAccessedAt;        // volatile = access time visible to all threads
    private final long ttlMillis;                // final = immutable TTL; safe for concurrent reads

    public CacheEntry(String key, V value, long ttlMillis) {
        this.key = key;
        this.value = value;
        this.ttlMillis = ttlMillis;
        this.createdAt = System.currentTimeMillis();
        this.lastAccessedAt = this.createdAt;
    }

    public String getKey() { return key; }
    public V getValue() { return value; }
    public long getLastAccessedAt() { return lastAccessedAt; }

    public void setValue(V value) {
        this.value = value;
        this.createdAt = System.currentTimeMillis();
        this.lastAccessedAt = this.createdAt;
    }

    public void touch() {
        this.lastAccessedAt = System.currentTimeMillis();
    }

    public boolean isExpired() {
        return (System.currentTimeMillis() - createdAt) > ttlMillis;
    }

    @Override
    public String toString() {
        return key + "=" + value + (isExpired() ? " [EXPIRED]" : " [VALID]");
    }
}

// concurrent/service/ConcurrentLRUCache.java — ReentrantReadWriteLock based concurrent LRU cache

import java.util.*;
import java.util.concurrent.locks.ReentrantReadWriteLock;
import java.util.concurrent.atomic.AtomicLong;

class ConcurrentLRUCache<V> {
    private final int capacity;                  // final = immutable config; safe for all threads
    private final long ttlMillis;                // final = set once; no synchronization needed to read
    private final LinkedHashMap<String, CacheEntry<V>> cache; // LinkedHashMap = accessOrder LRU; guarded by rwLock
    private final ReentrantReadWriteLock rwLock = new ReentrantReadWriteLock(); // RWLock = many readers OR one writer; better than synchronized
    private final AtomicLong hits = new AtomicLong(0);  // AtomicLong = thread-safe counter without locks
    private final AtomicLong misses = new AtomicLong(0); // AtomicLong = concurrent miss tracking

    public ConcurrentLRUCache(int capacity, long ttlMillis) {
        this.capacity = capacity;
        this.ttlMillis = ttlMillis;
        this.cache = new LinkedHashMap<String, CacheEntry<V>>(capacity, 0.75f, true) {
            @Override
            protected boolean removeEldestEntry(Map.Entry<String, CacheEntry<V>> eldest) {
                return size() > ConcurrentLRUCache.this.capacity;
            }
        };
    }

    public V get(String key) {
        rwLock.readLock().lock();
        try {
            CacheEntry<V> entry = cache.get(key);
            if (entry == null) {
                misses.incrementAndGet();
                return null;
            }
            if (entry.isExpired()) {
                misses.incrementAndGet();
                return null; // Will be cleaned up on next write
            }
            entry.touch();
            hits.incrementAndGet();
            return entry.getValue();
        } finally {
            rwLock.readLock().unlock();
        }
    }

    public void put(String key, V value) {
        rwLock.writeLock().lock();
        try {
            CacheEntry<V> existing = cache.get(key);
            if (existing != null) {
                existing.setValue(value);
            } else {
                cache.put(key, new CacheEntry<>(key, value, ttlMillis));
            }
        } finally {
            rwLock.writeLock().unlock();
        }
    }

    public void remove(String key) {
        rwLock.writeLock().lock();
        try {
            cache.remove(key);
        } finally {
            rwLock.writeLock().unlock();
        }
    }

    public int size() {
        rwLock.readLock().lock();
        try {
            return cache.size();
        } finally {
            rwLock.readLock().unlock();
        }
    }

    public long getHits() { return hits.get(); }
    public long getMisses() { return misses.get(); }

    public void evictExpired() {
        rwLock.writeLock().lock();
        try {
            cache.entrySet().removeIf(e -> e.getValue().isExpired());
        } finally {
            rwLock.writeLock().unlock();
        }
    }
}

// concurrent/service/StampedeProtection.java — Singleflight pattern: only one thread recomputes expired key

import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.locks.ReentrantLock;
import java.util.concurrent.atomic.AtomicInteger;
import java.util.function.Function;

/**
 * Cache stampede protection using the "singleflight" pattern.
 *
 * PROBLEM: When a popular cache key expires, 100 threads all see the miss
 * and all try to recompute the value simultaneously — hammering the backend.
 *
 * SOLUTION: Only ONE thread computes the new value. All other threads wait
 * for that computation to complete, then share the result.
 */
class StampedeProtection<V> {
    private final ConcurrentLRUCache<V> cache;   // final = reference never changes; safe publication
    private final ConcurrentHashMap<String, ReentrantLock> computeLocks = new ConcurrentHashMap<>(); // ConcurrentHashMap = per-key lock registry; thread-safe
    private final AtomicInteger computeCount = new AtomicInteger(0); // AtomicInteger = tracks computations across threads
    private final AtomicInteger waitCount = new AtomicInteger(0); // AtomicInteger = tracks threads that shared a result

    public StampedeProtection(ConcurrentLRUCache<V> cache) {
        this.cache = cache;
    }

    /**
     * Get value from cache, computing if missing/expired.
     * Only ONE thread per key will invoke the computeFunction.
     * Others wait and get the computed result.
     */
    public V getOrCompute(String key, Function<String, V> computeFunction) {
        // Fast path: cache hit
        V value = cache.get(key);
        if (value != null) {
            return value;
        }

        // Slow path: cache miss — use per-key lock to prevent stampede
        ReentrantLock lock = computeLocks.computeIfAbsent(key, k -> new ReentrantLock());
        lock.lock();
        try {
            // Double-check after acquiring lock (another thread may have computed it)
            value = cache.get(key);
            if (value != null) {
                waitCount.incrementAndGet();
                return value;
            }

            // We're the chosen one — compute the value
            computeCount.incrementAndGet();
            value = computeFunction.apply(key);
            cache.put(key, value);
            return value;
        } finally {
            lock.unlock();
            // Clean up lock entry to prevent memory leak
            computeLocks.remove(key, lock);
        }
    }

    public int getComputeCount() { return computeCount.get(); }
    public int getWaitCount() { return waitCount.get(); }
}

