// service/MessageBroker.java — Central message router managing topics, subscriptions, and delivery

import java.util.*;

public class MessageBroker {
    private Map<String, Topic> topics;           // private = internal topic registry
    private Map<String, List<Subscriber>> subscriptions; // topicName -> subscribers
    private Map<String, MessageQueue> queues; // subscriberId -> queue
    private DeliveryGuarantee defaultGuarantee;   // private = delivery mode encapsulated in broker
    private int totalPublished;
    private int totalDelivered;

    public MessageBroker(DeliveryGuarantee guarantee) {
        this.topics = new HashMap<>();
        this.subscriptions = new HashMap<>();
        this.queues = new HashMap<>();
        this.defaultGuarantee = guarantee;
        this.totalPublished = 0;
        this.totalDelivered = 0;
    }

    public MessageBroker() {
        this(DeliveryGuarantee.AT_MOST_ONCE);
    }

    public Topic createTopic(String name) {
        Topic topic = new Topic(name);
        topics.put(name, topic);
        subscriptions.put(name, new ArrayList<>());
        System.out.println("Topic created: " + name);
        return topic;
    }

    public boolean subscribe(String topicName, Subscriber subscriber) {
        List<Subscriber> subs = subscriptions.get(topicName);
        if (subs == null) {
            System.out.println("Topic not found: " + topicName);
            return false;
        }
        subs.add(subscriber);
        queues.put(subscriber.getId(), new MessageQueue(subscriber.getId(), 1000));
        System.out.printf("  %s subscribed to '%s' (filter: %s)%n",
                subscriber.getName(), topicName, subscriber.getFilter().getDescription());
        return true;
    }

    public boolean unsubscribe(String topicName, Subscriber subscriber) {
        List<Subscriber> subs = subscriptions.get(topicName);
        if (subs == null) return false;
        boolean removed = subs.remove(subscriber);
        if (removed) {
            System.out.printf("  %s unsubscribed from '%s'%n", subscriber.getName(), topicName);
        }
        return removed;
    }

    public void publish(String topicName, Message message) {
        Topic topic = topics.get(topicName);
        if (topic == null) {
            System.out.println("Topic not found: " + topicName);
            return;
        }

        topic.addMessage(message);
        totalPublished++;

        List<Subscriber> subs = subscriptions.get(topicName);
        if (subs == null || subs.isEmpty()) return;

        for (Subscriber sub : subs) {
            // Apply filter
            if (!sub.getFilter().matches(message)) continue;

            // Deliver based on guarantee
            if (defaultGuarantee == DeliveryGuarantee.AT_LEAST_ONCE) {
                MessageQueue queue = queues.get(sub.getId());
                if (queue != null) {
                    queue.enqueue(message);
                }
            }

            sub.onMessage(message);
            totalDelivered++;
        }
    }

    public void acknowledgeMessage(Subscriber subscriber, String messageId) {
        MessageQueue queue = queues.get(subscriber.getId());
        if (queue != null) {
            queue.acknowledge(messageId);
            System.out.printf("  Message %s acknowledged by %s%n", messageId, subscriber.getName());
        }
    }

    public MessageQueue getQueue(Subscriber subscriber) {
        return queues.get(subscriber.getId());
    }

    public Topic getTopic(String name) { return topics.get(name); }
    public int getTotalPublished() { return totalPublished; }
    public int getTotalDelivered() { return totalDelivered; }
    public int getTopicCount() { return topics.size(); }
    public int getSubscriberCount(String topicName) {
        List<Subscriber> subs = subscriptions.get(topicName);
        return subs != null ? subs.size() : 0;
    }
}

// service/MessageQueue.java — Per-subscriber buffer with ordered delivery and ack tracking

import java.util.*;

public class MessageQueue {
    private String subscriberId;                 // private = internal subscriber identity
    private Queue<Message> queue;                // private = FIFO delivery order maintained internally
    private Set<String> acknowledgedIds;         // private = tracks which messages were acked
    private int maxSize;

    public MessageQueue(String subscriberId, int maxSize) {
        this.subscriberId = subscriberId;
        this.queue = new LinkedList<>();
        this.acknowledgedIds = new HashSet<>();
        this.maxSize = maxSize;
    }

    public boolean enqueue(Message message) {
        if (queue.size() >= maxSize) {
            return false; // Queue full, message dropped
        }
        queue.offer(message);
        return true;
    }

    public Message dequeue() {
        return queue.poll();
    }

    public Message peek() {
        return queue.peek();
    }

    public void acknowledge(String messageId) {
        acknowledgedIds.add(messageId);
    }

    public boolean isAcknowledged(String messageId) {
        return acknowledgedIds.contains(messageId);
    }

    public int size() { return queue.size(); }
    public boolean isEmpty() { return queue.isEmpty(); }
    public String getSubscriberId() { return subscriberId; }
    public int getAcknowledgedCount() { return acknowledgedIds.size(); }
}

// service/Subscriber.java — Observer pattern interface for message consumers
//
// WHO IMPLEMENTS THIS? → ConcreteSubscriber (in ConcreteSubscriber.java)
// WHO CALLS IT? → Topic.publish() delivers messages to subscribers
// WHY? → Decouples "message published" from "how subscriber processes it".
//         Different subscriber types can handle messages differently.

interface Subscriber {                // interface = contract for any message consumer
    String getId();
    String getName();
    void onMessage(Message message);
    Filter getFilter();
}

// strategy/Filter.java — Interchangeable message filtering rules for subscribers

public interface Filter {                         // interface = contract for message filtering rules
    boolean matches(Message message);
    String getDescription();
}

class PayloadContainsFilter implements Filter {  // implements = fulfills Filter contract for keyword matching
    private String keyword;                      // private = internal filter criteria

    public PayloadContainsFilter(String keyword) {
        this.keyword = keyword;
    }

    @Override
    public boolean matches(Message message) {
        return message.getPayload().contains(keyword);
    }

    @Override
    public String getDescription() {
        return "payload contains '" + keyword + "'";
    }
}

class HeaderFilter implements Filter {            // implements = fulfills Filter contract for header matching
    private String headerKey;
    private String headerValue;

    public HeaderFilter(String key, String value) {
        this.headerKey = key;
        this.headerValue = value;
    }

    @Override
    public boolean matches(Message message) {
        String val = message.getHeader(headerKey);
        return headerValue.equals(val);
    }

    @Override
    public String getDescription() {
        return "header[" + headerKey + "]=" + headerValue;
    }
}

class AllPassFilter implements Filter {           // implements = fulfills Filter; accepts all messages
    @Override
    public boolean matches(Message message) { return true; }

    @Override
    public String getDescription() { return "all"; }
}

