// model/DelayedTask.java — Task with scheduled execution time deferring until delay elapses

public class DelayedTask extends Task {          // extends = inherits Task; adds delay-based scheduling
    private String description;
    private long delayMs;
    private long scheduledTime;

    public DelayedTask(String name, TaskPriority priority, String description, long delayMs) {
        super(name, priority);
        this.description = description;
        this.delayMs = delayMs;
        this.scheduledTime = System.currentTimeMillis() + delayMs;
    }

    public boolean isReadyToExecute() {
        return System.currentTimeMillis() >= scheduledTime;
    }

    @Override
    public boolean isReady() {
        return super.isReady() && isReadyToExecute();
    }

    @Override
    public TaskResult execute() {
        long start = System.currentTimeMillis();
        System.out.printf("    Executing delayed task: %s (was delayed by %dms)%n", getName(), delayMs);
        long elapsed = System.currentTimeMillis() - start;
        return TaskResult.success(getTaskId(), description + " completed after delay", elapsed);
    }

    public long getDelayMs() { return delayMs; }
    public long getScheduledTime() { return scheduledTime; }
}

// model/RecurringTask.java — Task with recurring execution at fixed intervals

public class RecurringTask extends Task {        // extends = inherits Task; adds recurring execution logic
    private String description;
    private int maxRuns;
    private int currentRun;
    private long intervalMs;

    public RecurringTask(String name, TaskPriority priority, String description,
                         int maxRuns, long intervalMs) {
        super(name, priority);
        this.description = description;
        this.maxRuns = maxRuns;
        this.currentRun = 0;
        this.intervalMs = intervalMs;
    }

    @Override
    public TaskResult execute() {
        long start = System.currentTimeMillis();
        currentRun++;
        System.out.printf("    Executing recurring: %s (run %d/%d)%n", getName(), currentRun, maxRuns);
        long elapsed = System.currentTimeMillis() - start;
        return TaskResult.success(getTaskId(),
                String.format("Run %d/%d completed", currentRun, maxRuns), elapsed);
    }

    public boolean hasMoreRuns() { return currentRun < maxRuns; }
    public int getCurrentRun() { return currentRun; }
    public int getMaxRuns() { return maxRuns; }
    public long getIntervalMs() { return intervalMs; }

    public void resetForNextRun() {
        setState(State.PENDING);
    }
}

// model/Task.java — Schedulable unit of work with priority, dependencies, and state

import java.util.*;

public abstract class Task implements Comparable<Task> { // abstract = can't instantiate directly; must be subclassed
    public enum State { PENDING, READY, RUNNING, COMPLETED, FAILED, CANCELLED } // enum = fixed set of task states

    private String taskId;                       // private = only this class manages task identity
    private String name;
    private TaskPriority priority;
    private State state;
    private TaskResult result;
    private long createdAt;
    private Set<String> dependencies; // taskIds this task depends on
    private static int counter = 0;              // static = shared ID counter across all Task instances

    public Task(String name, TaskPriority priority) {
        this.taskId = "TASK-" + (++counter);
        this.name = name;
        this.priority = priority;
        this.state = State.PENDING;
        this.createdAt = System.currentTimeMillis();
        this.dependencies = new HashSet<>();
    }

    public abstract TaskResult execute();         // abstract = subclass MUST provide its own execution logic

    public void addDependency(String taskId) {
        dependencies.add(taskId);
    }

    public boolean hasDependencies() { return !dependencies.isEmpty(); }

    public void removeDependency(String taskId) {
        dependencies.remove(taskId);
    }

    public boolean isReady() {
        return dependencies.isEmpty() && state == State.PENDING;
    }

    public String getTaskId() { return taskId; }
    public String getName() { return name; }
    public TaskPriority getPriority() { return priority; }
    public State getState() { return state; }
    public void setState(State state) { this.state = state; }
    public TaskResult getResult() { return result; }
    public void setResult(TaskResult result) { this.result = result; }
    public long getCreatedAt() { return createdAt; }
    public Set<String> getDependencies() { return Collections.unmodifiableSet(dependencies); }

    @Override
    public int compareTo(Task other) {
        // Higher priority first
        int prioDiff = other.priority.getLevel() - this.priority.getLevel();
        if (prioDiff != 0) return prioDiff;
        // Older tasks first (FIFO for same priority)
        return Long.compare(this.createdAt, other.createdAt);
    }

    @Override
    public String toString() {
        return String.format("Task[%s] \"%s\" [%s] State=%s", taskId, name, priority, state);
    }
}

class SimpleTask extends Task {                  // extends = inherits from abstract Task; provides execute()
    private Runnable action;
    private String actionDescription;

    public SimpleTask(String name, TaskPriority priority, String description) {
        super(name, priority);
        this.actionDescription = description;
    }

    @Override
    public TaskResult execute() {
        long start = System.currentTimeMillis();
        try {
            // Simulate task execution
            System.out.printf("    Executing: %s (%s)%n", getName(), actionDescription);
            long elapsed = System.currentTimeMillis() - start;
            return TaskResult.success(getTaskId(), actionDescription + " completed", elapsed);
        } catch (Exception e) {
            long elapsed = System.currentTimeMillis() - start;
            return TaskResult.failure(getTaskId(), e.getMessage(), elapsed);
        }
    }
}

// model/TaskDependency.java — Dependency graph with cycle detection for execution ordering

import java.util.*;

public class TaskDependency {
    private Map<String, Set<String>> dependsOn;    // private = internal graph edges; taskId -> dependencies
    private Map<String, Set<String>> dependedBy;   // private = reverse edges for notification on completion

    public TaskDependency() {
        this.dependsOn = new HashMap<>();
        this.dependedBy = new HashMap<>();
    }

    public boolean addDependency(String taskId, String dependsOnTaskId) {
        // Check for circular dependency
        if (wouldCreateCycle(taskId, dependsOnTaskId)) {
            System.out.printf("  [REJECTED] Adding dependency %s -> %s would create a cycle%n",
                    taskId, dependsOnTaskId);
            return false;
        }

        dependsOn.computeIfAbsent(taskId, k -> new HashSet<>()).add(dependsOnTaskId);
        dependedBy.computeIfAbsent(dependsOnTaskId, k -> new HashSet<>()).add(taskId);
        return true;
    }

    private boolean wouldCreateCycle(String taskId, String dependsOnTaskId) {
        // If dependsOnTaskId transitively depends on taskId, we have a cycle
        Set<String> visited = new HashSet<>();
        Queue<String> queue = new LinkedList<>();
        queue.add(dependsOnTaskId);

        while (!queue.isEmpty()) {
            String current = queue.poll();
            if (current.equals(taskId)) return true;
            if (visited.contains(current)) continue;
            visited.add(current);

            Set<String> deps = dependsOn.get(current);
            if (deps != null) queue.addAll(deps);
        }
        return false;
    }

    public Set<String> getDependencies(String taskId) {
        return dependsOn.getOrDefault(taskId, Collections.emptySet());
    }

    public Set<String> getDependents(String taskId) {
        return dependedBy.getOrDefault(taskId, Collections.emptySet());
    }

    public void markCompleted(String taskId) {
        // Remove this task from all tasks that depend on it
        Set<String> dependents = dependedBy.get(taskId);
        if (dependents != null) {
            for (String dependent : dependents) {
                Set<String> deps = dependsOn.get(dependent);
                if (deps != null) deps.remove(taskId);
            }
        }
    }

    public boolean isReady(String taskId) {
        Set<String> deps = dependsOn.get(taskId);
        return deps == null || deps.isEmpty();
    }
}

// model/TaskPriority.java — Task priority levels for scheduling order decisions

public enum TaskPriority {                       // enum = fixed set of priority constants; type-safe
    LOW(1),
    MEDIUM(2),
    HIGH(3),
