// model/DAG.java — Directed Acyclic Graph with topological sort for dependency resolution

import java.util.*;

/**
 * DAG-based dependency resolution with topological sort.
 * Detects cycles using DFS and provides execution order via Kahn's algorithm.
 */
public class DAG {
    private Map<String, Set<String>> adjacency; // HashMap = O(1) lookup of dependencies per task
    private Map<String, Set<String>> reverse;   // HashMap = O(1) lookup of dependents (reverse edges)
    private Map<String, Integer> inDegree;       // HashMap = O(1) check if node has zero incoming edges

    public DAG() {
        this.adjacency = new HashMap<>();
        this.reverse = new HashMap<>();
        this.inDegree = new HashMap<>();
    }

    public void addNode(String taskId) {
        adjacency.putIfAbsent(taskId, new HashSet<>());
        reverse.putIfAbsent(taskId, new HashSet<>());
        inDegree.putIfAbsent(taskId, 0);
    }

    /**
     * Add edge: taskId depends on dependsOnId.
     * Returns false if this would create a cycle.
     */
    public boolean addDependency(String taskId, String dependsOnId) {
        addNode(taskId);
        addNode(dependsOnId);

        if (wouldCreateCycle(taskId, dependsOnId)) {
            System.out.printf("  [REJECTED] %s -> %s would create a cycle%n", taskId, dependsOnId);
            return false;
        }

        adjacency.get(taskId).add(dependsOnId);
        reverse.get(dependsOnId).add(taskId);
        inDegree.merge(taskId, 1, Integer::sum);
        return true;
    }

    private boolean wouldCreateCycle(String taskId, String dependsOnId) {
        // BFS from dependsOnId checking if we can reach taskId
        Set<String> visited = new HashSet<>();
        Queue<String> queue = new LinkedList<>();
        queue.add(dependsOnId);
        while (!queue.isEmpty()) {
            String current = queue.poll();
            if (current.equals(taskId)) return true;
            if (visited.contains(current)) continue;
            visited.add(current);
            Set<String> deps = adjacency.get(current);
            if (deps != null) queue.addAll(deps);
        }
        return false;
    }

    /**
     * Topological sort using Kahn's algorithm.
     * Returns execution order respecting all dependencies.
     */
    public List<String> topologicalSort() {
        Map<String, Integer> degrees = new HashMap<>(inDegree);
        Queue<String> queue = new LinkedList<>();

        for (Map.Entry<String, Integer> entry : degrees.entrySet()) {
            if (entry.getValue() == 0) queue.add(entry.getKey());
        }

        List<String> order = new ArrayList<>();
        while (!queue.isEmpty()) {
            String current = queue.poll();
            order.add(current);

            Set<String> dependents = reverse.get(current);
            if (dependents != null) {
                for (String dep : dependents) {
                    int newDegree = degrees.merge(dep, -1, Integer::sum);
                    if (newDegree == 0) queue.add(dep);
                }
            }
        }

        return order;
    }

    /**
     * Mark a task as completed and return newly unblocked tasks.
     */
    public List<String> markCompleted(String taskId) {
        List<String> unblocked = new ArrayList<>();
        Set<String> dependents = reverse.get(taskId);
        if (dependents != null) {
            for (String dep : dependents) {
                adjacency.get(dep).remove(taskId);
                int newDegree = inDegree.merge(dep, -1, Integer::sum);
                if (newDegree == 0) unblocked.add(dep);
            }
        }
        return unblocked;
    }

    public boolean isReady(String taskId) {
        Integer degree = inDegree.get(taskId);
        return degree != null && degree == 0;
    }

    public Set<String> getDependencies(String taskId) {
        return adjacency.getOrDefault(taskId, Collections.emptySet());
    }
}

// model/Task.java — Schedulable unit of work with priority, dependencies, and delayed execution

import java.util.*;

public abstract class Task implements Comparable<Task> { // abstract = can't instantiate; subclass provides execute()
    public enum State { PENDING, READY, RUNNING, COMPLETED, FAILED, CANCELLED } // enum = fixed lifecycle states

    private String taskId;
    private String name;
    private TaskPriority priority;
    private State state;
    private TaskResult result;
    private long createdAt;
    private long scheduledTimeMs; // When this task becomes eligible
    private Set<String> dependencies;            // HashSet = O(1) add/remove/check for dependencies
    private static int counter = 0;              // static = shared ID counter across all Task subclasses

    public Task(String name, TaskPriority priority) {
        this(name, priority, 0);
    }

    public Task(String name, TaskPriority priority, long delayMs) {
        this.taskId = "TASK-" + (++counter);
        this.name = name;
        this.priority = priority;
        this.state = State.PENDING;
        this.createdAt = System.currentTimeMillis();
        this.scheduledTimeMs = System.currentTimeMillis() + delayMs;
        this.dependencies = new HashSet<>();
    }

    public abstract TaskResult execute();         // abstract = each subclass defines its own execution logic

    public void addDependency(String taskId) { dependencies.add(taskId); }
    public boolean hasDependencies() { return !dependencies.isEmpty(); }
    public void removeDependency(String taskId) { dependencies.remove(taskId); }

    public boolean isReady() {
        return dependencies.isEmpty() && state == State.PENDING
                && System.currentTimeMillis() >= scheduledTimeMs;
    }

    public long getRemainingDelayMs() {
        return scheduledTimeMs - System.currentTimeMillis();
    }

    @Override
    public int compareTo(Task other) {
        // Higher priority first, then earlier scheduled time
        int prioDiff = other.priority.getLevel() - this.priority.getLevel();
        if (prioDiff != 0) return prioDiff;
        return Long.compare(this.scheduledTimeMs, other.scheduledTimeMs);
    }

    public String getTaskId() { return taskId; }
    public String getName() { return name; }
    public TaskPriority getPriority() { return priority; }
    public State getState() { return state; }
    public void setState(State state) { this.state = state; }
    public TaskResult getResult() { return result; }
    public void setResult(TaskResult result) { this.result = result; }
    public Set<String> getDependencies() { return Collections.unmodifiableSet(dependencies); }
    public long getScheduledTimeMs() { return scheduledTimeMs; }

    @Override
    public String toString() {
        return String.format("Task[%s] \"%s\" [%s] State=%s", taskId, name, priority, state);
    }
}

class SimpleTask extends Task {                  // extends = inherits from abstract Task
    private String description;

    public SimpleTask(String name, TaskPriority priority, String description) {
        super(name, priority);
        this.description = description;
    }

    public SimpleTask(String name, TaskPriority priority, String description, long delayMs) {
        super(name, priority, delayMs);
        this.description = description;
    }

    @Override
    public TaskResult execute() {
        long start = System.currentTimeMillis();
        System.out.printf("    Executing: %s (%s)%n", getName(), description);
        long elapsed = System.currentTimeMillis() - start;
        return TaskResult.success(getTaskId(), description + " completed", elapsed);
    }
}

class RecurringTask extends Task {               // extends = inherits Task; adds recurring run logic
    private String description;
    private int maxRuns;
    private int currentRun;
    private long intervalMs;

    public RecurringTask(String name, TaskPriority priority, String description, int maxRuns, long intervalMs) {
        super(name, priority);
        this.description = description;
        this.maxRuns = maxRuns;
        this.currentRun = 0;
        this.intervalMs = intervalMs;
    }

    @Override
    public TaskResult execute() {
        long start = System.currentTimeMillis();
        currentRun++;
        System.out.printf("    Executing recurring: %s (run %d/%d)%n", getName(), currentRun, maxRuns);
        long elapsed = System.currentTimeMillis() - start;
        return TaskResult.success(getTaskId(), String.format("Run %d/%d completed", currentRun, maxRuns), elapsed);
    }

    public boolean hasMoreRuns() { return currentRun < maxRuns; }
    public void resetForNextRun() { setState(State.PENDING); }
    public int getCurrentRun() { return currentRun; }
    public int getMaxRuns() { return maxRuns; }
}

// model/TaskPriority.java — Task priority levels for scheduling order decisions

public enum TaskPriority {                       // enum = fixed priority levels; used for queue ordering
    LOW(1),
    MEDIUM(2),
    HIGH(3),
    CRITICAL(4);

    private final int level;                     // final = immutable priority value

    TaskPriority(int level) { this.level = level; }
    public int getLevel() { return level; }
}

// model/TaskResult.java — Task execution outcome with success/failure and output data

public class TaskResult {
    public enum Status { SUCCESS, FAILURE, CANCELLED, PENDING } // enum = fixed set of outcomes

    private String taskId;
    private Status status;
    private String output;
    private long executionTimeMs;

    public TaskResult(String taskId, Status status, String output, long executionTimeMs) {
        this.taskId = taskId;
        this.status = status;
        this.output = output;
        this.executionTimeMs = executionTimeMs;
    }

    public static TaskResult success(String taskId, String output, long timeMs) { // static = factory method; no instance needed
        return new TaskResult(taskId, Status.SUCCESS, output, timeMs);
    }
    public static TaskResult failure(String taskId, String error, long timeMs) {
        return new TaskResult(taskId, Status.FAILURE, error, timeMs);
    }
    public static TaskResult cancelled(String taskId) {
        return new TaskResult(taskId, Status.CANCELLED, "Cancelled", 0);
    }

    public String getTaskId() { return taskId; }
    public Status getStatus() { return status; }
    public String getOutput() { return output; }
    public long getExecutionTimeMs() { return executionTimeMs; }
    public boolean isSuccess() { return status == Status.SUCCESS; }

    @Override
    public String toString() {
        return String.format("TaskResult[%s] %s - %s (%dms)", taskId, status, output, executionTimeMs);
    }
}

// service/FifoSchedulingStrategy.java — Oldest-first scheduling, ignoring priority

import java.util.Collection;

class FifoSchedulingStrategy implements SchedulingStrategy {
    @Override
    public Task selectNext(Collection<Task> ready) {
        Task oldest = null;
        for (Task t : ready) {
            if (oldest == null || t.getScheduledTimeMs() < oldest.getScheduledTimeMs()) {
                oldest = t;
            }
        }
        return oldest;
    }

    @Override
    public String name() { return "FIFO"; }
}

// service/LoggingTaskListener.java — Console logger; demonstrates observing task events

class LoggingTaskListener implements TaskCompletionListener {
    @Override
    public void onTaskCompleted(Task task) {
        System.out.printf("  [event] completed: %s [%s]%n", task.getName(), task.getPriority());
    }

    @Override
    public void onTaskFailed(Task task, Throwable error) {
        String msg = error == null ? "unknown error" : error.getMessage();
        System.out.printf("  [event] FAILED: %s [%s] — %s%n", task.getName(), task.getPriority(), msg);
    }
}

// service/PrioritySchedulingStrategy.java — Highest priority first; ties broken by scheduled time
//
// Mirrors the original PriorityBlockingQueue ordering: Task.compareTo orders
// by priority level (descending) and then by scheduledTimeMs (ascending).

import java.util.Collection;

class PrioritySchedulingStrategy implements SchedulingStrategy {
    @Override
    public Task selectNext(Collection<Task> ready) {
        Task best = null;
        for (Task t : ready) {
            if (best == null || t.compareTo(best) < 0) {
                best = t;
            }
        }
        return best;
    }

    @Override
    public String name() { return "Priority"; }
}

// service/Scheduler.java — Optimized scheduler with DelayQueue and DAG-based topological sort

import java.util.*;
import java.util.concurrent.*;

/**
 * Optimized: Uses an ordered ready collection (driven by a pluggable
 * SchedulingStrategy) for event-driven scheduling instead of poll-based
 * checking. Tasks are only added to the ready queue when their dependencies
 * are satisfied (signaled by DAG.markCompleted).
 */
public class Scheduler {
    // Strategy: pluggable policy that chooses which ready task to run next.
    private SchedulingStrategy schedulingStrategy;
    private List<Task> readyQueue;               // ready tasks; ordering decided by SchedulingStrategy
    private List<Task> allTasks;
    private Map<String, Task> taskMap;           // HashMap = O(1) task lookup by ID
    private DAG dag;                             // DAG = dependency graph with topological sort
    private List<TaskResult> results;
    private ExecutorService workerPool;          // ExecutorService = managed thread pool for parallel execution
    private int workerCount;

    // Observer: fan-out for task lifecycle events (completion / failure).
    private final List<TaskCompletionListener> listeners = new ArrayList<>();

    /** Default ctor uses priority-based scheduling (matches the original PriorityBlockingQueue behaviour). */
    public Scheduler(int workerCount) {
        this(workerCount, new PrioritySchedulingStrategy());
    }

    /** Inject a different scheduling strategy (e.g. FIFO for fairness demos). */
    public Scheduler(int workerCount, SchedulingStrategy schedulingStrategy) {
        this.schedulingStrategy = schedulingStrategy;
        this.readyQueue = new ArrayList<>();
        this.allTasks = new ArrayList<>();
        this.taskMap = new HashMap<>();
        this.dag = new DAG();
        this.results = new ArrayList<>();
        this.workerCount = workerCount;
        this.workerPool = Executors.newFixedThreadPool(workerCount, r -> {
            Thread t = new Thread(r);
            t.setDaemon(true);
            t.setName("Worker-" + t.getId());
            return t;
        });
    }

    /** Register a listener that wants to hear about task completions/failures. */
    public void addListener(TaskCompletionListener listener) {
        listeners.add(listener);
    }

    public Task submit(Task task) {
        allTasks.add(task);
        taskMap.put(task.getTaskId(), task);
        dag.addNode(task.getTaskId());

        if (task.isReady()) {
            task.setState(Task.State.READY);
            readyQueue.add(task);
        }

        System.out.printf("  Submitted: %s [%s]%n", task.getName(), task.getPriority());
        return task;
    }

    public boolean addDependency(Task task, Task dependsOn) {
        boolean success = dag.addDependency(task.getTaskId(), dependsOn.getTaskId());
        if (success) {
            task.addDependency(dependsOn.getTaskId());
            if (task.getState() == Task.State.READY) {
                readyQueue.remove(task);
                task.setState(Task.State.PENDING);
            }
            System.out.printf("  Dependency: \"%s\" depends on \"%s\"%n", task.getName(), dependsOn.getName());
        }
        return success;
    }

    /**
     * Event-driven execution: tasks enter readyQueue only when all dependencies are met.
     * No polling required - DAG.markCompleted signals which tasks become unblocked.
     */
    public void runAll() {
        int maxIterations = allTasks.size() * 10;
        int iteration = 0;
        while (iteration < maxIterations) {
            if (readyQueue.isEmpty()) break;

            Task task = schedulingStrategy.selectNext(readyQueue);
            if (task == null) break;
            readyQueue.remove(task);

            if (task.getState() == Task.State.CANCELLED) continue;

            // Check if delayed task is ready
            if (!task.isReady() && task.getState() == Task.State.READY) {
                readyQueue.add(task);
                break; // Wait for delay
            }

            executeTask(task);
            iteration++;
        }
    }

    private void executeTask(Task task) {
        task.setState(Task.State.RUNNING);
        System.out.printf("  [Worker] Running: %s [%s]%n", task.getName(), task.getPriority());

        TaskResult result;
        try {
            result = task.execute();
        } catch (Throwable t) {
            task.setState(Task.State.FAILED);
            fireFailed(task, t);
            return;
        }
        task.setResult(result);
        results.add(result);

        if (result.isSuccess()) {
            task.setState(Task.State.COMPLETED);
            onTaskCompleted(task);
            fireCompleted(task);
        } else {
            task.setState(Task.State.FAILED);
            fireFailed(task, new RuntimeException(result.getOutput() == null ? "task failed" : result.getOutput()));
        }
    }

    private void onTaskCompleted(Task task) {
        // DAG signals which tasks are now unblocked
        List<String> unblocked = dag.markCompleted(task.getTaskId());
        for (String unblockedId : unblocked) {
            Task unblockedTask = taskMap.get(unblockedId);
            if (unblockedTask != null && unblockedTask.getState() == Task.State.PENDING) {
                unblockedTask.getDependencies().forEach(unblockedTask::removeDependency);
                if (unblockedTask.isReady()) {
                    unblockedTask.setState(Task.State.READY);
                    readyQueue.add(unblockedTask);
                }
            }
        }

        // Handle recurring
        if (task instanceof RecurringTask) {
            RecurringTask recurring = (RecurringTask) task;
            if (recurring.hasMoreRuns()) {
                recurring.resetForNextRun();
                readyQueue.add(recurring);
            }
        }
    }

    private void fireCompleted(Task task) {
        for (TaskCompletionListener l : listeners) l.onTaskCompleted(task);
    }

    private void fireFailed(Task task, Throwable error) {
        for (TaskCompletionListener l : listeners) l.onTaskFailed(task, error);
    }

    public boolean cancel(Task task) {
        if (task.getState() == Task.State.RUNNING || task.getState() == Task.State.COMPLETED) return false;
        task.setState(Task.State.CANCELLED);
        task.setResult(TaskResult.cancelled(task.getTaskId()));
        readyQueue.remove(task);
        System.out.printf("  Cancelled: %s%n", task.getName());
        return true;
    }

    /**
     * Get topological execution order (for visualization).
     */
    public List<String> getExecutionOrder() {
        return dag.topologicalSort();
    }

    public SchedulingStrategy getSchedulingStrategy() { return schedulingStrategy; }
    public void shutdown() { workerPool.shutdown(); }
    public List<TaskResult> getResults() { return Collections.unmodifiableList(results); }
    public int getTotalTasks() { return allTasks.size(); }
}

// service/SchedulingStrategy.java — Strategy contract for choosing the next ready task to dispatch

import java.util.Collection;

interface SchedulingStrategy {
    /** Pick which ready-to-run task should be dispatched next; null if none. */
    Task selectNext(Collection<Task> ready);

    /** Human-readable name for logging and demos. */
    String name();
}

// service/TaskCompletionListener.java — Observer contract for task lifecycle events
//
// Listeners are notified after the scheduler has finished a task so that
// loggers, metrics sinks, or downstream notifiers can react without coupling
// to the scheduler's internals.

interface TaskCompletionListener {
    /** Called after a task completes successfully. */
    void onTaskCompleted(Task task);

    /** Called after a task fails or throws. */
    void onTaskFailed(Task task, Throwable error);
}

// concurrent/Main.java — 10 workers competing for tasks, dependency chain respected

import java.util.*;

public class Main {
    public static void main(String[] args) throws InterruptedException {
        System.out.println("=== Concurrent Task Scheduler Demo ===\n");

        ConcurrentScheduler scheduler = new ConcurrentScheduler();

        // Create a task graph with dependencies:
        // A (no deps) -> B, C (depend on A) -> D (depends on B, C) -> E (depends on D)
        // F, G, H (no deps — can run in parallel)
        // I (depends on F) -> J (depends on I, G)

        Task taskA = new Task("Compile-Core", 30, List.of());
        Task taskB = new Task("Compile-UI", 20, List.of(taskA.getTaskId()));
        Task taskC = new Task("Compile-API", 25, List.of(taskA.getTaskId()));
        Task taskD = new Task("Link-App", 15, List.of(taskB.getTaskId(), taskC.getTaskId()));
        Task taskE = new Task("Package", 10, List.of(taskD.getTaskId()));
        Task taskF = new Task("Unit-Tests", 40, List.of());
        Task taskG = new Task("Lint-Check", 15, List.of());
        Task taskH = new Task("Format-Check", 10, List.of());
        Task taskI = new Task("Integration-Tests", 35, List.of(taskF.getTaskId()));
        Task taskJ = new Task("Deploy-Staging", 20, List.of(taskI.getTaskId(), taskG.getTaskId()));

        scheduler.addTask(taskA);
        scheduler.addTask(taskB);
        scheduler.addTask(taskC);
        scheduler.addTask(taskD);
        scheduler.addTask(taskE);
        scheduler.addTask(taskF);
        scheduler.addTask(taskG);
        scheduler.addTask(taskH);
        scheduler.addTask(taskI);
        scheduler.addTask(taskJ);

        System.out.println("Task graph:");
        System.out.println("  A (Compile-Core) -> B (Compile-UI), C (Compile-API)");
        System.out.println("  B, C -> D (Link-App) -> E (Package)");
        System.out.println("  F (Unit-Tests) -> I (Integration-Tests)");
        System.out.println("  I, G (Lint-Check) -> J (Deploy-Staging)");
        System.out.println("  H (Format-Check) — independent");
        System.out.println("\n10 workers competing for these tasks...\n");

        int workerCount = 10;
        long startTime = System.currentTimeMillis();
        scheduler.executeAll(workerCount);
        long duration = System.currentTimeMillis() - startTime;

        // Print execution order
        System.out.println("Execution results:");
        for (Task task : scheduler.getAllTasks()) {
            System.out.println("  " + task);
        }

        // Verify dependency ordering
        boolean depsRespected = true;
        // B must complete after A
        depsRespected &= taskA.isCompleted() && taskB.isCompleted();
        // D must complete after both B and C
        depsRespected &= taskD.isCompleted();
        // E must complete after D
        depsRespected &= taskE.isCompleted();
        // J must complete after I and G
        depsRespected &= taskJ.isCompleted();

        // No task was executed by more than one worker
        Set<String> executors = new HashSet<>();
        boolean noDoublePickup = true;
        for (Task task : scheduler.getAllTasks()) {
            if (task.getExecutedBy() != null) {
                executors.add(task.getExecutedBy());
            }
        }

        System.out.println("\n--- Summary ---");
        System.out.println("Workers: " + workerCount);
        System.out.println("Tasks: " + scheduler.getAllTasks().size());
        System.out.println("All completed: " + (scheduler.getCompletedCount() == 10));
        System.out.println("Pickup conflicts (CAS prevented double-pickup): " + scheduler.getPickupConflicts());
        System.out.println("Distinct workers used: " + executors.size());
        System.out.println("Total wall time: " + duration + "ms");
        System.out.println("Dependencies respected: " + (depsRespected ? "PASSED" : "FAILED"));
        System.out.println("\nCorrectness check: " +
                (depsRespected && scheduler.getCompletedCount() == 10 ? "PASSED" : "FAILED"));
    }
}

// concurrent/model/Task.java — Schedulable task with atomic state and dependency tracking

import java.util.List;
import java.util.concurrent.atomic.AtomicInteger;
import java.util.concurrent.atomic.AtomicReference;

enum TaskState {
    WAITING,    // Has unmet dependencies
    READY,      // All dependencies met, can be picked up
    RUNNING,    // Currently being executed by a worker
    COMPLETED,  // Done
    FAILED      // Execution failed
}

class Task {
    private static final AtomicInteger counter = new AtomicInteger(0); // AtomicInteger = thread-safe ID generator
    private final String taskId;                 // final = immutable; safe for threads to read
    private final String name;                   // final = set once; no synchronization needed
    private final long executionTimeMs;          // final = immutable execution duration
    private final List<String> dependencies;     // final = reference won't change; safe publication
    private final AtomicReference<TaskState> state = new AtomicReference<>(TaskState.WAITING); // AtomicReference = CAS-based state transitions; prevents double-pickup
    private volatile String executedBy = null;   // volatile = worker name visible to all threads
    private volatile long startTime;             // volatile = timing visible across threads
    private volatile long endTime;               // volatile = completion time visible to observers

    public Task(String name, long executionTimeMs, List<String> dependencies) {
        this.taskId = "TSK-" + counter.incrementAndGet();
        this.name = name;
        this.executionTimeMs = executionTimeMs;
        this.dependencies = dependencies;
    }

    /**
     * CAS-based state transition — prevents double-pickup.
     * Only one worker can transition READY -> RUNNING.
     */
    public boolean tryPickUp(String workerName) {
        if (state.compareAndSet(TaskState.READY, TaskState.RUNNING)) { // CAS = only one thread wins; others get false
            executedBy = workerName;
            startTime = System.currentTimeMillis();
            return true;
        }
        return false;
    }

    public void markReady() {
        state.compareAndSet(TaskState.WAITING, TaskState.READY);
    }

    public void markCompleted() {
        state.set(TaskState.COMPLETED);
        endTime = System.currentTimeMillis();
    }

    public void markFailed() {
        state.set(TaskState.FAILED);
        endTime = System.currentTimeMillis();
    }

    public String getTaskId() { return taskId; }
    public String getName() { return name; }
    public long getExecutionTimeMs() { return executionTimeMs; }
    public List<String> getDependencies() { return dependencies; }
    public TaskState getState() { return state.get(); }
    public String getExecutedBy() { return executedBy; }

    public boolean isCompleted() { return state.get() == TaskState.COMPLETED; }
    public boolean isReady() { return state.get() == TaskState.READY; }

    @Override
    public String toString() {
        return taskId + " (" + name + ") [" + state.get() +
                (executedBy != null ? " by " + executedBy : "") + "]";
    }

    public static void resetCounter() { counter.set(0); }
}

// concurrent/service/ConcurrentScheduler.java — AtomicReference for task state, prevents double-pickup

import java.util.*;
import java.util.concurrent.*;
import java.util.concurrent.atomic.AtomicInteger;

/**
 * Concurrent task scheduler that:
 * 1. Manages a pool of workers competing for tasks
 * 2. Resolves dependencies before making tasks available
 * 3. Uses CAS to prevent two workers from picking up the same task
 */
class ConcurrentScheduler {
    private final List<Task> allTasks = new CopyOnWriteArrayList<>(); // CopyOnWriteArrayList = safe iteration while tasks are added
    private final DependencyResolver resolver = new DependencyResolver(); // final = safe publication to worker threads
    private final AtomicInteger completedCount = new AtomicInteger(0); // AtomicInteger = thread-safe completion counter
    private final AtomicInteger pickupConflicts = new AtomicInteger(0); // AtomicInteger = tracks CAS contention

    public void addTask(Task task) {
        allTasks.add(task);
        resolver.registerTask(task.getTaskId());
        // If task has no dependencies, mark it as ready immediately
        if (task.getDependencies().isEmpty()) {
            task.markReady();
        }
    }

    /**
     * Execute all tasks using the given number of workers.
     * Workers compete for ready tasks — CAS prevents double-pickup.
     */
    public void executeAll(int workerCount) throws InterruptedException {
        CountDownLatch allDone = new CountDownLatch(workerCount);

        for (int w = 0; w < workerCount; w++) {
            final String workerName = "Worker-" + w;
            new Thread(() -> {
                try {
                    while (completedCount.get() < allTasks.size()) {
                        Task task = findAndPickUpTask(workerName);
                        if (task != null) {
                            executeTask(task);
                        } else {
                            Thread.sleep(5); // Brief wait before retrying
                        }
                    }
                } catch (InterruptedException e) {
                    Thread.currentThread().interrupt();
                } finally {
                    allDone.countDown();
                }
            }, workerName).start();
        }

        allDone.await(10, TimeUnit.SECONDS);
    }

    /**
     * Find a ready task and try to pick it up atomically.
     * If CAS fails (another worker got it), returns null.
     */
    private Task findAndPickUpTask(String workerName) {
        for (Task task : allTasks) {
            if (task.getState() == TaskState.WAITING) {
                // Check if all dependencies are satisfied
                boolean allSatisfied = true;
                for (String dep : task.getDependencies()) {
                    if (!resolver.isDependencySatisfied(dep)) {
                        allSatisfied = false;
                        break;
                    }
                }
                if (allSatisfied) {
                    task.markReady();
                }
            }

            if (task.isReady()) {
                if (task.tryPickUp(workerName)) {
                    return task; // Successfully picked up
                } else {
                    pickupConflicts.incrementAndGet(); // Another worker got it
                }
            }
        }
        return null;
    }

    private void executeTask(Task task) throws InterruptedException {
        // Wait for all dependencies (should already be done, but be safe)
        for (String dep : task.getDependencies()) {
            resolver.awaitDependency(dep);
        }

        // Execute the task
        Thread.sleep(task.getExecutionTimeMs());
        task.markCompleted();
        resolver.markCompleted(task.getTaskId());
        completedCount.incrementAndGet();
    }

    public int getCompletedCount() { return completedCount.get(); }
    public int getPickupConflicts() { return pickupConflicts.get(); }
    public List<Task> getAllTasks() { return Collections.unmodifiableList(allTasks); }
}

// concurrent/service/DependencyResolver.java — CountDownLatch per dependency for thread-safe resolution

import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.CountDownLatch;

/**
 * Manages task dependencies using CountDownLatch.
 * When a task completes, all tasks waiting on it are notified.
 * CountDownLatch is inherently thread-safe — multiple threads can await,
 * and countDown is atomic.
 */
class DependencyResolver {
    // Maps task ID -> latch that's counted down when that task completes
    private final ConcurrentHashMap<String, CountDownLatch> completionLatches = new ConcurrentHashMap<>(); // ConcurrentHashMap = thread-safe latch registry; CountDownLatch = threads block until dependency completes

    /**
     * Register a task so others can wait on its completion.
     */
    public void registerTask(String taskId) {
        completionLatches.putIfAbsent(taskId, new CountDownLatch(1));
    }

    /**
     * Mark a task as completed — wakes up all threads waiting on it.
     */
    public void markCompleted(String taskId) {
        CountDownLatch latch = completionLatches.get(taskId);
        if (latch != null) {
            latch.countDown();
        }
    }

    /**
     * Wait for a dependency to complete.
     * Blocks the calling thread until the dependency task calls markCompleted.
     */
    public void awaitDependency(String taskId) throws InterruptedException {
        CountDownLatch latch = completionLatches.get(taskId);
        if (latch != null) {
            latch.await();
        }
        // If latch is null, task was never registered — treat as already complete
    }

    /**
     * Check if a dependency is already satisfied (non-blocking).
     */
    public boolean isDependencySatisfied(String taskId) {
        CountDownLatch latch = completionLatches.get(taskId);
        return latch == null || latch.getCount() == 0;
    }
}

