// service/FileSystem.java — Indexed file system with O(1) path resolution via HashMap
import java.util.ArrayList;
import java.util.HashMap;
import java.util.List;
import java.util.Map;

public class FileSystem {
    private Directory root;
    // HashMap index gives O(1) path resolution instead of O(depth) tree traversal
    private Map<String, FileSystemEntry> pathIndex;       // HashMap = O(1) lookup by full path string

    public FileSystem() {
        this.root = new Directory("", "/");
        this.pathIndex = new HashMap<>();
        pathIndex.put("/", root);
    }

    public Directory getRoot() { return root; }

    public void mkdir(String path) {
        String normalized = Path.normalize(path);
        String[] parts = Path.split(normalized);
        Directory current = root;

        StringBuilder currentPath = new StringBuilder();
        for (String part : parts) {
            currentPath.append("/").append(part);
            String pathStr = currentPath.toString();

            // O(1) check if directory already exists in index
            FileSystemEntry existing = pathIndex.get(pathStr);
            if (existing != null) {
                if (existing.isDirectory()) {
                    current = (Directory) existing;
                } else {
                    throw new IllegalArgumentException("Path component is a file: " + part);
                }
            } else {
                Directory newDir = new Directory(part, pathStr);
                current.addEntry(newDir);
                pathIndex.put(pathStr, newDir); // Index the new directory
                current = newDir;
            }
        }
    }

    public File createFile(String path, String content) {
        String normalized = Path.normalize(path);
        String parentPath = Path.getParent(normalized);
        String fileName = Path.getName(normalized);

        mkdir(parentPath);
        Directory parent = (Directory) pathIndex.get(parentPath);

        FileSystemEntry existing = pathIndex.get(normalized);
        if (existing != null && existing.isDirectory()) {
            throw new IllegalArgumentException("A directory exists with that name: " + fileName);
        }

        File file;
        if (existing != null) {
            file = (File) existing;
            file.setContent(content);
        } else {
            file = new File(fileName, normalized, content);
            parent.addEntry(file);
            pathIndex.put(normalized, file); // Index the new file
        }
        // Invalidate parent size cache up the tree
        invalidateSizeChain(parentPath);
        return file;
    }

    // O(1) path resolution using the index
    public FileSystemEntry resolve(String path) {
        String normalized = Path.normalize(path);
        FileSystemEntry entry = pathIndex.get(normalized);
        if (entry == null) {
            throw new IllegalArgumentException("Entry not found: " + normalized);
        }
        return entry;
    }

    public Directory resolveDirectory(String path) {
        FileSystemEntry entry = resolve(path);
        if (!entry.isDirectory()) {
            throw new IllegalArgumentException("Not a directory: " + path);
        }
        return (Directory) entry;
    }

    public boolean delete(String path) {
        String normalized = Path.normalize(path);
        if (normalized.equals("/")) {
            throw new IllegalArgumentException("Cannot delete root directory");
        }
        String parentPath = Path.getParent(normalized);
        String name = Path.getName(normalized);
        Directory parent = resolveDirectory(parentPath);

        FileSystemEntry entry = pathIndex.get(normalized);
        if (entry == null) return false;

        // Remove from index (recursively for directories)
        removeFromIndex(entry);
        parent.removeEntry(name);
        invalidateSizeChain(parentPath);
        return true;
    }

    private void removeFromIndex(FileSystemEntry entry) {
        pathIndex.remove(entry.getPath());
        if (entry.isDirectory()) {
            for (FileSystemEntry child : ((Directory) entry).getChildren()) {
                removeFromIndex(child);
            }
        }
    }

    // WHY: propagate size invalidation up to root so cached sizes stay consistent
    private void invalidateSizeChain(String path) {
        String current = path;
        while (!current.equals("/")) {
            FileSystemEntry entry = pathIndex.get(current);
            if (entry != null) entry.invalidateSize();
            current = Path.getParent(current);
        }
        root.invalidateSize();
    }

    public List<FileSystemEntry> ls(String path) {
        Directory dir = resolveDirectory(path);
        return dir.getChildren();
    }

    // Search uses index for O(n) scan of all entries (no tree traversal overhead)
    public List<String> search(String startPath, String pattern) {
        List<String> results = new ArrayList<>();
        String normalizedStart = Path.normalize(startPath);

        // WHY: scanning the flat index is cache-friendly and avoids recursive descent
        for (Map.Entry<String, FileSystemEntry> e : pathIndex.entrySet()) {
            String entryPath = e.getKey();
            // Only include entries under the start path
            if (entryPath.startsWith(normalizedStart) || normalizedStart.equals("/")) {
                String name = e.getValue().getName();
                if (!name.isEmpty() && Path.matches(name, pattern)) {
                    results.add(entryPath);
                }
            }
        }
        return results;
    }

    // Size uses cached values — O(1) if cache is warm
    public long calculateSize(String path) {
        FileSystemEntry entry = resolve(path);
        return entry.getSize();
    }
}

// service/SearchVisitor.java — Searches entries matching a name pattern (kept for visitor demo)
import java.util.ArrayList;
import java.util.List;

public class SearchVisitor implements FileSystemVisitor {  // implements = fulfills visitor interface
    private String pattern;
    private List<String> results;                         // ArrayList = accumulates matched paths

    public SearchVisitor(String pattern) {
        this.pattern = pattern;
        this.results = new ArrayList<>();
    }

    @Override
    public void visitFile(File file) {
        if (Path.matches(file.getName(), pattern)) {
            results.add(file.getPath());
        }
    }

    @Override
    public void visitDirectory(Directory directory) {
        if (Path.matches(directory.getName(), pattern)) {
            results.add(directory.getPath());
        }
    }

    public List<String> getResults() { return results; }
}

// service/SizeVisitor.java — Size calculation visitor (kept for pattern demo)
import java.util.HashMap;
import java.util.Map;

public class SizeVisitor implements FileSystemVisitor {    // implements = fulfills visitor interface
    private Map<String, Long> directorySizes;             // HashMap = O(1) dir-size lookup by path
    private long totalSize;

    public SizeVisitor() {
        this.directorySizes = new HashMap<>();
        this.totalSize = 0;
    }

    @Override
    public void visitFile(File file) {
        totalSize += file.getSize();
    }

    @Override
    public void visitDirectory(Directory directory) {
        long dirSize = directory.getSize();
        directorySizes.put(directory.getPath(), dirSize);
    }

    public long getTotalSize() { return totalSize; }

    public long getDirectorySize(String path) {
        return directorySizes.getOrDefault(path, 0L);
    }
}

// strategy/FileSystemVisitor.java — Visitor interface for traversing file system entries
public interface FileSystemVisitor {                      // interface = decouples traversal logic from tree structure
    void visitFile(File file);
    void visitDirectory(Directory directory);
}

// concurrent/Main.java — 10 threads creating/deleting files in same dir, verify directory always consistent

import java.util.*;
import java.util.concurrent.*;
import java.util.concurrent.atomic.AtomicBoolean;
import java.util.concurrent.atomic.AtomicInteger;

public class Main {
    public static void main(String[] args) throws InterruptedException {
        System.out.println("=== Concurrent File System Demo ===\n");

        FileSystem fs = new FileSystem();
        fs.createDirectory("/", "shared");

        int threadCount = 10;
        int opsPerThread = 100;
        CountDownLatch startLatch = new CountDownLatch(1);
        CountDownLatch doneLatch = new CountDownLatch(threadCount);
        AtomicBoolean inconsistencyFound = new AtomicBoolean(false);
        AtomicInteger totalCreates = new AtomicInteger(0);
        AtomicInteger totalDeletes = new AtomicInteger(0);

        System.out.println("Scenario: 10 threads each perform 100 create/delete operations");
        System.out.println("  in the same directory simultaneously.");
        System.out.println("Expected: Directory listing is always consistent (no corruption).\n");

        for (int t = 0; t < threadCount; t++) {
            final int threadId = t;
            new Thread(() -> {
                try {
                    startLatch.await();
                    Random random = new Random(threadId);
                    for (int i = 0; i < opsPerThread; i++) {
                        String fileName = "file-" + threadId + "-" + i + ".txt";
                        // Create
                        fs.createFile("/shared", fileName, "content-" + threadId + "-" + i);
                        totalCreates.incrementAndGet();

                        // Verify listing is a valid snapshot
                        Set<String> listing = fs.listDirectory("/shared");
                        if (listing == null) {
                            inconsistencyFound.set(true);
                        }

                        // Sometimes delete own files
                        if (random.nextBoolean()) {
                            fs.deleteFile("/shared", fileName);
                            totalDeletes.incrementAndGet();
                        }

                        // Verify child count is non-negative
                        int count = fs.getChildCount("/shared");
                        if (count < 0) {
                            inconsistencyFound.set(true);
                        }
                    }
                } catch (Exception e) {
                    inconsistencyFound.set(true);
                    e.printStackTrace();
                } finally {
                    doneLatch.countDown();
                }
            }, "FileWorker-" + t).start();
        }

        startLatch.countDown();
        doneLatch.await();

        // Final verification
        Set<String> finalListing = fs.listDirectory("/shared");
        int finalCount = fs.getChildCount("/shared");
        boolean listingMatchesCount = (finalListing != null && finalListing.size() == finalCount);

        System.out.println("--- Results ---");
        System.out.println("Total creates: " + totalCreates.get());
        System.out.println("Total deletes: " + totalDeletes.get());
        System.out.println("Final file count: " + finalCount);
        System.out.println("Listing size matches count: " + listingMatchesCount);
        System.out.println("No inconsistency detected: " + !inconsistencyFound.get());

        boolean passed = !inconsistencyFound.get() && listingMatchesCount && finalCount >= 0;
        System.out.println("\nCorrectness check: " + (passed ? "PASSED" : "FAILED"));
    }
}

// concurrent/model/FileNode.java — Represents a file or directory with thread-safe content and children

import java.util.Collections;
import java.util.Set;
import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.atomic.AtomicReference;

public class FileNode {
    private final String name;                            // final = safe publication; immutable after construction
    private final boolean isDirectory;                    // final = never changes once created
    private final AtomicReference<String> content;        // AtomicReference = lock-free thread-safe reads/writes
    private final ConcurrentHashMap<String, FileNode> children; // ConcurrentHashMap = thread-safe map; no external lock needed

    public FileNode(String name, boolean isDirectory) {
        this.name = name;
        this.isDirectory = isDirectory;
        this.content = isDirectory ? null : new AtomicReference<>("");
        this.children = isDirectory ? new ConcurrentHashMap<>() : null;
    }

    public String getName() { return name; }
    public boolean isDirectory() { return isDirectory; }

    public String getContent() {
        if (!isDirectory) return content.get();
        throw new UnsupportedOperationException("Directories have no content");
    }

    public void setContent(String newContent) {
        if (!isDirectory) content.set(newContent);
        else throw new UnsupportedOperationException("Directories have no content");
    }

    public boolean addChild(FileNode child) {
        if (!isDirectory) throw new UnsupportedOperationException("Files cannot have children");
        return children.putIfAbsent(child.getName(), child) == null;
    }

    public FileNode removeChild(String childName) {
        if (!isDirectory) throw new UnsupportedOperationException("Files cannot have children");
        return children.remove(childName);
    }

    public FileNode getChild(String childName) {
        if (!isDirectory) return null;
        return children.get(childName);
    }

    public Set<String> listChildren() {
        if (!isDirectory) return Collections.emptySet();
        return Collections.unmodifiableSet(children.keySet());
    }

    public int childCount() {
        if (!isDirectory) return 0;
        return children.size();
    }
}

// concurrent/service/FileSystem.java — Thread-safe file system using ConcurrentHashMap and AtomicReference

import java.util.Set;

public class FileSystem {
    private final FileNode root;                          // final = safely shared across threads after construction

    public FileSystem() {
        this.root = new FileNode("/", true);
    }

    public boolean createFile(String dirPath, String fileName, String content) {
        FileNode dir = navigate(dirPath);
        if (dir == null || !dir.isDirectory()) return false;
        FileNode file = new FileNode(fileName, false);
        file.setContent(content);
        return dir.addChild(file);
    }

    public boolean deleteFile(String dirPath, String fileName) {
        FileNode dir = navigate(dirPath);
        if (dir == null || !dir.isDirectory()) return false;
        return dir.removeChild(fileName) != null;
    }

    public String readFile(String dirPath, String fileName) {
        FileNode dir = navigate(dirPath);
        if (dir == null || !dir.isDirectory()) return null;
        FileNode file = dir.getChild(fileName);
        if (file == null || file.isDirectory()) return null;
        return file.getContent();
    }

    public void writeFile(String dirPath, String fileName, String content) {
        FileNode dir = navigate(dirPath);
        if (dir == null || !dir.isDirectory()) return;
        FileNode file = dir.getChild(fileName);
        if (file != null && !file.isDirectory()) {
            file.setContent(content);
        }
    }

    public boolean createDirectory(String parentPath, String dirName) {
        FileNode parent = navigate(parentPath);
        if (parent == null || !parent.isDirectory()) return false;
        return parent.addChild(new FileNode(dirName, true));
    }

    public Set<String> listDirectory(String path) {
        FileNode dir = navigate(path);
        if (dir == null || !dir.isDirectory()) return null;
        return dir.listChildren();
    }

    public int getChildCount(String path) {
        FileNode dir = navigate(path);
        if (dir == null || !dir.isDirectory()) return -1;
        return dir.childCount();
    }

    private FileNode navigate(String path) {
        if (path == null || path.equals("/")) return root;
        String[] parts = path.split("/");
        FileNode current = root;
        for (String part : parts) {
            if (part.isEmpty()) continue;
            current = current.getChild(part);
            if (current == null) return null;
        }
        return current;
    }
}

