                + oldValue + "\" -> \"" + newValue + "\"");
    }
}

// service/Spreadsheet.java — Manages cells, formulas, dependencies, and undo/redo
import java.util.*;

public class Spreadsheet {
    private Map<String, Cell> cells;                      // private = internal cell storage by ID
    private DependencyGraph dependencyGraph;              // private = tracks formula dependencies
    private Deque<CellCommand> undoStack;                 // private = stack of commands for undo (LIFO)
    private Deque<CellCommand> redoStack;                 // private = stack of undone commands for redo

    // Observer: fan-out for cell change events (value set, dependents recalculated).
    private final List<CellObserver> observers = new ArrayList<>();

    public Spreadsheet() {
        this.cells = new HashMap<>();
        this.dependencyGraph = new DependencyGraph();
        this.undoStack = new ArrayDeque<>();
        this.redoStack = new ArrayDeque<>();
    }

    // === Observer plumbing ===
    public void addObserver(CellObserver observer) { observers.add(observer); }
    public void removeObserver(CellObserver observer) { observers.remove(observer); }

    private void fireCellChanged(String cellId, String oldValue, String newValue) {
        for (CellObserver o : observers) o.onCellChanged(cellId, oldValue, newValue);
    }

    public Cell getCell(String id) { return cells.get(id); }

    public Cell getOrCreateCell(String id) {
        return cells.computeIfAbsent(id, Cell::new);
    }

    public void setCellValue(String cellId, double value) {
        CellValue cv = new CellValue.NumericValue(value);
        CellCommand cmd = new CellCommand(this, cellId, cv);
        cmd.execute();
        undoStack.push(cmd);
        redoStack.clear();
    }

    public void setCellText(String cellId, String text) {
        CellValue cv = new CellValue.TextValue(text);
        CellCommand cmd = new CellCommand(this, cellId, cv);
        cmd.execute();
        undoStack.push(cmd);
        redoStack.clear();
    }

    public void setCellFormula(String cellId, String expression) {
        Formula formula = new Formula(expression);
        List<String> refs = formula.getReferencedCells();
        if (dependencyGraph.hasCircularDependency(cellId, refs)) {
            throw new IllegalArgumentException("Circular dependency detected for " + cellId);
        }
        CellCommand cmd = new CellCommand(this, cellId, formula);
        cmd.execute();
        undoStack.push(cmd);
        redoStack.clear();
    }

    void setCellValueInternal(String cellId, CellValue value) {
        Cell cell = getOrCreateCell(cellId);
        String oldDisplay = cell.getDisplayValue(this);
        cell.setValue(value);
        if (value instanceof Formula) {
            Formula formula = (Formula) value;
            dependencyGraph.setDependencies(cellId, formula.getReferencedCells());
        } else {
            dependencyGraph.clearDependencies(cellId);
        }
        // Snapshot dependents' display values BEFORE recalculation so we can report old->new
        List<String> deps = dependencyGraph.getAllDependentsTopological(cellId);
        Map<String, String> depOldValues = new HashMap<>();
        for (String dep : deps) {
            Cell c = cells.get(dep);
            if (c != null) depOldValues.put(dep, c.getDisplayValue(this));
        }
        recalculateDependents(cellId);
        String newDisplay = cell.getDisplayValue(this);
        fireCellChanged(cellId, oldDisplay, newDisplay);
        // Fire for dependents whose computed display changed
        for (String dep : deps) {
            Cell c = cells.get(dep);
            if (c == null) continue;
            String oldV = depOldValues.get(dep);
            String newV = c.getDisplayValue(this);
            if (!java.util.Objects.equals(oldV, newV)) {
                fireCellChanged(dep, oldV, newV);
            }
        }
    }

    // Naive: recalculates ALL dependents even if their values haven't changed
    void recalculateDependents(String cellId) {
        List<String> deps = dependencyGraph.getAllDependentsTopological(cellId);
        // Formulas evaluate lazily — no explicit action needed for this naive version
    }

    public double getCellNumericValue(String cellId) {
        Cell cell = cells.get(cellId);
        if (cell == null) return 0;
        return cell.getNumericValue(this);
    }

    public String getCellDisplayValue(String cellId) {
        Cell cell = cells.get(cellId);
        if (cell == null) return "";
        return cell.getDisplayValue(this);
    }

    public void undo() {
        if (!undoStack.isEmpty()) {
            CellCommand cmd = undoStack.pop();
            cmd.undo();
            redoStack.push(cmd);
        }
    }

    public void redo() {
        if (!redoStack.isEmpty()) {
            CellCommand cmd = redoStack.pop();
            cmd.redo();
            undoStack.push(cmd);
        }
    }

    public SpreadsheetIterator rangeIterator(String start, String end) {
        return new SpreadsheetIterator(this, start, end);
    }
}

// service/SpreadsheetIterator.java — Iterates over a cell range
import java.util.Iterator;
import java.util.List;
import java.util.ArrayList;

public class SpreadsheetIterator implements Iterator<Cell> { // implements Iterator = enables for-each style traversal
    private Spreadsheet spreadsheet;
    private List<String> cellIds;                         // private = expanded range of cell references
    private int index;                                    // private = current position in iteration

    public SpreadsheetIterator(Spreadsheet spreadsheet, String startCell, String endCell) {
        this.spreadsheet = spreadsheet;
        this.cellIds = expandRange(startCell, endCell);
        this.index = 0;
    }

    private List<String> expandRange(String start, String end) {
        List<String> cells = new ArrayList<>();
        String colStart = start.replaceAll("\\d", "");
        int rowStart = Integer.parseInt(start.replaceAll("[A-Z]", ""));
        String colEnd = end.replaceAll("\\d", "");
        int rowEnd = Integer.parseInt(end.replaceAll("[A-Z]", ""));
        for (char c = colStart.charAt(0); c <= colEnd.charAt(0); c++) {
            for (int r = rowStart; r <= rowEnd; r++) {
                cells.add(String.valueOf(c) + r);
            }
        }
        return cells;
    }

    @Override
    public boolean hasNext() { return index < cellIds.size(); }

    @Override
    public Cell next() {
        String id = cellIds.get(index++);
        return spreadsheet.getOrCreateCell(id);
    }
}

// Main.java — Demonstrates optimized spreadsheet with incremental recalculation
public class Main {
    public static void main(String[] args) {
        System.out.println("=== Spreadsheet Demo (Optimized) ===");
        System.out.println("Optimization: Topological sort-based incremental update\n");

        Spreadsheet sheet = new Spreadsheet();
        sheet.addObserver(new LoggingCellObserver());

        sheet.setCellValue("A1", 10.0);
        sheet.setCellValue("A2", 20.0);
        sheet.setCellValue("A3", 30.0);
        System.out.println("Set A1=10, A2=20, A3=30");

        sheet.setCellFormula("A4", "A1+A2");
        sheet.setCellFormula("A5", "SUM(A1:A3)");
        sheet.setCellFormula("A6", "A4+A5");
        System.out.println("A4=A1+A2, A5=SUM(A1:A3), A6=A4+A5");
        System.out.println("A4=" + sheet.getCellDisplayValue("A4"));
        System.out.println("A5=" + sheet.getCellDisplayValue("A5"));
        System.out.println("A6=" + sheet.getCellDisplayValue("A6"));

        System.out.println("\n--- Update A1=50 (only A4, A5, A6 recalc — not B1, C1, etc.) ---");
        sheet.setCellValue("A1", 50.0);
        System.out.println("A4=" + sheet.getCellDisplayValue("A4") + " (was 30)");
        System.out.println("A5=" + sheet.getCellDisplayValue("A5") + " (was 60)");
        System.out.println("A6=" + sheet.getCellDisplayValue("A6") + " (was 90)");

        System.out.println("\n--- Circular Dependency Detection ---");
        sheet.setCellFormula("C1", "C2+1");
        try {
            sheet.setCellFormula("C2", "C1+1");
        } catch (IllegalArgumentException e) {
            System.out.println("C2=C1+1 → " + e.getMessage());
        }

        System.out.println("\n=== Demo Complete ===");
    }
}

// command/CellCommand.java — Undoable command for cell value changes
public class CellCommand {                                // Command pattern = encapsulates cell change for undo/redo
    private Spreadsheet spreadsheet;
    private String cellId;
    private CellMemento previousState;                    // stores snapshot for O(1) undo restore
    private CellValue newValue;

    public CellCommand(Spreadsheet spreadsheet, String cellId, CellValue newValue) {
        this.spreadsheet = spreadsheet;
        this.cellId = cellId;
        this.newValue = newValue;
    }

    public void execute() {
        Cell cell = spreadsheet.getOrCreateCell(cellId);
        this.previousState = cell.saveState();
        spreadsheet.setCellValueInternal(cellId, newValue);
    }

    public void undo() {
        Cell cell = spreadsheet.getOrCreateCell(cellId);
        cell.restoreState(previousState);
        spreadsheet.recalculateDependents(cellId);
    }

    public void redo() {
        spreadsheet.setCellValueInternal(cellId, newValue);
    }

    public String getCellId() { return cellId; }
}

// model/Cell.java — Cell with cached computed value for incremental updates
public class Cell {
    private String id;
    private CellValue value;
    // cache the computed numeric value to avoid re-evaluation when nothing changed
    private double cachedNumeric;                         // avoids recomputing formula if deps unchanged
    private boolean dirty;                                // dirty flag = O(1) invalidation, lazy recompute on read

    public Cell(String id) {
        this.id = id;
        this.value = null;
        this.dirty = true;
    }

    public String getId() { return id; }
    public CellValue getValue() { return value; }

    public void setValue(CellValue value) {
        this.value = value;
        this.dirty = true;
    }

    public void markDirty() { this.dirty = true; }
    public boolean isDirty() { return dirty; }

    public double getNumericValue(Spreadsheet sheet) {
        if (value == null) return 0;
        if (dirty) {
            cachedNumeric = value.getNumericValue(sheet);
            dirty = false;
        }
        return cachedNumeric;
    }

    public String getDisplayValue(Spreadsheet sheet) {
        if (value == null) return "";
        return value.getDisplayValue(sheet);
    }

    public CellMemento saveState() {
        return new CellMemento(id, value != null ? value.copy() : null);
    }

    public void restoreState(CellMemento memento) {
        this.value = memento.getValue();
        this.dirty = true;
    }
}

// model/CellMemento.java — Snapshot of cell state for undo support
public class CellMemento {                                // Memento pattern = lightweight state snapshot
    private String cellId;
    private CellValue value;                              // deep-copied value enables independent restore

    public CellMemento(String cellId, CellValue value) {
        this.cellId = cellId;
        this.value = value;
    }

    public String getCellId() { return cellId; }
    public CellValue getValue() { return value; }
}

// model/CellValue.java — Abstract cell value (numeric, text, or formula)
public abstract class CellValue {                         // abstract = polymorphic base; Cell stores one of these
    public abstract double getNumericValue(Spreadsheet sheet);
    public abstract String getDisplayValue(Spreadsheet sheet);
    public abstract boolean isFormula();
    public abstract CellValue copy();                     // copy() enables snapshot for undo without aliasing

    public static class NumericValue extends CellValue {
        private double value;

        public NumericValue(double value) { this.value = value; }
        public double getValue() { return value; }

        @Override
        public double getNumericValue(Spreadsheet sheet) { return value; }
        @Override
        public String getDisplayValue(Spreadsheet sheet) { return String.valueOf(value); }
        @Override
        public boolean isFormula() { return false; }
        @Override
        public CellValue copy() { return new NumericValue(value); }
    }

    public static class TextValue extends CellValue {
        private String text;

        public TextValue(String text) { this.text = text; }
        public String getText() { return text; }

        @Override
        public double getNumericValue(Spreadsheet sheet) { return 0; }
        @Override
        public String getDisplayValue(Spreadsheet sheet) { return text; }
        @Override
        public boolean isFormula() { return false; }
        @Override
        public CellValue copy() { return new TextValue(text); }
    }
}

// model/Formula.java — Cell formula with references and evaluation logic
import java.util.ArrayList;
import java.util.List;
import java.util.regex.Matcher;
import java.util.regex.Pattern;

public class Formula extends CellValue {
    private String expression;
    private List<String> referencedCells;                 // pre-parsed refs; avoids re-parsing on each eval

    public Formula(String expression) {
        this.expression = expression;
        this.referencedCells = parseReferences(expression);
    }

    public String getExpression() { return expression; }
    public List<String> getReferencedCells() { return referencedCells; }

    @Override
    public boolean isFormula() { return true; }

    @Override
    public CellValue copy() { return new Formula(expression); }

    @Override
    public double getNumericValue(Spreadsheet sheet) {
        return evaluate(expression, sheet);
    }

    @Override
    public String getDisplayValue(Spreadsheet sheet) {
        return String.valueOf(getNumericValue(sheet));
    }

    private List<String> parseReferences(String expr) {
        List<String> refs = new ArrayList<>();
        Pattern rangePattern = Pattern.compile("([A-Z]+\\d+):([A-Z]+\\d+)");
        Matcher rangeMatcher = rangePattern.matcher(expr);
        while (rangeMatcher.find()) {
            refs.addAll(expandRange(rangeMatcher.group(1), rangeMatcher.group(2)));
        }

        String noRanges = expr.replaceAll("[A-Z]+\\d+:[A-Z]+\\d+", "");
        Pattern cellPattern = Pattern.compile("[A-Z]+\\d+");
        Matcher cellMatcher = cellPattern.matcher(noRanges);
        while (cellMatcher.find()) {
            String ref = cellMatcher.group();
            if (!refs.contains(ref)) refs.add(ref);
        }
        return refs;
    }

    private List<String> expandRange(String start, String end) {
        List<String> cells = new ArrayList<>();
        String colStart = start.replaceAll("\\d", "");
        int rowStart = Integer.parseInt(start.replaceAll("[A-Z]", ""));
        String colEnd = end.replaceAll("\\d", "");
        int rowEnd = Integer.parseInt(end.replaceAll("[A-Z]", ""));

        if (colStart.equals(colEnd)) {
            for (int r = rowStart; r <= rowEnd; r++) {
                cells.add(colStart + r);
            }
        } else if (rowStart == rowEnd) {
            for (char c = colStart.charAt(0); c <= colEnd.charAt(0); c++) {
                cells.add(String.valueOf(c) + rowStart);
            }
        }
        return cells;
    }

    private double evaluate(String expr, Spreadsheet sheet) {
        Pattern sumPattern = Pattern.compile("SUM\\(([A-Z]+\\d+):([A-Z]+\\d+)\\)");
        Matcher sumMatcher = sumPattern.matcher(expr);
        if (sumMatcher.find()) {
            List<String> cells = expandRange(sumMatcher.group(1), sumMatcher.group(2));
            double sum = 0;
            for (String ref : cells) {
                Cell cell = sheet.getCell(ref);
                sum += (cell != null) ? cell.getNumericValue(sheet) : 0;
            }
            return sum;
        }

        Pattern avgPattern = Pattern.compile("AVERAGE\\(([A-Z]+\\d+):([A-Z]+\\d+)\\)");
        Matcher avgMatcher = avgPattern.matcher(expr);
        if (avgMatcher.find()) {
            List<String> cells = expandRange(avgMatcher.group(1), avgMatcher.group(2));
            double sum = 0;
            for (String ref : cells) {
                Cell cell = sheet.getCell(ref);
                sum += (cell != null) ? cell.getNumericValue(sheet) : 0;
            }
            return cells.isEmpty() ? 0 : sum / cells.size();
        }

        String resolved = expr;
        List<String> sortedRefs = new ArrayList<>(referencedCells);
        sortedRefs.sort((a, b) -> b.length() - a.length());
        for (String ref : sortedRefs) {
            Cell cell = sheet.getCell(ref);
            double val = (cell != null) ? cell.getNumericValue(sheet) : 0;
            resolved = resolved.replace(ref, String.valueOf(val));
        }
        return evaluateArithmetic(resolved);
    }

    private double evaluateArithmetic(String expr) {
        expr = expr.trim();
        int parenDepth = 0;
        int lastPlusOrMinus = -1;
        for (int i = expr.length() - 1; i >= 0; i--) {
            char c = expr.charAt(i);
            if (c == ')') parenDepth++;
            else if (c == '(') parenDepth--;
            else if (parenDepth == 0 && (c == '+' || c == '-') && i > 0) {
                lastPlusOrMinus = i;
                break;
            }
        }
        if (lastPlusOrMinus > 0) {
            double left = evaluateArithmetic(expr.substring(0, lastPlusOrMinus));
            char op = expr.charAt(lastPlusOrMinus);
            double right = evaluateArithmetic(expr.substring(lastPlusOrMinus + 1));
            return op == '+' ? left + right : left - right;
        }

        parenDepth = 0;
        int lastMulOrDiv = -1;
        for (int i = expr.length() - 1; i >= 0; i--) {
            char c = expr.charAt(i);
            if (c == ')') parenDepth++;
            else if (c == '(') parenDepth--;
            else if (parenDepth == 0 && (c == '*' || c == '/')) {
                lastMulOrDiv = i;
                break;
            }
        }
        if (lastMulOrDiv > 0) {
            double left = evaluateArithmetic(expr.substring(0, lastMulOrDiv));
            char op = expr.charAt(lastMulOrDiv);
            double right = evaluateArithmetic(expr.substring(lastMulOrDiv + 1));
            return op == '*' ? left * right : left / right;
        }

        if (expr.startsWith("(") && expr.endsWith(")")) {
            return evaluateArithmetic(expr.substring(1, expr.length() - 1));
        }
        return Double.parseDouble(expr);
    }
}

// service/CellObserver.java — Observer contract for cell value changes
//
// Subscribers are notified after a cell's value is set (or recalculated as a
// dependent of another cell). Examples: a console logger, an audit trail, a
// UI re-renderer. The spreadsheet fires events; observers decide what to do.

interface CellObserver {
    /** Fired after cellId's display value changed from oldValue to newValue. */
    void onCellChanged(String cellId, String oldValue, String newValue);
}

// service/DependencyGraph.java — Dependency graph with topological sort for minimal recalculation
import java.util.*;

public class DependencyGraph {
    private Map<String, Set<String>> precedents;          // HashMap = O(1) lookup of what a cell depends on
    // reverse dependency graph lets us find exactly which cells need recalc
    private Map<String, Set<String>> dependents;          // HashSet per entry = O(1) add/remove of dependents

    public DependencyGraph() {
        this.precedents = new HashMap<>();
        this.dependents = new HashMap<>();
    }

    public void setDependencies(String cellId, List<String> deps) {
        clearDependencies(cellId);
        Set<String> depSet = new HashSet<>(deps);
        precedents.put(cellId, depSet);
        for (String dep : deps) {
            dependents.computeIfAbsent(dep, k -> new HashSet<>()).add(cellId);
        }
    }

    public void clearDependencies(String cellId) {
        Set<String> oldDeps = precedents.remove(cellId);
        if (oldDeps != null) {
            for (String dep : oldDeps) {
                Set<String> depSet = dependents.get(dep);
                if (depSet != null) {
                    depSet.remove(cellId);
                    if (depSet.isEmpty()) dependents.remove(dep);
                }
            }
        }
    }

    public Set<String> getDependents(String cellId) {
        return dependents.getOrDefault(cellId, Collections.emptySet());
    }

    // WHY: Topological sort ensures each cell is recalculated only ONCE in correct order
    // Only cells actually affected by the change are included
    public List<String> getTopologicalOrder(String changedCell) {
        // Kahn's algorithm on the affected subgraph
        Map<String, Integer> inDegree = new HashMap<>();
        Set<String> affected = new HashSet<>();
        Queue<String> bfs = new LinkedList<>();

        // Find all transitively affected cells
        bfs.add(changedCell);
        while (!bfs.isEmpty()) {
            String current = bfs.poll();
            for (String dep : getDependents(current)) {
                if (affected.add(dep)) {
                    bfs.add(dep);
                }
            }
        }

        // Calculate in-degrees for affected cells only
        for (String cell : affected) {
            int degree = 0;
            Set<String> precs = precedents.getOrDefault(cell, Collections.emptySet());
            for (String prec : precs) {
                if (affected.contains(prec) || prec.equals(changedCell)) {
                    degree++;
                }
            }
            inDegree.put(cell, degree);
        }

        // Start with cells whose only changed precedent is the changedCell
        Queue<String> ready = new LinkedList<>();
        for (String cell : affected) {
            Set<String> precs = precedents.getOrDefault(cell, Collections.emptySet());
            boolean allPrecsResolved = true;
            for (String prec : precs) {
                if (affected.contains(prec)) {
                    allPrecsResolved = false;
                    break;
                }
            }
            if (allPrecsResolved) ready.add(cell);
        }

        List<String> order = new ArrayList<>();
        Set<String> processed = new HashSet<>();
        while (!ready.isEmpty()) {
            String current = ready.poll();
            if (!processed.add(current)) continue;
            order.add(current);
            for (String dep : getDependents(current)) {
                if (affected.contains(dep) && !processed.contains(dep)) {
                    ready.add(dep);
                }
            }
        }

        // Add any remaining affected cells
        for (String cell : affected) {
            if (!processed.contains(cell)) order.add(cell);
        }

        return order;
    }

    public boolean hasCircularDependency(String cellId, List<String> newDeps) {
        Set<String> visited = new HashSet<>();
        visited.add(cellId);
        Queue<String> queue = new LinkedList<>(newDeps);
        while (!queue.isEmpty()) {
            String current = queue.poll();
            if (current.equals(cellId)) return true;
            if (visited.add(current)) {
                queue.addAll(precedents.getOrDefault(current, Collections.emptySet()));
            }
        }
        return false;
    }
}

