// service/Spreadsheet.java — Spreadsheet with incremental recalculation via topological sort
import java.util.*;

public class Spreadsheet {
    private Map<String, Cell> cells;                      // HashMap = O(1) cell access by ID
    private DependencyGraph dependencyGraph;              // tracks which cells to invalidate on change
    private Deque<CellCommand> undoStack;                 // ArrayDeque = faster than Stack for LIFO operations
    private Deque<CellCommand> redoStack;                 // ArrayDeque = no synchronization overhead vs Stack

    // Observer: fan-out for cell change events (value set, dependents recalculated).
    private final List<CellObserver> observers = new ArrayList<>();

    public Spreadsheet() {
        this.cells = new HashMap<>();
        this.dependencyGraph = new DependencyGraph();
        this.undoStack = new ArrayDeque<>();
        this.redoStack = new ArrayDeque<>();
    }

    // === Observer plumbing ===
    public void addObserver(CellObserver observer) { observers.add(observer); }
    public void removeObserver(CellObserver observer) { observers.remove(observer); }

    private void fireCellChanged(String cellId, String oldValue, String newValue) {
        for (CellObserver o : observers) o.onCellChanged(cellId, oldValue, newValue);
    }

    public Cell getCell(String id) { return cells.get(id); }

    public Cell getOrCreateCell(String id) {
        return cells.computeIfAbsent(id, Cell::new);
    }

    public void setCellValue(String cellId, double value) {
        CellValue cv = new CellValue.NumericValue(value);
        CellCommand cmd = new CellCommand(this, cellId, cv);
        cmd.execute();
        undoStack.push(cmd);
        redoStack.clear();
    }

    public void setCellText(String cellId, String text) {
        CellValue cv = new CellValue.TextValue(text);
        CellCommand cmd = new CellCommand(this, cellId, cv);
        cmd.execute();
        undoStack.push(cmd);
        redoStack.clear();
    }

    public void setCellFormula(String cellId, String expression) {
        Formula formula = new Formula(expression);
        List<String> refs = formula.getReferencedCells();
        if (dependencyGraph.hasCircularDependency(cellId, refs)) {
            throw new IllegalArgumentException("Circular dependency detected for " + cellId);
        }
        CellCommand cmd = new CellCommand(this, cellId, formula);
        cmd.execute();
        undoStack.push(cmd);
        redoStack.clear();
    }

    void setCellValueInternal(String cellId, CellValue value) {
        Cell cell = getOrCreateCell(cellId);
        String oldDisplay = cell.getDisplayValue(this);
        // Snapshot dependents' display values BEFORE recalculation so we can report old->new
        List<String> deps = dependencyGraph.getTopologicalOrder(cellId);
        Map<String, String> depOldValues = new HashMap<>();
        for (String dep : deps) {
            Cell c = cells.get(dep);
            if (c != null) depOldValues.put(dep, c.getDisplayValue(this));
        }
        cell.setValue(value);
        if (value instanceof Formula) {
            dependencyGraph.setDependencies(cellId, ((Formula) value).getReferencedCells());
        } else {
            dependencyGraph.clearDependencies(cellId);
        }
        recalculateDependents(cellId);
        String newDisplay = cell.getDisplayValue(this);
        fireCellChanged(cellId, oldDisplay, newDisplay);
        // Fire for dependents whose computed display changed
        for (String dep : deps) {
            Cell c = cells.get(dep);
            if (c == null) continue;
            String oldV = depOldValues.get(dep);
            String newV = c.getDisplayValue(this);
            if (!java.util.Objects.equals(oldV, newV)) {
                fireCellChanged(dep, oldV, newV);
            }
        }
    }

    // WHY: Only mark affected cells as dirty in topological order
    // Cells that aren't affected by this change keep their cached values
    void recalculateDependents(String cellId) {
        List<String> order = dependencyGraph.getTopologicalOrder(cellId);
        for (String dep : order) {
            Cell cell = cells.get(dep);
            if (cell != null) {
                cell.markDirty(); // Will re-evaluate lazily on next read
            }
        }
    }

    public double getCellNumericValue(String cellId) {
        Cell cell = cells.get(cellId);
        if (cell == null) return 0;
        return cell.getNumericValue(this);
    }

    public String getCellDisplayValue(String cellId) {
        Cell cell = cells.get(cellId);
        if (cell == null) return "";
        return cell.getDisplayValue(this);
    }

    public void undo() {
        if (!undoStack.isEmpty()) {
            CellCommand cmd = undoStack.pop();
            cmd.undo();
            redoStack.push(cmd);
        }
    }

    public void redo() {
        if (!redoStack.isEmpty()) {
            CellCommand cmd = redoStack.pop();
            cmd.redo();
            undoStack.push(cmd);
        }
    }

    public SpreadsheetIterator rangeIterator(String start, String end) {
        return new SpreadsheetIterator(this, start, end);
    }
}

// service/SpreadsheetIterator.java — Iterates over a cell range
import java.util.Iterator;
import java.util.List;
import java.util.ArrayList;

public class SpreadsheetIterator implements Iterator<Cell> { // implements Iterator = enables for-each traversal
    private Spreadsheet spreadsheet;
    private List<String> cellIds;                         // pre-expanded range; avoids re-computation per next()
    private int index;

    public SpreadsheetIterator(Spreadsheet spreadsheet, String startCell, String endCell) {
        this.spreadsheet = spreadsheet;
        this.cellIds = expandRange(startCell, endCell);
        this.index = 0;
    }

    private List<String> expandRange(String start, String end) {
        List<String> cells = new ArrayList<>();
        String colStart = start.replaceAll("\\d", "");
        int rowStart = Integer.parseInt(start.replaceAll("[A-Z]", ""));
        String colEnd = end.replaceAll("\\d", "");
        int rowEnd = Integer.parseInt(end.replaceAll("[A-Z]", ""));
        for (char c = colStart.charAt(0); c <= colEnd.charAt(0); c++) {
            for (int r = rowStart; r <= rowEnd; r++) {
                cells.add(String.valueOf(c) + r);
            }
        }
        return cells;
    }

    @Override
    public boolean hasNext() { return index < cellIds.size(); }

    @Override
    public Cell next() {
        String id = cellIds.get(index++);
        return spreadsheet.getOrCreateCell(id);
    }
}

// concurrent/Main.java — 10 threads editing interdependent cells simultaneously, verify formulas consistent

import java.util.concurrent.*;
import java.util.concurrent.atomic.AtomicBoolean;
import java.util.concurrent.atomic.AtomicInteger;

public class Main {
    public static void main(String[] args) throws InterruptedException {
        System.out.println("=== Concurrent Spreadsheet Demo ===\n");

        Spreadsheet sheet = new Spreadsheet();

        // Setup: A1..A10 are raw values, B1 = SUM(A1..A10)
        for (int i = 1; i <= 10; i++) {
            sheet.setCellValue("A" + i, 1.0);
        }
        String[] deps = new String[10];
        for (int i = 0; i < 10; i++) deps[i] = "A" + (i + 1);
        sheet.setCellFormula("B1", "SUM(A1:A10)", deps);

        int threadCount = 10;
        int opsPerThread = 200;
        CountDownLatch startLatch = new CountDownLatch(1);
        CountDownLatch doneLatch = new CountDownLatch(threadCount);
        AtomicBoolean errorFound = new AtomicBoolean(false);
        AtomicInteger totalEdits = new AtomicInteger(0);
        AtomicInteger staleRetries = new AtomicInteger(0);

        System.out.println("Scenario: 10 threads each edit A1..A10 (200 ops each)");
        System.out.println("  while B1 = SUM(A1:A10) is recalculated.");
        System.out.println("Expected: No torn reads, versions monotonically increase.\n");

        for (int t = 0; t < threadCount; t++) {
            final int threadId = t;
            new Thread(() -> {
                try {
                    startLatch.await();
                    for (int i = 0; i < opsPerThread; i++) {
                        String cellId = "A" + ((threadId % 10) + 1);
                        double newVal = threadId * 1000.0 + i;
                        long prevVersion = sheet.getCellVersion(cellId);

                        sheet.setCellValue(cellId, newVal);
                        totalEdits.incrementAndGet();

                        long newVersion = sheet.getCellVersion(cellId);
                        if (newVersion < prevVersion) {
                            errorFound.set(true); // version went backwards
                        }

                        // Recalculate B1
                        boolean success = sheet.recalculate("B1", deps);
                        if (!success) {
                            staleRetries.incrementAndGet();
                        }

                        // Read B1 — should never be NaN or negative
                        double b1 = sheet.getCellValue("B1");
                        if (Double.isNaN(b1) || Double.isInfinite(b1)) {
                            errorFound.set(true);
                        }
                    }
                } catch (Exception e) {
                    errorFound.set(true);
                    e.printStackTrace();
                } finally {
                    doneLatch.countDown();
                }
            }, "Editor-" + t).start();
        }

        startLatch.countDown();
        doneLatch.await();

        // Final recalculation
        sheet.recalculate("B1", deps);

        // Verify final state
        double sum = 0;
        for (int i = 1; i <= 10; i++) {
            sum += sheet.getCellValue("A" + i);
        }
        double b1Final = sheet.getCellValue("B1");
        boolean sumMatches = Math.abs(sum - b1Final) < 0.001;

        System.out.println("--- Results ---");
        System.out.println("Total edits: " + totalEdits.get());
        System.out.println("Stale-read retries: " + staleRetries.get());
        System.out.println("Final SUM(A1:A10) = " + sum);
        System.out.println("Final B1 = " + b1Final);
        System.out.println("Sum matches B1 (after final recalc): " + sumMatches);
        System.out.println("No version anomalies: " + !errorFound.get());

        boolean passed = !errorFound.get() && sumMatches;
        System.out.println("\nCorrectness check: " + (passed ? "PASSED" : "FAILED"));
    }
}

// concurrent/model/Cell.java — A spreadsheet cell with ReentrantReadWriteLock and version tracking

import java.util.concurrent.atomic.AtomicLong;
import java.util.concurrent.locks.ReentrantReadWriteLock;

public class Cell {
    private final String id;                              // final = immutable identity; safe to share across threads
    private volatile double value;                        // volatile = writes visible to all threads immediately
    private volatile String formula;                      // volatile = other threads see latest formula assignment
    private final AtomicLong version;                     // AtomicLong = lock-free monotonic version counter
    private final ReentrantReadWriteLock lock;            // RW lock = many readers OR one writer; maximizes concurrency

    public Cell(String id) {
        this.id = id;
        this.value = 0.0;
        this.formula = null;
        this.version = new AtomicLong(0);
        this.lock = new ReentrantReadWriteLock();
    }

    public String getId() { return id; }

    public double getValue() {
        lock.readLock().lock();
        try {
            return value;
        } finally {
            lock.readLock().unlock();
        }
    }

    public long getVersion() { return version.get(); }

    public String getFormula() {
        lock.readLock().lock();
        try {
            return formula;
        } finally {
            lock.readLock().unlock();
        }
    }

    public void setRawValue(double val) {
        lock.writeLock().lock();
        try {
            this.value = val;
            this.formula = null;
            this.version.incrementAndGet();
        } finally {
            lock.writeLock().unlock();
        }
    }

    public void setFormula(String formula, double computedValue) {
        lock.writeLock().lock();
        try {
            this.formula = formula;
            this.value = computedValue;
            this.version.incrementAndGet();
        } finally {
            lock.writeLock().unlock();
        }
    }

    public void updateComputedValue(double computedValue) {
        lock.writeLock().lock();
        try {
            this.value = computedValue;
            this.version.incrementAndGet();
        } finally {
            lock.writeLock().unlock();
        }
    }

    public ReentrantReadWriteLock getLock() { return lock; }
}

// concurrent/service/Spreadsheet.java — Thread-safe spreadsheet with per-cell locking and version checks

import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.atomic.AtomicLong;

public class Spreadsheet {
    private final ConcurrentHashMap<String, Cell> cells = new ConcurrentHashMap<>(); // ConcurrentHashMap = thread-safe map without global lock
    private final AtomicLong globalVersion = new AtomicLong(0); // AtomicLong = lock-free global change counter

    public Cell getOrCreateCell(String id) {
        return cells.computeIfAbsent(id, Cell::new);
    }

    public void setCellValue(String id, double value) {
        Cell cell = getOrCreateCell(id);
        cell.setRawValue(value);
        globalVersion.incrementAndGet();
    }

    public void setCellFormula(String id, String formula, String... dependencyIds) {
        Cell cell = getOrCreateCell(id);
        double computed = evaluateFormula(formula, dependencyIds);
        cell.setFormula(formula, computed);
        globalVersion.incrementAndGet();
    }

    public double getCellValue(String id) {
        Cell cell = cells.get(id);
        return cell == null ? 0.0 : cell.getValue();
    }

    public long getCellVersion(String id) {
        Cell cell = cells.get(id);
        return cell == null ? 0 : cell.getVersion();
    }

    /**
     * Recalculates a cell's formula using current dependency values.
     * Uses version checking to detect stale reads.
     */
    public boolean recalculate(String id, String... dependencyIds) {
        Cell cell = cells.get(id);
        if (cell == null || cell.getFormula() == null) return false;

        // Capture dependency versions before read
        long[] preVersions = new long[dependencyIds.length];
        double[] values = new double[dependencyIds.length];
        for (int i = 0; i < dependencyIds.length; i++) {
            Cell dep = cells.get(dependencyIds[i]);
            if (dep != null) {
                preVersions[i] = dep.getVersion();
                values[i] = dep.getValue();
            }
        }

        // Verify versions haven't changed (no stale reads)
        for (int i = 0; i < dependencyIds.length; i++) {
            Cell dep = cells.get(dependencyIds[i]);
            if (dep != null && dep.getVersion() != preVersions[i]) {
                return false; // Stale read detected, caller should retry
            }
        }

        // Compute sum of dependencies
        double sum = 0;
        for (double v : values) sum += v;

        cell.updateComputedValue(sum);
        return true;
    }

    private double evaluateFormula(String formula, String[] dependencyIds) {
        // Simple SUM formula
        double sum = 0;
        for (String depId : dependencyIds) {
            Cell dep = cells.get(depId);
            if (dep != null) sum += dep.getValue();
        }
        return sum;
    }

    public long getGlobalVersion() {
        return globalVersion.get();
    }

    public int getCellCount() {
        return cells.size();
    }
}

