        return group;
    }

    public Expense addExpense(String id, String description, double amount, User paidBy,
                              List<User> participants, SplitStrategy strategy, Map<User, Double> params) {
        Expense expense = new Expense(id, description, amount, paidBy, participants, strategy, params);
        expenseManager.addExpense(expense);
        return expense;
    }

    public Expense addGroupExpense(String groupId, String expenseId, String description,
                                    double amount, User paidBy, SplitStrategy strategy, Map<User, Double> params) {
        Group group = groups.get(groupId);
        if (group == null) throw new IllegalArgumentException("Group not found: " + groupId);
        Expense expense = new Expense(expenseId, description, amount, paidBy, group.getMembers(), strategy, params);
        group.addExpense(expense);
        expenseManager.addExpense(expense);
        return expense;
    }

    public List<Balance> getBalances() { return expenseManager.getBalances(users); }
    public List<Settlement> getSettlements() { return expenseManager.calculateSettlements(users); }
    public Map<String, User> getUsers() { return users; }
}

// strategy/SplitStrategy.java — Interchangeable expense split algorithms
// DESIGN PATTERN: Strategy
import java.util.HashMap;
import java.util.List;
import java.util.Map;

public interface SplitStrategy {                          // interface = swappable split algorithms (Strategy pattern)
    Map<User, Double> split(double totalAmount, List<User> participants, Map<User, Double> params);

    class EqualSplit implements SplitStrategy {
        @Override
        public Map<User, Double> split(double totalAmount, List<User> participants, Map<User, Double> params) {
            Map<User, Double> shares = new HashMap<>();
            double each = Math.round(totalAmount * 100.0 / participants.size()) / 100.0;
            for (User user : participants) {
                shares.put(user, each);
            }
            return shares;
        }
    }

    class PercentageSplit implements SplitStrategy {
        @Override
        public Map<User, Double> split(double totalAmount, List<User> participants, Map<User, Double> params) {
            double totalPercent = 0;
            for (Double pct : params.values()) totalPercent += pct;
            if (Math.abs(totalPercent - 100.0) > 0.01) {
                throw new IllegalArgumentException("Percentages must sum to 100, got " + totalPercent);
            }
            Map<User, Double> shares = new HashMap<>();
            for (User user : participants) {
                double pct = params.getOrDefault(user, 0.0);
                shares.put(user, Math.round(totalAmount * pct) / 100.0);
            }
            return shares;
        }
    }

    class ExactSplit implements SplitStrategy {
        @Override
        public Map<User, Double> split(double totalAmount, List<User> participants, Map<User, Double> params) {
            double totalShares = 0;
            for (Double amount : params.values()) totalShares += amount;
            if (Math.abs(totalShares - totalAmount) > 0.01) {
                throw new IllegalArgumentException(
                    "Exact amounts must sum to total. Expected " + totalAmount + ", got " + totalShares);
            }
            return new HashMap<>(params);
        }
    }
}

// concurrent/Main.java — 20 threads adding expenses among 5 users, verify net balances sum to zero

import java.util.*;
import java.util.concurrent.*;
import java.util.concurrent.atomic.AtomicInteger;

public class Main {
    public static void main(String[] args) throws InterruptedException {
        System.out.println("=== Concurrent Splitwise Demo ===\n");

        BalanceManager manager = new BalanceManager();
        String[] users = {"Alice", "Bob", "Charlie", "Diana", "Eve"};
        Set<String> userSet = new HashSet<>(Arrays.asList(users));

        int threadCount = 20;
        int expensesPerThread = 50;
        CountDownLatch startLatch = new CountDownLatch(1);
        CountDownLatch doneLatch = new CountDownLatch(threadCount);
        AtomicInteger totalExpenses = new AtomicInteger(0);

        System.out.println("Scenario: 20 threads add 50 expenses each among 5 users simultaneously.");
        System.out.println("Expected: Net balances across all users always sum to zero.\n");

        for (int t = 0; t < threadCount; t++) {
            final int threadId = t;
            new Thread(() -> {
                try {
                    startLatch.await();
                    Random random = new Random(threadId);
                    for (int i = 0; i < expensesPerThread; i++) {
                        String payer = users[random.nextInt(users.length)];
                        // Pick 2-5 participants (always including payer)
                        List<String> participants = new ArrayList<>();
                        participants.add(payer);
                        int numOthers = 1 + random.nextInt(4);
                        for (int j = 0; j < numOthers; j++) {
                            String other = users[random.nextInt(users.length)];
                            if (!participants.contains(other)) {
                                participants.add(other);
                            }
                        }
                        long amount = (random.nextInt(100) + 1) * 100L; // $1-$100 in cents
                        Expense expense = new Expense(payer, amount, participants);
                        manager.addExpense(expense);
                        totalExpenses.incrementAndGet();
                    }
                } catch (Exception e) {
                    e.printStackTrace();
                } finally {
                    doneLatch.countDown();
                }
            }, "Expenser-" + t).start();
        }

        startLatch.countDown();
        doneLatch.await();

        // Verify: sum of all net balances must be zero
        long totalNet = manager.totalNetBalance(userSet);

        System.out.println("--- Results ---");
        System.out.println("Total expenses added: " + totalExpenses.get());
        for (String user : users) {
            long net = manager.getNetBalance(user);
            String status = net > 0 ? "is owed" : net < 0 ? "owes" : "settled";
            System.out.printf("  %s: %+d cents (%s)%n", user, net, status);
        }
        System.out.println("Sum of all net balances: " + totalNet);

        boolean passed = totalNet == 0;
        System.out.println("\nCorrectness check: " + (passed ? "PASSED" : "FAILED"));
    }
}

// concurrent/model/Expense.java — Represents an expense with payer and participants

import java.util.List;

public class Expense {
    private final String payer;                           // final = immutable once created; safe to share across threads
    private final long amountCents;                       // final = use cents (long) to avoid floating-point races
    private final List<String> participants;              // final = participant list won't change after construction

    public Expense(String payer, long amountCents, List<String> participants) {
        this.payer = payer;
        this.amountCents = amountCents;
        this.participants = participants;
    }

    public String getPayer() { return payer; }
    public long getAmountCents() { return amountCents; }
    public List<String> getParticipants() { return participants; }
}

// concurrent/service/BalanceManager.java — AtomicLong per user-pair balance with CAS updates

import java.util.Map;
import java.util.Set;
import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.atomic.AtomicLong;

public class BalanceManager {
    // Key: "userA|userB" — alphabetically smaller user first
    // Value: positive = first owes second; negative = second owes first
    private final ConcurrentHashMap<String, AtomicLong> balances = new ConcurrentHashMap<>(); // ConcurrentHashMap + AtomicLong = lock-free per-pair updates

    private String pairKey(String u1, String u2) {
        return u1.compareTo(u2) < 0 ? u1 + "|" + u2 : u2 + "|" + u1;
    }

    /**
     * Records that 'debtor' owes 'creditor' the given amount (in cents).
     * Uses AtomicLong.addAndGet for lock-free update.
     */
    public void recordDebt(String debtor, String creditor, long amountCents) {
        if (debtor.equals(creditor)) return;
        String key = pairKey(debtor, creditor);
        AtomicLong balance = balances.computeIfAbsent(key, k -> new AtomicLong(0));

        // Convention: positive means first-alphabetical owes second-alphabetical
        if (debtor.compareTo(creditor) < 0) {
            balance.addAndGet(amountCents);
        } else {
            balance.addAndGet(-amountCents);
        }
    }

    public void addExpense(Expense expense) {
        String payer = expense.getPayer();
        long total = expense.getAmountCents();
        int numParticipants = expense.getParticipants().size();
        long share = total / numParticipants;

        for (String participant : expense.getParticipants()) {
            if (!participant.equals(payer)) {
                recordDebt(participant, payer, share);
            }
        }
    }

    /**
     * Returns net balance for a user (positive = others owe them, negative = they owe others).
     */
    public long getNetBalance(String user) {
        long net = 0;
        for (Map.Entry<String, AtomicLong> entry : balances.entrySet()) {
            String key = entry.getKey();
            String[] parts = key.split("\\|");
            long val = entry.getValue().get();
            if (parts[0].equals(user)) {
                net -= val; // user is first alphabetically, positive means they owe
            } else if (parts[1].equals(user)) {
                net += val; // user is second alphabetically, positive means first owes them
            }
        }
        return net;
    }

    /**
     * Sum of all net balances across all users should always be zero.
     */
    public long totalNetBalance(Set<String> users) {
        long total = 0;
        for (String user : users) {
            total += getNetBalance(user);
        }
        return total;
    }

    public Set<String> getPairKeys() {
        return balances.keySet();
    }
}

