// model/Bidder.java — Auction participant with notifications
import java.util.ArrayList;
import java.util.List;

public class Bidder {
    private String id;                                    // private = unique bidder identity
    private String name;                                  // private = display name
    private List<String> notifications;                   // private = Observer pattern: stores received messages

    public Bidder(String id, String name) {
        this.id = id; this.name = name; this.notifications = new ArrayList<>();
    }

    public String getId() { return id; }
    public String getName() { return name; }
