// service/Auction.java — Manages bidding with linear scan for highest bid
import java.util.ArrayList;
import java.util.Collections;
import java.util.List;

public class Auction {
    private String id;
    private Item item;
    private AuctionState state;                           // private = tracks lifecycle; controls valid operations
    private double startingBid;
    private double minIncrement;
    private List<Bid> bids;                               // private = full bid history
    private List<Bidder> watchers;                        // private = Observer pattern: notified on events
    private WinnerStrategy winnerStrategy;                // private = Strategy pattern: pluggable winner logic

    public Auction(String id, Item item, double startingBid, double minIncrement, WinnerStrategy strategy) {
        this.id = id; this.item = item; this.state = AuctionState.UPCOMING;
        this.startingBid = startingBid; this.minIncrement = minIncrement;
        this.bids = new ArrayList<>(); this.watchers = new ArrayList<>();
        this.winnerStrategy = strategy;
    }

    public void start() {
        if (state != AuctionState.UPCOMING) throw new IllegalStateException("Can only start UPCOMING auction");
        state = AuctionState.ACTIVE;
        notifyWatchers("Auction for " + item.getName() + " is now ACTIVE!");
    }

    public boolean placeBid(Bidder bidder, double amount) {
        if (state != AuctionState.ACTIVE) return false;
        // Naive: linear scan to find current highest
        double currentHighest = getCurrentHighestBid();
        double minRequired = currentHighest > 0 ? currentHighest + minIncrement : startingBid;
        if (amount < minRequired) return false;
        bids.add(new Bid(bidder, amount, false));
        addWatcher(bidder);
        return true;
    }

    // Naive: O(n) scan every time we need the highest bid
    public double getCurrentHighestBid() {
        double max = 0;
        for (Bid bid : bids) max = Math.max(max, bid.getAmount());
        return max;
    }

    public WinnerStrategy.WinnerResult close() {
        if (state != AuctionState.ACTIVE) throw new IllegalStateException("Can only close ACTIVE auction");
        state = AuctionState.CLOSED;
        WinnerStrategy.WinnerResult result = winnerStrategy.determineWinner(bids, item.getReservePrice());
        if (result != null) notifyWatchers("Winner: " + result.getWinner().getName());
        else notifyWatchers("Reserve not met. No winner.");
        return result;
    }

    private void notifyWatchers(String message) {
        for (Bidder w : watchers) w.notify(message);
    }

    public void addWatcher(Bidder bidder) { if (!watchers.contains(bidder)) watchers.add(bidder); }
    public String getId() { return id; }
    public Item getItem() { return item; }
    public AuctionState getState() { return state; }
    public List<Bid> getBids() { return Collections.unmodifiableList(bids); }
}

// service/AuctionSystem.java — Facade managing auctions and bidders
import java.util.*;

public class AuctionSystem {                              // Facade pattern = entry point for auction operations
    private Map<String, Auction> auctions;                // private = internal auction registry
    private Map<String, Bidder> bidders;                  // private = internal bidder registry

    public AuctionSystem() { this.auctions = new HashMap<>(); this.bidders = new HashMap<>(); }

    public Bidder registerBidder(String id, String name) {
        Bidder b = new Bidder(id, name); bidders.put(id, b); return b;
    }

    public Auction createAuction(String id, Item item, double startingBid, double minIncrement, WinnerStrategy strategy) {
        Auction a = new Auction(id, item, startingBid, minIncrement, strategy); auctions.put(id, a); return a;
    }

    public Auction getAuction(String id) { return auctions.get(id); }
}

// strategy/WinnerStrategy.java — Pluggable winner determination algorithms
// DESIGN PATTERN: Strategy
import java.util.List;

public interface WinnerStrategy {                         // interface = contract for pluggable winner algorithms
    WinnerResult determineWinner(List<Bid> bids, double reservePrice);

    class WinnerResult {
        private Bidder winner;
        private double winningPrice;
        private String description;

        public WinnerResult(Bidder winner, double winningPrice, String description) {
            this.winner = winner; this.winningPrice = winningPrice; this.description = description;
        }
        public Bidder getWinner() { return winner; }
        public double getWinningPrice() { return winningPrice; }
        public String getDescription() { return description; }
    }

    class HighestBidStrategy implements WinnerStrategy {   // implements = provides highest-bid-wins logic
        @Override
        public WinnerResult determineWinner(List<Bid> bids, double reservePrice) {
            if (bids.isEmpty()) return null;
            // Naive: linear scan through all bids to find highest
            Bid highest = bids.get(0);
            for (Bid bid : bids) {
                if (bid.getAmount() > highest.getAmount()) highest = bid;
            }
            if (highest.getAmount() < reservePrice) return null;
            return new WinnerResult(highest.getBidder(), highest.getAmount(),
                "Highest bid: $" + String.format("%.2f", highest.getAmount()));
        }
    }

    class SecondPriceStrategy implements WinnerStrategy {  // implements = Vickrey auction (pay 2nd price)
        @Override
        public WinnerResult determineWinner(List<Bid> bids, double reservePrice) {
            if (bids.isEmpty()) return null;
            if (bids.size() == 1) {
                Bid only = bids.get(0);
                if (only.getAmount() >= reservePrice)
                    return new WinnerResult(only.getBidder(), reservePrice, "Only bidder, pays reserve");
                return null;
            }
            Bid highest = null, secondHighest = null;
            for (Bid bid : bids) {
                if (highest == null || bid.getAmount() > highest.getAmount()) {
                    secondHighest = highest; highest = bid;
                } else if (secondHighest == null || bid.getAmount() > secondHighest.getAmount()) {
                    secondHighest = bid;
                }
            }
            if (highest.getAmount() < reservePrice) return null;
            double price = Math.max(secondHighest.getAmount(), reservePrice);
            return new WinnerResult(highest.getBidder(), price,
                "Winner pays second-highest: $" + String.format("%.2f", price));
        }
    }
}

