// service/MatchingEngine.java — Matches orders using O(n) scans
import java.util.ArrayList;
import java.util.List;

public class MatchingEngine {
    private int tradeCounter = 0;                         // private = generates unique trade IDs

    public List<Trade> match(Order incoming, OrderBook book) {
        List<Trade> trades = new ArrayList<>();
        if (incoming.getSide() == OrderSide.BUY) {
            while (incoming.getRemainingQuantity() > 0) {
                Order bestSell = book.getBestSell(); // O(n) scan each time
                if (bestSell == null || (!incoming.isMarketOrder() && bestSell.getPrice() > incoming.getPrice())) break;
                executeTrade(incoming, bestSell, bestSell.getPrice(), trades);
            }
        } else {
            while (incoming.getRemainingQuantity() > 0) {
                Order bestBuy = book.getBestBuy(); // O(n) scan each time
                if (bestBuy == null || (!incoming.isMarketOrder() && bestBuy.getPrice() < incoming.getPrice())) break;
                executeTrade(bestBuy, incoming, bestBuy.getPrice(), trades);
            }
        }
        book.removeFilledOrders();
        return trades;
    }

    private void executeTrade(Order buy, Order sell, double price, List<Trade> trades) {
        int qty = Math.min(buy.getRemainingQuantity(), sell.getRemainingQuantity());
        Trade trade = new Trade("T" + (++tradeCounter), buy.getStock(), buy.getTrader(), sell.getTrader(), price, qty);
        trades.add(trade);
        buy.fill(qty); sell.fill(qty);
        buy.getTrader().notify("Bought " + qty + " @ $" + String.format("%.2f", price));
        sell.getTrader().notify("Sold " + qty + " @ $" + String.format("%.2f", price));
    }
}

// service/OrderBook.java — Naive: unsorted lists requiring O(n) scan for best price
import java.util.*;

public class OrderBook {
    private Stock stock;
    // Naive: unsorted lists — finding best price requires O(n) scan
    private List<Order> buyOrders;                        // private = unsorted; O(n) scan for best buy
    private List<Order> sellOrders;                       // private = unsorted; O(n) scan for best sell

    public OrderBook(Stock stock) {
        this.stock = stock;
        this.buyOrders = new ArrayList<>();
        this.sellOrders = new ArrayList<>();
    }

    public void addOrder(Order order) {
        if (order.getSide() == OrderSide.BUY) buyOrders.add(order);
        else sellOrders.add(order);
    }

    // O(n) scan to find best buy (highest price)
    public Order getBestBuy() {
        Order best = null;
        for (Order o : buyOrders) {
            if (o.getRemainingQuantity() > 0 && (best == null || o.getPrice() > best.getPrice())) best = o;
        }
        return best;
    }

    // O(n) scan to find best sell (lowest price)
    public Order getBestSell() {
        Order best = null;
        for (Order o : sellOrders) {
            if (o.getRemainingQuantity() > 0 && (best == null || o.getPrice() < best.getPrice())) best = o;
        }
        return best;
    }

    public void removeFilledOrders() {
        buyOrders.removeIf(o -> o.getStatus() == OrderStatus.FILLED || o.getStatus() == OrderStatus.CANCELLED);
        sellOrders.removeIf(o -> o.getStatus() == OrderStatus.FILLED || o.getStatus() == OrderStatus.CANCELLED);
    }

    public Stock getStock() { return stock; }
    public List<Order> getBuyOrders() { return buyOrders; }
    public List<Order> getSellOrders() { return sellOrders; }
}

// service/StockExchange.java — Exchange facade
import java.util.*;

public class StockExchange {                              // Facade pattern = single entry point for exchange ops
    private Map<String, OrderBook> orderBooks;            // private = one order book per stock symbol
    private Map<String, Trader> traders;                  // private = registered traders
    private List<Trade> tradeHistory;                     // private = all executed trades
    private MatchingEngine matchingEngine;                // private = delegates order matching logic
    private int orderCounter = 0;

    public StockExchange() {
        this.orderBooks = new HashMap<>(); this.traders = new HashMap<>();
        this.tradeHistory = new ArrayList<>(); this.matchingEngine = new MatchingEngine();
    }

    public void registerStock(Stock stock) { orderBooks.put(stock.getSymbol(), new OrderBook(stock)); }
    public Trader registerTrader(String id, String name) { Trader t = new Trader(id, name); traders.put(id, t); return t; }

    public Order placeLimitOrder(Trader trader, Stock stock, OrderSide side, int qty, double price) {
        Order order = new LimitOrder("O" + (++orderCounter), trader, stock, side, qty, price);
        return processOrder(order);
    }

    public Order placeMarketOrder(Trader trader, Stock stock, OrderSide side, int qty) {
        Order order = new MarketOrder("O" + (++orderCounter), trader, stock, side, qty);
        return processOrder(order);
    }

    private Order processOrder(Order order) {
        OrderBook book = orderBooks.get(order.getStock().getSymbol());
        List<Trade> trades = matchingEngine.match(order, book);
        tradeHistory.addAll(trades);
        if (order.getRemainingQuantity() > 0 && !order.isMarketOrder()) book.addOrder(order);
        return order;
    }

    public List<Trade> getTradeHistory() { return tradeHistory; }
}

