// service/MatchingEngine.java — O(log n) matching with TreeMap price levels
import java.util.ArrayList;
import java.util.List;

public class MatchingEngine {
    private int tradeCounter = 0;                         // simple counter; single-threaded matching

    public List<Trade> match(Order incoming, OrderBook book) {
        List<Trade> trades = new ArrayList<>();
        if (incoming.getSide() == OrderSide.BUY) {
            // WHY: getBestSell is O(1) from TreeMap first entry
            while (incoming.getRemainingQuantity() > 0) {
                Order bestSell = book.getBestSell();
                if (bestSell == null || (!incoming.isMarketOrder() && bestSell.getPrice() > incoming.getPrice())) break;
                executeTrade(incoming, bestSell, bestSell.getPrice(), trades, book);
            }
        } else {
            while (incoming.getRemainingQuantity() > 0) {
                Order bestBuy = book.getBestBuy();
                if (bestBuy == null || (!incoming.isMarketOrder() && bestBuy.getPrice() < incoming.getPrice())) break;
                executeTrade(bestBuy, incoming, bestBuy.getPrice(), trades, book);
            }
        }
        return trades;
    }

    private void executeTrade(Order buy, Order sell, double price, List<Trade> trades, OrderBook book) {
        int qty = Math.min(buy.getRemainingQuantity(), sell.getRemainingQuantity());
        Trade trade = new Trade("T" + (++tradeCounter), buy.getStock(), buy.getTrader(), sell.getTrader(), price, qty);
        trades.add(trade);
        buy.fill(qty); sell.fill(qty);
        buy.getTrader().notify("Bought " + qty + " @ $" + String.format("%.2f", price));
        sell.getTrader().notify("Sold " + qty + " @ $" + String.format("%.2f", price));
        // Clean up filled orders from the book
        if (buy.getStatus() == OrderStatus.FILLED) book.removeFilled(buy);
        if (sell.getStatus() == OrderStatus.FILLED) book.removeFilled(sell);
    }
}

// service/OrderBook.java — TreeMap-based order book for O(log n) best-price access
import java.util.*;

public class OrderBook {
    private Stock stock;
    // TreeMap keeps orders sorted by price: O(log n) insert, O(1) best price
    // Buy side: descending price (highest first) for price-time priority
    private TreeMap<Double, Queue<Order>> buyLevels;      // TreeMap = sorted by price; firstEntry() gives best bid
    // Sell side: ascending price (lowest first) for price-time priority
    private TreeMap<Double, Queue<Order>> sellLevels;     // TreeMap = sorted naturally; firstEntry() gives best ask

    public OrderBook(Stock stock) {
        this.stock = stock;
        this.buyLevels = new TreeMap<>(Collections.reverseOrder()); // highest first
        this.sellLevels = new TreeMap<>(); // lowest first
    }

    public void addOrder(Order order) {
        TreeMap<Double, Queue<Order>> levels = order.getSide() == OrderSide.BUY ? buyLevels : sellLevels;
        levels.computeIfAbsent(order.getPrice(), k -> new LinkedList<>()).add(order);
    }

    // O(1): first entry of sorted map
    public Order getBestBuy() {
        while (!buyLevels.isEmpty()) {
            Queue<Order> queue = buyLevels.firstEntry().getValue();
            while (!queue.isEmpty()) {
                Order o = queue.peek();
                if (o.getRemainingQuantity() > 0) return o;
                queue.poll(); // remove filled
            }
            buyLevels.pollFirstEntry(); // remove empty price level
        }
        return null;
    }

    // O(1): first entry of sorted map
    public Order getBestSell() {
        while (!sellLevels.isEmpty()) {
            Queue<Order> queue = sellLevels.firstEntry().getValue();
            while (!queue.isEmpty()) {
                Order o = queue.peek();
                if (o.getRemainingQuantity() > 0) return o;
                queue.poll();
            }
            sellLevels.pollFirstEntry();
        }
        return null;
    }

    public void removeFilled(Order order) {
        TreeMap<Double, Queue<Order>> levels = order.getSide() == OrderSide.BUY ? buyLevels : sellLevels;
        Queue<Order> queue = levels.get(order.getPrice());
        if (queue != null) {
            queue.remove(order);
            if (queue.isEmpty()) levels.remove(order.getPrice());
        }
    }

    public Stock getStock() { return stock; }
}

