// concurrent/Main.java — 100 traders submitting orders simultaneously, verifies all trades are consistent

import java.util.*;
import java.util.concurrent.CountDownLatch;
import java.util.concurrent.atomic.AtomicInteger;

public class Main {
    public static void main(String[] args) throws InterruptedException {
        System.out.println("=== Concurrent Stock Exchange Demo ===\n");

        MatchingEngine engine = new MatchingEngine();

        int traderCount = 100;
        CountDownLatch startLatch = new CountDownLatch(1);
        CountDownLatch doneLatch = new CountDownLatch(traderCount);
        AtomicInteger totalTradesMade = new AtomicInteger(0);

        System.out.println("Scenario: 100 traders submit orders simultaneously for AAPL.");
        System.out.println("  50 buyers at prices $148-$152");
        System.out.println("  50 sellers at prices $149-$153");
        System.out.println("Expected: Matching orders execute, no quantity appears from nowhere.\n");

        // 50 buyers, 50 sellers
        for (int i = 0; i < traderCount; i++) {
            final int id = i;
            new Thread(() -> {
                try {
                    startLatch.await();
                    Order order;
                    if (id < 50) {
                        // Buyers: prices from 148 to 152
                        double price = 148.0 + (id % 5);
                        order = new Order("Buyer-" + id, "AAPL", OrderSide.BUY, price, 10);
                    } else {
                        // Sellers: prices from 149 to 153
                        double price = 149.0 + ((id - 50) % 5);
                        order = new Order("Seller-" + id, "AAPL", OrderSide.SELL, price, 10);
                    }
                    List<Trade> trades = engine.submitOrder(order);
                    totalTradesMade.addAndGet(trades.size());
                } catch (InterruptedException e) {
                    Thread.currentThread().interrupt();
                } finally {
                    doneLatch.countDown();
                }
            }, "Trader-" + id).start();
        }

        startLatch.countDown();
        doneLatch.await();

        // Print results
        List<Trade> allTrades = engine.getAllTrades();
        System.out.println("Trades executed (first 10):");
        int shown = 0;
        for (Trade trade : allTrades) {
            if (shown++ >= 10) break;
            System.out.println("  " + trade);
        }
        if (allTrades.size() > 10) {
            System.out.println("  ... and " + (allTrades.size() - 10) + " more");
        }

        // Verify consistency: total bought quantity == total sold quantity
        long totalBought = 0;
        long totalSold = 0;
        for (Trade trade : allTrades) {
            totalBought += trade.getQuantity();
            totalSold += trade.getQuantity();
        }

        // Verify no negative quantities
        boolean noNegatives = allTrades.stream()
                .allMatch(t -> t.getQuantity() > 0);

        // Verify prices are valid (buy price >= sell price for matching)
        boolean validPrices = allTrades.stream()
                .allMatch(t -> t.getBuyOrder().getPrice() >= t.getSellOrder().getPrice());

        System.out.println("\n--- Summary ---");
        System.out.println("Orders submitted: " + engine.getOrdersProcessed());
        System.out.println("Trades executed: " + engine.getTradesExecuted());
        System.out.println("Total volume traded: " + totalBought + " shares");
        System.out.println("All quantities positive: " + noNegatives);
        System.out.println("All prices valid (buy >= sell): " + validPrices);
        System.out.println("\nCorrectness check: " +
                (noNegatives && validPrices ? "PASSED" : "FAILED"));
    }
}

// concurrent/model/Order.java — Order with atomic state management for concurrent matching

import java.util.concurrent.atomic.AtomicInteger;
import java.util.concurrent.atomic.AtomicReference;

enum OrderSide { BUY, SELL }
enum OrderStatus { PENDING, PARTIAL, FILLED, CANCELLED }

class Order {
    private static final AtomicInteger counter = new AtomicInteger(0); // static AtomicInteger = thread-safe global ID generator
    private final String orderId;                         // final = immutable after construction; safe publication
    private final String traderId;                        // final = never changes; no synchronization needed
    private final String symbol;                          // final = immutable; shared safely across threads
    private final OrderSide side;                         // final = direction fixed at creation
    private final double price;                           // final = limit price never changes
    private final int originalQuantity;                   // final = initial qty for reference
    private final AtomicInteger remainingQuantity;        // AtomicInteger = CAS-based partial fill without locks
    private final AtomicReference<OrderStatus> status;    // AtomicReference = lock-free status transitions
    private final long timestamp;                         // final = creation time for price-time priority

    public Order(String traderId, String symbol, OrderSide side, double price, int quantity) {
        this.orderId = "ORD-" + counter.incrementAndGet();
        this.traderId = traderId;
        this.symbol = symbol;
        this.side = side;
        this.price = price;
        this.originalQuantity = quantity;
        this.remainingQuantity = new AtomicInteger(quantity);
        this.status = new AtomicReference<>(OrderStatus.PENDING);
        this.timestamp = System.nanoTime();
    }

    /**
     * Atomically reduce quantity. Returns actual amount filled.
     * Handles partial fills correctly under concurrency.
     */
    public int fill(int quantity) {
        while (true) {
            int current = remainingQuantity.get();
            if (current <= 0) return 0;
            int toFill = Math.min(quantity, current);
            if (remainingQuantity.compareAndSet(current, current - toFill)) {
                if (current - toFill == 0) {
                    status.set(OrderStatus.FILLED);
                } else {
                    status.set(OrderStatus.PARTIAL);
                }
                return toFill;
            }
            // CAS failed — another thread filled some quantity, retry
        }
    }

    public String getOrderId() { return orderId; }
    public String getTraderId() { return traderId; }
    public String getSymbol() { return symbol; }
    public OrderSide getSide() { return side; }
    public double getPrice() { return price; }
    public int getOriginalQuantity() { return originalQuantity; }
    public int getRemainingQuantity() { return remainingQuantity.get(); }
    public OrderStatus getStatus() { return status.get(); }
    public long getTimestamp() { return timestamp; }

    public boolean isFilled() { return status.get() == OrderStatus.FILLED; }

    @Override
    public String toString() {
        return orderId + " [" + side + " " + symbol + " " + remainingQuantity.get() + "@" + price + " " + status.get() + "]";
    }

    public static void resetCounter() { counter.set(0); }
}

// concurrent/model/Trade.java — Executed trade record

import java.util.concurrent.atomic.AtomicInteger;

class Trade {
    private static final AtomicInteger counter = new AtomicInteger(0); // static AtomicInteger = thread-safe unique trade IDs
    private final String tradeId;                         // final = immutable; safe to read from any thread
    private final Order buyOrder;                         // final = reference won't change after creation
    private final Order sellOrder;                        // final = reference won't change after creation
    private final double price;                           // final = execution price is permanent record
    private final int quantity;                           // final = filled quantity is permanent record
    private final long timestamp;                         // final = when the trade occurred

    public Trade(Order buyOrder, Order sellOrder, double price, int quantity) {
        this.tradeId = "TRD-" + counter.incrementAndGet();
        this.buyOrder = buyOrder;
        this.sellOrder = sellOrder;
        this.price = price;
        this.quantity = quantity;
        this.timestamp = System.currentTimeMillis();
    }

    public String getTradeId() { return tradeId; }
    public Order getBuyOrder() { return buyOrder; }
    public Order getSellOrder() { return sellOrder; }
    public double getPrice() { return price; }
    public int getQuantity() { return quantity; }
    public long getTimestamp() { return timestamp; }

    @Override
    public String toString() {
        return tradeId + " [" + buyOrder.getTraderId() + " bought " + quantity +
               " from " + sellOrder.getTraderId() + " @" + price + "]";
    }

    public static void resetCounter() { counter.set(0); }
}

// concurrent/service/ConcurrentOrderBook.java — ConcurrentSkipListMap for price levels, ReentrantLock per price level

import java.util.*;
import java.util.concurrent.ConcurrentSkipListMap;
import java.util.concurrent.ConcurrentLinkedQueue;
import java.util.concurrent.locks.ReentrantLock;

/**
 * Thread-safe order book using ConcurrentSkipListMap for ordered price levels.
 * Buy side: descending (highest price first — best bid)
 * Sell side: ascending (lowest price first — best ask)
 */
class ConcurrentOrderBook {
    private final String symbol;                          // final = immutable; safe to share across threads
    // Buy orders: highest price first (reverse order)
    private final ConcurrentSkipListMap<Double, ConcurrentLinkedQueue<Order>> buyLevels = // ConcurrentSkipListMap = thread-safe sorted map; O(log n) insert
            new ConcurrentSkipListMap<>(Comparator.reverseOrder());
    // Sell orders: lowest price first (natural order)
    private final ConcurrentSkipListMap<Double, ConcurrentLinkedQueue<Order>> sellLevels = // ConcurrentSkipListMap = lock-free reads; sorted by price
            new ConcurrentSkipListMap<>();
    private final ReentrantLock matchLock = new ReentrantLock(); // ReentrantLock = serializes matching for one symbol; explicit control

    public ConcurrentOrderBook(String symbol) {
        this.symbol = symbol;
    }

    public void addOrder(Order order) {
        ConcurrentSkipListMap<Double, ConcurrentLinkedQueue<Order>> levels =
                (order.getSide() == OrderSide.BUY) ? buyLevels : sellLevels;
        levels.computeIfAbsent(order.getPrice(), k -> new ConcurrentLinkedQueue<>()).offer(order);
    }

    public ConcurrentSkipListMap<Double, ConcurrentLinkedQueue<Order>> getBuyLevels() { return buyLevels; }
    public ConcurrentSkipListMap<Double, ConcurrentLinkedQueue<Order>> getSellLevels() { return sellLevels; }
    public String getSymbol() { return symbol; }
    public ReentrantLock getMatchLock() { return matchLock; }

    public Order getBestBid() {
        Map.Entry<Double, ConcurrentLinkedQueue<Order>> entry = buyLevels.firstEntry();
        if (entry == null) return null;
        return entry.getValue().peek();
    }

    public Order getBestAsk() {
        Map.Entry<Double, ConcurrentLinkedQueue<Order>> entry = sellLevels.firstEntry();
        if (entry == null) return null;
        return entry.getValue().peek();
    }
}

// concurrent/service/MatchingEngine.java — Atomic matching with proper locking

import java.util.*;
import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.ConcurrentLinkedQueue;
import java.util.concurrent.CopyOnWriteArrayList;
import java.util.concurrent.atomic.AtomicInteger;

/**
 * Matching engine that processes orders and matches them atomically.
 * Uses per-orderbook locking to allow parallel matching across different symbols.
 */
class MatchingEngine {
    private final ConcurrentHashMap<String, ConcurrentOrderBook> orderBooks = new ConcurrentHashMap<>(); // ConcurrentHashMap = one order book per symbol; thread-safe registry
    private final CopyOnWriteArrayList<Trade> trades = new CopyOnWriteArrayList<>(); // CopyOnWriteArrayList = safe iteration; writes copy the array
    private final AtomicInteger ordersProcessed = new AtomicInteger(0); // AtomicInteger = lock-free counter
    private final AtomicInteger tradesExecuted = new AtomicInteger(0);  // AtomicInteger = lock-free counter

    public ConcurrentOrderBook getOrCreateOrderBook(String symbol) {
        return orderBooks.computeIfAbsent(symbol, ConcurrentOrderBook::new);
    }

    /**
     * Submit an order and attempt to match it.
     * Lock is per-order-book, so different symbols can match in parallel.
     */
    public List<Trade> submitOrder(Order order) {
        ordersProcessed.incrementAndGet();
        ConcurrentOrderBook book = getOrCreateOrderBook(order.getSymbol());
        List<Trade> newTrades = new ArrayList<>();

        book.getMatchLock().lock();
        try {
            if (order.getSide() == OrderSide.BUY) {
                matchBuyOrder(order, book, newTrades);
            } else {
                matchSellOrder(order, book, newTrades);
            }

            // If order still has remaining quantity, add to book
            if (order.getRemainingQuantity() > 0) {
                book.addOrder(order);
            }
        } finally {
            book.getMatchLock().unlock();
        }

        trades.addAll(newTrades);
        tradesExecuted.addAndGet(newTrades.size());
        return newTrades;
    }

    private void matchBuyOrder(Order buyOrder, ConcurrentOrderBook book, List<Trade> newTrades) {
        var sellLevels = book.getSellLevels();

        while (buyOrder.getRemainingQuantity() > 0 && !sellLevels.isEmpty()) {
            Map.Entry<Double, ConcurrentLinkedQueue<Order>> bestAsk = sellLevels.firstEntry();
            if (bestAsk == null || bestAsk.getKey() > buyOrder.getPrice()) break;

            ConcurrentLinkedQueue<Order> queue = bestAsk.getValue();
            Order sellOrder = queue.peek();
            if (sellOrder == null) {
                sellLevels.remove(bestAsk.getKey());
                continue;
            }

            int fillQty = Math.min(buyOrder.getRemainingQuantity(), sellOrder.getRemainingQuantity());
            buyOrder.fill(fillQty);
            sellOrder.fill(fillQty);

            newTrades.add(new Trade(buyOrder, sellOrder, bestAsk.getKey(), fillQty));

            if (sellOrder.isFilled()) {
                queue.poll();
                if (queue.isEmpty()) {
                    sellLevels.remove(bestAsk.getKey());
                }
            }
        }
    }

    private void matchSellOrder(Order sellOrder, ConcurrentOrderBook book, List<Trade> newTrades) {
        var buyLevels = book.getBuyLevels();

        while (sellOrder.getRemainingQuantity() > 0 && !buyLevels.isEmpty()) {
            Map.Entry<Double, ConcurrentLinkedQueue<Order>> bestBid = buyLevels.firstEntry();
            if (bestBid == null || bestBid.getKey() < sellOrder.getPrice()) break;

            ConcurrentLinkedQueue<Order> queue = bestBid.getValue();
            Order buyOrder = queue.peek();
            if (buyOrder == null) {
                buyLevels.remove(bestBid.getKey());
                continue;
            }

            int fillQty = Math.min(sellOrder.getRemainingQuantity(), buyOrder.getRemainingQuantity());
            sellOrder.fill(fillQty);
            buyOrder.fill(fillQty);

            newTrades.add(new Trade(buyOrder, sellOrder, bestBid.getKey(), fillQty));

            if (buyOrder.isFilled()) {
                queue.poll();
                if (queue.isEmpty()) {
                    buyLevels.remove(bestBid.getKey());
                }
            }
        }
    }

    public List<Trade> getAllTrades() { return new ArrayList<>(trades); }
    public int getOrdersProcessed() { return ordersProcessed.get(); }
    public int getTradesExecuted() { return tradesExecuted.get(); }
}

