// Main.java — Demonstrates payment gateway with sequential validation
public class Main {
    public static void main(String[] args) {
        System.out.println("=== Payment Gateway Demo (Naive) ===\n");

        PaymentGateway gateway = new PaymentGateway();
        gateway.registerProcessor("STRIPE", new PaymentProcessor.StripeProcessor());
        gateway.registerProcessor("PAYPAL", new PaymentProcessor.PayPalProcessor());

        System.out.println("--- Processing Payments ---");
        gateway.processPayment(new PaymentRequest("key-001", 99.99, "USD", "4111111111111111", "STRIPE", "Purchase #1"));
        gateway.processPayment(new PaymentRequest("key-002", 250.00, "USD", "4222222222222222", "PAYPAL", "Subscription"));

        System.out.println("\n--- Validation Failure ---");
        gateway.processPayment(new PaymentRequest("key-003", -50.00, "USD", "4111111111111111", "STRIPE", "Bad amount"));

        System.out.println("\n--- Idempotency ---");
        gateway.processPayment(new PaymentRequest("key-001", 99.99, "USD", "4111111111111111", "STRIPE", "Purchase #1"));

        System.out.println("\n--- All Transactions ---");
        for (Transaction t : gateway.getAllTransactions()) System.out.println("  " + t);

        System.out.println("\n=== Demo Complete ===");
    }
}

// model/PaymentRequest.java — Payment initiation data
public class PaymentRequest {
    private String idempotencyKey;   // private = only this class can read/write; hides internals
    private double amount;           // private = external code must use getters to access
    private String currency;
    private String cardNumber;
    private String processorType;
    private String description;

    public PaymentRequest(String idempotencyKey, double amount, String currency,
                          String cardNumber, String processorType, String description) {
        this.idempotencyKey = idempotencyKey; this.amount = amount; this.currency = currency;
        this.cardNumber = cardNumber; this.processorType = processorType; this.description = description;
    }

    public String getIdempotencyKey() { return idempotencyKey; }
    public double getAmount() { return amount; }
    public String getCurrency() { return currency; }
    public String getCardNumber() { return cardNumber; }
    public String getProcessorType() { return processorType; }
    public String getDescription() { return description; }
}

// model/Transaction.java — Payment transaction record
public class Transaction {
    private String id;                   // private = encapsulated; only exposed via getId()
    private double amount;
    private String currency;
    private String processorType;
    private TransactionStatus status;    // private = mutable state hidden; changed via setStatus()
    private String description;
    private String failureReason;
    private double refundedAmount;

    public Transaction(String id, double amount, String currency, String processorType, String description) {
        this.id = id; this.amount = amount; this.currency = currency;
        this.processorType = processorType; this.status = TransactionStatus.PENDING;
        this.description = description; this.refundedAmount = 0;
    }

    public String getId() { return id; }
    public double getAmount() { return amount; }
    public String getProcessorType() { return processorType; }
    public TransactionStatus getStatus() { return status; }
    public String getDescription() { return description; }
    public double getRefundedAmount() { return refundedAmount; }
    public void setStatus(TransactionStatus status) { this.status = status; }
    public void setFailureReason(String reason) { this.failureReason = reason; }
    public void addRefund(double amount) {
        this.refundedAmount += amount;
        if (this.refundedAmount >= this.amount) this.status = TransactionStatus.REFUNDED;
    }
    @Override public String toString() { return String.format("[%s] $%.2f %s -> %s", id, amount, processorType, status); }
}

// service/PaymentGateway.java — Sequential validation and processing
import java.util.*;

public class PaymentGateway {
    private Map<String, PaymentProcessor> processors;    // private = internal registry hidden from callers
    private ValidationChain validationChain;
    private Map<String, Transaction> transactions;
    private Set<String> processedKeys;                   // Set = no duplicates; used for idempotency
    private int txnCounter = 0;

    public PaymentGateway() {
        this.processors = new HashMap<>();
        this.validationChain = new ValidationChain();
        this.transactions = new LinkedHashMap<>();
        this.processedKeys = new HashSet<>();
        validationChain.addValidator(new ValidationChain.AmountValidator());
        validationChain.addValidator(new ValidationChain.CardValidator());
    }

    public void registerProcessor(String type, PaymentProcessor processor) {
        processors.put(type, processor);
    }

    // Naive: sequential validation, HashSet for idempotency (not concurrent-safe)
    public Transaction processPayment(PaymentRequest request) {
        if (processedKeys.contains(request.getIdempotencyKey())) {
            System.out.println("  Duplicate request (idempotency key: " + request.getIdempotencyKey() + ")");
            return null;
        }
        if (!validationChain.validate(request)) return null;

        PaymentProcessor processor = processors.get(request.getProcessorType());
        if (processor == null) { System.out.println("  No processor for: " + request.getProcessorType()); return null; }

        String txnId = "TXN-" + String.format("%03d", ++txnCounter);
        Transaction txn = new Transaction(txnId, request.getAmount(), request.getCurrency(), request.getProcessorType(), request.getDescription());

        boolean success = processor.processPayment(request);
        txn.setStatus(success ? TransactionStatus.SUCCESS : TransactionStatus.FAILED);
        transactions.put(txnId, txn);
        processedKeys.add(request.getIdempotencyKey());
        System.out.println("  " + txn);
        return txn;
    }

    public Collection<Transaction> getAllTransactions() { return transactions.values(); }
}

// service/ValidationChain.java — Sequential validation pipeline
import java.util.ArrayList;
import java.util.List;

public class ValidationChain {
    public interface Validator {              // interface = contract; any validator must implement these
        boolean validate(PaymentRequest request);
        String getName();
    }

    private List<Validator> validators;
    public ValidationChain() { this.validators = new ArrayList<>(); }
    public void addValidator(Validator v) { validators.add(v); }

    // Naive: validators run sequentially, one after another
    public boolean validate(PaymentRequest request) {
        for (Validator v : validators) {
            System.out.println("  Validating: " + v.getName() + "...");
            if (!v.validate(request)) {
                System.out.println("  FAILED: " + v.getName());
                return false;
            }
        }
        return true;
    }

    public static class AmountValidator implements Validator { // static = no reference to outer class; implements = fulfills Validator contract
        @Override public boolean validate(PaymentRequest req) { return req.getAmount() > 0 && req.getAmount() <= 100000; } // @Override = must match interface method
        @Override public String getName() { return "Amount check"; }
    }

