// concurrent/Main.java — Same payment submitted 10 times concurrently, exactly 1 processed

import java.util.concurrent.*;
import java.util.concurrent.atomic.AtomicInteger;

public class Main {
    public static void main(String[] args) throws InterruptedException {
        System.out.println("=== Concurrent Payment Gateway Demo ===\n");

        PaymentGateway gateway = new PaymentGateway();
        int duplicateSubmissions = 10;
        CountDownLatch startLatch = new CountDownLatch(1);           // CountDownLatch = barrier; all threads wait until released
        CountDownLatch doneLatch = new CountDownLatch(duplicateSubmissions); // counts down as threads finish
        AtomicInteger successCount = new AtomicInteger(0);          // AtomicInteger = thread-safe counter without locks

        String idempotencyKey = "pay-order-12345-abc";
        String orderId = "ORDER-12345";
        long amount = 9999L; // $99.99

        System.out.println("Scenario: Same payment (key=" + idempotencyKey + ") submitted 10 times concurrently.");
        System.out.println("Expected: Exactly 1 payment processed, 9 rejected as duplicates.\n");

        for (int t = 0; t < duplicateSubmissions; t++) {
            new Thread(() -> {
                try {
                    startLatch.await();
                    Transaction result = gateway.processPayment(idempotencyKey, orderId, amount);
                    if (result != null) {
                        successCount.incrementAndGet();
                    }
                } catch (InterruptedException e) {
                    Thread.currentThread().interrupt();
                } finally {
                    doneLatch.countDown();
                }
            }, "PayThread-" + t).start();
        }

        startLatch.countDown();
        doneLatch.await();

        // Also test that different idempotency keys work independently
        gateway.processPayment("pay-order-99999-xyz", "ORDER-99999", 5000L);

        System.out.println("--- Results ---");
        System.out.println("Total attempts for same key: " + duplicateSubmissions);
        System.out.println("Successful processes: " + successCount.get());
        System.out.println("Duplicates rejected: " + gateway.getDuplicatesRejected());
        System.out.println("Total unique payments in system: " + gateway.getProcessedCount());

        boolean passed = successCount.get() == 1 && gateway.getProcessedCount() == 2;
        System.out.println("\nCorrectness check: " + (passed ? "PASSED" : "FAILED"));
    }
}

// concurrent/model/Transaction.java — Immutable transaction record

public class Transaction {
    private final String idempotencyKey; // final = set once in constructor, never changes; safe for threads to read
    private final String orderId;        // final = immutable after construction; no synchronization needed
    private final long amountCents;      // final = guarantees safe publication to other threads
    private final long processedAt;      // final = records when created; immutable
    private final String threadName;     // final = captures which thread processed this; immutable

    public Transaction(String idempotencyKey, String orderId, long amountCents) {
        this.idempotencyKey = idempotencyKey;
        this.orderId = orderId;
        this.amountCents = amountCents;
        this.processedAt = System.nanoTime();
        this.threadName = Thread.currentThread().getName();
    }

    public String getIdempotencyKey() { return idempotencyKey; }
    public String getOrderId() { return orderId; }
    public long getAmountCents() { return amountCents; }
    public long getProcessedAt() { return processedAt; }
    public String getThreadName() { return threadName; }

    @Override
    public String toString() {
        return "Transaction[order=" + orderId + ", amount=$" + (amountCents / 100) +
               "." + String.format("%02d", amountCents % 100) + ", by=" + threadName + "]";
    }
}

// concurrent/service/PaymentGateway.java — ConcurrentHashMap with putIfAbsent for idempotent payments

import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.atomic.AtomicInteger;

public class PaymentGateway {
    private final ConcurrentHashMap<String, Transaction> processedPayments = new ConcurrentHashMap<>(); // ConcurrentHashMap = lock-free reads; putIfAbsent is atomic
    private final AtomicInteger totalAttempts = new AtomicInteger(0);       // AtomicInteger = thread-safe counter; no locks needed
    private final AtomicInteger duplicatesRejected = new AtomicInteger(0);  // AtomicInteger = incrementAndGet is atomic via CAS

    /**
     * Process a payment. Uses putIfAbsent to atomically prevent double-processing.
     * Returns the transaction if this call actually processed it, null if duplicate.
     */
    public Transaction processPayment(String idempotencyKey, String orderId, long amountCents) {
        totalAttempts.incrementAndGet();

        Transaction newTxn = new Transaction(idempotencyKey, orderId, amountCents);
        Transaction existing = processedPayments.putIfAbsent(idempotencyKey, newTxn);

        if (existing != null) {
            duplicatesRejected.incrementAndGet();
            return null; // duplicate — already processed
        }

        // Simulate payment processing work
        simulateProcessing();
        return newTxn;
    }

    private void simulateProcessing() {
        try {
            Thread.sleep(1); // simulate network call
        } catch (InterruptedException e) {
            Thread.currentThread().interrupt();
        }
    }

    public Transaction getTransaction(String idempotencyKey) {
        return processedPayments.get(idempotencyKey);
    }

    public int getProcessedCount() { return processedPayments.size(); }
    public int getTotalAttempts() { return totalAttempts.get(); }
    public int getDuplicatesRejected() { return duplicatesRejected.get(); }
}

