// Main.java — Demonstrates rate limiting with synchronized counters
public class Main {
    public static void main(String[] args) throws InterruptedException {
        System.out.println("=== Rate Limiter Demo (Naive) ===\n");

        RateLimiter limiter = RateLimiterService.createSlidingWindow(5, 2000);
        System.out.println("--- Sliding Window: 5 requests per 2s (synchronized) ---");

        for (int i = 1; i <= 7; i++) {
            boolean allowed = limiter.allowRequest(new Request("client1"));
            System.out.println("Request " + i + ": " + (allowed ? "ALLOWED" : "DENIED"));
        }

        System.out.println("\nWaiting 2.1 seconds...");
        Thread.sleep(2100);

        boolean allowed = limiter.allowRequest(new Request("client1"));
        System.out.println("After window: " + (allowed ? "ALLOWED" : "DENIED"));

        System.out.println("\n--- Multi-client isolation ---");
        System.out.println("ClientA: " + (limiter.allowRequest(new Request("A")) ? "ALLOWED" : "DENIED"));
        System.out.println("ClientB: " + (limiter.allowRequest(new Request("B")) ? "ALLOWED" : "DENIED"));

        System.out.println("\n=== Demo Complete ===");
    }
}

// model/RateLimitConfig.java — Configuration for rate limiters
public class RateLimitConfig {
    private int capacity;           // private = only accessible via getter; encapsulates config
    private long windowSizeMs;      // private = hides implementation detail from outside

    public RateLimitConfig(int capacity, long windowSizeMs) {
        this.capacity = capacity; this.windowSizeMs = windowSizeMs;
    }
    public int getCapacity() { return capacity; }
    public long getWindowSizeMs() { return windowSizeMs; }
}

// model/Request.java — Incoming request to be rate-limited
public class Request {
    private String clientId;    // private = only this class manages the client identity
    private long timestamp;     // private = encapsulates when the request arrived

    public Request(String clientId) { this.clientId = clientId; this.timestamp = System.currentTimeMillis(); }
    public Request(String clientId, long timestamp) { this.clientId = clientId; this.timestamp = timestamp; }
    public String getClientId() { return clientId; }
    public long getTimestamp() { return timestamp; }
}

// service/RateLimiterService.java — Creates and manages rate limiters
public class RateLimiterService {
    public static RateLimiter createSlidingWindow(int maxRequests, long windowMs) { // static = factory method; no instance needed to call
        return new SlidingWindowLimiter(maxRequests, windowMs);
    }
}

// strategy/RateLimiter.java — Rate limiting interface
public interface RateLimiter {              // interface = contract; different algorithms can implement this
    boolean allowRequest(Request request);
    String getAlgorithmName();
}

// strategy/SlidingWindowLimiter.java — Naive: synchronized counter with LinkedList
import java.util.Map;
import java.util.HashMap;
import java.util.LinkedList;
import java.util.Queue;

public class SlidingWindowLimiter implements RateLimiter { // implements = fulfills the RateLimiter contract
    private int maxRequests;
    private long windowSizeMs;
    private Map<String, Queue<Long>> requestLogs; // Map = per-client request timestamps; Queue = FIFO ordering

    public SlidingWindowLimiter(int maxRequests, long windowSizeMs) {
        this.maxRequests = maxRequests; this.windowSizeMs = windowSizeMs;
        this.requestLogs = new HashMap<>();
    }

    @Override
    public synchronized boolean allowRequest(Request request) { // synchronized = locks entire object; only one thread enters at a time
        String clientId = request.getClientId();
        long now = request.getTimestamp();
        Queue<Long> log = requestLogs.computeIfAbsent(clientId, k -> new LinkedList<>());
        // Remove expired entries
        while (!log.isEmpty() && log.peek() <= now - windowSizeMs) log.poll();
        if (log.size() < maxRequests) { log.add(now); return true; }
        return false;
    }

    @Override public String getAlgorithmName() { return "Sliding Window (synchronized)"; }
}

// Main.java — Demonstrates rate limiting with atomic circular buffer
public class Main {
    public static void main(String[] args) throws InterruptedException {
        System.out.println("=== Rate Limiter Demo (Optimized) ===");
        System.out.println("Optimizations: AtomicInteger + circular buffer, ConcurrentHashMap per-client\n");

        RateLimiter limiter = RateLimiterService.createSlidingWindow(5, 2000);
        System.out.println("--- Sliding Window: 5 requests per 2s (lock-free) ---");

        for (int i = 1; i <= 7; i++) {
            boolean allowed = limiter.allowRequest(new Request("client1"));
            System.out.println("Request " + i + ": " + (allowed ? "ALLOWED" : "DENIED"));
        }

        System.out.println("\nWaiting 2.1 seconds...");
        Thread.sleep(2100);

        boolean allowed = limiter.allowRequest(new Request("client1"));
        System.out.println("After window: " + (allowed ? "ALLOWED" : "DENIED"));

        System.out.println("\n--- Multi-client (no contention between clients) ---");
        System.out.println("ClientA: " + (limiter.allowRequest(new Request("A")) ? "ALLOWED" : "DENIED"));
        System.out.println("ClientB: " + (limiter.allowRequest(new Request("B")) ? "ALLOWED" : "DENIED"));

        System.out.println("\n=== Demo Complete ===");
    }
}

// model/RateLimitConfig.java — Configuration for rate limiters
