    private String clientId;    // private = only this class manages the client identity
    private long timestamp;     // private = encapsulates when the request arrived

    public Request(String clientId) { this.clientId = clientId; this.timestamp = System.currentTimeMillis(); }
    public Request(String clientId, long timestamp) { this.clientId = clientId; this.timestamp = timestamp; }
    public String getClientId() { return clientId; }
    public long getTimestamp() { return timestamp; }
}

// service/RateLimiterService.java — Creates rate limiters
public class RateLimiterService {
    public static RateLimiter createSlidingWindow(int maxRequests, long windowMs) { // static = factory method; no instance needed
        return new SlidingWindowLimiter(maxRequests, windowMs);
    }
}

// strategy/RateLimiter.java — Rate limiting interface
public interface RateLimiter {              // interface = contract; allows swapping algorithm implementations
    boolean allowRequest(Request request);
    String getAlgorithmName();
}

// strategy/SlidingWindowLimiter.java — Optimized: atomic operations with circular buffer
import java.util.Map;
import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.atomic.AtomicInteger;
import java.util.concurrent.atomic.AtomicLongArray;

public class SlidingWindowLimiter implements RateLimiter { // implements = fulfills the RateLimiter contract
    private int maxRequests;
    private long windowSizeMs;
    private int bucketCount;                             // circular buffer size; avoids scanning all timestamps
    private long bucketSizeMs;
    private Map<String, ClientWindow> windows;           // ConcurrentHashMap = per-client access without global lock

    public SlidingWindowLimiter(int maxRequests, long windowSizeMs) {
        this.maxRequests = maxRequests;
        this.windowSizeMs = windowSizeMs;
        // WHY: Circular buffer with 10 sub-windows gives O(1) check without scanning timestamps
        this.bucketCount = 10;
        this.bucketSizeMs = windowSizeMs / bucketCount;
        this.windows = new ConcurrentHashMap<>();
    }

    @Override
    public boolean allowRequest(Request request) {
        ClientWindow window = windows.computeIfAbsent(
            request.getClientId(), k -> new ClientWindow(bucketCount));
        return window.tryIncrement(request.getTimestamp(), maxRequests, bucketSizeMs, bucketCount, windowSizeMs);
    }

    @Override
    public String getAlgorithmName() { return "Sliding Window (atomic circular buffer)"; }

    private static class ClientWindow {                   // static = no reference to outer class needed
        private AtomicLongArray bucketTimestamps;         // AtomicLongArray = thread-safe array of timestamps
        private AtomicInteger[] bucketCounts;             // AtomicInteger = lock-free counter per bucket
        private int bucketCount;

        ClientWindow(int bucketCount) {
            this.bucketCount = bucketCount;
            this.bucketTimestamps = new AtomicLongArray(bucketCount);
            this.bucketCounts = new AtomicInteger[bucketCount];
            for (int i = 0; i < bucketCount; i++) {
                bucketCounts[i] = new AtomicInteger(0);
            }
        }

        boolean tryIncrement(long now, int maxRequests, long bucketSizeMs, int bucketCount, long windowSizeMs) {
            int currentBucket = (int) ((now / bucketSizeMs) % bucketCount);

            // Reset bucket if it's from a previous window cycle
            long bucketTime = bucketTimestamps.get(currentBucket);
            if (now - bucketTime >= windowSizeMs) {
                bucketTimestamps.set(currentBucket, now);
                bucketCounts[currentBucket].set(0);
            }

            // Count requests across all active buckets
            int total = 0;
            for (int i = 0; i < bucketCount; i++) {
                long ts = bucketTimestamps.get(i);
                if (now - ts < windowSizeMs) {
                    total += bucketCounts[i].get();
                }
            }

            if (total < maxRequests) {
                bucketCounts[currentBucket].incrementAndGet();
                return true;
            }
            return false;
        }
    }
}

// concurrent/Main.java — 100 concurrent requests with limit=10/second, exactly 10 pass

import java.util.concurrent.*;
import java.util.concurrent.atomic.AtomicInteger;

public class Main {
    public static void main(String[] args) throws InterruptedException {
        System.out.println("=== Concurrent Rate Limiter Demo ===\n");

        int limit = 10;
        TokenBucketRateLimiter limiter = new TokenBucketRateLimiter(limit);

        int requestCount = 100;
        CountDownLatch startLatch = new CountDownLatch(1);    // CountDownLatch = barrier; threads wait until released
        CountDownLatch doneLatch = new CountDownLatch(requestCount); // counts down as threads complete
        AtomicInteger allowed = new AtomicInteger(0);        // AtomicInteger = thread-safe counter
        AtomicInteger rejected = new AtomicInteger(0);       // AtomicInteger = no lost increments under contention

        System.out.println("Scenario: 100 concurrent requests against a rate limit of 10 tokens.");
        System.out.println("Expected: Exactly 10 requests pass, 90 are rejected.\n");

        for (int t = 0; t < requestCount; t++) {
            new Thread(() -> {
                try {
                    startLatch.await();
                    RateLimitResult result = limiter.tryAcquire();
                    if (result.isAllowed()) {
                        allowed.incrementAndGet();
                    } else {
                        rejected.incrementAndGet();
                    }
                } catch (InterruptedException e) {
                    Thread.currentThread().interrupt();
                } finally {
                    doneLatch.countDown();
                }
            }, "Req-" + t).start();
        }

        startLatch.countDown();
        doneLatch.await();

        System.out.println("--- Results ---");
        System.out.println("Total requests: " + requestCount);
        System.out.println("Allowed: " + allowed.get());
        System.out.println("Rejected: " + rejected.get());
        System.out.println("Remaining tokens: " + limiter.getAvailableTokens());

        boolean passed = allowed.get() == limit && rejected.get() == (requestCount - limit);
        System.out.println("\nCorrectness check: " + (passed ? "PASSED" : "FAILED"));
    }
}

// concurrent/model/RateLimitResult.java — Result of a rate limit check

public class RateLimitResult {
    private final boolean allowed;          // final = immutable after construction; safe to share across threads
    private final int remainingTokens;      // final = set once; no synchronization needed to read

    public RateLimitResult(boolean allowed, int remainingTokens) {
        this.allowed = allowed;
        this.remainingTokens = remainingTokens;
    }

    public boolean isAllowed() { return allowed; }
    public int getRemainingTokens() { return remainingTokens; }
}

// concurrent/service/TokenBucketRateLimiter.java — AtomicInteger with CAS loop for token bucket

import java.util.concurrent.atomic.AtomicInteger;

public class TokenBucketRateLimiter {
    private final AtomicInteger tokens;    // AtomicInteger = thread-safe counter; CAS ensures no lost decrements
    private final int maxTokens;           // final = immutable config; safe for all threads to read

    public TokenBucketRateLimiter(int maxTokens) {
        this.maxTokens = maxTokens;
        this.tokens = new AtomicInteger(maxTokens);
    }

    /**
     * Try to consume one token. Uses CAS loop to ensure atomic decrement.
     * Only succeeds if tokens > 0 at the moment of CAS.
     */
    public RateLimitResult tryAcquire() {
        while (true) {
            int current = tokens.get();
            if (current <= 0) {
                return new RateLimitResult(false, 0);
            }
            if (tokens.compareAndSet(current, current - 1)) { // CAS = atomic compare-and-swap; succeeds only if no other thread changed it
                return new RateLimitResult(true, current - 1);
            }
            // CAS failed means another thread decremented first; retry with fresh value
        }
    }

    /**
     * Refill tokens (called by a background refill mechanism).
     */
    public void refill(int count) {
        while (true) {
            int current = tokens.get();
            int newVal = Math.min(current + count, maxTokens);
            if (tokens.compareAndSet(current, newVal)) {
                return;
            }
        }
    }

    public int getAvailableTokens() {
        return tokens.get();
    }

    public int getMaxTokens() {
        return maxTokens;
    }
}

