// Main.java — Demonstrates URL shortener with random encoding and collision checks
public class Main {
    public static void main(String[] args) {
        System.out.println("=== URL Shortener Demo (Naive) ===\n");

        URLShortener shortener = new URLShortener("https://short.ly", new EncodingStrategy.RandomEncoding());

        System.out.println("--- Shortening URLs (random + collision check) ---");
        String s1 = shortener.shorten("https://www.example.com/very/long/path");
        System.out.println("https://www.example.com/very/long/path → " + s1);

        String s2 = shortener.shorten("https://docs.google.com/doc/abc123");
        System.out.println("https://docs.google.com/doc/abc123 → " + s2);

        System.out.println("\n--- Resolution ---");
        System.out.println(s1 + " → " + shortener.resolve(s1));

        System.out.println("\n--- Duplicate URL returns same code ---");
        String s3 = shortener.shorten("https://www.example.com/very/long/path");
        System.out.println("Same URL again → " + s3 + " (same: " + s1.equals(s3) + ")");

        System.out.println("\nTotal mappings: " + shortener.getTotalMappings());
        System.out.println("\n=== Demo Complete ===");
    }
}

// model/URLMapping.java — Maps short code to original URL
public class URLMapping {
    private String shortCode;       // private = encapsulates the generated short code
    private String longUrl;         // private = original URL hidden behind getter
    private long createdAt;
    private long expiresAt;
    private boolean active;         // private = mutable state; controlled via deactivate()

    public URLMapping(String shortCode, String longUrl, long ttlMs) {
        this.shortCode = shortCode; this.longUrl = longUrl;
        this.createdAt = System.currentTimeMillis();
        this.expiresAt = (ttlMs > 0) ? createdAt + ttlMs : 0;
        this.active = true;
    }

    public String getShortCode() { return shortCode; }
    public String getLongUrl() { return longUrl; }
    public boolean isActive() { return active; }
    public void deactivate() { this.active = false; }
    public boolean isExpired() { return expiresAt > 0 && System.currentTimeMillis() > expiresAt; }
    @Override public String toString() { return shortCode + " -> " + longUrl; }
}

// service/URLShortener.java — Naive: random code with collision check loop
import java.util.HashMap;
import java.util.Map;

public class URLShortener {
    private String baseUrl;
    private EncodingStrategy strategy;                   // private = pluggable encoding hidden from callers
    private Map<String, URLMapping> shortToMapping;      // Map = O(1) lookup from short code to mapping
    private Map<String, String> longToShort;             // Map = reverse lookup to detect duplicate URLs
    private long idCounter;

    public URLShortener(String baseUrl, EncodingStrategy strategy) {
        this.baseUrl = baseUrl; this.strategy = strategy;
        this.shortToMapping = new HashMap<>(); this.longToShort = new HashMap<>();
        this.idCounter = 100000;
    }

    public String shorten(String longUrl) {
        if (longToShort.containsKey(longUrl)) return baseUrl + "/" + longToShort.get(longUrl);

        // Naive: generate random code and check for collisions — may loop many times
        String shortCode;
        int attempts = 0;
        do {
            shortCode = strategy.encode(longUrl, ++idCounter);
            attempts++;
            if (attempts > 100) throw new RuntimeException("Unable to generate unique code");
        } while (shortToMapping.containsKey(shortCode));

        URLMapping mapping = new URLMapping(shortCode, longUrl, 0);
        shortToMapping.put(shortCode, mapping);
        longToShort.put(longUrl, shortCode);
        return baseUrl + "/" + shortCode;
    }

    public String resolve(String shortUrl) {
        String code = shortUrl.replace(baseUrl + "/", "");
        URLMapping mapping = shortToMapping.get(code);
        if (mapping == null) throw new IllegalArgumentException("Not found: " + shortUrl);
        if (!mapping.isActive()) throw new IllegalStateException("Deactivated: " + shortUrl);
        if (mapping.isExpired()) throw new IllegalStateException("Expired: " + shortUrl);
        return mapping.getLongUrl();
    }

    public int getTotalMappings() { return shortToMapping.size(); }
}

// strategy/EncodingStrategy.java — URL encoding algorithms
// DESIGN PATTERN: Strategy
import java.util.Random;

public interface EncodingStrategy {            // interface = contract; different encodings can be swapped in
    String encode(String url, long id);

    // Naive: random generation — may collide, requires collision check loop
    class RandomEncoding implements EncodingStrategy { // implements = fulfills the EncodingStrategy contract
        private static final String CHARS = "0123456789abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ"; // static final = shared constant
        private Random random = new Random();

        @Override
        public String encode(String url, long id) {
            StringBuilder sb = new StringBuilder();
            for (int i = 0; i < 7; i++) sb.append(CHARS.charAt(random.nextInt(62)));
            return sb.toString();
        }
    }
}

// Main.java — Demonstrates URL shortener with atomic counter (no collision checks)
public class Main {
    public static void main(String[] args) {
        System.out.println("=== URL Shortener Demo (Optimized) ===");
        System.out.println("Optimization: AtomicLong counter + Base62 = guaranteed unique, O(1)\n");

        URLShortener shortener = new URLShortener("https://short.ly", new EncodingStrategy.Base62Encoding());

        System.out.println("--- Shortening URLs (counter-based, no collision check) ---");
        String s1 = shortener.shorten("https://www.example.com/very/long/path");
        System.out.println("https://www.example.com/very/long/path → " + s1);

        String s2 = shortener.shorten("https://docs.google.com/doc/abc123");
        System.out.println("https://docs.google.com/doc/abc123 → " + s2);

        System.out.println("\n--- Resolution ---");
        System.out.println(s1 + " → " + shortener.resolve(s1));

        System.out.println("\n--- Duplicate URL returns same code ---");
        String s3 = shortener.shorten("https://www.example.com/very/long/path");
        System.out.println("Same URL again → " + s3 + " (same: " + s1.equals(s3) + ")");

        System.out.println("\nTotal mappings: " + shortener.getTotalMappings());
        System.out.println("\n=== Demo Complete ===");
    }
}

// model/URLMapping.java — Maps short code to original URL
public class URLMapping {
    private String shortCode;       // private = encapsulates the generated short code
    private String longUrl;         // private = original URL hidden behind getter
    private long createdAt;
    private long expiresAt;
    private boolean active;         // private = mutable state; controlled via deactivate()

    public URLMapping(String shortCode, String longUrl, long ttlMs) {
        this.shortCode = shortCode; this.longUrl = longUrl;
        this.createdAt = System.currentTimeMillis();
        this.expiresAt = (ttlMs > 0) ? createdAt + ttlMs : 0;
        this.active = true;
    }

    public String getShortCode() { return shortCode; }
    public String getLongUrl() { return longUrl; }
    public boolean isActive() { return active; }
    public void deactivate() { this.active = false; }
    public boolean isExpired() { return expiresAt > 0 && System.currentTimeMillis() > expiresAt; }
    @Override public String toString() { return shortCode + " -> " + longUrl; }
}

// service/URLShortener.java — Optimized: AtomicLong counter guarantees unique codes
import java.util.HashMap;
import java.util.Map;
import java.util.concurrent.atomic.AtomicLong;

public class URLShortener {
    private String baseUrl;
    private EncodingStrategy strategy;
    private Map<String, URLMapping> shortToMapping;      // HashMap = O(1) lookup by short code
    private Map<String, String> longToShort;             // HashMap = reverse index to prevent duplicate entries
    private AtomicLong idCounter;                        // AtomicLong = thread-safe counter; guarantees unique IDs without locks

    public URLShortener(String baseUrl, EncodingStrategy strategy) {
        this.baseUrl = baseUrl; this.strategy = strategy;
        this.shortToMapping = new HashMap<>(); this.longToShort = new HashMap<>();
        this.idCounter = new AtomicLong(100000);
    }

    public String shorten(String longUrl) {
        if (longToShort.containsKey(longUrl)) return baseUrl + "/" + longToShort.get(longUrl);

        // WHY: getAndIncrement is atomic — guaranteed unique, no collision possible
        long id = idCounter.getAndIncrement();
        String shortCode = strategy.encode(longUrl, id);

        URLMapping mapping = new URLMapping(shortCode, longUrl, 0);
        shortToMapping.put(shortCode, mapping);
        longToShort.put(longUrl, shortCode);
        return baseUrl + "/" + shortCode;
    }

    public String resolve(String shortUrl) {
        String code = shortUrl.replace(baseUrl + "/", "");
        URLMapping mapping = shortToMapping.get(code);
        if (mapping == null) throw new IllegalArgumentException("Not found: " + shortUrl);
        if (!mapping.isActive()) throw new IllegalStateException("Deactivated: " + shortUrl);
        if (mapping.isExpired()) throw new IllegalStateException("Expired: " + shortUrl);
        return mapping.getLongUrl();
    }

    public int getTotalMappings() { return shortToMapping.size(); }
}

// strategy/EncodingStrategy.java — Counter-based Base62 encoding (no collisions)
// DESIGN PATTERN: Strategy
import java.util.concurrent.atomic.AtomicLong;

public interface EncodingStrategy {            // interface = contract; encoding algorithms are pluggable
    String encode(String url, long id);

    // Base62 gives short, URL-safe codes: 62^6 = 56 billion possible codes
    class Base62Encoding implements EncodingStrategy { // implements = fulfills the EncodingStrategy contract
        private static final String CHARS = "0123456789abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ"; // static final = shared constant; never changes

        @Override
        public String encode(String url, long id) {
            StringBuilder sb = new StringBuilder();
            long num = id;
            while (num > 0) {
                sb.append(CHARS.charAt((int) (num % 62)));
                num /= 62;
            }
            while (sb.length() < 6) sb.append('0');
            return sb.reverse().toString();
        }
    }
}

// concurrent/Main.java — 1000 concurrent URL creations, verify all unique short codes

import java.util.*;
import java.util.concurrent.*;
import java.util.concurrent.atomic.AtomicBoolean;

public class Main {
    public static void main(String[] args) throws InterruptedException {
        System.out.println("=== Concurrent URL Shortener Demo ===\n");

        UrlShortenerService service = new UrlShortenerService();
        int urlCount = 1000;
        int threadCount = 50;
        CountDownLatch startLatch = new CountDownLatch(1);
        CountDownLatch doneLatch = new CountDownLatch(threadCount);

        ConcurrentHashMap<String, String> results = new ConcurrentHashMap<>(); // ConcurrentHashMap = thread-safe result collector
        AtomicBoolean collisionFound = new AtomicBoolean(false);             // AtomicBoolean = thread-safe flag; visible to all threads

        System.out.println("Scenario: 1000 unique URLs shortened by 50 threads concurrently.");
        System.out.println("Expected: All 1000 get unique short codes, no collisions.\n");

        // Pre-generate URLs
        String[] urls = new String[urlCount];
        for (int i = 0; i < urlCount; i++) {
            urls[i] = "https://example.com/page/" + i + "/" + UUID.randomUUID();
        }

        int urlsPerThread = urlCount / threadCount;
        for (int t = 0; t < threadCount; t++) {
            final int start = t * urlsPerThread;
            new Thread(() -> {
                try {
                    startLatch.await();
                    for (int i = start; i < start + urlsPerThread; i++) {
                        String code = service.shorten(urls[i]);
                        String prev = results.putIfAbsent(code, urls[i]);
                        if (prev != null && !prev.equals(urls[i])) {
                            collisionFound.set(true);
                            System.err.println("COLLISION: " + code + " -> " + prev + " AND " + urls[i]);
                        }
                    }
                } catch (InterruptedException e) {
                    Thread.currentThread().interrupt();
                } finally {
                    doneLatch.countDown();
                }
            }, "Shortener-" + t).start();
        }

        startLatch.countDown();
        doneLatch.await();

        // Verify all codes are unique and resolvable
        Set<String> uniqueCodes = results.keySet();
        boolean allUnique = uniqueCodes.size() == urlCount;
        boolean allResolvable = true;
        int checked = 0;
        for (Map.Entry<String, String> entry : results.entrySet()) {
            String resolved = service.resolve(entry.getKey());
            if (!entry.getValue().equals(resolved)) {
                allResolvable = false;
                break;
            }
            checked++;
        }

        System.out.println("--- Results ---");
        System.out.println("URLs shortened: " + service.getUrlCount());
        System.out.println("Unique codes generated: " + uniqueCodes.size());
        System.out.println("All unique: " + allUnique);
        System.out.println("All resolvable: " + allResolvable);
        System.out.println("Collisions found: " + collisionFound.get());

        boolean passed = allUnique && allResolvable && !collisionFound.get();
        System.out.println("\nCorrectness check: " + (passed ? "PASSED" : "FAILED"));
    }
}

// concurrent/model/ShortUrl.java — Mapping between short code and original URL

public class ShortUrl {
    private final String shortCode;     // final = immutable after construction; safe to share across threads
    private final String originalUrl;   // final = never changes; no synchronization needed to read
    private final long createdAt;       // final = safe publication guaranteed by JMM

    public ShortUrl(String shortCode, String originalUrl) {
        this.shortCode = shortCode;
        this.originalUrl = originalUrl;
        this.createdAt = System.nanoTime();
    }

    public String getShortCode() { return shortCode; }
    public String getOriginalUrl() { return originalUrl; }
    public long getCreatedAt() { return createdAt; }
}

// concurrent/service/UrlShortenerService.java — AtomicLong counter + ConcurrentHashMap.putIfAbsent

import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.atomic.AtomicLong;

public class UrlShortenerService {
    private static final String BASE62 = "0123456789ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz"; // static final = shared constant
    private static final int CODE_LENGTH = 7;

    private final AtomicLong counter = new AtomicLong(100000);            // AtomicLong = thread-safe sequential ID; getAndIncrement is atomic
    private final ConcurrentHashMap<String, ShortUrl> codeToUrl = new ConcurrentHashMap<>(); // ConcurrentHashMap = lock-free reads; putIfAbsent is atomic
    private final ConcurrentHashMap<String, String> urlToCode = new ConcurrentHashMap<>();   // ConcurrentHashMap = atomic dedup check across threads

    /**
     * Shorten a URL. Uses AtomicLong for unique sequential ID generation
     * and putIfAbsent for collision-free registration.
     */
    public String shorten(String originalUrl) {
        // Check if already shortened
        String existingCode = urlToCode.get(originalUrl);
        if (existingCode != null) return existingCode;

        // Generate unique code from sequential counter
        long id = counter.getAndIncrement();
        String code = encode(id);

        ShortUrl shortUrl = new ShortUrl(code, originalUrl);

        // Atomically register — putIfAbsent guarantees no collision
        ShortUrl existing = codeToUrl.putIfAbsent(code, shortUrl);
        if (existing != null) {
            // Extremely unlikely with sequential IDs, but handle gracefully
            return existing.getShortCode();
        }

        // Register reverse mapping (race-safe: first one wins)
        urlToCode.putIfAbsent(originalUrl, code);
        return code;
    }

    public String resolve(String code) {
        ShortUrl shortUrl = codeToUrl.get(code);
        return shortUrl != null ? shortUrl.getOriginalUrl() : null;
    }

    private String encode(long num) {
        StringBuilder sb = new StringBuilder();
        while (sb.length() < CODE_LENGTH) {
            sb.append(BASE62.charAt((int) (num % 62)));
            num /= 62;
        }
        return sb.reverse().toString();
    }

    public int getUrlCount() { return codeToUrl.size(); }
    public long getCounterValue() { return counter.get(); }
}

