// Main.java — Demonstrates key-value store with HashMap + TTL scan + Strategy + Observer
public class Main {
    public static void main(String[] args) throws InterruptedException {
        System.out.println("=== Key-Value Store Demo (Naive) ===\n");

        // Strategy is injected; here we use an append-only-log persistence backend.
        KVStore store = new KVStore(new AppendOnlyLogPersistence());
        // Observer: console logger receives set/delete/expire events.
        store.addObserver(new LoggingKVObserver());

        System.out.println("--- Basic Operations ---");
        store.set("name", "Alice");
        store.set("age", "30");
        System.out.println("GET name -> " + store.get("name"));
        System.out.println("GET age -> " + store.get("age"));
        store.delete("name");
        System.out.println("DELETE name -> GET name = " + store.get("name"));

        System.out.println("\n--- TTL Expiration ---");
        store.set("session", "abc123", 1500);
        System.out.println("SET session (TTL 1.5s) -> " + store.get("session"));
        Thread.sleep(1600);
        System.out.println("After 1.6s -> " + (store.get("session") == null ? "(expired)" : store.get("session")));

        System.out.println("\n--- Log ---");
        for (Command cmd : store.getLog()) System.out.println("  " + cmd);

        System.out.println("\n=== Demo Complete ===");
    }
}

// command/Command.java — Store operation as executable object
public class Command {
    public enum Type { SET, DELETE }     // enum = fixed set of operations; type-safe, no invalid commands
    private Type type;                   // private = only this class manages command type
    private String key;
    private String value;
    private long ttlMs;

    public Command(Type type, String key, String value, long ttlMs) {
        this.type = type; this.key = key; this.value = value; this.ttlMs = ttlMs;
    }

    public static Command set(String key, String value) { return new Command(Type.SET, key, value, 0); } // static = factory method; creates Command without exposing constructor details
    public static Command setWithTtl(String key, String value, long ttlMs) { return new Command(Type.SET, key, value, ttlMs); }
    public static Command delete(String key) { return new Command(Type.DELETE, key, null, 0); }

    public Type getType() { return type; }
    public String getKey() { return key; }
    public String getValue() { return value; }
    public long getTtlMs() { return ttlMs; }
    @Override public String toString() { return type == Type.SET ? "SET " + key + " " + value : "DELETE " + key; }
}

// model/Entry.java — Key-value entry with TTL
public class Entry {
    private String key;             // private = encapsulated; accessed only via getter
    private String value;           // private = mutable; can be updated via setValue()
    private long createdAt;
    private long expiresAt;         // private = 0 means no expiry; positive means TTL-based

    public Entry(String key, String value, long ttlMs) {
        this.key = key; this.value = value; this.createdAt = System.currentTimeMillis();
        this.expiresAt = (ttlMs > 0) ? createdAt + ttlMs : 0;
    }

    public String getKey() { return key; }
    public String getValue() { return value; }
    public void setValue(String value) { this.value = value; }
    public boolean isExpired() { return expiresAt > 0 && System.currentTimeMillis() > expiresAt; }
    public long getRemainingTtl() { return expiresAt == 0 ? -1 : Math.max(0, expiresAt - System.currentTimeMillis()); }
}

// service/AppendOnlyLogPersistence.java — Strategy impl: simulates an append-only log
//
// In a real deployment this would fsync to disk on every append. For the
// problem demo we keep the log in memory but expose the same contract a
// disk-backed AOL would expose: append-only writes, full replay on read,
// and a compaction hook.

import java.util.ArrayList;
import java.util.Collections;
import java.util.List;

class AppendOnlyLogPersistence implements PersistenceStrategy {
    private final List<Command> log = new ArrayList<>();
    private long appendCount = 0;

    @Override
    public void append(Command command) {
        // Simulated durable append. A real impl would write to a file and fsync.
        log.add(command);
        appendCount++;
    }

    @Override
    public List<Command> getLog() {
        return Collections.unmodifiableList(log);
    }

    @Override
    public void replaceLog(List<Command> compacted) {
        // Simulated atomic swap: write compacted log to a temp file, then rename.
        log.clear();
        log.addAll(compacted);
    }

    public long getAppendCount() { return appendCount; }
}

// service/InMemoryPersistence.java — Strategy impl: keeps the command log in a heap list only

import java.util.ArrayList;
import java.util.Collections;
import java.util.List;

class InMemoryPersistence implements PersistenceStrategy {
    private final List<Command> log = new ArrayList<>();

    @Override
    public void append(Command command) {
        log.add(command);
    }

    @Override
    public List<Command> getLog() {
        return Collections.unmodifiableList(log);
    }

    @Override
    public void replaceLog(List<Command> compacted) {
        log.clear();
        log.addAll(compacted);
    }
}

// service/KVStore.java — Naive: HashMap with TTL scan; pluggable persistence + observer fan-out
import java.util.*;

public class KVStore {
    private Map<String, Entry> data;                       // private = internal storage hidden; HashMap gives O(1) get/put

    // Strategy: pluggable persistence backend (in-memory list, AOL, etc.).
    private PersistenceStrategy persistence;

    // Observer: fan-out for KV events (set, delete, expire).
    private final List<KVStoreObserver> observers = new ArrayList<>();

    /** Default ctor uses an in-memory persistence strategy. */
    public KVStore() {
        this(new InMemoryPersistence());
    }

    /** Inject a different persistence strategy (e.g. AppendOnlyLogPersistence). */
    public KVStore(PersistenceStrategy persistence) {
        this.data = new HashMap<>();
        this.persistence = persistence;
    }

    public void set(String key, String value) { set(key, value, 0); }

    public void set(String key, String value, long ttlMs) {
        Entry entry = new Entry(key, value, ttlMs);
        data.put(key, entry);
        persistence.append(ttlMs > 0 ? Command.setWithTtl(key, value, ttlMs) : Command.set(key, value));
        for (KVStoreObserver o : observers) o.onSet(key, value, ttlMs);
    }

    public String get(String key) {
        Entry entry = data.get(key);
        if (entry == null) return null;
        // Naive: check expiration on every get (lazy expiration)
        if (entry.isExpired()) {
            data.remove(key);
            for (KVStoreObserver o : observers) o.onExpire(key);
            return null;
        }
        return entry.getValue();
    }

    public boolean delete(String key) {
        boolean existed = data.remove(key) != null;
        if (existed) {
            persistence.append(Command.delete(key));
            for (KVStoreObserver o : observers) o.onDelete(key);
        }
        return existed;
    }

    public boolean exists(String key) {
        Entry entry = data.get(key);
        if (entry == null) return false;
        if (entry.isExpired()) {
            data.remove(key);
            for (KVStoreObserver o : observers) o.onExpire(key);
            return false;
        }
        return true;
    }

    // Naive: full scan to find expired keys
    public void cleanupExpired() {
        Iterator<Map.Entry<String, Entry>> iter = data.entrySet().iterator();
        while (iter.hasNext()) {
            Map.Entry<String, Entry> e = iter.next();
            if (e.getValue().isExpired()) {
                iter.remove();
                for (KVStoreObserver o : observers) o.onExpire(e.getKey());
            }
        }
    }

    public int size() { return data.size(); }
    public List<Command> getLog() { return persistence.getLog(); }

    // === Strategy plumbing ===
    public PersistenceStrategy getPersistence() { return persistence; }
    public void setPersistence(PersistenceStrategy persistence) { this.persistence = persistence; }

    // === Observer plumbing ===
    public void addObserver(KVStoreObserver observer) { observers.add(observer); }
    public void removeObserver(KVStoreObserver observer) { observers.remove(observer); }
}

// service/KVStoreObserver.java — Observer contract for key-value store events
