// service/PersistenceStrategy.java — Strategy contract for KV-store persistence backends
//
// Different deployments need different durability stories: in-memory only
// (for tests / caches), append-only log (for crash recovery), snapshot
// files, or networked storage. The store delegates persistence here so the
// core logic stays unchanged across backends.

import java.util.List;

interface PersistenceStrategy {
    /** Append a single command to the durable log. */
    void append(Command command);

    /** Return the full ordered command history (for replay / inspection). */
    List<Command> getLog();

    /** Replace the log with a compacted command list (e.g. after compaction). */
    void replaceLog(List<Command> compacted);
}

// Main.java — Demonstrates KV store with ConcurrentHashMap, DelayQueue, Strategy + Observer
public class Main {
    public static void main(String[] args) throws InterruptedException {
        System.out.println("=== Key-Value Store Demo (Optimized) ===");
        System.out.println("Optimizations: ConcurrentHashMap, DelayQueue expiration, background compaction\n");

        // Strategy is injected; here we use an append-only-log persistence backend.
        KVStore store = new KVStore(new AppendOnlyLogPersistence());
        // Observer: console logger receives set/delete/expire events.
        store.addObserver(new LoggingKVObserver());

        System.out.println("--- Basic Operations (lock-free via ConcurrentHashMap) ---");
        store.set("name", "Alice");
        store.set("age", "30");
        System.out.println("GET name -> " + store.get("name"));
        System.out.println("GET age -> " + store.get("age"));
        store.delete("name");
        System.out.println("DELETE name -> GET name = " + store.get("name"));

        System.out.println("\n--- TTL via DelayQueue (auto-expires, no scan) ---");
        store.set("session", "abc123", 1500);
        System.out.println("SET session (TTL 1.5s) -> " + store.get("session"));
        Thread.sleep(1600);
        System.out.println("After 1.6s -> " + (store.get("session") == null ? "(expired by background thread)" : store.get("session")));

        System.out.println("\n--- Background Compaction ---");
        store.set("x", "1"); store.set("x", "2"); store.set("x", "3");
        System.out.println("Log before compaction: " + store.getLog().size() + " entries");
        store.compact();
        System.out.println("Log after compaction: " + store.getLog().size() + " entries");

        System.out.println("\n=== Demo Complete ===");
    }
}

// command/Command.java — Store operation as executable object
public class Command {
    public enum Type { SET, DELETE }     // enum = fixed set of operations; type-safe command types
    private Type type;
    private String key;
    private String value;
    private long ttlMs;

    public Command(Type type, String key, String value, long ttlMs) {
        this.type = type; this.key = key; this.value = value; this.ttlMs = ttlMs;
    }

    public static Command set(String key, String value) { return new Command(Type.SET, key, value, 0); }
    public static Command setWithTtl(String key, String value, long ttlMs) { return new Command(Type.SET, key, value, ttlMs); }
    public static Command delete(String key) { return new Command(Type.DELETE, key, null, 0); }

    public Type getType() { return type; }
    public String getKey() { return key; }
    public String getValue() { return value; }
    public long getTtlMs() { return ttlMs; }
    @Override public String toString() { return type == Type.SET ? "SET " + key + " " + value : "DELETE " + key; }
}

// model/Entry.java — Key-value entry with TTL
public class Entry {
    private String key;             // private = encapsulated; accessed only via getter
    private String value;           // private = mutable; can be updated via setValue()
    private long createdAt;
    private long expiresAt;         // private = 0 means no expiry; positive means TTL-based

    public Entry(String key, String value, long ttlMs) {
        this.key = key; this.value = value; this.createdAt = System.currentTimeMillis();
        this.expiresAt = (ttlMs > 0) ? createdAt + ttlMs : 0;
    }

    public String getKey() { return key; }
    public String getValue() { return value; }
    public void setValue(String value) { this.value = value; }
    public boolean isExpired() { return expiresAt > 0 && System.currentTimeMillis() > expiresAt; }
    public long getRemainingTtl() { return expiresAt == 0 ? -1 : Math.max(0, expiresAt - System.currentTimeMillis()); }
}

// service/AppendOnlyLogPersistence.java — Strategy impl: simulates an append-only log
//
// In a real deployment this would fsync to disk on every append. For the
// problem demo we keep the log in memory but expose the same contract a
// disk-backed AOL would expose: append-only writes, full replay on read,
// and a compaction hook.

import java.util.ArrayList;
import java.util.Collections;
import java.util.List;

class AppendOnlyLogPersistence implements PersistenceStrategy {
    private final List<Command> log = Collections.synchronizedList(new ArrayList<>());
    private long appendCount = 0;

    @Override
    public synchronized void append(Command command) {
        // Simulated durable append. A real impl would write to a file and fsync.
        log.add(command);
        appendCount++;
    }

    @Override
    public List<Command> getLog() {
        synchronized (log) {
            return Collections.unmodifiableList(new ArrayList<>(log));
        }
    }

    @Override
    public void replaceLog(List<Command> compacted) {
        // Simulated atomic swap: write compacted log to a temp file, then rename.
        synchronized (log) {
            log.clear();
            log.addAll(compacted);
        }
    }

    public long getAppendCount() { return appendCount; }
}

