// concurrent/Main.java — 100 threads incrementing same counter key, verify final value = 100

import java.util.concurrent.*;
import java.util.concurrent.atomic.AtomicBoolean;

public class Main {
    public static void main(String[] args) throws InterruptedException {
        System.out.println("=== Concurrent Key-Value Store Demo ===\n");

        KeyValueStore store = new KeyValueStore();
        int threadCount = 100;
        CountDownLatch startLatch = new CountDownLatch(1);    // CountDownLatch = barrier; threads wait until released
        CountDownLatch doneLatch = new CountDownLatch(threadCount);
        AtomicBoolean errorFound = new AtomicBoolean(false); // AtomicBoolean = thread-safe flag for error detection

        System.out.println("Scenario: 100 threads each increment the same counter key once.");
        System.out.println("Expected: Final value = 100 (no lost updates).\n");

        for (int t = 0; t < threadCount; t++) {
            new Thread(() -> {
                try {
                    startLatch.await();
                    store.increment("counter");
                } catch (Exception e) {
                    errorFound.set(true);
                    e.printStackTrace();
                } finally {
                    doneLatch.countDown();
                }
            }, "Incrementer-" + t).start();
        }

        startLatch.countDown();
        doneLatch.await();

        Long finalValue = store.get("counter");
        long version = store.getVersion("counter");

        System.out.println("--- Results ---");
        System.out.println("Threads: " + threadCount);
        System.out.println("Final counter value: " + finalValue);
        System.out.println("Final version: " + version);
        System.out.println("No errors: " + !errorFound.get());

        boolean passed = finalValue != null && finalValue == threadCount && !errorFound.get();
        System.out.println("\nCorrectness check: " + (passed ? "PASSED" : "FAILED"));
    }
}

// concurrent/model/VersionedValue.java — Immutable value with version number for CAS

public class VersionedValue {
    private final long value;       // final = immutable; safe to read from any thread without locks
    private final long version;     // final = version for CAS; enables optimistic concurrency control

    public VersionedValue(long value, long version) {
        this.value = value;
        this.version = version;
    }

    public long getValue() { return value; }
    public long getVersion() { return version; }

    @Override
    public String toString() {
        return "VersionedValue[value=" + value + ", version=" + version + "]";
    }
}

// concurrent/service/KeyValueStore.java — ConcurrentHashMap with compute/merge for atomic read-modify-write

import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.atomic.AtomicReference;

public class KeyValueStore {
    private final ConcurrentHashMap<String, AtomicReference<VersionedValue>> store = new ConcurrentHashMap<>(); // ConcurrentHashMap + AtomicReference = lock-free CAS per key

    public void put(String key, long value) {
        store.compute(key, (k, existing) -> {
            if (existing == null) {
                AtomicReference<VersionedValue> ref = new AtomicReference<>();
                ref.set(new VersionedValue(value, 1));
                return ref;
            } else {
                VersionedValue old = existing.get();
                existing.set(new VersionedValue(value, old.getVersion() + 1));
                return existing;
            }
        });
    }

    public Long get(String key) {
        AtomicReference<VersionedValue> ref = store.get(key);
        if (ref == null) return null;
        VersionedValue vv = ref.get();
        return vv != null ? vv.getValue() : null;
    }

    /**
     * Atomic increment using ConcurrentHashMap.compute.
     * This ensures no lost updates even under concurrent modification.
     */
    public long increment(String key) {
        AtomicReference<VersionedValue> ref = store.compute(key, (k, existing) -> {
            if (existing == null) {
                AtomicReference<VersionedValue> newRef = new AtomicReference<>();
                newRef.set(new VersionedValue(1, 1));
                return newRef;
            } else {
                VersionedValue old = existing.get();
                existing.set(new VersionedValue(old.getValue() + 1, old.getVersion() + 1));
                return existing;
            }
        });
        return ref.get().getValue();
    }

    /**
     * CAS-based update: only updates if current value matches expected.
     */
    public boolean compareAndSet(String key, long expected, long newValue) {
        AtomicReference<VersionedValue> ref = store.get(key); // AtomicReference = allows CAS on the value object
        if (ref == null) return false;
        while (true) {                                         // CAS loop = retry until success or value mismatch
            VersionedValue current = ref.get();
            if (current.getValue() != expected) return false;
            VersionedValue updated = new VersionedValue(newValue, current.getVersion() + 1);
            if (ref.compareAndSet(current, updated)) return true; // CAS = atomic swap; fails if another thread changed it
        }
    }

    public int size() { return store.size(); }

    public long getVersion(String key) {
        AtomicReference<VersionedValue> ref = store.get(key);
        if (ref == null) return 0;
        return ref.get().getVersion();
    }
}

