// service/ConnectionPool.java — Optimized: BlockingQueue + Semaphore + background health check
import java.util.Set;
import java.util.concurrent.*;
import java.util.concurrent.atomic.AtomicInteger;

public class ConnectionPool {
    private PoolConfig config;
    private AtomicInteger connCounter;                           // AtomicInteger = thread-safe ID counter
    private LinkedBlockingQueue<Connection> idleConnections;     // BlockingQueue = thread-safe FIFO; no explicit locking needed
    private Semaphore sizeLimiter;                               // Semaphore = bounds total connections; tryAcquire is non-blocking
    private Set<Connection> activeConnections;                   // ConcurrentHashMap.newKeySet = thread-safe Set
    private volatile boolean shutdown;                           // volatile = all threads see shutdown flag immediately
    private ScheduledExecutorService healthChecker;              // ScheduledExecutor = runs health check on a timer

    public ConnectionPool(PoolConfig config) {
        this.config = config;
        this.connCounter = new AtomicInteger(0);
        this.idleConnections = new LinkedBlockingQueue<>();
        this.sizeLimiter = new Semaphore(config.getMaxSize());
        this.activeConnections = ConcurrentHashMap.newKeySet();
        this.shutdown = false;

        // Pre-create minimum connections
        for (int i = 0; i < config.getMinSize(); i++) {
            Connection conn = createConnection();
            idleConnections.offer(conn);
            sizeLimiter.tryAcquire(); // Reserve permits for pre-created connections
        }

        // WHY: Background health check thread removes stale connections proactively
        this.healthChecker = Executors.newSingleThreadScheduledExecutor(r -> {
            Thread t = new Thread(r, "pool-health-check");
            t.setDaemon(true);
            return t;
        });
        healthChecker.scheduleAtFixedRate(this::runHealthCheck, 5, 5, TimeUnit.SECONDS);
    }

    private Connection createConnection() {
        return new Connection("Conn-" + connCounter.incrementAndGet());
    }

    // WHY: No synchronized block — Semaphore + BlockingQueue handle concurrency
    public Connection borrow() {
        if (shutdown) throw new IllegalStateException("Pool is shut down");

        // Try to get an idle connection first (non-blocking)
        Connection conn = idleConnections.poll();
        if (conn != null && conn.isHealthy()) {
            activeConnections.add(conn);
            return conn;
        }

        // Try to create a new one if under limit
        // WHY: tryAcquire with timeout replaces busy-wait loop
        try {
            if (sizeLimiter.tryAcquire(config.getBorrowTimeoutMs(), TimeUnit.MILLISECONDS)) {
                conn = createConnection();
                activeConnections.add(conn);
                return conn;
            }
        } catch (InterruptedException e) {
            Thread.currentThread().interrupt();
            throw new RuntimeException("Interrupted while waiting for connection");
        }

        throw new RuntimeException("Pool exhausted: timeout after " + config.getBorrowTimeoutMs() + "ms");
    }

    public void returnConnection(Connection conn) {
        activeConnections.remove(conn);
        if (!shutdown && conn.isHealthy()) {
            idleConnections.offer(conn);
        } else {
            conn.close();
            sizeLimiter.release(); // Free the permit for a new connection
        }
    }

    // Background health check — removes unhealthy idle connections
    private void runHealthCheck() {
        int checked = 0;
        for (Connection conn : idleConnections) {
            if (!conn.isHealthy()) {
                if (idleConnections.remove(conn)) {
                    conn.close();
                    sizeLimiter.release();
                    checked++;
                }
            }
        }
        if (checked > 0) System.out.println("  [Health] Removed " + checked + " unhealthy connections");
    }

    public void shutdown() {
        shutdown = true;
        healthChecker.shutdown();
        Connection conn;
        while ((conn = idleConnections.poll()) != null) conn.close();
    }

    public PoolStats getStats() {
        return new PoolStats(activeConnections.size(), idleConnections.size(),
            activeConnections.size() + idleConnections.size());
    }
}

// concurrent/Main.java — 50 threads requesting from pool of 10, demonstrates proper blocking and timeout

import java.util.*;
import java.util.concurrent.CountDownLatch;
import java.util.concurrent.atomic.AtomicInteger;

public class Main {
    public static void main(String[] args) throws InterruptedException {
        System.out.println("=== Concurrent Connection Pool Demo ===\n");

        int poolSize = 10;
        long timeoutMs = 500;
        int threadCount = 50;

        ConcurrentConnectionPool pool = new ConcurrentConnectionPool(poolSize, timeoutMs);

        CountDownLatch startLatch = new CountDownLatch(1);    // CountDownLatch = barrier; all threads start simultaneously
        CountDownLatch doneLatch = new CountDownLatch(threadCount); // counts down as each thread finishes
        AtomicInteger acquired = new AtomicInteger(0);       // AtomicInteger = thread-safe success counter
        AtomicInteger timedOut = new AtomicInteger(0);       // AtomicInteger = thread-safe timeout counter
        AtomicInteger errors = new AtomicInteger(0);
        List<String> log = Collections.synchronizedList(new ArrayList<>()); // synchronizedList = thread-safe appends

        System.out.println("Scenario: 50 threads request connections from a pool of 10.");
        System.out.println("Each thread holds the connection for 200ms (simulating work).");
        System.out.println("Timeout: " + timeoutMs + "ms\n");

        for (int i = 0; i < threadCount; i++) {
            final int id = i;
            new Thread(() -> {
                try {
                    startLatch.await();
                    Connection conn = pool.acquire();
                    if (conn != null) {
                        acquired.incrementAndGet();
                        try {
                            // Simulate doing work with the connection
                            String result = conn.execute("SELECT * FROM users WHERE id=" + id);
                            Thread.sleep(200); // Hold connection for 200ms
                        } finally {
                            pool.release(conn);
                        }
                    } else {
                        timedOut.incrementAndGet();
                        log.add("  [TIMEOUT] Thread-" + id + " could not get connection within " + timeoutMs + "ms");
                    }
                } catch (InterruptedException e) {
                    Thread.currentThread().interrupt();
                    errors.incrementAndGet();
                } finally {
                    doneLatch.countDown();
                }
            }, "Worker-" + id).start();
        }

        startLatch.countDown();
        doneLatch.await();

        // Print timeout logs (first 5)
        int shown = 0;
        for (String entry : log) {
            if (shown++ >= 5) {
                System.out.println("  ... and " + (log.size() - 5) + " more timeouts");
                break;
            }
            System.out.println(entry);
        }

        System.out.println("\n--- Summary ---");
        System.out.println("Pool size: " + poolSize);
        System.out.println("Threads attempted: " + threadCount);
        System.out.println("Successfully acquired: " + acquired.get());
        System.out.println("Timed out: " + timedOut.get());
        System.out.println("Errors: " + errors.get());
        System.out.println("Final pool state: active=" + pool.getActiveCount() + ", idle=" + pool.getIdleCount());

        // Verify: no connection leaks
        boolean noLeaks = pool.getActiveCount() == 0;
        boolean allAccountedFor = acquired.get() + timedOut.get() == threadCount;
        System.out.println("\nNo connection leaks: " + (noLeaks ? "PASSED" : "FAILED"));
        System.out.println("All threads accounted for: " + (allAccountedFor ? "PASSED" : "FAILED"));

        pool.shutdown();
    }
}

// concurrent/RaceConditionDemo.java — Shows connection leak bug when thread dies without returning connection

import java.util.concurrent.CountDownLatch;
import java.util.concurrent.atomic.AtomicInteger;

/**
 * RACE CONDITION: Pool exhaustion due to connection leaks.
 *
 * BUG: If a thread acquires a connection but crashes/throws before returning it,
 * the connection is permanently lost from the pool. Eventually the pool is exhausted.
 *
 * FIX: Use try-finally to guarantee connection return, or implement
 * a reaper thread that reclaims connections held too long.
 */
public class RaceConditionDemo {

    // ===== BUGGY VERSION: No try-finally — connection leak on exception =====
    static class BuggyWorker implements Runnable { // implements Runnable = can be executed by a Thread
        private final ConcurrentConnectionPool pool; // final = safe publication; reference never changes
        private final int id;
        private final AtomicInteger leaks;           // AtomicInteger = thread-safe leak counter

        BuggyWorker(ConcurrentConnectionPool pool, int id, AtomicInteger leaks) {
            this.pool = pool;
            this.id = id;
            this.leaks = leaks;
        }

        @Override
        public void run() {
            try {
                Connection conn = pool.acquire();
                if (conn == null) return;

                // BUG: If this throws, connection is never returned!
                if (id % 3 == 0) {
                    throw new RuntimeException("Simulated crash in thread " + id);
                }

                // Only reached if no exception
                pool.release(conn);
            } catch (RuntimeException e) {
                leaks.incrementAndGet();
                // Connection leaked! Never returned to pool.
            } catch (InterruptedException e) {
                Thread.currentThread().interrupt();
            }
        }
    }

    // ===== FIXED VERSION: try-finally guarantees connection return =====
    static class FixedWorker implements Runnable { // implements Runnable = can be executed by a Thread
        private final ConcurrentConnectionPool pool; // final = safe publication; reference never changes
        private final int id;

        FixedWorker(ConcurrentConnectionPool pool, int id) {
            this.pool = pool;
            this.id = id;
        }

        @Override
        public void run() {
            Connection conn = null;
            try {
                conn = pool.acquire();
                if (conn == null) return;

                // Even if this throws, finally block returns the connection
                if (id % 3 == 0) {
                    throw new RuntimeException("Simulated crash in thread " + id);
                }

                conn.execute("SELECT 1");
            } catch (RuntimeException e) {
                // Exception handled, but connection still safe
            } catch (InterruptedException e) {
                Thread.currentThread().interrupt();
            } finally {
                // FIX: Always return connection, even on exception
                if (conn != null) {
                    pool.release(conn);
                }
            }
        }
    }

    public static void main(String[] args) throws InterruptedException {
        System.out.println("=== Race Condition Demo: Connection Pool Leak ===\n");
        demonstrateBug();
        System.out.println();
        demonstrateFix();
    }

    static void demonstrateBug() throws InterruptedException {
        System.out.println("--- BUGGY VERSION (no try-finally) ---");
        System.out.println("Threads crash without returning connections.\n");

        ConcurrentConnectionPool pool = new ConcurrentConnectionPool(5, 200);
        AtomicInteger leaks = new AtomicInteger(0);
        int threadCount = 15;

        CountDownLatch done = new CountDownLatch(threadCount);
        for (int i = 0; i < threadCount; i++) {
            final int id = i;
            new Thread(() -> {
                new BuggyWorker(pool, id, leaks).run();
                done.countDown();
            }).start();
        }
        done.await();

        System.out.println("Pool size: 5");
        System.out.println("Threads that crashed: " + leaks.get());
        System.out.println("Connections leaked (never returned): " + leaks.get());
        System.out.println("Pool active connections: " + pool.getActiveCount());
        System.out.println("Pool idle connections: " + pool.getIdleCount());
        System.out.println("BUG: " + leaks.get() + " connections permanently lost from pool!");
        System.out.println("Eventually, all connections leak and pool becomes unusable.");
        pool.shutdown();
    }

    static void demonstrateFix() throws InterruptedException {
        System.out.println("--- FIXED VERSION (try-finally guarantees return) ---");
        System.out.println("Threads crash but connections are always returned.\n");

        ConcurrentConnectionPool pool = new ConcurrentConnectionPool(5, 200);
        int threadCount = 15;

        CountDownLatch done = new CountDownLatch(threadCount);
        for (int i = 0; i < threadCount; i++) {
            final int id = i;
            new Thread(() -> {
                new FixedWorker(pool, id).run();
                done.countDown();
            }).start();
        }
        done.await();

        System.out.println("Pool size: 5");
        System.out.println("Pool active connections: " + pool.getActiveCount());
        System.out.println("Pool idle connections: " + pool.getIdleCount());
        boolean healthy = pool.getActiveCount() == 0 && pool.getIdleCount() == 5;
        System.out.println("FIX VERIFIED: All connections returned despite crashes. Pool healthy: " + healthy);
        pool.shutdown();
    }
}

// concurrent/model/Connection.java — Simulated database connection

import java.util.concurrent.atomic.AtomicInteger;
import java.util.concurrent.atomic.AtomicBoolean;

class Connection {
    private static final AtomicInteger counter = new AtomicInteger(0); // static = shared across all instances; AtomicInteger = thread-safe ID generator
    private final String connectionId;          // final = set once; safe for threads to read without synchronization
    private final AtomicBoolean inUse = new AtomicBoolean(false); // AtomicBoolean = CAS-based acquire/release; no locks needed
    private final long createdAt;               // final = immutable timestamp; safe publication
    private volatile long lastUsedAt;           // volatile = visible to all threads immediately when updated
    private volatile boolean closed = false;    // volatile = shutdown flag seen by all threads instantly

    public Connection() {
        this.connectionId = "CONN-" + counter.incrementAndGet();
        this.createdAt = System.currentTimeMillis();
        this.lastUsedAt = this.createdAt;
    }

    public boolean acquire() {
        return inUse.compareAndSet(false, true); // CAS = only one thread can acquire; others get false
    }

    public void release() {
        lastUsedAt = System.currentTimeMillis();
        inUse.set(false);
    }

    public void close() {
        closed = true;
    }

    public boolean isInUse() { return inUse.get(); }
    public boolean isClosed() { return closed; }
    public String getConnectionId() { return connectionId; }
    public long getCreatedAt() { return createdAt; }
    public long getLastUsedAt() { return lastUsedAt; }

    /**
     * Simulate executing a query on this connection.
     */
    public String execute(String query) {
        if (closed) throw new IllegalStateException("Connection is closed");
        if (!inUse.get()) throw new IllegalStateException("Connection not acquired");
        lastUsedAt = System.currentTimeMillis();
        return "Result of: " + query + " [via " + connectionId + "]";
    }

    @Override
    public String toString() {
        return connectionId + (inUse.get() ? " [IN USE]" : " [IDLE]");
    }

    public static void resetCounter() { counter.set(0); }
}

// concurrent/service/ConcurrentConnectionPool.java — Semaphore for bounding, BlockingQueue for idle connections

import java.util.concurrent.*;
import java.util.concurrent.atomic.AtomicInteger;

/**
 * Thread-safe connection pool using:
 * - Semaphore: bounds the total number of connections that can be acquired
 * - BlockingQueue: efficiently hands out idle connections (threads block if none available)
 * - AtomicInteger: tracks pool statistics without locks
 */
class ConcurrentConnectionPool {
    private final int maxSize;                  // final = immutable config; safe for all threads to read
    private final long timeoutMillis;           // final = immutable; no synchronization needed
    private final Semaphore semaphore;          // Semaphore = bounds concurrent access; fair=true for FIFO ordering
    private final BlockingQueue<Connection> idleConnections; // BlockingQueue = thread-safe; threads block when empty
    private final AtomicInteger totalCreated = new AtomicInteger(0); // AtomicInteger = lock-free counter
    private final AtomicInteger activeCount = new AtomicInteger(0);  // AtomicInteger = thread-safe active tracking
    private final AtomicInteger waitCount = new AtomicInteger(0);
    private final AtomicInteger timeoutCount = new AtomicInteger(0);
    private volatile boolean shutdown = false;  // volatile = shutdown flag visible to all threads immediately

    public ConcurrentConnectionPool(int maxSize, long timeoutMillis) {
        this.maxSize = maxSize;
        this.timeoutMillis = timeoutMillis;
        this.semaphore = new Semaphore(maxSize, true); // fair=true ensures FIFO; longest-waiting thread acquires first
        this.idleConnections = new LinkedBlockingQueue<>();

        // Pre-create all connections
        for (int i = 0; i < maxSize; i++) {
            Connection conn = new Connection();
            idleConnections.offer(conn);
            totalCreated.incrementAndGet();
        }
    }

    /**
     * Acquire a connection from the pool.
     * Blocks up to timeoutMillis if all connections are in use.
     * Returns null if timeout expires (pool exhaustion).
     */
    public Connection acquire() throws InterruptedException {
        if (shutdown) throw new IllegalStateException("Pool is shut down");

        waitCount.incrementAndGet();
        try {
            if (!semaphore.tryAcquire(timeoutMillis, TimeUnit.MILLISECONDS)) { // tryAcquire = blocks up to timeout; no busy-wait
                timeoutCount.incrementAndGet();
                return null; // Pool exhausted — timeout
            }
        } finally {
            waitCount.decrementAndGet();
        }

        Connection conn = idleConnections.poll();
        if (conn == null || conn.isClosed()) {
            // Create a new connection if needed
            conn = new Connection();
            totalCreated.incrementAndGet();
        }
        conn.acquire();
        activeCount.incrementAndGet();
        return conn;
    }

    /**
     * Return a connection to the pool.
     */
    public void release(Connection conn) {
        if (conn == null) return;
        conn.release();
        activeCount.decrementAndGet();
        if (!shutdown) {
            idleConnections.offer(conn);
        } else {
            conn.close();
        }
        semaphore.release();
    }

    public void shutdown() {
        shutdown = true;
        Connection conn;
        while ((conn = idleConnections.poll()) != null) {
            conn.close();
        }
    }

    public int getMaxSize() { return maxSize; }
    public int getActiveCount() { return activeCount.get(); }
    public int getIdleCount() { return idleConnections.size(); }
    public int getWaitCount() { return waitCount.get(); }
    public int getTimeoutCount() { return timeoutCount.get(); }
    public int getTotalCreated() { return totalCreated.get(); }
}

