// Main.java — Demonstrates thread pool with basic synchronized queue approach
public class Main {
    public static void main(String[] args) throws InterruptedException {
        System.out.println("=== Thread Pool (Naive) Demo ===\n");

        // --- Test 1: Basic Task Execution ---
        System.out.println("--- Test 1: Basic Task Execution ---");
        PoolConfig config = new PoolConfig(3, 5, 10, 5000);
        ThreadPool pool = new ThreadPool(config);

        for (int i = 1; i <= 5; i++) {
            final int taskId = i;
            pool.submit(new Task() {
                @Override public String getName() { return "Task-" + taskId; }
                @Override public void execute() {
                    System.out.println("  " + getName() + " executed by " + Thread.currentThread().getName());
                    try { Thread.sleep(100); } catch (InterruptedException e) { Thread.currentThread().interrupt(); }
                }
            });
        }
        Thread.sleep(800);
        pool.shutdownNow();

        // --- Test 2: Rejection Policies ---
        System.out.println("\n--- Test 2: Rejection Policies ---");
        Task slowTask = new Task() {
            @Override public String getName() { return "SlowTask"; }
            @Override public void execute() {
                try { Thread.sleep(5000); } catch (InterruptedException e) { Thread.currentThread().interrupt(); }
            }
        };

        ThreadPool abortPool = new ThreadPool(new PoolConfig(1, 1, 2, 1000));
        abortPool.setRejectionPolicy(new AbortPolicy());
        abortPool.submit(slowTask);
        Thread.sleep(50);
        abortPool.submit(slowTask);
        abortPool.submit(slowTask);
        try {
            abortPool.submit(slowTask);
        } catch (RuntimeException e) {
            System.out.println("  " + e.getMessage());
        }
        abortPool.shutdownNow();

        // --- Test 3: Pool Statistics ---
        System.out.println("\n--- Test 3: Pool Statistics ---");
        ThreadPool statsPool = new ThreadPool(new PoolConfig(3, 5, 20, 5000));
        for (int i = 1; i <= 10; i++) {
            final int id = i;
            statsPool.submit(new Task() {
                @Override public String getName() { return "StatsTask-" + id; }
                @Override public void execute() {
                    try { Thread.sleep(50); } catch (InterruptedException e) { Thread.currentThread().interrupt(); }
                }
            });
        }
        Thread.sleep(100);
        System.out.println("  Mid-execution: " + statsPool.getStats());
        Thread.sleep(600);
        System.out.println("  After completion: " + statsPool.getStats());
        statsPool.shutdownNow();

        System.out.println("\n=== Thread Pool (Naive) Demo Complete ===");
    }
}

// model/CompletionCallback.java — Observer notified when a task finishes execution
public interface CompletionCallback { // interface = contract any listener must implement
    void onComplete(Task task);
    void onError(Task task, Exception e);
}

// model/PoolConfig.java — Configuration for pool size, queue capacity, and keep-alive time
public class PoolConfig {
    private final int coreSize;          // final = value set once in constructor, never changes
    private final int maxSize;           // private = only this class can read/write these fields
    private final int queueCapacity;     // final = guarantees immutability after construction
    private final long keepAliveTimeMs;  // private final = safe to share across threads without locks

    public PoolConfig(int coreSize, int maxSize, int queueCapacity, long keepAliveTimeMs) {
        if (coreSize <= 0 || maxSize < coreSize || queueCapacity <= 0) {
            throw new IllegalArgumentException("Invalid pool configuration");
        }
        this.coreSize = coreSize;
        this.maxSize = maxSize;
        this.queueCapacity = queueCapacity;
        this.keepAliveTimeMs = keepAliveTimeMs;
    }

    public int getCoreSize() { return coreSize; }
    public int getMaxSize() { return maxSize; }
    public int getQueueCapacity() { return queueCapacity; }
    public long getKeepAliveTimeMs() { return keepAliveTimeMs; }

    @Override
    public String toString() {
        return String.format("PoolConfig[core=%d, max=%d, queue=%d, keepAlive=%dms]",
                coreSize, maxSize, queueCapacity, keepAliveTimeMs);
    }
}

// model/Task.java — Unit of work to be executed by the pool
public interface Task { // interface = contract; any task must provide these methods
    String getName();
    void execute();
}

// model/ThreadPoolStats.java — Runtime statistics for pool health and throughput
import java.util.concurrent.atomic.AtomicInteger;
import java.util.concurrent.atomic.AtomicLong;

public class ThreadPoolStats {
    private final AtomicInteger activeThreads = new AtomicInteger(0);  // private = encapsulated; final = reference never reassigned
    private final AtomicInteger queuedTasks = new AtomicInteger(0);   // AtomicInteger = thread-safe counter
    private final AtomicLong completedTasks = new AtomicLong(0);      // AtomicLong = thread-safe for larger counts
    private final AtomicLong failedTasks = new AtomicLong(0);
    private final AtomicLong rejectedTasks = new AtomicLong(0);

    public void incrementActive() { activeThreads.incrementAndGet(); }
    public void decrementActive() { activeThreads.decrementAndGet(); }
    public void incrementQueued() { queuedTasks.incrementAndGet(); }
    public void decrementQueued() { queuedTasks.decrementAndGet(); }
    public void incrementCompleted() { completedTasks.incrementAndGet(); }
    public void incrementFailed() { failedTasks.incrementAndGet(); }
    public void incrementRejected() { rejectedTasks.incrementAndGet(); }

    public int getActiveThreads() { return activeThreads.get(); }
    public int getQueuedTasks() { return queuedTasks.get(); }
    public long getCompletedTasks() { return completedTasks.get(); }
    public long getFailedTasks() { return failedTasks.get(); }
    public long getRejectedTasks() { return rejectedTasks.get(); }

    @Override
    public String toString() {
        return String.format("ThreadPoolStats[active=%d, queued=%d, completed=%d, failed=%d, rejected=%d]",
                activeThreads.get(), queuedTasks.get(), completedTasks.get(),
                failedTasks.get(), rejectedTasks.get());
    }
}

// service/TaskQueue.java — Thread-safe synchronized queue for buffering submitted tasks
import java.util.LinkedList;
import java.util.Queue;

public class TaskQueue {
    private final Queue<Task> queue = new LinkedList<>(); // private final = only this class uses it; reference never changes
    private final int capacity;

    public TaskQueue(int capacity) {
        this.capacity = capacity;
    }

    public synchronized boolean offer(Task task) { // synchronized = only one thread can enter at a time
        if (queue.size() >= capacity) {
            return false;
        }
        queue.add(task);
        notifyAll();
        return true;
    }

    public synchronized Task poll(long timeoutMs) throws InterruptedException { // synchronized = mutual exclusion on this object
        long deadline = System.currentTimeMillis() + timeoutMs;
        while (queue.isEmpty()) {
            long remaining = deadline - System.currentTimeMillis();
            if (remaining <= 0) {
                return null;
            }
            wait(remaining);
        }
        return queue.poll();
    }

    public synchronized Task poll() throws InterruptedException {
        while (queue.isEmpty()) {
            wait();
        }
        return queue.poll();
    }

    public synchronized int size() {
        return queue.size();
    }

    public synchronized boolean isEmpty() {
        return queue.isEmpty();
    }

    public synchronized void clear() {
        queue.clear();
    }

    public synchronized void wakeAll() {
        notifyAll();
    }
}

// service/ThreadPool.java — Manages worker threads and dispatches tasks from a single shared queue
import java.util.ArrayList;
import java.util.List;

public class ThreadPool {
    private final PoolConfig config;                   // private final = only this class uses; never reassigned
    private final TaskQueue taskQueue;                 // final = reference fixed; contents change via synchronized
    private final List<Worker> workers;                // private = internal detail hidden from outside
    private final ThreadPoolStats stats;
    private RejectionPolicy rejectionPolicy;           // private = can only be changed via setter method
    private CompletionCallback completionCallback;
    private volatile boolean shutdown = false;          // volatile = all threads see updated value immediately

    public ThreadPool(PoolConfig config) {
        this.config = config;
        this.taskQueue = new TaskQueue(config.getQueueCapacity());
        this.workers = new ArrayList<>();
        this.stats = new ThreadPoolStats();
        this.rejectionPolicy = new AbortPolicy();
        System.out.println("[Pool] Created with core=" + config.getCoreSize() +
                ", max=" + config.getMaxSize() + ", queueCapacity=" + config.getQueueCapacity());
        initCoreWorkers();
    }

    private void initCoreWorkers() {
        for (int i = 0; i < config.getCoreSize(); i++) {
            Worker worker = new Worker("pool-worker-" + (i + 1), taskQueue, stats, completionCallback);
            workers.add(worker);
            worker.start();
        }
    }

    public void setRejectionPolicy(RejectionPolicy policy) {
        this.rejectionPolicy = policy;
    }

    public void setCompletionCallback(CompletionCallback callback) {
        this.completionCallback = callback;
    }

    public void submit(Task task) {
        if (shutdown) {
            throw new IllegalStateException("Pool is shut down, cannot accept tasks");
        }
        boolean queued = taskQueue.offer(task);
        if (queued) {
            stats.incrementQueued();
        } else {
            synchronized (workers) {
                if (workers.size() < config.getMaxSize()) {
                    Worker worker = new Worker("pool-worker-" + (workers.size() + 1),
                            taskQueue, stats, completionCallback);
                    workers.add(worker);
                    worker.start();
                    queued = taskQueue.offer(task);
                    if (queued) {
                        stats.incrementQueued();
                        return;
                    }
                }
            }
            stats.incrementRejected();
            rejectionPolicy.reject(task, this);
        }
    }

    public void shutdown() {
        shutdown = true;
        System.out.println("Pool shutting down gracefully...");
        while (!taskQueue.isEmpty()) {
            try { Thread.sleep(50); } catch (InterruptedException e) { Thread.currentThread().interrupt(); break; }
        }
        try { Thread.sleep(200); } catch (InterruptedException e) { Thread.currentThread().interrupt(); }
        for (Worker worker : workers) { worker.shutdown(); }
        for (Worker worker : workers) {
            try { worker.join(1000); } catch (InterruptedException e) { Thread.currentThread().interrupt(); }
        }
        System.out.println("All tasks completed. Pool terminated.");
    }

    public void shutdownNow() {
        shutdown = true;
        taskQueue.clear();
        for (Worker worker : workers) { worker.shutdown(); }
    }

    public boolean isShutdown() { return shutdown; }
    public ThreadPoolStats getStats() { return stats; }
    public PoolConfig getConfig() { return config; }
}

// service/Worker.java — Long-lived thread that pulls and executes tasks from a shared queue
public class Worker extends Thread { // extends Thread = this IS a thread; can be started directly
    private final TaskQueue taskQueue;       // private final = only this worker uses; never reassigned
    private final ThreadPoolStats stats;
    private final CompletionCallback callback;
    private volatile boolean running = true; // volatile = shutdown() in another thread is seen immediately

    public Worker(String name, TaskQueue taskQueue, ThreadPoolStats stats, CompletionCallback callback) {
        super(name);
        this.taskQueue = taskQueue;
        this.stats = stats;
        this.callback = callback;
        setDaemon(true);
    }

    @Override // @Override = compiler checks this actually overrides Thread.run()
    public void run() {
        while (running) {
            try {
                Task task = taskQueue.poll(500);
                if (task == null) {
                    continue;
                }
                stats.decrementQueued();
                stats.incrementActive();
                try {
                    task.execute();
                    stats.incrementCompleted();
                    if (callback != null) {
                        callback.onComplete(task);
                    }
                } catch (Exception e) {
                    stats.incrementFailed();
                    if (callback != null) {
                        callback.onError(task, e);
                    }
                } finally {
                    stats.decrementActive();
                }
            } catch (InterruptedException e) {
                Thread.currentThread().interrupt();
                break;
            }
        }
    }

    public void shutdown() {
        running = false;
        interrupt();
    }

    public boolean isRunning() {
        return running;
    }
}

// strategy/RejectionPolicy.java — Configurable behavior when task queue is full
public interface RejectionPolicy { // interface = contract; each policy provides its own reject logic
    void reject(Task task, ThreadPool pool);
}

class AbortPolicy implements RejectionPolicy { // implements = fulfills the RejectionPolicy contract
    @Override // @Override = guarantees this method matches the interface signature
    public void reject(Task task, ThreadPool pool) {
        throw new RuntimeException("[AbortPolicy] Task rejected: queue is full - " + task.getName());
    }
}

class CallerRunsPolicy implements RejectionPolicy { // implements = this class fulfills the policy contract
    @Override
    public void reject(Task task, ThreadPool pool) {
        if (!pool.isShutdown()) {
            System.out.println("[CallerRunsPolicy] Running task '" + task.getName() + "' in caller thread");
            task.execute();
        }
    }
}

class DiscardPolicy implements RejectionPolicy { // implements = another variant of the same contract
    @Override
    public void reject(Task task, ThreadPool pool) {
        System.out.println("[DiscardPolicy] Task silently discarded: " + task.getName());
    }
}

