public interface Task { // interface = contract any submitted task must fulfill
    String getName();
    void execute();
}

// service/StealingWorker.java — Worker with its own deque; steals from peers when idle
public class StealingWorker extends Thread { // extends Thread = each worker IS its own thread
    private final int index;                   // identifies this worker for round-robin and steal-avoidance
    private final WorkStealingDeque localDeque; // per-worker deque eliminates shared-queue contention
    private final WorkStealingPool pool;        // reference back to pool for cross-worker stealing
    private final PoolStats stats;
    private volatile boolean running = true;    // volatile = shutdown signal visible across threads instantly

    public StealingWorker(int index, WorkStealingDeque localDeque, WorkStealingPool pool, PoolStats stats) {
        super("steal-worker-" + index);
        this.index = index;
        this.localDeque = localDeque;
        this.pool = pool;
        this.stats = stats;
        setDaemon(true);
    }

    @Override
    public void run() {
        while (running) {
            Task task = localDeque.pop();

            // WHY: If own queue is empty, steal from a random peer.
            // This balances load without centralized scheduling.
            if (task == null) {
                task = pool.stealFrom(index);
                if (task != null) {
                    stats.recordSteal();
                }
            }

            if (task != null) {
                try {
                    task.execute();
                    stats.recordComplete();
                } catch (Exception e) {
                    stats.recordFailure();
                }
            } else {
                // WHY: Brief park avoids busy-spin when all queues are empty
                try { Thread.sleep(1); } catch (InterruptedException e) {
                    Thread.currentThread().interrupt();
                    break;
                }
            }
        }
    }

    public WorkStealingDeque getDeque() { return localDeque; }
    public int getIndex() { return index; }

    public void shutdown() {
        running = false;
        interrupt();
    }
}

// service/WorkStealingDeque.java — Lock-free per-worker deque supporting push/pop (owner) and steal (thieves)
import java.util.concurrent.atomic.AtomicInteger;

public class WorkStealingDeque {
    // WHY: Per-worker deques eliminate contention on a single shared queue.
    // The owner pushes/pops from the bottom (no lock needed for LIFO locality),
    // while thieves steal from the top using CAS to avoid locks.
    private final Task[] buffer;                                // fixed-size array = no allocation during runtime
    private final AtomicInteger top = new AtomicInteger(0);    // AtomicInteger = thieves CAS here to steal safely
    private volatile int bottom = 0;                            // volatile = owner writes, stealers read; no CAS needed

    public WorkStealingDeque(int capacity) {
        this.buffer = new Task[capacity];
    }

    // Called only by the owning worker thread — no synchronization needed for bottom
    public void push(Task task) {
        int b = bottom;
        buffer[b % buffer.length] = task;
        bottom = b + 1;
    }

    // Called only by the owning worker — pops from bottom (LIFO for cache locality)
    public Task pop() {
        int b = bottom - 1;
        bottom = b;
        int t = top.get();

        if (t <= b) {
            Task task = buffer[b % buffer.length];
            if (t == b) {
                // Last element — compete with stealers via CAS
                if (!top.compareAndSet(t, t + 1)) {
                    // Lost race to stealer
                    bottom = t + 1;
                    return null;
                }
                bottom = t + 1;
            }
            return task;
        } else {
            // Deque is empty
            bottom = t;
            return null;
        }
    }

    // Called by other workers — steals from top (FIFO to preserve fairness)
    public Task steal() {
        int t = top.get();
        int b = bottom;
        if (t < b) {
            Task task = buffer[t % buffer.length];
            // WHY CAS: Multiple thieves may race; only one wins without locks
            if (top.compareAndSet(t, t + 1)) {
                return task;
            }
        }
        return null;
    }

    public int size() {
        return Math.max(0, bottom - top.get());
    }

    public boolean isEmpty() {
        return top.get() >= bottom;
    }
}

// service/WorkStealingPool.java — Pool with per-worker deques and work-stealing for load balancing
import java.util.concurrent.atomic.AtomicInteger;

public class WorkStealingPool {
    private final StealingWorker[] workers;                     // array = O(1) access by index for stealing
    private final PoolStats stats;
    private final AtomicInteger nextWorker = new AtomicInteger(0); // AtomicInteger = lock-free round-robin counter
    private volatile boolean shutdown = false;                  // volatile = all workers see shutdown immediately

    // WHY: Each worker has its own deque, eliminating the single-queue bottleneck.
    // Submissions are round-robin distributed; idle workers steal from busy ones.
    public WorkStealingPool(PoolConfig config) {
        this.stats = new PoolStats();
        this.workers = new StealingWorker[config.getWorkerCount()];
        for (int i = 0; i < config.getWorkerCount(); i++) {
            WorkStealingDeque deque = new WorkStealingDeque(config.getLocalQueueCapacity());
            workers[i] = new StealingWorker(i, deque, this, stats);
            workers[i].start();
        }
        System.out.println("[WorkStealingPool] Started " + config.getWorkerCount() + " workers");
    }

    // WHY: Round-robin submission distributes tasks evenly across workers without locking
    public void submit(Task task) {
        if (shutdown) {
            throw new IllegalStateException("Pool is shut down");
        }
        int idx = Math.abs(nextWorker.getAndIncrement() % workers.length);
        workers[idx].getDeque().push(task);
        stats.recordSubmit();
    }

    // Called by idle workers to steal from a random peer
    Task stealFrom(int callerIndex) {
        // WHY: Random victim selection avoids thundering-herd on one queue
        int start = (callerIndex + 1) % workers.length;
        for (int i = 0; i < workers.length - 1; i++) {
            int victim = (start + i) % workers.length;
            Task stolen = workers[victim].getDeque().steal();
            if (stolen != null) {
                return stolen;
            }
        }
        return null;
    }

    public void shutdown() {
        shutdown = true;
        // Wait for queues to drain
        boolean allEmpty;
        do {
            allEmpty = true;
            for (StealingWorker w : workers) {
                if (!w.getDeque().isEmpty()) {
                    allEmpty = false;
                    break;
                }
            }
            if (!allEmpty) {
                try { Thread.sleep(10); } catch (InterruptedException e) { break; }
            }
        } while (!allEmpty);

        try { Thread.sleep(100); } catch (InterruptedException e) { Thread.currentThread().interrupt(); }
        for (StealingWorker w : workers) { w.shutdown(); }
        System.out.println("[WorkStealingPool] Shut down. " + stats);
    }

    public void shutdownNow() {
        shutdown = true;
        for (StealingWorker w : workers) { w.shutdown(); }
    }

    public PoolStats getStats() { return stats; }
    public boolean isShutdown() { return shutdown; }
}

// concurrent/Main.java — Submits tasks, triggers shutdown, shows some are rejected properly

import java.util.*;
import java.util.concurrent.CountDownLatch;
import java.util.concurrent.TimeUnit;
import java.util.concurrent.atomic.AtomicInteger;

public class Main {
    public static void main(String[] args) throws InterruptedException {
        System.out.println("=== Concurrent Thread Pool Demo ===\n");

        int poolSize = 4;
        int queueCapacity = 10;
        ConcurrentThreadPool pool = new ConcurrentThreadPool(poolSize, queueCapacity, new DiscardPolicy());

        List<Task> allTasks = Collections.synchronizedList(new ArrayList<>());
        AtomicInteger rejectedAfterShutdown = new AtomicInteger(0);

        System.out.println("Pool: " + poolSize + " workers, queue capacity: " + queueCapacity);
        System.out.println("Scenario: Submit 20 tasks, then shutdown, then try 10 more.\n");

        // Phase 1: Submit 20 tasks (some will execute, some will queue)
        System.out.println("--- Phase 1: Submitting 20 tasks before shutdown ---");
        for (int i = 0; i < 20; i++) {
            Task task = new Task("Work-" + i, 50); // Each task takes 50ms
            allTasks.add(task);
            pool.submit(task);
        }
        System.out.println("Submitted 20 tasks.");
        System.out.println("Queue size after submission: " + pool.getQueueSize());

        // Phase 2: Initiate shutdown
        Thread.sleep(100); // Let some tasks start executing
        System.out.println("\n--- Phase 2: Initiating shutdown ---");
        pool.shutdown();
        System.out.println("Shutdown initiated. Queue size: " + pool.getQueueSize());

        // Phase 3: Try to submit more tasks (should be rejected)
        System.out.println("\n--- Phase 3: Submitting 10 tasks after shutdown ---");
        for (int i = 20; i < 30; i++) {
            Task task = new Task("Late-" + i, 50);
            allTasks.add(task);
            try {
                pool.submit(task);
            } catch (RejectedTaskException e) {
                // Expected with AbortPolicy
            }
            if (task.isRejected()) {
                rejectedAfterShutdown.incrementAndGet();
            }
        }
        System.out.println("Rejected after shutdown: " + rejectedAfterShutdown.get());

        // Wait for graceful termination
        boolean terminated = pool.awaitTermination(5, TimeUnit.SECONDS);
        System.out.println("\n--- Phase 4: Awaiting termination ---");
        System.out.println("Graceful termination: " + (terminated ? "SUCCESS" : "TIMED OUT"));

        // Summary
        long executed = allTasks.stream().filter(Task::isExecuted).count();
        long rejected = allTasks.stream().filter(Task::isRejected).count();
        long pending = allTasks.stream().filter(t -> !t.isExecuted() && !t.isRejected()).count();

        System.out.println("\n--- Summary ---");
        System.out.println("Total tasks created: " + allTasks.size());
        System.out.println("Executed: " + executed);
        System.out.println("Rejected: " + rejected);
        System.out.println("Pending (never ran): " + pending);
        System.out.println("Pool stats — submitted: " + pool.getSubmittedCount() +
                ", executed: " + pool.getExecutedCount() + ", rejected: " + pool.getRejectedCount());

        // Correctness: no task both executed AND rejected
        boolean noConflicts = allTasks.stream().noneMatch(t -> t.isExecuted() && t.isRejected());
        boolean shutdownTasksRejected = rejectedAfterShutdown.get() == 10;
        System.out.println("\nNo execute+reject conflicts: " + (noConflicts ? "PASSED" : "FAILED"));
        System.out.println("All post-shutdown tasks rejected: " + (shutdownTasksRejected ? "PASSED" : "FAILED"));
    }
}

// concurrent/model/Task.java — A unit of work submitted to the thread pool

import java.util.concurrent.atomic.AtomicInteger;

class Task implements Runnable { // implements Runnable = can be passed to a Thread for execution
    private static final AtomicInteger counter = new AtomicInteger(0); // static final = shared ID generator across all Task instances
    private final String taskId;           // final = assigned once; safe to read from any thread
    private final String name;             // final = safe publication; no synchronization needed to read
    private final long executionTimeMs;
    private volatile boolean executed = false;  // volatile = worker thread sets, main thread reads immediately
    private volatile boolean rejected = false;  // volatile = rejection visible across threads without lock
    private volatile String executedBy = null;  // volatile = ensures happens-before when read by another thread

    public Task(String name, long executionTimeMs) {
        this.taskId = "TASK-" + counter.incrementAndGet();
        this.name = name;
        this.executionTimeMs = executionTimeMs;
    }

    @Override
    public void run() {
        executedBy = Thread.currentThread().getName();
        try {
            Thread.sleep(executionTimeMs);
        } catch (InterruptedException e) {
            Thread.currentThread().interrupt();
        }
        executed = true;
    }

    public void markRejected() { this.rejected = true; }

    public String getTaskId() { return taskId; }
    public String getName() { return name; }
    public boolean isExecuted() { return executed; }
    public boolean isRejected() { return rejected; }
    public String getExecutedBy() { return executedBy; }

    @Override
    public String toString() {
        if (rejected) return taskId + " (" + name + ") [REJECTED]";
        if (executed) return taskId + " (" + name + ") [DONE by " + executedBy + "]";
        return taskId + " (" + name + ") [PENDING]";
    }

    public static void resetCounter() { counter.set(0); }
}

// concurrent/service/ConcurrentThreadPool.java — volatile shutdown flag, CountDownLatch for graceful termination

import java.util.concurrent.*;
import java.util.concurrent.atomic.AtomicInteger;

/**
 * Custom thread pool demonstrating:
 * - volatile shutdown flag for visibility across threads
 * - CountDownLatch for graceful termination (wait for workers to finish)
 * - Rejection policies for tasks submitted during/after shutdown
 */
class ConcurrentThreadPool {
    private final int poolSize;
    private final BlockingQueue<Task> taskQueue;       // final = reference never changes; BlockingQueue = thread-safe with blocking
    private final Thread[] workers;                    // final = array ref fixed at construction
    private volatile boolean shutdown = false;          // volatile = all worker threads see this flag immediately
    private final CountDownLatch terminationLatch;     // CountDownLatch = workers count down; awaitTermination blocks until zero
    private final RejectionPolicy rejectionPolicy;
    private final AtomicInteger submittedCount = new AtomicInteger(0); // AtomicInteger = lock-free thread-safe counter
    private final AtomicInteger executedCount = new AtomicInteger(0);
    private final AtomicInteger rejectedCount = new AtomicInteger(0);

    public ConcurrentThreadPool(int poolSize, int queueCapacity, RejectionPolicy policy) {
        this.poolSize = poolSize;
        this.taskQueue = new LinkedBlockingQueue<>(queueCapacity);
        this.workers = new Thread[poolSize];
        this.terminationLatch = new CountDownLatch(poolSize);
        this.rejectionPolicy = policy;

        // Start worker threads
        for (int i = 0; i < poolSize; i++) {
            workers[i] = new Thread(() -> {
                try {
                    while (!shutdown || !taskQueue.isEmpty()) {
                        Task task = taskQueue.poll(100, TimeUnit.MILLISECONDS);
                        if (task != null) {
                            task.run();
                            executedCount.incrementAndGet();
                        }
                    }
                } catch (InterruptedException e) {
                    Thread.currentThread().interrupt();
                } finally {
                    terminationLatch.countDown();
                }
            }, "PoolWorker-" + i);
            workers[i].setDaemon(true);
            workers[i].start();
        }
    }

    /**
     * Submit a task. If pool is shutting down, apply rejection policy.
     */
    public void submit(Task task) {
        if (shutdown) {
            rejectedCount.incrementAndGet();
            rejectionPolicy.reject(task, this);
            return;
        }

        submittedCount.incrementAndGet();
        if (!taskQueue.offer(task)) {
            // Queue full — reject
            rejectedCount.incrementAndGet();
            rejectionPolicy.reject(task, this);
        }
    }

    /**
     * Initiate graceful shutdown.
     * No new tasks accepted, existing tasks in queue will complete.
     */
    public void shutdown() {
        shutdown = true;
    }

    /**
     * Wait for all workers to finish processing remaining tasks.
     */
    public boolean awaitTermination(long timeout, TimeUnit unit) throws InterruptedException {
        return terminationLatch.await(timeout, unit);
    }

    public boolean isShutdown() { return shutdown; }
    public int getSubmittedCount() { return submittedCount.get(); }
    public int getExecutedCount() { return executedCount.get(); }
    public int getRejectedCount() { return rejectedCount.get(); }
    public int getQueueSize() { return taskQueue.size(); }
    public int getPoolSize() { return poolSize; }
}

// concurrent/service/RejectionPolicy.java — Policies for handling rejected tasks

interface RejectionPolicy { // interface = strategy pattern; swap rejection behavior at runtime
    void reject(Task task, ConcurrentThreadPool pool);
}

/**
 * AbortPolicy: Reject the task and throw an exception.
 */
class AbortPolicy implements RejectionPolicy {
    @Override
    public void reject(Task task, ConcurrentThreadPool pool) {
        task.markRejected();
        throw new RejectedTaskException("Task " + task.getTaskId() + " rejected — pool is shutting down");
    }
}

/**
 * CallerRunsPolicy: Execute the task in the caller's thread instead.
 * This provides backpressure — the submitting thread slows down.
 */
class CallerRunsPolicy implements RejectionPolicy {
    @Override
    public void reject(Task task, ConcurrentThreadPool pool) {
        if (!pool.isShutdown()) {
            task.run(); // Run in the caller's thread
        } else {
            task.markRejected();
        }
    }
}

/**
 * DiscardPolicy: Silently discard the rejected task.
 */
class DiscardPolicy implements RejectionPolicy {
    @Override
    public void reject(Task task, ConcurrentThreadPool pool) {
        task.markRejected();
        // Silently discarded
    }
}

class RejectedTaskException extends RuntimeException { // extends = inherits from RuntimeException (unchecked)
    public RejectedTaskException(String message) {
        super(message);
    }
}

