// service/BatchConsumer.java — Consumes items in batches for higher throughput
public class BatchConsumer implements Runnable { // Runnable = can be submitted to a Thread
    private final String name;
    private final LockFreeRingBuffer buffer; // ring buffer = fixed memory, no GC pressure
    private final int totalItems;
    private final int batchSize;             // batch draining reduces per-item CAS overhead
    private volatile boolean running = true;  // volatile = stop signal visible across threads
    private int consumed = 0;

    // WHY batch consume: Reduces contention by draining multiple items
    // per wake cycle rather than one-at-a-time with context switches
    public BatchConsumer(String name, LockFreeRingBuffer buffer, int totalItems, int batchSize) {
        this.name = name;
        this.buffer = buffer;
        this.totalItems = totalItems;
        this.batchSize = batchSize;
    }

    @Override
    public void run() {
        try {
            while (consumed < totalItems && running) {
                int batchConsumed = 0;
                // WHY: Drain up to batchSize in a tight loop without sleeping
                while (batchConsumed < batchSize && consumed < totalItems) {
                    Item item = buffer.poll();
                    if (item != null) {
                        consumed++;
                        batchConsumed++;
                    } else {
                        // Nothing available — brief yield instead of blocking
                        if (batchConsumed > 0) break;
                        Thread.yield();
                    }
                }
                if (batchConsumed > 0) {
                    System.out.println("  " + name + " consumed batch of " + batchConsumed + ", total=" + consumed);
                }
            }
        } catch (Exception e) {
            Thread.currentThread().interrupt();
        }
        System.out.println("  " + name + " done. Consumed: " + consumed);
    }

    public void stop() { running = false; }
    public String getName() { return name; }
    public int getConsumed() { return consumed; }
}

// service/BatchProducer.java — Produces items in batches to reduce per-item overhead
public class BatchProducer implements Runnable { // Runnable = can be executed by a Thread
    private final String name;
    private final LockFreeRingBuffer buffer; // CAS-based ring buffer = no locks on hot path
    private final int totalItems;
    private final int batchSize;             // batching amortizes CAS cost over multiple items
    private volatile boolean running = true;  // volatile = cancellation flag visible to all threads

    // WHY batch: Amortizes the CAS cost over multiple items,
    // improving throughput by reducing per-item atomic operations
    public BatchProducer(String name, LockFreeRingBuffer buffer, int totalItems, int batchSize) {
        this.name = name;
        this.buffer = buffer;
        this.totalItems = totalItems;
        this.batchSize = batchSize;
    }

    @Override
    public void run() {
        int produced = 0;
        try {
            while (produced < totalItems && running) {
                int batchEnd = Math.min(produced + batchSize, totalItems);
                // WHY: Produce a batch without yielding between items
                for (int i = produced; i < batchEnd; i++) {
                    Item item = new Item(name + "-" + (i + 1), "batch-data");
                    // Spin-wait if buffer is full (backpressure)
                    while (!buffer.offer(item) && running) {
                        Thread.yield();
                    }
                }
                produced = batchEnd;
                System.out.println("  " + name + " produced batch, total=" + produced);
            }
        } catch (Exception e) {
            Thread.currentThread().interrupt();
        }
        System.out.println("  " + name + " done. Produced: " + produced);
    }

    public void stop() { running = false; }
    public String getName() { return name; }
}

// service/LockFreeRingBuffer.java — CAS-based ring buffer for single-producer/single-consumer (SPSC)
import java.util.concurrent.atomic.AtomicLong;

public class LockFreeRingBuffer {
    // WHY power-of-2: Allows bitwise AND for modulo (faster than %)
    private final Item[] buffer;                         // fixed array = zero GC allocation during operation
    private final int mask;                              // mask = capacity-1; used for fast index wrapping via &

    // WHY separate atomics: Producer only writes head, consumer only writes tail.
    // Each lives on its own cache line to avoid false sharing in a real JVM.
    private final AtomicLong head = new AtomicLong(0); // AtomicLong = CAS-based lock-free write position
    private final AtomicLong tail = new AtomicLong(0); // AtomicLong = CAS-based lock-free read position

    public LockFreeRingBuffer(int capacityPowerOf2) {
        // WHY: Power of 2 size enables bit masking instead of modulo
        int capacity = Integer.highestOneBit(capacityPowerOf2);
        this.buffer = new Item[capacity];
        this.mask = capacity - 1;
    }

    // WHY CAS loop: Multiple producers can attempt simultaneously;
    // CAS ensures only one wins the slot, others retry.
    public boolean offer(Item item) {
        long currentHead;
        do {
            currentHead = head.get();
            long currentTail = tail.get();
            // Buffer full when head is one full cycle ahead of tail
            if (currentHead - currentTail >= buffer.length) {
                return false; // Full — caller decides to retry or block
            }
        } while (!head.compareAndSet(currentHead, currentHead + 1));

        // WHY: We reserved the slot atomically, now write without contention
        buffer[(int)(currentHead & mask)] = item;
        return true;
    }

    // WHY CAS loop: Multiple consumers race for the same slot
    public Item poll() {
        long currentTail;
        do {
            currentTail = tail.get();
            long currentHead = head.get();
            if (currentTail >= currentHead) {
                return null; // Empty
            }
        } while (!tail.compareAndSet(currentTail, currentTail + 1));

        // Spin until the producer finishes writing to this slot
        Item item;
        int idx = (int)(currentTail & mask);
        while ((item = buffer[idx]) == null) {
            Thread.yield();
        }
        buffer[idx] = null; // Clear slot for reuse
        return item;
    }

    public int size() {
        return (int)(head.get() - tail.get());
    }

    public boolean isEmpty() { return head.get() <= tail.get(); }
    public boolean isFull() { return head.get() - tail.get() >= buffer.length; }
    public int capacity() { return buffer.length; }
}

// concurrent/Main.java — Multiple producers + consumers, verifies no lost items, no duplicates

import java.util.*;
import java.util.concurrent.CountDownLatch;
import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.atomic.AtomicInteger;

public class Main {
    public static void main(String[] args) throws InterruptedException {
        System.out.println("=== Concurrent Producer-Consumer Demo ===\n");

        demonstrateBoundedBuffer();
        System.out.println();
        demonstrateLockFreeBuffer();
    }

    static void demonstrateBoundedBuffer() throws InterruptedException {
        System.out.println("--- Lock-Based Bounded Buffer (ReentrantLock + Condition) ---");

        int bufferSize = 5;
        int producerCount = 4;
        int consumerCount = 4;
        int itemsPerProducer = 100;
        int totalItems = producerCount * itemsPerProducer;

        BoundedBuffer buffer = new BoundedBuffer(bufferSize);
        Set<Integer> consumedIds = ConcurrentHashMap.newKeySet();
        AtomicInteger duplicates = new AtomicInteger(0);
        CountDownLatch producersDone = new CountDownLatch(producerCount);
        CountDownLatch consumersDone = new CountDownLatch(consumerCount);
        AtomicInteger totalConsumed = new AtomicInteger(0);

        System.out.println("Buffer capacity: " + bufferSize);
        System.out.println("Producers: " + producerCount + " (each produces " + itemsPerProducer + " items)");
        System.out.println("Consumers: " + consumerCount);
        System.out.println("Total items to produce: " + totalItems + "\n");

        // Start producers
        for (int p = 0; p < producerCount; p++) {
            final String name = "Producer-" + p;
            new Thread(() -> {
                try {
                    for (int i = 0; i < itemsPerProducer; i++) {
                        buffer.put(new Item(name));
                    }
                } catch (InterruptedException e) {
                    Thread.currentThread().interrupt();
                } finally {
                    producersDone.countDown();
                }
            }, name).start();
        }

        // Start consumers
        for (int c = 0; c < consumerCount; c++) {
            final String name = "Consumer-" + c;
            new Thread(() -> {
                try {
                    while (true) {
                        Item item = buffer.take();
                        if (item == null) break;
                        item.markConsumed(name);
                        if (!consumedIds.add(item.getItemId())) {
                            duplicates.incrementAndGet(); // Duplicate detected!
                        }
                        totalConsumed.incrementAndGet();
                    }
                } catch (InterruptedException e) {
                    Thread.currentThread().interrupt();
                } finally {
                    consumersDone.countDown();
                }
            }, name).start();
        }

        // Wait for all producers to finish, then shutdown
        producersDone.await();
        // Give consumers time to drain the buffer
        while (buffer.size() > 0) {
            Thread.sleep(10);
        }
        buffer.shutdown();
        consumersDone.await();

        System.out.println("Results:");
        System.out.println("  Items produced: " + buffer.getProducedCount());
        System.out.println("  Items consumed: " + totalConsumed.get());
        System.out.println("  Duplicates: " + duplicates.get());
        System.out.println("  Lost items: " + (totalItems - totalConsumed.get()));

        boolean correct = totalConsumed.get() == totalItems && duplicates.get() == 0;
        System.out.println("  Correctness: " + (correct ? "PASSED" : "FAILED") +
                " (no lost items, no duplicates)");
    }

    static void demonstrateLockFreeBuffer() throws InterruptedException {
        System.out.println("--- Lock-Free Ring Buffer (CAS-based) ---");

        int bufferSize = 8; // Must be power of 2
        int producerCount = 4;
        int consumerCount = 4;
        int itemsPerProducer = 100;
        int totalItems = producerCount * itemsPerProducer;

        LockFreeBuffer buffer = new LockFreeBuffer(bufferSize);
        Set<Integer> consumedIds = ConcurrentHashMap.newKeySet();
        AtomicInteger duplicates = new AtomicInteger(0);
        AtomicInteger totalProduced = new AtomicInteger(0);
        AtomicInteger totalConsumed = new AtomicInteger(0);
        CountDownLatch allDone = new CountDownLatch(producerCount + consumerCount);
        AtomicInteger producersDone = new AtomicInteger(0);

        System.out.println("Buffer capacity: " + buffer.getCapacity() + " (power of 2)");
        System.out.println("Producers: " + producerCount + " (each produces " + itemsPerProducer + " items)");
        System.out.println("Consumers: " + consumerCount);
        System.out.println("Total items to produce: " + totalItems + "\n");

        // Start producers
        for (int p = 0; p < producerCount; p++) {
            final String name = "Producer-" + p;
            new Thread(() -> {
                int produced = 0;
                while (produced < itemsPerProducer) {
                    if (buffer.offer(new Item(name))) {
                        produced++;
                        totalProduced.incrementAndGet();
                    } else {
                        Thread.yield(); // Buffer full — yield and retry
                    }
                }
                producersDone.incrementAndGet();
                allDone.countDown();
            }, name).start();
        }

        // Start consumers
        for (int c = 0; c < consumerCount; c++) {
            final String name = "Consumer-" + c;
            final int expected = totalItems;
            new Thread(() -> {
                int emptyPolls = 0;
                while (true) {
                    Item item = buffer.poll();
                    if (item != null) {
                        item.markConsumed(name);
                        if (!consumedIds.add(item.getItemId())) {
                            duplicates.incrementAndGet();
                        }
                        totalConsumed.incrementAndGet();
                        emptyPolls = 0;
                    } else if (producersDone.get() == producerCount
                            && totalConsumed.get() >= expected) {
                        break; // All items produced and consumed
                    } else {
                        emptyPolls++;
                        if (emptyPolls > 1000) {
                            Thread.yield();
                            emptyPolls = 0;
                        }
                    }
                }
                allDone.countDown();
            }, name).start();
        }

        allDone.await();

        System.out.println("Results:");
        System.out.println("  Items produced: " + totalProduced.get());
        System.out.println("  Items consumed: " + totalConsumed.get());
        System.out.println("  Duplicates: " + duplicates.get());
        System.out.println("  Lost items: " + (totalProduced.get() - totalConsumed.get()));

        boolean correct = totalConsumed.get() == totalItems && duplicates.get() == 0;
        System.out.println("  Correctness: " + (correct ? "PASSED" : "FAILED") +
                " (no lost items, no duplicates)");
    }
}

// concurrent/model/Item.java — An item produced and consumed

import java.util.concurrent.atomic.AtomicInteger;

class Item {
    private static final AtomicInteger counter = new AtomicInteger(0); // static final = shared ID generator; AtomicInteger = thread-safe
    private final int itemId;              // final = safe publication; readable by consumer without sync
    private final String producedBy;       // final = set by producer, safely visible to consumer
    private final long producedAt;
    private volatile String consumedBy;    // volatile = written by consumer, readable by main thread immediately
    private volatile long consumedAt;      // volatile = ensures cross-thread visibility of consumption time

    public Item(String producedBy) {
        this.itemId = counter.incrementAndGet();
        this.producedBy = producedBy;
        this.producedAt = System.nanoTime();
    }

    public void markConsumed(String consumer) {
        this.consumedBy = consumer;
        this.consumedAt = System.nanoTime();
    }

    public int getItemId() { return itemId; }
    public String getProducedBy() { return producedBy; }
    public String getConsumedBy() { return consumedBy; }
    public long getProducedAt() { return producedAt; }
    public long getConsumedAt() { return consumedAt; }

    @Override
    public String toString() {
        return "Item-" + itemId + " [by " + producedBy + "]";
    }

    public static void resetCounter() { counter.set(0); }
}

// concurrent/service/BoundedBuffer.java — Using ReentrantLock + Condition (await/signal)

import java.util.LinkedList;
import java.util.Queue;
import java.util.concurrent.locks.Condition;
import java.util.concurrent.locks.ReentrantLock;
import java.util.concurrent.atomic.AtomicInteger;

/**
 * Thread-safe bounded buffer using explicit lock + conditions.
 *
 * - Producers block when buffer is FULL (notFull condition)
 * - Consumers block when buffer is EMPTY (notEmpty condition)
 * - No busy-waiting — threads are parked and signaled efficiently
 */
class BoundedBuffer {
    private final Queue<Item> buffer;
    private final int capacity;
    private final ReentrantLock lock = new ReentrantLock();       // ReentrantLock = explicit lock; more flexible than synchronized
    private final Condition notFull = lock.newCondition();        // Condition = producers wait here when buffer is full
    private final Condition notEmpty = lock.newCondition();       // Condition = consumers wait here when buffer is empty
    private final AtomicInteger produced = new AtomicInteger(0); // AtomicInteger = lock-free counter for stats
    private final AtomicInteger consumed = new AtomicInteger(0);
    private volatile boolean shutdown = false;                    // volatile = shutdown visible to all blocked threads

    public BoundedBuffer(int capacity) {
        this.capacity = capacity;
        this.buffer = new LinkedList<>();
    }

    /**
     * Put an item into the buffer. Blocks if buffer is full.
     */
    public boolean put(Item item) throws InterruptedException {
        lock.lock();
        try {
            while (buffer.size() == capacity && !shutdown) {
                notFull.await(); // Wait until space available
            }
            if (shutdown) return false;
            buffer.offer(item);
            produced.incrementAndGet();
            notEmpty.signal(); // Wake one waiting consumer
            return true;
        } finally {
            lock.unlock();
        }
    }

    /**
     * Take an item from the buffer. Blocks if buffer is empty.
     */
    public Item take() throws InterruptedException {
        lock.lock();
        try {
            while (buffer.isEmpty() && !shutdown) {
                notEmpty.await(); // Wait until item available
            }
            if (buffer.isEmpty()) return null; // Shutdown with empty buffer
            Item item = buffer.poll();
            consumed.incrementAndGet();
            notFull.signal(); // Wake one waiting producer
            return item;
        } finally {
            lock.unlock();
        }
    }

    public void shutdown() {
        lock.lock();
        try {
            shutdown = true;
            notFull.signalAll();
            notEmpty.signalAll();
        } finally {
            lock.unlock();
        }
    }

    public int size() {
        lock.lock();
        try {
            return buffer.size();
        } finally {
            lock.unlock();
        }
    }

    public int getProducedCount() { return produced.get(); }
    public int getConsumedCount() { return consumed.get(); }
    public boolean isShutdown() { return shutdown; }
    public int getCapacity() { return capacity; }
}

// concurrent/service/LockFreeBuffer.java — Lock-free buffer using ConcurrentLinkedQueue with capacity control

import java.util.concurrent.ConcurrentLinkedQueue;
import java.util.concurrent.atomic.AtomicInteger;

/**
 * "Lock-free" bounded buffer using ConcurrentLinkedQueue (Michael-Scott queue)
 * with an AtomicInteger size counter for bounded capacity.
 *
 * ConcurrentLinkedQueue is a proven lock-free data structure (uses CAS internally).
 * We add bounded capacity via AtomicInteger to demonstrate backpressure.
 *
 * This is the pragmatic approach to lock-free producer/consumer in Java.
 * The pure ring-buffer CAS approach (Disruptor-style) is extremely complex
 * to get right and is typically only used in ultra-low-latency systems.
 */
class LockFreeBuffer {
    private final ConcurrentLinkedQueue<Item> queue = new ConcurrentLinkedQueue<>(); // ConcurrentLinkedQueue = lock-free Michael-Scott queue
    private final AtomicInteger size = new AtomicInteger(0);    // AtomicInteger = CAS-based capacity enforcement without locks
    private final int capacity;
    private final AtomicInteger produced = new AtomicInteger(0);
    private final AtomicInteger consumed = new AtomicInteger(0);
    private volatile boolean shutdown = false;                   // volatile = all threads see shutdown flag immediately

    public LockFreeBuffer(int capacity) {
        this.capacity = capacity;
    }

    /**
     * Non-blocking offer. Returns false if buffer is at capacity.
     * Uses CAS on the size counter to enforce bounds without locks.
     */
    public boolean offer(Item item) {
        if (shutdown) return false;
        while (true) {
            int current = size.get();
            if (current >= capacity) {
                return false; // Buffer full — backpressure
            }
            if (size.compareAndSet(current, current + 1)) {
                queue.offer(item);
                produced.incrementAndGet();
                return true;
            }
            // CAS failed — another producer incremented, retry
        }
    }

    /**
     * Non-blocking poll. Returns null if buffer is empty.
     */
    public Item poll() {
        Item item = queue.poll();
        if (item != null) {
            size.decrementAndGet();
            consumed.incrementAndGet();
        }
        return item;
    }

    public void shutdown() { shutdown = true; }
    public int getProducedCount() { return produced.get(); }
    public int getConsumedCount() { return consumed.get(); }
    public int getCapacity() { return capacity; }
    public boolean isShutdown() { return shutdown; }

    public int approximateSize() {
        return size.get();
    }
}

