// model/Event.java — Base event with type, timestamp, and optional source
public class Event {
    private final String type;       // private final = immutable once created; safe to pass around
    private final long timestamp;
    private final Object source;     // Object = any type can be the event source (flexible)

    public Event(String type, Object source) {
        this.type = type;
        this.timestamp = System.currentTimeMillis();
        this.source = source;
    }

    public Event(String type) { this(type, null); }

    public String getType() { return type; }
    public long getTimestamp() { return timestamp; }
    public Object getSource() { return source; }

    @Override
    public String toString() { return getClass().getSimpleName() + "[" + type + "]"; }
}

class UserEvent extends Event { // extends = inherits from Event; IS-A relationship
    private final String username;

    public UserEvent(String type, String username) {
        super(type); // super = calls parent Event constructor
        this.username = username;
    }

    public String getUsername() { return username; }

    @Override
    public String toString() { return "UserEvent[" + getType() + ", user=" + username + "]"; }
}

class SystemEvent extends Event { // extends = another Event subtype for system-level events
    private final String message;

    public SystemEvent(String type, String message) {
        super(type);
        this.message = message;
    }

    public String getMessage() { return message; }

    @Override
    public String toString() { return "SystemEvent[" + getType() + ": " + message + "]"; }
}

// model/EventHandler.java — Interface for objects that react to events
public interface EventHandler { // interface = contract; any handler must implement handle()
    void handle(Event event);
    String getName();
}

// model/Subscription.java — Tracks a handler's registration with filter and priority
public class Subscription implements Comparable<Subscription> { // implements Comparable = enables sorting by priority
    private final EventHandler handler;                 // private final = bound at creation, never swapped
    private final int priority;
    private final EventFilter filter;                   // filter may be null = optional narrowing of events
    private final Class<? extends Event> eventType;     // Class<? extends Event> = wildcard; matches Event or any subclass

    public Subscription(EventHandler handler, Class<? extends Event> eventType, int priority, EventFilter filter) {
        this.handler = handler;
        this.eventType = eventType;
        this.priority = priority;
        this.filter = filter;
    }

    public Subscription(EventHandler handler, Class<? extends Event> eventType, int priority) {
        this(handler, eventType, priority, null);
    }

    public Subscription(EventHandler handler, Class<? extends Event> eventType) {
        this(handler, eventType, 0, null);
    }

    public EventHandler getHandler() { return handler; }
    public int getPriority() { return priority; }
    public EventFilter getFilter() { return filter; }
    public Class<? extends Event> getEventType() { return eventType; }

    public boolean matches(Event event) {
        if (!eventType.isAssignableFrom(event.getClass())) return false;
        if (filter != null && !filter.accept(event)) return false;
        return true;
    }

    @Override
    public int compareTo(Subscription other) {
        return Integer.compare(other.priority, this.priority);
    }
}

// service/DeadLetterQueue.java — Captures undelivered events for debugging
import java.util.ArrayList;
import java.util.Collections;
import java.util.List;

public class DeadLetterQueue {
    private final List<Event> deadLetters = new ArrayList<>(); // private = internal store; synchronized methods guard access

    public synchronized void add(Event event) { deadLetters.add(event); } // synchronized = thread-safe access
    public synchronized List<Event> getAll() { return Collections.unmodifiableList(new ArrayList<>(deadLetters)); }
    public synchronized int size() { return deadLetters.size(); }
}

// service/EventBus.java — Central hub with ArrayList of handlers, synchronous dispatch
import java.util.ArrayList;
import java.util.Collections;
import java.util.List;

public class EventBus {
    private final List<Subscription> subscriptions = new ArrayList<>(); // private = internal registry of handlers
    private final DeadLetterQueue deadLetterQueue = new DeadLetterQueue(); // stores events with no matching handler

    public void subscribe(EventHandler handler, Class<? extends Event> eventType) {
        subscriptions.add(new Subscription(handler, eventType));
    }

    public void subscribe(EventHandler handler, Class<? extends Event> eventType, int priority) {
        subscriptions.add(new Subscription(handler, eventType, priority));
    }

    public void subscribe(EventHandler handler, Class<? extends Event> eventType, int priority, EventFilter filter) {
        subscriptions.add(new Subscription(handler, eventType, priority, filter));
    }

    public void unsubscribe(EventHandler handler) {
        subscriptions.removeIf(s -> s.getHandler() == handler);
    }

    public void publish(Event event) {
        List<Subscription> matching = new ArrayList<>();
        for (Subscription sub : subscriptions) {
            if (sub.matches(event)) matching.add(sub);
        }
        if (matching.isEmpty()) {
            deadLetterQueue.add(event);
            return;
        }
        Collections.sort(matching);
        for (Subscription sub : matching) {
            sub.getHandler().handle(event);
        }
    }

    public DeadLetterQueue getDeadLetterQueue() { return deadLetterQueue; }
    public int getSubscriptionCount() { return subscriptions.size(); }
}

// strategy/EventFilter.java — Determines which events a subscription receives
public interface EventFilter { // interface = contract for filtering logic; swappable per subscription
    boolean accept(Event event);
}

// Main.java — Demonstrates event bus with per-type handlers and async CompletableFuture dispatch
public class Main {
    public static void main(String[] args) throws InterruptedException {
        System.out.println("=== Event Bus (Optimized: Per-Type + Async) Demo ===\n");

        // --- Test 1: Type-Safe Subscribe ---
        System.out.println("--- Test 1: Type-Safe Subscribe ---");
        EventBus bus = new EventBus();

        EventHandler<UserEvent> userHandler = new EventHandler<UserEvent>() {
            public void handle(UserEvent event) { System.out.println("  UserHandler: " + event); }
            public String getName() { return "UserHandler"; }
        };
