            public void handle(Event event) { System.out.println("  AllHandler: " + event); }
            public String getName() { return "AllHandler"; }
        };

        bus.subscribe(UserEvent.class, userHandler);
        bus.subscribe(Event.class, allHandler);

        bus.publish(new UserEvent("LOGIN", "alice"));
        bus.publish(new SystemEvent("BOOT", "started"));

        // --- Test 2: Priority ---
        System.out.println("\n--- Test 2: Priority ---");
        EventBus pBus = new EventBus();
        pBus.subscribe(Event.class, new EventHandler<Event>() {
            public void handle(Event e) { System.out.println("  [LOW-1]"); }
            public String getName() { return "Low"; }
        }, 1);
        pBus.subscribe(Event.class, new EventHandler<Event>() {
            public void handle(Event e) { System.out.println("  [HIGH-10]"); }
            public String getName() { return "High"; }
        }, 10);
        pBus.publish(new Event("TEST"));

        // --- Test 3: Async Dispatch ---
        System.out.println("\n--- Test 3: Async Dispatch (CompletableFuture) ---");
        EventBus asyncBus = new EventBus();
        asyncBus.setAsyncMode(true);
        asyncBus.subscribe(Event.class, new EventHandler<Event>() {
            public void handle(Event event) {
                System.out.println("  [Async] " + Thread.currentThread().getName() + ": " + event);
            }
            public String getName() { return "AsyncHandler"; }
        });
        asyncBus.publish(new Event("ASYNC_1"));
        asyncBus.publish(new Event("ASYNC_2"));
        asyncBus.publish(new Event("ASYNC_3"));
        Thread.sleep(200);

        // --- Test 4: Dead Letter Queue ---
        System.out.println("\n--- Test 4: Dead Letter Queue ---");
        EventBus dlqBus = new EventBus();
        dlqBus.publish(new Event("ORPHAN"));
        System.out.println("  Dead letters: " + dlqBus.getDeadLetters().size());

        // --- Test 5: Unsubscribe ---
        System.out.println("\n--- Test 5: Unsubscribe ---");
        System.out.println("  Before: " + bus.getSubscriptionCount());
        bus.unsubscribe(userHandler);
        System.out.println("  After: " + bus.getSubscriptionCount());

        System.out.println("\n=== Event Bus (Optimized) Demo Complete ===");
    }
}

// model/Event.java — Base event with type hierarchy for type-safe dispatch
public class Event {
    private final String type;      // final = immutable; safe to dispatch to multiple handlers
    private final long timestamp;

    public Event(String type) {
        this.type = type;
        this.timestamp = System.currentTimeMillis();
    }

    public String getType() { return type; }
    public long getTimestamp() { return timestamp; }

    @Override
    public String toString() { return getClass().getSimpleName() + "[" + type + "]"; }
}

class UserEvent extends Event { // extends = subtype enables type-safe dispatch via class hierarchy
    private final String username;
    public UserEvent(String type, String username) { super(type); this.username = username; }
    public String getUsername() { return username; }
    @Override public String toString() { return "UserEvent[" + getType() + ", user=" + username + "]"; }
}

class SystemEvent extends Event { // extends = another subtype; handlers can subscribe per-type
    private final String message;
    public SystemEvent(String type, String message) { super(type); this.message = message; }
    public String getMessage() { return message; }
    @Override public String toString() { return "SystemEvent[" + getType() + ": " + message + "]"; }
}

// model/EventHandler.java — Type-safe handler interface using generics
public interface EventHandler<T extends Event> { // <T extends Event> = generic; handler only receives its declared type
    void handle(T event);
    String getName();
}

// service/EventBus.java — Per-type CopyOnWriteArrayList handlers with async CompletableFuture dispatch
import java.util.List;
import java.util.Map;
import java.util.concurrent.CompletableFuture;
import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.CopyOnWriteArrayList;
import java.util.concurrent.Executor;
import java.util.concurrent.Executors;

public class EventBus {
    // WHY ConcurrentHashMap of CopyOnWriteArrayLists: Subscribe is rare, publish is frequent.
    // CopyOnWrite gives lock-free iteration during dispatch — no synchronization on hot path.
    private final Map<Class<?>, CopyOnWriteArrayList<HandlerEntry>> handlersByType = new ConcurrentHashMap<>(); // ConcurrentHashMap = lock-free reads; CopyOnWriteArrayList = snapshot iteration

    // WHY dedicated executor: Async dispatch doesn't block the publisher thread,
    // preventing slow handlers from cascading delays to other subscribers.
    private final Executor asyncExecutor = Executors.newFixedThreadPool(
            Runtime.getRuntime().availableProcessors(),
            r -> { Thread t = new Thread(r, "eventbus-async"); t.setDaemon(true); return t; });

    private final CopyOnWriteArrayList<Event> deadLetters = new CopyOnWriteArrayList<>(); // CopyOnWrite = safe to read concurrently
    private boolean asyncMode = false;

    @SuppressWarnings("unchecked")
    public <T extends Event> void subscribe(Class<T> eventType, EventHandler<T> handler, int priority) {
        // WHY per-type list: O(1) lookup for event type instead of scanning all subscriptions
        handlersByType.computeIfAbsent(eventType, k -> new CopyOnWriteArrayList<>())
                .add(new HandlerEntry(handler, priority));
    }

    public <T extends Event> void subscribe(Class<T> eventType, EventHandler<T> handler) {
        subscribe(eventType, handler, 0);
    }

    public void unsubscribe(EventHandler<?> handler) {
        for (CopyOnWriteArrayList<HandlerEntry> entries : handlersByType.values()) {
            entries.removeIf(e -> e.handler == handler);
        }
    }

    @SuppressWarnings("unchecked")
    public void publish(Event event) {
        List<HandlerEntry> handlers = findHandlers(event.getClass());

        if (handlers.isEmpty()) {
            deadLetters.add(event);
            return;
        }

        if (asyncMode) {
            // WHY CompletableFuture: Non-blocking dispatch, each handler runs independently.
            // Failures in one handler don't affect others.
            for (HandlerEntry entry : handlers) {
                CompletableFuture.runAsync(() -> entry.handler.handle(event), asyncExecutor)
                        .exceptionally(ex -> {
                            System.err.println("  [EventBus] Handler error: " + ex.getMessage());
                            return null;
                        });
            }
        } else {
            for (HandlerEntry entry : handlers) {
                entry.handler.handle(event);
            }
        }
    }

    @SuppressWarnings("unchecked")
    private List<HandlerEntry> findHandlers(Class<?> eventType) {
        // WHY walk class hierarchy: Allows subscribing to base Event type
        // and receiving all subtypes (UserEvent, SystemEvent, etc.)
        CopyOnWriteArrayList<HandlerEntry> result = new CopyOnWriteArrayList<>();
        Class<?> current = eventType;
        while (current != null && Event.class.isAssignableFrom(current)) {
            CopyOnWriteArrayList<HandlerEntry> entries = handlersByType.get(current);
            if (entries != null) result.addAll(entries);
            current = current.getSuperclass();
        }
        result.sort((a, b) -> Integer.compare(b.priority, a.priority));
        return result;
    }

    public void setAsyncMode(boolean async) { this.asyncMode = async; }
    public List<Event> getDeadLetters() { return deadLetters; }
    public int getSubscriptionCount() {
        int count = 0;
        for (var list : handlersByType.values()) count += list.size();
        return count;
    }

    private static class HandlerEntry { // private static = inner class with no reference to outer EventBus instance
        final EventHandler handler;    // final = never reassigned after construction
        final int priority;
        HandlerEntry(EventHandler handler, int priority) {
            this.handler = handler;
            this.priority = priority;
        }
    }
}

// concurrent/Main.java — Publisher + subscriber registration racing, verify no ConcurrentModificationException

import java.util.*;
import java.util.concurrent.*;
import java.util.concurrent.atomic.AtomicBoolean;
import java.util.concurrent.atomic.AtomicInteger;

public class Main {
    public static void main(String[] args) throws InterruptedException {
        System.out.println("=== Concurrent Event Bus Demo ===\n");

        ConcurrentEventBus bus = new ConcurrentEventBus();
        String topic = "orders";

        int publisherThreads = 5;
        int subscriberThreads = 5;
        int eventsPerPublisher = 100;
        int subscribersPerThread = 20;

        CountDownLatch startLatch = new CountDownLatch(1);
        CountDownLatch doneLatch = new CountDownLatch(publisherThreads + subscriberThreads);
        AtomicBoolean exceptionFound = new AtomicBoolean(false);
        AtomicInteger eventsReceived = new AtomicInteger(0);

        System.out.println("Scenario: 5 publisher threads + 5 subscriber threads racing.");
        System.out.println("  Publishers send 100 events each while subscribers register.");
        System.out.println("Expected: No ConcurrentModificationException, all events delivered.\n");

        // Subscriber threads — keep registering handlers while events fire
        for (int t = 0; t < subscriberThreads; t++) {
            new Thread(() -> {
                try {
                    startLatch.await();
                    for (int i = 0; i < subscribersPerThread; i++) {
                        bus.subscribe(topic, event -> eventsReceived.incrementAndGet());
                        Thread.yield(); // Increase interleaving
                    }
                } catch (ConcurrentModificationException e) {
                    exceptionFound.set(true);
                    e.printStackTrace();
                } catch (Exception e) {
                    exceptionFound.set(true);
                    e.printStackTrace();
                } finally {
                    doneLatch.countDown();
                }
            }, "Subscriber-" + t).start();
        }

        // Publisher threads — publish events while handlers are being registered
        for (int t = 0; t < publisherThreads; t++) {
            final int threadId = t;
            new Thread(() -> {
                try {
                    startLatch.await();
                    for (int i = 0; i < eventsPerPublisher; i++) {
                        Event event = new Event(topic, "order-" + threadId + "-" + i);
                        bus.publish(event);
                        Thread.yield(); // Increase interleaving
                    }
                } catch (ConcurrentModificationException e) {
                    exceptionFound.set(true);
                    e.printStackTrace();
                } catch (Exception e) {
                    exceptionFound.set(true);
                    e.printStackTrace();
                } finally {
                    doneLatch.countDown();
                }
            }, "Publisher-" + t).start();
        }

        startLatch.countDown();
        doneLatch.await();

        int totalEventsPublished = bus.getEventsPublished();
        int totalSubscribers = bus.getSubscriberCount(topic);

        System.out.println("--- Results ---");
        System.out.println("Events published: " + totalEventsPublished);
        System.out.println("Total subscribers registered: " + totalSubscribers);
        System.out.println("Handler invocations: " + bus.getHandlersInvoked());
        System.out.println("Events received by handlers: " + eventsReceived.get());
        System.out.println("ConcurrentModificationException: " + exceptionFound.get());

        boolean passed = !exceptionFound.get()
                && totalEventsPublished == publisherThreads * eventsPerPublisher
                && totalSubscribers == subscriberThreads * subscribersPerThread;
        System.out.println("\nCorrectness check: " + (passed ? "PASSED" : "FAILED"));
    }
}

// concurrent/model/Event.java — Simple event with topic and payload

public class Event {
    private final String topic;    // final = immutable; safe to read from any thread without sync
    private final String payload;  // final = set once at construction; guarantees safe publication
    private final long timestamp;

    public Event(String topic, String payload) {
        this.topic = topic;
        this.payload = payload;
        this.timestamp = System.nanoTime();
    }

    public String getTopic() { return topic; }
    public String getPayload() { return payload; }
    public long getTimestamp() { return timestamp; }

    @Override
    public String toString() {
        return "Event[" + topic + ": " + payload + "]";
    }
}

// concurrent/model/EventHandler.java — Functional interface for event handlers

public interface EventHandler { // interface with single method = can be used as lambda
    void handle(Event event);
}

// concurrent/service/ConcurrentEventBus.java — CopyOnWriteArrayList for handler list (snapshot iteration)

import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.CopyOnWriteArrayList;
import java.util.concurrent.atomic.AtomicInteger;

public class ConcurrentEventBus {
    private final ConcurrentHashMap<String, CopyOnWriteArrayList<EventHandler>> handlers = new ConcurrentHashMap<>(); // ConcurrentHashMap = lock-free reads; CopyOnWriteArrayList = no ConcurrentModificationException during iteration
    private final AtomicInteger eventsPublished = new AtomicInteger(0); // AtomicInteger = thread-safe counter without locks
    private final AtomicInteger handlersInvoked = new AtomicInteger(0);

    /**
     * Subscribe a handler to a topic. Uses CopyOnWriteArrayList so that
     * publishing (iteration) never sees a partially-constructed list.
     */
    public void subscribe(String topic, EventHandler handler) {
        handlers.computeIfAbsent(topic, k -> new CopyOnWriteArrayList<>()).add(handler);
    }

    /**
     * Publish an event to all current subscribers. CopyOnWriteArrayList
     * guarantees snapshot iteration — no ConcurrentModificationException
     * even if new handlers are being registered simultaneously.
     */
    public void publish(Event event) {
        eventsPublished.incrementAndGet();
        CopyOnWriteArrayList<EventHandler> topicHandlers = handlers.get(event.getTopic());
        if (topicHandlers != null) {
            for (EventHandler handler : topicHandlers) {
                handler.handle(event);
                handlersInvoked.incrementAndGet();
            }
        }
    }

    public int getEventsPublished() { return eventsPublished.get(); }
    public int getHandlersInvoked() { return handlersInvoked.get(); }
    public int getSubscriberCount(String topic) {
        CopyOnWriteArrayList<EventHandler> list = handlers.get(topic);
        return list == null ? 0 : list.size();
    }
}

