// Main.java — Demonstrates circuit breaker with simple failure counter
public class Main {
    private static boolean serviceHealthy = true;

    public static void main(String[] args) throws Exception {
        System.out.println("=== Circuit Breaker (Naive) Demo ===\n");

        CircuitBreakerConfig config = new CircuitBreakerConfig(3, 500, 2);
        CircuitBreaker cb = new CircuitBreaker("PaymentService", config);
        ServiceCall<String> call = () -> {
            if (!serviceHealthy) throw new RuntimeException("Service unavailable");
            return "OK";
        };

        // --- Test 1: Normal Operation ---
        System.out.println("--- Test 1: Normal (CLOSED) ---");
        System.out.println("  Result: " + cb.execute(call));
        System.out.println("  State: " + cb.getStateName());

        // --- Test 2: Failures Trip Circuit ---
        System.out.println("\n--- Test 2: Failures Trip Circuit ---");
        serviceHealthy = false;
        for (int i = 1; i <= 3; i++) {
            try { cb.execute(call); } catch (Exception e) { System.out.println("  Fail " + i + ": " + e.getMessage()); }
        }
        System.out.println("  State: " + cb.getStateName());

        // --- Test 3: Open Fails Fast ---
        System.out.println("\n--- Test 3: Open Fails Fast ---");
        try { cb.execute(call); } catch (Exception e) { System.out.println("  " + e.getMessage()); }

        // --- Test 4: Recovery ---
        System.out.println("\n--- Test 4: Recovery via HALF_OPEN ---");
        Thread.sleep(600);
        serviceHealthy = true;
        System.out.println("  Result: " + cb.execute(call));
        System.out.println("  Result: " + cb.execute(call));
        System.out.println("  State: " + cb.getStateName());

        System.out.println("\n  Metrics: " + cb.getMetrics());
        System.out.println("\n=== Circuit Breaker (Naive) Demo Complete ===");
    }
}

// model/CircuitBreakerConfig.java — Configuration for thresholds and timeouts
public class CircuitBreakerConfig {
    private final int failureThreshold;     // private final = immutable config; set once, never modified
    private final long openTimeoutMs;       // how long to stay OPEN before trying HALF_OPEN
    private final int halfOpenTrialCount;   // private = only accessible via getters

    public CircuitBreakerConfig(int failureThreshold, long openTimeoutMs, int halfOpenTrialCount) {
        this.failureThreshold = failureThreshold;
        this.openTimeoutMs = openTimeoutMs;
        this.halfOpenTrialCount = halfOpenTrialCount;
    }

    public int getFailureThreshold() { return failureThreshold; }
    public long getOpenTimeoutMs() { return openTimeoutMs; }
    public int getHalfOpenTrialCount() { return halfOpenTrialCount; }
}

// model/CircuitBreakerMetrics.java — Tracks success/failure rates
import java.util.concurrent.atomic.AtomicInteger;

public class CircuitBreakerMetrics {
    private final AtomicInteger successCount = new AtomicInteger(0);  // private final = reference fixed; AtomicInteger for thread-safe counting
    private final AtomicInteger failureCount = new AtomicInteger(0);
    private final AtomicInteger rejectedCount = new AtomicInteger(0);

    public void recordSuccess() { successCount.incrementAndGet(); }
    public void recordFailure() { failureCount.incrementAndGet(); }
    public void recordRejected() { rejectedCount.incrementAndGet(); }

    public int getSuccessCount() { return successCount.get(); }
    public int getFailureCount() { return failureCount.get(); }
    public int getRejectedCount() { return rejectedCount.get(); }

    @Override
    public String toString() {
        return String.format("Metrics[success=%d, fail=%d, rejected=%d]",
                successCount.get(), failureCount.get(), rejectedCount.get());
    }
}

// model/ServiceCall.java — Represents a callable remote service operation
public interface ServiceCall<T> { // interface + generic <T> = contract for any callable returning type T
    T call() throws Exception;
}

// service/CircuitBreaker.java — Wraps service calls with fail-fast protection using synchronized state
public class CircuitBreaker {
    private final String name;                    // private final = identifies this breaker instance
    private final CircuitBreakerConfig config;    // final = config never changes after construction
    private final CircuitBreakerMetrics metrics;
    private CircuitState currentState;            // private = mutable state; protected by synchronized methods

    public CircuitBreaker(String name, CircuitBreakerConfig config) {
        this.name = name;
        this.config = config;
        this.metrics = new CircuitBreakerMetrics();
        this.currentState = new ClosedState();
    }

    public synchronized <T> T execute(ServiceCall<T> call) throws Exception { // synchronized = only one thread executes at a time
        return currentState.execute(call, this);
    }

    public synchronized void transitionTo(CircuitState newState) { // synchronized = state transitions are atomic
        System.out.println("  [" + name + "] " + currentState.getName() + " -> " + newState.getName());
        this.currentState = newState;
    }

    public String getStateName() { return currentState.getName(); }
    public CircuitBreakerConfig getConfig() { return config; }
    public CircuitBreakerMetrics getMetrics() { return metrics; }
}

// state/CircuitState.java — Interface for circuit breaker states (State pattern)
// DESIGN PATTERN: State
public interface CircuitState { // interface = each state (Closed/Open/HalfOpen) provides its own behavior
    String getName();
    <T> T execute(ServiceCall<T> call, CircuitBreaker breaker) throws Exception;
}

// state/ClosedState.java — Normal state, tracks consecutive failures with simple counter
public class ClosedState implements CircuitState { // implements = fulfills the CircuitState contract
    private int consecutiveFailures = 0;           // private = internal counter; reset on success

    @Override
    public String getName() { return "CLOSED"; }

    @Override
    public <T> T execute(ServiceCall<T> call, CircuitBreaker breaker) throws Exception {
        try {
            T result = call.call();
            consecutiveFailures = 0;
            breaker.getMetrics().recordSuccess();
            return result;
        } catch (Exception e) {
            consecutiveFailures++;
            breaker.getMetrics().recordFailure();
            if (consecutiveFailures >= breaker.getConfig().getFailureThreshold()) {
                breaker.transitionTo(new OpenState());
            }
            throw e;
        }
    }
}

// state/HalfOpenState.java — Trial state allowing limited calls to test recovery
public class HalfOpenState implements CircuitState { // implements = another state variant in the State pattern
    private int trialSuccesses = 0;                   // private = tracks probe outcomes internally
    private int trialAttempts = 0;

    @Override
    public String getName() { return "HALF_OPEN"; }

    @Override
    public <T> T execute(ServiceCall<T> call, CircuitBreaker breaker) throws Exception {
        int maxTrials = breaker.getConfig().getHalfOpenTrialCount();
        trialAttempts++;
        try {
            T result = call.call();
            trialSuccesses++;
            breaker.getMetrics().recordSuccess();
            if (trialSuccesses >= maxTrials) {
                breaker.transitionTo(new ClosedState());
            }
            return result;
        } catch (Exception e) {
            breaker.getMetrics().recordFailure();
            breaker.transitionTo(new OpenState());
            throw e;
        }
    }
}

// state/OpenState.java — Fail-fast state, rejects all calls until timeout elapses
public class OpenState implements CircuitState { // implements = State pattern; rejects all calls
    private final long enteredAt = System.currentTimeMillis(); // final = captured once when state is created

    @Override
    public String getName() { return "OPEN"; }

    @Override
    public <T> T execute(ServiceCall<T> call, CircuitBreaker breaker) throws Exception {
        long elapsed = System.currentTimeMillis() - enteredAt;
        if (elapsed >= breaker.getConfig().getOpenTimeoutMs()) {
            breaker.transitionTo(new HalfOpenState());
            return breaker.execute(call);
        }
        breaker.getMetrics().recordRejected();
        throw new RuntimeException("Circuit OPEN - failing fast");
    }
}

// Main.java — Demonstrates circuit breaker with sliding window and atomic state transitions
public class Main {
    private static boolean serviceHealthy = true;

    public static void main(String[] args) throws Exception {
        System.out.println("=== Circuit Breaker (Optimized: Sliding Window) Demo ===\n");

        // Window of 10, trip at 50% failure rate, 500ms open timeout, 2 probes required
        CircuitBreakerConfig config = new CircuitBreakerConfig(10, 0.5, 500, 2);
        CircuitBreaker cb = new CircuitBreaker("PaymentService", config);
        ServiceCall<String> call = () -> {
            if (!serviceHealthy) throw new RuntimeException("Service down");
            return "OK";
        };

        // --- Test 1: Normal Operation ---
        System.out.println("--- Test 1: Normal (stays CLOSED) ---");
        serviceHealthy = true;
        for (int i = 0; i < 5; i++) System.out.println("  " + cb.execute(call));
        System.out.println("  State: " + cb.getStateName());

        // --- Test 2: Intermittent Failures (below threshold) ---
        System.out.println("\n--- Test 2: Intermittent Failures (below 50%) ---");
        // 3 failures out of 10 = 30% < 50% threshold — should stay closed
        for (int i = 0; i < 3; i++) {
            serviceHealthy = false;
            try { cb.execute(call); } catch (Exception e) { System.out.println("  Fail: " + e.getMessage()); }
        }
        serviceHealthy = true;
        for (int i = 0; i < 2; i++) cb.execute(call);
        System.out.println("  State (should be CLOSED): " + cb.getStateName());

        // --- Test 3: Sustained Failures Trip Circuit ---
        System.out.println("\n--- Test 3: Sustained failures trip to OPEN ---");
        serviceHealthy = false;
        for (int i = 0; i < 10; i++) {
            try { cb.execute(call); } catch (Exception e) { /* expected */ }
        }
        System.out.println("  State: " + cb.getStateName());

        // --- Test 4: Fast-Fail While Open ---
        System.out.println("\n--- Test 4: Fast-Fail while OPEN ---");
        try { cb.execute(call); } catch (Exception e) { System.out.println("  " + e.getMessage()); }

        // --- Test 5: Recovery with Probes ---
        System.out.println("\n--- Test 5: Recovery (HALF_OPEN probes) ---");
        Thread.sleep(600);
        serviceHealthy = true;
        System.out.println("  Probe 1: " + cb.execute(call));
        System.out.println("  Probe 2: " + cb.execute(call));
        System.out.println("  State: " + cb.getStateName());

        System.out.println("\n  " + cb.getMetrics());
        System.out.println("\n=== Circuit Breaker (Optimized) Demo Complete ===");
    }
}

