// model/ServiceCall.java — Represents a callable remote service operation
public interface ServiceCall<T> { // interface + generic = any callable returning type T
    T call() throws Exception;
}

// service/CircuitBreaker.java — Sliding window metrics with atomic state transitions
import java.util.concurrent.atomic.AtomicReference;
import java.util.concurrent.atomic.AtomicInteger;

public class CircuitBreaker {
    // WHY AtomicReference for state: Lock-free state transitions using CAS.
    // Multiple threads can check state without blocking each other.
    private enum State { CLOSED, OPEN, HALF_OPEN } // enum = fixed set of states; type-safe instead of magic strings

    private final String name;
    private final CircuitBreakerConfig config;
    private final SlidingWindow window;                              // SlidingWindow = ring buffer for rolling failure rate
    private final AtomicReference<State> state = new AtomicReference<>(State.CLOSED); // AtomicReference = CAS-based lock-free state transitions
    private volatile long openedAt;                                  // volatile = all threads read the latest open timestamp
    private final AtomicInteger halfOpenSuccesses = new AtomicInteger(0); // AtomicInteger = lock-free probe tracking
    private final AtomicInteger halfOpenAttempts = new AtomicInteger(0);

    // Metrics — AtomicIntegers for lock-free concurrent updates from multiple threads
    private final AtomicInteger totalSuccess = new AtomicInteger(0);
    private final AtomicInteger totalFailure = new AtomicInteger(0);
    private final AtomicInteger totalRejected = new AtomicInteger(0);

    public CircuitBreaker(String name, CircuitBreakerConfig config) {
        this.name = name;
        this.config = config;
        this.window = new SlidingWindow(config.getWindowSize());
    }

    public <T> T execute(ServiceCall<T> call) throws Exception {
        State currentState = state.get();

        switch (currentState) {
            case OPEN:
                return handleOpen(call);
            case HALF_OPEN:
                return handleHalfOpen(call);
            default: // CLOSED
                return handleClosed(call);
        }
    }

    private <T> T handleClosed(ServiceCall<T> call) throws Exception {
        try {
            T result = call.call();
            window.record(true);
            totalSuccess.incrementAndGet();
            return result;
        } catch (Exception e) {
            window.record(false);
            totalFailure.incrementAndGet();
            // WHY rate-based: Trip only when failure RATE exceeds threshold over the window
            if (window.getCount() >= config.getWindowSize() &&
                window.getFailureRate() >= config.getFailureRateThreshold()) {
                tripOpen();
            }
            throw e;
        }
    }

    private <T> T handleOpen(ServiceCall<T> call) throws Exception {
        long elapsed = System.currentTimeMillis() - openedAt;
        if (elapsed >= config.getOpenTimeoutMs()) {
            // WHY CAS: Only one thread transitions to HALF_OPEN; others still fail fast
            if (state.compareAndSet(State.OPEN, State.HALF_OPEN)) {
                System.out.println("  [" + name + "] OPEN -> HALF_OPEN");
                halfOpenSuccesses.set(0);
                halfOpenAttempts.set(0);
            }
            return execute(call); // Retry in new state
        }
        totalRejected.incrementAndGet();
        throw new RuntimeException("Circuit OPEN - failing fast (" + (config.getOpenTimeoutMs() - elapsed) + "ms remaining)");
    }

    private <T> T handleHalfOpen(ServiceCall<T> call) throws Exception {
        int attempt = halfOpenAttempts.incrementAndGet();
        if (attempt > config.getHalfOpenProbeCount()) {
            // Exceeded probe count, wait for probes to finish
            totalRejected.incrementAndGet();
            throw new RuntimeException("Circuit HALF_OPEN - probe limit reached");
        }

        try {
            T result = call.call();
            int successes = halfOpenSuccesses.incrementAndGet();
            totalSuccess.incrementAndGet();
            System.out.println("  [" + name + "] Probe " + successes + "/" + config.getHalfOpenProbeCount() + " passed");
            // WHY configurable probe count: Single success may be a fluke;
            // require N consecutive successes for confidence.
            if (successes >= config.getHalfOpenProbeCount()) {
                if (state.compareAndSet(State.HALF_OPEN, State.CLOSED)) {
                    System.out.println("  [" + name + "] HALF_OPEN -> CLOSED");
                    window.reset();
                }
            }
            return result;
        } catch (Exception e) {
            totalFailure.incrementAndGet();
            tripOpen();
            throw e;
        }
    }

    private void tripOpen() {
        State prev = state.getAndSet(State.OPEN);
        if (prev != State.OPEN) {
            openedAt = System.currentTimeMillis();
            System.out.println("  [" + name + "] " + prev + " -> OPEN (failure rate: " +
                    String.format("%.0f%%", window.getFailureRate() * 100) + ")");
        }
    }

    public String getStateName() { return state.get().name(); }
    public String getMetrics() {
        return String.format("Metrics[success=%d, fail=%d, rejected=%d, windowRate=%.0f%%]",
                totalSuccess.get(), totalFailure.get(), totalRejected.get(),
                window.getFailureRate() * 100);
    }
}

// service/SlidingWindow.java — Ring buffer tracking last N call outcomes for failure rate calculation
public class SlidingWindow {
    // WHY ring buffer: Fixed memory O(windowSize), O(1) record/query,
    // naturally evicts old entries without shifting. Gives rolling failure rate
    // instead of naive consecutive-count which resets on a single success.
    private final boolean[] outcomes; // boolean[] ring buffer = fixed memory, automatic eviction of oldest
    private int head = 0;            // private = internal pointer; guarded by synchronized
    private int count = 0;
    private int failures = 0;

    public SlidingWindow(int size) {
        this.outcomes = new boolean[size];
    }

    public synchronized void record(boolean success) { // synchronized = only one thread records at a time
        if (count == outcomes.length) {
            // Evict oldest entry
            if (!outcomes[head]) {
                failures--; // Old failure being evicted
            }
        } else {
            count++;
        }
        outcomes[head] = success;
        if (!success) failures++;
        head = (head + 1) % outcomes.length;
    }

    // WHY failure rate (not count): A single timeout among 100 successes
    // shouldn't trip the breaker — percentage-based is more robust.
    public synchronized double getFailureRate() {
        if (count == 0) return 0.0;
        return (double) failures / count;
    }

    public synchronized int getFailureCount() { return failures; }
    public synchronized int getCount() { return count; }

    public synchronized void reset() {
        head = 0;
        count = 0;
        failures = 0;
    }
}

// concurrent/Main.java — 50 threads making requests, circuit trips correctly even under concurrency

import java.util.concurrent.CountDownLatch;
import java.util.concurrent.atomic.AtomicInteger;

public class Main {
    public static void main(String[] args) throws InterruptedException {
        System.out.println("=== Concurrent Circuit Breaker Demo ===\n");

        // Fast config: trips after 3 failures, resets after 200ms
        CircuitBreakerConfig config = CircuitBreakerConfig.fastConfig();
        ConcurrentCircuitBreaker breaker = new ConcurrentCircuitBreaker(config);

        System.out.println("Config: threshold=" + config.getFailureThreshold() +
                " failures, resetTimeout=" + config.getResetTimeoutMs() + "ms");
        System.out.println("\n--- Phase 1: 50 threads hitting a FAILING service ---");

        int threadCount = 50;
        CountDownLatch startLatch = new CountDownLatch(1);
        CountDownLatch doneLatch = new CountDownLatch(threadCount);
        AtomicInteger succeeded = new AtomicInteger(0);
        AtomicInteger failed = new AtomicInteger(0);
        AtomicInteger rejected = new AtomicInteger(0);

        // All requests will fail — simulating a backend outage
        for (int i = 0; i < threadCount; i++) {
            new Thread(() -> {
                try {
                    startLatch.await();
                    breaker.execute(() -> {
                        throw new RuntimeException("Backend unavailable");
                    });
                    succeeded.incrementAndGet();
                } catch (CircuitOpenException e) {
                    rejected.incrementAndGet(); // Circuit was open — fast fail!
                } catch (RuntimeException e) {
                    failed.incrementAndGet(); // Request went through but failed
                } catch (InterruptedException e) {
                    Thread.currentThread().interrupt();
                } finally {
                    doneLatch.countDown();
                }
            }).start();
        }

        startLatch.countDown();
        doneLatch.await();

        System.out.println("Results:");
        System.out.println("  Requests that hit backend (failed): " + failed.get());
        System.out.println("  Requests fast-rejected by circuit: " + rejected.get());
        System.out.println("  Circuit state: " + breaker.getState());
        System.out.println("  Total failures recorded: " + breaker.getFailureCount());
        System.out.println("\n  KEY INSIGHT: Only ~" + failed.get() + " requests hit the failing backend.");
        System.out.println("  The other " + rejected.get() + " were fast-rejected, protecting the backend.");

        // Phase 2: Wait for reset timeout, then send successful requests
        System.out.println("\n--- Phase 2: After reset timeout, service recovers ---");
        Thread.sleep(config.getResetTimeoutMs() + 50);

        CountDownLatch phase2Done = new CountDownLatch(5);
        AtomicInteger phase2Success = new AtomicInteger(0);

        for (int i = 0; i < 5; i++) {
            new Thread(() -> {
                try {
                    String result = breaker.execute(() -> "OK");
                    phase2Success.incrementAndGet();
                } catch (CircuitOpenException e) {
                    // May happen for threads that arrive while still HALF_OPEN
                } catch (Exception e) {
                    // Shouldn't happen
                } finally {
                    phase2Done.countDown();
                }
            }).start();
        }

        phase2Done.await();

        System.out.println("After recovery:");
        System.out.println("  Successful requests: " + phase2Success.get());
        System.out.println("  Circuit state: " + breaker.getState());

        // Summary
        System.out.println("\n--- Summary ---");
        System.out.println("Total requests: " + breaker.getTotalRequests());
        System.out.println("Successes: " + breaker.getSuccessCount());
        System.out.println("Failures: " + breaker.getFailureCount());
        System.out.println("Fast-rejected: " + breaker.getRejectedCount());
        System.out.println("Final state: " + breaker.getState());

        boolean circuitProtected = rejected.get() > 0; // Some requests were fast-failed
        boolean stateCorrect = breaker.getState() == CircuitState.CLOSED; // Recovery worked
        System.out.println("\nCircuit protected backend: " + (circuitProtected ? "PASSED" : "FAILED"));
        System.out.println("Circuit recovered correctly: " + (stateCorrect ? "PASSED" : "FAILED"));
    }
}

// concurrent/model/CircuitBreakerConfig.java — Configuration for circuit breaker behavior

class CircuitBreakerConfig {
    private final int failureThreshold;     // final = immutable config; safe to read from any thread
    private final long resetTimeoutMs;      // final = no synchronization needed to read these values
    private final int halfOpenMaxAttempts;  // private = encapsulated; accessed only via getters

    public CircuitBreakerConfig(int failureThreshold, long resetTimeoutMs, int halfOpenMaxAttempts) {
        this.failureThreshold = failureThreshold;
        this.resetTimeoutMs = resetTimeoutMs;
        this.halfOpenMaxAttempts = halfOpenMaxAttempts;
    }

    public int getFailureThreshold() { return failureThreshold; }
    public long getResetTimeoutMs() { return resetTimeoutMs; }
    public int getHalfOpenMaxAttempts() { return halfOpenMaxAttempts; }

    public static CircuitBreakerConfig defaultConfig() {
        return new CircuitBreakerConfig(5, 3000, 2);
    }

    public static CircuitBreakerConfig fastConfig() {
