// concurrent/Main.java — 20 threads borrowing from pool of 5, verify proper blocking and no double-borrow

import java.util.*;
import java.util.concurrent.*;
import java.util.concurrent.atomic.AtomicBoolean;
import java.util.concurrent.atomic.AtomicInteger;

public class Main {
    public static void main(String[] args) throws InterruptedException {
        System.out.println("=== Concurrent Object Pool Demo ===\n");

        int poolSize = 5;
        int threadCount = 20;
        ObjectPool pool = new ObjectPool(poolSize);

        CountDownLatch startLatch = new CountDownLatch(1);
        CountDownLatch doneLatch = new CountDownLatch(threadCount);
        AtomicBoolean doubleBorrow = new AtomicBoolean(false);
        AtomicInteger successfulBorrows = new AtomicInteger(0);
        ConcurrentHashMap<Integer, AtomicInteger> concurrentUsers = new ConcurrentHashMap<>();

        System.out.println("Scenario: 20 threads borrow from a pool of 5 objects.");
        System.out.println("  Each thread holds the object for 50ms then returns it.");
        System.out.println("Expected: No double-borrow, proper blocking, all threads served.\n");

        for (int t = 0; t < threadCount; t++) {
            new Thread(() -> {
                try {
                    startLatch.await();
                    PooledObject obj = pool.borrow(5000); // 5s timeout
                    if (obj != null) {
                        // Track concurrent usage of same object
                        AtomicInteger users = concurrentUsers.computeIfAbsent(
                            obj.getId(), k -> new AtomicInteger(0));
                        int active = users.incrementAndGet();
                        if (active > 1) {
                            doubleBorrow.set(true);
                        }

                        obj.use();
                        successfulBorrows.incrementAndGet();

                        // Simulate work
                        Thread.sleep(50);

                        users.decrementAndGet();
                        pool.returnObject(obj);
                    }
                } catch (InterruptedException e) {
                    Thread.currentThread().interrupt();
                } finally {
                    doneLatch.countDown();
                }
            }, "Worker-" + t).start();
        }

        startLatch.countDown();
        doneLatch.await();

        System.out.println("--- Results ---");
        System.out.println("Pool capacity: " + poolSize);
        System.out.println("Threads: " + threadCount);
        System.out.println("Successful borrows: " + successfulBorrows.get());
        System.out.println("Total borrows: " + pool.getBorrowCount());
        System.out.println("Total returns: " + pool.getReturnCount());
        System.out.println("Double-borrow detected: " + doubleBorrow.get());
        System.out.println("Final available: " + pool.getAvailable());

        boolean passed = !doubleBorrow.get()
                && successfulBorrows.get() == threadCount
                && pool.getAvailable() == poolSize;
        System.out.println("\nCorrectness check: " + (passed ? "PASSED" : "FAILED"));
    }
}

// concurrent/model/PooledObject.java — A pooled resource with ID and usage tracking

import java.util.concurrent.atomic.AtomicBoolean;
import java.util.concurrent.atomic.AtomicInteger;

public class PooledObject {
    private final int id;                                          // final = safe publication; readable from any thread
    private final AtomicBoolean inUse = new AtomicBoolean(false);  // AtomicBoolean = CAS-based acquire prevents double-borrow
    private final AtomicInteger usageCount = new AtomicInteger(0); // AtomicInteger = thread-safe usage counter

    public PooledObject(int id) {
        this.id = id;
    }

    public int getId() { return id; }

    public boolean acquire() {
        return inUse.compareAndSet(false, true); // CAS = only one thread wins; prevents double-borrow
    }

    public void release() {
        inUse.set(false);
    }

    public boolean isInUse() { return inUse.get(); }

    public void use() {
        usageCount.incrementAndGet();
    }

    public int getUsageCount() { return usageCount.get(); }

    @Override
    public String toString() {
        return "PooledObject[id=" + id + ", inUse=" + inUse.get() + "]";
    }
}

// concurrent/service/ObjectPool.java — Semaphore for capacity + ConcurrentLinkedDeque for idle objects

import java.util.concurrent.ConcurrentLinkedDeque;
import java.util.concurrent.Semaphore;
import java.util.concurrent.TimeUnit;
import java.util.concurrent.atomic.AtomicInteger;

public class ObjectPool {
    private final ConcurrentLinkedDeque<PooledObject> idle; // ConcurrentLinkedDeque = lock-free; threads poll/offer without blocking each other
    private final Semaphore semaphore;                      // Semaphore = limits concurrent borrows to capacity; threads block when exhausted
    private final int capacity;                             // final = pool size fixed at creation
    private final AtomicInteger borrowCount = new AtomicInteger(0); // AtomicInteger = lock-free stats counter
    private final AtomicInteger returnCount = new AtomicInteger(0);

    public ObjectPool(int capacity) {
        this.capacity = capacity;
        this.semaphore = new Semaphore(capacity);
        this.idle = new ConcurrentLinkedDeque<>();

        for (int i = 0; i < capacity; i++) {
            idle.offer(new PooledObject(i));
        }
    }

    /**
     * Borrow an object from the pool. Blocks if pool is exhausted.
     * Semaphore ensures no more than 'capacity' objects are borrowed simultaneously.
     */
    public PooledObject borrow(long timeoutMs) throws InterruptedException {
        if (!semaphore.tryAcquire(timeoutMs, TimeUnit.MILLISECONDS)) {
            return null; // timed out
        }
        PooledObject obj = idle.poll();
        if (obj != null) {
            obj.acquire();
            borrowCount.incrementAndGet();
            return obj;
        }
        // Should not happen if semaphore is correctly managed
        semaphore.release();
        return null;
    }

    /**
     * Return an object to the pool.
     */
    public void returnObject(PooledObject obj) {
        if (obj == null) return;
        obj.release();
        idle.offer(obj);
        returnCount.incrementAndGet();
        semaphore.release();
    }

    public int getAvailable() { return semaphore.availablePermits(); }
    public int getCapacity() { return capacity; }
    public int getBorrowCount() { return borrowCount.get(); }
    public int getReturnCount() { return returnCount.get(); }
}

