// command/Command.java — Interface for all editor operations (supports undo/redo)
// DESIGN PATTERN: Command
public interface Command {              // interface = contract all commands must fulfill
    void execute();                     // any command must know how to run itself
    void undo();                        // any command must know how to reverse itself
    String getDescription();
}

// command/DeleteCommand.java — Deletes text range, saves for undo
public class DeleteCommand implements Command { // implements = fulfills the Command contract
    private final Document document;            // final = target document never reassigned
    private final int position;                 // final = deletion start is immutable once set
    private final int length;                   // final = deletion length is immutable once set
    private String deletedText;                 // private = internal state hidden from outside

    public DeleteCommand(Document document, int position, int length) {
        this.document = document;
        this.position = position;
        this.length = length;
    }

    @Override public void execute() { deletedText = document.delete(position, length); } // @Override = proves we implement Command
    @Override public void undo() { document.insert(position, deletedText); }
    @Override public String getDescription() { return "Delete " + length + " at " + position; }
}

// command/InsertCommand.java — Inserts text at a position with undo support
public class InsertCommand implements Command { // implements = fulfills the Command contract
    private final Document document;            // final = target document never reassigned
    private final int position;                 // final = insertion point fixed at creation
    private final String text;                  // final = text to insert is immutable

    public InsertCommand(Document document, int position, String text) {
        this.document = document;
        this.position = position;
        this.text = text;
    }

    @Override public void execute() { document.insert(position, text); }
    @Override public void undo() { document.delete(position, text.length()); }
    @Override public String getDescription() { return "Insert \"" + text + "\" at " + position; }
}

// command/MacroCommand.java — Groups commands into single undoable unit
import java.util.ArrayList;
import java.util.List;

public class MacroCommand implements Command {           // implements = fulfills Command contract
    private final String name;                           // final = macro name set once at creation
    private final List<Command> commands = new ArrayList<>(); // private = only this class manages the list

    public MacroCommand(String name) { this.name = name; }
    public void addCommand(Command cmd) { commands.add(cmd); }

    @Override public void execute() { for (Command c : commands) c.execute(); }
    @Override public void undo() { for (int i = commands.size()-1; i >= 0; i--) commands.get(i).undo(); }
    @Override public String getDescription() { return "Macro \"" + name + "\" (" + commands.size() + " cmds)"; }
}

// command/ReplaceCommand.java — Replaces first occurrence of text
public class ReplaceCommand implements Command {   // implements = fulfills the Command contract
    private final Document document;               // final = document reference never changes
    private final String oldText;                  // final = search text is immutable
    private final String newText;                  // final = replacement text is immutable
    private int position = -1;                     // private = tracks where replacement occurred

    public ReplaceCommand(Document document, String oldText, String newText) {
        this.document = document;
        this.oldText = oldText;
        this.newText = newText;
    }

    @Override public void execute() {
        position = document.indexOf(oldText);
        if (position >= 0) {
            document.delete(position, oldText.length());
            document.insert(position, newText);
        }
    }
    @Override public void undo() {
        if (position >= 0) {
            document.delete(position, newText.length());
            document.insert(position, oldText);
        }
    }
    @Override public String getDescription() { return "Replace \"" + oldText + "\" -> \"" + newText + "\""; }
}

// model/Clipboard.java — Stores copied text for paste operations
public class Clipboard {
    private String content = "";       // private = encapsulates clipboard data from outside
    public void set(String text) { this.content = text; }
    public String get() { return content; }
    public boolean isEmpty() { return content == null || content.isEmpty(); }
}

// model/Document.java — Represents the text document being edited
public class Document {
    private StringBuilder content;     // private = only Document methods can modify text

    public Document() { this.content = new StringBuilder(); }
    public Document(String initial) { this.content = new StringBuilder(initial); }

    public void insert(int position, String text) { content.insert(position, text); }
    public String delete(int position, int length) {
        String deleted = content.substring(position, position + length);
        content.delete(position, position + length);
        return deleted;
    }
    public String getText() { return content.toString(); }
    public int length() { return content.length(); }
    public int indexOf(String text) { return content.indexOf(text); }

    // === Memento pattern ===
    // Document (originator) is the only class that can read the memento's
    // private state. Callers pass mementos around opaquely; they cannot peek.

    /** Capture current state into an opaque memento. */
    public DocumentMemento save() {
        return new DocumentMemento(content.toString());
    }

    /** Restore from a previously captured memento. */
    public void restore(DocumentMemento memento) {
        if (memento == null) throw new IllegalArgumentException("memento required");
        this.content = new StringBuilder(memento.getState()); // package-private getState — only Document calls this
    }

    @Override public String toString() { return "\"" + content + "\""; }
}

// model/DocumentMemento.java — Memento pattern: opaque snapshot of Document state
//
// GoF Memento roles:
//   - Originator: Document (creates the memento, restores from it)
//   - Memento: DocumentMemento (this class) — opaque to outsiders, transparent to Document
//   - Caretaker: history/undo stack (holds onto mementos but never inspects them)
//
// The state is private and only Document (the originator) can read it via
// the package-private accessor. Outside callers can only pass the memento
// back into Document.restore(memento) — they cannot inspect or mutate it.
public final class DocumentMemento {
    private final String state;          // private = caretaker cannot read; only Document can
    private final long capturedAtMillis; // private = metadata for tooling/debugging

    /** Package-private ctor: only Document is allowed to create mementos. */
    DocumentMemento(String state) {
        this.state = state;
        this.capturedAtMillis = System.currentTimeMillis();
    }

    /** Package-private accessor: only Document (in the same package/default-package) reads the state. */
    String getState() { return state; }

    /** Public, non-revealing metadata — safe for caretakers. */
    public long getCapturedAtMillis() { return capturedAtMillis; }

    @Override public String toString() {
        return "DocumentMemento[" + state.length() + " chars @ " + capturedAtMillis + "]";
    }
}

// service/CommandHistory.java — Unlimited undo/redo stacks (potential memory leak)
import java.util.Stack;

public class CommandHistory {
    private final Stack<Command> undoStack = new Stack<>();  // private final = stack ref never changes
    private final Stack<Command> redoStack = new Stack<>();  // private final = stack ref never changes

    public void execute(Command command) {
        command.execute();
        undoStack.push(command);
        redoStack.clear();
    }

    public boolean undo() {
        if (undoStack.isEmpty()) return false;
        Command cmd = undoStack.pop();
        cmd.undo();
        redoStack.push(cmd);
        return true;
    }

    public boolean redo() {
        if (redoStack.isEmpty()) return false;
        Command cmd = redoStack.pop();
        cmd.execute();
        undoStack.push(cmd);
        return true;
    }

    public int getUndoCount() { return undoStack.size(); }
    public int getRedoCount() { return redoStack.size(); }
}

// service/Editor.java — Orchestrates editing via command pattern
public class Editor {
    private final Document document;         // final = document reference never changes
    private final CommandHistory history;     // final = history reference never changes
    private final Clipboard clipboard;       // final = clipboard reference never changes

    public Editor() { this(""); }
    public Editor(String text) {
        this.document = new Document(text);
        this.history = new CommandHistory();
        this.clipboard = new Clipboard();
    }

    public void insert(int pos, String text) { history.execute(new InsertCommand(document, pos, text)); }
    public void delete(int pos, int len) { history.execute(new DeleteCommand(document, pos, len)); }
    public void replace(String old, String nw) { history.execute(new ReplaceCommand(document, old, nw)); }
    public void executeMacro(MacroCommand macro) { history.execute(macro); }
    public boolean undo() { return history.undo(); }
    public boolean redo() { return history.redo(); }

    public String getText() { return document.getText(); }
    public Document getDocument() { return document; }
    public Clipboard getClipboard() { return clipboard; }
    public CommandHistory getHistory() { return history; }
    @Override public String toString() { return document.toString(); }
}

// Main.java — Demonstrates bounded circular-buffer history and composite macros
public class Main {
    public static void main(String[] args) {
        System.out.println("=== Command Editor (Optimized: Bounded History) Demo ===\n");

        // --- Test 1: Basic Editing with Bounded History (max 5) ---
        System.out.println("--- Test 1: Bounded History (max=5) ---");
        Editor editor = new Editor(5);
        editor.insert(0, "A");
        editor.insert(1, "B");
        editor.insert(2, "C");
        editor.insert(3, "D");
        editor.insert(4, "E");
        System.out.println("  After 5 inserts: " + editor);
        System.out.println("  History size: " + editor.getHistory().getCurrentSize() + "/" + editor.getHistory().getMaxSize());

        // --- Test 2: Overflow (6th command evicts oldest) ---
        System.out.println("\n--- Test 2: History Overflow ---");
        editor.insert(5, "F");
        editor.insert(6, "G");
        System.out.println("  After 7 total inserts: " + editor);
        System.out.println("  History size capped at: " + editor.getHistory().getCurrentSize());

        // Undo all available (only 5 most recent)
        int undone = 0;
        while (editor.undo()) undone++;
        System.out.println("  Undone " + undone + " commands (max 5 available)");
        System.out.println("  Document: " + editor);

        // --- Test 3: Redo ---
        System.out.println("\n--- Test 3: Redo ---");
        editor.redo();
        editor.redo();
        System.out.println("  After 2 redos: " + editor);

        // --- Test 4: Macro as Single Undo Step ---
        System.out.println("\n--- Test 4: Macro (composite) ---");
        Editor e2 = new Editor("Hello World", 10);
        MacroCommand macro = new MacroCommand("transform");
        macro.addCommand(new DeleteCommand(e2.getDocument(), 6, 5));
        macro.addCommand(new InsertCommand(e2.getDocument(), 6, "Java"));
        macro.addCommand(new InsertCommand(e2.getDocument(), 10, "!"));
        e2.executeMacro(macro);
        System.out.println("  After macro (3 ops, 1 undo step): " + e2);
        e2.undo(); // Undoes entire macro
        System.out.println("  After single undo: " + e2);

        // --- Test 5: Memory Bounded ---
        System.out.println("\n--- Test 5: Memory Stays Bounded ---");
        Editor bigEditor = new Editor(10); // Max 10 history entries
        for (int i = 0; i < 1000; i++) {
            bigEditor.insert(i, String.valueOf((char)('A' + i % 26)));
        }
        System.out.println("  1000 edits done, history still: " + bigEditor.getHistory().getCurrentSize());
        System.out.println("  Last: " + bigEditor.getHistory().getLastDescription());

        System.out.println("\n=== Command Editor (Optimized) Demo Complete ===");
    }
}

// command/Command.java — Interface for all editor operations
// DESIGN PATTERN: Command
public interface Command {              // interface = contract all commands must fulfill
    void execute();
    void undo();
    String getDescription();
}

// command/DeleteCommand.java — Deletes text range with undo
public class DeleteCommand implements Command { // implements = fulfills the Command contract
    private final Document document;            // final = reference never reassigned after init
    private final int position;                 // final = deletion start fixed at creation
    private final int length;                   // final = deletion length fixed at creation
    private String deletedText;                 // stores removed text for undo restoration

    public DeleteCommand(Document document, int position, int length) {
        this.document = document;
        this.position = position;
        this.length = length;
    }

    @Override public void execute() { deletedText = document.delete(position, length); }
    @Override public void undo() { document.insert(position, deletedText); }
    @Override public String getDescription() { return "Delete " + length + " at " + position; }
}

// command/InsertCommand.java — Inserts text at position
public class InsertCommand implements Command { // implements = fulfills the Command contract
    private final Document document;            // final = reference never reassigned
    private final int position;                 // final = insertion point fixed at creation
    private final String text;                  // final = text to insert is immutable

    public InsertCommand(Document document, int position, String text) {
        this.document = document;
        this.position = position;
        this.text = text;
    }

    @Override public void execute() { document.insert(position, text); }
    @Override public void undo() { document.delete(position, text.length()); }
    @Override public String getDescription() { return "Insert at " + position; }
}

// command/MacroCommand.java — Composite macro that counts as single undo step
import java.util.ArrayList;
import java.util.List;

public class MacroCommand implements Command {           // implements = fulfills Command contract
    private final String name;                           // final = macro name set once
    private final List<Command> commands = new ArrayList<>(); // List = ordered sub-commands

    public MacroCommand(String name) { this.name = name; }
    public void addCommand(Command cmd) { commands.add(cmd); }

    @Override public void execute() { for (Command c : commands) c.execute(); }
    @Override public void undo() { for (int i = commands.size()-1; i >= 0; i--) commands.get(i).undo(); }
    @Override public String getDescription() { return "Macro \"" + name + "\" (" + commands.size() + " cmds)"; }
    public int getCommandCount() { return commands.size(); }
}

// model/Document.java — Text document with Memento-pattern snapshot/restore
//
// Document plays the *Originator* role in the Memento pattern. It hands out
// opaque DocumentMemento instances; only Document itself can read their state.
public class Document {
    private StringBuilder content;     // StringBuilder = mutable text; efficient for edits

    public Document() { this.content = new StringBuilder(); }
    public Document(String initial) { this.content = new StringBuilder(initial); }

    public void insert(int position, String text) { content.insert(position, text); }
    public String delete(int position, int length) {
        String deleted = content.substring(position, position + length);
        content.delete(position, position + length);
        return deleted;
    }
    public String getText() { return content.toString(); }
    public int length() { return content.length(); }
    public int indexOf(String text) { return content.indexOf(text); }

    // === Memento pattern ===

    /** Capture current state into an opaque memento (Originator -> Memento). */
    public DocumentMemento save() {
        return new DocumentMemento(content.toString());
    }

    /** Restore from a previously captured memento. Only Document reads memento internals. */
    public void restore(DocumentMemento memento) {
        if (memento == null) throw new IllegalArgumentException("memento required");
        this.content = new StringBuilder(memento.getState()); // package-private accessor
    }

    @Override public String toString() { return "\"" + content + "\""; }
}

// model/DocumentMemento.java — Memento pattern: opaque snapshot of Document state
//
// GoF Memento roles:
//   - Originator: Document (creates the memento, restores from it)
//   - Memento: DocumentMemento (this class) — opaque to outsiders, transparent to Document
//   - Caretaker: BoundedHistory (holds onto mementos but never inspects them)
//
// The state is private and only Document (the originator) can read it via
// the package-private accessor. Outside callers can only pass the memento
// back into Document.restore(memento) — they cannot inspect or mutate it.
public final class DocumentMemento {
    private final String state;          // private = caretaker cannot read; only Document can
    private final long capturedAtMillis; // private = metadata for tooling/debugging

    /** Package-private ctor: only Document is allowed to create mementos. */
    DocumentMemento(String state) {
        this.state = state;
        this.capturedAtMillis = System.currentTimeMillis();
    }

    /** Package-private accessor: only Document (in the same package/default-package) reads the state. */
    String getState() { return state; }

    /** Public, non-revealing metadata — safe for caretakers. */
    public long getCapturedAtMillis() { return capturedAtMillis; }

    /** Approximate size for diagnostic logging (does not reveal content). */
    public int approximateSize() { return state.length(); }

    @Override public String toString() {
        return "DocumentMemento[" + state.length() + " chars @ " + capturedAtMillis + "]";
    }
}

// service/BoundedHistory.java — Circular buffer for bounded undo history (prevents memory leak)
public class BoundedHistory {
    // WHY circular buffer: Naive Stack grows unbounded — a 10-hour editing session
    // accumulates thousands of commands. Circular buffer caps memory at O(maxSize)
    // and naturally evicts the oldest operations.
    private final Command[] buffer;             // Command[] = fixed-size circular buffer for O(1) ops
    private final DocumentMemento[] snapshots;  // Memento pattern: opaque snapshots; this class is the *caretaker*
    private int head = 0;     // write position
    private int size = 0;     // current number of valid entries
    private int undoPos = 0;  // current position for undo/redo
    private final Document document;         // final = document ref never changes

    public BoundedHistory(int maxSize, Document document) {
        this.buffer = new Command[maxSize];
        this.snapshots = new DocumentMemento[maxSize];
        this.document = document;
    }

    public void execute(Command command) {
        command.execute();

        // WHY snapshot on boundary: When oldest entry is about to be overwritten,
        // save a snapshot so we can still "undo to beginning" of visible history.
        // BoundedHistory is the *caretaker* in the Memento pattern: it stores the
        // memento opaquely and never inspects its contents.
        if (size == buffer.length) {
            // About to overwrite oldest — take snapshot at eviction point
            snapshots[head] = null; // Clear old snapshot
        }
        if (size == 0 || (size == buffer.length && snapshots[(head) % buffer.length] == null)) {
            snapshots[head] = document.save();
        }

        buffer[head] = command;
        head = (head + 1) % buffer.length;
        if (size < buffer.length) size++;
        undoPos = 0; // Reset redo capability
    }

    public boolean undo() {
        if (undoPos >= size) return false;
        undoPos++;
        int idx = Math.floorMod(head - undoPos, buffer.length);
        Command cmd = buffer[idx];
        if (cmd == null) return false;
        cmd.undo();
        return true;
    }

    public boolean redo() {
        if (undoPos <= 0) return false;
        undoPos--;
        int idx = Math.floorMod(head - undoPos - 1, buffer.length);
        Command cmd = buffer[idx];
        if (cmd == null) return false;
        cmd.execute();
        return true;
    }

    public int getUndoDepth() { return size - undoPos; }
    public int getMaxSize() { return buffer.length; }
    public int getCurrentSize() { return size; }

    public String getLastDescription() {
        if (size == 0) return "none";
        int idx = Math.floorMod(head - 1, buffer.length);
        return buffer[idx] == null ? "none" : buffer[idx].getDescription();
    }
}

// service/Editor.java — Editor with bounded history to prevent memory leaks
public class Editor {
    private final Document document;         // final = document ref set once at creation
    private final BoundedHistory history;    // BoundedHistory = circular buffer caps memory usage

    public Editor(int maxHistory) { this("", maxHistory); }
    public Editor(String text, int maxHistory) {
        this.document = new Document(text);
        this.history = new BoundedHistory(maxHistory, document);
    }

    public void insert(int pos, String text) { history.execute(new InsertCommand(document, pos, text)); }
    public void delete(int pos, int len) { history.execute(new DeleteCommand(document, pos, len)); }
    public void executeMacro(MacroCommand macro) { history.execute(macro); }
    public boolean undo() { return history.undo(); }
    public boolean redo() { return history.redo(); }

    public String getText() { return document.getText(); }
    public Document getDocument() { return document; }
    public BoundedHistory getHistory() { return history; }
    @Override public String toString() { return document.toString(); }
}

// concurrent/Main.java — 2 editor threads with interleaved edits, verify no lost edits

import java.util.concurrent.*;
import java.util.concurrent.atomic.AtomicInteger;

public class Main {
    public static void main(String[] args) throws InterruptedException {
        System.out.println("=== Concurrent Command Pattern Editor Demo ===\n");

        ConcurrentDocument doc = new ConcurrentDocument();
        int editsPerEditor = 50;
        int editorCount = 2;
        CountDownLatch startLatch = new CountDownLatch(1);
        CountDownLatch doneLatch = new CountDownLatch(editorCount);
        AtomicInteger totalEditsAttempted = new AtomicInteger(0);

        System.out.println("Scenario: 2 editor threads each make 50 edits with optimistic locking.");
        System.out.println("  Each edit uses CAS to check version before applying.");
        System.out.println("Expected: All 100 edits eventually applied, no lost edits.\n");

        for (int e = 0; e < editorCount; e++) {
            final String editorName = "Editor-" + (char)('A' + e);
            new Thread(() -> {
                try {
                    startLatch.await();
                    for (int i = 0; i < editsPerEditor; i++) {
                        String text = editorName + "-line-" + i;
                        doc.applyEditWithRetry(editorName, text);
                        totalEditsAttempted.incrementAndGet();
                    }
                } catch (InterruptedException ex) {
                    Thread.currentThread().interrupt();
                } finally {
                    doneLatch.countDown();
                }
            }, editorName).start();
        }

        startLatch.countDown();
        doneLatch.await();

        int expectedTotal = editorCount * editsPerEditor;

        System.out.println("--- Results ---");
        System.out.println("Total edits applied: " + doc.getSuccessfulEdits());
        System.out.println("Conflicts detected (retried): " + doc.getConflictedEdits());
        System.out.println("Document version: " + doc.getVersion());
        System.out.println("Content lines: " + doc.getContentSize());
        System.out.println("History entries: " + doc.getHistorySize());
        System.out.println("Expected total: " + expectedTotal);

        boolean passed = doc.getSuccessfulEdits() == expectedTotal
                && doc.getContentSize() == expectedTotal
                && doc.getVersion() == expectedTotal;
        System.out.println("\nCorrectness check: " + (passed ? "PASSED" : "FAILED"));
    }
}

// concurrent/model/EditCommand.java — Immutable edit command with version tracking

public class EditCommand {
    private final String editor;             // final = safe publication; visible to all threads
    private final String text;               // final = immutable once constructed; no synchronization needed
    private final int expectedVersion;       // final = version snapshot for CAS comparison
    private final long timestamp;            // final = creation time for ordering/debugging

    public EditCommand(String editor, String text, int expectedVersion) {
        this.editor = editor;
        this.text = text;
        this.expectedVersion = expectedVersion;
        this.timestamp = System.nanoTime();
    }

    public String getEditor() { return editor; }
    public String getText() { return text; }
    public int getExpectedVersion() { return expectedVersion; }
    public long getTimestamp() { return timestamp; }

    @Override
    public String toString() {
        return "Edit[" + editor + ": '" + text + "' @v" + expectedVersion + "]";
    }
}

// concurrent/service/ConcurrentDocument.java — AtomicInteger version + CAS-based optimistic locking

import java.util.concurrent.atomic.AtomicInteger;
import java.util.concurrent.CopyOnWriteArrayList;

public class ConcurrentDocument {
    private final AtomicInteger version = new AtomicInteger(0);       // AtomicInteger = lock-free version counter for CAS
    private final CopyOnWriteArrayList<String> content = new CopyOnWriteArrayList<>(); // CopyOnWriteArrayList = safe concurrent reads without locking
    private final CopyOnWriteArrayList<EditCommand> history = new CopyOnWriteArrayList<>(); // thread-safe append-only log

    private final AtomicInteger successfulEdits = new AtomicInteger(0);  // AtomicInteger = lock-free success counter
    private final AtomicInteger conflictedEdits = new AtomicInteger(0);  // AtomicInteger = lock-free conflict counter

    /**
     * Apply an edit using optimistic locking.
     * Only succeeds if the document version matches the editor's expected version.
     */
    public boolean applyEdit(EditCommand command) {
        // CAS: only apply if version hasn't changed since editor last read it
        int currentVersion = version.get();
        if (currentVersion != command.getExpectedVersion()) {
            conflictedEdits.incrementAndGet();
            return false; // Conflict — editor must re-read and retry
        }

        // Try to advance version atomically
        if (version.compareAndSet(currentVersion, currentVersion + 1)) { // CAS = atomic compare-and-swap; no locks needed
            content.add(command.getText());
            history.add(command);
            successfulEdits.incrementAndGet();
            return true;
        }

        conflictedEdits.incrementAndGet();
        return false; // CAS failed — concurrent edit
    }

    /**
     * Apply edit with retry loop — keeps retrying until it succeeds.
     */
    public void applyEditWithRetry(String editor, String text) {
        while (true) {
            int ver = version.get();
            EditCommand cmd = new EditCommand(editor, text, ver);
            if (applyEdit(cmd)) return;
            // Re-read version and retry
            Thread.yield();
        }
    }

    public int getVersion() { return version.get(); }
    public int getContentSize() { return content.size(); }
    public int getHistorySize() { return history.size(); }
    public int getSuccessfulEdits() { return successfulEdits.get(); }
    public int getConflictedEdits() { return conflictedEdits.get(); }

    public String getContentAt(int index) {
        return index < content.size() ? content.get(index) : null;
    }
}

