// Main.java — Demonstrates state machine with if-else transition lookup
public class Main {
    public static void main(String[] args) {
        System.out.println("=== State Machine (Naive) Demo ===\n");

        // Order lifecycle state machine
        System.out.println("--- Order State Machine ---");
        StateMachine sm = new StateMachineBuilder("Order")
                .initialState("CREATED")
                .state("PENDING").state("PAID").state("SHIPPED").state("DELIVERED").state("CANCELLED")
                .transition("CREATED", "SUBMIT", "PENDING", new Action() {
                    public void execute(Event e) { System.out.println("    [Action] Sending confirmation"); }
                    public String getDescription() { return "confirm"; }
                })
                .transition("PENDING", "PAY", "PAID")
                .transition("PAID", "SHIP", "SHIPPED")
                .transition("SHIPPED", "DELIVER", "DELIVERED")
                .transition("CREATED", "CANCEL", "CANCELLED")
                .transition("PENDING", "CANCEL", "CANCELLED")
                .build();

        sm.fire("SUBMIT");
        sm.fire("PAY");
        sm.fire("SHIP");
        sm.fire("DELIVER");
        System.out.println("  Final: " + sm.getCurrentStateName());
        System.out.println("  History: " + sm.getHistory());

        // Invalid transition
        System.out.println("\n--- Invalid Transition ---");
        StateMachine sm2 = new StateMachineBuilder("Order2")
                .initialState("CREATED").state("PENDING")
                .transition("CREATED", "SUBMIT", "PENDING")
                .build();
        sm2.fire("DELIVER");

        // Traffic light with entry actions
        System.out.println("\n--- Traffic Light ---");
        StateMachine light = new StateMachineBuilder("Light")
                .initialState("RED").state("GREEN").state("YELLOW")
                .onEntry("RED", new Action() { public void execute(Event e) { System.out.println("    STOP!"); } public String getDescription() { return ""; } })
                .onEntry("GREEN", new Action() { public void execute(Event e) { System.out.println("    GO!"); } public String getDescription() { return ""; } })
                .transition("RED", "TIMER", "GREEN")
                .transition("GREEN", "TIMER", "YELLOW")
                .transition("YELLOW", "TIMER", "RED")
                .build();
        light.fire("TIMER");
        light.fire("TIMER");
        light.fire("TIMER");

        System.out.println("\n=== State Machine (Naive) Demo Complete ===");
    }
}

// model/Action.java — Side-effect executed during a transition
public interface Action {               // interface = contract for any transition side-effect
    void execute(Event event);
    String getDescription();
}

// model/Event.java — Trigger that may cause a state transition
public class Event {
    private final String name;             // final = event name is immutable once created
    private final Object payload;          // final = payload is immutable; carries extra data

    public Event(String name) { this(name, null); }
    public Event(String name, Object payload) { this.name = name; this.payload = payload; }

    public String getName() { return name; }
    public Object getPayload() { return payload; }
    @Override public String toString() { return name; }
    @Override public int hashCode() { return name.hashCode(); }
    @Override public boolean equals(Object o) {
        if (this == o) return true;
        if (o == null || getClass() != o.getClass()) return false;
        return name.equals(((Event) o).name);
    }
}

// model/State.java — Named state with entry/exit actions and transitions list
import java.util.ArrayList;
import java.util.List;

public class State {
    private final String name;                                  // final = state name is immutable
    private final List<Transition> transitions = new ArrayList<>(); // private = only this class manages transitions
    private Action entryAction;                                 // private = action run when entering this state
    private Action exitAction;                                  // private = action run when leaving this state

    public State(String name) { this.name = name; }

    public void addTransition(Transition t) { transitions.add(t); }
    public void setEntryAction(Action a) { this.entryAction = a; }
    public void setExitAction(Action a) { this.exitAction = a; }

    public void onEntry(Event e) { if (entryAction != null) entryAction.execute(e); }
    public void onExit(Event e) { if (exitAction != null) exitAction.execute(e); }

    // Linear search through transitions for matching event
    public Transition findTransition(Event event) {
        for (Transition t : transitions) {
            if (t.getEventName().equals(event.getName())) {
                if (t.getGuard() == null || t.getGuard().evaluate(event)) return t;
            }
        }
        return null;
    }

    public String getName() { return name; }
    @Override public String toString() { return name; }
}

// model/Transition.java — Defines a valid state transition with optional guard and action
public class Transition {
    private final State source;            // final = source state is fixed at creation
    private final State target;            // final = target state is fixed at creation
    private final String eventName;        // final = triggering event name is immutable
    private final Guard guard;             // final = optional condition; null means always allowed
    private final Action action;           // final = optional side-effect during transition

    public Transition(State source, State target, String eventName, Guard guard, Action action) {
        this.source = source;
        this.target = target;
        this.eventName = eventName;
        this.guard = guard;
        this.action = action;
    }

    public State getTarget() { return target; }
    public String getEventName() { return eventName; }
    public Guard getGuard() { return guard; }
    public void executeAction(Event e) { if (action != null) action.execute(e); }
}

// service/StateMachine.java — Executes transitions via if-else linear search in State
import java.util.ArrayList;
import java.util.HashMap;
import java.util.List;
import java.util.Map;

public class StateMachine {
    private final String name;                             // final = machine name set once
    private State currentState;                            // private = only machine controls state changes
    private final List<String> history = new ArrayList<>(); // private = internal transition log

    public StateMachine(String name, State initialState) {
        this.name = name;
        this.currentState = initialState;
        history.add(initialState.getName());
    }

    public boolean fire(Event event) {
        Transition t = currentState.findTransition(event);
        if (t == null) {
            System.out.println("  [" + name + "] No transition for '" + event.getName() + "' in " + currentState.getName());
            return false;
        }
        currentState.onExit(event);
        t.executeAction(event);
        State oldState = currentState;
        currentState = t.getTarget();
        currentState.onEntry(event);
        history.add(currentState.getName());
        System.out.println("  [" + name + "] " + oldState.getName() + " --[" + event.getName() + "]--> " + currentState.getName());
        return true;
    }

    public boolean fire(String eventName) { return fire(new Event(eventName)); }
    public String getCurrentStateName() { return currentState.getName(); }
    public List<String> getHistory() { return history; }
}

// service/StateMachineBuilder.java — Fluent builder for constructing state machines
import java.util.HashMap;
import java.util.Map;

public class StateMachineBuilder {
    private final String name;                             // final = builder name set once
    private final Map<String, State> states = new HashMap<>(); // private = internal registry of states
    private String initialStateName;                       // private = tracks which state is first

    public StateMachineBuilder(String name) { this.name = name; }

    public StateMachineBuilder state(String s) { states.putIfAbsent(s, new State(s)); return this; }
    public StateMachineBuilder initialState(String s) { state(s); initialStateName = s; return this; }

    public StateMachineBuilder onEntry(String s, Action a) { state(s); states.get(s).setEntryAction(a); return this; }
    public StateMachineBuilder onExit(String s, Action a) { state(s); states.get(s).setExitAction(a); return this; }

    public StateMachineBuilder transition(String from, String event, String to) { return transition(from, event, to, null, null); }
    public StateMachineBuilder transition(String from, String event, String to, Action action) { return transition(from, event, to, null, action); }
    public StateMachineBuilder transition(String from, String event, String to, Guard guard, Action action) {
        state(from); state(to);
        states.get(from).addTransition(new Transition(states.get(from), states.get(to), event, guard, action));
        return this;
    }

    public StateMachine build() {
        if (initialStateName == null) throw new IllegalStateException("No initial state");
        return new StateMachine(name, states.get(initialStateName));
    }
}

// strategy/Guard.java — Condition that must be true for a transition to fire
public interface Guard {                // interface = contract for transition conditions
    boolean evaluate(Event event);      // returns true if transition is allowed
    String getDescription();
