// model/Action.java — Side-effect executed during a transition
public interface Action {               // interface = contract; can be a lambda for concise use
    void execute(Event event);
}

// model/Event.java — Trigger that causes state transitions
public class Event {
    private final String name;             // final = event name immutable after creation
    private final Object payload;          // final = extra data attached to event

    public Event(String name) { this(name, null); }
    public Event(String name, Object payload) { this.name = name; this.payload = payload; }

    public String getName() { return name; }
    public Object getPayload() { return payload; }
    @Override public String toString() { return name; }
}

// model/Guard.java — Condition evaluated before allowing a transition
public interface Guard {                // interface = contract; can be a lambda predicate
    boolean evaluate(Event event);
}

// model/Transition.java — Transition definition with target, guard, and action
public class Transition {
    private final String targetState;      // final = destination state fixed at creation
    private final Guard guard;             // final = optional condition; null means always pass
    private final Action action;           // final = optional side-effect on transition

    public Transition(String targetState, Guard guard, Action action) {
        this.targetState = targetState;
        this.guard = guard;
        this.action = action;
    }

    public String getTargetState() { return targetState; }
    public Guard getGuard() { return guard; }
    public Action getAction() { return action; }

    public boolean isAllowed(Event event) {
        return guard == null || guard.evaluate(event);
    }

    public void executeAction(Event event) {
        if (action != null) action.execute(event);
    }
}

// model/TransitionKey.java — Composite key (state + event) for O(1) transition table lookup
import java.util.Objects;

public class TransitionKey {
    private final String state;            // final = state part of key is immutable
    private final String event;            // final = event part of key is immutable

    public TransitionKey(String state, String event) {
        this.state = state;
        this.event = event;
    }

    // WHY composite key: HashMap<(State,Event), List<Transition>> gives O(1)
    // lookup vs. naive O(n) linear scan through all transitions in a state.
    @Override
    public boolean equals(Object o) {
        if (this == o) return true;
        if (!(o instanceof TransitionKey)) return false;
        TransitionKey k = (TransitionKey) o;
        return state.equals(k.state) && event.equals(k.event);
    }

    @Override
    public int hashCode() { return Objects.hash(state, event); }

    @Override
    public String toString() { return "(" + state + "," + event + ")"; }
}

// service/StateMachine.java — O(1) transition lookup via HashMap<TransitionKey, List<Transition>>
import java.util.ArrayList;
import java.util.HashMap;
import java.util.HashSet;
import java.util.List;
import java.util.Map;
import java.util.Set;

public class StateMachine {
    private final String name;
    // WHY HashMap: O(1) transition lookup by (state, event) composite key.
    // Naive approach uses if-else or linear scan through all transitions in a state = O(n).
    private final Map<TransitionKey, List<Transition>> transitionTable; // HashMap = O(1) lookup by composite key
    private final Map<String, Action> entryActions;  // HashMap = O(1) entry action lookup by state name
    private final Map<String, Action> exitActions;   // HashMap = O(1) exit action lookup by state name
    private String currentState;                     // private = only fire() changes state
    private final List<String> history = new ArrayList<>(); // tracks visited states in order

    StateMachine(String name, String initialState,
                 Map<TransitionKey, List<Transition>> transitionTable,
                 Map<String, Action> entryActions,
                 Map<String, Action> exitActions) {
        this.name = name;
        this.currentState = initialState;
        this.transitionTable = transitionTable;
        this.entryActions = entryActions;
        this.exitActions = exitActions;
        history.add(initialState);
    }

    public boolean fire(Event event) {
        TransitionKey key = new TransitionKey(currentState, event.getName());
        List<Transition> candidates = transitionTable.get(key);

        if (candidates == null || candidates.isEmpty()) {
            System.out.println("  [" + name + "] No transition for '" + event.getName() + "' in " + currentState);
            return false;
        }

        // WHY list of candidates: Multiple transitions for same (state, event)
        // with different guards — first passing guard wins (priority by order).
        for (Transition t : candidates) {
            if (t.isAllowed(event)) {
                String oldState = currentState;

                // Exit action
                Action exitAction = exitActions.get(currentState);
                if (exitAction != null) exitAction.execute(event);

                // Transition action
                t.executeAction(event);

                // State change
                currentState = t.getTargetState();

                // Entry action
                Action entryAction = entryActions.get(currentState);
                if (entryAction != null) entryAction.execute(event);

                history.add(currentState);
                System.out.println("  [" + name + "] " + oldState + " --[" + event.getName() + "]--> " + currentState);
                return true;
            }
        }

        System.out.println("  [" + name + "] All guards failed for '" + event.getName() + "' in " + currentState);
        return false;
    }

    public boolean fire(String eventName) { return fire(new Event(eventName)); }
    public String getCurrentState() { return currentState; }
    public List<String> getHistory() { return history; }
}

// service/StateMachineBuilder.java — Builder that validates at construction time and builds transition table
import java.util.ArrayList;
import java.util.HashMap;
import java.util.HashSet;
import java.util.List;
import java.util.Map;
import java.util.Set;

public class StateMachineBuilder {
    private final String name;
    private final Set<String> states = new HashSet<>();           // HashSet = O(1) state existence check
    private String initialState;
    private final Map<TransitionKey, List<Transition>> transitionTable = new HashMap<>(); // HashMap = O(1) lookup table built here
    private final Map<String, Action> entryActions = new HashMap<>();
    private final Map<String, Action> exitActions = new HashMap<>();

    public StateMachineBuilder(String name) { this.name = name; }

    public StateMachineBuilder state(String s) { states.add(s); return this; }
    public StateMachineBuilder initialState(String s) { states.add(s); initialState = s; return this; }
    public StateMachineBuilder onEntry(String s, Action a) { states.add(s); entryActions.put(s, a); return this; }
    public StateMachineBuilder onExit(String s, Action a) { states.add(s); exitActions.put(s, a); return this; }

    public StateMachineBuilder transition(String from, String event, String to) {
        return transition(from, event, to, null, null);
    }
    public StateMachineBuilder transition(String from, String event, String to, Action action) {
        return transition(from, event, to, null, action);
    }
    public StateMachineBuilder transition(String from, String event, String to, Guard guard, Action action) {
        states.add(from);
        states.add(to);
        TransitionKey key = new TransitionKey(from, event);
        transitionTable.computeIfAbsent(key, k -> new ArrayList<>())
                .add(new Transition(to, guard, action));
        return this;
    }

    // WHY validate at build time: Catches misconfiguration early (missing states,
    // unreachable states, dangling targets) rather than at runtime.
    public StateMachine build() {
        if (initialState == null) throw new IllegalStateException("No initial state set");
        if (!states.contains(initialState)) throw new IllegalStateException("Initial state not in state set");

        // Validate all transition targets exist
        for (var entry : transitionTable.entrySet()) {
            for (Transition t : entry.getValue()) {
                if (!states.contains(t.getTargetState())) {
                    throw new IllegalStateException("Target state '" + t.getTargetState() + "' not defined");
                }
            }
        }

        return new StateMachine(name, initialState, transitionTable, entryActions, exitActions);
    }
}

// concurrent/Main.java — Multiple event threads, verify no invalid state ever observed

import java.util.concurrent.*;
import java.util.concurrent.atomic.AtomicBoolean;
import java.util.concurrent.atomic.AtomicInteger;

public class Main {
    public static void main(String[] args) throws InterruptedException {
        System.out.println("=== Concurrent State Machine Demo ===\n");

        ConcurrentStateMachine sm = new ConcurrentStateMachine(State.CREATED);
        int threadCount = 10;
        CountDownLatch startLatch = new CountDownLatch(1);
        CountDownLatch doneLatch = new CountDownLatch(threadCount);
        AtomicBoolean invalidStateObserved = new AtomicBoolean(false);
        AtomicInteger attempts = new AtomicInteger(0);

        System.out.println("Scenario: 10 threads try various transitions simultaneously.");
        System.out.println("  Some try CREATED->VALIDATED, others CREATED->CANCELLED, etc.");
        System.out.println("Expected: Only valid transitions succeed, no invalid state observed.\n");

        // Different threads try different transitions
        State[][] transitionAttempts = {
            {State.VALIDATED},                           // thread 0
            {State.CANCELLED},                          // thread 1
            {State.VALIDATED, State.PROCESSING},        // thread 2
            {State.CANCELLED},                          // thread 3
            {State.VALIDATED, State.PROCESSING, State.SHIPPED}, // thread 4
            {State.VALIDATED},                           // thread 5
            {State.CANCELLED},                          // thread 6
            {State.VALIDATED, State.PROCESSING, State.SHIPPED, State.DELIVERED}, // thread 7
            {State.VALIDATED, State.CANCELLED},          // thread 8
            {State.VALIDATED, State.PROCESSING},         // thread 9
        };

        for (int t = 0; t < threadCount; t++) {
            final State[] targetStates = transitionAttempts[t];
            new Thread(() -> {
                try {
                    startLatch.await();
                    for (State target : targetStates) {
                        attempts.incrementAndGet();
                        sm.transition(target);

                        // Verify current state is always a valid State enum value
                        State observed = sm.getCurrentState();
                        if (observed == null) {
                            invalidStateObserved.set(true);
                        }
                    }
                } catch (Exception e) {
                    invalidStateObserved.set(true);
                    e.printStackTrace();
                } finally {
                    doneLatch.countDown();
                }
            }, "EventThread-" + t).start();
        }

        startLatch.countDown();
        doneLatch.await();

        boolean historyValid = sm.isHistoryValid();

        System.out.println("--- Results ---");
        System.out.println("Final state: " + sm.getCurrentState());
        System.out.println("Transition attempts: " + attempts.get());
        System.out.println("Successful transitions: " + sm.getSuccessfulTransitions());
        System.out.println("Rejected (CAS conflict): " + sm.getRejectedTransitions());
        System.out.println("Invalid (wrong source state): " + sm.getInvalidTransitions());
        System.out.println("Transition history valid: " + historyValid);
        System.out.println("History length: " + sm.getHistorySize());
        System.out.println("Invalid state observed: " + invalidStateObserved.get());

        boolean passed = historyValid && !invalidStateObserved.get();
        System.out.println("\nCorrectness check: " + (passed ? "PASSED" : "FAILED"));
    }
}

// concurrent/model/State.java — Enum representing states in an order lifecycle

public enum State {                     // enum = fixed set of states; type-safe, no invalid values
    CREATED,
    VALIDATED,
    PROCESSING,
    SHIPPED,
    DELIVERED,
    CANCELLED;

    public boolean canTransitionTo(State target) {
        switch (this) {
            case CREATED: return target == VALIDATED || target == CANCELLED;
            case VALIDATED: return target == PROCESSING || target == CANCELLED;
            case PROCESSING: return target == SHIPPED || target == CANCELLED;
            case SHIPPED: return target == DELIVERED;
            case DELIVERED: return false;
            case CANCELLED: return false;
            default: return false;
        }
    }
}

// concurrent/service/ConcurrentStateMachine.java — AtomicReference<State> with CAS for valid transitions

import java.util.concurrent.atomic.AtomicReference;
import java.util.concurrent.atomic.AtomicInteger;
import java.util.concurrent.CopyOnWriteArrayList;

public class ConcurrentStateMachine {
    private final AtomicReference<State> currentState;              // AtomicReference = CAS-based thread-safe state swap
    private final CopyOnWriteArrayList<State> transitionHistory = new CopyOnWriteArrayList<>(); // CopyOnWriteArrayList = safe concurrent reads of history
    private final AtomicInteger successfulTransitions = new AtomicInteger(0); // AtomicInteger = lock-free counter
    private final AtomicInteger rejectedTransitions = new AtomicInteger(0);  // tracks CAS failures
    private final AtomicInteger invalidTransitions = new AtomicInteger(0);   // tracks illegal transitions

    public ConcurrentStateMachine(State initial) {
        this.currentState = new AtomicReference<>(initial);
        transitionHistory.add(initial);
    }

    /**
     * Attempt a state transition. Uses CAS to ensure only valid transitions
     * from the current state succeed. Two concurrent events cannot both succeed
     * if they target different next states from the same current state.
     */
    public boolean transition(State targetState) {
        while (true) {
            State current = currentState.get();

            if (!current.canTransitionTo(targetState)) {
                invalidTransitions.incrementAndGet();
                return false; // Invalid transition from current state
            }

            // CAS: only transition if state hasn't changed since we checked
            if (currentState.compareAndSet(current, targetState)) { // CAS = atomic swap; prevents two threads both transitioning
                transitionHistory.add(targetState);
                successfulTransitions.incrementAndGet();
                return true;
            }

            // CAS failed — state changed, re-evaluate
            rejectedTransitions.incrementAndGet();
            return false; // Don't loop — let caller decide retry policy
        }
    }

    public State getCurrentState() { return currentState.get(); }
    public int getSuccessfulTransitions() { return successfulTransitions.get(); }
    public int getRejectedTransitions() { return rejectedTransitions.get(); }
    public int getInvalidTransitions() { return invalidTransitions.get(); }

    /**
     * Verify transition history is valid: each consecutive pair must be a valid transition.
     */
    public boolean isHistoryValid() {
        for (int i = 0; i < transitionHistory.size() - 1; i++) {
            State from = transitionHistory.get(i);
            State to = transitionHistory.get(i + 1);
            if (!from.canTransitionTo(to)) {
                return false;
            }
        }
        return true;
    }

    public int getHistorySize() { return transitionHistory.size(); }
}

