// concurrent/Main.java — Waiter adding items while kitchen polls queue, verify no partial orders

import java.util.concurrent.*;
import java.util.concurrent.atomic.AtomicBoolean;
import java.util.concurrent.atomic.AtomicInteger;

public class Main {
    public static void main(String[] args) throws InterruptedException {
        System.out.println("=== Concurrent Restaurant Ordering Demo ===\n");

        Restaurant restaurant = new Restaurant();
        int orderCount = 20;
        int itemsPerOrder = 5;
        CountDownLatch startLatch = new CountDownLatch(1);
        CountDownLatch waiterDone = new CountDownLatch(1);
        AtomicBoolean partialOrderServed = new AtomicBoolean(false);
        AtomicInteger kitchenProcessed = new AtomicInteger(0);

        System.out.println("Scenario: Waiter builds 20 orders (5 items each).");
        System.out.println("  Kitchen thread polls simultaneously trying to pick up orders.");
        System.out.println("Expected: Kitchen never gets a partial order (fewer than 5 items).\n");

        // Kitchen thread — aggressively polls for orders
        Thread kitchenThread = new Thread(() -> {
            try {
                startLatch.await();
                while (!Thread.currentThread().isInterrupted()) {
                    Order order = restaurant.kitchenPickup();
                    if (order != null) {
                        int items = order.getItemCount();
                        if (items < itemsPerOrder) {
                            partialOrderServed.set(true);
                            System.err.println("PARTIAL ORDER! Order " + order.getId() +
                                " has " + items + " items (expected " + itemsPerOrder + ")");
                        }
                        restaurant.verifyOrder(order, itemsPerOrder);
                        kitchenProcessed.incrementAndGet();
                    }
                    if (kitchenProcessed.get() >= orderCount) break;
                    Thread.yield();
                }
            } catch (InterruptedException e) {
                Thread.currentThread().interrupt();
            }
        }, "Kitchen");

        // Waiter thread — builds orders and submits them
        Thread waiterThread = new Thread(() -> {
            try {
                startLatch.await();
                for (int o = 0; o < orderCount; o++) {
                    Order order = restaurant.createOrder(o);
                    for (int i = 0; i < itemsPerOrder; i++) {
                        order.addItem("Item-" + o + "-" + i);
                        Thread.yield(); // Maximize race window
                    }
                    restaurant.submitOrder(order);
                }
            } catch (InterruptedException e) {
                Thread.currentThread().interrupt();
            } finally {
                waiterDone.countDown();
            }
        }, "Waiter");

        kitchenThread.start();
        waiterThread.start();
        startLatch.countDown();

        waiterDone.await();
        kitchenThread.join(3000); // Wait up to 3s for kitchen to finish
        if (kitchenThread.isAlive()) kitchenThread.interrupt();

        System.out.println("--- Results ---");
        System.out.println("Orders created: " + orderCount);
        System.out.println("Orders processed by kitchen: " + kitchenProcessed.get());
        System.out.println("Partial orders detected: " + restaurant.getPartialOrdersDetected());
        System.out.println("Partial order served: " + partialOrderServed.get());

        boolean passed = !partialOrderServed.get() && kitchenProcessed.get() == orderCount;
        System.out.println("\nCorrectness check: " + (passed ? "PASSED" : "FAILED"));
    }
}

// concurrent/model/Order.java — Thread-safe order with lock for item addition and atomic state

import java.util.ArrayList;
import java.util.Collections;
import java.util.List;
import java.util.concurrent.atomic.AtomicReference;
import java.util.concurrent.locks.ReentrantLock;

public class Order {
    private final int id;                                      // final = safe publication; ID visible to all threads
    private final List<String> items = new ArrayList<>();       // guarded by itemsLock
    private final ReentrantLock itemsLock = new ReentrantLock(); // ReentrantLock = mutual exclusion for item list
    private final AtomicReference<OrderState> state = new AtomicReference<>(OrderState.BUILDING); // AtomicReference = CAS-based state transitions

    public Order(int id) {
        this.id = id;
    }

    public int getId() { return id; }

    /**
     * Add an item. Only allowed while in BUILDING state.
     * Waiter holds lock while building the order.
     */
    public boolean addItem(String item) {
        itemsLock.lock();
        try {
            if (state.get() != OrderState.BUILDING) return false;
            items.add(item);
            return true;
        } finally {
            itemsLock.unlock();
        }
    }

    /**
     * Submit the order. Transitions from BUILDING to SUBMITTED atomically.
     * Lock ensures no items are being added during transition.
     */
    public boolean submit() {
        itemsLock.lock();
        try {
            return state.compareAndSet(OrderState.BUILDING, OrderState.SUBMITTED); // CAS = only transitions if still BUILDING
        } finally {
            itemsLock.unlock();
        }
    }

    /**
     * Kitchen picks up the order. Only from SUBMITTED state.
     */
    public boolean startPreparing() {
        return state.compareAndSet(OrderState.SUBMITTED, OrderState.PREPARING); // CAS = prevents double-pickup
    }

    /**
     * Get a snapshot of items. Only valid after submission.
     */
    public List<String> getItems() {
        itemsLock.lock();
        try {
            return new ArrayList<>(items);
        } finally {
            itemsLock.unlock();
        }
    }

    public int getItemCount() {
        itemsLock.lock();
        try {
            return items.size();
        } finally {
            itemsLock.unlock();
        }
    }

    public OrderState getState() { return state.get(); }

    public boolean markReady() {
        return state.compareAndSet(OrderState.PREPARING, OrderState.READY); // CAS = atomic state advance
    }
}

// concurrent/service/Restaurant.java — Order queue with thread-safe lifecycle management

import java.util.concurrent.ConcurrentLinkedQueue;
import java.util.concurrent.CopyOnWriteArrayList;
import java.util.concurrent.atomic.AtomicInteger;

public class Restaurant {
    private final ConcurrentLinkedQueue<Order> orderQueue = new ConcurrentLinkedQueue<>(); // ConcurrentLinkedQueue = lock-free FIFO; multiple threads can offer/poll
    private final CopyOnWriteArrayList<Order> allOrders = new CopyOnWriteArrayList<>();   // CopyOnWriteArrayList = safe iteration while orders added
    private final AtomicInteger partialOrdersDetected = new AtomicInteger(0); // AtomicInteger = lock-free counter
    private final AtomicInteger ordersCompleted = new AtomicInteger(0);       // AtomicInteger = lock-free counter

    public Order createOrder(int id) {
        Order order = new Order(id);
        allOrders.add(order);
        return order;
    }

    public void submitOrder(Order order) {
        if (order.submit()) {
            orderQueue.offer(order);
        }
    }

    /**
     * Kitchen polls for the next submitted order.
     * Only processes orders in SUBMITTED state.
     */
    public Order kitchenPickup() {
        Order order = orderQueue.poll();
        if (order == null) return null;

        if (order.startPreparing()) {
            return order;
        }
        return null; // order was in unexpected state
    }

    /**
     * Check if an order was picked up with fewer items than expected.
     */
    public void verifyOrder(Order order, int expectedItems) {
        if (order.getItemCount() < expectedItems) {
            partialOrdersDetected.incrementAndGet();
        }
        order.markReady();
        ordersCompleted.incrementAndGet();
    }

    public int getPartialOrdersDetected() { return partialOrdersDetected.get(); }
    public int getOrdersCompleted() { return ordersCompleted.get(); }
    public int getQueueSize() { return orderQueue.size(); }
}

