// Main.java — Demonstrates airline reservation with linear seat search
import java.util.List;

public class Main {
    public static void main(String[] args) {
        System.out.println("=== Airline Reservation (Naive) Demo ===\n");
        Booking.resetCounter();

        AirlineSystem airline = new AirlineSystem();
        Flight f1 = new Flight("AA101", "NYC", "LAX", 250.00);
        f1.addSeats(10, 4, 2);
        Flight f2 = new Flight("AA202", "NYC", "LAX", 280.00);
        f2.addSeats(8, 3, 1);
        airline.addFlight(f1);
        airline.addFlight(f2);

        System.out.println("--- Search ---");
        List<Flight> results = airline.search("NYC", "LAX");
        System.out.println("  Found: " + results.size() + " flights");

        System.out.println("\n--- Booking ---");
        Passenger alice = new Passenger("Alice", "alice@mail.com");
        Passenger bob = new Passenger("Bob", "bob@mail.com");
        Booking b1 = airline.book(alice, f1, "BUSINESS");
        Booking b2 = airline.book(bob, f1, "ECONOMY");

        System.out.println("\n--- Check-In ---");
        airline.checkIn(b1);

        System.out.println("\n--- Cancel ---");
        airline.cancel(b2);
        System.out.println("  Economy available after cancel: " + f1.getAvailable("ECONOMY"));

        System.out.println("\n--- Sell Out ---");
        for (int i = 0; i < 2; i++) airline.book(new Passenger("P" + i, ""), f1, "FIRST");
        airline.book(new Passenger("Extra", ""), f1, "FIRST"); // Should fail

        System.out.println("\n=== Airline Reservation (Naive) Demo Complete ===");
    }
}

// model/Booking.java — Confirmed reservation linking passenger, flight, and seat
public class Booking {
    private static int counter = 0;        // static = shared ID counter across all bookings
    private final String id;               // final = booking ID is permanent once assigned
    private final Passenger passenger;     // final = passenger link is immutable
    private final Flight flight;           // final = flight link is immutable
    private final Seat seat;               // final = seat assignment is permanent
    private final double price;            // final = price locked at booking time
    private String state = "CONFIRMED";    // private = lifecycle state managed internally

    public Booking(Passenger p, Flight f, Seat s, double price) {
        this.id = "BK" + String.format("%04d", ++counter);
        this.passenger = p; this.flight = f; this.seat = s; this.price = price;
    }

    public void cancel() { state = "CANCELLED"; seat.release(); }
    public void checkIn() { state = "CHECKED_IN"; }

    public String getId() { return id; }
    public Passenger getPassenger() { return passenger; }
    public Flight getFlight() { return flight; }
    public Seat getSeat() { return seat; }
    public double getPrice() { return price; }
    public String getState() { return state; }
    @Override public String toString() { return id + ": " + passenger.getName() + " on " + flight.getFlightNumber() + " seat " + seat.getNumber(); }
    public static void resetCounter() { counter = 0; }
}

// model/Flight.java — Scheduled flight with seat inventory
import java.util.ArrayList;
import java.util.List;

public class Flight {
    private final String flightNumber;     // final = flight number never changes
    private final String origin;           // final = departure city is fixed
    private final String destination;      // final = arrival city is fixed
    private final double basePrice;        // final = base fare set at creation
    private final List<Seat> seats = new ArrayList<>(); // private = only flight manages its seats

    public Flight(String flightNumber, String origin, String destination, double basePrice) {
        this.flightNumber = flightNumber;
        this.origin = origin;
        this.destination = destination;
        this.basePrice = basePrice;
    }

    public void addSeats(int economy, int business, int first) {
        int n = 1;
        for (int i = 0; i < first; i++) seats.add(new Seat(n++ + "F", "FIRST"));
        for (int i = 0; i < business; i++) seats.add(new Seat(n++ + "B", "BUSINESS"));
        for (int i = 0; i < economy; i++) seats.add(new Seat(n++ + "E", "ECONOMY"));
    }

    // Linear search for available seat by class
    public Seat bookSeat(String seatClass) {
        for (Seat s : seats) {
            if (s.getSeatClass().equals(seatClass) && !s.isBooked()) {
                s.book();
                return s;
            }
        }
        return null;
    }

    public int getAvailable(String seatClass) {
        int c = 0;
        for (Seat s : seats) if (s.getSeatClass().equals(seatClass) && !s.isBooked()) c++;
        return c;
    }

    public String getFlightNumber() { return flightNumber; }
    public String getOrigin() { return origin; }
    public String getDestination() { return destination; }
    public double getBasePrice() { return basePrice; }
    public List<Seat> getSeats() { return seats; }
    @Override public String toString() { return flightNumber + ": " + origin + "->" + destination; }
}

// model/Passenger.java — Traveler with personal details
public class Passenger {
    private final String name;             // final = passenger name is immutable
    private final String email;            // final = email is immutable

    public Passenger(String name, String email) { this.name = name; this.email = email; }
    public String getName() { return name; }
    public String getEmail() { return email; }
    @Override public String toString() { return name; }
}

// model/Seat.java — Individual seat with class and availability
public class Seat {
    private final String number;           // final = seat number is permanent (e.g., "3B")
    private final String seatClass;        // final = ECONOMY, BUSINESS, or FIRST; never changes
    private boolean booked;                // private = only this class controls booking status

    public Seat(String number, String seatClass) {
        this.number = number; this.seatClass = seatClass;
    }

    public String getNumber() { return number; }
    public String getSeatClass() { return seatClass; }
    public boolean isBooked() { return booked; }
    public void book() { booked = true; }
    public void release() { booked = false; }
    @Override public String toString() { return number + "(" + seatClass + ")" + (booked ? "[X]" : "[O]"); }
}

// service/AirlineSystem.java — Manages flights, bookings, and search with linear seat lookup
import java.util.ArrayList;
import java.util.List;

public class AirlineSystem {
    private final List<Flight> flights = new ArrayList<>();    // private = internal flight registry
    private final List<Booking> bookings = new ArrayList<>();  // private = internal booking log

    public void addFlight(Flight f) { flights.add(f); }

    public List<Flight> search(String origin, String dest) {
        List<Flight> results = new ArrayList<>();
        for (Flight f : flights) {
            if (f.getOrigin().equalsIgnoreCase(origin) && f.getDestination().equalsIgnoreCase(dest))
                results.add(f);
        }
        return results;
    }

    public Booking book(Passenger p, Flight f, String seatClass) {
        Seat seat = f.bookSeat(seatClass);
        if (seat == null) { System.out.println("  No " + seatClass + " seats on " + f.getFlightNumber()); return null; }
        double multiplier = seatClass.equals("FIRST") ? 4.0 : seatClass.equals("BUSINESS") ? 2.5 : 1.0;
        double price = f.getBasePrice() * multiplier;
        Booking b = new Booking(p, f, seat, price);
        bookings.add(b);
        System.out.println("  Booked: " + b + " ($" + String.format("%.2f", price) + ")");
        return b;
    }

    public void cancel(Booking b) { b.cancel(); System.out.println("  Cancelled: " + b.getId()); }
    public void checkIn(Booking b) { b.checkIn(); System.out.println("  Checked in: " + b.getPassenger().getName()); }
}

// Main.java — Demonstrates airline reservation with BitSet seat map for O(1) availability
public class Main {
    public static void main(String[] args) {
        System.out.println("=== Airline Reservation (Optimized: BitSet Seats) Demo ===\n");
        Booking.resetCounter();

        AirlineSystem airline = new AirlineSystem();
        Flight f1 = new Flight("AA101", "NYC", "LAX", 250.00, 10, 4, 2);
        airline.addFlight(f1);

        System.out.println("--- Seat Availability (BitSet) ---");
        System.out.println("  FIRST: " + f1.getAvailable("FIRST"));
        System.out.println("  BUSINESS: " + f1.getAvailable("BUSINESS"));
        System.out.println("  ECONOMY: " + f1.getAvailable("ECONOMY"));

        System.out.println("\n--- Bookings ---");
        Passenger alice = new Passenger("Alice", "alice@mail.com");
        Booking b1 = airline.book(alice, f1, "BUSINESS");
        Booking b2 = airline.book(new Passenger("Bob", "bob@mail.com"), f1, "ECONOMY");
        Booking b3 = airline.book(new Passenger("Carol", "c@mail.com"), f1, "FIRST");

        System.out.println("\n--- Availability After Bookings ---");
        System.out.println("  FIRST: " + f1.getAvailable("FIRST"));
        System.out.println("  BUSINESS: " + f1.getAvailable("BUSINESS"));
        System.out.println("  Occupancy: " + String.format("%.0f%%", f1.getOccupancy() * 100));

        System.out.println("\n--- Cancel and Rebook ---");
        airline.cancel(b2, f1);
        System.out.println("  ECONOMY after cancel: " + f1.getAvailable("ECONOMY"));
        Booking b4 = airline.book(new Passenger("Dave", "d@mail.com"), f1, "ECONOMY");

        System.out.println("\n--- Fill All First Class ---");
        airline.book(new Passenger("Eve", ""), f1, "FIRST");
        airline.book(new Passenger("Frank", ""), f1, "FIRST"); // Should fail

        System.out.println("\n--- Check-In ---");
