import java.util.concurrent.atomic.AtomicInteger;

public class Product {
    private final String id;               // final = safe publication; ID visible to all threads
    private final String name;             // final = safe publication; name visible to all threads
    private final AtomicInteger stock;     // AtomicInteger = CAS-based stock; no locks needed for deduction

    public Product(String id, String name, int initialStock) {
        this.id = id;
        this.name = name;
        this.stock = new AtomicInteger(initialStock);
    }

    public String getId() { return id; }
    public String getName() { return name; }
    public int getStock() { return stock.get(); }

    /**
     * Try to deduct quantity using CAS loop.
     * Only succeeds if current stock >= quantity.
     * Prevents overselling.
     */
    public boolean tryDeduct(int quantity) {
        while (true) {
            int current = stock.get();
            if (current < quantity) {
                return false; // Not enough stock
            }
            if (stock.compareAndSet(current, current - quantity)) { // CAS = atomic deduct; prevents overselling
                return true; // Successfully deducted
            }
            // CAS failed — another thread changed stock, retry
        }
    }

    public void restock(int quantity) {
        stock.addAndGet(quantity);          // addAndGet = atomic increment; safe from any thread
    }
}

// concurrent/service/InventoryService.java — Thread-safe inventory with CAS-based stock deduction

import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.atomic.AtomicInteger;

public class InventoryService {
    private final ConcurrentHashMap<String, Product> products = new ConcurrentHashMap<>(); // ConcurrentHashMap = lock-free reads, segmented writes
    private final AtomicInteger successfulOrders = new AtomicInteger(0); // AtomicInteger = lock-free counter
    private final AtomicInteger failedOrders = new AtomicInteger(0);     // AtomicInteger = lock-free counter

    public void addProduct(Product product) {
        products.put(product.getId(), product);
    }

    /**
     * Process an order: deduct stock atomically.
     * Returns true only if stock was sufficient and deducted.
     */
    public boolean processOrder(String productId, int quantity) {
        Product product = products.get(productId);
        if (product == null) {
            failedOrders.incrementAndGet();
            return false;
        }

        if (product.tryDeduct(quantity)) {
            successfulOrders.incrementAndGet();
            return true;
        }

        failedOrders.incrementAndGet();
        return false;
    }

    public int getStock(String productId) {
        Product product = products.get(productId);
        return product != null ? product.getStock() : -1;
    }

    public int getSuccessfulOrders() { return successfulOrders.get(); }
    public int getFailedOrders() { return failedOrders.get(); }
}

