// Main.java — Entry point demonstrating the chat application
import java.util.Arrays;
import java.util.List;

public class Main {
    public static void main(String[] args) {
        System.out.println("=== Chat Application Demo (Naive) ===");

        ChatService chatService = new ChatService();

        User alice = chatService.registerUser("Alice");
        User bob = chatService.registerUser("Bob");
        User charlie = chatService.registerUser("Charlie");
        System.out.println("Users created: Alice, Bob, Charlie");

        chatService.setUserStatus(alice.getId(), OnlineStatus.ONLINE);
        chatService.setUserStatus(bob.getId(), OnlineStatus.ONLINE);
        chatService.setUserStatus(charlie.getId(), OnlineStatus.ONLINE);

        System.out.println("\n--- Direct Chat: Alice & Bob ---");
        ChatRoom directChat = chatService.createDirectChat(alice.getId(), bob.getId());
        chatService.sendMessage(directChat.getId(), alice.getId(), "Hey Bob, how are you?");
        chatService.sendMessage(directChat.getId(), bob.getId(), "I'm great! Thanks for asking.");

        System.out.println("\n--- Group Chat: Project Team ---");
        ChatRoom groupChat = chatService.createGroupChat("Project Team", alice.getId(),
            Arrays.asList(alice.getId(), bob.getId(), charlie.getId()));
        chatService.sendMessage(groupChat.getId(), alice.getId(), "Meeting at 3pm today");
        chatService.sendMessage(groupChat.getId(), charlie.getId(), "Got it, thanks!");

        System.out.println("\n--- Typing Indicators ---");
        chatService.startTyping(groupChat.getId(), alice.getId());
        chatService.stopTyping(groupChat.getId(), alice.getId());

        System.out.println("\n--- Message History ---");
        System.out.println("Direct chat history (Alice & Bob):");
        List<Message> directHistory = chatService.getMessageHistory(directChat.getId());
        for (Message msg : directHistory) {
            User sender = chatService.getUser(msg.getSenderId());
            System.out.println("  [" + sender.getName() + "]: " + msg.getDisplayText());
        }

        System.out.println("Group chat history (Project Team):");
        List<Message> groupHistory = chatService.getMessageHistory(groupChat.getId());
        for (Message msg : groupHistory) {
            User sender = chatService.getUser(msg.getSenderId());
            System.out.println("  [" + sender.getName() + "]: " + msg.getDisplayText());
        }

        System.out.println("\n--- Different Message Types ---");
        chatService.sendMessage(directChat.getId(), alice.getId(), "photo.jpg", Message.MessageType.IMAGE);
        chatService.sendMessage(directChat.getId(), bob.getId(), "report.pdf", Message.MessageType.FILE);

        System.out.println("\n--- Status Changes ---");
        chatService.setUserStatus(bob.getId(), OnlineStatus.AWAY);
        chatService.setUserStatus(charlie.getId(), OnlineStatus.OFFLINE);

        System.out.println("\n=== Chat Application Demo Complete ===");
    }
}

// model/Message.java — Represents a chat message with sender, content, and timestamp
import java.time.LocalDateTime;

public abstract class Message {              // abstract = can't create Message directly; must use subclass
    private String id;                        // private = only Message class can access this field
    private String senderId;                  // private = hides internal data from outside classes
    private String content;                   // private = forces access through getter methods
    private LocalDateTime timestamp;          // private = internal state hidden from external code
    private MessageType type;                 // private = controlled via constructor only

    public enum MessageType {                 // enum = fixed set of message types; compile-time safe
        TEXT, IMAGE, FILE
    }

    public Message(String id, String senderId, String content, MessageType type) {
        this.id = id;
        this.senderId = senderId;
        this.content = content;
        this.type = type;
        this.timestamp = LocalDateTime.now();
    }

    public String getId() { return id; }
    public String getSenderId() { return senderId; }
    public String getContent() { return content; }
    public LocalDateTime getTimestamp() { return timestamp; }
    public MessageType getType() { return type; }

    public abstract String getDisplayText();   // abstract = each subclass formats display differently

    public static Message createTextMessage(String id, String senderId, String text) { // static = factory method; no instance needed
        return new TextMessage(id, senderId, text);
    }

    public static Message createImageMessage(String id, String senderId, String url) {
        return new ImageMessage(id, senderId, url);
    }

    public static Message createFileMessage(String id, String senderId, String fileName) {
        return new FileMessage(id, senderId, fileName);
    }
}

class TextMessage extends Message {           // extends = inherits from Message; IS-A relationship
    public TextMessage(String id, String senderId, String text) {
        super(id, senderId, text, MessageType.TEXT);
    }

    @Override                                   // @Override = ensures we correctly override parent method
    public String getDisplayText() {
        return getContent();
    }
}

class ImageMessage extends Message {          // extends = inherits Message behavior for images
    public ImageMessage(String id, String senderId, String imageUrl) {
        super(id, senderId, imageUrl, MessageType.IMAGE);
    }

    @Override
    public String getDisplayText() {
        return "[Image: " + getContent() + "]";
    }
}

class FileMessage extends Message {           // extends = inherits Message behavior for files
    public FileMessage(String id, String senderId, String fileName) {
        super(id, senderId, fileName, MessageType.FILE);
    }

    @Override
    public String getDisplayText() {
        return "[File: " + getContent() + "]";
    }
}

// model/OnlineStatus.java — Enumerates user presence states
public enum OnlineStatus {                    // enum = fixed set of statuses; no invalid values possible
    ONLINE, OFFLINE, AWAY;

    @Override
    public String toString() {
        return name();
    }
}

// model/TypingIndicator.java — Tracks which users are currently typing in a room
import java.util.HashMap;
import java.util.HashSet;
import java.util.Map;
import java.util.Set;

public class TypingIndicator {
    private Map<String, Set<String>> typingUsers; // private = hides internal tracking from outside

    public TypingIndicator() {
        this.typingUsers = new HashMap<>();
    }

    public void startTyping(String roomId, String userId, String userName) {
        typingUsers.computeIfAbsent(roomId, k -> new HashSet<>()).add(userId);
        System.out.println(userName + " is typing in " + roomId + "...");
    }

    public void stopTyping(String roomId, String userId, String userName) {
        Set<String> users = typingUsers.get(roomId);
        if (users != null) {
            users.remove(userId);
            System.out.println(userName + " stopped typing in " + roomId);
        }
    }

    public boolean isTyping(String roomId, String userId) {
        Set<String> users = typingUsers.get(roomId);
        return users != null && users.contains(userId);
    }

    public Set<String> getTypingUsers(String roomId) {
        return typingUsers.getOrDefault(roomId, new HashSet<>());
    }
}

// model/User.java — Represents a chat user with profile and status
import java.util.ArrayList;
import java.util.List;

public class User {
    private String id;                        // private = only this class can read the user's id
    private String name;                      // private = encapsulates user identity
    private OnlineStatus status;              // private = status changes go through setStatus()
    private List<String> chatRoomIds;         // private = room membership controlled internally
    private List<String> notifications;       // private = notifications managed by class methods

    public User(String id, String name) {
        this.id = id;
        this.name = name;
        this.status = OnlineStatus.OFFLINE;
        this.chatRoomIds = new ArrayList<>();
        this.notifications = new ArrayList<>();
    }

    public String getId() { return id; }
    public String getName() { return name; }
    public OnlineStatus getStatus() { return status; }
    public List<String> getChatRoomIds() { return chatRoomIds; }

    public void setStatus(OnlineStatus status) {
        this.status = status;
    }

    public void joinChatRoom(String roomId) {
        if (!chatRoomIds.contains(roomId)) {
            chatRoomIds.add(roomId);
        }
    }

    public void leaveChatRoom(String roomId) {
        chatRoomIds.remove(roomId);
    }

    public void receiveNotification(String notification) {
        notifications.add(notification);
        System.out.println(name + " receives notification: " + notification);
    }

    public List<String> getNotifications() {
        return new ArrayList<>(notifications);
    }

    public void clearNotifications() {
        notifications.clear();
    }

    @Override
    public String toString() {
        return name + " (" + status + ")";
    }
}

// service/ChatRoom.java — Manages participants and message broadcast within a room
import java.util.ArrayList;
import java.util.List;

public abstract class ChatRoom {              // abstract = can't create generic room; must be Direct or Group
    protected String id;                      // protected = subclasses (DirectChat, GroupChat) can access
    protected String name;                    // protected = shared with subclasses but hidden from others
    protected List<String> participantIds;    // protected = subclasses manage their own participants

    public ChatRoom(String id, String name) {
        this.id = id;
        this.name = name;
        this.participantIds = new ArrayList<>();
    }

    public String getId() { return id; }
    public String getName() { return name; }
    public List<String> getParticipantIds() { return new ArrayList<>(participantIds); }

    public void addParticipant(String userId) {
        if (!participantIds.contains(userId)) {
            participantIds.add(userId);
        }
    }

    public void removeParticipant(String userId) {
        participantIds.remove(userId);
    }

    public boolean hasParticipant(String userId) {
        return participantIds.contains(userId);
    }

    public abstract String getRoomType();      // abstract = each room subclass identifies itself
}

class DirectChat extends ChatRoom {           // extends = inherits ChatRoom; adds 2-person limit
    public DirectChat(String id, String user1Id, String user2Id) {
        super(id, "Direct:" + user1Id + "-" + user2Id);
        addParticipant(user1Id);
        addParticipant(user2Id);
    }

    @Override
    public void addParticipant(String userId) {
        if (participantIds.size() < 2) {
            super.addParticipant(userId);
        }
    }

    @Override
    public String getRoomType() {
        return "DIRECT";
    }
}

class GroupChat extends ChatRoom {            // extends = inherits ChatRoom; allows many participants
    private String creatorId;                 // private = only GroupChat knows who created it

    public GroupChat(String id, String name, String creatorId) {
        super(id, name);
        this.creatorId = creatorId;
        addParticipant(creatorId);
    }

    public String getCreatorId() { return creatorId; }

    @Override
    public String getRoomType() {
        return "GROUP";
    }
}

// service/ChatService.java — Manages user sessions, rooms, and message routing
import java.util.HashMap;
import java.util.List;
import java.util.Map;

public class ChatService {
    private Map<String, User> users;              // private = internal registry hidden from outside
    private Map<String, ChatRoom> chatRooms;      // private = rooms managed only through service methods
    private MessageStore messageStore;            // private = storage is an implementation detail
    private NotificationManager notificationManager; // private = notification logic encapsulated
    private TypingIndicator typingIndicator;      // private = typing state is internal concern
    private int messageCounter;                   // private = auto-increment counter for unique IDs
    private int roomCounter;                      // private = auto-increment counter for room IDs

    public ChatService() {
        this.users = new HashMap<>();
        this.chatRooms = new HashMap<>();
        this.messageStore = new MessageStore();
        this.notificationManager = new NotificationManager();
        this.typingIndicator = new TypingIndicator();
        this.messageCounter = 0;
        this.roomCounter = 0;
    }

    public User registerUser(String name) {
        String id = "user_" + (users.size() + 1);
        User user = new User(id, name);
        users.put(id, user);
        // Register a default console listener so the demo shows event delivery.
        notificationManager.addListener(id, new ConsoleMessageListener(name));
        return user;
    }

    /** Register an additional listener for a user (push, toast, email, etc.). */
    public void addMessageListener(String userId, MessageListener listener) {
        notificationManager.addListener(userId, listener);
    }

    public void setUserStatus(String userId, OnlineStatus status) {
        User user = users.get(userId);
        if (user != null) {
            OnlineStatus oldStatus = user.getStatus();
            user.setStatus(status);
            notificationManager.notifyStatusChange(user, oldStatus, status, users);
        }
    }

    public ChatRoom createDirectChat(String user1Id, String user2Id) {
        for (ChatRoom room : chatRooms.values()) {
            if (room instanceof DirectChat &&
                room.hasParticipant(user1Id) && room.hasParticipant(user2Id)) {
                return room;
            }
        }
        String roomId = "room_" + (++roomCounter);
        DirectChat chat = new DirectChat(roomId, user1Id, user2Id);
        chatRooms.put(roomId, chat);
        users.get(user1Id).joinChatRoom(roomId);
        users.get(user2Id).joinChatRoom(roomId);
        return chat;
    }

    public ChatRoom createGroupChat(String name, String creatorId, List<String> memberIds) {
        String roomId = "room_" + (++roomCounter);
        GroupChat group = new GroupChat(roomId, name, creatorId);
        for (String memberId : memberIds) {
            group.addParticipant(memberId);
            users.get(memberId).joinChatRoom(roomId);
        }
        chatRooms.put(roomId, group);
        System.out.println("Group '" + name + "' created with " +
            String.join(", ", memberIds.stream()
                .map(id -> users.get(id).getName())
                .toArray(String[]::new)));
        return group;
    }

    public Message sendMessage(String roomId, String senderId, String content) {
        return sendMessage(roomId, senderId, content, Message.MessageType.TEXT);
    }

    public Message sendMessage(String roomId, String senderId, String content, Message.MessageType type) {
        ChatRoom room = chatRooms.get(roomId);
        if (room == null || !room.hasParticipant(senderId)) {
            throw new IllegalArgumentException("Invalid room or user not a participant");
        }

        String msgId = "msg_" + (++messageCounter);
        Message message;
        switch (type) {
            case IMAGE:
                message = Message.createImageMessage(msgId, senderId, content);
                break;
            case FILE:
                message = Message.createFileMessage(msgId, senderId, content);
                break;
            default:
                message = Message.createTextMessage(msgId, senderId, content);
        }

        messageStore.storeMessage(roomId, message);
        String senderName = users.get(senderId).getName();

        if (room instanceof GroupChat) {
            System.out.println(senderName + " sends to group: " + message.getDisplayText());
        } else {
            System.out.println(senderName + " sends: " + message.getDisplayText());
        }

        notificationManager.notifyNewMessage(room, message, users);
        return message;
    }

    public List<Message> getMessageHistory(String roomId) {
        return messageStore.getMessages(roomId);
    }

    public void startTyping(String roomId, String userId) {
        User user = users.get(userId);
        ChatRoom room = chatRooms.get(roomId);
        if (user != null && room != null) {
            typingIndicator.startTyping(room.getName(), userId, user.getName());
        }
    }

    public void stopTyping(String roomId, String userId) {
        User user = users.get(userId);
        ChatRoom room = chatRooms.get(roomId);
        if (user != null && room != null) {
            typingIndicator.stopTyping(room.getName(), userId, user.getName());
        }
    }

    public User getUser(String userId) { return users.get(userId); }
    public ChatRoom getChatRoom(String roomId) { return chatRooms.get(roomId); }
}

// service/ConsoleMessageListener.java — Console listener; demonstrates observing message events
//
// One listener per recipient: receives onMessage callbacks for any room the
// recipient participates in. NotificationManager filters by room membership
// and online status before invoking us.

class ConsoleMessageListener implements MessageListener {
    private final String recipientName;

    public ConsoleMessageListener(String recipientName) {
        this.recipientName = recipientName;
    }

    @Override
    public void onMessage(Message message, ChatRoom room) {
        String label = (room instanceof GroupChat)
                ? "new message in " + room.getName()
                : "new direct message";
        System.out.println("  [event] " + recipientName + " <- " + label
                + ": " + message.getDisplayText());
    }
}

// service/MessageListener.java — Observer contract for new-message events
//
// Subscribers are notified when a message is delivered to a chat room they
// care about. Examples: a console display, a push-notification dispatcher, a
// desktop toast, an email digest. NotificationManager fans out events;
// listeners decide how to render them.

interface MessageListener {
    /** A new message was delivered to the room. */
    void onMessage(Message message, ChatRoom room);
}

// service/MessageStore.java — Persists and retrieves message history
import java.util.ArrayList;
import java.util.HashMap;
import java.util.List;
import java.util.Map;

public class MessageStore {
    private Map<String, List<Message>> messagesByRoom; // private = storage internals hidden

    public MessageStore() {
        this.messagesByRoom = new HashMap<>();
    }

    public void storeMessage(String roomId, Message message) {
        messagesByRoom.computeIfAbsent(roomId, k -> new ArrayList<>()).add(message);
    }

    public List<Message> getMessages(String roomId) {
        return messagesByRoom.getOrDefault(roomId, new ArrayList<>());
    }

    public List<Message> getMessages(String roomId, int limit) {
        List<Message> messages = getMessages(roomId);
        int start = Math.max(0, messages.size() - limit);
        return messages.subList(start, messages.size());
    }

    public int getMessageCount(String roomId) {
        return messagesByRoom.getOrDefault(roomId, new ArrayList<>()).size();
    }
}

// service/NotificationManager.java — Delivers push notifications via per-user MessageListeners
import java.util.ArrayList;
import java.util.HashMap;
import java.util.List;
import java.util.Map;

public class NotificationManager {
    // Observer: per-user listener registry. Many listeners can subscribe per user
    // (e.g. a console renderer, a mobile push hook, a desktop toast).
    private final Map<String, List<MessageListener>> listeners = new HashMap<>();

    public void addListener(String userId, MessageListener listener) {
        listeners.computeIfAbsent(userId, k -> new ArrayList<>()).add(listener);
    }

    public void removeListener(String userId, MessageListener listener) {
        List<MessageListener> ls = listeners.get(userId);
        if (ls != null) ls.remove(listener);
    }

    public void notifyNewMessage(ChatRoom room, Message message, Map<String, User> users) {
        for (String participantId : room.getParticipantIds()) {
            if (participantId.equals(message.getSenderId())) continue;
            User participant = users.get(participantId);
            if (participant == null || participant.getStatus() == OnlineStatus.OFFLINE) continue;
            List<MessageListener> ls = listeners.get(participantId);
            if (ls == null) continue;
            for (MessageListener l : ls) l.onMessage(message, room);
        }
    }

    public void notifyStatusChange(User user, OnlineStatus oldStatus, OnlineStatus newStatus,
                                    Map<String, User> allUsers) {
        System.out.println(user.getName() + " is now " + newStatus);
    }
}

