// service/MessageStore.java — Indexed message store with O(1) lookups by user and timestamp
import java.time.LocalDateTime;
import java.util.ArrayList;
import java.util.HashMap;
import java.util.List;
import java.util.Map;
import java.util.TreeMap;
import java.util.stream.Collectors;

public class MessageStore {
    private Map<String, List<Message>> messagesByRoom;              // primary store: append-only list
    private Map<String, TreeMap<LocalDateTime, Message>> messagesByTimestamp; // TreeMap = O(log n) time-range queries
    private Map<String, Map<String, List<Message>>> messagesByRoomAndSender; // HashMap index = O(1) per-sender lookup

    public MessageStore() {
        this.messagesByRoom = new HashMap<>();
        this.messagesByTimestamp = new HashMap<>();
        this.messagesByRoomAndSender = new HashMap<>();
    }

    public void storeMessage(String roomId, Message message) {
        // Store in primary list
        messagesByRoom.computeIfAbsent(roomId, k -> new ArrayList<>()).add(message);

        // Index by timestamp for range queries
        messagesByTimestamp.computeIfAbsent(roomId, k -> new TreeMap<>())
            .put(message.getTimestamp(), message);

        // Index by sender for user-specific queries
        messagesByRoomAndSender
            .computeIfAbsent(roomId, k -> new HashMap<>())
            .computeIfAbsent(message.getSenderId(), k -> new ArrayList<>())
            .add(message);
    }

    public List<Message> getMessages(String roomId) {
        return messagesByRoom.getOrDefault(roomId, new ArrayList<>());
    }

    public List<Message> getMessages(String roomId, int limit) {
        List<Message> messages = getMessages(roomId);
        int start = Math.max(0, messages.size() - limit);
        return messages.subList(start, messages.size());
    }

    // WHY: O(log n) range query instead of scanning all messages
    public List<Message> getMessagesBetween(String roomId, LocalDateTime from, LocalDateTime to) {
        TreeMap<LocalDateTime, Message> timeIndex = messagesByTimestamp.get(roomId);
        if (timeIndex == null) return new ArrayList<>();
        return new ArrayList<>(timeIndex.subMap(from, true, to, true).values());
    }

    // WHY: O(1) lookup for messages by a specific sender
    public List<Message> getMessagesBySender(String roomId, String senderId) {
        Map<String, List<Message>> senderIndex = messagesByRoomAndSender.get(roomId);
        if (senderIndex == null) return new ArrayList<>();
        return senderIndex.getOrDefault(senderId, new ArrayList<>());
    }

    public int getMessageCount(String roomId) {
        return messagesByRoom.getOrDefault(roomId, new ArrayList<>()).size();
    }
}

// service/NotificationManager.java — Async notification delivery via per-user MessageListeners
import java.util.List;
import java.util.Map;
import java.util.concurrent.CompletableFuture;
import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.CopyOnWriteArrayList;

public class NotificationManager {
    private ConcurrentHashMap<String, OnlineStatus> statusCache; // ConcurrentHashMap = O(1) thread-safe status cache

    // Observer: per-user listener registry. CopyOnWriteArrayList tolerates concurrent
    // listener add/remove vs notify without external locking.
    private final ConcurrentHashMap<String, List<MessageListener>> listeners = new ConcurrentHashMap<>();

    public NotificationManager() {
        this.statusCache = new ConcurrentHashMap<>();
    }

    public void addListener(String userId, MessageListener listener) {
        listeners.computeIfAbsent(userId, k -> new CopyOnWriteArrayList<>()).add(listener);
    }

    public void removeListener(String userId, MessageListener listener) {
        List<MessageListener> ls = listeners.get(userId);
        if (ls != null) ls.remove(listener);
    }

    public void updateStatusCache(String userId, OnlineStatus status) {
        statusCache.put(userId, status);
    }

    // WHY: O(1) status check from cache avoids traversing user objects
    public boolean isOnline(String userId) {
        OnlineStatus status = statusCache.get(userId);
        return status != null && status != OnlineStatus.OFFLINE;
    }

    public void notifyNewMessage(ChatRoom room, Message message, Map<String, User> users) {
        for (String participantId : room.getParticipantIds()) {
            if (participantId.equals(message.getSenderId())) continue;
            // WHY: CompletableFuture enables async delivery without blocking sender
            CompletableFuture.runAsync(() -> {
                if (!isOnline(participantId)) return;
                List<MessageListener> ls = listeners.get(participantId);
                if (ls == null) return;
                for (MessageListener l : ls) l.onMessage(message, room);
            }).join(); // join() for demo output ordering only
        }
    }

    public void notifyStatusChange(User user, OnlineStatus oldStatus, OnlineStatus newStatus,
                                    Map<String, User> allUsers) {
        updateStatusCache(user.getId(), newStatus);
        System.out.println(user.getName() + " is now " + newStatus);
    }
}

// concurrent/Main.java — 10 users sending to same room simultaneously, verify all messages received in consistent order

import java.util.*;
import java.util.concurrent.*;

public class Main {
    public static void main(String[] args) throws InterruptedException {
        System.out.println("=== Concurrent Chat Application Demo ===\n");
        System.out.println("Race condition: Two users sending messages to same group chat simultaneously");
        System.out.println("— message ordering inconsistent, messages lost.\n");

        ChatRoom room = new ChatRoom("general");
        int userCount = 10;
        int messagesPerUser = 100;
        int totalExpected = userCount * messagesPerUser;

        CountDownLatch startLatch = new CountDownLatch(1);
        CountDownLatch doneLatch = new CountDownLatch(userCount);

        for (int u = 0; u < userCount; u++) {
            final String userId = "User-" + u;
            new Thread(() -> {
                try {
                    startLatch.await(); // all threads start simultaneously
                    for (int m = 0; m < messagesPerUser; m++) {
                        room.sendMessage(userId, "msg-" + m);
                    }
                } catch (InterruptedException e) {
                    Thread.currentThread().interrupt();
                } finally {
                    doneLatch.countDown();
                }
            }).start();
        }

        // Fire all threads at once
        startLatch.countDown();
        doneLatch.await();

        // Verify correctness
        List<Message> ordered = room.getMessagesInOrder();
        int actualCount = ordered.size();

        // Check 1: No messages lost
        boolean noLoss = (actualCount == totalExpected);

        // Check 2: Sequence numbers are unique and contiguous (1..totalExpected)
        Set<Long> seqNums = new HashSet<>();
        for (Message msg : ordered) {
            seqNums.add(msg.getSequenceNumber());
        }
        boolean uniqueSeqs = (seqNums.size() == totalExpected);
        boolean contiguous = true;
        for (long i = 1; i <= totalExpected; i++) {
            if (!seqNums.contains(i)) {
                contiguous = false;
                break;
            }
        }

        // Check 3: Ordering is consistent (sorted by sequence)
        boolean orderConsistent = true;
        for (int i = 1; i < ordered.size(); i++) {
            if (ordered.get(i).getSequenceNumber() <= ordered.get(i - 1).getSequenceNumber()) {
                orderConsistent = false;
                break;
            }
        }

        // Check 4: Each user sent exactly messagesPerUser messages
        Map<String, Integer> perUser = new HashMap<>();
        for (Message msg : ordered) {
            perUser.merge(msg.getSenderId(), 1, Integer::sum);
        }
        boolean perUserCorrect = true;
        for (int u = 0; u < userCount; u++) {
            if (perUser.getOrDefault("User-" + u, 0) != messagesPerUser) {
                perUserCorrect = false;
                break;
            }
        }

        System.out.println("--- Results ---");
        System.out.println("Users: " + userCount);
        System.out.println("Messages per user: " + messagesPerUser);
        System.out.println("Total expected: " + totalExpected);
        System.out.println("Total received: " + actualCount);
        System.out.println("No messages lost: " + noLoss);
        System.out.println("Unique sequence numbers: " + uniqueSeqs);
        System.out.println("Contiguous sequences (1.." + totalExpected + "): " + contiguous);
        System.out.println("Order consistent: " + orderConsistent);
        System.out.println("Per-user count correct: " + perUserCorrect);

        System.out.println("\nSample messages (first 10):");
        for (int i = 0; i < Math.min(10, ordered.size()); i++) {
            System.out.println("  " + ordered.get(i));
        }

        boolean passed = noLoss && uniqueSeqs && contiguous && orderConsistent && perUserCorrect;
        System.out.println("\nCorrectness check: " + (passed ? "PASSED" : "FAILED"));
    }
}

// concurrent/model/Message.java — Immutable message with sequence number for total ordering

public class Message {
    private final String senderId;            // final = immutable after construction; safe to share across threads
    private final String content;             // final = no thread can modify after creation
    private final long sequenceNumber;        // final = assigned once by AtomicLong; globally unique ordering
    private final long timestamp;             // final = captured at creation; safe publication guaranteed

    public Message(String senderId, String content, long sequenceNumber) {
        this.senderId = senderId;
        this.content = content;
        this.sequenceNumber = sequenceNumber;
        this.timestamp = System.nanoTime();
    }

    public String getSenderId() { return senderId; }
    public String getContent() { return content; }
    public long getSequenceNumber() { return sequenceNumber; }
    public long getTimestamp() { return timestamp; }

    @Override
    public String toString() {
        return "[#" + sequenceNumber + " from " + senderId + "]: " + content;
    }
}

// concurrent/service/ChatRoom.java — Thread-safe chat room with ConcurrentLinkedQueue and AtomicLong sequencing

import java.util.concurrent.ConcurrentLinkedQueue;
import java.util.concurrent.atomic.AtomicLong;
import java.util.List;
import java.util.ArrayList;
import java.util.Comparator;

public class ChatRoom {
    private final String roomId;              // final = safe publication; all threads see this after construction
    private final ConcurrentLinkedQueue<Message> messageBuffer; // ConcurrentLinkedQueue = lock-free adds from many threads
    private final AtomicLong sequenceGenerator; // AtomicLong = CAS-based increment; unique sequence without locks

    public ChatRoom(String roomId) {
        this.roomId = roomId;
        this.messageBuffer = new ConcurrentLinkedQueue<>();
        this.sequenceGenerator = new AtomicLong(0);
    }

    /**
     * Send a message to this chat room. Thread-safe via AtomicLong for sequence
     * and ConcurrentLinkedQueue for buffer.
     */
    public Message sendMessage(String senderId, String content) {
        long seq = sequenceGenerator.incrementAndGet();
        Message msg = new Message(senderId, content, seq);
        messageBuffer.add(msg);
        return msg;
    }

    /**
     * Get all messages sorted by sequence number (total ordering).
     */
    public List<Message> getMessagesInOrder() {
        List<Message> messages = new ArrayList<>(messageBuffer);
        messages.sort(Comparator.comparingLong(Message::getSequenceNumber));
        return messages;
    }

    public int getMessageCount() {
        return messageBuffer.size();
    }

    public String getRoomId() { return roomId; }
}

