// Main.java — Entry point demonstrating the calendar system
import java.time.LocalDateTime;
import java.util.List;

public class Main {
    public static void main(String[] args) {
        System.out.println("=== Calendar System Demo (Naive) ===");

        CalendarService service = new CalendarService();

        Calendar aliceCal = service.createCalendar("alice", "Alice");
        Calendar bobCal = service.createCalendar("bob", "Bob");
        System.out.println("Created calendars for Alice and Bob");

        System.out.println("\n--- Creating Events ---");
        LocalDateTime today = LocalDateTime.of(2026, 5, 13, 0, 0);

        Event standup = new EventBuilder(service.nextEventId())
            .title("Team Standup")
            .description("Daily standup meeting")
            .from(today.withHour(9).withMinute(0))
            .to(today.withHour(9).withMinute(30))
            .organizer("alice")
            .reminder(15)
            .build();
        service.addEvent("alice", standup);

        Event review = new EventBuilder(service.nextEventId())
            .title("Project Review")
            .from(today.withHour(14).withMinute(0))
            .to(today.withHour(15).withMinute(0))
            .organizer("alice")
            .reminder(30)
            .build();
        service.addEvent("alice", review);

        System.out.println("\n--- Recurring Events ---");
        Event dailyStandup = new EventBuilder(service.nextEventId())
            .title("Daily Standup")
            .from(today.withHour(9).withMinute(0))
            .to(today.withHour(9).withMinute(15))
            .organizer("alice")
            .recurring(new DailyRecurrence())
            .build();

        List<TimeSlot> dailySlots = dailyStandup.getOccurrences(5);
        System.out.println("Daily standup recurrences for " + dailySlots.size() + " days");

        System.out.println("\n--- Conflict Detection ---");
        Event morningSync = new EventBuilder(service.nextEventId())
            .title("Morning Sync")
            .from(today.withHour(9).withMinute(15))
            .to(today.withHour(9).withMinute(45))
            .organizer("alice")
            .build();
        service.addEvent("alice", morningSync);

        List<String> conflicts = service.checkConflicts("alice");
        for (String conflict : conflicts) {
            System.out.println(conflict);
        }

        System.out.println("\n--- Invitations ---");
        Invitation inv = service.inviteUser(review.getId(), "alice", "bob", review);
        service.acceptInvitation(inv, review);

        System.out.println("\n--- Reminders ---");
        for (Reminder r : standup.getReminders()) { r.trigger(); }
        for (Reminder r : review.getReminders()) { r.trigger(); }

        System.out.println("\n=== Calendar System Demo Complete ===");
    }
}

// model/Event.java — Represents a scheduled event with time, location, and attendees
import java.util.ArrayList;
import java.util.List;

public class Event {
    private String id;                        // private = unique ID hidden from direct modification
    private String title;                     // private = only accessible via getters
    private String description;               // private = optional detail, set through setter
    private TimeSlot timeSlot;                // private = time range encapsulated
    private String organizerId;               // private = who created the event
    private RecurrenceRule recurrenceRule;     // private = strategy pattern for repeat behavior
    private List<Reminder> reminders;         // private = managed through addReminder()
    private List<Invitation> invitations;     // private = managed through addInvitation()
    private List<String> attendeeIds;         // private = controlled through addAttendee()

    public Event(String id, String title, TimeSlot timeSlot, String organizerId) {
        this.id = id;
        this.title = title;
        this.timeSlot = timeSlot;
        this.organizerId = organizerId;
        this.reminders = new ArrayList<>();
        this.invitations = new ArrayList<>();
        this.attendeeIds = new ArrayList<>();
        this.attendeeIds.add(organizerId);
    }

    public String getId() { return id; }
    public String getTitle() { return title; }
    public String getDescription() { return description; }
    public TimeSlot getTimeSlot() { return timeSlot; }
    public String getOrganizerId() { return organizerId; }
    public RecurrenceRule getRecurrenceRule() { return recurrenceRule; }
    public List<Reminder> getReminders() { return reminders; }
    public List<Invitation> getInvitations() { return invitations; }
    public List<String> getAttendeeIds() { return attendeeIds; }

    public void setDescription(String description) { this.description = description; }
    public void setRecurrenceRule(RecurrenceRule rule) { this.recurrenceRule = rule; }

    public void addReminder(Reminder reminder) { reminders.add(reminder); }
    public void addInvitation(Invitation invitation) { invitations.add(invitation); }

    public void addAttendee(String userId) {
        if (!attendeeIds.contains(userId)) {
            attendeeIds.add(userId);
        }
    }

    public boolean isRecurring() { return recurrenceRule != null; }

    public List<TimeSlot> getOccurrences(int count) {
        if (recurrenceRule != null) {
            return recurrenceRule.generateOccurrences(timeSlot, count);
        }
        List<TimeSlot> single = new ArrayList<>();
        single.add(timeSlot);
        return single;
    }

    @Override
    public String toString() {
        return title + " (" + timeSlot + ")";
    }
}

// model/Invitation.java — Represents an event invitation with RSVP status
public class Invitation {
    public enum Status { PENDING, ACCEPTED, DECLINED, TENTATIVE } // enum = fixed RSVP states; type-safe

    private String eventId;                   // private = tracks which event this invitation is for
    private String inviterId;                 // private = who sent the invitation
    private String inviteeId;                 // private = who received the invitation
    private Status status;                    // private = controlled through accept/decline methods

    public Invitation(String eventId, String inviterId, String inviteeId) {
        this.eventId = eventId;
        this.inviterId = inviterId;
        this.inviteeId = inviteeId;
        this.status = Status.PENDING;
    }

    public String getEventId() { return eventId; }
    public String getInviterId() { return inviterId; }
    public String getInviteeId() { return inviteeId; }
    public Status getStatus() { return status; }

    public void accept() { this.status = Status.ACCEPTED; }
    public void decline() { this.status = Status.DECLINED; }
    public void tentative() { this.status = Status.TENTATIVE; }

    @Override
    public String toString() {
        return "Invitation[event=" + eventId + ", status=" + status + "]";
    }
}

// model/Reminder.java — Triggers notifications before an event starts
public class Reminder {
    private int minutesBefore;                // private = how far before event to fire
    private String eventTitle;                // private = which event this reminder belongs to
    private boolean triggered;                // private = internal flag prevents double-firing

    public Reminder(int minutesBefore, String eventTitle) {
        this.minutesBefore = minutesBefore;
        this.eventTitle = eventTitle;
        this.triggered = false;
    }

    public int getMinutesBefore() { return minutesBefore; }
    public String getEventTitle() { return eventTitle; }
    public boolean isTriggered() { return triggered; }

    public void trigger() {
        if (!triggered) {
            triggered = true;
            System.out.println("Reminder: " + eventTitle + " starts in " + minutesBefore + " minutes");
        }
    }

    @Override
    public String toString() {
        return "Remind " + minutesBefore + " min before " + eventTitle;
    }
}

// model/TimeSlot.java — Represents a time range with start and end
import java.time.LocalDateTime;
import java.time.format.DateTimeFormatter;

public class TimeSlot {
    private LocalDateTime start;              // private = enforced by constructor validation
    private LocalDateTime end;                // private = must be after start

    public TimeSlot(LocalDateTime start, LocalDateTime end) {
        if (end.isBefore(start)) {
            throw new IllegalArgumentException("End time must be after start time");
        }
        this.start = start;
        this.end = end;
    }

    public LocalDateTime getStart() { return start; }
    public LocalDateTime getEnd() { return end; }

    public boolean overlapsWith(TimeSlot other) {
        return start.isBefore(other.end) && other.start.isBefore(end);
    }

    public long getDurationMinutes() {
        return java.time.Duration.between(start, end).toMinutes();
    }

    @Override
    public String toString() {
        DateTimeFormatter fmt = DateTimeFormatter.ofPattern("yyyy-MM-dd HH:mm");
        return start.format(fmt) + " - " + end.format(fmt);
    }
}

// service/Calendar.java — Represents a named calendar containing events
import java.time.LocalDate;
import java.util.ArrayList;
import java.util.List;
import java.util.stream.Collectors;

public class Calendar {
    private String userId;                    // private = owner identity encapsulated
    private String userName;                  // private = display name hidden from direct access
    private List<Event> events;               // private = events managed through add/remove methods
    private ConflictDetector conflictDetector; // private = detection logic is implementation detail

    public Calendar(String userId, String userName) {
        this.userId = userId;
        this.userName = userName;
        this.events = new ArrayList<>();
        this.conflictDetector = new ConflictDetector();
    }

    public String getUserId() { return userId; }
    public String getUserName() { return userName; }
    public List<Event> getEvents() { return new ArrayList<>(events); }

    public boolean addEvent(Event event) {
        if (conflictDetector.hasConflict(event, events)) {
            System.out.println("Warning: Event '" + event.getTitle() + "' conflicts with existing event!");
        }
        events.add(event);
        return true;
    }

    public void removeEvent(String eventId) {
        events.removeIf(e -> e.getId().equals(eventId));
    }

    public List<Event> getEventsForDate(LocalDate date) {
        return events.stream()
            .filter(e -> e.getTimeSlot().getStart().toLocalDate().equals(date))
            .collect(Collectors.toList());
    }

    public List<String> checkConflicts() {
        return conflictDetector.findConflicts(events);
    }
}

// service/CalendarService.java — Orchestrates event creation and conflict detection
import java.util.HashMap;
import java.util.List;
import java.util.Map;

public class CalendarService {
    private Map<String, Calendar> calendars;  // private = user-to-calendar registry encapsulated
    private int eventCounter;                 // private = auto-incrementing ID generator

    public CalendarService() {
        this.calendars = new HashMap<>();
        this.eventCounter = 0;
    }

    public Calendar createCalendar(String userId, String userName) {
        Calendar calendar = new Calendar(userId, userName);
        calendars.put(userId, calendar);
