        }
        return List.of();
    }
}

// service/ConflictDetector.java — O(n) scan to detect overlapping events
import java.util.ArrayList;
import java.util.List;

public class ConflictDetector {

    public List<String> findConflicts(List<Event> events) {
        List<String> conflicts = new ArrayList<>();
        // O(n^2) pairwise comparison of all events
        for (int i = 0; i < events.size(); i++) {
            for (int j = i + 1; j < events.size(); j++) {
                Event e1 = events.get(i);
                Event e2 = events.get(j);
                if (e1.getTimeSlot().overlapsWith(e2.getTimeSlot())) {
                    conflicts.add("CONFLICT: " + e1.getTitle() + " overlaps with " + e2.getTitle());
                }
            }
        }
        return conflicts;
    }

    public boolean hasConflict(Event newEvent, List<Event> existingEvents) {
        // O(n) linear scan through all existing events
        for (Event existing : existingEvents) {
            if (!existing.getId().equals(newEvent.getId()) &&
                existing.getTimeSlot().overlapsWith(newEvent.getTimeSlot())) {
                return true;
            }
        }
        return false;
    }
}

// service/EventBuilder.java — Fluent builder for constructing complex events
import java.time.LocalDateTime;

public class EventBuilder {
    private String id;
    private String title;
    private String description;
    private LocalDateTime startTime;
    private LocalDateTime endTime;
    private String organizerId;
    private RecurrenceRule recurrenceRule;
    private int reminderMinutes = -1;

    public EventBuilder(String id) {
        this.id = id;
    }

    public EventBuilder title(String title) { this.title = title; return this; }
    public EventBuilder description(String description) { this.description = description; return this; }
    public EventBuilder from(LocalDateTime start) { this.startTime = start; return this; }
    public EventBuilder to(LocalDateTime end) { this.endTime = end; return this; }
    public EventBuilder organizer(String organizerId) { this.organizerId = organizerId; return this; }
    public EventBuilder recurring(RecurrenceRule rule) { this.recurrenceRule = rule; return this; }
    public EventBuilder reminder(int minutesBefore) { this.reminderMinutes = minutesBefore; return this; }

    public Event build() {
        if (title == null || startTime == null || endTime == null || organizerId == null) {
            throw new IllegalStateException("Title, start, end, and organizer are required");
        }
        TimeSlot slot = new TimeSlot(startTime, endTime);
        Event event = new Event(id, title, slot, organizerId);
        if (description != null) event.setDescription(description);
        if (recurrenceRule != null) event.setRecurrenceRule(recurrenceRule);
        if (reminderMinutes >= 0) event.addReminder(new Reminder(reminderMinutes, title));
        return event;
    }
}

// strategy/RecurrenceRule.java — Defines how an event repeats (daily, weekly, custom)
import java.time.LocalDateTime;
import java.util.ArrayList;
import java.util.List;

public interface RecurrenceRule {             // interface = contract for recurrence strategies
    List<TimeSlot> generateOccurrences(TimeSlot original, int count);
    String getDescription();
}

class DailyRecurrence implements RecurrenceRule { // implements = fulfills the RecurrenceRule contract
    @Override
    public List<TimeSlot> generateOccurrences(TimeSlot original, int count) {
        List<TimeSlot> occurrences = new ArrayList<>();
        for (int i = 0; i < count; i++) {
            LocalDateTime newStart = original.getStart().plusDays(i);
            LocalDateTime newEnd = original.getEnd().plusDays(i);
            occurrences.add(new TimeSlot(newStart, newEnd));
        }
        return occurrences;
    }

    @Override
    public String getDescription() { return "Daily"; }
}

class WeeklyRecurrence implements RecurrenceRule { // implements = weekly version of recurrence
    @Override
    public List<TimeSlot> generateOccurrences(TimeSlot original, int count) {
        List<TimeSlot> occurrences = new ArrayList<>();
        for (int i = 0; i < count; i++) {
            LocalDateTime newStart = original.getStart().plusWeeks(i);
            LocalDateTime newEnd = original.getEnd().plusWeeks(i);
            occurrences.add(new TimeSlot(newStart, newEnd));
        }
        return occurrences;
    }

    @Override
    public String getDescription() { return "Weekly"; }
}

class MonthlyRecurrence implements RecurrenceRule { // implements = monthly version of recurrence
    @Override
    public List<TimeSlot> generateOccurrences(TimeSlot original, int count) {
        List<TimeSlot> occurrences = new ArrayList<>();
        for (int i = 0; i < count; i++) {
            LocalDateTime newStart = original.getStart().plusMonths(i);
            LocalDateTime newEnd = original.getEnd().plusMonths(i);
            occurrences.add(new TimeSlot(newStart, newEnd));
        }
        return occurrences;
    }

    @Override
    public String getDescription() { return "Monthly"; }
}

