// strategy/RecurrenceRule.java — Defines how an event repeats (daily, weekly, custom)
import java.time.LocalDateTime;
import java.util.ArrayList;
import java.util.List;

public interface RecurrenceRule {             // interface = pluggable recurrence strategies
    List<TimeSlot> generateOccurrences(TimeSlot original, int count);
    String getDescription();
}

class DailyRecurrence implements RecurrenceRule {
    @Override
    public List<TimeSlot> generateOccurrences(TimeSlot original, int count) {
        List<TimeSlot> occurrences = new ArrayList<>();
        for (int i = 0; i < count; i++) {
            LocalDateTime newStart = original.getStart().plusDays(i);
            LocalDateTime newEnd = original.getEnd().plusDays(i);
            occurrences.add(new TimeSlot(newStart, newEnd));
        }
        return occurrences;
    }

    @Override
    public String getDescription() { return "Daily"; }
}

class WeeklyRecurrence implements RecurrenceRule {
    @Override
    public List<TimeSlot> generateOccurrences(TimeSlot original, int count) {
        List<TimeSlot> occurrences = new ArrayList<>();
        for (int i = 0; i < count; i++) {
            LocalDateTime newStart = original.getStart().plusWeeks(i);
            LocalDateTime newEnd = original.getEnd().plusWeeks(i);
            occurrences.add(new TimeSlot(newStart, newEnd));
        }
        return occurrences;
    }

    @Override
    public String getDescription() { return "Weekly"; }
}

class MonthlyRecurrence implements RecurrenceRule {
    @Override
    public List<TimeSlot> generateOccurrences(TimeSlot original, int count) {
        List<TimeSlot> occurrences = new ArrayList<>();
        for (int i = 0; i < count; i++) {
            LocalDateTime newStart = original.getStart().plusMonths(i);
            LocalDateTime newEnd = original.getEnd().plusMonths(i);
            occurrences.add(new TimeSlot(newStart, newEnd));
        }
        return occurrences;
    }

    @Override
    public String getDescription() { return "Monthly"; }
}

// concurrent/Main.java — 10 threads booking same time range, only 1 succeeds

import java.util.*;
import java.util.concurrent.*;
import java.util.concurrent.atomic.AtomicInteger;

public class Main {
    public static void main(String[] args) throws InterruptedException {
        System.out.println("=== Concurrent Calendar System Demo ===\n");
        System.out.println("Race condition: Two people booking overlapping time slots simultaneously.\n");

        CalendarService calendar = new CalendarService();
        int threadCount = 10;
        long slotStart = 1000L; // Same time slot for all
        long slotEnd = 2000L;

        CountDownLatch startLatch = new CountDownLatch(1);
        CountDownLatch doneLatch = new CountDownLatch(threadCount);
        AtomicInteger successCount = new AtomicInteger(0);

        for (int i = 0; i < threadCount; i++) {
            final int threadId = i;
            new Thread(() -> {
                try {
                    startLatch.await();
                    Event event = new Event(
                        "evt-" + threadId,
                        "Meeting-" + threadId,
                        slotStart,
                        slotEnd,
                        "User-" + threadId
                    );
                    boolean success = calendar.book(event);
                    if (success) {
                        successCount.incrementAndGet();
                        System.out.println("  User-" + threadId + " BOOKED successfully");
                    } else {
                        System.out.println("  User-" + threadId + " REJECTED (conflict)");
                    }
                } catch (InterruptedException e) {
                    Thread.currentThread().interrupt();
                } finally {
                    doneLatch.countDown();
                }
            }).start();
        }

        startLatch.countDown();
        doneLatch.await();

        // Now test non-overlapping bookings — should all succeed
        System.out.println("\n--- Non-overlapping bookings test ---");
        int nonOverlapSuccess = 0;
        for (int i = 0; i < 5; i++) {
            long start = 3000L + (i * 1000);
            long end = start + 500;
            Event event = new Event("nol-" + i, "Separate-" + i, start, end, "User-X");
            if (calendar.book(event)) {
                nonOverlapSuccess++;
            }
        }

        System.out.println("\n--- Results ---");
        System.out.println("Threads competing for same slot: " + threadCount);
        System.out.println("Successful bookings for same slot: " + successCount.get());
        System.out.println("Rejected bookings: " + calendar.getRejectedCount());
        System.out.println("Non-overlapping bookings succeeded: " + nonOverlapSuccess + "/5");
        System.out.println("Total events in calendar: " + calendar.getBookedCount());

        boolean exactlyOneWins = (successCount.get() == 1);
        boolean allNonOverlap = (nonOverlapSuccess == 5);
        boolean totalCorrect = (calendar.getBookedCount() == 6); // 1 overlapping + 5 non-overlapping

        System.out.println("\nExactly one winner: " + exactlyOneWins);
        System.out.println("Non-overlapping all accepted: " + allNonOverlap);

        boolean passed = exactlyOneWins && allNonOverlap && totalCorrect;
        System.out.println("\nCorrectness check: " + (passed ? "PASSED" : "FAILED"));
    }
}

// concurrent/model/Event.java — Calendar event with start/end times

public class Event {
    private final String eventId;             // final = immutable after construction; safe to share across threads
    private final String title;               // final = no thread can change title after creation
    private final long startTime;             // final = time boundaries are fixed once created
    private final long endTime;               // final = guarantees safe publication to all threads
    private final String bookedBy;            // final = ownership is immutable

    public Event(String eventId, String title, long startTime, long endTime, String bookedBy) {
        this.eventId = eventId;
        this.title = title;
        this.startTime = startTime;
        this.endTime = endTime;
        this.bookedBy = bookedBy;
    }

    public String getEventId() { return eventId; }
    public String getTitle() { return title; }
    public long getStartTime() { return startTime; }
    public long getEndTime() { return endTime; }
    public String getBookedBy() { return bookedBy; }

