    private String snapshotText;
    private String authorId;
    private LocalDateTime timestamp;
    private String description;

    public Version(String versionId, String snapshotText, String authorId, String description) {
        this.versionId = versionId;
        this.snapshotText = snapshotText;
        this.authorId = authorId;
        this.timestamp = LocalDateTime.now();
        this.description = description;
    }

    public String getVersionId() { return versionId; }
    public String getSnapshotText() { return snapshotText; }
    public String getAuthorId() { return authorId; }
    public LocalDateTime getTimestamp() { return timestamp; }
    public String getDescription() { return description; }

    @Override
    public String toString() { return versionId; }
}

// service/DocumentEditor.java — Editor using GapBuffer for O(1) inserts and reverse-diff undo
import java.util.ArrayList;
import java.util.HashMap;
import java.util.List;
import java.util.Map;

public class DocumentEditor {
    private GapBuffer buffer;                 // GapBuffer = O(1) insert at cursor vs O(n) String concat
    private String title;
    private List<EditCommand> commandHistory;
    private List<EditCommand> redoStack;
    private VersionHistory versionHistory;
    private Map<String, Collaborator> collaborators;
    private int versionCounter;

    public DocumentEditor(String title) {
        this.title = title;
        this.buffer = new GapBuffer();
        this.commandHistory = new ArrayList<>();
        this.redoStack = new ArrayList<>();
        this.versionHistory = new VersionHistory();
        this.collaborators = new HashMap<>();
        this.versionCounter = 0;
    }

    public String getFullText() { return buffer.getText(); }
    public int length() { return buffer.length(); }
    public VersionHistory getVersionHistory() { return versionHistory; }

    public Collaborator addCollaborator(String userId, String name) {
        Collaborator collab = new Collaborator(userId, name);
        collaborators.put(userId, collab);
        return collab;
    }

    public void insertText(int position, String text) {
        EditCommand cmd = new InsertText(buffer, position, text);
        cmd.execute();
        commandHistory.add(cmd);
        redoStack.clear();
        System.out.println(cmd.getDescription());
    }

    public void deleteText(int position, int length) {
        EditCommand cmd = new DeleteText(buffer, position, length);
        cmd.execute();
        commandHistory.add(cmd);
        redoStack.clear();
        System.out.println(cmd.getDescription());
    }

    // WHY: Undo uses reverse-diff (stored deleted text) instead of full snapshot
    public boolean undo() {
        if (commandHistory.isEmpty()) return false;
        EditCommand cmd = commandHistory.remove(commandHistory.size() - 1);
        cmd.undo();
        redoStack.add(cmd);
        return true;
    }

    public boolean redo() {
        if (redoStack.isEmpty()) return false;
        EditCommand cmd = redoStack.remove(redoStack.size() - 1);
        cmd.execute();
        commandHistory.add(cmd);
        return true;
    }

    public String saveVersion(String authorId, String description) {
        String verId = "v" + (++versionCounter);
        // WHY: Store only text string, not full object graph
        Version version = new Version(verId, buffer.getText(), authorId, description);
        versionHistory.saveVersion(version);
        return verId;
    }

    public void restoreVersion(String versionId) {
        Version version = versionHistory.getVersion(versionId);
        if (version != null) {
            this.buffer = new GapBuffer(version.getSnapshotText());
            commandHistory.clear();
            redoStack.clear();
        }
    }
}

// service/EditCommand.java — Encapsulates edits as undoable operations with reverse-diffs
public interface EditCommand {                // interface = pluggable command pattern for undo/redo
    void execute();
    void undo();
    String getDescription();
}

class InsertText implements EditCommand {
    private GapBuffer buffer;
    private int position;
    private String text;

    public InsertText(GapBuffer buffer, int position, String text) {
        this.buffer = buffer; this.position = position; this.text = text;
    }

    @Override public void execute() { buffer.insert(position, text); }
    // WHY: Reverse-diff approach — undo just deletes the exact chars inserted
    @Override public void undo() { buffer.delete(position, text.length()); }
    @Override public String getDescription() { return "Insert '" + text + "' at position " + position; }
}

class DeleteText implements EditCommand {
    private GapBuffer buffer;
    private int position;
    private int length;
    private String deletedText;

    public DeleteText(GapBuffer buffer, int position, int length) {
        this.buffer = buffer; this.position = position; this.length = length;
    }

    @Override public void execute() { deletedText = buffer.delete(position, length); }
    // WHY: Stores only the deleted text (reverse-diff) rather than full document snapshot
    @Override public void undo() { buffer.insert(position, deletedText); }
    @Override public String getDescription() { return "Delete " + length + " chars at position " + position; }
}

// service/VersionHistory.java — Maintains document versions with text snapshots
import java.util.ArrayList;
import java.util.HashMap;
import java.util.List;
import java.util.Map;

public class VersionHistory {
    private List<Version> versions;            // ordered history for chronological access
    private Map<String, Version> versionIndex; // HashMap = O(1) version lookup by ID vs O(n) scan

    public VersionHistory() {
        this.versions = new ArrayList<>();
        this.versionIndex = new HashMap<>();
    }

    public void saveVersion(Version version) {
        versions.add(version);
        versionIndex.put(version.getVersionId(), version);
    }

    // WHY: O(1) lookup via index vs O(n) linear search
    public Version getVersion(String versionId) {
        return versionIndex.get(versionId);
    }

    public Version getLatestVersion() {
        if (versions.isEmpty()) return null;
        return versions.get(versions.size() - 1);
    }

    public int size() { return versions.size(); }

    @Override
    public String toString() { return versions.toString(); }
}

// concurrent/Main.java — 5 collaborators editing simultaneously, verify no lost edits

import java.util.*;
import java.util.concurrent.*;
import java.util.concurrent.atomic.AtomicInteger;

public class Main {
    public static void main(String[] args) throws InterruptedException {
        System.out.println("=== Concurrent Document Editor Demo ===\n");
        System.out.println("Race condition: Two collaborators editing same paragraph —");
        System.out.println("one's changes overwrite the other's.\n");

        CollaborativeEditor editor = new CollaborativeEditor();
        editor.addSegment("para-1", "Initial content of paragraph 1");

        int collaboratorCount = 5;
        int editsPerCollaborator = 50;
        int totalAttempts = collaboratorCount * editsPerCollaborator;

        // Test 1: Optimistic CAS without retry — conflicts detected
        System.out.println("--- Test 1: CAS without retry (conflicts expected) ---");
        CountDownLatch startLatch = new CountDownLatch(1);
        CountDownLatch doneLatch = new CountDownLatch(collaboratorCount);
        AtomicInteger perThreadSuccess = new AtomicInteger(0);
        AtomicInteger perThreadConflict = new AtomicInteger(0);

        for (int c = 0; c < collaboratorCount; c++) {
            final String editorId = "Editor-" + c;
            new Thread(() -> {
                try {
                    startLatch.await();
                    for (int e = 0; e < editsPerCollaborator; e++) {
                        boolean ok = editor.editSegment("para-1", editorId, "edit-" + e);
                        if (ok) perThreadSuccess.incrementAndGet();
                        else perThreadConflict.incrementAndGet();
                    }
                } catch (InterruptedException ex) {
                    Thread.currentThread().interrupt();
                } finally {
                    doneLatch.countDown();
                }
            }).start();
        }

        startLatch.countDown();
        doneLatch.await();

        DocumentSegment seg = editor.getSegment("para-1");
        int versionAfterTest1 = seg.getVersion();

        System.out.println("Total attempts: " + totalAttempts);
        System.out.println("Successful edits: " + perThreadSuccess.get());
        System.out.println("Conflicts detected: " + perThreadConflict.get());
        System.out.println("Sum (success+conflict): " + (perThreadSuccess.get() + perThreadConflict.get()));
        System.out.println("Segment version: " + versionAfterTest1);
        System.out.println("Version matches successes: " + (versionAfterTest1 == perThreadSuccess.get()));

        // Test 2: CAS with retry — all edits eventually succeed
        System.out.println("\n--- Test 2: CAS with retry (all edits must succeed) ---");
        CollaborativeEditor editor2 = new CollaborativeEditor();
        editor2.addSegment("para-2", "Initial content");

        CountDownLatch startLatch2 = new CountDownLatch(1);
        CountDownLatch doneLatch2 = new CountDownLatch(collaboratorCount);

        for (int c = 0; c < collaboratorCount; c++) {
            final String editorId = "Editor-" + c;
            new Thread(() -> {
                try {
                    startLatch2.await();
                    for (int e = 0; e < editsPerCollaborator; e++) {
                        editor2.editWithRetry("para-2", editorId, "retry-edit-" + e);
                    }
                } catch (InterruptedException ex) {
                    Thread.currentThread().interrupt();
                } finally {
                    doneLatch2.countDown();
                }
            }).start();
        }

        startLatch2.countDown();
        doneLatch2.await();

        DocumentSegment seg2 = editor2.getSegment("para-2");
        int finalVersion = seg2.getVersion();
        int expectedVersion = totalAttempts;

        System.out.println("Total edits attempted: " + totalAttempts);
        System.out.println("Final version: " + finalVersion);
        System.out.println("Expected version: " + expectedVersion);
        System.out.println("Conflicts encountered (retried): " + editor2.getConflictsDetected());
        System.out.println("All edits applied: " + (finalVersion == expectedVersion));

        // Correctness checks
        boolean test1Correct = (perThreadSuccess.get() + perThreadConflict.get() == totalAttempts)
                && (versionAfterTest1 == perThreadSuccess.get());
        boolean test2Correct = (finalVersion == expectedVersion);

        System.out.println("\n--- Summary ---");
        System.out.println("Test 1 (conflict detection): " + (test1Correct ? "PASSED" : "FAILED"));
        System.out.println("Test 2 (no lost edits with retry): " + (test2Correct ? "PASSED" : "FAILED"));
        System.out.println("\nCorrectness check: " + (test1Correct && test2Correct ? "PASSED" : "FAILED"));
    }
}

// concurrent/model/DocumentSegment.java — Document segment with AtomicInteger version for CAS-based optimistic concurrency

import java.util.concurrent.atomic.AtomicInteger;
import java.util.concurrent.atomic.AtomicReference;

public class DocumentSegment {
    private final String segmentId;           // final = safe publication; identity never changes
    private final AtomicInteger version;      // AtomicInteger = CAS-based version for optimistic concurrency
    private final AtomicReference<String> content; // AtomicReference = atomic content swap on successful CAS

    public DocumentSegment(String segmentId, String initialContent) {
        this.segmentId = segmentId;
        this.version = new AtomicInteger(0);
        this.content = new AtomicReference<>(initialContent);
    }

    /**
     * CAS-based edit: read version, prepare edit, CAS(oldVersion, newVersion).
     * Returns true if edit applied, false if conflict detected.
     */
    public boolean tryEdit(int expectedVersion, String newContent) {
        if (version.compareAndSet(expectedVersion, expectedVersion + 1)) {
            content.set(newContent);
            return true;
        }
        return false; // Conflict — another editor changed version
    }

    public int getVersion() { return version.get(); }
    public String getContent() { return content.get(); }
    public String getSegmentId() { return segmentId; }

    @Override
    public String toString() {
        return segmentId + " v" + version.get() + ": " + content.get();
    }
}

// concurrent/service/CollaborativeEditor.java — Manages concurrent edits with CAS optimistic concurrency

import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.atomic.AtomicInteger;

public class CollaborativeEditor {
    private final ConcurrentHashMap<String, DocumentSegment> segments; // ConcurrentHashMap = thread-safe segment registry
    private final AtomicInteger successfulEdits;  // AtomicInteger = lock-free counter across threads
    private final AtomicInteger conflictDetected; // AtomicInteger = tracks CAS failures atomically

    public CollaborativeEditor() {
        this.segments = new ConcurrentHashMap<>();
        this.successfulEdits = new AtomicInteger(0);
        this.conflictDetected = new AtomicInteger(0);
    }

    public void addSegment(String segmentId, String initialContent) {
        segments.put(segmentId, new DocumentSegment(segmentId, initialContent));
    }

    /**
     * Attempt an edit with optimistic concurrency.
     * Reads current version, applies transform, CAS to commit.
     * Returns true if edit was applied, false if conflict.
     */
    public boolean editSegment(String segmentId, String editorId, String newContent) {
        DocumentSegment segment = segments.get(segmentId);
        if (segment == null) return false;

        int currentVersion = segment.getVersion();
        // Simulate read-modify-write with potential conflict window
        String editedContent = "[" + editorId + "] " + newContent;

        boolean success = segment.tryEdit(currentVersion, editedContent);
        if (success) {
            successfulEdits.incrementAndGet();
        } else {
            conflictDetected.incrementAndGet();
        }
        return success;
    }

    /**
     * Retry-based edit: keep trying until succeeds (for mandatory edits).
     */
    public void editWithRetry(String segmentId, String editorId, String newContent) {
        DocumentSegment segment = segments.get(segmentId);
        if (segment == null) return;

        while (true) {
            int currentVersion = segment.getVersion();
            String editedContent = "[" + editorId + " v" + (currentVersion + 1) + "] " + newContent;
            if (segment.tryEdit(currentVersion, editedContent)) {
                successfulEdits.incrementAndGet();
                return;
            }
            conflictDetected.incrementAndGet();
            // Retry with fresh version
        }
    }

    public DocumentSegment getSegment(String segmentId) {
        return segments.get(segmentId);
    }

    public int getSuccessfulEdits() { return successfulEdits.get(); }
    public int getConflictsDetected() { return conflictDetected.get(); }
}

