// Main.java — Entry point demonstrating the music player
public class Main {
    public static void main(String[] args) {
        System.out.println("=== Music Player Demo (Naive) ===");

        Song s1 = new Song("1", "Bohemian Rhapsody", "Queen", "A Night at the Opera", 354);
        Song s2 = new Song("2", "Hotel California", "Eagles", "Hotel California", 391);
        Song s3 = new Song("3", "Stairway to Heaven", "Led Zeppelin", "Led Zeppelin IV", 482);
        Song s4 = new Song("4", "Yesterday", "Beatles", "Help!", 125);
        Song s5 = new Song("5", "Imagine", "John Lennon", "Imagine", 187);

        Playlist playlist = new Playlist("My Favorites");
        playlist.addSong(s1); playlist.addSong(s2); playlist.addSong(s3);
        playlist.addSong(s4); playlist.addSong(s5);

        MusicPlayer player = new MusicPlayer();
        player.addObserver(new ConsolePlayerObserver("UI"));
        player.loadPlaylist(playlist);

        System.out.println("\n--- Playback ---");
        player.play();
        player.next();
        player.next();
        player.previous();

        System.out.println("\n--- Queue ---");
        player.addToQueue(s4);
        player.next();

        System.out.println("\n--- Shuffle ---");
        player.enableShuffle(new RandomShuffle());
        for (int i = 0; i < 3; i++) player.next();

        System.out.println("\n--- Repeat ---");
        player.disableShuffle();
        player.setRepeatMode(RepeatMode.ONE);
        player.loadPlaylist(playlist);
        player.play();
        player.next();

        System.out.println("\n=== Music Player Demo Complete ===");
    }
}

// model/Playlist.java — An ordered collection of songs
import java.util.ArrayList;
import java.util.List;

public class Playlist {
    private String name;                      // private = playlist identity encapsulated
    private List<Song> songs;                 // private = song list managed through add/remove

    public Playlist(String name) { this.name = name; this.songs = new ArrayList<>(); }

    public String getName() { return name; }
    public List<Song> getSongs() { return songs; }
    public int size() { return songs.size(); }
    public void addSong(Song song) { songs.add(song); }
    public void removeSong(String songId) { songs.removeIf(s -> s.getId().equals(songId)); }

    public PlaylistIterator createIterator(RepeatMode repeatMode) {
        List<Integer> order = new ArrayList<>();
        for (int i = 0; i < songs.size(); i++) order.add(i);
        return new PlaylistIterator(songs, order, repeatMode);
    }

    public PlaylistIterator createShuffledIterator(ShuffleStrategy strategy, RepeatMode repeatMode) {
        List<Integer> shuffledOrder = strategy.shuffle(songs.size());
        return new PlaylistIterator(songs, shuffledOrder, repeatMode);
    }

    @Override
    public String toString() { return name + " (" + songs.size() + " songs)"; }
}

// model/Queue.java — The current playback queue of upcoming songs
import java.util.LinkedList;

public class Queue {
    private LinkedList<Song> queue;           // private = internal queue hidden; accessed via enqueue/dequeue

    public Queue() { this.queue = new LinkedList<>(); }
    public void enqueue(Song song) { queue.addLast(song); }
    public Song dequeue() { if (queue.isEmpty()) return null; return queue.removeFirst(); }
    public Song peek() { return queue.peekFirst(); }
    public boolean isEmpty() { return queue.isEmpty(); }
    public int size() { return queue.size(); }
    public void clear() { queue.clear(); }
}

// model/RepeatMode.java — Enumerates repeat modes (none, one, all)
public enum RepeatMode {                      // enum = fixed set of repeat modes; no invalid values
    NONE, ONE, ALL;
    @Override public String toString() { return name(); }
}

// model/Song.java — Represents a music track with title, artist, and duration
public class Song {
    private String id;                        // private = unique identity hidden from outside
    private String title;                     // private = accessed only via getTitle()
    private String artist;                    // private = metadata encapsulated
    private String album;                     // private = metadata encapsulated
    private int durationSeconds;              // private = track length in seconds
    private int playCount;                    // private = incremented internally on each play

    public Song(String id, String title, String artist, String album, int durationSeconds) {
        this.id = id; this.title = title; this.artist = artist;
        this.album = album; this.durationSeconds = durationSeconds; this.playCount = 0;
    }

    public String getId() { return id; }
    public String getTitle() { return title; }
    public String getArtist() { return artist; }
    public String getAlbum() { return album; }
    public int getDurationSeconds() { return durationSeconds; }
    public int getPlayCount() { return playCount; }
    public void incrementPlayCount() { playCount++; }

    @Override
    public String toString() { return title + " - " + artist; }
}

// service/ConsolePlayerObserver.java — Concrete observer that prints playback events to console
//
// This class IMPLEMENTS PlayerObserver (defined in PlayerObserver.java).

class ConsolePlayerObserver implements PlayerObserver { // implements = fulfills observer contract
    private String name;              // private = observer's display name

    public ConsolePlayerObserver(String name) { this.name = name; }

    @Override
    public void onTrackChanged(Song newTrack) {
        System.out.println("[" + name + "] Track: " + newTrack);
    }

    @Override
    public void onStateChanged(String newState) {
        System.out.println("[" + name + "] State: " + newState);
    }
}

// service/MusicPlayer.java — Controls playback and manages the play queue
import java.util.ArrayList;
import java.util.List;

public class MusicPlayer {
    private PlayerState state;                // private = state pattern; current player state
    private Playlist currentPlaylist;         // private = currently loaded playlist
    private PlaylistIterator iterator;        // private = traversal logic encapsulated
    private Queue playQueue;                  // private = user-queued songs take priority
    private Song currentSong;                 // private = what's playing now
    private RepeatMode repeatMode;            // private = repeat behavior setting
    private ShuffleStrategy shuffleStrategy;  // private = pluggable shuffle algorithm
    private boolean shuffleEnabled;           // private = shuffle on/off flag
    private List<PlayerObserver> observers;   // private = registered event listeners

    public MusicPlayer() {
        this.state = new StoppedState(); this.playQueue = new Queue();
        this.repeatMode = RepeatMode.NONE; this.shuffleEnabled = false;
        this.observers = new ArrayList<>();
    }

    public void addObserver(PlayerObserver observer) { observers.add(observer); }
    private void notifyTrackChanged() { for (PlayerObserver obs : observers) obs.onTrackChanged(currentSong); }
    private void notifyStateChanged() { for (PlayerObserver obs : observers) obs.onStateChanged(state.getStateName()); }

    public void loadPlaylist(Playlist playlist) {
        this.currentPlaylist = playlist;
        if (shuffleEnabled && shuffleStrategy != null) {
            this.iterator = playlist.createShuffledIterator(shuffleStrategy, repeatMode);
        } else { this.iterator = playlist.createIterator(repeatMode); }
        this.currentSong = iterator.current();
    }

    public void play() { state.play(this); notifyStateChanged(); }
    public void pause() { state.pause(this); notifyStateChanged(); }
    public void stop() { state.stop(this); notifyStateChanged(); }

    public Song next() {
        if (!playQueue.isEmpty()) { currentSong = playQueue.dequeue(); }
        else if (iterator != null) {
            Song nextSong = iterator.next();
            if (nextSong != null) { currentSong = nextSong; }
            else { System.out.println("End of playlist reached"); stop(); return null; }
        }
        if (currentSong != null) {
            currentSong.incrementPlayCount(); state = new PlayingState();
            System.out.println("Now playing: " + currentSong); notifyTrackChanged();
        }
        return currentSong;
    }

    public Song previous() {
        if (iterator != null) {
            Song prevSong = iterator.previous();
            if (prevSong != null) {
                currentSong = prevSong; state = new PlayingState();
                System.out.println("Now playing: " + currentSong); notifyTrackChanged();
            }
        }
        return currentSong;
    }

    public void addToQueue(Song song) { playQueue.enqueue(song); System.out.println("Added to queue: " + song); }

    public void setRepeatMode(RepeatMode mode) {
        this.repeatMode = mode;
        if (iterator != null) iterator.setRepeatMode(mode);
        System.out.println("Repeat mode: " + mode);
    }

    public void enableShuffle(ShuffleStrategy strategy) {
        this.shuffleEnabled = true; this.shuffleStrategy = strategy;
        if (currentPlaylist != null) {
            this.iterator = currentPlaylist.createShuffledIterator(strategy, repeatMode);
            this.currentSong = iterator.current();
        }
        System.out.println("Shuffle enabled (" + strategy.getName() + ")");
    }

    public void disableShuffle() {
        this.shuffleEnabled = false;
        if (currentPlaylist != null) {
            this.iterator = currentPlaylist.createIterator(repeatMode);
            this.currentSong = iterator.current();
        }
        System.out.println("Shuffle disabled");
    }

    public Song getCurrentSong() { return currentSong; }
    public PlayerState getState() { return state; }
    public void setState(PlayerState state) { this.state = state; }
}

