// Main.java — Entry point demonstrating the shopping cart
public class Main {
    public static void main(String[] args) {
        System.out.println("=== Shopping Cart Demo (Naive) ===");

        ShoppingCart cart = new ShoppingCart("CA");
        cart.addObserver(new PriceDropNotifier("Alice"));

        Product laptop = new Product("p1", "Laptop", 999.99, "Electronics");
        Product headphones = new Product("p2", "Headphones", 79.99, "Electronics");
        Product mouse = new Product("p3", "Mouse", 29.99, "Accessories");

        System.out.println("\n--- Adding Items ---");
        cart.addItem(laptop, 1);
        cart.addItem(headphones, 2);
        cart.addItem(mouse, 1);
        System.out.println("Subtotal: $" + String.format("%.2f", cart.getSubtotal()));

        System.out.println("\n--- Discount ---");
        cart.applyDiscount(new PercentageDiscount(10));

        System.out.println("\n--- Coupon ---");
        cart.applyCoupon(new Coupon("FLAT50", new FlatDiscount(50.00), 100.0));

        System.out.println("\n--- Add-ons ---");
        cart.addService(new GiftWrap());
        cart.addService(new ExpressShipping());

        System.out.println("\n--- Checkout ---");
        cart.checkout();

        System.out.println("\n--- Price Drop ---");
        double oldPrice = laptop.getPrice();
        laptop.setPrice(899.99);
        cart.notifyPriceChange(laptop, oldPrice, 899.99);

        // === Test: Composite — combine multiple discount strategies as one ===
        System.out.println("\n--- Composite Discount ---");
        DiscountStrategy combined = new CompositeDiscount(
                new PercentageDiscount(10),
                new FlatDiscount(50.00));
        System.out.println("  Description: " + combined.getDescription());
        System.out.printf("  Discount on cart: $%.2f%n", combined.calculateDiscount(cart.getItems()));

        System.out.println("\n=== Shopping Cart Demo Complete ===");
    }
}

// model/CartItem.java — Represents a product in the cart with quantity
public class CartItem {
    private Product product;                  // private = which product this cart line represents
    private int quantity;                     // private = controlled via set/increment methods

    public CartItem(Product product, int quantity) { this.product = product; this.quantity = quantity; }

    public Product getProduct() { return product; }
    public int getQuantity() { return quantity; }
    public void setQuantity(int quantity) { if (quantity > 0) this.quantity = quantity; }
    public void incrementQuantity(int amount) { this.quantity += amount; }
    public double getSubtotal() { return product.getPrice() * quantity; }

    @Override public String toString() { return product.getName() + " x" + quantity + ": $" + String.format("%.2f", getSubtotal()); }
}

// model/Coupon.java — Represents a discount coupon with code and rules
public class Coupon {
    private String code;                      // private = coupon code encapsulated
    private DiscountStrategy discountStrategy; // private = strategy pattern for discount calculation
    private boolean used;                     // private = one-time-use enforced internally
    private double minimumOrder;              // private = minimum order threshold for validity

    public Coupon(String code, DiscountStrategy discountStrategy, double minimumOrder) {
        this.code = code; this.discountStrategy = discountStrategy; this.used = false; this.minimumOrder = minimumOrder;
    }

    public String getCode() { return code; }
    public DiscountStrategy getDiscountStrategy() { return discountStrategy; }
    public boolean isUsed() { return used; }
    public double getMinimumOrder() { return minimumOrder; }
    public boolean isValid(double orderTotal) { return !used && orderTotal >= minimumOrder; }
    public void markUsed() { this.used = true; }

    @Override public String toString() { return code + " (" + discountStrategy.getDescription() + ")"; }
}

// model/Product.java — Represents a purchasable product with price and details
public class Product {
    private String id;                        // private = product identity hidden from outside
    private String name;                      // private = accessed only via getName()
    private double price;                     // private = changed only through setPrice()
    private String category;                  // private = grouping info encapsulated

    public Product(String id, String name, double price, String category) {
        this.id = id; this.name = name; this.price = price; this.category = category;
    }

    public String getId() { return id; }
    public String getName() { return name; }
    public double getPrice() { return price; }
    public String getCategory() { return category; }
    public void setPrice(double newPrice) { this.price = newPrice; }

    @Override public String toString() { return name + " ($" + String.format("%.2f", price) + ")"; }
}

// service/CartDecorator.java — Adds extras (gift wrap, shipping) to cart
public abstract class CartDecorator {         // abstract = can't create generic decorator; use GiftWrap etc.
    protected String name;                    // protected = subclasses can access service name
    protected double cost;                    // protected = subclasses set their own cost

    public CartDecorator(String name, double cost) { this.name = name; this.cost = cost; }
    public String getName() { return name; }
    public double getCost() { return cost; }
    @Override public String toString() { return name + ": $" + String.format("%.2f", cost); }
}

class GiftWrap extends CartDecorator { public GiftWrap() { super("Gift Wrap", 5.99); } } // extends = concrete add-on
class ExpressShipping extends CartDecorator { public ExpressShipping() { super("Express Shipping", 14.99); } } // extends = concrete add-on

// service/PriceDropNotifier.java — Concrete observer that notifies users of price drops
//
// This class IMPLEMENTS PriceObserver (defined in PriceObserver.java).

class PriceDropNotifier implements PriceObserver { // implements = fulfills observer contract
    private String userName;          // private = who gets notified

    public PriceDropNotifier(String userName) { this.userName = userName; }

    @Override
    public void onPriceChanged(Product product, double oldPrice, double newPrice) {
        if (newPrice < oldPrice) {
            System.out.println("[" + userName + "] Price drop: " + product.getName() +
                " $" + String.format("%.2f", oldPrice) + " -> $" + String.format("%.2f", newPrice));
        }
    }
}

// service/PriceObserver.java — Observer pattern interface for price change events
// DESIGN PATTERN: Observer
//
// WHO IMPLEMENTS THIS? → PriceDropNotifier (in PriceDropNotifier.java)
// WHO CALLS IT? → Cart/ProductCatalog calls observers when product prices change
// WHY? → Decouples "price changed" from "notify user about the drop".

interface PriceObserver {             // interface = observer contract for price-change events
    void onPriceChanged(Product product, double oldPrice, double newPrice);
}

// service/ShoppingCart.java — Manages cart items and recalculates total every time
import java.util.ArrayList;
import java.util.List;

public class ShoppingCart {
    private List<CartItem> items;             // private = cart contents managed through methods
    private DiscountStrategy discountStrategy; // private = strategy pattern for discounts
    private Coupon appliedCoupon;             // private = single coupon per cart
    private List<CartDecorator> addOns;       // private = extra services (gift wrap, shipping)
    private TaxCalculator taxCalculator;      // private = tax logic encapsulated
    private String taxRegion;                 // private = determines tax rate
    private List<PriceObserver> priceObservers; // private = registered price-change listeners

    public ShoppingCart(String taxRegion) {
        this.items = new ArrayList<>(); this.addOns = new ArrayList<>();
        this.taxCalculator = new TaxCalculator(); this.taxRegion = taxRegion;
        this.priceObservers = new ArrayList<>();
    }

    public void addObserver(PriceObserver observer) { priceObservers.add(observer); }

    public void addItem(Product product, int quantity) {
        for (CartItem item : items) {
            if (item.getProduct().getId().equals(product.getId())) {
                item.incrementQuantity(quantity);
                System.out.println("Added: " + product.getName() + " x" + quantity);
                return;
            }
        }
        items.add(new CartItem(product, quantity));
        System.out.println("Added: " + product.getName() + " x" + quantity);
    }

    public void removeItem(String productId) { items.removeIf(item -> item.getProduct().getId().equals(productId)); }

    // Recalculates total from scratch every time
    public double getSubtotal() {
        return items.stream().mapToDouble(CartItem::getSubtotal).sum();
    }

    public void applyDiscount(DiscountStrategy strategy) {
        this.discountStrategy = strategy;
        double discount = strategy.calculateDiscount(items);
        System.out.println("Applied " + strategy.getDescription() + ": -$" + String.format("%.2f", discount));
    }

    public boolean applyCoupon(Coupon coupon) {
        if (coupon.isValid(getSubtotal())) {
            this.appliedCoupon = coupon;
            double discount = coupon.getDiscountStrategy().calculateDiscount(items);
            System.out.println("Applied coupon " + coupon.getCode() + ": -$" + String.format("%.2f", discount));
            coupon.markUsed();
            return true;
        }
        System.out.println("Coupon " + coupon.getCode() + " is not valid");
        return false;
    }

    public void addService(CartDecorator service) {
        addOns.add(service);
        System.out.println(service.getName() + " added: +$" + String.format("%.2f", service.getCost()));
    }

    public void notifyPriceChange(Product product, double oldPrice, double newPrice) {
        for (PriceObserver obs : priceObservers) obs.onPriceChanged(product, oldPrice, newPrice);
    }

    public void checkout() {
        double subtotal = getSubtotal();
        double discount = discountStrategy != null ? discountStrategy.calculateDiscount(items) : 0;
        double couponDiscount = appliedCoupon != null ? appliedCoupon.getDiscountStrategy().calculateDiscount(items) : 0;
        double taxable = subtotal - discount - couponDiscount;
        double tax = taxCalculator.calculateTax(taxable, taxRegion);
        double addOnsTotal = addOns.stream().mapToDouble(CartDecorator::getCost).sum();
        double total = taxable + tax + addOnsTotal;

        System.out.println("Checkout: Subtotal=$" + String.format("%.2f", subtotal) +
            " Discount=-$" + String.format("%.2f", discount + couponDiscount) +
            " Tax=$" + String.format("%.2f", tax) + " Total=$" + String.format("%.2f", total));
    }

    public List<CartItem> getItems() { return items; }
}

// service/TaxCalculator.java — Computes applicable taxes based on location
import java.util.HashMap;
import java.util.Map;

public class TaxCalculator {
    private Map<String, Double> taxRates;     // private = rate table hidden from outside

    public TaxCalculator() {
        taxRates = new HashMap<>();
        taxRates.put("CA", 9.5); taxRates.put("NY", 8.875); taxRates.put("TX", 8.25);
    }

    public double calculateTax(double amount, String region) {
        double rate = taxRates.getOrDefault(region, 0.0);
        return amount * (rate / 100.0);
    }
}

// strategy/CompositeDiscount.java — Composite of DiscountStrategy children, treated uniformly
// DESIGN PATTERN: Composite (a DiscountStrategy that contains other DiscountStrategy instances)
import java.util.ArrayList;
import java.util.Arrays;
import java.util.List;
import java.util.stream.Collectors;

class CompositeDiscount implements DiscountStrategy { // composite = a strategy that aggregates child strategies
    private final List<DiscountStrategy> children;

    public CompositeDiscount(DiscountStrategy... strategies) {
        this.children = new ArrayList<>(Arrays.asList(strategies));
    }

    @Override public double calculateDiscount(List<CartItem> items) {
        double total = 0.0;                                          // accumulate child discount amounts uniformly
        for (DiscountStrategy child : children) {
            total += child.calculateDiscount(items);                 // each child treated as a leaf or composite — same call
        }
        return total;
    }

    @Override public String getDescription() {
        if (children.isEmpty()) return "Composite (empty)";
        return "Composite[" + children.stream()
                .map(DiscountStrategy::getDescription)
                .collect(Collectors.joining(" + ")) + "]";
    }
}

// strategy/DiscountStrategy.java — Defines how discounts are calculated
// DESIGN PATTERN: Strategy
import java.util.List;

public interface DiscountStrategy {           // interface = strategy pattern for discount calculations
    double calculateDiscount(List<CartItem> items);
    String getDescription();
}

class PercentageDiscount implements DiscountStrategy { // implements = percentage-based discount
    private double percentage;
    public PercentageDiscount(double percentage) { this.percentage = percentage; }

    @Override public double calculateDiscount(List<CartItem> items) {
        double total = items.stream().mapToDouble(CartItem::getSubtotal).sum();
        return total * (percentage / 100.0);
    }
    @Override public String getDescription() { return String.format("%.0f%%", percentage); }
}

class FlatDiscount implements DiscountStrategy { // implements = fixed-amount discount
    private double amount;
    public FlatDiscount(double amount) { this.amount = amount; }

    @Override public double calculateDiscount(List<CartItem> items) {
        double total = items.stream().mapToDouble(CartItem::getSubtotal).sum();
        return Math.min(amount, total);
    }
    @Override public String getDescription() { return String.format("$%.2f off", amount); }
}

class BuyOneGetOne implements DiscountStrategy { // implements = BOGO discount strategy
    private String productId;
    public BuyOneGetOne(String productId) { this.productId = productId; }

    @Override public double calculateDiscount(List<CartItem> items) {
        for (CartItem item : items) {
            if (item.getProduct().getId().equals(productId) && item.getQuantity() >= 2) {
                return (item.getQuantity() / 2) * item.getProduct().getPrice();
            }
        }
        return 0;
    }
    @Override public String getDescription() { return "Buy One Get One Free"; }
}

// Main.java — Entry point demonstrating the optimized shopping cart
public class Main {
    public static void main(String[] args) {
        System.out.println("=== Shopping Cart Demo (Optimized - Running Total) ===");

