// service/ShoppingCart.java — Cart with running total maintained on add/remove/update
import java.util.ArrayList;
import java.util.HashMap;
import java.util.List;
import java.util.Map;

public class ShoppingCart {
    private List<CartItem> items;
    private Map<String, CartItem> itemIndex;  // HashMap = O(1) item lookup by product ID
    private double runningSubtotal;           // running total = O(1) getSubtotal() vs O(n) recalculation
    private DiscountStrategy discountStrategy;
    private Coupon appliedCoupon;
    private List<CartDecorator> addOns;
    private TaxCalculator taxCalculator;
    private String taxRegion;
    private List<PriceObserver> priceObservers;
    private boolean discountDirty;             // dirty flag = recalculate discount only when cart changes
    private double cachedDiscount;            // cached value avoids re-running discount strategy

    public ShoppingCart(String taxRegion) {
        this.items = new ArrayList<>(); this.itemIndex = new HashMap<>();
        this.addOns = new ArrayList<>(); this.taxCalculator = new TaxCalculator();
        this.taxRegion = taxRegion; this.priceObservers = new ArrayList<>();
        this.runningSubtotal = 0; this.discountDirty = true;
    }

    public void addObserver(PriceObserver observer) { priceObservers.add(observer); }

    public void addItem(Product product, int quantity) {
        CartItem existing = itemIndex.get(product.getId());
        if (existing != null) {
            // WHY: Update running total incrementally — O(1) instead of O(n)
            runningSubtotal += product.getPrice() * quantity;
            existing.incrementQuantity(quantity);
        } else {
            CartItem newItem = new CartItem(product, quantity);
            items.add(newItem);
            itemIndex.put(product.getId(), newItem);
            runningSubtotal += product.getPrice() * quantity;
        }
        discountDirty = true;
        System.out.println("Added: " + product.getName() + " x" + quantity);
    }

    public void removeItem(String productId) {
        CartItem item = itemIndex.remove(productId);
        if (item != null) {
            // WHY: Subtract from running total — O(1) instead of recalculating
            runningSubtotal -= item.getSubtotal();
            items.remove(item);
            discountDirty = true;
        }
    }

    public void updateQuantity(String productId, int newQuantity) {
        CartItem item = itemIndex.get(productId);
        if (item != null) {
            double oldSubtotal = item.getSubtotal();
            item.setQuantity(newQuantity);
            // WHY: Adjust running total by delta — O(1)
            runningSubtotal += (item.getSubtotal() - oldSubtotal);
            discountDirty = true;
        }
    }

    // WHY: O(1) — returns pre-computed running total instead of iterating all items
    public double getSubtotal() { return runningSubtotal; }

    public void applyDiscount(DiscountStrategy strategy) {
        this.discountStrategy = strategy;
        this.discountDirty = true;
        double discount = strategy.calculateDiscount(items);
        System.out.println("Applied " + strategy.getDescription() + ": -$" + String.format("%.2f", discount));
    }

    public boolean applyCoupon(Coupon coupon) {
        if (coupon.isValid(runningSubtotal)) {
            this.appliedCoupon = coupon;
            this.discountDirty = true;
            double discount = coupon.getDiscountStrategy().calculateDiscount(items);
            System.out.println("Applied coupon " + coupon.getCode() + ": -$" + String.format("%.2f", discount));
            coupon.markUsed();
            return true;
        }
        System.out.println("Coupon " + coupon.getCode() + " is not valid");
        return false;
    }

    public void addService(CartDecorator service) {
        addOns.add(service);
        System.out.println(service.getName() + " added: +$" + String.format("%.2f", service.getCost()));
    }

    public void notifyPriceChange(Product product, double oldPrice, double newPrice) {
        // WHY: Event-driven price sync — update running total on price change
        CartItem item = itemIndex.get(product.getId());
        if (item != null) {
            double priceDelta = (newPrice - oldPrice) * item.getQuantity();
            runningSubtotal += priceDelta;
            discountDirty = true;
        }
        for (PriceObserver obs : priceObservers) obs.onPriceChanged(product, oldPrice, newPrice);
    }

    public void checkout() {
        double discount = discountStrategy != null ? discountStrategy.calculateDiscount(items) : 0;
        double couponDiscount = appliedCoupon != null ? appliedCoupon.getDiscountStrategy().calculateDiscount(items) : 0;
        double taxable = runningSubtotal - discount - couponDiscount;
        double tax = taxCalculator.calculateTax(taxable, taxRegion);
        double addOnsTotal = addOns.stream().mapToDouble(CartDecorator::getCost).sum();
        double total = taxable + tax + addOnsTotal;

        System.out.println("Checkout: Subtotal=$" + String.format("%.2f", runningSubtotal) +
            " Discount=-$" + String.format("%.2f", discount + couponDiscount) +
            " Tax=$" + String.format("%.2f", tax) + " Total=$" + String.format("%.2f", total));
    }

    public List<CartItem> getItems() { return items; }
}

// service/TaxCalculator.java — Computes applicable taxes based on location
import java.util.HashMap;
import java.util.Map;

public class TaxCalculator {
    private Map<String, Double> taxRates;

    public TaxCalculator() {
        taxRates = new HashMap<>();
        taxRates.put("CA", 9.5); taxRates.put("NY", 8.875); taxRates.put("TX", 8.25);
    }

    public double calculateTax(double amount, String region) {
        double rate = taxRates.getOrDefault(region, 0.0);
        return amount * (rate / 100.0);
    }
}

// strategy/CompositeDiscount.java — Composite of DiscountStrategy children, treated uniformly
// DESIGN PATTERN: Composite (a DiscountStrategy that contains other DiscountStrategy instances)
import java.util.ArrayList;
import java.util.Arrays;
import java.util.List;
import java.util.stream.Collectors;

class CompositeDiscount implements DiscountStrategy { // composite = a strategy that aggregates child strategies
    private final List<DiscountStrategy> children;

    public CompositeDiscount(DiscountStrategy... strategies) {
        this.children = new ArrayList<>(Arrays.asList(strategies));
    }

    @Override public double calculateDiscount(List<CartItem> items) {
        double total = 0.0;                                          // accumulate child discount amounts uniformly
        for (DiscountStrategy child : children) {
            total += child.calculateDiscount(items);                 // each child treated as a leaf or composite — same call
        }
        return total;
    }

    @Override public String getDescription() {
        if (children.isEmpty()) return "Composite (empty)";
        return "Composite[" + children.stream()
                .map(DiscountStrategy::getDescription)
                .collect(Collectors.joining(" + ")) + "]";
    }
}

// strategy/DiscountStrategy.java — Defines how discounts are calculated
// DESIGN PATTERN: Strategy
import java.util.List;

public interface DiscountStrategy {           // interface = strategy pattern for discount calculations
    double calculateDiscount(List<CartItem> items);
    String getDescription();
}

class PercentageDiscount implements DiscountStrategy {
    private double percentage;
    public PercentageDiscount(double percentage) { this.percentage = percentage; }

    @Override public double calculateDiscount(List<CartItem> items) {
        double total = items.stream().mapToDouble(CartItem::getSubtotal).sum();
        return total * (percentage / 100.0);
    }
    @Override public String getDescription() { return String.format("%.0f%%", percentage); }
}

class FlatDiscount implements DiscountStrategy {
    private double amount;
    public FlatDiscount(double amount) { this.amount = amount; }

    @Override public double calculateDiscount(List<CartItem> items) {
        double total = items.stream().mapToDouble(CartItem::getSubtotal).sum();
        return Math.min(amount, total);
    }
    @Override public String getDescription() { return String.format("$%.2f off", amount); }
}

class BuyOneGetOne implements DiscountStrategy {
    private String productId;
    public BuyOneGetOne(String productId) { this.productId = productId; }

    @Override public double calculateDiscount(List<CartItem> items) {
        for (CartItem item : items) {
            if (item.getProduct().getId().equals(productId) && item.getQuantity() >= 2) {
                return (item.getQuantity() / 2) * item.getProduct().getPrice();
            }
        }
        return 0;
    }
    @Override public String getDescription() { return "Buy One Get One Free"; }
}

// concurrent/Main.java — Add-to-cart threads racing with checkout thread, verify checkout snapshot is consistent

import java.util.*;
import java.util.concurrent.*;
import java.util.concurrent.atomic.AtomicInteger;

public class Main {
    public static void main(String[] args) throws InterruptedException {
        System.out.println("=== Concurrent Shopping Cart Demo ===\n");
        System.out.println("Race condition: User adds item while checkout process is reading cart");
        System.out.println("— inconsistent total, item missed in order.\n");

        ShoppingCart cart = new ShoppingCart();
        int adderThreads = 8;
        int itemsPerThread = 50;
        AtomicInteger addSuccessCount = new AtomicInteger(0);
        AtomicInteger addRejectedCount = new AtomicInteger(0);

        CountDownLatch startLatch = new CountDownLatch(1);
        CountDownLatch doneLatch = new CountDownLatch(adderThreads + 1); // +1 for checkout thread
        List<CartItem> checkoutSnapshot = new CopyOnWriteArrayList<>();

        // Adder threads
        for (int t = 0; t < adderThreads; t++) {
            final int threadId = t;
            new Thread(() -> {
                try {
                    startLatch.await();
                    for (int i = 0; i < itemsPerThread; i++) {
                        CartItem item = new CartItem(
                            "item-" + threadId + "-" + i,
                            "Product-" + threadId + "-" + i,
                            10.0 + threadId,
                            1
                        );
                        if (cart.addItem(item)) {
                            addSuccessCount.incrementAndGet();
                        } else {
                            addRejectedCount.incrementAndGet();
                        }
                    }
                } catch (InterruptedException e) {
                    Thread.currentThread().interrupt();
                } finally {
                    doneLatch.countDown();
                }
            }).start();
        }

        // Checkout thread — starts slightly after adders to let some items accumulate
        new Thread(() -> {
            try {
                startLatch.await();
                Thread.sleep(5); // Let some adds happen first
                List<CartItem> snapshot = cart.checkout();
                checkoutSnapshot.addAll(snapshot);
            } catch (InterruptedException e) {
                Thread.currentThread().interrupt();
            } finally {
                doneLatch.countDown();
            }
        }).start();

        startLatch.countDown();
        doneLatch.await();

        // Verify snapshot consistency
        int snapshotSize = checkoutSnapshot.size();
        double snapshotTotal = 0;
        for (CartItem item : checkoutSnapshot) {
            snapshotTotal += item.getTotal();
        }

        // Recalculate total from snapshot items to verify consistency
        double recalcTotal = 0;
        for (CartItem item : checkoutSnapshot) {
            recalcTotal += item.getPrice() * item.getQuantity();
        }

        // After checkout, no more adds should succeed
        boolean postCheckoutAdd = cart.addItem(new CartItem("late", "Late Item", 5.0, 1));

        System.out.println("--- Results ---");
        System.out.println("Adder threads: " + adderThreads);
        System.out.println("Items per thread: " + itemsPerThread);
        System.out.println("Total add attempts: " + (adderThreads * itemsPerThread));
        System.out.println("Adds succeeded: " + addSuccessCount.get());
        System.out.println("Adds rejected (after checkout): " + addRejectedCount.get());
        System.out.println("Checkout snapshot size: " + snapshotSize);
        System.out.println("Snapshot total: $" + String.format("%.2f", snapshotTotal));
        System.out.println("Recalculated total: $" + String.format("%.2f", recalcTotal));
        System.out.println("Post-checkout add rejected: " + !postCheckoutAdd);

        // Consistency checks
        boolean totalsMatch = (Math.abs(snapshotTotal - recalcTotal) < 0.001);
        boolean snapshotSizeMatchesAdds = (snapshotSize <= addSuccessCount.get());
        boolean noPostCheckoutAdd = !postCheckoutAdd;
        boolean allAccountedFor = (addSuccessCount.get() + addRejectedCount.get() == adderThreads * itemsPerThread);

        System.out.println("\n--- Consistency Checks ---");
        System.out.println("Totals consistent: " + totalsMatch);
        System.out.println("Snapshot size <= successful adds: " + snapshotSizeMatchesAdds);
        System.out.println("Post-checkout blocked: " + noPostCheckoutAdd);
        System.out.println("All attempts accounted for: " + allAccountedFor);

        boolean passed = totalsMatch && snapshotSizeMatchesAdds && noPostCheckoutAdd && allAccountedFor;
        System.out.println("\nCorrectness check: " + (passed ? "PASSED" : "FAILED"));
    }
}

// concurrent/model/CartItem.java — Immutable cart item

