// concurrent/Main.java — Pay thread + cancel thread racing, verify exactly one wins

import java.util.*;
import java.util.concurrent.*;
import java.util.concurrent.atomic.AtomicInteger;

public class Main {
    public static void main(String[] args) throws InterruptedException {
        System.out.println("=== Concurrent Order Management Demo ===\n");
        System.out.println("Race condition: Payment confirmation and user cancellation arrive simultaneously");
        System.out.println("— order is both paid and cancelled.\n");

        int orderCount = 100; // Test with 100 orders for statistical confidence
        OrderService service = new OrderService();
        List<Order> orders = new ArrayList<>();
        for (int i = 0; i < orderCount; i++) {
            orders.add(new Order("ORD-" + i));
        }

        CountDownLatch startLatch = new CountDownLatch(1);
        CountDownLatch doneLatch = new CountDownLatch(orderCount * 2); // 2 threads per order

        AtomicInteger payWins = new AtomicInteger(0);
        AtomicInteger cancelWins = new AtomicInteger(0);

        for (int i = 0; i < orderCount; i++) {
            final Order order = orders.get(i);

            // Payment thread
            new Thread(() -> {
                try {
                    startLatch.await();
                    if (service.pay(order, "PaymentGateway")) {
                        payWins.incrementAndGet();
                    }
                } catch (InterruptedException e) {
                    Thread.currentThread().interrupt();
                } finally {
                    doneLatch.countDown();
                }
            }).start();

            // Cancel thread
            new Thread(() -> {
                try {
                    startLatch.await();
                    if (service.cancel(order, "UserAction")) {
                        cancelWins.incrementAndGet();
                    }
                } catch (InterruptedException e) {
                    Thread.currentThread().interrupt();
                } finally {
                    doneLatch.countDown();
                }
            }).start();
        }

        startLatch.countDown();
        doneLatch.await();

        // Verify correctness
        int bothState = 0;
        int neitherState = 0;
        int paidCount = 0;
        int cancelledCount = 0;

        for (Order order : orders) {
            OrderState state = order.getState();
            if (state == OrderState.PAID) paidCount++;
            else if (state == OrderState.CANCELLED) cancelledCount++;
            else if (state == OrderState.CREATED) neitherState++; // Should never happen
        }

        System.out.println("--- Results ---");
        System.out.println("Orders tested: " + orderCount);
        System.out.println("Payment wins: " + payWins.get());
        System.out.println("Cancel wins: " + cancelWins.get());
        System.out.println("Orders in PAID state: " + paidCount);
        System.out.println("Orders in CANCELLED state: " + cancelledCount);
        System.out.println("Orders still CREATED (bug): " + neitherState);

        // Each order must be in exactly one terminal state
        boolean eachOrderOneState = (paidCount + cancelledCount == orderCount);
        boolean winsMatchStates = (payWins.get() == paidCount && cancelWins.get() == cancelledCount);
        boolean totalWinsCorrect = (payWins.get() + cancelWins.get() == orderCount);
        boolean noContradiction = (neitherState == 0);

        System.out.println("\n--- Consistency Checks ---");
        System.out.println("Each order in exactly one state: " + eachOrderOneState);
        System.out.println("Win counts match states: " + winsMatchStates);
        System.out.println("Total winners = order count: " + totalWinsCorrect);
        System.out.println("No contradictory state: " + noContradiction);

        boolean passed = eachOrderOneState && winsMatchStates && totalWinsCorrect && noContradiction;
        System.out.println("\nCorrectness check: " + (passed ? "PASSED" : "FAILED"));
    }
}

// concurrent/model/Order.java — Order with AtomicReference state machine

import java.util.concurrent.atomic.AtomicReference;

public class Order {
    private final String orderId;                   // final = ID never changes after construction; safe publication
    private final AtomicReference<OrderState> state; // AtomicReference = lock-free CAS state transitions
    private volatile String transitionBy;           // volatile = all threads see who won the race immediately

    public Order(String orderId) {
        this.orderId = orderId;
        this.state = new AtomicReference<>(OrderState.CREATED);
    }

    /**
     * CAS transition: only succeeds if current state matches expected.
     * cancel only from CREATED, pay only from CREATED.
     */
    public boolean tryTransition(OrderState expected, OrderState next, String actor) { // CAS = only one thread wins the transition
        if (state.compareAndSet(expected, next)) { // compareAndSet = atomic; fails if another thread already changed state
            transitionBy = actor;
            return true;
        }
        return false;
    }

    public OrderState getState() { return state.get(); }
    public String getOrderId() { return orderId; }
    public String getTransitionBy() { return transitionBy; }

    @Override
    public String toString() {
        return orderId + " [" + state.get() + "] by " + transitionBy;
    }
}

// concurrent/service/OrderService.java — CAS-based order state transitions

import java.util.concurrent.atomic.AtomicInteger;

public class OrderService {
    private final AtomicInteger paySuccessCount = new AtomicInteger(0);    // AtomicInteger = thread-safe counter without locking
    private final AtomicInteger cancelSuccessCount = new AtomicInteger(0); // AtomicInteger = many threads increment safely
    private final AtomicInteger payFailCount = new AtomicInteger(0);       // AtomicInteger = tracks failed pay attempts across threads
    private final AtomicInteger cancelFailCount = new AtomicInteger(0);    // AtomicInteger = tracks failed cancel attempts across threads

    /**
     * Attempt to pay for an order. Only succeeds from CREATED state.
     */
    public boolean pay(Order order, String actor) {
        boolean success = order.tryTransition(OrderState.CREATED, OrderState.PAID, actor);
        if (success) paySuccessCount.incrementAndGet();
        else payFailCount.incrementAndGet();
        return success;
    }

    /**
     * Attempt to cancel an order. Only succeeds from CREATED state.
     */
    public boolean cancel(Order order, String actor) {
        boolean success = order.tryTransition(OrderState.CREATED, OrderState.CANCELLED, actor);
        if (success) cancelSuccessCount.incrementAndGet();
        else cancelFailCount.incrementAndGet();
        return success;
    }

    public int getPaySuccessCount() { return paySuccessCount.get(); }
    public int getCancelSuccessCount() { return cancelSuccessCount.get(); }
    public int getPayFailCount() { return payFailCount.get(); }
    public int getCancelFailCount() { return cancelFailCount.get(); }
}

