// Main.java — Entry point demonstrating the conference room booking system
import java.time.LocalDateTime;
import java.util.HashSet;
import java.util.Set;

public class Main {
    public static void main(String[] args) {
        System.out.println("=== Conference Room Booking Demo (Naive) ===");

        BookingSystem system = new BookingSystem();
        Room roomA = new Room("r1", "Room A", 4, 1, Room.Amenity.WHITEBOARD);
        Room roomB = new Room("r2", "Room B", 8, 2, Room.Amenity.PROJECTOR, Room.Amenity.WHITEBOARD);
        Room roomC = new Room("r3", "Room C", 20, 3, Room.Amenity.PROJECTOR, Room.Amenity.VIDEO_CONF);
        system.addRoom(roomA); system.addRoom(roomB); system.addRoom(roomC);

        User alice = new User("u1", "Alice", "Engineering", 2);
        User bob = new User("u2", "Bob", "Product", 1);

        LocalDateTime today = LocalDateTime.of(2026, 5, 13, 0, 0);
        TimeSlot slot1 = new TimeSlot(today.withHour(9), today.withHour(10));

        System.out.println("\n--- Book Room ---");
        Set<Room.Amenity> need = new HashSet<>(); need.add(Room.Amenity.PROJECTOR);
        Room found = system.findAvailableRoom(6, need, slot1);
        if (found != null) system.bookRoom(found, slot1, alice, MeetingType.REVIEW, "Sprint Review");

        System.out.println("\n--- Conflict ---");
        system.bookRoom(found, slot1, bob, MeetingType.REVIEW, "Another Meeting");

        System.out.println("\n--- Recurring ---");
        TimeSlot standupSlot = new TimeSlot(today.plusDays(1).withHour(9), today.plusDays(1).withHour(9).plusMinutes(15));
        // BookingComponent = Composite; same type whether single or recurring
        BookingComponent recurring = system.createRecurringBooking(roomA, standupSlot, alice,
            MeetingType.STANDUP, "Standup", RecurringBooking.Frequency.WEEKLY, 4);
        System.out.println("Series " + recurring.getId() + " has " + recurring.getTimeSlots().size() + " slot(s)");

        System.out.println("\n--- Cancel (composite cancel via series id) ---");
        // Composite cancel: cancelling the series id cancels every leaf in one call
        system.cancelBooking(recurring.getId());

        System.out.println("\n=== Conference Room Booking Demo Complete ===");
    }
}

// model/Booking.java — Represents a confirmed room reservation; leaf in the BookingComponent composite
import java.util.Collections;
import java.util.List;

public class Booking implements BookingComponent { // implements BookingComponent = leaf node treatable as a single-slot component
    private String id;                  // private = booking ID hidden from external modification
    private Room room;                  // private = room reference set at creation only
    private TimeSlot timeSlot;          // private = time range fixed once booked
    private User organizer;             // private = who created this booking
    private MeetingType meetingType;    // private = meeting type locked at booking time
    private String title;               // private = title encapsulated within this booking
    private boolean cancelled;          // private = only cancel() can flip this flag

    public Booking(String id, Room room, TimeSlot timeSlot, User organizer, MeetingType meetingType, String title) {
        this.id = id; this.room = room; this.timeSlot = timeSlot;
        this.organizer = organizer; this.meetingType = meetingType; this.title = title; this.cancelled = false;
    }

    public String getId() { return id; }
    public Room getRoom() { return room; }
    public TimeSlot getTimeSlot() { return timeSlot; }
    public User getOrganizer() { return organizer; }
    public String getTitle() { return title; }
    public boolean isCancelled() { return cancelled; }
    @Override public void cancel() { this.cancelled = true; }
    @Override public List<TimeSlot> getTimeSlots() { return Collections.singletonList(timeSlot); }

    @Override public String toString() { return room.getName() + ", " + timeSlot + " (" + title + ")"; }
}

// model/BookingComponent.java — Composite interface; treats single Booking and RecurringBooking series uniformly
import java.util.List;

public interface BookingComponent { // interface = Composite root; both leaf (Booking) and composite (RecurringBooking) implement this
    String getId();                  // unique identifier (booking id or series id)
    List<TimeSlot> getTimeSlots();   // one slot for a leaf, many slots for a series
    void cancel();                   // cancel the leaf booking, or cancel every booking in a series
}

// model/MeetingType.java — Enumerates meeting types
import java.util.Arrays;
import java.util.HashSet;
import java.util.Set;

public enum MeetingType { // enum = fixed set of meeting categories with predefined needs
    STANDUP(15, 5, new HashSet<>(Arrays.asList(Room.Amenity.WHITEBOARD))),
    REVIEW(60, 10, new HashSet<>(Arrays.asList(Room.Amenity.PROJECTOR))),
    INTERVIEW(45, 4, new HashSet<>(Arrays.asList(Room.Amenity.WHITEBOARD, Room.Amenity.VIDEO_CONF)));

    private int durationMinutes;                // private = duration per meeting type
    private int typicalAttendees;               // private = expected attendee count
    private Set<Room.Amenity> requiredAmenities; // private = amenities this meeting type needs

    MeetingType(int durationMinutes, int typicalAttendees, Set<Room.Amenity> requiredAmenities) {
        this.durationMinutes = durationMinutes; this.typicalAttendees = typicalAttendees;
        this.requiredAmenities = requiredAmenities;
    }

    public int getDurationMinutes() { return durationMinutes; }
    public Set<Room.Amenity> getRequiredAmenities() { return requiredAmenities; }
}

// model/RecurringBooking.java — Composite of Booking leaves repeating on a schedule
import java.time.LocalDateTime;
import java.util.ArrayList;
import java.util.List;

public class RecurringBooking implements BookingComponent { // implements BookingComponent = composite node aggregating leaf bookings
    public enum Frequency { DAILY, WEEKLY } // enum = fixed recurrence patterns; type-safe

    private String seriesId;            // private = unique series identifier
    private Frequency frequency;        // private = how often this booking repeats
    private int occurrences;            // private = total number of repetitions
    private List<Booking> bookings;     // private = all individual bookings in this series

    public RecurringBooking(String seriesId, Frequency frequency, int occurrences) {
        this.seriesId = seriesId; this.frequency = frequency;
        this.occurrences = occurrences; this.bookings = new ArrayList<>();
    }

    @Override public String getId() { return seriesId; }
    public List<Booking> getBookings() { return bookings; }
    public void addBooking(Booking booking) { bookings.add(booking); }

    // Composite cancel = cancel every leaf booking in the series
    @Override public void cancel() { for (Booking b : bookings) b.cancel(); }

    // Composite getTimeSlots = aggregate all leaf time slots
    @Override public List<TimeSlot> getTimeSlots() {
        List<TimeSlot> slots = new ArrayList<>();
        for (Booking b : bookings) slots.add(b.getTimeSlot());
        return slots;
    }

    public List<TimeSlot> generateTimeSlots(TimeSlot firstSlot) {
        List<TimeSlot> slots = new ArrayList<>();
        for (int i = 0; i < occurrences; i++) {
            LocalDateTime start, end;
            if (frequency == Frequency.DAILY) { start = firstSlot.getStart().plusDays(i); end = firstSlot.getEnd().plusDays(i); }
            else { start = firstSlot.getStart().plusWeeks(i); end = firstSlot.getEnd().plusWeeks(i); }
            slots.add(new TimeSlot(start, end));
        }
        return slots;
    }
}

// model/Room.java — Represents a conference room with capacity and amenities
import java.util.Arrays;
import java.util.HashSet;
import java.util.Set;

public class Room {
    public enum Amenity { PROJECTOR, WHITEBOARD, VIDEO_CONF, PHONE, TV_SCREEN } // enum = fixed amenity types

    private String id;              // private = room ID encapsulated
    private String name;            // private = display name of room
    private int capacity;           // private = max people this room holds
    private int floor;              // private = which floor this room is on
    private Set<Amenity> amenities; // private = what equipment this room has

    public Room(String id, String name, int capacity, int floor, Amenity... amenities) {
        this.id = id; this.name = name; this.capacity = capacity; this.floor = floor;
        this.amenities = new HashSet<>(Arrays.asList(amenities));
    }

    public String getId() { return id; }
    public String getName() { return name; }
    public int getCapacity() { return capacity; }
    public int getFloor() { return floor; }
    public Set<Amenity> getAmenities() { return amenities; }
    public boolean hasAllAmenities(Set<Amenity> required) { return amenities.containsAll(required); }
    public boolean fitsCapacity(int required) { return capacity >= required; }

    @Override public String toString() { return name + " (cap:" + capacity + ", " + amenities + ")"; }
