// service/BookingSystem.java — Booking system with O(log n) conflict detection per room
// DESIGN PATTERN: Facade
import java.util.ArrayList;
import java.util.List;
import java.util.Set;

public class BookingSystem {
    private List<Room> rooms;                            // private = room registry managed internally
    private List<Booking> bookings;                      // private = leaf bookings retained for conflict detection
    private List<BookingComponent> components;            // private = both leaf and recurring components for uniform lookup
    private ConflictDetector conflictDetector;            // private = O(log n) TreeMap-based conflict checker
    private RoomFinder roomFinder;                        // private = capacity-indexed room finder strategy
    private int bookingCounter;                           // private = generates unique booking IDs

    public BookingSystem() {
        this.rooms = new ArrayList<>(); this.bookings = new ArrayList<>();
        this.components = new ArrayList<>();
        this.conflictDetector = new ConflictDetector(); this.bookingCounter = 0;
    }

    public void addRoom(Room room) {
        rooms.add(room);
        conflictDetector.registerRoom(room.getId());
    }

    public List<Room> getRooms() { return rooms; }

    public void initRoomFinder() {
        // WHY: Initialize capacity-indexed finder after all rooms are added
        this.roomFinder = new SmallestFittingStrategy(rooms);
    }

    public Room findAvailableRoom(int capacity, Set<Room.Amenity> amenities, TimeSlot timeSlot) {
        return roomFinder.findRoom(rooms, capacity, amenities, timeSlot, conflictDetector);
    }

    // WHY: Returns BookingComponent so callers can treat single bookings and recurring series uniformly
    public BookingComponent bookRoom(Room room, TimeSlot timeSlot, User organizer, MeetingType type, String title) {
        // WHY: O(log n) conflict check using room-specific TreeMap
        if (conflictDetector.hasConflict(room, timeSlot)) {
            System.out.println("CONFLICT: " + room.getName() + " already booked");
            return null;
        }
        String id = "BK-" + String.format("%03d", ++bookingCounter);
        Booking booking = new Booking(id, room, timeSlot, organizer, type, title);
        bookings.add(booking); components.add(booking);
        conflictDetector.addBooking(booking);
        System.out.println("Booking confirmed: " + booking);
        return booking;
    }

    // WHY: Returns BookingComponent (the recurring series) so callers can call cancel() once to cancel all leaves
    public BookingComponent createRecurringBooking(Room room, TimeSlot firstSlot, User organizer,
            MeetingType type, String title, RecurringBooking.Frequency freq, int occurrences) {
        String seriesId = "SER-" + (bookingCounter + 1);
        RecurringBooking recurring = new RecurringBooking(seriesId, freq, occurrences);
        int booked = 0;
        for (TimeSlot slot : recurring.generateTimeSlots(firstSlot)) {
            if (!conflictDetector.hasConflict(room, slot)) {
                String id = "BK-" + String.format("%03d", ++bookingCounter);
                Booking booking = new Booking(id, room, slot, organizer, type, title);
                bookings.add(booking); conflictDetector.addBooking(booking);
                recurring.addBooking(booking); booked++;
            }
        }
        components.add(recurring);
        System.out.println("Recurring: " + booked + "/" + occurrences + " booked in " + room.getName());
        return recurring;
    }

    // WHY: Composite cancel — id may be a leaf booking id (BK-*) or a series id (SER-*); both handled the same way
    public boolean cancelBooking(String id) {
        for (BookingComponent c : components) {
            if (c.getId().equals(id)) {
                c.cancel();
                // Sync the conflict detector with whichever leaves were just cancelled
                if (c instanceof Booking) {
                    conflictDetector.removeBooking((Booking) c);
                } else if (c instanceof RecurringBooking) {
                    for (Booking leaf : ((RecurringBooking) c).getBookings()) conflictDetector.removeBooking(leaf);
                }
                System.out.println("Cancelled: " + id);
                return true;
            }
        }
        return false;
    }
}

// service/ConflictDetector.java — O(log n) conflict detection using TreeMap per room
import java.time.LocalDateTime;
import java.util.HashMap;
import java.util.Map;
import java.util.TreeMap;

public class ConflictDetector {
    // TreeMap<startTime, Booking> per room gives O(log n) conflict check
    // instead of scanning all bookings across all rooms
    private Map<String, TreeMap<LocalDateTime, Booking>> roomSchedules; // HashMap<roomId, TreeMap> = O(1) room lookup + O(log n) time search

    public ConflictDetector() {
        this.roomSchedules = new HashMap<>();
    }

    public void registerRoom(String roomId) {
        roomSchedules.putIfAbsent(roomId, new TreeMap<>());
    }

    // WHY: O(log n) — check floor/ceiling entries in the room's TreeMap
    public boolean hasConflict(Room room, TimeSlot timeSlot) {
        TreeMap<LocalDateTime, Booking> schedule = roomSchedules.get(room.getId());
        if (schedule == null || schedule.isEmpty()) return false;

        // Check the booking starting just before our start time
        Map.Entry<LocalDateTime, Booking> floor = schedule.floorEntry(timeSlot.getStart());
        if (floor != null && !floor.getValue().isCancelled() &&
            floor.getValue().getTimeSlot().overlapsWith(timeSlot)) {
            return true;
        }

        // Check the booking starting at or just after our start time
        Map.Entry<LocalDateTime, Booking> ceiling = schedule.ceilingEntry(timeSlot.getStart());
        if (ceiling != null && !ceiling.getValue().isCancelled() &&
            ceiling.getValue().getTimeSlot().overlapsWith(timeSlot)) {
            return true;
        }

        return false;
    }

    public void addBooking(Booking booking) {
        roomSchedules.computeIfAbsent(booking.getRoom().getId(), k -> new TreeMap<>())
            .put(booking.getTimeSlot().getStart(), booking);
    }

    public void removeBooking(Booking booking) {
        TreeMap<LocalDateTime, Booking> schedule = roomSchedules.get(booking.getRoom().getId());
        if (schedule != null) {
            schedule.remove(booking.getTimeSlot().getStart());
        }
    }
}

// strategy/RoomFinder.java — Finds rooms with capacity index for fast filtering
import java.util.List;
import java.util.Set;
import java.util.TreeMap;
import java.util.ArrayList;
import java.util.Map;

public interface RoomFinder { // interface = contract for room-finding strategies
    Room findRoom(List<Room> rooms, int requiredCapacity, Set<Room.Amenity> requiredAmenities,
                  TimeSlot timeSlot, ConflictDetector conflictDetector);
}

class SmallestFittingStrategy implements RoomFinder { // implements = finds smallest fitting room
    // TreeMap<capacity, List<Room>> indexes rooms by capacity
    // so we only check rooms >= required capacity via tailMap — O(log n) to find starting point
    private TreeMap<Integer, List<Room>> capacityIndex; // TreeMap = sorted by capacity; tailMap skips too-small rooms

    public SmallestFittingStrategy(List<Room> allRooms) {
        this.capacityIndex = new TreeMap<>();
        for (Room room : allRooms) {
            capacityIndex.computeIfAbsent(room.getCapacity(), k -> new ArrayList<>()).add(room);
        }
    }

    @Override
    public Room findRoom(List<Room> rooms, int requiredCapacity, Set<Room.Amenity> requiredAmenities,
                         TimeSlot timeSlot, ConflictDetector conflictDetector) {
        // WHY: tailMap gives only rooms with capacity >= required, smallest first
        for (Map.Entry<Integer, List<Room>> entry : capacityIndex.tailMap(requiredCapacity).entrySet()) {
            for (Room room : entry.getValue()) {
                if (room.hasAllAmenities(requiredAmenities) && !conflictDetector.hasConflict(room, timeSlot)) {
                    return room;
                }
            }
        }
        return null;
    }
}

// concurrent/Main.java — 20 bookings for same room/time, exactly 1 succeeds

import java.util.*;
import java.util.concurrent.*;
import java.util.concurrent.atomic.AtomicInteger;

public class Main {
    public static void main(String[] args) throws InterruptedException {
        System.out.println("=== Concurrent Conference Room Booking Demo ===\n");
        System.out.println("Race condition: Two meetings booked in same room at overlapping times.\n");

        List<String> rooms = List.of("Room-A", "Room-B");
        RoomBookingService service = new RoomBookingService(rooms);

        int threadCount = 20;
        long slotStart = 900; // 9:00 AM
        long slotEnd = 1000;  // 10:00 AM

        // Test 1: 20 threads booking exact same slot in Room-A
        System.out.println("--- Test 1: 20 threads, same room, same time ---");
        CountDownLatch startLatch = new CountDownLatch(1);
        CountDownLatch doneLatch = new CountDownLatch(threadCount);
        AtomicInteger wins = new AtomicInteger(0);

        for (int i = 0; i < threadCount; i++) {
            final int id = i;
            new Thread(() -> {
                try {
                    startLatch.await();
                    TimeSlot slot = new TimeSlot(slotStart, slotEnd);
                    Booking booking = new Booking("BK-" + id, "User-" + id, slot, "Room-A");
                    if (service.bookRoom("Room-A", booking)) {
                        wins.incrementAndGet();
                        System.out.println("  User-" + id + " BOOKED Room-A " + slot);
                    }
                } catch (InterruptedException e) {
                    Thread.currentThread().interrupt();
                } finally {
                    doneLatch.countDown();
                }
            }).start();
        }

        startLatch.countDown();
        doneLatch.await();

        // Test 2: Non-overlapping bookings should all succeed
        System.out.println("\n--- Test 2: Non-overlapping bookings ---");
        int nonOverlapCount = 5;
        int nonOverlapSuccess = 0;
        for (int i = 0; i < nonOverlapCount; i++) {
            long start = 1100 + (i * 200);
            long end = start + 100;
            TimeSlot slot = new TimeSlot(start, end);
            Booking booking = new Booking("NOL-" + i, "UserB-" + i, slot, "Room-B");
            if (service.bookRoom("Room-B", booking)) {
                nonOverlapSuccess++;
            }
        }

        System.out.println("  Non-overlapping bookings succeeded: " + nonOverlapSuccess + "/" + nonOverlapCount);

        // Results
        System.out.println("\n--- Results ---");
        System.out.println("Threads competing for same slot: " + threadCount);
        System.out.println("Winners (same slot): " + wins.get());
        System.out.println("Total successful bookings: " + service.getSuccessCount());
        System.out.println("Total rejections: " + service.getRejectCount());
        System.out.println("Room-A bookings: " + service.getBookingCount("Room-A"));
        System.out.println("Room-B bookings: " + service.getBookingCount("Room-B"));

        boolean exactlyOneWins = (wins.get() == 1);
        boolean allNonOverlap = (nonOverlapSuccess == nonOverlapCount);
        boolean rejectsCorrect = (service.getRejectCount() == threadCount - 1);

        System.out.println("\nExactly one winner: " + exactlyOneWins);
        System.out.println("All non-overlapping accepted: " + allNonOverlap);
        System.out.println("Rejections = " + (threadCount - 1) + ": " + rejectsCorrect);

        boolean passed = exactlyOneWins && allNonOverlap && rejectsCorrect;
        System.out.println("\nCorrectness check: " + (passed ? "PASSED" : "FAILED"));
    }
}

// concurrent/model/Booking.java — Booking record for a conference room

public class Booking {
    private final String bookingId;  // final = booking ID never changes; safe to share across threads
    private final String bookedBy;   // final = who booked; immutable for safe publication
    private final TimeSlot timeSlot; // final = time range fixed; threads see consistent value
    private final String roomId;     // final = room assignment immutable once created

    public Booking(String bookingId, String bookedBy, TimeSlot timeSlot, String roomId) {
        this.bookingId = bookingId;
        this.bookedBy = bookedBy;
        this.timeSlot = timeSlot;
        this.roomId = roomId;
    }

    public String getBookingId() { return bookingId; }
    public String getBookedBy() { return bookedBy; }
    public TimeSlot getTimeSlot() { return timeSlot; }
    public String getRoomId() { return roomId; }

    @Override
    public String toString() {
        return bookingId + " by " + bookedBy + " " + timeSlot;
    }
}

// concurrent/model/TimeSlot.java — Time slot with start/end, implements Comparable for ConcurrentSkipListMap

public class TimeSlot implements Comparable<TimeSlot> { // Comparable = required for ConcurrentSkipListMap ordering
    private final long startTime; // final = immutable; safe to read from any thread without sync
    private final long endTime;   // final = immutable; no race conditions on time boundaries

    public TimeSlot(long startTime, long endTime) {
        this.startTime = startTime;
        this.endTime = endTime;
    }

    public long getStartTime() { return startTime; }
    public long getEndTime() { return endTime; }

    public boolean overlaps(TimeSlot other) {
        return this.startTime < other.endTime && other.startTime < this.endTime;
    }

    @Override
    public int compareTo(TimeSlot other) {
        int cmp = Long.compare(this.startTime, other.startTime);
        if (cmp != 0) return cmp;
        return Long.compare(this.endTime, other.endTime);
    }

    @Override
    public boolean equals(Object o) {
        if (this == o) return true;
        if (!(o instanceof TimeSlot)) return false;
        TimeSlot ts = (TimeSlot) o;
        return startTime == ts.startTime && endTime == ts.endTime;
    }

    @Override
    public int hashCode() {
        return Long.hashCode(startTime) * 31 + Long.hashCode(endTime);
    }

    @Override
    public String toString() {
        return "[" + startTime + "-" + endTime + "]";
    }
}

// concurrent/service/RoomBookingService.java — ConcurrentSkipListMap + ReentrantLock per room for atomic conflict check

import java.util.*;
import java.util.concurrent.ConcurrentSkipListMap;
import java.util.concurrent.locks.ReentrantLock;
import java.util.concurrent.atomic.AtomicInteger;

public class RoomBookingService {
    private final Map<String, ConcurrentSkipListMap<TimeSlot, Booking>> roomBookings; // ConcurrentSkipListMap = sorted, lock-free reads for time-based lookups
    private final Map<String, ReentrantLock> roomLocks;  // ReentrantLock = per-room lock; atomic conflict-check-then-book
    private final AtomicInteger successCount;            // AtomicInteger = thread-safe booking counter
    private final AtomicInteger rejectCount;             // AtomicInteger = thread-safe rejection counter

    public RoomBookingService(List<String> roomIds) {
        this.roomBookings = new HashMap<>();
        this.roomLocks = new HashMap<>();
        this.successCount = new AtomicInteger(0);
        this.rejectCount = new AtomicInteger(0);

        for (String roomId : roomIds) {
            roomBookings.put(roomId, new ConcurrentSkipListMap<>());
            roomLocks.put(roomId, new ReentrantLock());
        }
    }

    /**
     * Book a room. Uses per-room ReentrantLock for atomic conflict-check-then-book.
     */
    public boolean bookRoom(String roomId, Booking booking) {
        ReentrantLock lock = roomLocks.get(roomId);
        if (lock == null) return false;

        lock.lock();
        try {
            ConcurrentSkipListMap<TimeSlot, Booking> bookings = roomBookings.get(roomId);
            TimeSlot requested = booking.getTimeSlot();

            // Check for conflicts — look at nearby time slots
            TimeSlot searchStart = new TimeSlot(requested.getStartTime() - 1, requested.getStartTime());
            TimeSlot searchEnd = new TimeSlot(requested.getEndTime(), requested.getEndTime() + 1);

            // Check all bookings that could potentially overlap
            for (Map.Entry<TimeSlot, Booking> entry : bookings.entrySet()) {
                if (entry.getKey().overlaps(requested)) {
                    rejectCount.incrementAndGet();
                    return false;
                }
            }

            bookings.put(requested, booking);
            successCount.incrementAndGet();
            return true;
        } finally {
            lock.unlock();
        }
    }

    public int getSuccessCount() { return successCount.get(); }
    public int getRejectCount() { return rejectCount.get(); }

    public int getBookingCount(String roomId) {
        ConcurrentSkipListMap<TimeSlot, Booking> bookings = roomBookings.get(roomId);
        return bookings != null ? bookings.size() : 0;
    }
}

