// model/Crust.java — Enumerates crust types
public enum Crust { // enum = fixed set of crust types with associated costs
    THIN(0.00, "Thin"), REGULAR(0.00, "Regular"), THICK(1.50, "Thick"), STUFFED(3.00, "Stuffed");
    private double extraCost; private String displayName; // private = cost/name per crust type
    Crust(double extraCost, String displayName) { this.extraCost = extraCost; this.displayName = displayName; }
    public double getExtraCost() { return extraCost; }
    public String getDisplayName() { return displayName; }
}

// model/Order.java — Represents a customer's pizza order
import java.util.ArrayList;
import java.util.List;

public class Order {
    public enum OrderStatus { PLACED, PREPARING, BAKING, READY, OUT_FOR_DELIVERY, DELIVERED } // enum = fixed order lifecycle stages

    private String id;              // private = order ID encapsulated
    private List<OrderLine> lines;  // private = pizza lines managed via addPizza()
    private OrderStatus status;     // private = status changes via advanceStatus() only

    public Order(String id) { this.id = id; this.lines = new ArrayList<>(); this.status = OrderStatus.PLACED; }

    public String getId() { return id; }
    public OrderStatus getStatus() { return status; }
    public List<OrderLine> getLines() { return lines; }

    public void addPizza(Pizza pizza, List<PizzaDecorator> extras) { lines.add(new OrderLine(pizza, extras)); }

    public double getTotal() { return lines.stream().mapToDouble(OrderLine::getPrice).sum(); }

    public void advanceStatus() {
        switch (status) {
            case PLACED: status = OrderStatus.PREPARING; break;
            case PREPARING: status = OrderStatus.BAKING; break;
            case BAKING: status = OrderStatus.READY; break;
            case READY: status = OrderStatus.OUT_FOR_DELIVERY; break;
            case OUT_FOR_DELIVERY: status = OrderStatus.DELIVERED; break;
            default: return;
        }
        System.out.println("  Order " + id + " status: " + status);
    }

    public static class OrderLine { // static = no reference to enclosing Order; standalone line item
        private Pizza pizza;               // private = which pizza was ordered
        private List<PizzaDecorator> extras; // private = add-ons for this pizza
        public OrderLine(Pizza pizza, List<PizzaDecorator> extras) { this.pizza = pizza; this.extras = extras; }
        public double getPrice() {
            double price = pizza.getBasePrice();
            for (PizzaDecorator extra : extras) price += extra.getCost();
            return price;
        }
    }
}

// model/Pizza.java — Represents a configured pizza
import java.util.ArrayList;
import java.util.List;

public class Pizza {
    private Size size;              // private = pizza size set once at creation
    private Crust crust;            // private = crust type set once at creation
    private List<Topping> toppings; // private = toppings list encapsulated

    public Pizza(Size size, Crust crust, List<Topping> toppings) {
        this.size = size; this.crust = crust; this.toppings = new ArrayList<>(toppings);
    }

    public Size getSize() { return size; }
    public Crust getCrust() { return crust; }
    public List<Topping> getToppings() { return toppings; }

    // Fixed price calculation with sequential additions
    public double getBasePrice() {
        double price = size.getBasePrice() + crust.getExtraCost();
        for (Topping t : toppings) price += t.getPrice();
        return price;
    }

    public String getName() { return size.getDisplayName() + " " + crust.getDisplayName(); }
    @Override public String toString() { return getName(); }
}

// model/Size.java — Enumerates pizza sizes
public enum Size { // enum = fixed pizza sizes with base prices; type-safe
    SMALL(8.99, "Small"), MEDIUM(11.99, "Medium"), LARGE(14.99, "Large"), EXTRA_LARGE(17.99, "Extra Large");
    private double basePrice; private String displayName; // private = price/name per size
    Size(double basePrice, String displayName) { this.basePrice = basePrice; this.displayName = displayName; }
    public double getBasePrice() { return basePrice; }
    public String getDisplayName() { return displayName; }
    @Override public String toString() { return displayName; }
}

// model/Topping.java — Enumerates available pizza toppings
public enum Topping { // enum = fixed set of toppings with prices; type-safe
    MOZZARELLA(1.00), PEPPERONI(1.50), MUSHROOMS(1.00), OLIVES(0.75),
    ONIONS(0.75), PEPPERS(0.75), SAUSAGE(1.50), BBQ_CHICKEN(2.00), BACON(1.75);
    private double price; // private = topping price encapsulated per constant
    Topping(double price) { this.price = price; }
    public double getPrice() { return price; }
}

// service/PizzaBuilder.java — Fluent builder for constructing custom pizzas
import java.util.ArrayList;
import java.util.List;

public class PizzaBuilder { // Builder pattern: constructs a Pizza step-by-step
    private Size size = Size.MEDIUM;            // private = default size; overridden by size()
    private Crust crust = Crust.REGULAR;        // private = default crust; overridden by crust()
    private List<Topping> toppings = new ArrayList<>(); // private = accumulated toppings

    public PizzaBuilder size(Size size) { this.size = size; return this; }
    public PizzaBuilder crust(Crust crust) { this.crust = crust; return this; }
    public PizzaBuilder addTopping(Topping t) { toppings.add(t); return this; }
    public PizzaBuilder addToppings(Topping... ts) { for (Topping t : ts) toppings.add(t); return this; }
    public Pizza build() { return new Pizza(size, crust, toppings); }
}

// service/PizzaDecorator.java — Adds extras to a pizza
public abstract class PizzaDecorator { // abstract = can't instantiate directly; subclasses provide specifics
    protected String name;  // protected = subclasses (ExtraCheese etc.) can access directly
    protected double cost;  // protected = subclasses set cost via super() constructor
    public PizzaDecorator(String name, double cost) { this.name = name; this.cost = cost; }
    public String getName() { return name; }
    public double getCost() { return cost; }
    @Override public String toString() { return "+ " + name + ": $" + String.format("%.2f", cost); }
}

class ExtraCheese extends PizzaDecorator { public ExtraCheese() { super("Extra Cheese", 2.50); } } // extends = inherits from PizzaDecorator
class ExtraSauce extends PizzaDecorator { public ExtraSauce() { super("Extra Sauce", 1.50); } } // extends = another concrete decorator add-on

// service/PizzaShop.java — Manages pizza ordering and delivery
import java.util.ArrayList;
import java.util.List;

public class PizzaShop {
    private List<Order> orders;    // private = order list managed internally
    private int orderCounter;      // private = generates unique order IDs

    public PizzaShop() { this.orders = new ArrayList<>(); this.orderCounter = 0; }

    public Order createOrder() {
        String id = "ORD-" + String.format("%03d", ++orderCounter);
        Order order = new Order(id);
        orders.add(order);
        return order;
    }

    public void processOrder(Order order) {
        while (order.getStatus() != Order.OrderStatus.DELIVERED) order.advanceStatus();
    }
}

// Main.java — Entry point demonstrating the optimized pizza delivery
import java.util.ArrayList;
import java.util.List;
import java.util.Set;

public class Main {
    public static void main(String[] args) {
        System.out.println("=== Pizza Delivery Demo (Optimized - Decorator + ConcurrentHashMap + Topping Interning) ===");

        PizzaShop shop = new PizzaShop();

        System.out.println("\n--- Build Pizza (validated builder) ---");
        Pizza pizza1 = new PizzaBuilder().size(Size.LARGE).crust(Crust.THIN)
            .addToppings(Topping.MOZZARELLA, Topping.PEPPERONI, Topping.MUSHROOMS).build();
        List<PizzaDecorator> extras1 = new ArrayList<>();
        extras1.add(new ExtraCheese());
        extras1.add(new ExtraSauce());
        double total = pizza1.getBasePrice();
        for (PizzaDecorator d : extras1) total += d.getCost();
        System.out.println(pizza1.getName() + " total: $" + String.format("%.2f", total));

        System.out.println("\n--- Topping Interning (memory optimization) ---");
        // Build two more pizzas with the SAME topping selection — different size/crust, same toppings.
        // The interned topping-Set should be reference-equal across all three pizzas.
        Pizza pizza2 = new PizzaBuilder().size(Size.MEDIUM).crust(Crust.REGULAR)
            .addToppings(Topping.MOZZARELLA, Topping.PEPPERONI, Topping.MUSHROOMS).build();
        // Build with toppings in a different order — interning normalizes via EnumSet, so still shared.
        Pizza pizza3 = new PizzaBuilder().size(Size.SMALL).crust(Crust.STUFFED)
            .addToppings(Topping.MUSHROOMS, Topping.PEPPERONI, Topping.MOZZARELLA).build();
        Set<Topping> t1 = pizza1.getToppings();
        Set<Topping> t2 = pizza2.getToppings();
        Set<Topping> t3 = pizza3.getToppings();
        System.out.println("pizza1 toppings identityHashCode: " + System.identityHashCode(t1));
        System.out.println("pizza2 toppings identityHashCode: " + System.identityHashCode(t2));
        System.out.println("pizza3 toppings identityHashCode: " + System.identityHashCode(t3));
        System.out.println("pizza1.toppings == pizza2.toppings ? " + (t1 == t2));
        System.out.println("pizza2.toppings == pizza3.toppings ? " + (t2 == t3));
        // Build one with a DIFFERENT topping set — should NOT share with the above.
        Pizza pizza4 = new PizzaBuilder().addToppings(Topping.BBQ_CHICKEN, Topping.BACON).build();
        System.out.println("pizza1.toppings == pizza4.toppings ? " + (t1 == pizza4.getToppings())
            + " (different toppings, different interned set)");
        System.out.println("Distinct interned topping-sets cached: " + PizzaBuilder.internedSetCount());

        System.out.println("\n--- Create Order (running total) ---");
        Order order = shop.createOrder();
        order.addPizza(pizza1, extras1);
        System.out.println("Order total (O(1)): $" + String.format("%.2f", order.getTotal()));

        System.out.println("\n--- Process Order (concurrent tracking) ---");
        shop.processOrder(order);
        System.out.println("Order complete, removed from active tracking");

        System.out.println("\n=== Pizza Delivery Demo Complete ===");
    }
}

// model/Crust.java — Enumerates crust types
public enum Crust { // enum = fixed set of crust types with associated costs
    THIN(0.00, "Thin"), REGULAR(0.00, "Regular"), THICK(1.50, "Thick"), STUFFED(3.00, "Stuffed");
    private double extraCost; private String displayName; // private = cost/name per crust type
    Crust(double extraCost, String displayName) { this.extraCost = extraCost; this.displayName = displayName; }
