// service/PizzaShop.java — Shop with concurrent order tracking
import java.util.concurrent.ConcurrentHashMap;

public class PizzaShop {
    // ConcurrentHashMap for thread-safe concurrent order tracking
    private ConcurrentHashMap<String, Order> activeOrders; // ConcurrentHashMap = O(1) thread-safe order lookup
    private int orderCounter;                              // sequential counter for unique order IDs

    public PizzaShop() { this.activeOrders = new ConcurrentHashMap<>(); this.orderCounter = 0; }

    public Order createOrder() {
        String id = "ORD-" + String.format("%03d", ++orderCounter);
        Order order = new Order(id);
        activeOrders.put(id, order);
        return order;
    }

    // WHY: O(1) order lookup by ID for status checks
    public Order getOrder(String orderId) { return activeOrders.get(orderId); }

    public void processOrder(Order order) {
        while (order.getStatus() != Order.OrderStatus.DELIVERED) order.advanceStatus();
        // WHY: Remove from active orders when delivered to free memory
        activeOrders.remove(order.getId());
    }
}

// concurrent/Main.java — 10 orders progressing through stages concurrently, verify each order's lifecycle is independent

import java.util.*;
import java.util.concurrent.*;
import java.util.concurrent.atomic.AtomicInteger;

public class Main {
    public static void main(String[] args) throws InterruptedException {
        System.out.println("=== Concurrent Pizza Delivery Demo ===\n");
        System.out.println("Race condition: Multiple orders from same address processed simultaneously");
        System.out.println("— delivery tracking gets mixed up.\n");

        DeliveryTracker tracker = new DeliveryTracker();
        int orderCount = 10;
        String sharedAddress = "123 Main St";

        // Create orders from same address
        for (int i = 0; i < orderCount; i++) {
            tracker.addOrder(new PizzaOrder("PIZZA-" + i, sharedAddress));
        }

        // Each order gets its own progression thread
        CountDownLatch startLatch = new CountDownLatch(1);
        CountDownLatch doneLatch = new CountDownLatch(orderCount);
        AtomicInteger progressSuccess = new AtomicInteger(0);

        for (int i = 0; i < orderCount; i++) {
            final String orderId = "PIZZA-" + i;
            new Thread(() -> {
                try {
                    startLatch.await();
                    if (tracker.progressOrder(orderId)) {
                        progressSuccess.incrementAndGet();
                    }
                } catch (InterruptedException e) {
                    Thread.currentThread().interrupt();
                } finally {
                    doneLatch.countDown();
                }
            }).start();
        }

        // Also spawn duplicate progression threads to simulate race
        CountDownLatch doneLatch2 = new CountDownLatch(orderCount);
        AtomicInteger duplicateFails = new AtomicInteger(0);

        for (int i = 0; i < orderCount; i++) {
            final String orderId = "PIZZA-" + i;
            new Thread(() -> {
                try {
                    startLatch.await();
                    if (!tracker.progressOrder(orderId)) {
                        duplicateFails.incrementAndGet();
                    }
                } catch (InterruptedException e) {
                    Thread.currentThread().interrupt();
                } finally {
                    doneLatch2.countDown();
                }
            }).start();
        }

        startLatch.countDown();
        doneLatch.await();
        doneLatch2.await();

        // Verify
        System.out.println("--- Results ---");
        System.out.println("Orders from same address: " + orderCount);
        System.out.println("Successful full progressions: " + progressSuccess.get());
        System.out.println("Duplicate progressions blocked: " + duplicateFails.get());
        System.out.println("Total completed: " + tracker.getCompletedCount());

        // Check each order independently
        boolean allIndependent = true;
        boolean allValidHistory = true;
        DeliveryState[] expectedProgression = DeliveryState.values();

        for (PizzaOrder order : tracker.getAllOrders()) {
            List<String> history = order.getStateHistory();

            // Verify ordering is valid (each state appears in correct sequence)
            int lastIdx = -1;
            for (String stateStr : history) {
                DeliveryState s = DeliveryState.valueOf(stateStr);
                int idx = s.ordinal();
                if (idx <= lastIdx) {
                    allValidHistory = false;
                    break;
                }
                lastIdx = idx;
            }

            // Verify final state is DELIVERED
            if (!order.isDelivered()) {
                // Only the winner thread delivers, duplicate might fail partway
            }
        }

        // Exactly one progression per order should fully succeed
        // (either the primary or duplicate thread, but not both)
        boolean completedMatchesOrders = (tracker.getCompletedCount() == orderCount);
        boolean noMixup = (progressSuccess.get() + duplicateFails.get() >= orderCount);

        System.out.println("\nAll orders delivered: " + completedMatchesOrders);
        System.out.println("Valid state histories: " + allValidHistory);
        System.out.println("No tracking mixup (primary+dup >= orders): " + noMixup);

        // Print sample order histories
        System.out.println("\nSample histories:");
        int shown = 0;
        for (PizzaOrder order : tracker.getAllOrders()) {
            if (shown++ >= 3) break;
            System.out.println("  " + order.getOrderId() + ": " + order.getStateHistory());
        }

        boolean passed = completedMatchesOrders && allValidHistory && noMixup;
        System.out.println("\nCorrectness check: " + (passed ? "PASSED" : "FAILED"));
    }
}

// concurrent/model/PizzaOrder.java — Pizza order with AtomicReference lifecycle

import java.util.concurrent.atomic.AtomicReference;
import java.util.List;
import java.util.ArrayList;
import java.util.Collections;

public class PizzaOrder {
    private final String orderId;                       // final = immutable ID; safe publication to threads
    private final String address;                       // final = delivery address never changes
    private final AtomicReference<DeliveryState> state; // AtomicReference = CAS-based state transitions
    private final List<String> stateHistory;            // synchronizedList = thread-safe append of state log

    public PizzaOrder(String orderId, String address) {
        this.orderId = orderId;
        this.address = address;
        this.state = new AtomicReference<>(DeliveryState.PLACED);
        this.stateHistory = Collections.synchronizedList(new ArrayList<>());
        this.stateHistory.add(DeliveryState.PLACED.name());
    }

    /**
     * Advance state to the next expected state. CAS ensures only valid transitions.
     */
    public boolean advanceTo(DeliveryState expected, DeliveryState next) { // CAS = only valid sequential transitions succeed
        if (state.compareAndSet(expected, next)) { // compareAndSet = atomic; fails if another thread already advanced
            stateHistory.add(next.name());
            return true;
        }
        return false;
    }

    public DeliveryState getState() { return state.get(); }
    public String getOrderId() { return orderId; }
    public String getAddress() { return address; }
    public List<String> getStateHistory() { return new ArrayList<>(stateHistory); }

    public boolean isDelivered() { return state.get() == DeliveryState.DELIVERED; }

    @Override
    public String toString() {
        return orderId + " @ " + address + " [" + state.get() + "]";
    }
}

// concurrent/service/DeliveryTracker.java — ConcurrentHashMap for thread-safe tracking

import java.util.*;
import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.atomic.AtomicInteger;

public class DeliveryTracker {
    private final ConcurrentHashMap<String, PizzaOrder> orders; // ConcurrentHashMap = thread-safe order registry; O(1) lookup
    private final AtomicInteger completedCount;                 // AtomicInteger = thread-safe delivered counter

    public DeliveryTracker() {
        this.orders = new ConcurrentHashMap<>();
        this.completedCount = new AtomicInteger(0);
    }

    public void addOrder(PizzaOrder order) {
        orders.put(order.getOrderId(), order);
    }

    public PizzaOrder getOrder(String orderId) {
        return orders.get(orderId);
    }

    /**
     * Progress an order through its full lifecycle.
     * Each transition uses CAS to ensure ordered progression.
     */
    public boolean progressOrder(String orderId) {
        PizzaOrder order = orders.get(orderId);
        if (order == null) return false;

        // Walk through state machine: PLACED -> PREPARING -> BAKING -> READY -> OUT_FOR_DELIVERY -> DELIVERED
        DeliveryState[] progression = DeliveryState.values();
        for (int i = 0; i < progression.length - 1; i++) {
            boolean advanced = order.advanceTo(progression[i], progression[i + 1]);
            if (!advanced) {
                return false; // Someone else already advanced this state
            }
            // Simulate work at each stage
            try { Thread.sleep(1); } catch (InterruptedException e) {
                Thread.currentThread().interrupt();
                return false;
            }
        }

        if (order.isDelivered()) {
            completedCount.incrementAndGet();
        }
        return order.isDelivered();
    }

    public int getCompletedCount() { return completedCount.get(); }
    public int getTotalOrders() { return orders.size(); }

    public Collection<PizzaOrder> getAllOrders() {
        return orders.values();
    }
}

