import java.time.LocalDateTime;

public class Alert {
    public enum AlertType { GEOFENCE_ENTER, GEOFENCE_EXIT, SPEEDING } // enum = fixed alert categories; type-safe

    private String id;                  // private = alert ID encapsulated
