// service/TrackingService.java — Tracking with spatial grid and circular buffer
import java.util.ArrayList;
import java.util.HashMap;
import java.util.List;
import java.util.Map;

public class TrackingService {
    private Map<String, Vehicle> vehicles;                          // HashMap = O(1) vehicle lookup by ID
    private List<GeoFence> geoFences;                               // all registered geofences
    private List<Alert> alerts;                                     // all generated alerts
    private SpeedMonitor speedMonitor;                              // speed limit checker
    // Spatial grid for O(1) average geofence candidate lookup
    private SpatialGrid spatialGrid;                                // SpatialGrid = O(1) geofence lookup by cell
    private Map<String, Map<String, Boolean>> vehicleGeoFenceState; // tracks enter/exit per vehicle per fence
    private int alertCounter;                                       // generates unique alert IDs

    // Observer: fan-out for alerts (speeding, geofence enter/exit).
    private final List<AlertListener> alertListeners = new ArrayList<>();

    public TrackingService(double defaultSpeedLimit) {
        this.vehicles = new HashMap<>(); this.geoFences = new ArrayList<>();
        this.alerts = new ArrayList<>(); this.speedMonitor = new SpeedMonitor(defaultSpeedLimit);
        this.spatialGrid = new SpatialGrid(1000); // 1km cells
        this.vehicleGeoFenceState = new HashMap<>(); this.alertCounter = 0;
    }

    // === Observer plumbing ===
    public void addListener(AlertListener listener) { alertListeners.add(listener); }
    public void removeListener(AlertListener listener) { alertListeners.remove(listener); }

    public Vehicle registerVehicle(String id, String name, String type) {
        Vehicle vehicle = new Vehicle(id, name, type);
        vehicles.put(id, vehicle); vehicleGeoFenceState.put(id, new HashMap<>());
        return vehicle;
    }

    public void addGeoFence(String id, String name, Location center, double radiusMeters) {
        GeoFence fence = new GeoFence(id, name, center, radiusMeters);
        geoFences.add(fence);
        spatialGrid.addFence(fence);
        System.out.println("Geofence created: " + name);
    }

    public void updateLocation(String vehicleId, Location location, double timeDeltaSeconds) {
        Vehicle vehicle = vehicles.get(vehicleId);
        if (vehicle == null) return;
        Location previous = vehicle.getCurrentLocation();

        // WHY: Distance-based dedup rejects noise; returns false if too close
        boolean stored = vehicle.updateLocation(location);

        if (previous != null && timeDeltaSeconds > 0) {
            double speed = speedMonitor.calculateSpeed(previous, location, timeDeltaSeconds);
            vehicle.setCurrentSpeedKmh(speed);
            if (speed < 1) vehicle.setState(VehicleState.IDLE);
            else vehicle.setState(VehicleState.MOVING);
            if (speedMonitor.isExceedingLimit(speed)) {
                createAlert(vehicleId, Alert.AlertType.SPEEDING, vehicle.getName() + " speeding: " + String.format("%.0f", speed) + " km/h");
            }
        }

        // WHY: O(1) geofence check via spatial grid instead of O(n) scan
        checkGeoFences(vehicleId, location);
    }

    private void checkGeoFences(String vehicleId, Location location) {
        Vehicle vehicle = vehicles.get(vehicleId);
        Map<String, Boolean> fenceState = vehicleGeoFenceState.get(vehicleId);

        // WHY: Only check fences in the same spatial grid cell — typically O(1)
        List<GeoFence> candidates = spatialGrid.getCandidateFences(location);
        for (GeoFence fence : candidates) {
            boolean isInside = fence.contains(location);
            Boolean wasInside = fenceState.get(fence.getId());
            if (wasInside == null) { fenceState.put(fence.getId(), isInside); }
            else if (!wasInside && isInside) {
                fenceState.put(fence.getId(), true);
                createAlert(vehicleId, Alert.AlertType.GEOFENCE_ENTER, vehicle.getName() + " entered " + fence.getName());
            } else if (wasInside && !isInside) {
                fenceState.put(fence.getId(), false);
                createAlert(vehicleId, Alert.AlertType.GEOFENCE_EXIT, vehicle.getName() + " exited " + fence.getName());
            }
        }
    }

    private void createAlert(String vehicleId, Alert.AlertType type, String message) {
        Alert alert = new Alert("ALT-" + (++alertCounter), vehicleId, type, message);
        alerts.add(alert); System.out.println(alert);
        for (AlertListener l : alertListeners) l.onAlert(alert);
    }

    public void setVehicleState(String vehicleId, VehicleState state) {
        Vehicle v = vehicles.get(vehicleId);
        if (v != null) { v.setState(state); System.out.println(v.getName() + " -> " + state); }
    }

    public void setSpeedLimit(double kmh) { speedMonitor.setSpeedLimitKmh(kmh); }
    public List<Alert> getAlerts() { return alerts; }
}

// concurrent/Main.java — Rapid GPS updates + geofence checker running, verify alerts always use latest position

import java.util.*;
import java.util.concurrent.*;
import java.util.concurrent.atomic.AtomicInteger;

public class Main {
    public static void main(String[] args) throws InterruptedException {
        System.out.println("=== Concurrent Vehicle Tracking Demo ===\n");
        System.out.println("Race condition: GPS update arriving while geofence check runs on previous location");
        System.out.println("— alert based on stale position.\n");

        Location initial = new Location(0.0, 0.0, System.nanoTime(), 0);
        VehicleTracker tracker = new VehicleTracker("VH-001", initial);

        // Geofence centered at (5.0, 5.0) with radius 1.0
        Geofence restrictedZone = new Geofence("RestrictedZone", 5.0, 5.0, 1.0);

        int gpsUpdateCount = 500;
        int geofenceChecks = 200;

        CountDownLatch startLatch = new CountDownLatch(1);
        CountDownLatch doneLatch = new CountDownLatch(3); // 2 updaters + 1 checker

        AtomicInteger outOfOrderAttempts = new AtomicInteger(0);

        // GPS updater thread 1: moves vehicle along a path (increasing sequence)
        new Thread(() -> {
            try {
                startLatch.await();
                for (int i = 1; i <= gpsUpdateCount; i++) {
                    double lat = (i * 10.0) / gpsUpdateCount;
                    double lon = (i * 10.0) / gpsUpdateCount;
                    Location loc = new Location(lat, lon, System.nanoTime(), i * 2);
                    tracker.updateLocation(loc);
                }
            } catch (InterruptedException e) {
                Thread.currentThread().interrupt();
            } finally {
                doneLatch.countDown();
            }
        }).start();

        // GPS updater thread 2: tries to inject stale (out-of-order) updates
        new Thread(() -> {
            try {
                startLatch.await();
                for (int i = 1; i <= gpsUpdateCount; i++) {
                    // Odd sequence numbers — interleaved but sometimes stale
                    Location loc = new Location(0.0, 0.0, System.nanoTime(), i * 2 - 1);
                    if (!tracker.updateLocation(loc)) {
                        outOfOrderAttempts.incrementAndGet();
                    }
                }
            } catch (InterruptedException e) {
                Thread.currentThread().interrupt();
            } finally {
                doneLatch.countDown();
            }
        }).start();

        // Geofence checker thread: continuously checks position
        List<Integer> alertSequences = new CopyOnWriteArrayList<>();
        new Thread(() -> {
            try {
                startLatch.await();
                for (int i = 0; i < geofenceChecks; i++) {
                    Location loc = tracker.getLatestLocation();
                    if (restrictedZone.contains(loc)) {
                        alertSequences.add(loc.getSequenceNum());
                    }
                    Thread.sleep(0, 100); // Tiny delay between checks
                }
            } catch (InterruptedException e) {
                Thread.currentThread().interrupt();
            } finally {
                doneLatch.countDown();
            }
        }).start();

        startLatch.countDown();
        doneLatch.await();

        // Verify: final location should have highest sequence number
        Location finalLoc = tracker.getLatestLocation();
        int highestPossibleSeq = gpsUpdateCount * 2;

        // Check that alerts never reference a sequence number lower than previous alert
        boolean alertsMonotonic = true;
        int prevSeq = -1;
        for (int seq : alertSequences) {
            if (seq < prevSeq) {
                alertsMonotonic = false;
                break;
            }
            prevSeq = seq;
        }

        // Check no alert used seq=0 (the stale initial position) after updates started
        boolean noStaleAlerts = true;
        for (int seq : alertSequences) {
            if (seq == 0) {
                noStaleAlerts = false;
                break;
            }
        }

        System.out.println("--- Results ---");
        System.out.println("GPS updates sent (thread 1): " + gpsUpdateCount);
        System.out.println("Stale updates sent (thread 2): " + gpsUpdateCount);
        System.out.println("Successful updates: " + tracker.getUpdateCount());
        System.out.println("Stale rejects: " + tracker.getStaleRejects());
        System.out.println("Final location seq: " + finalLoc.getSequenceNum());
        System.out.println("Highest possible seq: " + highestPossibleSeq);
        System.out.println("Geofence checks performed: " + geofenceChecks);
        System.out.println("Geofence alerts triggered: " + alertSequences.size());
        System.out.println("Out-of-order attempts blocked: " + outOfOrderAttempts.get());

        boolean finalIsHighest = (finalLoc.getSequenceNum() == highestPossibleSeq);
        boolean staleRejected = (tracker.getStaleRejects() > 0);

        System.out.println("\n--- Consistency Checks ---");
        System.out.println("Final position has highest seq: " + finalIsHighest);
        System.out.println("Stale updates were rejected: " + staleRejected);
        System.out.println("Alerts use monotonically increasing seq: " + alertsMonotonic);
        System.out.println("No stale-position alerts: " + noStaleAlerts);

        boolean passed = finalIsHighest && staleRejected && alertsMonotonic && noStaleAlerts;
        System.out.println("\nCorrectness check: " + (passed ? "PASSED" : "FAILED"));
    }
}

// concurrent/model/Geofence.java — Circular geofence zone

public class Geofence {
    private final String zoneId;    // final = immutable; safe to read from any thread
    private final double centerLat; // final = center latitude never changes; no sync needed
    private final double centerLon; // final = center longitude never changes; no sync needed
    private final double radius;    // final = radius fixed at creation; thread-safe by design

    public Geofence(String zoneId, double centerLat, double centerLon, double radius) {
        this.zoneId = zoneId;
        this.centerLat = centerLat;
        this.centerLon = centerLon;
        this.radius = radius;
    }

    public boolean contains(Location loc) {
        double dLat = loc.getLatitude() - centerLat;
        double dLon = loc.getLongitude() - centerLon;
        return Math.sqrt(dLat * dLat + dLon * dLon) <= radius;
    }

    public String getZoneId() { return zoneId; }

    @Override
    public String toString() { return zoneId + " center=(" + centerLat + "," + centerLon + ") r=" + radius; }
}

// concurrent/model/Location.java — Immutable GPS location with timestamp

public class Location {
    private final double latitude;  // final = immutable; safe to share across threads without sync
    private final double longitude; // final = immutable; no thread can corrupt this value
    private final long timestamp;   // final = when reading was taken; immutable
    private final int sequenceNum;  // final = ordering key; used for CAS stale-detection

    public Location(double latitude, double longitude, long timestamp, int sequenceNum) {
        this.latitude = latitude;
        this.longitude = longitude;
        this.timestamp = timestamp;
        this.sequenceNum = sequenceNum;
    }

    public double getLatitude() { return latitude; }
    public double getLongitude() { return longitude; }
    public long getTimestamp() { return timestamp; }
    public int getSequenceNum() { return sequenceNum; }

    public double distanceTo(Location other) {
        double dLat = this.latitude - other.latitude;
        double dLon = this.longitude - other.longitude;
        return Math.sqrt(dLat * dLat + dLon * dLon);
    }

    @Override
    public String toString() {
        return String.format("(%,.4f, %,.4f) seq=%d", latitude, longitude, sequenceNum);
    }
}

// concurrent/service/VehicleTracker.java — AtomicReference for latest position, CAS-based updates

import java.util.concurrent.atomic.AtomicReference;
import java.util.concurrent.atomic.AtomicInteger;
import java.util.List;
import java.util.concurrent.CopyOnWriteArrayList;

public class VehicleTracker {
    private final String vehicleId;                         // final = ID immutable; safe publication
    private final AtomicReference<Location> latestLocation; // AtomicReference = CAS-based location swap; always latest
    private final AtomicInteger updateCount;                // AtomicInteger = thread-safe success counter
    private final AtomicInteger staleRejects;               // AtomicInteger = counts rejected out-of-order updates
    private final List<String> alerts;                      // CopyOnWriteArrayList = thread-safe alert log

    public VehicleTracker(String vehicleId, Location initial) {
        this.vehicleId = vehicleId;
        this.latestLocation = new AtomicReference<>(initial);
        this.updateCount = new AtomicInteger(0);
        this.staleRejects = new AtomicInteger(0);
        this.alerts = new CopyOnWriteArrayList<>();
    }

    /**
     * CAS-based location update. Only accepts updates with higher sequence number
     * to never process stale locations.
     */
    public boolean updateLocation(Location newLocation) {
        while (true) {
            Location current = latestLocation.get();
            if (newLocation.getSequenceNum() <= current.getSequenceNum()) {
                staleRejects.incrementAndGet();
                return false; // Stale update — reject
            }
            if (latestLocation.compareAndSet(current, newLocation)) { // CAS = atomic swap; retries if another thread won
                updateCount.incrementAndGet();
                return true;
            }
            // CAS failed — another thread updated. Re-check if still newer.
        }
    }

    /**
     * Check geofence against latest known position.
     * Always reads the latest position via AtomicReference.
     */
    public boolean checkGeofence(Geofence fence) {
        Location loc = latestLocation.get(); // Always gets latest
        boolean inside = fence.contains(loc);
        if (inside) {
            alerts.add("Vehicle " + vehicleId + " inside " + fence.getZoneId()
                    + " at " + loc + " (seq=" + loc.getSequenceNum() + ")");
        }
        return inside;
    }

    public Location getLatestLocation() { return latestLocation.get(); }
    public int getUpdateCount() { return updateCount.get(); }
    public int getStaleRejects() { return staleRejects.get(); }
    public List<String> getAlerts() { return alerts; }
    public String getVehicleId() { return vehicleId; }
}

