// model/Bet.java — Represents a wager placed by a player
public class Bet {
    private double amount;   // private = wager amount set once at creation
    private boolean settled; // private = only settle() can mark bet as resolved

    public Bet(double amount) { this.amount = amount; this.settled = false; }
    public double getAmount() { return amount; }
    public double getWinAmount() { return amount; }
    public double getBlackjackWinAmount() { return amount * 1.5; }
    public void settle() { this.settled = true; }
}

// model/Card.java — Represents a single playing card
public class Card {
    private Rank rank; // private = card rank encapsulated; accessed via getRank()
    private Suit suit; // private = card suit encapsulated; accessed via getSuit()

    public Card(Rank rank, Suit suit) { this.rank = rank; this.suit = suit; }
    public Rank getRank() { return rank; }
    public Suit getSuit() { return suit; }
    public int getValue() { return rank.getValue(); }
    public boolean isAce() { return rank == Rank.ACE; }
    @Override public String toString() { return rank + " of " + suit; }
}

// model/Deck.java — 52-card deck with shuffle (creates new deck on reshuffle)
import java.util.ArrayList;
import java.util.Collections;
import java.util.List;
import java.util.Random;

public class Deck {
    private List<Card> cards;  // private = deck contents managed internally
    private Random random;     // private = seed-based RNG for reproducible shuffles

    public Deck(long seed) { this.random = new Random(seed); buildDeck(); }

    private void buildDeck() {
        cards = new ArrayList<>();
        for (Suit suit : Suit.values())
            for (Rank rank : Rank.values())
                cards.add(new Card(rank, suit));
    }

    // Creates new deck objects on every shuffle
    public void shuffle() { Collections.shuffle(cards, random); }

    public Card deal() {
        if (cards.isEmpty()) { buildDeck(); shuffle(); }
        return cards.remove(cards.size() - 1);
    }

    public int remaining() { return cards.size(); }
    public void reset() { buildDeck(); shuffle(); }
}

// model/Hand.java — Represents a player's current hand of cards
import java.util.ArrayList;
import java.util.List;

public class Hand {
    private List<Card> cards; // private = hand managed via addCard()/clear()

    public Hand() { this.cards = new ArrayList<>(); }
    public void addCard(Card card) { cards.add(card); }
    public List<Card> getCards() { return new ArrayList<>(cards); }

    public int getScore() {
        int score = 0; int aces = 0;
        for (Card card : cards) { score += card.getValue(); if (card.isAce()) aces++; }
        while (score > 21 && aces > 0) { score -= 10; aces--; }
        return score;
    }

    public boolean isBusted() { return getScore() > 21; }
    public boolean isBlackjack() { return cards.size() == 2 && getScore() == 21; }
    public void clear() { cards.clear(); }

    @Override public String toString() {
        StringBuilder sb = new StringBuilder("[");
        for (int i = 0; i < cards.size(); i++) { if (i > 0) sb.append(", "); sb.append(cards.get(i)); }
        return sb.append("]").toString();
    }
}

// model/Player.java — Represents a player with chips and current hand
public class Player {
    private String name;    // private = player name encapsulated
    private Hand hand;      // private = current hand managed internally
    private double balance; // private = chip balance only changes via addToBalance()

    public Player(String name, double initialBalance) { this.name = name; this.hand = new Hand(); this.balance = initialBalance; }
    public String getName() { return name; }
    public Hand getHand() { return hand; }
    public double getBalance() { return balance; }
    public void addToBalance(double amount) { this.balance += amount; }
    public boolean canBet(double amount) { return balance >= amount; }
    public void resetHand() { hand.clear(); }
}

// model/Rank.java — Enumerates card ranks with values
public enum Rank { // enum = fixed set of card ranks with point values
    ACE("Ace",11), TWO("2",2), THREE("3",3), FOUR("4",4), FIVE("5",5),
    SIX("6",6), SEVEN("7",7), EIGHT("8",8), NINE("9",9), TEN("10",10),
    JACK("Jack",10), QUEEN("Queen",10), KING("King",10);
    private String displayName; private int value; // private = name/value per rank constant
    Rank(String displayName, int value) { this.displayName = displayName; this.value = value; }
    public int getValue() { return value; }
    @Override public String toString() { return displayName; }
}

// service/BlackjackGame.java — Manages game flow and win/loss determination
public class BlackjackGame {
    private Deck deck;          // private = deck managed internally; deals cards
    private Player player;      // private = the player in this game session
    private Dealer dealer;      // private = dealer with configurable strategy
    private GameState state;    // private = game phase controlled by game logic only
    private Bet currentBet;     // private = current wager for this round

    public BlackjackGame(Player player, DealerStrategy dealerStrategy, long seed) {
        this.deck = new Deck(seed); this.deck.shuffle();
        this.player = player; this.dealer = new Dealer(dealerStrategy);
        this.state = GameState.BETTING;
    }

    public GameState getState() { return state; }
    public Player getPlayer() { return player; }

    public boolean placeBet(double amount) {
        if (state != GameState.BETTING || !player.canBet(amount)) return false;
        currentBet = new Bet(amount); player.addToBalance(-amount);
        System.out.println("Bet: $" + String.format("%.0f", amount));
        return true;
    }

    public void deal() {
        if (state != GameState.BETTING || currentBet == null) return;
        state = GameState.DEALING;
        player.resetHand(); dealer.resetHand();
        player.getHand().addCard(deck.deal()); dealer.getHand().addCard(deck.deal());
        player.getHand().addCard(deck.deal()); dealer.getHand().addCard(deck.deal());
        System.out.println("Player: " + player.getHand() + " = " + player.getHand().getScore());

        if (player.getHand().isBlackjack()) {
            state = GameState.GAME_OVER;
            double winnings = currentBet.getAmount() + currentBet.getBlackjackWinAmount();
            player.addToBalance(winnings); currentBet.settle();
            System.out.println("BLACKJACK! +$" + String.format("%.0f", currentBet.getBlackjackWinAmount()));
        } else { state = GameState.PLAYING; }
    }

    public boolean hit() {
        if (state != GameState.PLAYING) return false;
        Card card = deck.deal(); player.getHand().addCard(card);
        System.out.println("Hit: " + card + " -> " + player.getHand().getScore());
        if (player.getHand().isBusted()) {
            System.out.println("BUST! -$" + String.format("%.0f", currentBet.getAmount()));
            state = GameState.GAME_OVER; currentBet.settle(); return false;
        }
        return true;
    }

    public void stand() {
        if (state != GameState.PLAYING) return;
        state = GameState.DEALER_TURN;
        System.out.println("Stand with " + player.getHand().getScore());
        System.out.println("Dealer: " + dealer.getHand() + " = " + dealer.getHand().getScore());
        while (dealer.shouldHit()) {
            Card card = deck.deal(); dealer.getHand().addCard(card);
            System.out.println("Dealer hits: " + card + " -> " + dealer.getHand().getScore());
        }
        settleRound();
    }

    private void settleRound() {
        state = GameState.GAME_OVER;
        int ps = player.getHand().getScore(), ds = dealer.getHand().getScore();
        if (dealer.getHand().isBusted()) { player.addToBalance(currentBet.getAmount() + currentBet.getWinAmount()); System.out.println("Dealer busts! +$" + String.format("%.0f", currentBet.getWinAmount())); }
        else if (ps > ds) { player.addToBalance(currentBet.getAmount() + currentBet.getWinAmount()); System.out.println("Player wins! +$" + String.format("%.0f", currentBet.getWinAmount())); }
        else if (ds > ps) { System.out.println("Dealer wins! -$" + String.format("%.0f", currentBet.getAmount())); }
        else { player.addToBalance(currentBet.getAmount()); System.out.println("Push!"); }
        currentBet.settle();
        System.out.println("Balance: $" + String.format("%.0f", player.getBalance()));
    }

    public void newRound() { state = GameState.BETTING; currentBet = null; if (deck.remaining() < 15) deck.reset(); }
}

