// model/Deck.java — Deck with Fisher-Yates in-place shuffle (no new object allocation)
import java.util.Random;

public class Deck {
    // Fixed-size array avoids ArrayList overhead and GC pressure
    private Card[] cards;                   // Card[] = fixed array; no resizing, no boxing overhead
    private int top;                        // index of next card to deal; O(1) dealing
    private Random random;                  // seeded RNG for reproducible shuffles
    private static final int DECK_SIZE = 52; // static final = constant; same for all Deck instances

    public Deck(long seed) {
        this.random = new Random(seed);
        this.cards = new Card[DECK_SIZE];
        buildDeck();
        shuffle();
    }

    private void buildDeck() {
        int i = 0;
        for (Suit suit : Suit.values())
            for (Rank rank : Rank.values())
                cards[i++] = new Card(rank, suit);
        top = DECK_SIZE - 1;
    }

    // WHY: Fisher-Yates in-place shuffle — O(n) with no new allocations
    // vs Collections.shuffle which may create temporary arrays
    public void shuffle() {
        for (int i = DECK_SIZE - 1; i > 0; i--) {
            int j = random.nextInt(i + 1);
            Card temp = cards[i];
            cards[i] = cards[j];
            cards[j] = temp;
        }
        top = DECK_SIZE - 1;
    }

    public Card deal() {
        if (top < 0) { shuffle(); }
        return cards[top--];
    }

    public int remaining() { return top + 1; }

    // WHY: Reset just reshuffles existing cards in-place — no GC
    public void reset() { shuffle(); }
}

// model/Hand.java — Hand with memoized score computation
import java.util.ArrayList;
import java.util.List;

public class Hand {
    private List<Card> cards;   // ArrayList = dynamic card collection for the hand
    // Memoized score — only recomputes when hand changes, not on every getScore()
    private int cachedScore;    // cached value = O(1) repeat access without re-summing
    private boolean scoreDirty; // dirty flag = signals when cache must be recomputed

    public Hand() { this.cards = new ArrayList<>(); this.cachedScore = 0; this.scoreDirty = true; }

    public void addCard(Card card) {
        cards.add(card);
        scoreDirty = true; // Invalidate cache
    }

    public List<Card> getCards() { return new ArrayList<>(cards); }

    // WHY: O(1) when cache is valid (most calls), O(n) only after addCard
    public int getScore() {
        if (!scoreDirty) return cachedScore;
        int score = 0; int aces = 0;
        for (Card card : cards) { score += card.getValue(); if (card.isAce()) aces++; }
        while (score > 21 && aces > 0) { score -= 10; aces--; }
        cachedScore = score;
        scoreDirty = false;
        return cachedScore;
    }

    public boolean isBusted() { return getScore() > 21; }
    public boolean isBlackjack() { return cards.size() == 2 && getScore() == 21; }
    public int size() { return cards.size(); }

    public void clear() { cards.clear(); cachedScore = 0; scoreDirty = true; }

    @Override public String toString() {
        StringBuilder sb = new StringBuilder("[");
        for (int i = 0; i < cards.size(); i++) { if (i > 0) sb.append(", "); sb.append(cards.get(i)); }
        return sb.append("]").toString();
    }
}

